Session fixation is a critical vulnerability where an attacker tricks a victim into using a session ID that the attacker already knows. If your application doesn't regenerate the session ID after successful authentication, the attacker can hijack the user's authenticated session.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const session = require('express-session');
const bcrypt = require('bcrypt');

const app = express();

app.use(session({
  secret: 'mysecret',
  resave: false,
  saveUninitialized: true // VULNERABLE: Creates session before auth
}));

app.use(express.json());

// VULNERABLE: No session regeneration after login
app.post('/login', async (req, res) => {
  const { username, password } = req.body;

  // Find user in database
  const user = await findUserByUsername(username);

  if (user && await bcrypt.compare(password, user.passwordHash)) {
    // VULNERABLE: Reusing the same session ID
    req.session.userId = user.id;
    req.session.username = user.username;
    req.session.isAuthenticated = true;

    res.json({ message: 'Login successful' });
  } else {
    res.status(401).json({ error: 'Invalid credentials' });
  }
});

app.listen(3000);
```

**Attack Payload**:
```text
1. Attacker visits the site, receives session ID: abc123
2. Attacker crafts malicious link: https://target.com/login?SID=abc123
3. Attacker sends link to victim via phishing email
4. Victim clicks link, browser now uses session ID abc123
5. Victim logs in successfully
6. Attacker uses session ID abc123 to access victim's authenticated session

Alternatively via cookie injection:
Set-Cookie: connect.sid=s%3Aattacker-known-session-id
```

**Why This Is Dangerous**:
- Session ID remains the same before and after authentication, allowing session fixation attacks
- `saveUninitialized: true` creates sessions for unauthenticated users, making fixation easier
- Weak session secret makes session tokens predictable
- No session expiration or security flags configured

**SECURE VERSION**:

```javascript
const express = require('express');
const session = require('express-session');
const bcrypt = require('bcrypt');
const crypto = require('crypto');

const app = express();

app.use(session({
  secret: process.env.SESSION_SECRET || crypto.randomBytes(32).toString('hex'),
  resave: false,
  saveUninitialized: false, // SECURE: Don't create sessions until needed
  name: '__Host-sessionId', // SECURE: Use __Host- prefix for additional protection
  cookie: {
    secure: process.env.NODE_ENV === 'production', // HTTPS only in production
    httpOnly: true, // Prevent JavaScript access
    sameSite: 'strict', // Prevent CSRF
    maxAge: 30 * 60 * 1000 // 30 minute timeout
  }
}));

app.use(express.json());

// SECURE: Regenerate session after successful login
app.post('/login', async (req, res) => {
  const { username, password } = req.body;

  const user = await findUserByUsername(username);

  if (user && await bcrypt.compare(password, user.passwordHash)) {
    // CRITICAL: Regenerate session ID to prevent fixation
    req.session.regenerate((err) => {
      if (err) {
        console.error('Session regeneration failed:', err);
        return res.status(500).json({ error: 'Authentication failed' });
      }

      req.session.userId = user.id;
      req.session.username = user.username;
      req.session.isAuthenticated = true;
      req.session.loginTime = Date.now();
      req.session.ipAddress = req.ip;

      res.json({ message: 'Login successful' });
    });
  } else {
    res.status(401).json({ error: 'Invalid credentials' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- `session.regenerate()`: Creates a new session ID after authentication, invalidating any previously known session ID
- `saveUninitialized: false`: Prevents session creation until authentication, reducing attack surface
- Secure cookie flags: `httpOnly`, `secure`, `sameSite` prevent session theft via XSS and CSRF
- Session metadata tracking: `loginTime` and `ipAddress` enable anomaly detection

Excellent question! Session regeneration should occur at ANY privilege level change, not just initial login. This includes role changes, password changes, and logout. Let me show you a production-ready pattern.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const session = require('express-session');
const RedisStore = require('connect-redis').default;
const { createClient } = require('redis');
const bcrypt = require('bcrypt');
const crypto = require('crypto');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// Redis client for session storage
const redisClient = createClient({
  url: process.env.REDIS_URL,
  socket: { tls: process.env.NODE_ENV === 'production' }
});
redisClient.connect().catch(console.error);

// Security headers
app.use(helmet());

// Rate limiting for auth endpoints
const authLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 5, // 5 attempts per window
  message: { error: 'Too many attempts, please try again later' },
  standardHeaders: true,
  legacyHeaders: false
});

// Session configuration
app.use(session({
  store: new RedisStore({ client: redisClient }),
  secret: process.env.SESSION_SECRET,
  resave: false,
  saveUninitialized: false,
  name: '__Host-sid',
  cookie: {
    secure: process.env.NODE_ENV === 'production',
    httpOnly: true,
    sameSite: 'strict',
    maxAge: 30 * 60 * 1000,
    path: '/'
  },
  rolling: true // Reset expiration on activity
}));

app.use(express.json());

// Session regeneration utility with audit logging
async function regenerateSession(req, newData = {}) {
  return new Promise((resolve, reject) => {
    const oldSessionId = req.sessionID;
    const preservedData = { ...req.session };
    delete preservedData.cookie;

    req.session.regenerate((err) => {
      if (err) {
        console.error('[SECURITY] Session regeneration failed:', {
          oldSessionId: oldSessionId.substring(0, 8) + '...',
          error: err.message,
          ip: req.ip,
          timestamp: new Date().toISOString()
        });
        return reject(err);
      }

      // Restore necessary data and apply new data
      Object.assign(req.session, preservedData, newData, {
        regeneratedAt: Date.now(),
        previousSessionId: oldSessionId.substring(0, 8)
      });

      console.log('[AUDIT] Session regenerated:', {
        newSessionId: req.sessionID.substring(0, 8) + '...',
        reason: newData.regenerationReason || 'unknown',
        userId: req.session.userId,
        ip: req.ip,
        timestamp: new Date().toISOString()
      });

      resolve();
    });
  });
}

// Secure session destruction
async function destroySession(req) {
  return new Promise((resolve, reject) => {
    const sessionId = req.sessionID;
    const userId = req.session?.userId;

    req.session.destroy((err) => {
      if (err) {
        console.error('[SECURITY] Session destruction failed:', err);
        return reject(err);
      }

      console.log('[AUDIT] Session destroyed:', {
        sessionId: sessionId.substring(0, 8) + '...',
        userId,
        ip: req.ip,
        timestamp: new Date().toISOString()
      });

      resolve();
    });
  });
}

// Login with session regeneration
app.post('/login', authLimiter, async (req, res) => {
  try {
    const { username, password } = req.body;
    const user = await findUserByUsername(username);

    if (!user || !(await bcrypt.compare(password, user.passwordHash))) {
      console.log('[SECURITY] Failed login attempt:', {
        username,
        ip: req.ip,
        userAgent: req.get('User-Agent'),
        timestamp: new Date().toISOString()
      });
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    await regenerateSession(req, {
      userId: user.id,
      username: user.username,
      role: user.role,
      isAuthenticated: true,
      loginTime: Date.now(),
      ipAddress: req.ip,
      userAgent: req.get('User-Agent'),
      regenerationReason: 'login'
    });

    res.json({ message: 'Login successful', role: user.role });
  } catch (err) {
    console.error('[ERROR] Login failed:', err);
    res.status(500).json({ error: 'Authentication failed' });
  }
});

// Privilege escalation with session regeneration
app.post('/elevate-privileges', authLimiter, async (req, res) => {
  try {
    if (!req.session.isAuthenticated) {
      return res.status(401).json({ error: 'Not authenticated' });
    }

    const { adminPassword } = req.body;
    const user = await findUserById(req.session.userId);

    // Verify admin credentials (second factor for elevation)
    if (!user.isAdmin || !(await bcrypt.compare(adminPassword, user.adminPasswordHash))) {
      console.log('[SECURITY] Failed privilege escalation:', {
        userId: req.session.userId,
        ip: req.ip,
        timestamp: new Date().toISOString()
      });
      return res.status(403).json({ error: 'Elevation denied' });
    }

    // CRITICAL: Regenerate session on privilege change
    await regenerateSession(req, {
      role: 'admin',
      elevatedAt: Date.now(),
      regenerationReason: 'privilege_escalation'
    });

    res.json({ message: 'Privileges elevated to admin' });
  } catch (err) {
    console.error('[ERROR] Privilege escalation failed:', err);
    res.status(500).json({ error: 'Elevation failed' });
  }
});

// Secure logout
app.post('/logout', async (req, res) => {
  try {
    await destroySession(req);

    // Clear the session cookie
    res.clearCookie('__Host-sid', {
      path: '/',
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict'
    });

    res.json({ message: 'Logged out successfully' });
  } catch (err) {
    console.error('[ERROR] Logout failed:', err);
    // Still clear cookie even if session destruction fails
    res.clearCookie('__Host-sid');
    res.status(500).json({ error: 'Logout may be incomplete' });
  }
});

// Global logout - invalidate all sessions for user
app.post('/logout-all', async (req, res) => {
  try {
    if (!req.session.isAuthenticated) {
      return res.status(401).json({ error: 'Not authenticated' });
    }

    const userId = req.session.userId;

    // Increment user's session version to invalidate all existing sessions
    await incrementUserSessionVersion(userId);

    await destroySession(req);
    res.clearCookie('__Host-sid');

    console.log('[AUDIT] Global logout executed:', {
      userId,
      ip: req.ip,
      timestamp: new Date().toISOString()
    });

    res.json({ message: 'All sessions terminated' });
  } catch (err) {
    console.error('[ERROR] Global logout failed:', err);
    res.status(500).json({ error: 'Logout failed' });
  }
});

// Session validation middleware
const validateSession = async (req, res, next) => {
  if (!req.session.isAuthenticated) {
    return next();
  }

  // Check session version against user's current version
  const user = await findUserById(req.session.userId);
  if (!user || req.session.sessionVersion !== user.sessionVersion) {
    await destroySession(req);
    return res.status(401).json({ error: 'Session invalidated' });
  }

  // Check for IP address change (optional, can cause issues with mobile)
  if (req.session.ipAddress !== req.ip) {
    console.log('[SECURITY] IP address changed during session:', {
      userId: req.session.userId,
      originalIp: req.session.ipAddress,
      newIp: req.ip,
      timestamp: new Date().toISOString()
    });
    // Consider requiring re-authentication for sensitive operations
  }

  next();
};

app.use(validateSession);

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Session Regeneration at Every Privilege Change**:
```javascript
// Regenerate on: login, privilege escalation, role change, password change
await regenerateSession(req, { regenerationReason: 'password_change' });
```

2. **Server-Side Session Storage with Redis**:
```javascript
// Sessions stored server-side, not in cookies
store: new RedisStore({ client: redisClient })
// Enables global logout and session version tracking
```

3. **Session Version Tracking for Global Invalidation**:
```javascript
// Each user has a session version; incrementing invalidates all sessions
if (req.session.sessionVersion !== user.sessionVersion) {
  await destroySession(req);
}
```

**Additional Protections**:
- **Rate limiting on auth endpoints**: Prevents brute-force attacks on session fixation vectors
- **Comprehensive audit logging**: All session lifecycle events logged with IP, timestamp, and user context
- **Secure cookie attributes**: `__Host-` prefix, `httpOnly`, `secure`, `sameSite=strict` prevent session theft
- **IP address tracking**: Detects potential session hijacking from different networks
- **Session timeout with rolling expiration**: Balances security with usability
- **Graceful error handling**: Security failures don't leak information, sessions cleared on errors

Your code likely has a critical authorization vulnerability. This is the exact pattern that led to the Parler data breach where attackers scraped 70TB of user data by simply incrementing IDs in API requests.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();
const db = require('./database');

// VULNERABLE: No authorization check - any authenticated user can view ANY order
app.get('/api/orders/:orderId', authenticateToken, async (req, res) => {
  try {
    const orderId = req.params.orderId;

    // Directly fetches order without verifying ownership
    const order = await db.query(
      'SELECT * FROM orders WHERE id = $1',
      [orderId]
    );

    if (!order.rows[0]) {
      return res.status(404).json({ error: 'Order not found' });
    }

    // Returns order data to ANY authenticated user
    res.json(order.rows[0]);
  } catch (error) {
    res.status(500).json({ error: 'Server error' });
  }
});

app.listen(3000);
```

**Attack Payload**:
```bash
# Attacker authenticated as user 123 can access order belonging to user 456
curl -H "Authorization: Bearer <valid_token>" \
     https://api.example.com/api/orders/1

# Enumerate all orders by incrementing ID
for i in {1..10000}; do
  curl -s -H "Authorization: Bearer <token>" \
       https://api.example.com/api/orders/$i >> stolen_orders.json
done
```

**Why This Is Dangerous**:
- Authentication only verifies identity, not permission to access specific resources
- Sequential/predictable IDs make enumeration trivial
- Attacker can access any user's orders, payment info, addresses
- Violates principle of least privilege

**SECURE VERSION**:

```javascript
const express = require('express');
const app = express();
const db = require('./database');

// SECURE: Authorization check verifies resource ownership
app.get('/api/orders/:orderId', authenticateToken, async (req, res) => {
  try {
    const orderId = req.params.orderId;
    const userId = req.user.id; // From authenticated token

    // AUTHORIZATION CHECK: Only fetch if user owns this order
    const order = await db.query(
      'SELECT * FROM orders WHERE id = $1 AND user_id = $2',
      [orderId, userId]
    );

    if (!order.rows[0]) {
      // Same error for not found AND not authorized (prevents enumeration)
      return res.status(404).json({ error: 'Order not found' });
    }

    // Log access for audit trail
    console.log(`User ${userId} accessed order ${orderId}`);

    res.json(order.rows[0]);
  } catch (error) {
    console.error('Order fetch error:', error.message);
    res.status(500).json({ error: 'Server error' });
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Ownership verification**: Query includes `user_id` check, ensuring users can only access their own resources
- **Uniform error responses**: Returns 404 for both "not found" and "not authorized" to prevent attackers from enumerating valid IDs
- **Audit logging**: Records who accessed what for security monitoring and incident response

Excellent question! Role-based access control (RBAC) with hierarchical permissions requires a more sophisticated approach. Here's a production-ready pattern that handles multiple authorization levels securely.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const app = express();
const db = require('./database');
const winston = require('winston');
const rateLimit = require('express-rate-limit');

// Configure structured logging
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

// Rate limiting to prevent enumeration attacks
const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  message: { error: 'Too many requests, please try again later' }
});

// Authorization policy engine
class AuthorizationService {
  static ROLES = {
    ADMIN: 'admin',
    MANAGER: 'manager',
    USER: 'user'
  };

  static async canAccessOrder(user, orderId, db) {
    // Layer 1: Admin bypass - can access all orders
    if (user.role === this.ROLES.ADMIN) {
      return { authorized: true, reason: 'admin_access' };
    }

    // Fetch order with necessary context
    const orderResult = await db.query(
      `SELECT o.id, o.user_id, o.department_id, u.department_id as owner_dept
       FROM orders o
       JOIN users u ON o.user_id = u.id
       WHERE o.id = $1`,
      [orderId]
    );

    if (!orderResult.rows[0]) {
      return { authorized: false, reason: 'not_found' };
    }

    const order = orderResult.rows[0];

    // Layer 2: Owner can always access their own orders
    if (order.user_id === user.id) {
      return { authorized: true, reason: 'owner_access', order };
    }

    // Layer 3: Managers can access orders from their department
    if (user.role === this.ROLES.MANAGER && 
        order.owner_dept === user.department_id) {
      return { authorized: true, reason: 'manager_department_access', order };
    }

    // Default deny
    return { authorized: false, reason: 'insufficient_permissions' };
  }
}

// Authorization middleware factory
const authorizeOrderAccess = (requiredAction = 'read') => {
  return async (req, res, next) => {
    const startTime = Date.now();
    const orderId = req.params.orderId;
    const user = req.user;

    try {
      // Input validation
      if (!orderId || !/^\d+$/.test(orderId)) {
        logger.warn({
          event: 'invalid_order_id',
          user_id: user.id,
          attempted_id: orderId,
          ip: req.ip
        });
        return res.status(400).json({ error: 'Invalid order ID format' });
      }

      const authResult = await AuthorizationService.canAccessOrder(
        user,
        parseInt(orderId, 10),
        db
      );

      // Audit logging for all access attempts
      logger.info({
        event: 'authorization_check',
        user_id: user.id,
        user_role: user.role,
        resource_type: 'order',
        resource_id: orderId,
        action: requiredAction,
        authorized: authResult.authorized,
        reason: authResult.reason,
        ip: req.ip,
        user_agent: req.get('User-Agent'),
        duration_ms: Date.now() - startTime
      });

      if (!authResult.authorized) {
        // Return 404 for both not_found and unauthorized (prevent enumeration)
        return res.status(404).json({ error: 'Order not found' });
      }

      // Attach order to request for downstream handlers
      req.authorizedOrder = authResult.order;
      req.authorizationReason = authResult.reason;
      next();

    } catch (error) {
      logger.error({
        event: 'authorization_error',
        user_id: user.id,
        resource_id: orderId,
        error: error.message,
        stack: error.stack
      });
      return res.status(500).json({ error: 'Authorization check failed' });
    }
  };
};

// Protected endpoint with layered authorization
app.get('/api/orders/:orderId',
  apiLimiter,
  authenticateToken,
  authorizeOrderAccess('read'),
  async (req, res) => {
    try {
      // Order already fetched and authorized by middleware
      const order = req.authorizedOrder;

      // Redact sensitive fields based on access level
      const sanitizedOrder = sanitizeOrderResponse(order, req.user.role);

      res.json(sanitizedOrder);
    } catch (error) {
      logger.error({ event: 'order_fetch_error', error: error.message });
      res.status(500).json({ error: 'Failed to retrieve order' });
    }
  }
);

// Sanitize response based on role
function sanitizeOrderResponse(order, userRole) {
  const baseFields = {
    id: order.id,
    status: order.status,
    created_at: order.created_at,
    items: order.items,
    total: order.total
  };

  // Managers and admins see additional fields
  if (userRole === 'admin' || userRole === 'manager') {
    return {
      ...baseFields,
      user_id: order.user_id,
      internal_notes: order.internal_notes,
      profit_margin: order.profit_margin
    };
  }

  return baseFields;
}

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Rate Limiting**: Prevents brute-force enumeration attacks
```javascript
const limiter = rateLimit({
  windowMs: 15 * 60 * 1000,
  max: 100,
  standardHeaders: true
});
```

2. **Input Validation**: Rejects malformed IDs before authorization check
```javascript
if (!orderId || !/^\d+$/.test(orderId)) {
  return res.status(400).json({ error: 'Invalid order ID format' });
}
```

3. **Centralized Authorization Logic**: Single source of truth for permissions
```javascript
class AuthorizationService {
  static async canAccessOrder(user, orderId, db) {
    // All authorization logic in one place
  }
}
```

4. **Comprehensive Audit Logging**: Every access attempt recorded
```javascript
logger.info({
  event: 'authorization_check',
  user_id: user.id,
  resource_id: orderId,
  authorized: authResult.authorized,
  ip: req.ip
});
```

**Additional Protections**:
- **Uniform error responses**: Always return 404 regardless of whether order exists but is unauthorized, preventing enumeration
- **Field-level access control**: Different roles see different fields in the response
- **Principle of least privilege**: Default deny, explicitly grant access based on role hierarchy
- **Security monitoring**: Structured logs enable alerting on anomalous access patterns (e.g., single user accessing many different orders)
- **Request context preservation**: Attach authorization reason for downstream logging and decisions

Your registration endpoint likely has critical input validation flaws. The 2024 Twilio Authy breach (CVE-2024-39891) exposed 33 million phone numbers because their API accepted arbitrary input without proper validation or rate limiting. Attackers enumerated registered phone numbers, enabling targeted SIM-swap attacks against cryptocurrency holders.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const db = require('./database');

const app = express();
app.use(express.json());

// VULNERABLE: No input validation whatsoever
app.post('/api/register', async (req, res) => {
  const { username, email, password, age, phoneNumber } = req.body;

  // Directly using user input without validation
  const hashedPassword = await bcrypt.hash(password, 10);

  const query = `
    INSERT INTO users (username, email, password, age, phone_number)
    VALUES ($1, $2, $3, $4, $5)
    RETURNING id
  `;

  try {
    const result = await db.query(query, [
      username,
      email,
      hashedPassword,
      age,
      phoneNumber
    ]);

    res.json({ success: true, userId: result.rows[0].id });
  } catch (error) {
    res.status(500).json({ error: error.message }); // Leaks internal errors
  }
});

app.listen(3000);
```

**Attack Payloads**:
```text
// Mass enumeration attack
POST /api/register with sequential phone numbers:
+1555000001, +1555000002, +1555000003...

// Malformed data injection
{
  "username": "<script>alert('xss')</script>",
  "email": "not-an-email",
  "password": "1",
  "age": -500,
  "phoneNumber": "'); DROP TABLE users;--"
}

// Business logic abuse
{
  "username": "admin",
  "email": "attacker@evil.com",
  "password": "password123",
  "age": 999999999999999999999,
  "phoneNumber": "+0000000000000000000000000000"
}
```

**Why This Is Dangerous**:
- No validation allows XSS payloads in usernames stored and later rendered
- Missing email format validation enables account enumeration and spam
- No password complexity requirements leads to easily crackable credentials
- Unbounded numeric fields can cause integer overflow or database errors
- Phone number without validation enables mass enumeration attacks
- Error messages leak internal database structure to attackers

**SECURE VERSION**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const { body, validationResult } = require('express-validator');
const sanitizeHtml = require('sanitize-html');
const db = require('./database');

const app = express();
app.use(express.json({ limit: '10kb' })); // Limit payload size

// Input validation middleware
const registrationValidation = [
  body('username')
    .trim()
    .isLength({ min: 3, max: 30 })
    .matches(/^[a-zA-Z0-9_]+$/)
    .withMessage('Username must be 3-30 alphanumeric characters'),

  body('email')
    .trim()
    .isEmail()
    .normalizeEmail()
    .isLength({ max: 255 })
    .withMessage('Valid email required'),

  body('password')
    .isLength({ min: 12, max: 128 })
    .matches(/^(?=.*[a-z])(?=.*[A-Z])(?=.*\d)(?=.*[@$!%*?&])/)
    .withMessage('Password must be 12+ chars with uppercase, lowercase, number, and symbol'),

  body('age')
    .isInt({ min: 13, max: 120 })
    .withMessage('Age must be between 13 and 120'),

  body('phoneNumber')
    .matches(/^\+[1-9]\d{6,14}$/)
    .withMessage('Valid E.164 phone number required')
];

app.post('/api/register', registrationValidation, async (req, res) => {
  // Check validation results
  const errors = validationResult(req);
  if (!errors.isEmpty()) {
    return res.status(400).json({
      success: false,
      errors: errors.array().map(e => e.msg) // Don't expose field names
    });
  }

  const { username, email, password, age, phoneNumber } = req.body;

  // Additional sanitization
  const sanitizedUsername = sanitizeHtml(username, { allowedTags: [] });

  const hashedPassword = await bcrypt.hash(password, 12);

  try {
    const result = await db.query(
      `INSERT INTO users (username, email, password, age, phone_number)
       VALUES ($1, $2, $3, $4, $5) RETURNING id`,
      [sanitizedUsername, email, hashedPassword, age, phoneNumber]
    );

    res.status(201).json({ success: true, userId: result.rows[0].id });
  } catch (error) {
    console.error('Registration error:', error); // Log internally
    res.status(500).json({ success: false, error: 'Registration failed' });
  }
});
