Great question! Production environments require global exception handling with environment-aware error responses. You want detailed errors in development but sanitized responses in production.

**PRODUCTION PATTERN**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.http.ResponseEntity;
import org.springframework.http.HttpStatus;
import org.springframework.core.env.Environment;
import org.springframework.beans.factory.annotation.Autowired;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.slf4j.MDC;
import javax.servlet.http.HttpServletRequest;
import java.time.Instant;
import java.util.UUID;

@RestControllerAdvice
public class GlobalExceptionHandler {

    private static final Logger logger = LoggerFactory.getLogger(GlobalExceptionHandler.class);
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    @Autowired
    private Environment environment;

    @ExceptionHandler(Exception.class)
    public ResponseEntity<ErrorResponse> handleAllExceptions(
            Exception ex, HttpServletRequest request) {

        String correlationId = UUID.randomUUID().toString();
        MDC.put("correlationId", correlationId);
        MDC.put("clientIp", getClientIp(request));

        try {
            // Log full details internally
            logger.error("Unhandled exception [endpoint={}, method={}, correlationId={}]",
                request.getRequestURI(), request.getMethod(), correlationId, ex);

            // Security audit logging for potential attacks
            if (isPotentialAttack(ex, request)) {
                securityLogger.warn("POTENTIAL_ATTACK: {} from {} [correlationId={}]",
                    ex.getClass().getSimpleName(), getClientIp(request), correlationId);
            }

            ErrorResponse response = buildErrorResponse(ex, correlationId, request);
            return ResponseEntity.status(response.getStatusCode()).body(response);

        } finally {
            MDC.clear();
        }
    }

    @ExceptionHandler(ResourceNotFoundException.class)
    public ResponseEntity<ErrorResponse> handleNotFound(
            ResourceNotFoundException ex, HttpServletRequest request) {

        String correlationId = UUID.randomUUID().toString();
        logger.info("Resource not found: {} [correlationId={}]", 
            ex.getResourceType(), correlationId);

        return ResponseEntity.status(HttpStatus.NOT_FOUND)
            .body(new ErrorResponse(
                HttpStatus.NOT_FOUND.value(),
                "Resource not found",
                correlationId,
                Instant.now().toString()
            ));
    }

    @ExceptionHandler(ValidationException.class)
    public ResponseEntity<ErrorResponse> handleValidation(
            ValidationException ex, HttpServletRequest request) {

        String correlationId = UUID.randomUUID().toString();
        logger.warn("Validation failed: {} [correlationId={}]", 
            ex.getField(), correlationId);

        // Safe to return validation field name, but not internal details
        return ResponseEntity.status(HttpStatus.BAD_REQUEST)
            .body(new ErrorResponse(
                HttpStatus.BAD_REQUEST.value(),
                "Validation failed for field: " + sanitizeFieldName(ex.getField()),
                correlationId,
                Instant.now().toString()
            ));
    }

    private ErrorResponse buildErrorResponse(Exception ex, String correlationId, 
            HttpServletRequest request) {

        boolean isProduction = isProductionEnvironment();
        int statusCode = determineStatusCode(ex);

        String message;
        String details = null;

        if (isProduction) {
            // PRODUCTION: Generic message only
            message = "An unexpected error occurred. Please contact support with reference: " + correlationId;
        } else {
            // DEVELOPMENT: Include details for debugging
            message = ex.getClass().getSimpleName() + ": " + ex.getMessage();
            details = getStackTraceSummary(ex, 5); // Limited stack trace
        }

        return new ErrorResponse(statusCode, message, correlationId, 
            Instant.now().toString(), details);
    }

    private boolean isProductionEnvironment() {
        String[] profiles = environment.getActiveProfiles();
        for (String profile : profiles) {
            if ("prod".equals(profile) || "production".equals(profile)) {
                return true;
            }
        }
        return false;
    }

    private boolean isPotentialAttack(Exception ex, HttpServletRequest request) {
        // Detect potential SQL injection or path traversal attempts
        String uri = request.getRequestURI();
        String queryString = request.getQueryString();

        if (uri.contains("..") || uri.contains(";") || uri.contains("'")) {
            return true;
        }
        if (queryString != null && (queryString.contains("UNION") || 
                queryString.contains("SELECT") || queryString.contains("<script"))) {
            return true;
        }
        return ex instanceof NumberFormatException && 
               request.getParameter("id") != null && 
               request.getParameter("id").length() > 20;
    }

    private int determineStatusCode(Exception ex) {
        if (ex instanceof IllegalArgumentException || 
            ex instanceof NumberFormatException) {
            return HttpStatus.BAD_REQUEST.value();
        }
        return HttpStatus.INTERNAL_SERVER_ERROR.value();
    }

    private String getClientIp(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private String sanitizeFieldName(String field) {
        // Only allow alphanumeric and underscore
        return field.replaceAll("[^a-zA-Z0-9_]", "");
    }

    private String getStackTraceSummary(Exception ex, int maxFrames) {
        StringBuilder sb = new StringBuilder();
        StackTraceElement[] frames = ex.getStackTrace();
        int limit = Math.min(frames.length, maxFrames);
        for (int i = 0; i < limit; i++) {
            sb.append(frames[i].toString()).append("\n");
        }
        return sb.toString();
    }
}

class ErrorResponse {
    private int statusCode;
    private String message;
    private String referenceId;
    private String timestamp;
    private String details; // Only populated in non-production

    public ErrorResponse(int statusCode, String message, String referenceId, String timestamp) {
        this(statusCode, message, referenceId, timestamp, null);
    }

    public ErrorResponse(int statusCode, String message, String referenceId, 
            String timestamp, String details) {
        this.statusCode = statusCode;
        this.message = message;
        this.referenceId = referenceId;
        this.timestamp = timestamp;
        this.details = details;
    }

    // Getters
    public int getStatusCode() { return statusCode; }
    public String getMessage() { return message; }
    public String getReferenceId() { return referenceId; }
    public String getTimestamp() { return timestamp; }
    public String getDetails() { return details; }
}
```

