	// This is set by authentication middleware
	if userID, ok := r.Context().Value("authenticated_user_id").(int); ok {
		return userID
	}
	return 0
}

func isAdmin(userID int) bool {
	var role string
	err := db.QueryRow("SELECT role FROM users WHERE id = $1", userID).Scan(&role)
	return err == nil && role == "admin"
}
