**Key Security Controls**:
- **Duplicate parameter detection**: Explicitly check for and reject multiple values for sensitive parameters
- **Trusted identity source**: Get user identity from validated session/JWT, never from untrusted request parameters
- **Consistent parameter handling**: Use single source of truth for authorization decisions
- **Security logging**: Log parameter pollution attempts for incident detection

When legitimate functionality requires array parameters, you need strict validation and explicit handling to prevent parameter pollution attacks.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"regexp"
	"strconv"
	"strings"
	"time"

	_ "github.com/lib/pq"
)

type Document struct {
	ID      int    `json:"id"`
	Title   string `json:"title"`
	OwnerID int    `json:"owner_id"`
}

type APIResponse struct {
	Success   bool        `json:"success"`
	Data      interface{} `json:"data,omitempty"`
	Error     string      `json:"error,omitempty"`
	RequestID string      `json:"request_id"`
}

const (
	MaxArrayParams     = 100
	MaxParamValueLen   = 50
	RateLimitPerMinute = 60
)

var (
	db             *sql.DB
	auditLogger    *log.Logger
	securityLogger *log.Logger
	idArrayRegex   = regexp.MustCompile(`^[0-9,]+$`)
