// ParameterValidator provides safe parameter extraction with pollution detection
type ParameterValidator struct {
	request    *http.Request
	requestID  string
	violations []string
}

func NewParameterValidator(r *http.Request, requestID string) *ParameterValidator {
	return &ParameterValidator{
		request:   r,
		requestID: requestID,
	}
}

// GetSingleParam extracts a parameter that MUST be singular
func (pv *ParameterValidator) GetSingleParam(name string) (string, bool) {
	values := pv.request.URL.Query()[name]

	if len(values) == 0 {
		return "", true // Not present, which may be valid
	}

	if len(values) > 1 {
		pv.violations = append(pv.violations,
			fmt.Sprintf("parameter '%s' appeared %d times (expected 1)", name, len(values)))
		return "", false
	}

	value := strings.TrimSpace(values[0])
	if len(value) > MaxParamValueLen {
		pv.violations = append(pv.violations,
			fmt.Sprintf("parameter '%s' exceeds max length", name))
		return "", false
	}

	return value, true
}

// GetArrayParam extracts array params with strict bracket notation: ids[]=1&ids[]=2
func (pv *ParameterValidator) GetArrayParam(name string) ([]string, bool) {
	// CRITICAL: Only accept explicit array notation to prevent pollution
	arrayKey := name + "[]"

	// Check for pollution attempts via non-array key
	if values := pv.request.URL.Query()[name]; len(values) > 0 {
		pv.violations = append(pv.violations,
			fmt.Sprintf("parameter '%s' must use array notation '%s'", name, arrayKey))
		return nil, false
	}

	values := pv.request.URL.Query()[arrayKey]

	if len(values) > MaxArrayParams {
		pv.violations = append(pv.violations,
			fmt.Sprintf("array parameter '%s' exceeds max count %d", name, MaxArrayParams))
		return nil, false
	}

	// Validate each value
	for i, v := range values {
		if len(v) > MaxParamValueLen {
			pv.violations = append(pv.violations,
				fmt.Sprintf("array parameter '%s[%d]' exceeds max length", name, i))
			return nil, false
		}
	}

	return values, true
}

// GetIntArray extracts and validates integer array parameters
func (pv *ParameterValidator) GetIntArray(name string) ([]int, bool) {
	strValues, ok := pv.GetArrayParam(name)
	if !ok {
		return nil, false
	}

	if len(strValues) == 0 {
		return []int{}, true
	}

	result := make([]int, 0, len(strValues))
	seen := make(map[int]bool)

	for _, s := range strValues {
		val, err := strconv.Atoi(strings.TrimSpace(s))
		if err != nil || val <= 0 {
			pv.violations = append(pv.violations,
				fmt.Sprintf("invalid integer value '%s' in array '%s'", s, name))
			return nil, false
		}

		// Deduplicate to prevent amplification attacks
		if !seen[val] {
			seen[val] = true
			result = append(result, val)
		}
	}

	return result, true
}

func (pv *ParameterValidator) HasViolations() bool {
	return len(pv.violations) > 0
}

func (pv *ParameterValidator) LogViolations(remoteAddr string) {
	if len(pv.violations) > 0 {
		securityLogger.Printf("PARAM_POLLUTION request_id=%s ip=%s violations=%v",
			pv.requestID, remoteAddr, pv.violations)
	}
}

// PRODUCTION HANDLER: Get documents filtered by IDs with full protection
func getDocumentsHandler(w http.ResponseWriter, r *http.Request) {
