// Authorization is enforced AT THE DATABASE LEVEL - user can only see their documents
func fetchAuthorizedDocuments(ctx context.Context, userID int, documentIDs []int, page int) ([]Document, error) {
	limit := 50
	offset := (page - 1) * limit

	var query string
	var args []interface{}

	if len(documentIDs) == 0 {
		// No filter - get all user's documents
		query = `
			SELECT id, title, owner_id 
			FROM documents 
			WHERE owner_id = $1 
			ORDER BY id 
			LIMIT $2 OFFSET $3`
		args = []interface{}{userID, limit, offset}
	} else {
		// Filter by IDs - but ONLY return user's documents (authorization enforced)
		placeholders := make([]string, len(documentIDs))
		args = make([]interface{}, 0, len(documentIDs)+3)
		args = append(args, userID)

		for i, id := range documentIDs {
			placeholders[i] = fmt.Sprintf("$%d", i+2)
			args = append(args, id)
		}

		args = append(args, limit, offset)

		query = fmt.Sprintf(`
			SELECT id, title, owner_id 
			FROM documents 
			WHERE owner_id = $1 AND id IN (%s)
			ORDER BY id 
			LIMIT $%d OFFSET $%d`,
			strings.Join(placeholders, ","),
			len(documentIDs)+2,
			len(documentIDs)+3)
	}

	rows, err := db.QueryContext(ctx, query, args...)
	if err != nil {
		return nil, fmt.Errorf("query failed: %w", err)
	}
	defer rows.Close()

	var documents []Document
	for rows.Next() {
		var doc Document
		if err := rows.Scan(&doc.ID, &doc.Title, &doc.OwnerID); err != nil {
			return nil, fmt.Errorf("scan failed: %w", err)
		}
		documents = append(documents, doc)
	}

	return documents, rows.Err()
}

func getAuthenticatedUserIDFromContext(r *http.Request) int {
	if userID, ok := r.Context().Value("authenticated_user_id").(int); ok {
		return userID
	}
	return 0
}

func generateRequestID() string {
	return fmt.Sprintf("%d", time.Now().UnixNano())
}

func respondError(w http.ResponseWriter, message string, code int, requestID string) {
	w.WriteHeader(code)
	json.NewEncoder(w).Encode(APIResponse{
		Success:   false,
		Error:     message,
		RequestID: requestID,
	})
}

func respondSuccess(w http.ResponseWriter, data interface{}, requestID string) {
	json.NewEncoder(w).Encode(APIResponse{
		Success:   true,
		Data:      data,
		RequestID: requestID,
	})
}
