- Operations on file descriptors maintain identity consistency

Excellent question! Complex multi-step file operations require careful design to prevent TOCTOU attacks. The key principle is: open once, operate through file descriptors, and use file locking for read-modify-write scenarios.

**PRODUCTION PATTERN**:

```javascript
const fs = require('fs');
const path = require('path');
const crypto = require('crypto');
const { promisify } = require('util');
const { EventEmitter } = require('events');

// Promisify fs functions
const fsOpen = promisify(fs.open);
const fsRead = promisify(fs.read);
const fsWrite = promisify(fs.write);
const fsFstat = promisify(fs.fstat);
const fsClose = promisify(fs.close);
const fsFtruncate = promisify(fs.ftruncate);
const fsFsync = promisify(fs.fsync);

class SecureFileHandler extends EventEmitter {
  constructor(options = {}) {
    super();
    this.baseDir = options.baseDir || '/var/app/data';
    this.lockTimeout = options.lockTimeout || 30000;
    this.activeLocks = new Map();
  }

  /**
   * Secure file read with permission check - TOCTOU-safe
   * Opens file first, then checks permissions on the opened file
   */
  async secureRead(filePath, userId) {
    const sanitizedPath = this.sanitizePath(filePath);
    let fd = null;

    try {
      // Step 1: Open file with O_NOFOLLOW to prevent symlink attacks
      fd = await fsOpen(sanitizedPath, 
        fs.constants.O_RDONLY | fs.constants.O_NOFOLLOW);

      // Step 2: Check permissions on the OPENED file (not path)
      const stats = await fsFstat(fd);

      // Verify file type - must be regular file
      if (!stats.isFile()) {
        throw new SecureFileError('NOT_REGULAR_FILE', 'Target is not a regular file');
      }

      // Check ownership/permissions
      if (!this.checkPermissions(stats, userId, 'read')) {
        this.emit('security_violation', {
          type: 'unauthorized_read',
          userId,
          filePath: sanitizedPath,
          fileOwner: stats.uid
        });
        throw new SecureFileError('UNAUTHORIZED', 'Permission denied');
      }

      // Step 3: Read from file descriptor
      const buffer = Buffer.alloc(stats.size);
      const { bytesRead } = await fsRead(fd, buffer, 0, stats.size, 0);

      this.emit('file_read', { userId, filePath: sanitizedPath, size: bytesRead });

      return buffer.slice(0, bytesRead);
    } catch (err) {
      if (err.code === 'ELOOP') {
        throw new SecureFileError('SYMLINK_ATTACK', 'Symlink detected');
      }
      throw err;
    } finally {
      if (fd !== null) {
        await fsClose(fd).catch(() => {});
      }
    }
  }

  /**
   * Atomic read-modify-write with advisory file locking
   * Prevents concurrent modifications from corrupting data
   */
  async atomicUpdate(filePath, userId, transformer) {
    const sanitizedPath = this.sanitizePath(filePath);
    const lockId = crypto.randomUUID();
    let fd = null;
    let locked = false;

    try {
      // Acquire exclusive lock
      await this.acquireLock(sanitizedPath, lockId);
      locked = true;

      // Open for read/write
      fd = await fsOpen(sanitizedPath, 
        fs.constants.O_RDWR | fs.constants.O_NOFOLLOW);

      // Verify permissions on opened file
      const stats = await fsFstat(fd);
      if (!this.checkPermissions(stats, userId, 'write')) {
        throw new SecureFileError('UNAUTHORIZED', 'Write permission denied');
      }

      // Read current content through file descriptor
      const buffer = Buffer.alloc(stats.size);
      if (stats.size > 0) {
        await fsRead(fd, buffer, 0, stats.size, 0);
      }
      const currentContent = buffer.toString('utf8');

      // Apply transformation
      const newContent = await transformer(currentContent);
      const newBuffer = Buffer.from(newContent, 'utf8');

      // Atomic write: truncate and write to same fd
      await fsFtruncate(fd, 0);
      await fsWrite(fd, newBuffer, 0, newBuffer.length, 0);

      // Ensure data is flushed to disk
      await fsFsync(fd);

      this.emit('file_updated', { 
        userId, 
        filePath: sanitizedPath, 
        oldSize: stats.size, 
        newSize: newBuffer.length 
      });

      return newContent;
    } finally {
      if (fd !== null) {
        await fsClose(fd).catch(() => {});
      }
      if (locked) {
        this.releaseLock(sanitizedPath, lockId);
      }
    }
  }

  /**
   * Safe file replacement using atomic rename
   * Writes to temp file, then atomically renames
   */
  async atomicReplace(filePath, userId, content) {
    const sanitizedPath = this.sanitizePath(filePath);
    const tempPath = `${sanitizedPath}.${crypto.randomUUID()}.tmp`;
    let tempFd = null;

    try {
      // Check write permission on target (if exists)
      try {
        const existingFd = await fsOpen(sanitizedPath, 
          fs.constants.O_RDONLY | fs.constants.O_NOFOLLOW);
        try {
          const stats = await fsFstat(existingFd);
          if (!this.checkPermissions(stats, userId, 'write')) {
            throw new SecureFileError('UNAUTHORIZED', 'Permission denied');
          }
        } finally {
          await fsClose(existingFd);
        }
      } catch (err) {
        if (err.code !== 'ENOENT') throw err;
        // File doesn't exist - check directory permissions
      }

      // Create temp file with exclusive flag
      tempFd = await fsOpen(tempPath, 
        fs.constants.O_CREAT | fs.constants.O_EXCL | fs.constants.O_WRONLY, 
        0o644);

      // Write content
      const buffer = Buffer.from(content, 'utf8');
      await fsWrite(tempFd, buffer, 0, buffer.length, 0);
      await fsFsync(tempFd);
      await fsClose(tempFd);
      tempFd = null;

      // Atomic rename
      await promisify(fs.rename)(tempPath, sanitizedPath);

      this.emit('file_replaced', { userId, filePath: sanitizedPath });
    } catch (err) {
      // Cleanup temp file on error
      if (tempFd !== null) {
        await fsClose(tempFd).catch(() => {});
      }
      await promisify(fs.unlink)(tempPath).catch(() => {});
      throw err;
    }
  }

  /**
   * Advisory locking mechanism to prevent concurrent access
   */
  async acquireLock(filePath, lockId) {
    const start = Date.now();

    while (this.activeLocks.has(filePath)) {
      if (Date.now() - start > this.lockTimeout) {
        throw new SecureFileError('LOCK_TIMEOUT', 'Failed to acquire lock');
      }
      await new Promise(resolve => setTimeout(resolve, 100));
    }

    this.activeLocks.set(filePath, { lockId, timestamp: Date.now() });
  }

  releaseLock(filePath, lockId) {
    const lock = this.activeLocks.get(filePath);
    if (lock && lock.lockId === lockId) {
      this.activeLocks.delete(filePath);
    }
  }

  sanitizePath(filePath) {
    const basename = path.basename(filePath);
    const sanitized = basename.replace(/[^a-zA-Z0-9._-]/g, '');

    if (!sanitized || sanitized.startsWith('.')) {
      throw new SecureFileError('INVALID_PATH', 'Invalid filename');
    }

    const fullPath = path.join(this.baseDir, sanitized);
    const realBase = fs.realpathSync(this.baseDir);

    // Prevent directory traversal
    if (!fullPath.startsWith(realBase)) {
      throw new SecureFileError('PATH_TRAVERSAL', 'Path traversal detected');
    }

    return fullPath;
  }

  checkPermissions(stats, userId, operation) {
    // File owner has full access
    if (stats.uid === userId) return true;

    // Check group permissions
    const mode = stats.mode;
    if (operation === 'read') {
      return (mode & fs.constants.S_IROTH) !== 0;
    }
    if (operation === 'write') {
      return (mode & fs.constants.S_IWOTH) !== 0;
    }
    return false;
  }
}

class SecureFileError extends Error {
  constructor(code, message) {
    super(message);
    this.code = code;
    this.name = 'SecureFileError';
  }
}

