app.get('/api/files/:filename', async (req, res) => {
  try {
    const content = await fileHandler.secureRead(
      req.params.filename, 
      req.user.uid
    );
    res.send(content);
  } catch (err) {
    if (err.code === 'UNAUTHORIZED') {
      return res.status(403).json({ error: 'Access denied' });
    }
    res.status(500).json({ error: 'Read failed' });
  }
});

app.put('/api/files/:filename', async (req, res) => {
  try {
    await fileHandler.atomicReplace(
      req.params.filename,
      req.user.uid,
      req.body.content
    );
    res.json({ success: true });
  } catch (err) {
    if (err.code === 'UNAUTHORIZED') {
      return res.status(403).json({ error: 'Access denied' });
    }
    res.status(500).json({ error: 'Write failed' });
  }
});

module.exports = { SecureFileHandler, SecureFileError };
```

**Defense in Depth Layers**:

1. **Open-then-check pattern** - Always open file first, then check permissions on the open file descriptor:
```javascript
// WRONG: Check path, then open
fs.accessSync(path, fs.constants.R_OK);  // Check
const data = fs.readFileSync(path);       // Use - TOCTOU!

// RIGHT: Open, then check descriptor
const fd = fs.openSync(path, 'r');        // Open
const stats = fs.fstatSync(fd);           // Check on fd
const data = fs.readFileSync(fd);         // Use same fd
```

2. **O_NOFOLLOW for symlink protection**:
```javascript
// Prevents attacker from substituting symlink
const fd = await fsOpen(path, fs.constants.O_RDONLY | fs.constants.O_NOFOLLOW);
// Throws ELOOP if path is symlink
```

3. **Atomic operations using rename**:
```javascript
// Write to temp, then atomic rename
fs.writeFileSync(tempPath, content);
fs.renameSync(tempPath, targetPath);  // Atomic on same filesystem
```

**Additional Protections**:
- **File locking**: Prevents concurrent modifications in multi-process environments
- **fsync()**: Ensures data durability before reporting success
- **O_EXCL**: Atomic file creation that fails if file exists
- **Audit logging**: All file operations logged with user context
- **Path canonicalization**: Resolve symlinks in base directory, block traversal
- **Type checking**: Verify target is regular file, not directory/device/socket

