  // Get immutable original data
  const originalData = await workflowEngine.getWorkflowData(workflowId, token);
  const nextState = originalData.total > APPROVAL_THRESHOLD ? 'PENDING_APPROVAL' : 'PAYMENT_PENDING';

  const result = await workflowEngine.transition(workflowId, token, 'CART_REVIEWED', userId);
  if (!result.success) {
    return res.status(403).json({ error: result.error });
  }

