```rust
use std::env;
use std::time::Duration;
use std::collections::HashMap;
use std::error::Error;

use postgres::{Client, NoTls, Error as PgError};

#[derive(Debug)]
struct SearchFilters {
    username: Option<String>,
    email_domain: Option<String>,
    min_id: Option<i32>,
    limit: i64,
    offset: i64,
}

fn validate_filters(mut filters: SearchFilters) -> Result<SearchFilters, &'static str> {
    // Enforce sane pagination bounds
    if filters.limit <= 0 || filters.limit > 100 {
        filters.limit = 50; // default safe page size
    }
    if filters.offset < 0 {
        filters.offset = 0;
    }

    if let Some(ref u) = filters.username {
        if u.len() < 3 || u.len() > 32 {
            return Err("username length out of range");
        }
        if !u.chars().all(|c| c.is_ascii_alphanumeric() || c == '_' || c == '-') {
            return Err("username has invalid characters");
        }
    }

    if let Some(ref d) = filters.email_domain {
        if d.len() > 64 || !d.chars().all(|c| c.is_ascii_alphanumeric() || c == '.' || c == '-') {
            return Err("invalid email domain");
        }
    }

    Ok(filters)
}

fn build_search_query(filters: &SearchFilters) -> (String, Vec<Box<dyn postgres::types::ToSql + Sync>>) {
    let mut base = String::from("SELECT id, username, email FROM users WHERE 1=1");
    let mut params: Vec<Box<dyn postgres::types::ToSql + Sync>> = Vec::new();
    let mut index: i32 = 1;

    if let Some(ref u) = filters.username {
        base.push_str(&format!(" AND username ILIKE ${}", index));
        params.push(Box::new(format!("%{}%", u)));
        index += 1;
    }

    if let Some(ref d) = filters.email_domain {
        base.push_str(&format!(" AND email ILIKE ${}", index));
        params.push(Box::new(format!("%@{}", d)));
        index += 1;
    }

    if let Some(min_id) = filters.min_id {
        base.push_str(&format!(" AND id >= ${}", index));
        params.push(Box::new(min_id));
        index += 1;
    }

    // ORDER BY and pagination clauses must be fixed, not user-controlled
    base.push_str(&format!(" ORDER BY id ASC LIMIT ${} OFFSET ${}", index, index + 1));
    params.push(Box::new(filters.limit));
    params.push(Box::new(filters.offset));

    (base, params)
}

fn execute_search(client: &mut Client, filters: SearchFilters) -> Result<(), PgError> {
    let (sql, params) = build_search_query(&filters);

    // Structured audit log (here just println!; in real apps use a logging crate)
    println!(
        "[AUDIT] user_search filters={:?} sql_template=\"{}\"", 
        filters, sql
    );

    let param_refs: Vec<&(dyn postgres::types::ToSql + Sync)> =
        params.iter().map(|b| &**b as _).collect();

    let rows = client.query(&sql, &param_refs)?;

    for row in rows {
        let id: i32 = row.get("id");
        let username: String = row.get("username");
        let email: String = row.get("email");
        println!("[RESULT] {} ({}), {}", username, id, email);
    }

    Ok(())
}

fn main() -> Result<(), Box<dyn Error>> {
