```typescript
import express, { Request, Response, NextFunction } from 'express';
import helmet from 'helmet';

const app = express();
const PORT = process.env.PORT || 3000;
const NODE_ENV = process.env.NODE_ENV || 'development';

// Primary defense: use helmet to set sane defaults for security headers
app.disable('x-powered-by');

// Configure Helmet with explicit, strict policies
app.use(
  helmet({
    contentSecurityPolicy: {
      useDefaults: true,
      directives: {
        // Allow scripts only from self (and disallow inline/eval by default)
        "script-src": ["'self'"],
        // Allow styles only from self (can add 'https://fonts.googleapis.com' if needed)
        "style-src": ["'self'"],
        // Default: only same origin
        "default-src": ["'self'"],
        // Disallow framing to prevent clickjacking
        "frame-ancestors": ["'none'"],
      },
    },
    frameguard: { action: 'deny' },
    referrerPolicy: { policy: 'no-referrer' },
    hsts: NODE_ENV === 'production'
      ? { maxAge: 31536000, includeSubDomains: true, preload: true }
      : false,
  })
);

app.get('/api/profile', (req: Request, res: Response) => {
  const username = String(req.query.username || 'Guest')
    .replace(/[^a-zA-Z0-9_-]/g, ''); // basic output encoding/validation

  res.type('html').send(`
    <html>
      <head><title>Profile</title></head>
      <body>
        <h1>Welcome ${username}</h1>
      </body>
    </html>
  `);
});

// Secure error handler: does not leak stack traces and maintains headers
app.use((err: Error, _req: Request, res: Response, _next: NextFunction) => {
  console.error('Error:', err.message);
  if (NODE_ENV === 'production') {
    res.status(500).json({ error: 'Internal Server Error' });
  } else {
    res.status(500).json({ error: err.message });
  }
});

app.listen(PORT, () => {
  console.log(`Server listening on http://localhost:${PORT} in ${NODE_ENV} mode`);
});
```

**Key Security Controls**:
- Helmet-based security headers: Enforces `CSP`, `X-Frame-Options`/`frame-ancestors`, `Referrer-Policy`, and optionally `HSTS` to mitigate XSS, clickjacking, and downgrade attacks.
- Environment-aware configuration: Enables strict `HSTS` only in production to avoid issues during local development and testing.
- Input validation/output encoding: Sanitizes `username` before embedding into HTML, reducing XSS risk even if CSP is misconfigured later.

In production, you typically want environment-specific security header profiles, structured configuration, strong logging, and monitoring so you can safely iterate (e.g., CSP report-only first, then enforce).

