import express, { Request, Response, NextFunction } from 'express';
import helmet from 'helmet';
import morgan from 'morgan';
import fs from 'fs';
import path from 'path';

const app = express();
const NODE_ENV = (process.env.NODE_ENV || 'development').toLowerCase();
const PORT = process.env.PORT ? Number(process.env.PORT) : 3000;

// Centralized configuration for headers per environment
type SecurityConfig = {
  enableHsts: boolean;
  cspReportOnly: boolean;
};

const securityConfig: Record<string, SecurityConfig> = {
  development: {
    enableHsts: false,
    cspReportOnly: true, // easier CSP debugging in dev
  },
  staging: {
    enableHsts: false,
    cspReportOnly: true, // collect reports before enforcing
  },
  production: {
    enableHsts: true,
    cspReportOnly: false,
  },
};

const currentSecurity = securityConfig[NODE_ENV] || securityConfig.development;

// Request logging to file for audit and incident response
const logDir = path.join(__dirname, 'logs');
if (!fs.existsSync(logDir)) {
  fs.mkdirSync(logDir);
}
const accessLogStream = fs.createWriteStream(path.join(logDir, 'access.log'), {
  flags: 'a',
});

app.use(morgan('combined', { stream: accessLogStream }));
app.use(express.json());

app.disable('x-powered-by');

// CSP configuration with report endpoint
const cspDirectives: helmet.ContentSecurityPolicyOptions['directives'] = {
  "default-src": ["'self'"],
  "script-src": ["'self'"],
  "style-src": ["'self'", 'https://fonts.googleapis.com'],
  "font-src": ["'self'", 'https://fonts.gstatic.com'],
  "img-src": ["'self'", 'data:'],
  "connect-src": ["'self'"],
  "frame-ancestors": ["'none'"],
  // report-uri is deprecated in favor of report-to, but some browsers still honor it
  "report-uri": ['/csp-report'],
};

// Helmet with environment-aware CSP and HSTS
app.use(
  helmet({
    contentSecurityPolicy: {
      useDefaults: true,
      directives: cspDirectives,
      reportOnly: currentSecurity.cspReportOnly,
    },
    frameguard: { action: 'deny' },
    referrerPolicy: { policy: 'no-referrer' },
    xssFilter: true,
    noSniff: true,
    hsts: currentSecurity.enableHsts
      ? { maxAge: 31536000, includeSubDomains: true, preload: true }
      : false,
  })
);

// CSP violation report endpoint for monitoring
app.post('/csp-report', (req: Request, res: Response) => {
  console.warn('CSP Violation Report:', JSON.stringify(req.body));
  // In a real app, forward to SIEM/log aggregation here
  res.status(204).end();
});

// Example secured route
