**Attack Scenario**:
```text
1. Attacker compromises victim's old email backup from 6 months ago
2. Finds password reset link: https://app.com/reset?token=abc123-def456
3. Token still valid because it never expires
4. Attacker uses token to reset password and takes over account
5. Token can be reused multiple times since it's never invalidated
```

**Why This Is Dangerous**:
- Tokens without expiration can be used months or years after generation
- Tokens not invalidated after use allow replay attacks
- Database leaks or email compromises expose permanently valid credentials
- No rate limiting allows brute-force token guessing
- Password stored in plaintext enables mass credential theft

**SECURE VERSION**:

```java
import java.sql.*;
import java.security.SecureRandom;
import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.Base64;
import javax.crypto.SecretKeyFactory;
import javax.crypto.spec.PBEKeySpec;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecurePasswordResetService {
    private static final Logger logger = LoggerFactory.getLogger(SecurePasswordResetService.class);
    private static final int TOKEN_EXPIRY_MINUTES = 15;
    private static final int TOKEN_LENGTH_BYTES = 32;
    private static final SecureRandom secureRandom = new SecureRandom();

    private final DataSource dataSource;

    public SecurePasswordResetService(DataSource dataSource) {
        this.dataSource = dataSource;
    }

    public String generateResetToken(String email) throws SQLException {
        // Generate cryptographically secure token
        byte[] tokenBytes = new byte[TOKEN_LENGTH_BYTES];
        secureRandom.nextBytes(tokenBytes);
        String token = Base64.getUrlEncoder().withoutPadding().encodeToString(tokenBytes);

        // Calculate expiration timestamp
        Timestamp expiresAt = Timestamp.from(
            Instant.now().plus(TOKEN_EXPIRY_MINUTES, ChronoUnit.MINUTES)
        );

        try (Connection conn = dataSource.getConnection()) {
            // Invalidate any existing tokens for this email first
            invalidateExistingTokens(conn, email);

            // Store token with expiration and single-use flag
            String sql = "INSERT INTO password_reset_tokens (email, token_hash, expires_at, used) VALUES (?, ?, ?, false)";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, email);
            stmt.setString(2, hashToken(token)); // Store hash, not plaintext
            stmt.setTimestamp(3, expiresAt);
            stmt.executeUpdate();

            logger.info("Password reset token generated for email: {}", maskEmail(email));
        }
        return token;
    }

    public boolean resetPassword(String token, String newPassword) throws SQLException {
        try (Connection conn = dataSource.getConnection()) {
            conn.setAutoCommit(false);

            try {
                // Verify token: must exist, not expired, not used
                String sql = "SELECT id, email FROM password_reset_tokens " +
                             "WHERE token_hash = ? AND expires_at > NOW() AND used = false " +
                             "FOR UPDATE"; // Lock row to prevent race conditions
                PreparedStatement stmt = conn.prepareStatement(sql);
                stmt.setString(1, hashToken(token));
                ResultSet rs = stmt.executeQuery();

                if (rs.next()) {
                    long tokenId = rs.getLong("id");
                    String email = rs.getString("email");

                    // Immediately mark token as used (single-use)
                    markTokenUsed(conn, tokenId);

                    // Update password with secure hash
                    updatePasswordSecurely(conn, email, newPassword);

                    conn.commit();
                    logger.info("Password successfully reset for: {}", maskEmail(email));
                    return true;
                } else {
                    logger.warn("Invalid or expired reset token attempted");
                    conn.rollback();
                    return false;
                }
            } catch (SQLException e) {
                conn.rollback();
                throw e;
            }
        }
    }

    private void invalidateExistingTokens(Connection conn, String email) throws SQLException {
        String sql = "UPDATE password_reset_tokens SET used = true WHERE email = ? AND used = false";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setString(1, email);
        stmt.executeUpdate();
    }

    private void markTokenUsed(Connection conn, long tokenId) throws SQLException {
        String sql = "UPDATE password_reset_tokens SET used = true, used_at = NOW() WHERE id = ?";
        PreparedStatement stmt = conn.prepareStatement(sql);
        stmt.setLong(1, tokenId);
        stmt.executeUpdate();
    }

    private String hashToken(String token) {
        // Use SHA-256 for token storage (tokens are high-entropy)
        try {
            java.security.MessageDigest digest = java.security.MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(token.getBytes(java.nio.charset.StandardCharsets.UTF_8));
            return Base64.getEncoder().encodeToString(hash);
        } catch (Exception e) {
            throw new RuntimeException("Failed to hash token", e);
        }
    }

    private String maskEmail(String email) {
        int atIndex = email.indexOf('@');
        if (atIndex > 2) {
            return email.substring(0, 2) + "***" + email.substring(atIndex);
        }
        return "***";
    }

    private void updatePasswordSecurely(Connection conn, String email, String password) throws SQLException {
