import java.sql.*;
import java.security.SecureRandom;
import java.time.Instant;
import java.time.temporal.ChronoUnit;
import java.util.Base64;
import java.util.concurrent.*;
import javax.sql.DataSource;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Service;
import org.springframework.transaction.annotation.Transactional;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Counter;
import io.github.bucket4j.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import at.favre.lib.crypto.bcrypt.BCrypt;

@Service
public class ProductionPasswordResetService {
    private static final Logger logger = LoggerFactory.getLogger(ProductionPasswordResetService.class);
    private static final Logger securityAuditLog = LoggerFactory.getLogger("SECURITY_AUDIT");

    // Configuration - externalize in production
    private static final int TOKEN_EXPIRY_MINUTES = 15;
    private static final int TOKEN_LENGTH_BYTES = 32;
    private static final int MAX_ACTIVE_TOKENS_PER_EMAIL = 3;
    private static final int MAX_REQUESTS_PER_IP_PER_HOUR = 10;
    private static final int MAX_REQUESTS_PER_EMAIL_PER_HOUR = 5;
    private static final int BCRYPT_COST = 12;

    private final DataSource dataSource;
    private final SecureRandom secureRandom;
    private final MeterRegistry meterRegistry;
    private final Counter resetRequestCounter;
    private final Counter resetSuccessCounter;
    private final Counter resetFailureCounter;
    private final Counter rateLimitCounter;

    // Rate limiters: IP -> Bucket
    private final ConcurrentMap<String, Bucket> ipRateLimiters = new ConcurrentHashMap<>();
    private final ConcurrentMap<String, Bucket> emailRateLimiters = new ConcurrentHashMap<>();

    public ProductionPasswordResetService(DataSource dataSource, MeterRegistry meterRegistry) {
        this.dataSource = dataSource;
        this.secureRandom = new SecureRandom();
        this.meterRegistry = meterRegistry;

        // Initialize metrics
        this.resetRequestCounter = meterRegistry.counter("password_reset.requests");
        this.resetSuccessCounter = meterRegistry.counter("password_reset.success");
        this.resetFailureCounter = meterRegistry.counter("password_reset.failure");
        this.rateLimitCounter = meterRegistry.counter("password_reset.rate_limited");
    }

    @Transactional
    public PasswordResetResult requestPasswordReset(String email, String ipAddress, String userAgent) {
        resetRequestCounter.increment();

        // Defense Layer 1: Rate limiting by IP
        if (!checkIpRateLimit(ipAddress)) {
            rateLimitCounter.increment();
            securityAuditLog.warn("action=password_reset_rate_limited ip={} email={} reason=ip_limit",
                ipAddress, maskEmail(email));
            // Return success to prevent email enumeration
            return PasswordResetResult.success("If the email exists, a reset link has been sent.");
        }

        // Defense Layer 2: Rate limiting by email
        if (!checkEmailRateLimit(email)) {
            rateLimitCounter.increment();
            securityAuditLog.warn("action=password_reset_rate_limited ip={} email={} reason=email_limit",
                ipAddress, maskEmail(email));
            return PasswordResetResult.success("If the email exists, a reset link has been sent.");
        }

        try (Connection conn = dataSource.getConnection()) {
            // Defense Layer 3: Verify email exists (but don't leak this info)
            if (!emailExists(conn, email)) {
                // Log but return same message to prevent enumeration
                securityAuditLog.info("action=password_reset_unknown_email ip={} email={}",
                    ipAddress, maskEmail(email));
                // Add artificial delay to prevent timing attacks
                simulateProcessingDelay();
                return PasswordResetResult.success("If the email exists, a reset link has been sent.");
            }

            // Defense Layer 4: Limit active tokens per email
            int activeTokens = countActiveTokens(conn, email);
            if (activeTokens >= MAX_ACTIVE_TOKENS_PER_EMAIL) {
                securityAuditLog.warn("action=password_reset_max_tokens ip={} email={} active_tokens={}",
                    ipAddress, maskEmail(email), activeTokens);
                return PasswordResetResult.success("If the email exists, a reset link has been sent.");
            }

            // Generate secure token
            String token = generateSecureToken();
            Timestamp expiresAt = Timestamp.from(
                Instant.now().plus(TOKEN_EXPIRY_MINUTES, ChronoUnit.MINUTES)
            );

            // Store token with full audit trail
            String sql = "INSERT INTO password_reset_tokens " +
                "(email, token_hash, expires_at, used, created_at, request_ip, user_agent) " +
                "VALUES (?, ?, ?, false, NOW(), ?, ?)";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, email);
            stmt.setString(2, hashToken(token));
            stmt.setTimestamp(3, expiresAt);
            stmt.setString(4, ipAddress);
            stmt.setString(5, truncateUserAgent(userAgent));
            stmt.executeUpdate();

            securityAuditLog.info("action=password_reset_token_created ip={} email={} expires_at={}",
                ipAddress, maskEmail(email), expiresAt);

            // Send email asynchronously (implementation omitted)
            sendResetEmailAsync(email, token);

            return PasswordResetResult.success("If the email exists, a reset link has been sent.");

        } catch (SQLException e) {
            logger.error("Database error during password reset request", e);
            resetFailureCounter.increment();
            return PasswordResetResult.error("An error occurred. Please try again later.");
        }
    }

    @Transactional
    public PasswordResetResult resetPassword(String token, String newPassword, String ipAddress) {
        // Defense Layer 1: Validate password strength
        PasswordStrengthResult strengthResult = validatePasswordStrength(newPassword);
        if (!strengthResult.isValid()) {
            return PasswordResetResult.error(strengthResult.getMessage());
        }

        try (Connection conn = dataSource.getConnection()) {
            conn.setAutoCommit(false);

            try {
                // Find and lock valid token
                String sql = "SELECT id, email, request_ip FROM password_reset_tokens " +
                    "WHERE token_hash = ? AND expires_at > NOW() AND used = false " +
                    "FOR UPDATE SKIP LOCKED";
                PreparedStatement stmt = conn.prepareStatement(sql);
                stmt.setString(1, hashToken(token));
                ResultSet rs = stmt.executeQuery();

                if (!rs.next()) {
                    resetFailureCounter.increment();
                    securityAuditLog.warn("action=password_reset_invalid_token ip={}", ipAddress);
                    // Generic message prevents token enumeration
                    return PasswordResetResult.error("Invalid or expired reset link. Please request a new one.");
                }

                long tokenId = rs.getLong("id");
                String email = rs.getString("email");
                String originalIp = rs.getString("request_ip");

                // Defense Layer 2: Log if reset IP differs from request IP (potential attack indicator)
                if (!ipAddress.equals(originalIp)) {
                    securityAuditLog.warn("action=password_reset_ip_mismatch email={} request_ip={} reset_ip={}",
                        maskEmail(email), originalIp, ipAddress);
                }

                // Mark token as used immediately
                markTokenUsed(conn, tokenId, ipAddress);

                // Invalidate all other tokens for this email
                invalidateAllTokens(conn, email);

                // Hash and update password
                String passwordHash = BCrypt.withDefaults().hashToString(BCRYPT_COST, newPassword.toCharArray());
                updatePassword(conn, email, passwordHash);

                // Invalidate all existing sessions for this user
                invalidateUserSessions(conn, email);

                conn.commit();
                resetSuccessCounter.increment();

                securityAuditLog.info("action=password_reset_success email={} ip={}",
                    maskEmail(email), ipAddress);

                // Send notification email about password change
                sendPasswordChangedNotificationAsync(email, ipAddress);

                return PasswordResetResult.success("Password has been reset successfully. Please log in.");

            } catch (SQLException e) {
                conn.rollback();
                throw e;
            }
        } catch (SQLException e) {
            logger.error("Database error during password reset", e);
            resetFailureCounter.increment();
            return PasswordResetResult.error("An error occurred. Please try again later.");
        }
    }

    // Scheduled cleanup of expired tokens - runs every hour
    @Scheduled(fixedRate = 3600000)
    public void cleanupExpiredTokens() {
        logger.info("Starting expired token cleanup job");

        try (Connection conn = dataSource.getConnection()) {
            // Delete tokens expired more than 24 hours ago (keep recent for audit)
            String sql = "DELETE FROM password_reset_tokens WHERE expires_at < NOW() - INTERVAL '24 hours'";
            PreparedStatement stmt = conn.prepareStatement(sql);
            int deleted = stmt.executeUpdate();

            logger.info("Cleaned up {} expired password reset tokens", deleted);
            meterRegistry.counter("password_reset.cleanup.deleted").increment(deleted);

        } catch (SQLException e) {
            logger.error("Error cleaning up expired tokens", e);
        }

        // Clean up old rate limiter entries
        cleanupRateLimiters();
    }

    private boolean checkIpRateLimit(String ipAddress) {
        Bucket bucket = ipRateLimiters.computeIfAbsent(ipAddress, k -> 
            Bucket.builder()
                .addLimit(Bandwidth.classic(MAX_REQUESTS_PER_IP_PER_HOUR, Refill.greedy(MAX_REQUESTS_PER_IP_PER_HOUR, java.time.Duration.ofHours(1))))
                .build()
        );
        return bucket.tryConsume(1);
    }

    private boolean checkEmailRateLimit(String email) {
        String normalizedEmail = email.toLowerCase().trim();
        Bucket bucket = emailRateLimiters.computeIfAbsent(normalizedEmail, k -> 
            Bucket.builder()
                .addLimit(Bandwidth.classic(MAX_REQUESTS_PER_EMAIL_PER_HOUR, Refill.greedy(MAX_REQUESTS_PER_EMAIL_PER_HOUR, java.time.Duration.ofHours(1))))
                .build()
        );
        return bucket.tryConsume(1);
    }

    private void cleanupRateLimiters() {
        // Remove empty buckets to prevent memory leak
        ipRateLimiters.entrySet().removeIf(entry -> 
            entry.getValue().getAvailableTokens() >= MAX_REQUESTS_PER_IP_PER_HOUR);
        emailRateLimiters.entrySet().removeIf(entry -> 
            entry.getValue().getAvailableTokens() >= MAX_REQUESTS_PER_EMAIL_PER_HOUR);
    }

    private String generateSecureToken() {
        byte[] tokenBytes = new byte[TOKEN_LENGTH_BYTES];
        secureRandom.nextBytes(tokenBytes);
        return Base64.getUrlEncoder().withoutPadding().encodeToString(tokenBytes);
    }

    private String hashToken(String token) {
        try {
            java.security.MessageDigest digest = java.security.MessageDigest.getInstance("SHA-256");
            byte[] hash = digest.digest(token.getBytes(java.nio.charset.StandardCharsets.UTF_8));
            return Base64.getEncoder().encodeToString(hash);
        } catch (Exception e) {
            throw new RuntimeException("Failed to hash token", e);
        }
    }

    private String maskEmail(String email) {
        if (email == null) return "***";
        int atIndex = email.indexOf('@');
        if (atIndex > 2) {
            return email.substring(0, 2) + "***" + email.substring(atIndex);
        }
        return "***";
    }

    private void simulateProcessingDelay() {
        try {
            Thread.sleep(100 + secureRandom.nextInt(200));
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }

    // Additional helper methods omitted for brevity
    private boolean emailExists(Connection conn, String email) throws SQLException { return true; }
    private int countActiveTokens(Connection conn, String email) throws SQLException { return 0; }
