# app/security.py - Centralized security middleware
from flask import Flask, request, abort, Response
from functools import wraps
import logging
import hashlib
from pathlib import Path
from typing import Optional
import re

logger = logging.getLogger(__name__)

class FileSecurityMiddleware:
    """Middleware for secure file serving"""

    DANGEROUS_PATTERNS = [
        r'\.\.',           # Path traversal
        r'%2e%2e',         # URL-encoded traversal
        r'%252e',          # Double-encoded
        r'\.git',          # Git directory
        r'\.env',          # Environment files
        r'\.htaccess',     # Apache config
        r'\.htpasswd',     # Apache passwords
        r'web\.config',    # IIS config
        r'\.bak$',         # Backup files
        r'\.sql$',         # Database dumps
        r'\.log$',         # Log files
        r'__pycache__',    # Python cache
    ]

    def __init__(self, app: Flask):
        self.app = app
        self.blocked_pattern = re.compile(
            '|'.join(self.DANGEROUS_PATTERNS), 
            re.IGNORECASE
        )

    def is_dangerous_request(self, path: str) -> bool:
        """Check if request path contains dangerous patterns"""
        return bool(self.blocked_pattern.search(path))

    def validate_file_access(self, base_dir: Path, filename: str) -> Optional[Path]:
        """Validate and return safe file path or None"""
        # Check for dangerous patterns
        if self.is_dangerous_request(filename):
            logger.warning(
                f"Blocked dangerous pattern: {filename}",
                extra={'ip': request.remote_addr, 'path': filename}
            )
            return None

        # Resolve and validate path
        try:
            base = base_dir.resolve()
            target = (base / filename).resolve()

            # Must be under base directory
            if not target.is_relative_to(base):
                logger.warning(
                    f"Path traversal blocked: {filename} resolved to {target}",
                    extra={'ip': request.remote_addr}
                )
                return None

            # Must be a regular file (not directory, symlink, etc.)
            if not target.is_file():
                return None

            return target

        except (ValueError, RuntimeError, OSError) as e:
            logger.error(f"Path validation error: {e}")
            return None


def add_security_headers(response: Response) -> Response:
    """Add security headers to all responses"""
    response.headers['X-Content-Type-Options'] = 'nosniff'
    response.headers['X-Frame-Options'] = 'DENY'
    response.headers['X-XSS-Protection'] = '1; mode=block'
    response.headers['Content-Security-Policy'] = "default-src 'self'"
    response.headers['Referrer-Policy'] = 'strict-origin-when-cross-origin'
    response.headers['Permissions-Policy'] = 'geolocation=(), microphone=()'
    # Remove server identification
    response.headers.pop('Server', None)
    return response
