    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s'
)
logger = logging.getLogger(__name__)

def create_app(config_class=ProductionConfig):
    app = Flask(__name__)
    app.config.from_object(config_class())

    # Initialize rate limiter
    limiter = Limiter(
        app=app,
        key_func=get_remote_address,
        default_limits=["100 per hour"],
        storage_uri=app.config.get('RATELIMIT_STORAGE_URL', 'memory://')
    )

    # Initialize security middleware
    security = FileSecurityMiddleware(app)

    # Add security headers to all responses
    app.after_request(add_security_headers)

    @app.route('/files/<path:filename>')
    @limiter.limit("30 per minute")
    def serve_file(filename):
        """Serve individual files securely - NO directory listing"""
        # Validate file access
        safe_path = security.validate_file_access(
            app.config['UPLOAD_FOLDER'],
            filename
        )

        if safe_path is None:
            abort(404)  # Generic 404, don't reveal why

        # Validate extension
        if safe_path.suffix.lower() not in app.config['ALLOWED_EXTENSIONS']:
            logger.warning(f"Blocked extension: {safe_path.suffix}")
            abort(404)

        # Serve with correct content type, prevent MIME sniffing
        logger.info(
            f"File served: {filename}",
            extra={'ip': request.remote_addr, 'file': str(safe_path)}
        )

        return send_file(
            safe_path,
            as_attachment=False,
            download_name=safe_path.name
        )

    @app.errorhandler(404)
    def not_found(e):
        """Custom 404 - don't leak information"""
        return {'error': 'Not found'}, 404

    @app.errorhandler(500)
    def server_error(e):
        """Custom 500 - don't leak stack traces"""
        logger.error(f"Server error: {e}")
        return {'error': 'Internal server error'}, 500

    return app

if __name__ == '__main__':
    # Use gunicorn in production, not Flask dev server
    app = create_app()
    app.run(host='127.0.0.1', port=5000)
