**SECURE VERSION**:

```go
package main

import (
	"encoding/json"
	"errors"
	"io"
	"log"
	"net/http"
	"regexp"
)

// Strict allowlist of safe types - no executable types
type SafeMessageType string

const (
	MessageTypeUser    SafeMessageType = "user"
	MessageTypeProfile SafeMessageType = "profile"
)

// Only data-only structs, no methods that execute code
type User struct {
	ID   int    `json:"id"`
	Name string `json:"name"`
}

type Profile struct {
	UserID int    `json:"user_id"`
	Bio    string `json:"bio"`
}

type Message struct {
	Type    SafeMessageType `json:"type"`
	Payload json.RawMessage `json:"payload"`
}

const maxBodySize = 1024 * 1024 // 1MB limit

var validNamePattern = regexp.MustCompile(`^[a-zA-Z0-9\s]{1,100}$`)

func handleMessageSecure(w http.ResponseWriter, r *http.Request) {
	// SECURE: Limit request body size
	r.Body = http.MaxBytesReader(w, r.Body, maxBodySize)

	var msg Message
	decoder := json.NewDecoder(r.Body)
	decoder.DisallowUnknownFields() // Reject unexpected fields

	if err := decoder.Decode(&msg); err != nil {
		log.Printf("Decode error from %s: %v", r.RemoteAddr, err)
		http.Error(w, "Invalid request format", http.StatusBadRequest)
		return
	}

	// SECURE: Explicit type switch, not dynamic dispatch
	switch msg.Type {
	case MessageTypeUser:
		var user User
		if err := unmarshalAndValidate(msg.Payload, &user); err != nil {
			http.Error(w, "Invalid user data", http.StatusBadRequest)
			return
		}
		// Safe processing of validated data
		processUser(w, &user)

	case MessageTypeProfile:
		var profile Profile
		if err := unmarshalAndValidate(msg.Payload, &profile); err != nil {
			http.Error(w, "Invalid profile data", http.StatusBadRequest)
			return
		}
		processProfile(w, &profile)

	default:
		log.Printf("Unknown message type from %s: %s", r.RemoteAddr, msg.Type)
		http.Error(w, "Unknown message type", http.StatusBadRequest)
	}
}

func unmarshalAndValidate(data json.RawMessage, v interface{}) error {
	if len(data) > 10*1024 { // 10KB limit per payload
		return errors.New("payload too large")
	}

	decoder := json.NewDecoder(io.LimitReader(
		&jsonRawMessageReader{data: data},
		int64(len(data)),
	))
	decoder.DisallowUnknownFields()

	if err := decoder.Decode(v); err != nil {
		return err
	}

	return validateStruct(v)
}

type jsonRawMessageReader struct {
	data json.RawMessage
	pos  int
}

func (r *jsonRawMessageReader) Read(p []byte) (n int, err error) {
	if r.pos >= len(r.data) {
		return 0, io.EOF
	}
	n = copy(p, r.data[r.pos:])
	r.pos += n
	return n, nil
}

func validateStruct(v interface{}) error {
	switch val := v.(type) {
	case *User:
		if val.ID <= 0 || val.ID > 1000000 {
			return errors.New("invalid user ID")
		}
		if !validNamePattern.MatchString(val.Name) {
			return errors.New("invalid name format")
		}
	case *Profile:
		if val.UserID <= 0 {
			return errors.New("invalid user ID")
		}
		if len(val.Bio) > 500 {
			return errors.New("bio too long")
		}
	}
	return nil
}

func processUser(w http.ResponseWriter, u *User) {
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]string{"status": "user processed"})
}

func processProfile(w http.ResponseWriter, p *Profile) {
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]string{"status": "profile processed"})
}
```

**Key Security Controls**:
- **Explicit type allowlist**: Uses type switch instead of dynamic type registry - attacker cannot instantiate arbitrary types
- **Input size limits**: `MaxBytesReader` prevents memory exhaustion DoS attacks
- **DisallowUnknownFields**: Rejects payloads with unexpected fields that might indicate exploitation attempts
- **Post-deserialization validation**: Validates all field values against business rules after parsing

Plugin systems and binary serialization formats like `gob` are high-risk areas that require defense in depth. Gob can execute arbitrary code during deserialization through registered types' `GobDecode` methods. Here's a production-hardened approach.

**PRODUCTION PATTERN**:

```go
package main

import (
	"bytes"
	"context"
	"crypto/hmac"
	"crypto/sha256"
	"encoding/base64"
	"encoding/gob"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log"
	"net/http"
	"sync"
	"time"
)

// ===============================================
// LAYER 1: Cryptographic Integrity Verification
// ===============================================

type SecureSerializer struct {
	hmacKey []byte
	mu      sync.RWMutex
}

func NewSecureSerializer(key []byte) *SecureSerializer {
	if len(key) < 32 {
		panic("HMAC key must be at least 32 bytes")
	}
	return &SecureSerializer{hmacKey: key}
}

type SignedPayload struct {
	Data      []byte `json:"data"`
	Signature string `json:"sig"`
	Timestamp int64  `json:"ts"`
	Version   int    `json:"v"`
}

const (
	maxPayloadAge   = 5 * time.Minute
	currentVersion  = 1
	maxPayloadBytes = 512 * 1024 // 512KB
)

func (s *SecureSerializer) sign(data []byte) string {
	h := hmac.New(sha256.New, s.hmacKey)
	h.Write(data)
	return base64.StdEncoding.EncodeToString(h.Sum(nil))
}

func (s *SecureSerializer) verify(data []byte, signature string) bool {
	expected := s.sign(data)
	// Constant-time comparison to prevent timing attacks
	return hmac.Equal([]byte(expected), []byte(signature))
}

func (s *SecureSerializer) Serialize(v interface{}) ([]byte, error) {
	s.mu.RLock()
	defer s.mu.RUnlock()

	var buf bytes.Buffer
	enc := gob.NewEncoder(&buf)
	if err := enc.Encode(v); err != nil {
		return nil, fmt.Errorf("gob encode failed: %w", err)
	}

	data := buf.Bytes()
	if len(data) > maxPayloadBytes {
		return nil, errors.New("payload exceeds maximum size")
	}

	payload := SignedPayload{
		Data:      data,
		Signature: s.sign(data),
		Timestamp: time.Now().Unix(),
		Version:   currentVersion,
	}

	return json.Marshal(payload)
}

func (s *SecureSerializer) Deserialize(raw []byte, v interface{}) error {
	s.mu.RLock()
	defer s.mu.RUnlock()

	// Size check before any parsing
	if len(raw) > maxPayloadBytes+1024 { // Allow overhead for envelope
		return errors.New("payload too large")
	}

	var payload SignedPayload
	if err := json.Unmarshal(raw, &payload); err != nil {
		return fmt.Errorf("envelope parse failed: %w", err)
	}

	// LAYER 1: Version check
	if payload.Version != currentVersion {
		return fmt.Errorf("unsupported version: %d", payload.Version)
	}

	// LAYER 2: Timestamp freshness
	age := time.Since(time.Unix(payload.Timestamp, 0))
	if age > maxPayloadAge || age < -30*time.Second {
		return errors.New("payload expired or from future")
	}

	// LAYER 3: HMAC verification BEFORE deserialization
	if !s.verify(payload.Data, payload.Signature) {
		log.Printf("SECURITY: HMAC verification failed, potential tampering")
		return errors.New("signature verification failed")
	}

	// LAYER 4: Size check on inner data
	if len(payload.Data) > maxPayloadBytes {
		return errors.New("inner payload too large")
	}

	// Only deserialize AFTER signature verification
	dec := gob.NewDecoder(bytes.NewReader(payload.Data))
	if err := dec.Decode(v); err != nil {
		return fmt.Errorf("gob decode failed: %w", err)
	}

	return nil
}

// ===============================================
// LAYER 2: Safe Type Registration
// ===============================================

// Only register types with NO side effects in GobDecode/GobEncode
// NEVER register types that can execute code
func init() {
	// Safe data-only types
	gob.Register(&SafeTask{})
	gob.Register(&SafeResult{})
	// DO NOT register: os/exec.Cmd, reflect types, function types
}

type SafeTask struct {
	ID        string    `json:"id"`
	TaskType  string    `json:"type"` // Validated against allowlist
	Payload   []byte    `json:"payload"`
	CreatedAt time.Time `json:"created_at"`
}

type SafeResult struct {
	TaskID    string    `json:"task_id"`
	Status    string    `json:"status"`
	Output    []byte    `json:"output"`
	CompletedAt time.Time `json:"completed_at"`
}

// Validate task type against strict allowlist
var allowedTaskTypes = map[string]bool{
	"compute":    true,
	"transform":  true,
	"aggregate":  true,
}

func (t *SafeTask) Validate() error {
	if t.ID == "" || len(t.ID) > 64 {
		return errors.New("invalid task ID")
	}
	if !allowedTaskTypes[t.TaskType] {
		return fmt.Errorf("unknown task type: %s", t.TaskType)
	}
	if len(t.Payload) > 100*1024 {
		return errors.New("task payload too large")
	}
	return nil
}

// ===============================================
// LAYER 3: Isolated Processing with Context
// ===============================================

type TaskProcessor struct {
	serializer *SecureSerializer
	handlers   map[string]TaskHandler
}

type TaskHandler func(ctx context.Context, payload []byte) (*SafeResult, error)

func NewTaskProcessor(key []byte) *TaskProcessor {
	return &TaskProcessor{
		serializer: NewSecureSerializer(key),
		handlers:   make(map[string]TaskHandler),
	}
}

func (p *TaskProcessor) RegisterHandler(taskType string, handler TaskHandler) {
	if !allowedTaskTypes[taskType] {
		panic("cannot register handler for unknown task type")
	}
	p.handlers[taskType] = handler
}

func (p *TaskProcessor) ProcessTask(ctx context.Context, raw []byte) (*SafeResult, error) {
	// Timeout context for processing
	ctx, cancel := context.WithTimeout(ctx, 30*time.Second)
	defer cancel()

	var task SafeTask
	if err := p.serializer.Deserialize(raw, &task); err != nil {
		return nil, fmt.Errorf("deserialization failed: %w", err)
	}

	// Post-deserialization validation
	if err := task.Validate(); err != nil {
		return nil, fmt.Errorf("validation failed: %w", err)
	}

	handler, ok := p.handlers[task.TaskType]
	if !ok {
		return nil, fmt.Errorf("no handler for task type: %s", task.TaskType)
	}

	// Execute with context for cancellation
	return handler(ctx, task.Payload)
}

// ===============================================
// LAYER 4: HTTP Handler with Full Protection
// ===============================================

func (p *TaskProcessor) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	// Only accept POST
	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Strict content type
	if r.Header.Get("Content-Type") != "application/octet-stream" {
		http.Error(w, "Invalid content type", http.StatusBadRequest)
		return
	}

	// Size limit
	r.Body = http.MaxBytesReader(w, r.Body, maxPayloadBytes+2048)

	raw, err := io.ReadAll(r.Body)
	if err != nil {
		http.Error(w, "Failed to read request", http.StatusBadRequest)
		return
	}

	result, err := p.ProcessTask(r.Context(), raw)
	if err != nil {
		log.Printf("Task processing failed from %s: %v", r.RemoteAddr, err)
		http.Error(w, "Processing failed", http.StatusBadRequest)
		return
	}

	response, err := p.serializer.Serialize(result)
	if err != nil {
		log.Printf("Response serialization failed: %v", err)
		http.Error(w, "Internal error", http.StatusInternalServerError)
		return
	}

	w.Header().Set("Content-Type", "application/octet-stream")
	w.Write(response)
}

func main() {
	// In production, load from secure secret management
	key := []byte("your-32-byte-minimum-secret-key!")

	processor := NewTaskProcessor(key)

	// Register safe handlers only
	processor.RegisterHandler("compute", func(ctx context.Context, payload []byte) (*SafeResult, error) {
		// Safe computation, no shell execution
		return &SafeResult{
			Status:      "completed",
			Output:      []byte("result"),
			CompletedAt: time.Now(),
		}, nil
	})

	log.Println("Starting secure task processor on :8080")
	log.Fatal(http.ListenAndServe(":8080", processor))
}
```

**Defense in Depth Layers**:

1. **Cryptographic Integrity (HMAC-SHA256)**:
```go
// Verify signature BEFORE any deserialization
if !s.verify(payload.Data, payload.Signature) {
    return errors.New("signature verification failed")
}
```
Attacker cannot craft malicious payloads without the secret key.

2. **Temporal Validation**:
```go
age := time.Since(time.Unix(payload.Timestamp, 0))
if age > maxPayloadAge || age < -30*time.Second {
    return errors.New("payload expired")
}
```
Prevents replay attacks with captured valid payloads.

3. **Strict Type Allowlist**:
```go
var allowedTaskTypes = map[string]bool{
    "compute":   true,
    "transform": true,
}
// Handler dispatch only for pre-registered safe types
handler, ok := p.handlers[task.TaskType]
```
No dynamic type instantiation, explicit handler mapping.

**Additional Protections**:
- **Never use gob with untrusted data**: Only use for internal signed messages between trusted components
- **Consider alternatives**: Protocol Buffers or Cap'n Proto provide schema-based serialization without arbitrary code execution risks
- **Memory limits**: Use `io.LimitReader` and `MaxBytesReader` to prevent resource exhaustion
- **Context timeouts**: Always process with deadline context to prevent hanging on malformed data
- **Audit logging**: Log all deserialization failures with source IP for threat detection
- **Key rotation**: Implement HMAC key rotation with grace period for both old and new keys

You must never trust raw user input in SQL queries. Always combine strict input validation with parameterized queries.

**VULNERABLE CODE**:

```rust
use actix_web::{get, web, App, HttpRequest, HttpResponse, HttpServer, Responder};
use serde::Serialize;
use sqlx::{Connection, PgConnection};

#[derive(Serialize)]
struct User {
    id: i32,
    username: String,
}

#[get("/user")]
async fn get_user(req: HttpRequest) -> impl Responder {
    // Read `id` directly from the query string
    let id_param = req
        .query_string() // e.g. "id=1 OR 1=1"
        .replace("id=", "");

    // VULNERABLE: dynamic SQL with unvalidated input
    let query = format!("SELECT id, username FROM users WHERE id = {}", id_param);

    let db_url = "postgres://user:password@localhost/app";
    let mut conn = match PgConnection::connect(db_url).await {
        Ok(c) => c,
        Err(_) => return HttpResponse::InternalServerError().finish(),
    };

    let row = match sqlx::query_as::<_, User>(&query).fetch_one(&mut conn).await {
        Ok(r) => r,
        Err(_) => return HttpResponse::NotFound().finish(),
    };

    HttpResponse::Ok().json(row)
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| App::new().service(get_user))
        .bind(("127.0.0.1", 8080))?
        .run()
        .await
}
```

**Attack Payload** (if applicable):
```sql
id=1 OR 1=1--
```

This payload turns the WHERE clause into `WHERE id = 1 OR 1=1--`, which returns all users instead of a single user.

**Why This Is Dangerous**:
- User input is inserted directly into the SQL string with `format!`, allowing arbitrary SQL fragments.
- There is no type or range validation on `id`, so attackers can inject boolean logic, UNIONs, or DDL.
- Errors are handled generically, making it hard to detect exploitation in logs and monitoring.

**SECURE VERSION**:

```rust
use actix_web::{get, web, App, HttpRequest, HttpResponse, HttpServer, Responder};
use serde::Serialize;
use sqlx::{Connection, PgConnection};
use std::num::ParseIntError;

#[derive(Serialize)]
struct User {
    id: i32,
    username: String,
}

// Strongly-typed query params with validation
#[derive(serde::Deserialize)]
struct UserQuery {
    id: String,
}

fn validate_user_id(raw: &str) -> Result<i32, ParseIntError> {
    // PRIMARY DEFENSE: strict type & range check
    // Only allow positive integers within 32-bit range
    let parsed: i32 = raw.parse()?;
    if parsed <= 0 {
        // Map invalid values to a generic error later
        return Err("0".parse().unwrap_err());
    }
    Ok(parsed)
}

#[get("/user-safe")]
async fn get_user_safe(query: web::Query<UserQuery>) -> impl Responder {
    // 1) Input validation (defense in depth)
    let user_id = match validate_user_id(&query.id) {
        Ok(id) => id,
        Err(_) => {
            return HttpResponse::BadRequest()
                .body("Invalid id: must be a positive integer");
        }
    };

    let db_url = "postgres://user:password@localhost/app";
    let mut conn = match PgConnection::connect(db_url).await {
        Ok(c) => c,
        Err(e) => {
            eprintln!("[ERROR] DB connection failed: {e}");
            return HttpResponse::InternalServerError()
                .body("Temporary server issue");
        }
    };

    // 2) PRIMARY DEFENSE: parameterized query
    let row = match sqlx::query_as!(
        User,
        r#"SELECT id, username FROM users WHERE id = $1"#,
        user_id
    )
    .fetch_one(&mut conn)
    .await
    {
        Ok(r) => r,
        Err(e) => {
            // 3) Safe error handling & basic logging
            eprintln!("[WARN] User lookup failed for id={user_id}: {e}");
            return HttpResponse::NotFound().finish();
        }
    };

    HttpResponse::Ok().json(row)
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    HttpServer::new(|| App::new().service(get_user_safe))
        .bind(("127.0.0.1", 8080))?
        .run()
        .await
}
```

**Key Security Controls**:
- Input validation and typing: `validate_user_id` enforces that `id` is a positive integer, rejecting any non-numeric or out-of-range values before they reach the database.
- Parameterized queries: `sqlx::query_as!` with `$1` binds `user_id` as a value, not as SQL text, preventing injected SQL fragments from changing the query structure.
- Safe error handling and logging: user-facing errors are generic, while server-side logs capture details. This reduces information leakage while still supporting incident investigation.

For dynamic queries, you still rely on strong input validation and parameterization, but you build the SQL structure separately from the untrusted data. You also add production concerns like logging, rate limiting (at the framework or gateway level), and environment-aware behavior.

**PRODUCTION PATTERN**:

```rust
use actix_web::{get, middleware, web, App, HttpResponse, HttpServer, Responder};
use serde::{Deserialize, Serialize};
use sqlx::{postgres::PgPoolOptions, PgPool, Row};
use std::time::Duration;

#[derive(Deserialize)]
struct SearchQuery {
    username: Option<String>,
    email: Option<String>,
    status: Option<String>, // e.g. "active", "disabled"
    limit: Option<u32>,
}

#[derive(Serialize)]
struct UserSummary {
    id: i32,
    username: String,
    email: String,
    status: String,
}

fn sanitize_username(input: &str) -> Option<String> {
    let trimmed = input.trim();
    if trimmed.is_empty() || trimmed.len() > 32 {
        return None;
    }
    // Allow only simple usernames (letters, digits, underscore)
    if !trimmed.chars().all(|c| c.is_ascii_alphanumeric() || c == '_') {
        return None;
    }
    Some(trimmed.to_string())
}

fn sanitize_email(input: &str) -> Option<String> {
    let trimmed = input.trim();
    if trimmed.len() > 128 || !trimmed.contains('@') {
        return None;
    }
    Some(trimmed.to_string())
}

fn sanitize_status(input: &str) -> Option<String> {
    match input.trim() {
        "active" | "disabled" | "pending" => Some(input.trim().to_string()),
        _ => None,
    }
}

fn sanitize_limit(limit: Option<u32>) -> u32 {
    let default = 20;
    let max = 100;
    limit.map(|l| l.min(max)).unwrap_or(default)
}

#[get("/users/search")]
async fn search_users(
    pool: web::Data<PgPool>,
    query: web::Query<SearchQuery>,
) -> impl Responder {
    let env = std::env::var("APP_ENV").unwrap_or_else(|_| "development".to_string());

    // INPUT VALIDATION LAYER
    let mut conditions: Vec<String> = Vec::new();
    let mut params: Vec<(String, sqlx::types::Json<String>)> = Vec::new();

    if let Some(ref username) = query.username {
        if let Some(clean) = sanitize_username(username) {
            conditions.push(format!("username = ${}", conditions.len() + 1));
            params.push(("username".to_string(), sqlx::types::Json(clean)));
        } else {
            return HttpResponse::BadRequest().body("Invalid username");
        }
    }

    if let Some(ref email) = query.email {
        if let Some(clean) = sanitize_email(email) {
            conditions.push(format!("email = ${}", conditions.len() + 1));
            params.push(("email".to_string(), sqlx::types::Json(clean)));
        } else {
            return HttpResponse::BadRequest().body("Invalid email");
        }
    }

    if let Some(ref status) = query.status {
        if let Some(clean) = sanitize_status(status) {
            conditions.push(format!("status = ${}", conditions.len() + 1));
            params.push(("status".to_string(), sqlx::types::Json(clean)));
        } else {
            return HttpResponse::BadRequest().body("Invalid status");
        }
    }

    let limit = sanitize_limit(query.limit);

    // DYNAMIC QUERY BUILDING WITH PARAMETERIZATION
    let mut sql = "SELECT id, username, email, status FROM users".to_string();
    if !conditions.is_empty() {
        sql.push_str(" WHERE ");
        sql.push_str(&conditions.join(" AND "));
    }
    sql.push_str(" ORDER BY id ASC LIMIT ");
    sql.push_str(&limit.to_string());

    // PREPARE THE QUERY AND BIND PARAMETERS BY POSITION
    let mut q = sqlx::query(&sql);
    for (idx, (_, value)) in params.into_iter().enumerate() {
        // Bind parameters according to their position in the WHERE clause
        let Json(v) = value;
        let param_index = idx + 1;
        // Using `bind` keeps values separate from SQL text
        q = q.bind(v);
        // Note: "${}" placeholders were already placed by index order; we rely on consistent ordering
        let _ = param_index; // to avoid unused variable warning in this simplified example
    }

    // QUERY EXECUTION WITH ERROR HANDLING & AUDIT LOGGING
    let rows = match q.fetch_all(pool.get_ref()).await {
        Ok(r) => r,
        Err(e) => {
            // AUDIT LOGGING (redacted)
            eprintln!("[ERROR] /users/search DB error: {e}");
            if env == "production" {
                return HttpResponse::InternalServerError()
                    .body("Internal server error");
            } else {
                return HttpResponse::InternalServerError()
                    .body(format!("DB error: {e}"));
            }
        }
    };

    let mut users = Vec::new();
    for row in rows {
        let user = UserSummary {
            id: row.get("id"),
            username: row.get("username"),
            email: row.get("email"),
            status: row.get("status"),
        };
        users.push(user);
    }

    HttpResponse::Ok().json(users)
}

#[actix_web::main]
async fn main() -> std::io::Result<()> {
    // ENV-SPECIFIC CONFIGURATION
    let env = std::env::var("APP_ENV").unwrap_or_else(|_| "development".to_string());
    let db_url = std::env::var("DATABASE_URL")
        .unwrap_or_else(|_| "postgres://user:password@localhost/app".to_string());

    let pool = PgPoolOptions::new()
        .max_connections(if env == "production" { 20 } else { 5 })
        .connect_timeout(Duration::from_secs(5))
        .connect(&db_url)
        .await
        .expect("Failed to create DB pool");

    HttpServer::new(move || {
        let app = App::new()
            .wrap(middleware::Logger::default()) // BASIC REQUEST LOGGING
            .app_data(web::Data::new(pool.clone()))
            .service(search_users);

        // SECURITY HEADERS (defense in depth)
        app
    })
    .bind(("127.0.0.1", 8080))?
    .run()
    .await
}
```

**Defense in Depth Layers**:
1. **Strict input validation and normalization**:
   - `sanitize_username`, `sanitize_email`, and `sanitize_status` constrain allowed characters and values before they ever reach the SQL builder.
   - Example: rejecting `username=admin' OR '1'='1` because it contains disallowed characters.

2. **Parameterized dynamic queries**:
   - The SQL structure (`SELECT ... WHERE ...`) is built separately from the values, and `bind` is used to attach values.
   - Even though WHERE clauses are dynamic, untrusted data never becomes SQL keywords or operators.

3. **Environment-aware error handling and logging**:
   - In production, detailed DB errors are not returned to the client (to avoid information leakage), but are logged server-side for monitoring and forensic analysis.
   - In non-production, verbose errors help developers debug.

**Additional Protections**:
- **Rate limiting and abuse detection**: Implement at the API gateway or Actix middleware level (e.g., per-IP rate limits on `/users/search`) to reduce brute-force or enumeration attempts.
- **Security headers and hardening**: Add middleware to set headers like `X-Content-Type-Options`, `X-Frame-Options`, and `Content-Security-Policy` to reduce other web risks that might chain with SQL injection.
- **Monitoring and audit logging**: Log search parameters in a redacted or hashed form, along with caller IP and auth identity, to enable anomaly detection and incident response if suspicious query patterns are observed.

