**SECURE VERSION**:

```java
import javax.servlet.http.*;
import java.io.IOException;
import java.sql.*;
import java.util.concurrent.ConcurrentHashMap;
import java.util.concurrent.TimeUnit;
import com.google.common.cache.Cache;
import com.google.common.cache.CacheBuilder;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecureLoginServlet extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecureLoginServlet.class);
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    // Rate limiter: max 5 attempts per IP per 15 minutes
    private static final int MAX_ATTEMPTS_PER_IP = 5;
    private static final int MAX_ATTEMPTS_PER_USER = 3;
    private static final int LOCKOUT_DURATION_MINUTES = 15;

    // Track attempts by IP address
    private final Cache<String, Integer> ipAttempts = CacheBuilder.newBuilder()
            .expireAfterWrite(LOCKOUT_DURATION_MINUTES, TimeUnit.MINUTES)
            .build();

    // Track attempts by username
    private final Cache<String, Integer> userAttempts = CacheBuilder.newBuilder()
            .expireAfterWrite(LOCKOUT_DURATION_MINUTES, TimeUnit.MINUTES)
            .build();

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws IOException {
        String clientIp = getClientIp(request);
        String username = request.getParameter("username");
        String password = request.getParameter("password");

        // RATE LIMITING: Check IP-based limit
        Integer ipCount = ipAttempts.getIfPresent(clientIp);
        if (ipCount != null && ipCount >= MAX_ATTEMPTS_PER_IP) {
            logger.warn("Rate limit exceeded for IP: {}", clientIp);
            response.setStatus(429);
            response.setHeader("Retry-After", String.valueOf(LOCKOUT_DURATION_MINUTES * 60));
            response.getWriter().write("{\"error\": \"Too many attempts. Try again later.\"}");
            return;
        }

        // RATE LIMITING: Check username-based limit
        Integer userCount = userAttempts.getIfPresent(username);
        if (userCount != null && userCount >= MAX_ATTEMPTS_PER_USER) {
            logger.warn("Rate limit exceeded for user: {}", username);
            response.setStatus(429);
            response.setHeader("Retry-After", String.valueOf(LOCKOUT_DURATION_MINUTES * 60));
            response.getWriter().write("{\"error\": \"Account temporarily locked.\"}");
            return;
        }

        boolean loginSuccess = attemptLogin(username, password, request);

        if (loginSuccess) {
            // Clear attempts on successful login
            ipAttempts.invalidate(clientIp);
            userAttempts.invalidate(username);
            logger.info("Successful login for user: {} from IP: {}", username, clientIp);
            response.setStatus(200);
            response.getWriter().write("{\"status\": \"success\"}");
        } else {
            // Increment attempt counters
            ipAttempts.put(clientIp, (ipCount == null ? 0 : ipCount) + 1);
