import javax.servlet.http.*;
import java.io.IOException;
import java.time.Duration;
import java.time.Instant;
import java.security.MessageDigest;
import java.util.Base64;
import redis.clients.jedis.JedisPooled;
import redis.clients.jedis.params.SetParams;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Counter;

public class ProductionLoginServlet extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(ProductionLoginServlet.class);
    private static final Logger securityAudit = LoggerFactory.getLogger("SECURITY_AUDIT");

    // Centralized Redis for distributed rate limiting
    private final JedisPooled redis;
    private final MeterRegistry metrics;

    // Tiered rate limits
    private static final int GLOBAL_REQUESTS_PER_SECOND = 1000;
    private static final int IP_REQUESTS_PER_MINUTE = 10;
    private static final int USER_REQUESTS_PER_HOUR = 5;
    private static final int FINGERPRINT_REQUESTS_PER_HOUR = 20;

    // Lockout configuration
    private static final int PROGRESSIVE_LOCKOUT_BASE_SECONDS = 60;
    private static final int MAX_LOCKOUT_SECONDS = 3600; // 1 hour max

    private Counter loginAttempts;
    private Counter rateLimitedRequests;
    private Counter suspiciousActivityCounter;

    public ProductionLoginServlet(JedisPooled redis, MeterRegistry metrics) {
        this.redis = redis;
        this.metrics = metrics;
        this.loginAttempts = metrics.counter("login.attempts");
        this.rateLimitedRequests = metrics.counter("login.rate_limited");
        this.suspiciousActivityCounter = metrics.counter("login.suspicious");
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response)
            throws IOException {
        loginAttempts.increment();

        String clientIp = getClientIp(request);
        String username = sanitizeUsername(request.getParameter("username"));
        String deviceFingerprint = generateDeviceFingerprint(request);
        String requestId = generateRequestId();

        // LAYER 1: Global rate limit (protect against DDoS)
        if (!checkGlobalRateLimit()) {
            handleRateLimitExceeded(response, "global", requestId, clientIp);
            return;
        }

        // LAYER 2: IP-based rate limit with progressive lockout
        RateLimitResult ipResult = checkIpRateLimit(clientIp);
        if (!ipResult.allowed) {
            handleRateLimitExceeded(response, "ip", requestId, clientIp);
            logSuspiciousActivity(clientIp, username, deviceFingerprint, "IP rate limit", requestId);
            return;
        }

        // LAYER 3: Device fingerprint rate limit (catches botnet rotation)
        RateLimitResult fingerprintResult = checkFingerprintRateLimit(deviceFingerprint);
        if (!fingerprintResult.allowed) {
            handleRateLimitExceeded(response, "fingerprint", requestId, clientIp);
            logSuspiciousActivity(clientIp, username, deviceFingerprint, "Fingerprint rate limit", requestId);
            return;
        }

        // LAYER 4: Username-based rate limit with account lockout
        RateLimitResult userResult = checkUserRateLimit(username);
        if (!userResult.allowed) {
            handleAccountLockout(response, username, userResult.retryAfter, requestId);
            return;
        }

        // LAYER 5: Behavioral analysis - detect anomalies
        if (detectSuspiciousBehavior(clientIp, username, deviceFingerprint, request)) {
            suspiciousActivityCounter.increment();
            // Require CAPTCHA or additional verification
            response.setStatus(403);
            response.getWriter().write("{\"error\": \"Additional verification required\", \"captcha_required\": true}");
            return;
        }

        // Perform actual authentication
        boolean loginSuccess = performAuthentication(username, request.getParameter("password"), request);

        if (loginSuccess) {
            handleSuccessfulLogin(request, response, username, clientIp, deviceFingerprint, requestId);
        } else {
            handleFailedLogin(response, username, clientIp, deviceFingerprint, requestId);
        }
    }

    private boolean checkGlobalRateLimit() {
        String key = "ratelimit:global:" + Instant.now().getEpochSecond();
        Long count = redis.incr(key);
        if (count == 1) {
            redis.expire(key, 2); // 2 second window
        }
        return count <= GLOBAL_REQUESTS_PER_SECOND;
    }

    private RateLimitResult checkIpRateLimit(String ip) {
        String countKey = "ratelimit:ip:" + ip;
        String lockoutKey = "lockout:ip:" + ip;

        // Check if IP is locked out
        String lockoutTtl = redis.get(lockoutKey);
        if (lockoutTtl != null) {
            return new RateLimitResult(false, Long.parseLong(lockoutTtl));
        }

        // Sliding window rate limit
        long currentWindow = Instant.now().toEpochMilli() / 60000; // 1 minute windows
        String windowKey = countKey + ":" + currentWindow;

        Long attempts = redis.incr(windowKey);
        if (attempts == 1) {
            redis.expire(windowKey, 120); // Keep for 2 minutes
        }

        if (attempts > IP_REQUESTS_PER_MINUTE) {
            // Progressive lockout: double duration each time
            String lockoutCountKey = "lockout:count:ip:" + ip;
            Long lockoutCount = redis.incr(lockoutCountKey);
            redis.expire(lockoutCountKey, MAX_LOCKOUT_SECONDS);

            int lockoutDuration = Math.min(
                PROGRESSIVE_LOCKOUT_BASE_SECONDS * (int) Math.pow(2, lockoutCount - 1),
                MAX_LOCKOUT_SECONDS
            );

            redis.setex(lockoutKey, lockoutDuration, String.valueOf(lockoutDuration));
            return new RateLimitResult(false, lockoutDuration);
        }

        return new RateLimitResult(true, 0);
    }

    private RateLimitResult checkFingerprintRateLimit(String fingerprint) {
        String key = "ratelimit:fp:" + fingerprint;
        long currentHour = Instant.now().toEpochMilli() / 3600000;
        String hourKey = key + ":" + currentHour;

        Long attempts = redis.incr(hourKey);
        if (attempts == 1) {
            redis.expire(hourKey, 7200); // 2 hour TTL
        }

        if (attempts > FINGERPRINT_REQUESTS_PER_HOUR) {
            return new RateLimitResult(false, 3600 - (Instant.now().getEpochSecond() % 3600));
        }
        return new RateLimitResult(true, 0);
    }

    private RateLimitResult checkUserRateLimit(String username) {
        String lockoutKey = "lockout:user:" + username;
        String ttl = redis.get(lockoutKey);
        if (ttl != null) {
            return new RateLimitResult(false, Long.parseLong(ttl));
        }

        String countKey = "ratelimit:user:" + username;
        Long attempts = redis.incr(countKey);
        if (attempts == 1) {
            redis.expire(countKey, 3600);
        }

        if (attempts > USER_REQUESTS_PER_HOUR) {
            int lockoutDuration = 900; // 15 minutes
            redis.setex(lockoutKey, lockoutDuration, String.valueOf(lockoutDuration));

            // Alert security team for potential targeted attack
            securityAudit.warn("ACCOUNT_LOCKOUT username={} attempts={}", username, attempts);
            return new RateLimitResult(false, lockoutDuration);
        }
        return new RateLimitResult(true, 0);
    }

    private String generateDeviceFingerprint(HttpServletRequest request) {
        StringBuilder fp = new StringBuilder();
        fp.append(request.getHeader("User-Agent"));
        fp.append(request.getHeader("Accept-Language"));
        fp.append(request.getHeader("Accept-Encoding"));
        fp.append(request.getHeader("Accept"));
        // Add more headers for better fingerprinting

        try {
            MessageDigest md = MessageDigest.getInstance("SHA-256");
            byte[] hash = md.digest(fp.toString().getBytes());
            return Base64.getEncoder().encodeToString(hash).substring(0, 32);
        } catch (Exception e) {
            return "unknown";
        }
    }

    private boolean detectSuspiciousBehavior(String ip, String username, 
            String fingerprint, HttpServletRequest request) {
        // Check for known malicious patterns

        // 1. Multiple usernames from same IP in short time
        String ipUsersKey = "behavior:ip_users:" + ip;
        redis.sadd(ipUsersKey, username);
        redis.expire(ipUsersKey, 300);
        if (redis.scard(ipUsersKey) > 10) {
            return true; // 10+ different usernames = credential stuffing
        }

        // 2. Same fingerprint, multiple IPs (proxy/VPN rotation)
        String fpIpsKey = "behavior:fp_ips:" + fingerprint;
        redis.sadd(fpIpsKey, ip);
        redis.expire(fpIpsKey, 300);
        if (redis.scard(fpIpsKey) > 5) {
            return true; // Same browser, 5+ IPs = suspicious
        }

        // 3. Missing or suspicious headers
        if (request.getHeader("User-Agent") == null ||
            request.getHeader("Accept-Language") == null) {
            return true; // Bot-like behavior
        }

        return false;
    }

    private void handleSuccessfulLogin(HttpServletRequest request, HttpServletResponse response,
            String username, String ip, String fingerprint, String requestId) throws IOException {
        // Clear rate limit counters
        redis.del("ratelimit:user:" + username);
        redis.del("lockout:user:" + username);

        // Audit log
        securityAudit.info("LOGIN_SUCCESS requestId={} username={} ip={} fingerprint={}",
            requestId, username, ip, fingerprint);

        request.getSession().setAttribute("user", username);
        response.setStatus(200);
        response.getWriter().write("{\"status\": \"success\"}");
    }

    private void handleFailedLogin(HttpServletResponse response, String username, 
            String ip, String fingerprint, String requestId) throws IOException {
        securityAudit.warn("LOGIN_FAILURE requestId={} username={} ip={} fingerprint={}",
            requestId, username, ip, fingerprint);

        response.setStatus(401);
        response.getWriter().write("{\"error\": \"Invalid credentials\"}");
    }

    private void handleRateLimitExceeded(HttpServletResponse response, String type,
            String requestId, String ip) throws IOException {
        rateLimitedRequests.increment();
        securityAudit.warn("RATE_LIMITED requestId={} type={} ip={}", requestId, type, ip);

        response.setStatus(429);
        response.setHeader("Retry-After", "60");
        response.getWriter().write("{\"error\": \"Too many requests\"}");
    }

    private void handleAccountLockout(HttpServletResponse response, String username,
            long retryAfter, String requestId) throws IOException {
        response.setStatus(423); // Locked
        response.setHeader("Retry-After", String.valueOf(retryAfter));
        response.getWriter().write("{\"error\": \"Account temporarily locked\", \"retry_after\": " + retryAfter + "}");
    }

    private String getClientIp(HttpServletRequest request) {
        String[] headers = {"X-Forwarded-For", "X-Real-IP", "CF-Connecting-IP"};
        for (String header : headers) {
            String ip = request.getHeader(header);
            if (ip != null && !ip.isEmpty() && !"unknown".equalsIgnoreCase(ip)) {
                return ip.split(",")[0].trim();
            }
        }
        return request.getRemoteAddr();
    }

    private String sanitizeUsername(String username) {
        if (username == null) return "";
        return username.toLowerCase().replaceAll("[^a-z0-9@._-]", "").substring(0, Math.min(255, username.length()));
    }

    private String generateRequestId() {
        return java.util.UUID.randomUUID().toString().substring(0, 8);
    }

    private boolean performAuthentication(String username, String password, HttpServletRequest request) {
        // Actual authentication implementation
        return false;
    }

    private static class RateLimitResult {
        final boolean allowed;
        final long retryAfter;

        RateLimitResult(boolean allowed, long retryAfter) {
            this.allowed = allowed;
            this.retryAfter = retryAfter;
        }
    }
}
