use Illuminate\Support\Str;
use Illuminate\Validation\ValidationException;

class SecureLoginController extends Controller
{
    public function __construct()
    {
        $this->middleware('guest')->except('logout');
    }

    public function login(Request $request): RedirectResponse
    {
        $this->configureSessionForEnvironment();

        $credentials = $request->validate([
            'email' => ['required', 'string', 'email', 'max:255'],
            'password' => ['required', 'string', 'min:8', 'max:128'],
        ]);

        $this->ensureIsNotRateLimited($request);

        if (!Auth::attempt([
            'email' => $credentials['email'],
            'password' => $credentials['password'],
        ], $request->boolean('remember'))) {
            RateLimiter::hit($this->throttleKey($request));
            Log::warning('Login failed', [
                'email' => $credentials['email'],
                'ip' => $request->ip(),
                'user_agent' => $request->userAgent(),
            ]);

            throw ValidationException::withMessages([
                'email' => __('auth.failed'),
            ]);
        }

        // Primary session hardening
        $request->session()->invalidate();
        $request->session()->regenerateToken();
        $request->session()->regenerate();

        // Issue short-lived MFA challenge token
        if ($this->mfaRequired(Auth::user())) {
            $mfaToken = Str::random(64);
            $request->session()->put('mfa_token', $mfaToken);
            $request->session()->put('mfa_user_id', Auth::id());

            // Store device fingerprint hints for anomaly detection
            $request->session()->put('login_fingerprint', [
                'ip' => $request->ip(),
                'user_agent' => substr((string) $request->userAgent(), 0, 255),
                'time' => now()->timestamp,
            ]);

            // In real world, send OTP via SMS/email/app, not returned in response
            Log::info('MFA challenge issued', [
                'user_id' => Auth::id(),
                'ip' => $request->ip(),
            ]);

            return redirect()->route('mfa.challenge');
        }

        RateLimiter::clear($this->throttleKey($request));
        $this->logSuccessfulLogin($request, Auth::user());

        return redirect()->intended('/dashboard');
    }

    public function verifyMfa(Request $request): RedirectResponse
    {
        $request->validate([
            'code' => ['required', 'string', 'size:6'],
        ]);

        $userId = $request->session()->pull('mfa_user_id');
        $mfaToken = $request->session()->pull('mfa_token');

        if (!$userId || !$mfaToken) {
            throw ValidationException::withMessages([
                'code' => 'MFA session expired. Please login again.',
            ]);
        }

        $user = User::find($userId);
        if (!$user) {
            throw ValidationException::withMessages([
                'code' => 'User not found.',
            ]);
        }

        // Verify TOTP or one-time code (pseudo-code; integrate with package like laravel-mfa)
        $isValid = app('mfa')->verifyCode($user, $request->input('code'));

        if (!$isValid) {
            Log::warning('Invalid MFA code', [
                'user_id' => $userId,
                'ip' => $request->ip(),
            ]);

            throw ValidationException::withMessages([
                'code' => 'Invalid verification code.',
            ]);
        }

        // On MFA success, bind session to device characteristics
        $request->session()->put('session_fingerprint', [
            'ip' => $request->ip(),
            'user_agent' => substr((string) $request->userAgent(), 0, 255),
        ]);

        $this->logSuccessfulLogin($request, $user, true);

        return redirect()->intended('/dashboard');
    }

    public function logout(Request $request): RedirectResponse
    {
        Log::info('User logged out', [
            'user_id' => Auth::id(),
            'ip' => $request->ip(),
        ]);

        Auth::logout();
        $request->session()->invalidate();
        $request->session()->regenerateToken();

        return redirect('/');
    }

    protected function configureSessionForEnvironment(): void
    {
        if (app()->environment('production')) {
            Config::set('session.secure', true);
            Config::set('session.http_only', true);
            Config::set('session.same_site', 'lax');
        }
    }

    protected function ensureIsNotRateLimited(Request $request): void
    {
        if (!RateLimiter::tooManyAttempts($this->throttleKey($request), 5)) {
