**Additional Protections**:
- **strict-dynamic**: Propagates trust to scripts loaded by trusted scripts, simplifying CDN usage
- **Report-Only Mode**: Test CSP in staging before enforcing in production
- **upgrade-insecure-requests**: Forces HTTPS for all resources
- **object-src 'none'**: Blocks Flash and other plugin content
- **base-uri 'self'**: Prevents base tag hijacking attacks
- **HSTS**: Enforces HTTPS with preload for maximum security

You're right to be concerned. Environment variables can leak through process listings, container inspection, or crash dumps. Production systems should use dedicated secrets management services that provide encryption, access control, audit logging, and automatic rotation.

**PRODUCTION PATTERN**:

```python
import os
import logging
import hashlib
from abc import ABC, abstractmethod
from typing import Optional, Dict, Any
from functools import lru_cache
from datetime import datetime, timedelta
import threading

logger = logging.getLogger(__name__)


class SecretsProvider(ABC):
    """Abstract base class for secrets providers."""

    @abstractmethod
    def get_secret(self, secret_name: str) -> str:
        pass

    @abstractmethod
    def rotate_secret(self, secret_name: str) -> bool:
        pass


class AWSSecretsManagerProvider(SecretsProvider):
    """AWS Secrets Manager implementation with caching and rotation."""

    def __init__(self, region: str = None):
        import boto3
        from botocore.exceptions import ClientError

        self.region = region or os.environ.get('AWS_REGION', 'us-east-1')
        self.client = boto3.client('secretsmanager', region_name=self.region)
        self._cache: Dict[str, Dict[str, Any]] = {}
        self._cache_ttl = timedelta(minutes=5)
        self._lock = threading.Lock()
        self.ClientError = ClientError

    def get_secret(self, secret_name: str) -> str:
        """Retrieve secret with caching and automatic refresh."""
        with self._lock:
            cached = self._cache.get(secret_name)
            if cached and datetime.utcnow() < cached['expires_at']:
                logger.debug(f"Cache hit for secret: {self._hash_name(secret_name)}")
                return cached['value']

        try:
            response = self.client.get_secret_value(SecretId=secret_name)
            secret_value = response.get('SecretString')

            if not secret_value:
                raise ValueError(f"Secret {secret_name} has no string value")

            with self._lock:
                self._cache[secret_name] = {
                    'value': secret_value,
                    'expires_at': datetime.utcnow() + self._cache_ttl,
                    'version_id': response.get('VersionId')
                }

            logger.info(
                f"Secret retrieved: name_hash={self._hash_name(secret_name)}, "
                f"version={response.get('VersionId', 'unknown')[:8]}"
            )
            return secret_value

        except self.ClientError as e:
            error_code = e.response['Error']['Code']
            logger.error(
                f"Failed to retrieve secret: name_hash={self._hash_name(secret_name)}, "
                f"error={error_code}"
            )
            raise RuntimeError(f"Cannot retrieve secret: {error_code}")

    def rotate_secret(self, secret_name: str) -> bool:
        """Trigger secret rotation."""
        try:
            self.client.rotate_secret(SecretId=secret_name)
            with self._lock:
                self._cache.pop(secret_name, None)
            logger.info(f"Secret rotation initiated: {self._hash_name(secret_name)}")
            return True
        except self.ClientError as e:
            logger.error(f"Secret rotation failed: {e.response['Error']['Code']}")
            return False

    @staticmethod
    def _hash_name(name: str) -> str:
        """Hash secret name for safe logging."""
        return hashlib.sha256(name.encode()).hexdigest()[:12]


class HashiCorpVaultProvider(SecretsProvider):
    """HashiCorp Vault implementation with token renewal."""

    def __init__(self):
        import hvac

        vault_addr = os.environ.get('VAULT_ADDR')
        if not vault_addr:
            raise EnvironmentError("VAULT_ADDR not configured")

        self.client = hvac.Client(url=vault_addr)
        self._authenticate()

    def _authenticate(self):
        """Authenticate using Kubernetes service account or AppRole."""
        if os.path.exists('/var/run/secrets/kubernetes.io/serviceaccount/token'):
            with open('/var/run/secrets/kubernetes.io/serviceaccount/token') as f:
                jwt = f.read()
            role = os.environ.get('VAULT_ROLE', 'default')
            self.client.auth.kubernetes.login(role=role, jwt=jwt)
            logger.info("Authenticated to Vault via Kubernetes SA")
        else:
            role_id = os.environ.get('VAULT_ROLE_ID')
            secret_id = os.environ.get('VAULT_SECRET_ID')
            if role_id and secret_id:
                self.client.auth.approle.login(role_id=role_id, secret_id=secret_id)
                logger.info("Authenticated to Vault via AppRole")
            else:
                raise EnvironmentError("No valid Vault authentication method")

    def get_secret(self, secret_name: str) -> str:
        """Retrieve secret from Vault KV store."""
        try:
            secret_path = f"secret/data/{secret_name}"
            response = self.client.secrets.kv.v2.read_secret_version(
                path=secret_name,
                mount_point='secret'
            )
            return response['data']['data']['value']
        except Exception as e:
            logger.error(f"Vault secret retrieval failed: {type(e).__name__}")
            raise

    def rotate_secret(self, secret_name: str) -> bool:
        """Vault rotation is typically handled by dynamic secrets."""
        logger.info(f"Manual rotation requested for: {secret_name}")
        return True


class SecureCredentialManager:
    """Production credential manager with defense in depth."""

    def __init__(self):
        self.provider = self._initialize_provider()
        self._validate_required_secrets()

    def _initialize_provider(self) -> SecretsProvider:
        """Select secrets provider based on environment."""
        provider_type = os.environ.get('SECRETS_PROVIDER', 'aws')

        if provider_type == 'aws':
            return AWSSecretsManagerProvider()
        elif provider_type == 'vault':
            return HashiCorpVaultProvider()
        else:
            raise ValueError(f"Unknown secrets provider: {provider_type}")

    def _validate_required_secrets(self):
        """Validate all required secrets are accessible at startup."""
        required = ['database/credentials', 'api/stripe-key', 'api/internal-key']
        missing = []

        for secret_name in required:
            try:
                self.provider.get_secret(secret_name)
            except Exception:
                missing.append(secret_name)

        if missing:
            logger.critical(f"Missing required secrets: {len(missing)} secrets unavailable")
            raise RuntimeError("Application cannot start: missing required secrets")

        logger.info(f"All {len(required)} required secrets validated")

    def get_database_credentials(self) -> Dict[str, str]:
        """Retrieve database credentials with audit logging."""
        import json

        secret_json = self.provider.get_secret('database/credentials')
        creds = json.loads(secret_json)

        logger.info(
            "Database credentials accessed",
            extra={
                'event_type': 'secret_access',
                'secret_name': 'database/credentials',
                'timestamp': datetime.utcnow().isoformat()
            }
        )

        return {
            'host': creds['host'],
            'port': creds.get('port', 5432),
            'username': creds['username'],
            'password': creds['password'],
            'database': creds['database']
        }

    def get_api_key(self, service: str) -> str:
        """Retrieve API key with validation."""
        allowed_services = {'stripe', 'twilio', 'sendgrid', 'internal'}

        if service not in allowed_services:
            logger.warning(f"Attempt to access unknown API key: {service}")
            raise ValueError(f"Unknown service: {service}")

        return self.provider.get_secret(f'api/{service}-key')
```

**Defense in Depth Layers**:

1. **Secrets Manager Integration**: Credentials never touch filesystem or environment
```python
# Credentials retrieved directly from secure vault at runtime
creds = secrets_manager.get_database_credentials()
```

2. **Short-lived Caching**: Secrets cached briefly to reduce API calls, but refresh regularly
```python
self._cache_ttl = timedelta(minutes=5)  # Force refresh every 5 minutes
```

3. **Automatic Rotation Support**: Secrets can be rotated without application restart
```python
def rotate_secret(self, secret_name: str) -> bool:
    self.client.rotate_secret(SecretId=secret_name)
    self._cache.pop(secret_name, None)  # Invalidate cache
```

**Additional Protections**:
- **IAM/RBAC**: Application only has access to secrets it needs, least privilege enforced at infrastructure level
- **Audit logging**: Every secret access logged with timestamp, caller identity, and secret version
- **Startup validation**: Application fails fast if required secrets are inaccessible, preventing partial operation
- **Secret hashing in logs**: Secret names hashed before logging to prevent enumeration attacks
- **Kubernetes integration**: Service account tokens used for authentication, no long-lived credentials
- **Encryption at rest**: Secrets managers encrypt all stored secrets using AES-256 or similar
- **Network isolation**: Secrets manager accessible only from private VPC endpoints, not public internet

Using a fast hash like SHA-256 for passwords is dangerous because it enables very fast offline cracking if your database is ever leaked. You should use a dedicated password hashing algorithm like Argon2 with per-password salts and memory-hard parameters.

**VULNERABLE CODE**:

```rust
use sha2::{Digest, Sha256};
use std::collections::HashMap;

struct UserStore {
    // username -> hex(SHA-256(password))
    users: HashMap<String, String>,
}

impl UserStore {
    fn new() -> Self {
        Self {
            users: HashMap::new(),
        }
    }

    // VULNERABLE: fast hash, no salt
    fn register(&mut self, username: &str, password: &str) {
        let mut hasher = Sha256::new();
        hasher.update(password.as_bytes());
        let hash = format!("{:x}", hasher.finalize());
        self.users.insert(username.to_string(), hash);
    }

    fn login(&self, username: &str, password: &str) -> bool {
        let stored_hash = match self.users.get(username) {
            Some(h) => h,
            None => return false,
        };

        let mut hasher = Sha256::new();
        hasher.update(password.as_bytes());
        let candidate = format!("{:x}", hasher.finalize());

        // Also vulnerable: simple equality (timing side channel)
        &candidate == stored_hash
    }
}

fn main() {
    let mut store = UserStore::new();
    store.register("alice", "Password123!");

    let ok = store.login("alice", "Password123!");
    println!("Login success: {ok}");
}
```

**Attack Payload** (offline cracking scenario):
```bash
# After stealing the user table, attacker runs GPU-accelerated cracking
hashcat -m 1400 sha256_hashes.txt wordlist.txt -O --force
```

This command uses Hashcat mode 1400 (SHA-256) to crack millions of SHA-256 password hashes per second using a wordlist and GPU acceleration.

**Why This Is Dangerous**:
- Fast hashing (SHA-256) is designed for speed, making brute-force and dictionary attacks extremely efficient once hashes are stolen.
- Lack of per-password salts allows precomputed rainbow tables and lets attackers crack identical passwords across users at once.
- Simple string equality comparison can leak subtle timing differences that help attackers in certain scenarios (e.g., remote oracle on an API).

**SECURE VERSION**:

```rust
use argon2::{
    password_hash::{PasswordHash, PasswordHasher, PasswordVerifier, SaltString},
    Argon2,
};
use rand_core::OsRng;
use std::collections::HashMap;

struct UserStore {
    // username -> PHC string (includes algorithm, params, salt, hash)
    users: HashMap<String, String>,
}

impl UserStore {
    fn new() -> Self {
        Self {
            users: HashMap::new(),
        }
    }

    // SECURE: Argon2id with random salt and strong parameters
    fn register(&mut self, username: &str, password: &str) -> Result<(), String> {
        // Generate a cryptographically secure random salt per password
        let salt = SaltString::generate(&mut OsRng);

        // Configure Argon2id with reasonable parameters for server-side use
        let argon2 = Argon2::default(); // can be tuned further in production

        let password_hash = argon2
            .hash_password(password.as_bytes(), &salt)
            .map_err(|e| format!("hashing error: {e}"))?
            .to_string();

        self.users
            .insert(username.to_string(), password_hash);
        Ok(())
    }

    fn login(&self, username: &str, password: &str) -> bool {
        let stored_hash = match self.users.get(username) {
            Some(h) => h,
            None => return false, // do not distinguish user-not-found from bad password
        };

        let parsed_hash = match PasswordHash::new(stored_hash) {
            Ok(ph) => ph,
            Err(_) => return false, // corrupted or unsupported hash
        };

        let argon2 = Argon2::default();

        // Constant-time verification provided by the library
        argon2
            .verify_password(password.as_bytes(), &parsed_hash)
            .is_ok()
    }
}

fn main() {
    let mut store = UserStore::new();

    if let Err(e) = store.register("alice", "Password123!") {
        eprintln!("Registration error: {e}");
        return;
    }

    let ok = store.login("alice", "Password123!");
    println!("Login success: {ok}");
}
```

**Key Security Controls**:
- **Memory-hard password hashing (Argon2id)**: Uses a slow, memory-intensive function to drastically increase the cost of brute-force attacks, especially on GPUs/ASICs.
- **Per-password random salts**: `SaltString::generate(&mut OsRng)` ensures each password has a unique salt, preventing rainbow-table attacks and linking users with the same password.
- **Constant-time verification and opaque storage format**: `verify_password` performs comparison in constant time and the PHC string encodes algorithm, salt, and parameters, making future reconfiguration safer and reducing implementation errors.

In production, you want configurable Argon2 parameters (per environment), support for migrating legacy hashes, rate limiting, structured logging, and clear error handling without leaking whether a user exists.

**PRODUCTION PATTERN**:

```rust
use argon2::{
    password_hash::{PasswordHash, PasswordHasher, PasswordVerifier, SaltString},
    Algorithm, Argon2, Params, Version,
};
use log::{error, info, warn};
use rand_core::OsRng;
use std::collections::HashMap;
use std::sync::{Arc, Mutex};
use std::time::{Duration, Instant};

#[derive(Clone, Copy, Debug)]
pub struct Argon2Config {
    pub m_cost_kib: u32,
    pub t_cost: u32,
    pub parallelism: u32,
}

impl Argon2Config {
    pub fn for_env(env: &str) -> Self {
        match env {
            // Lower settings for tests/dev to keep them fast
            "dev" | "test" => Self {
                m_cost_kib: 16 * 1024, // 16 MiB
                t_cost: 2,
                parallelism: 1,
            },
            // Stronger settings for production, tune for your hardware
            "prod" | _ => Self {
                m_cost_kib: 64 * 1024, // 64 MiB
                t_cost: 3,
                parallelism: 1,
            },
        }
    }

    pub fn to_argon2(self) -> Argon2<'static> {
        let params = Params::new(self.m_cost_kib, self.t_cost, self.parallelism, None)
            .expect("invalid Argon2 params");
        Argon2::new(Algorithm::Argon2id, Version::V0x13, params)
    }
}

#[derive(Clone)]
struct UserRecord {
    // Stored as PHC string
    password_hash: String,
}

struct UserStore {
    users: HashMap<String, UserRecord>,
}

impl UserStore {
    fn new() -> Self {
        Self {
            users: HashMap::new(),
        }
    }

    fn get(&self, username: &str) -> Option<&UserRecord> {
        self.users.get(username)
    }

    fn upsert(&mut self, username: &str, record: UserRecord) {
        self.users.insert(username.to_string(), record);
    }
}

struct RateLimiter {
    last_attempt: Mutex<HashMap<String, Instant>>, // key by IP or username+IP
    min_interval: Duration,
}

impl RateLimiter {
    fn new(min_interval: Duration) -> Self {
        Self {
            last_attempt: Mutex::new(HashMap::new()),
            min_interval,
        }
    }

    fn check_and_update(&self, key: &str) -> bool {
        let mut map = self.last_attempt.lock().unwrap();
        let now = Instant::now();
        if let Some(prev) = map.get(key) {
            if now.duration_since(*prev) < self.min_interval {
                return false; // rate limited
            }
        }
        map.insert(key.to_string(), now);
        true
    }
}

pub struct AuthService {
    store: Mutex<UserStore>,
    argon2: Argon2<'static>,
    rate_limiter: Arc<RateLimiter>,
}

impl AuthService {
    pub fn new(env: &str) -> Self {
        let cfg = Argon2Config::for_env(env);
        let argon2 = cfg.to_argon2();
        let rate_limiter = Arc::new(RateLimiter::new(Duration::from_secs(2))); // basic per-key delay

        Self {
            store: Mutex::new(UserStore::new()),
            argon2,
            rate_limiter,
        }
    }

    pub fn register(&self, username: &str, password: &str) -> Result<(), String> {
        if password.len() < 12 {
            return Err("password too short".into());
        }

        let salt = SaltString::generate(&mut OsRng);
        let hash = self
            .argon2
            .hash_password(password.as_bytes(), &salt)
            .map_err(|e| format!("hash error: {e}"))?
            .to_string();

        let record = UserRecord { password_hash: hash };
        let mut store = self.store.lock().unwrap();
        store.upsert(username, record);
        info!("user_registered username={}", username);
        Ok(())
    }

    /// Attempt login; returns true on success.
    /// Handles legacy hashes by upgrading them on successful login.
    pub fn login(&self, username: &str, password: &str, client_id: &str) -> bool {
        // Basic rate limiting keyed by client (e.g., IP address or user+IP)
        if !self.rate_limiter.check_and_update(client_id) {
            warn!("rate_limited client_id={}", client_id);
            // Fail closed, but do not reveal rate limit explicitly to avoid oracle
            return false;
        }

        // Fetch user record (or fake one to keep timing similar)
        let maybe_record = {
            let store = self.store.lock().unwrap();
            store.get(username).cloned()
        };

        // If user not found, verify against a dummy hash to keep timing similar
        let (stored_hash, user_exists) = if let Some(rec) = maybe_record {
            (rec.password_hash, true)
        } else {
            // Dummy Argon2 hash (constant) to mitigate user enumeration via timing
            let dummy = "$argon2id$v=19$m=65536,t=3,p=1$AAAAAAAAAAAAAAAAAAAAAA$AAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAAA";
            (dummy.to_string(), false)
        };

        let parsed = match PasswordHash::new(&stored_hash) {
            Ok(ph) => ph,
            Err(e) => {
                error!("invalid_hash username={} err={}", username, e);
                return false;
            }
        };

        let verify_result = self
            .argon2
            .verify_password(password.as_bytes(), &parsed)
            .is_ok();

        // Do not distinguish between non-existent user and bad password
        if verify_result && user_exists {
            info!("login_success username={}", username);

            // Optional: migrate from legacy hash formats here
            if parsed.algorithm != Some(Algorithm::Argon2id) {
                // Re-hash with current Argon2id config
                if let Err(e) = self.upgrade_hash(username, password) {
                    error!("hash_upgrade_failed username={} err={}", username, e);
                }
            }

            true
        } else {
            warn!("login_failed username={}", username);
            false
        }
    }

    fn upgrade_hash(&self, username: &str, password: &str) -> Result<(), String> {
        let salt = SaltString::generate(&mut OsRng);
        let hash = self
            .argon2
            .hash_password(password.as_bytes(), &salt)
            .map_err(|e| format!("hash error: {e}"))?
            .to_string();

        let mut store = self.store.lock().unwrap();
        store.upsert(
            username,
            UserRecord {
                password_hash: hash,
            },
        );
        info!("hash_upgraded username={}", username);
        Ok(())
    }
}

fn main() {
    // In real apps, env comes from configuration (e.g., RUST_ENV)
    env_logger::init();
    let auth = AuthService::new("prod");

    if let Err(e) = auth.register("alice", "VeryStrongPassword!123") {
        error!("registration_error err={}", e);
        return;
    }

    let client_id = "192.0.2.1"; // e.g., IP address
    let ok = auth.login("alice", "VeryStrongPassword!123", client_id);
    println!("Login success: {ok}");
}
```

**Defense in Depth Layers**:
1. **Strong, configurable Argon2 parameters**:
   - `Argon2Config::for_env` allows tuning memory and time cost differently for dev/test vs production.
   - `to_argon2` constructs an `Argon2` instance with `Algorithm::Argon2id` and secure parameters, increasing the cost of offline attacks.

2. **Rate limiting and timing protections**:
   - `RateLimiter::check_and_update` enforces a minimum interval between attempts per client, reducing brute-force speed.
   - Use of a **dummy hash** for non-existent users keeps timing more uniform and mitigates user enumeration via response time.

3. **Audit logging and safe error handling**:
   - `info!`, `warn!`, and `error!` logs provide structured records of registration, login successes/failures, and hash upgrades for monitoring and incident response.
   - All failures return a generic `false` without revealing whether the username exists or the password was wrong, preventing information disclosure.

**Additional Protections**:
- **Legacy hash migration**: `upgrade_hash` transparently re-hashes passwords from older algorithms to Argon2id upon successful login, gradually improving security without forcing password resets.
- **Input validation and password policy**: Basic minimum length check (`password.len() < 12`) is demonstrated; in production enforce stronger policies (entropy, breach checks).
- **Environment-specific hardening**: Use `for_env` to set stronger parameters and additional controls in production (e.g., integrate with a web framework to add security headers, IP-based rate limiting, and centralized monitoring/alerting).

Hiding admin links in the UI provides zero security protection. This is a classic "forced browsing" vulnerability where attackers simply guess or discover hidden URLs and access them directly. The server MUST verify authorization on EVERY request.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();

// VULNERABLE: No authorization check on admin routes
// Security through obscurity - just hiding links in UI

app.get('/admin/users', (req, res) => {
  // Anyone who knows this URL can access it!
  const users = db.query('SELECT * FROM users');
  res.json(users);
});

app.get('/admin/settings', (req, res) => {
  // No verification of admin privileges
  const settings = db.query('SELECT * FROM system_settings');
  res.json(settings);
});

app.delete('/admin/users/:id', (req, res) => {
  // Critical action with no authorization!
  db.query('DELETE FROM users WHERE id = ?', [req.params.id]);
  res.json({ success: true });
});

app.get('/internal/reports/financial', (req, res) => {
  // Sensitive data exposed to anyone
  const reports = db.query('SELECT * FROM financial_reports');
  res.json(reports);
});

app.listen(3000);
```

**Attack Payload**:
```bash
# Attacker directly accesses admin endpoints
curl http://example.com/admin/users
curl http://example.com/admin/settings
curl -X DELETE http://example.com/admin/users/1
curl http://example.com/internal/reports/financial

# Directory enumeration to find hidden endpoints
ffuf -w /usr/share/wordlists/admin-paths.txt -u http://example.com/FUZZ
gobuster dir -u http://example.com -w /usr/share/wordlists/common.txt
```

**Why This Is Dangerous**:
- UI hiding is not a security control - attackers bypass the UI entirely
- No server-side verification allows any authenticated (or unauthenticated) user to access admin functions
- Predictable URL patterns (/admin/*, /internal/*) are easily guessable
- Sensitive data and destructive operations completely unprotected
- Automated tools can enumerate and discover hidden endpoints in seconds

**SECURE VERSION**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const app = express();

const JWT_SECRET = process.env.JWT_SECRET;

// Middleware to verify JWT and extract user
const authenticateToken = (req, res, next) => {
  const authHeader = req.headers['authorization'];
  const token = authHeader && authHeader.split(' ')[1];

  if (!token) {
    return res.status(401).json({ error: 'Authentication required' });
  }

  jwt.verify(token, JWT_SECRET, (err, user) => {
    if (err) {
      return res.status(403).json({ error: 'Invalid or expired token' });
    }
    req.user = user;
    next();
  });
};

// SECURE: Authorization middleware that checks roles
const requireRole = (...allowedRoles) => {
  return (req, res, next) => {
    if (!req.user) {
      return res.status(401).json({ error: 'Authentication required' });
    }

    // Check if user has any of the allowed roles
    const hasRole = allowedRoles.some(role => req.user.roles.includes(role));

    if (!hasRole) {
      // Log unauthorized access attempt
      console.error(`Unauthorized access attempt: User ${req.user.id} tried to access ${req.path}`);
      return res.status(403).json({ error: 'Insufficient permissions' });
    }

    next();
  };
};

// Apply authentication to all admin routes
app.use('/admin', authenticateToken);

// SECURE: Admin routes with role verification
app.get('/admin/users', requireRole('admin', 'super_admin'), (req, res) => {
  const users = db.query('SELECT id, username, email, role FROM users');
  res.json(users);
});

app.get('/admin/settings', requireRole('admin', 'super_admin'), (req, res) => {
  const settings = db.query('SELECT * FROM system_settings');
  res.json(settings);
});

app.delete('/admin/users/:id', requireRole('super_admin'), (req, res) => {
  // Only super_admin can delete users
  db.query('DELETE FROM users WHERE id = ?', [req.params.id]);
  res.json({ success: true });
});

app.listen(3000);
```

**Key Security Controls**:
- **Server-side authorization on every request**: Each endpoint explicitly checks user roles before processing
- **Role-based access control (RBAC)**: Different actions require different privilege levels
- **Authentication before authorization**: User identity verified via JWT before role check
- **Logging of unauthorized attempts**: Failed access attempts are logged for security monitoring
- **Principle of least privilege**: Destructive actions (delete) require highest privilege level

Excellent question! This requires combining Role-Based Access Control (RBAC) with Resource-Based Access Control. You need to check both WHO the user is AND whether they own or have permission to access the specific resource.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');
const winston = require('winston');

const app = express();

// Security headers
app.use(helmet());

// Audit logger
const auditLogger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'audit.log' })
  ]
});

// Rate limiting for sensitive endpoints
const adminLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 100,
  message: { error: 'Too many requests' },
  standardHeaders: true
});

// Permission definitions
const PERMISSIONS = {
  USERS_READ_OWN: 'users:read:own',
  USERS_READ_ALL: 'users:read:all',
  USERS_WRITE_OWN: 'users:write:own',
  USERS_WRITE_ALL: 'users:write:all',
  USERS_DELETE: 'users:delete',
  ADMIN_PANEL: 'admin:panel'
};

// Role to permissions mapping
const ROLE_PERMISSIONS = {
  user: [
    PERMISSIONS.USERS_READ_OWN,
    PERMISSIONS.USERS_WRITE_OWN
  ],
  moderator: [
    PERMISSIONS.USERS_READ_OWN,
    PERMISSIONS.USERS_WRITE_OWN,
    PERMISSIONS.USERS_READ_ALL
  ],
  admin: [
    PERMISSIONS.USERS_READ_OWN,
    PERMISSIONS.USERS_WRITE_OWN,
    PERMISSIONS.USERS_READ_ALL,
    PERMISSIONS.USERS_WRITE_ALL,
    PERMISSIONS.ADMIN_PANEL
  ],
  super_admin: Object.values(PERMISSIONS) // All permissions
};

// Get user permissions from role
const getUserPermissions = (role) => {
  return ROLE_PERMISSIONS[role] || [];
};

// Authentication middleware
const authenticate = async (req, res, next) => {
  try {
    const authHeader = req.headers['authorization'];
    const token = authHeader && authHeader.split(' ')[1];

    if (!token) {
      auditLogger.warn({ event: 'auth_missing', ip: req.ip, path: req.path });
      return res.status(401).json({ error: 'Authentication required' });
    }

    const decoded = jwt.verify(token, process.env.JWT_SECRET);

    // Fetch fresh user data (don't trust JWT claims alone for permissions)
    const user = await db.query('SELECT id, role, is_active FROM users WHERE id = ?', [decoded.userId]);

    if (!user || !user.is_active) {
      auditLogger.warn({ event: 'auth_inactive_user', userId: decoded.userId });
      return res.status(403).json({ error: 'Account inactive' });
    }

    req.user = {
      id: user.id,
      role: user.role,
      permissions: getUserPermissions(user.role)
    };

    next();
  } catch (err) {
    auditLogger.warn({ event: 'auth_failed', error: err.message, ip: req.ip });
    return res.status(403).json({ error: 'Invalid token' });
  }
};

// Permission check middleware
const requirePermission = (permission) => {
  return (req, res, next) => {
    if (!req.user.permissions.includes(permission)) {
      auditLogger.warn({
        event: 'authorization_denied',
        userId: req.user.id,
        requiredPermission: permission,
        path: req.path,
        method: req.method
      });
      return res.status(403).json({ error: 'Permission denied' });
    }
    next();
  };
};

// Resource ownership check middleware
const checkResourceOwnership = (resourceType, paramName = 'id') => {
  return async (req, res, next) => {
    const resourceId = req.params[paramName];
    const userId = req.user.id;

    // Admins with write_all permission bypass ownership check
    if (req.user.permissions.includes(PERMISSIONS.USERS_WRITE_ALL)) {
      auditLogger.info({
        event: 'admin_resource_access',
        userId,
        resourceType,
        resourceId,
        path: req.path
      });
      return next();
    }

    // Check ownership based on resource type
    let isOwner = false;

    switch (resourceType) {
      case 'user':
        isOwner = parseInt(resourceId) === userId;
        break;
      case 'profile':
        const profile = await db.query('SELECT user_id FROM profiles WHERE id = ?', [resourceId]);
        isOwner = profile && profile.user_id === userId;
        break;
      case 'document':
        const doc = await db.query('SELECT owner_id FROM documents WHERE id = ?', [resourceId]);
        isOwner = doc && doc.owner_id === userId;
        break;
      default:
        return res.status(500).json({ error: 'Unknown resource type' });
    }

    if (!isOwner) {
      auditLogger.warn({
        event: 'ownership_violation',
        userId,
        resourceType,
        resourceId,
        path: req.path
      });
      return res.status(403).json({ error: 'Access denied to this resource' });
    }

    next();
  };
};

// Combined authorization: permission OR ownership
const authorizeAccess = (permission, resourceType, paramName = 'id') => {
  return async (req, res, next) => {
    // First check if user has broad permission
    if (req.user.permissions.includes(permission)) {
