public class SecureApiClient {

    private static final Logger LOGGER = Logger.getLogger(SecureApiClient.class.getName());
    private static final String API_ENDPOINT = "https://api.payment-service.com/process";  // HTTPS enforced
    private final SSLContext sslContext;

    public SecureApiClient() throws Exception {
        this.sslContext = createSecureSSLContext();
    }

    private SSLContext createSecureSSLContext() throws Exception {
        // Use system default trust store with proper certificate validation
        TrustManagerFactory tmf = TrustManagerFactory.getInstance(
            TrustManagerFactory.getDefaultAlgorithm());
        tmf.init((KeyStore) null);  // Uses default system trust store

        SSLContext context = SSLContext.getInstance("TLSv1.3");  // Use TLS 1.3
        context.init(null, tmf.getTrustManagers(), new java.security.SecureRandom());
        return context;
    }

    public String processPayment(String cardNumber, String cvv, double amount) throws Exception {
        URL url = new URL(API_ENDPOINT);

        // Validate URL scheme
        if (!"https".equalsIgnoreCase(url.getProtocol())) {
            throw new SecurityException("Only HTTPS connections are allowed");
        }

        HttpsURLConnection conn = (HttpsURLConnection) url.openConnection();
        conn.setSSLSocketFactory(sslContext.getSocketFactory());

        // Enable hostname verification (default, but explicit for clarity)
        conn.setHostnameVerifier((hostname, session) -> {
            return javax.net.ssl.HttpsURLConnection
                .getDefaultHostnameVerifier().verify(hostname, session);
        });

        conn.setRequestMethod("POST");
        conn.setRequestProperty("Content-Type", "application/json");
        conn.setRequestProperty("Authorization", "Bearer " + getApiKeyFromSecureStore());
        conn.setConnectTimeout(10000);
        conn.setReadTimeout(30000);
        conn.setDoOutput(true);

        String jsonPayload = String.format(
            "{\"card\":\"%s\",\"cvv\":\"%s\",\"amount\":%.2f}",
            cardNumber, cvv, amount
        );

        LOGGER.info("Processing payment request (card masked: ****" + 
            cardNumber.substring(cardNumber.length() - 4) + ")");

        try (OutputStream os = conn.getOutputStream()) {
            byte[] input = jsonPayload.getBytes(StandardCharsets.UTF_8);
            os.write(input, 0, input.length);
        }

        int responseCode = conn.getResponseCode();
        if (responseCode != 200) {
            LOGGER.warning("Payment API returned status: " + responseCode);
            throw new RuntimeException("Payment processing failed");
        }

        StringBuilder response = new StringBuilder();
        try (BufferedReader br = new BufferedReader(
                new InputStreamReader(conn.getInputStream(), StandardCharsets.UTF_8))) {
            String line;
            while ((line = br.readLine()) != null) {
                response.append(line);
            }
        }
        return response.toString();
    }

    private String getApiKeyFromSecureStore() {
        // Retrieve from secure vault (HashiCorp Vault, AWS Secrets Manager, etc.)
        return System.getenv("PAYMENT_API_KEY");
    }
}
```

**Key Security Controls**:
- **HTTPS Enforcement**: All connections use TLS encryption, protecting data in transit
- **TLS 1.3**: Uses the latest TLS version with modern cipher suites
- **Certificate Validation**: Default trust store validates server certificates against trusted CAs
- **Hostname Verification**: Ensures the server certificate matches the expected hostname
- **Secure Key Storage**: API keys retrieved from environment/secret store, not hardcoded

Great question! Many developers make the critical mistake of disabling certificate validation entirely when dealing with self-signed certificates. This completely defeats the purpose of TLS. Instead, you should create a custom trust store containing only the specific certificates you trust.

**PRODUCTION PATTERN**:

```java
import javax.net.ssl.HttpsURLConnection;
import javax.net.ssl.SSLContext;
import javax.net.ssl.SSLSession;
import javax.net.ssl.TrustManager;
import javax.net.ssl.TrustManagerFactory;
import javax.net.ssl.X509TrustManager;
import java.io.BufferedReader;
import java.io.FileInputStream;
import java.io.InputStream;
import java.io.InputStreamReader;
import java.io.OutputStream;
import java.net.URL;
import java.nio.charset.StandardCharsets;
import java.security.KeyStore;
import java.security.cert.Certificate;
import java.security.cert.CertificateFactory;
import java.security.cert.X509Certificate;
import java.util.Arrays;
import java.util.HashSet;
import java.util.Set;
import java.util.logging.Level;
import java.util.logging.Logger;

public class ProductionSecureClient {

    private static final Logger LOGGER = Logger.getLogger(ProductionSecureClient.class.getName());
    private static final Set<String> ALLOWED_TLS_PROTOCOLS = new HashSet<>(Arrays.asList("TLSv1.2", "TLSv1.3"));
    private static final Set<String> ALLOWED_HOSTS = new HashSet<>(Arrays.asList(
        "api.internal.company.com",
        "payments.internal.company.com"
    ));

    private final SSLContext sslContext;
    private final boolean isPinningEnabled;
    private final String expectedCertFingerprint;

    public ProductionSecureClient(String truststorePath, String truststorePassword,
                                   boolean enablePinning, String certFingerprint) throws Exception {
        this.isPinningEnabled = enablePinning;
        this.expectedCertFingerprint = certFingerprint;
        this.sslContext = createCustomSSLContext(truststorePath, truststorePassword);
    }

    /**
     * Creates an SSL context with a custom trust store for internal certificates.
     * This is the SECURE way to handle self-signed or internal CA certificates.
     */
    private SSLContext createCustomSSLContext(String truststorePath, String password) throws Exception {
        // Load custom trust store containing internal CA or self-signed certs
        KeyStore trustStore = KeyStore.getInstance(KeyStore.getDefaultType());

        try (FileInputStream fis = new FileInputStream(truststorePath)) {
            trustStore.load(fis, password.toCharArray());
        }

        // Validate trust store is not empty
        if (trustStore.size() == 0) {
            throw new SecurityException("Trust store is empty - no certificates to trust");
        }

        LOGGER.info("Loaded trust store with " + trustStore.size() + " entries");

        TrustManagerFactory tmf = TrustManagerFactory.getInstance(
            TrustManagerFactory.getDefaultAlgorithm());
        tmf.init(trustStore);

        // Wrap trust managers with additional validation if pinning is enabled
        TrustManager[] trustManagers = tmf.getTrustManagers();
        if (isPinningEnabled) {
            trustManagers = wrapWithPinningValidation(trustManagers);
        }

        SSLContext context = SSLContext.getInstance("TLSv1.3");
        context.init(null, trustManagers, new java.security.SecureRandom());

        return context;
    }

    /**
     * Wraps trust managers with certificate pinning validation.
     */
    private TrustManager[] wrapWithPinningValidation(TrustManager[] original) {
        return new TrustManager[] {
            new X509TrustManager() {
                private final X509TrustManager delegate = (X509TrustManager) original[0];

                @Override
                public void checkClientTrusted(X509Certificate[] chain, String authType) 
                        throws java.security.cert.CertificateException {
                    delegate.checkClientTrusted(chain, authType);
                }

                @Override
                public void checkServerTrusted(X509Certificate[] chain, String authType) 
                        throws java.security.cert.CertificateException {
                    // First, perform standard validation
                    delegate.checkServerTrusted(chain, authType);

                    // Then verify certificate fingerprint (pinning)
                    if (chain.length > 0) {
                        String actualFingerprint = getCertificateFingerprint(chain[0]);
                        if (!actualFingerprint.equalsIgnoreCase(expectedCertFingerprint)) {
                            LOGGER.severe("Certificate pinning failed! Expected: " + 
                                expectedCertFingerprint + ", Got: " + actualFingerprint);
                            throw new java.security.cert.CertificateException(
                                "Certificate pinning validation failed");
                        }
                        LOGGER.fine("Certificate pinning validation passed");
                    }
                }

                @Override
                public X509Certificate[] getAcceptedIssuers() {
                    return delegate.getAcceptedIssuers();
                }
            }
        };
    }

    private String getCertificateFingerprint(X509Certificate cert) throws java.security.cert.CertificateException {
        try {
            java.security.MessageDigest md = java.security.MessageDigest.getInstance("SHA-256");
            byte[] digest = md.digest(cert.getEncoded());
            StringBuilder sb = new StringBuilder();
            for (byte b : digest) {
                sb.append(String.format("%02X:", b));
            }
            return sb.substring(0, sb.length() - 1);
        } catch (Exception e) {
            throw new java.security.cert.CertificateException("Failed to compute fingerprint", e);
        }
    }

    public String makeSecureRequest(String endpoint, String payload) throws Exception {
        URL url = new URL(endpoint);

        // Validate protocol
        if (!"https".equalsIgnoreCase(url.getProtocol())) {
            throw new SecurityException("HTTP connections are not allowed - use HTTPS");
        }

        // Validate host against allowlist
        if (!ALLOWED_HOSTS.contains(url.getHost().toLowerCase())) {
            LOGGER.warning("Connection attempt to non-allowlisted host: " + url.getHost());
            throw new SecurityException("Host not in allowlist: " + url.getHost());
        }

        HttpsURLConnection conn = (HttpsURLConnection) url.openConnection();
        conn.setSSLSocketFactory(sslContext.getSocketFactory());

        // Strict hostname verification
        conn.setHostnameVerifier((hostname, session) -> {
            // Use default verifier plus additional checks
            boolean defaultResult = HttpsURLConnection.getDefaultHostnameVerifier()
                .verify(hostname, session);

            if (!defaultResult) {
                LOGGER.severe("Hostname verification failed for: " + hostname);
                return false;
            }

            // Additional: Verify TLS protocol version
            String protocol = session.getProtocol();
            if (!ALLOWED_TLS_PROTOCOLS.contains(protocol)) {
                LOGGER.severe("Disallowed TLS protocol: " + protocol);
                return false;
            }

            logConnectionDetails(session);
            return true;
        });

        conn.setRequestMethod("POST");
        conn.setRequestProperty("Content-Type", "application/json");
        conn.setRequestProperty("X-Request-ID", java.util.UUID.randomUUID().toString());
        conn.setConnectTimeout(10000);
        conn.setReadTimeout(30000);
        conn.setDoOutput(true);

        try (OutputStream os = conn.getOutputStream()) {
            byte[] input = payload.getBytes(StandardCharsets.UTF_8);
            os.write(input, 0, input.length);
        }

        int responseCode = conn.getResponseCode();
        LOGGER.info("Request to " + url.getHost() + " completed with status: " + responseCode);

        InputStream is = (responseCode >= 400) ? conn.getErrorStream() : conn.getInputStream();
        StringBuilder response = new StringBuilder();
        try (BufferedReader br = new BufferedReader(new InputStreamReader(is, StandardCharsets.UTF_8))) {
            String line;
            while ((line = br.readLine()) != null) {
                response.append(line);
            }
        }

        if (responseCode >= 400) {
            throw new RuntimeException("Request failed with status " + responseCode);
        }

        return response.toString();
    }

    private void logConnectionDetails(SSLSession session) {
        LOGGER.fine(String.format(
            "TLS Connection established - Protocol: %s, Cipher: %s, Peer: %s",
            session.getProtocol(),
            session.getCipherSuite(),
            session.getPeerHost()
        ));
    }

    /**
     * Utility method to create trust store from PEM certificate file.
     */
    public static void createTrustStoreFromPem(String pemPath, String outputPath, 
                                                String password) throws Exception {
        CertificateFactory cf = CertificateFactory.getInstance("X.509");

        KeyStore ks = KeyStore.getInstance(KeyStore.getDefaultType());
        ks.load(null, password.toCharArray());

        try (FileInputStream fis = new FileInputStream(pemPath)) {
            Certificate cert = cf.generateCertificate(fis);
            ks.setCertificateEntry("internal-ca", cert);
        }

        try (java.io.FileOutputStream fos = new java.io.FileOutputStream(outputPath)) {
            ks.store(fos, password.toCharArray());
        }

        LOGGER.info("Trust store created at: " + outputPath);
    }
}
```

**Defense in Depth Layers**:

1. **Custom Trust Store (Never Disable Validation)**:
```java
// WRONG - Never do this!
TrustManager[] trustAllCerts = new TrustManager[] {
    new X509TrustManager() {
        public void checkServerTrusted(X509Certificate[] certs, String authType) { }
        public void checkClientTrusted(X509Certificate[] certs, String authType) { }
        public X509Certificate[] getAcceptedIssuers() { return new X509Certificate[0]; }
    }
};

// CORRECT - Use custom trust store with specific certificates
KeyStore trustStore = KeyStore.getInstance(KeyStore.getDefaultType());
try (FileInputStream fis = new FileInputStream("/path/to/internal-truststore.jks")) {
    trustStore.load(fis, "changeit".toCharArray());
}
```

2. **Certificate Pinning**:
```java
// Pin to specific certificate fingerprint
String expectedFingerprint = "SHA256:AB:CD:EF:12:34:56:78:90:...";
String actualFingerprint = getCertificateFingerprint(serverCert);
if (!expectedFingerprint.equals(actualFingerprint)) {
    throw new CertificateException("Certificate pinning failed");
}
```

3. **Protocol Version Enforcement**:
```java
// Only allow TLS 1.2 and 1.3
SSLContext ctx = SSLContext.getInstance("TLSv1.3");
// Or configure allowed protocols explicitly
SSLParameters params = new SSLParameters();
params.setProtocols(new String[] { "TLSv1.2", "TLSv1.3" });
socket.setSSLParameters(params);
```

**Additional Protections**:

- **Host Allowlisting**: Only permit connections to known, trusted internal hosts
- **Certificate Rotation Handling**: Implement graceful certificate rotation with monitoring
- **Audit Logging**: Log all TLS connection details for security monitoring
- **Cipher Suite Restrictions**: Disable weak cipher suites in JVM configuration:
```properties
# In java.security file
jdk.tls.disabledAlgorithms=SSLv3, RC4, DES, MD5withRSA, DH keySize < 1024, EC keySize < 224, 3DES_EDE_CBC, anon, NULL
```
- **HSTS Support**: For web applications, implement HTTP Strict Transport Security headers
- **Certificate Expiry Monitoring**: Alert before certificates expire to prevent outages

Logging JSON payloads requires additional care because attackers can craft malicious JSON that exploits log parsers, creates fake fields, or causes log analysis failures. Here's a production-ready approach:

**PRODUCTION PATTERN**:

```go
package main

import (
	"bytes"
	"context"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"io"
	"net/http"
	"regexp"
	"strings"
	"time"

	"github.com/google/uuid"
	"go.uber.org/zap"
	"go.uber.org/zap/zapcore"
)

type contextKey string

const (
	requestIDKey contextKey = "request_id"
	maxBodyLogSize          = 10240 // 10KB max for logging
)

// SensitiveFields that should never be logged
var sensitiveFields = map[string]bool{
	"password":      true,
	"secret":        true,
	"token":         true,
	"api_key":       true,
	"credit_card":   true,
	"ssn":           true,
	"authorization": true,
}

type AuditLogger struct {
	logger *zap.Logger
}

func NewAuditLogger() *AuditLogger {
	config := zap.Config{
		Level:       zap.NewAtomicLevelAt(zap.InfoLevel),
		Development: false,
		Encoding:    "json",
		EncoderConfig: zapcore.EncoderConfig{
			TimeKey:        "timestamp",
			LevelKey:       "level",
			NameKey:        "logger",
			CallerKey:      "caller",
			MessageKey:     "event",
			StacktraceKey:  "stacktrace",
			LineEnding:     zapcore.DefaultLineEnding,
			EncodeLevel:    zapcore.LowercaseLevelEncoder,
			EncodeTime:     zapcore.ISO8601TimeEncoder,
			EncodeDuration: zapcore.SecondsDurationEncoder,
			EncodeCaller:   zapcore.ShortCallerEncoder,
		},
		OutputPaths:      []string{"stdout", "/var/log/app/audit.log"},
		ErrorOutputPaths: []string{"stderr"},
	}

	logger, _ := config.Build()
	return &AuditLogger{logger: logger}
}

// sanitizeString removes injection characters and limits length
func (al *AuditLogger) sanitizeString(input string) string {
	// Remove control characters and escape sequences
	re := regexp.MustCompile(`[\x00-\x1f\x7f\x1b\[\]\(\)]`)
	sanitized := re.ReplaceAllString(input, "[REMOVED]")

	// Replace potential JSON breaking characters
	sanitized = strings.ReplaceAll(sanitized, "\\", "\\\\")

	// Truncate long strings
	if len(sanitized) > 500 {
		sanitized = sanitized[:500] + "...[truncated]"
	}

	return sanitized
}

// redactSensitiveData recursively redacts sensitive fields from a map
func (al *AuditLogger) redactSensitiveData(data map[string]interface{}) map[string]interface{} {
	redacted := make(map[string]interface{})

	for key, value := range data {
		lowerKey := strings.ToLower(key)

		// Check if field is sensitive
		if sensitiveFields[lowerKey] {
			redacted[key] = "[REDACTED]"
			continue
		}

		// Recursively process nested maps
		if nested, ok := value.(map[string]interface{}); ok {
			redacted[key] = al.redactSensitiveData(nested)
			continue
		}

		// Sanitize string values
		if strVal, ok := value.(string); ok {
			redacted[key] = al.sanitizeString(strVal)
			continue
		}

		// Keep other types as-is
		redacted[key] = value
	}

	return redacted
}

// SafeLogRequestBody safely logs API request bodies
func (al *AuditLogger) SafeLogRequestBody(ctx context.Context, body []byte, contentType string) {
	requestID, _ := ctx.Value(requestIDKey).(string)

	// Limit body size for logging
	if len(body) > maxBodyLogSize {
		al.logger.Info("request_body_truncated",
			zap.String("request_id", requestID),
			zap.Int("original_size", len(body)),
			zap.Int("logged_size", maxBodyLogSize),
		)
		body = body[:maxBodyLogSize]
	}

	// Calculate hash for integrity verification
	hash := sha256.Sum256(body)
	bodyHash := hex.EncodeToString(hash[:])

	// Only parse JSON if content type matches
	if strings.Contains(contentType, "application/json") {
		var jsonData map[string]interface{}
		if err := json.Unmarshal(body, &jsonData); err != nil {
			// Log as raw string if JSON parsing fails
			al.logger.Warn("request_body_invalid_json",
				zap.String("request_id", requestID),
				zap.String("body_hash", bodyHash),
				zap.Int("body_size", len(body)),
				zap.Error(err),
			)
			return
		}

		// Redact sensitive data and sanitize values
		safeData := al.redactSensitiveData(jsonData)

		// Log as structured data
		al.logger.Info("api_request_body",
			zap.String("request_id", requestID),
			zap.Any("body", safeData),
			zap.String("body_hash", bodyHash),
			zap.Int("body_size", len(body)),
			zap.Time("logged_at", time.Now().UTC()),
		)
	} else {
		// Non-JSON: log metadata only
		al.logger.Info("api_request_body_non_json",
			zap.String("request_id", requestID),
			zap.String("content_type", contentType),
			zap.String("body_hash", bodyHash),
			zap.Int("body_size", len(body)),
		)
	}
}

// LoggingMiddleware captures and logs all requests safely
func LoggingMiddleware(al *AuditLogger, next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		requestID := uuid.New().String()
		ctx := context.WithValue(r.Context(), requestIDKey, requestID)
		start := time.Now()

		// Log request start
		al.logger.Info("request_start",
			zap.String("request_id", requestID),
			zap.String("method", r.Method),
			zap.String("path", al.sanitizeString(r.URL.Path)),
			zap.String("query", al.sanitizeString(r.URL.RawQuery)),
			zap.String("client_ip", r.RemoteAddr),
			zap.String("user_agent", al.sanitizeString(r.UserAgent())),
		)

		// Read and restore body for logging
		if r.Body != nil && r.ContentLength > 0 {
			body, err := io.ReadAll(io.LimitReader(r.Body, maxBodyLogSize+1))
			if err == nil {
				al.SafeLogRequestBody(ctx, body, r.Header.Get("Content-Type"))
				r.Body = io.NopCloser(bytes.NewBuffer(body))
			}
		}

		// Create response wrapper to capture status
		rw := &responseWriter{ResponseWriter: w, statusCode: http.StatusOK}

		// Process request
		next.ServeHTTP(rw, r.WithContext(ctx))

		// Log request completion
		al.logger.Info("request_complete",
			zap.String("request_id", requestID),
			zap.Int("status_code", rw.statusCode),
			zap.Duration("duration", time.Since(start)),
		)
	})
}

type responseWriter struct {
	http.ResponseWriter
	statusCode int
}

func (rw *responseWriter) WriteHeader(code int) {
	rw.statusCode = code
	rw.ResponseWriter.WriteHeader(code)
}

func main() {
	al := NewAuditLogger()
	defer al.logger.Sync()

	mux := http.NewServeMux()
	mux.HandleFunc("/api/data", func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusOK)
		w.Write([]byte(`{"status":"ok"}`))
	})

	server := &http.Server{
		Addr:         ":8080",
		Handler:      LoggingMiddleware(al, mux),
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 10 * time.Second,
	}

	server.ListenAndServe()
}
```

**Defense in Depth Layers**:

1. **Input Sanitization Layer**:
```go
