```php
<?php
// src/Security/SupplyChainDefense.php

declare(strict_types=1);

namespace App\Security;

use Psr\Log\LoggerInterface;

class SupplyChainDefense
{
    public function __construct(
        private readonly LoggerInterface $logger,
        private readonly DependencySecurityMonitor $monitor
    ) {}

    /**
     * Runtime integrity check for critical dependencies
     */
    public function verifyCriticalPackages(): void
    {
        $criticalPackages = [
            'symfony/security-bundle',
            'doctrine/orm',
            'lcobucci/jwt',
        ];

        $vendorDir = dirname(__DIR__, 2) . '/vendor';

        foreach ($criticalPackages as $package) {
            $packagePath = $vendorDir . '/' . $package;
            if (!is_dir($packagePath)) {
                continue;
            }

            // Verify no unexpected .php files in vendor
            $iterator = new \RecursiveIteratorIterator(
                new \RecursiveDirectoryIterator($packagePath)
            );

            foreach ($iterator as $file) {
                if ($file->getExtension() !== 'php') {
                    continue;
                }

                $content = file_get_contents($file->getPathname());

                // Check for suspicious patterns
                $suspiciousPatterns = [
                    '/\beval\s*\(/i',
                    '/\bbase64_decode\s*\(.*\$_(GET|POST|REQUEST|COOKIE)/i',
                    '/\bfile_get_contents\s*\([\'"]https?:\/\/[^packagist]/i',
                    '/\bpreg_replace\s*\([\'"].*\/e[\'"]/',
                    '/\bcreate_function\s*\(/i',
                    '/\$\{.*\}/i',
                ];

                foreach ($suspiciousPatterns as $pattern) {
                    if (preg_match($pattern, $content)) {
                        $this->logger->emergency('Suspicious code detected in vendor', [
                            'file' => $file->getPathname(),
                            'pattern' => $pattern,
                        ]);

                        throw new \RuntimeException(
                            'Potentially malicious code detected in: ' . $file->getPathname()
                        );
                    }
                }
            }
        }
    }

    /**
     * Generates Software Bill of Materials (SBOM) for compliance
     */
    public function generateSBOM(): array
    {
        $lockFile = dirname(__DIR__, 2) . '/composer.lock';
        $lock = json_decode(file_get_contents($lockFile), true);

        $sbom = [
            'bomFormat' => 'CycloneDX',
            'specVersion' => '1.4',
            'version' => 1,
            'metadata' => [
                'timestamp' => date('c'),
                'tools' => [['name' => 'DependencySecurityMonitor', 'version' => '1.0']],
            ],
            'components' => [],
        ];

        foreach ($lock['packages'] ?? [] as $package) {
            $sbom['components'][] = [
                'type' => 'library',
                'name' => $package['name'],
                'version' => $package['version'],
                'purl' => 'pkg:composer/' . $package['name'] . '@' . $package['version'],
                'hashes' => [
                    ['alg' => 'SHA-256', 'content' => $package['dist']['shasum'] ?? 'unknown'],
                ],
                'licenses' => [['license' => ['id' => $package['license'][0] ?? 'unknown']]],
            ];
        }

        return $sbom;
    }
}
