Storing API keys directly in code is extremely dangerous and a leading cause of security breaches. When keys are hardcoded, they often end up in version control, build logs, and client-side bundles where attackers can easily find them.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const axios = require('axios');

const app = express();

// DANGEROUS: Hardcoded API keys in source code
const STRIPE_SECRET_KEY = 'sk_live_EXAMPLE1234567890abcdef';
const AWS_ACCESS_KEY = 'AKIAIOSFODNN7EXAMPLE';
const AWS_SECRET_KEY = 'wJalrXUtnFEMI/K7MDENG/bPxRfiCYEXAMPLEKEY';
const DATABASE_URL = 'mongodb://admin:SuperSecret123@prod-db.example.com:27017/app';

// Payment processing with exposed key
app.post('/api/payment', async (req, res) => {
  try {
    const response = await axios.post(
      'https://api.stripe.com/v1/charges',
      req.body,
      {
        headers: {
          'Authorization': `Bearer ${STRIPE_SECRET_KEY}`,
        }
      }
    );
    // DANGEROUS: Logging sensitive data
    console.log('Payment processed with key:', STRIPE_SECRET_KEY);
    res.json(response.data);
  } catch (error) {
    // DANGEROUS: Exposing error details with potential key info
    res.status(500).json({ error: error.message, config: error.config });
  }
});

// Frontend config endpoint - DANGEROUS!
app.get('/api/config', (req, res) => {
  res.json({
    apiEndpoint: 'https://api.example.com',
    stripeKey: STRIPE_SECRET_KEY,  // Exposed to frontend!
    debug: true
  });
});

app.listen(3000);
```

**Attack Vectors**:

1. **Git History Search**:
```bash
# Attackers scan public repos for exposed keys
git log -p | grep -i 'api_key\|secret\|password\|token'
trufflehog git https://github.com/target/repo --only-verified
```

2. **Build Log Extraction**:
```bash
# Keys often appear in CI/CD logs
curl https://ci.example.com/builds/123/logs | grep -E 'sk_live|AKIA'
```

3. **Frontend Bundle Analysis**:
```javascript
// Attacker deobfuscates bundled JavaScript
// Keys hardcoded in frontend code are trivially extractable
```

**Why This Is Dangerous**:
- Keys committed to Git are permanently in history, even after deletion
- Build systems and logs often expose environment variables
- Frontend bundles can be decompiled to extract embedded secrets
- Error messages may leak credentials in stack traces
- Developers often copy code with keys to Stack Overflow or public repos

**SECURE VERSION**:

```javascript
const express = require('express');
const axios = require('axios');
const helmet = require('helmet');

// Load environment variables (use dotenv only in development)
if (process.env.NODE_ENV !== 'production') {
  require('dotenv').config();
}

const app = express();
app.use(helmet());
app.use(express.json());

// SECURE: Load secrets from environment variables
const config = {
  stripe: {
    secretKey: process.env.STRIPE_SECRET_KEY,
    publishableKey: process.env.STRIPE_PUBLISHABLE_KEY // Only this goes to frontend
  },
  database: {
    url: process.env.DATABASE_URL
  }
};

// Validate required secrets exist at startup
function validateConfig() {
  const required = ['STRIPE_SECRET_KEY', 'DATABASE_URL'];
  const missing = required.filter(key => !process.env[key]);

  if (missing.length > 0) {
    console.error('Missing required environment variables:', missing.join(', '));
    process.exit(1);
  }
}
validateConfig();

// SECURE: Payment processing without exposing keys
app.post('/api/payment', async (req, res) => {
  try {
    const response = await axios.post(
      'https://api.stripe.com/v1/charges',
      req.body,
      {
        headers: {
          'Authorization': `Bearer ${config.stripe.secretKey}`,
        }
      }
    );
    // SECURE: Log only non-sensitive data
    console.log('Payment processed:', {
      amount: req.body.amount,
      timestamp: new Date().toISOString()
    });
    res.json({ success: true, chargeId: response.data.id });
  } catch (error) {
    // SECURE: Never expose internal error details
    console.error('Payment error:', error.message);
    res.status(500).json({ error: 'Payment processing failed' });
  }
});

// SECURE: Only expose publishable (public) key to frontend
app.get('/api/config', (req, res) => {
  res.json({
    stripePublishableKey: config.stripe.publishableKey,
    apiVersion: '2.0'
  });
});

app.listen(3000);
```

**Key Security Controls**:
- **Environment variables**: Secrets loaded from environment, never hardcoded
- **Startup validation**: Application fails fast if required secrets missing
- **Secret separation**: Only publishable keys sent to frontend, secret keys stay server-side
- **Safe error handling**: Internal errors logged but not exposed to clients
- **Helmet middleware**: Adds security headers to prevent common attacks

Production secret management requires a dedicated secrets manager with encryption at rest, access controls, audit logging, and rotation capabilities. Here's a production-grade implementation using AWS Secrets Manager with automatic rotation support.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const helmet = require('helmet');
const { SecretsManagerClient, GetSecretValueCommand } = require('@aws-sdk/client-secrets-manager');
const winston = require('winston');

const app = express();
app.use(helmet());
app.use(express.json());

// Production-grade logger (no sensitive data)
const logger = winston.createLogger({
  level: process.env.LOG_LEVEL || 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  defaultMeta: { service: 'payment-service' },
  transports: [
    new winston.transports.Console()
  ]
});

// Secrets cache with TTL for rotation support
class SecretsCache {
  constructor(options = {}) {
    this.client = new SecretsManagerClient({
      region: process.env.AWS_REGION || 'us-east-1'
    });
    this.cache = new Map();
    this.ttlMs = options.ttlMs || 300000; // 5 minute cache TTL
    this.refreshing = new Map();
  }

  async getSecret(secretId) {
    const cached = this.cache.get(secretId);
    const now = Date.now();

    // Return cached value if still valid
    if (cached && (now - cached.timestamp) < this.ttlMs) {
      return cached.value;
    }

    // Prevent thundering herd during refresh
    if (this.refreshing.has(secretId)) {
      return this.refreshing.get(secretId);
    }

    const refreshPromise = this.fetchSecret(secretId);
    this.refreshing.set(secretId, refreshPromise);

    try {
      const value = await refreshPromise;
      this.cache.set(secretId, { value, timestamp: now });
      return value;
    } finally {
      this.refreshing.delete(secretId);
    }
  }

  async fetchSecret(secretId) {
    try {
      const command = new GetSecretValueCommand({
        SecretId: secretId,
        VersionStage: 'AWSCURRENT' // Gets the current active version
      });

      const response = await this.client.send(command);

      logger.info('Secret fetched successfully', {
        secretId: secretId,
        versionId: response.VersionId,
        // Never log the actual secret value!
      });

      if (response.SecretString) {
        return JSON.parse(response.SecretString);
      }
      throw new Error('Binary secrets not supported');
    } catch (error) {
      logger.error('Failed to fetch secret', {
        secretId: secretId,
        errorCode: error.name,
        // Don't log full error message - may contain secret info
      });
      throw new Error('Secret retrieval failed');
    }
  }

  // Force refresh for rotation events
  invalidate(secretId) {
    this.cache.delete(secretId);
    logger.info('Secret cache invalidated', { secretId });
  }
}

const secretsCache = new SecretsCache({ ttlMs: 300000 });

// Secret names as constants (not the values!)
const SECRET_IDS = {
  STRIPE: process.env.STRIPE_SECRET_ID || 'prod/payment/stripe',
  DATABASE: process.env.DB_SECRET_ID || 'prod/database/main'
};

// Middleware to inject secrets into request context
const withSecrets = (requiredSecrets) => async (req, res, next) => {
  try {
    req.secrets = {};
    for (const secretId of requiredSecrets) {
      req.secrets[secretId] = await secretsCache.getSecret(secretId);
    }
    next();
  } catch (error) {
    logger.error('Secret injection failed', {
      requestId: req.id,
      path: req.path
    });
    res.status(503).json({ error: 'Service temporarily unavailable' });
  }
};

// Webhook endpoint for rotation events (Lambda or SNS trigger)
app.post('/internal/rotate-secrets', (req, res) => {
  // Validate internal request (check signature, source IP, etc.)
  const internalToken = req.headers['x-internal-token'];
  if (internalToken !== process.env.INTERNAL_WEBHOOK_TOKEN) {
    logger.warn('Unauthorized rotation webhook attempt', {
      sourceIp: req.ip
    });
    return res.status(403).json({ error: 'Forbidden' });
  }

  const { secretId } = req.body;
  if (secretId) {
    secretsCache.invalidate(secretId);
    logger.info('Secret rotation processed', { secretId });
  }
  res.json({ status: 'ok' });
});

// Payment endpoint with dynamic secret retrieval
app.post('/api/payment',
  withSecrets([SECRET_IDS.STRIPE]),
  async (req, res) => {
    const requestId = req.id || crypto.randomUUID();
    const stripeSecrets = req.secrets[SECRET_IDS.STRIPE];

    try {
      const stripe = require('stripe')(stripeSecrets.secretKey);

      const paymentIntent = await stripe.paymentIntents.create({
        amount: req.body.amount,
        currency: req.body.currency || 'usd',
        metadata: { requestId }
      });

      logger.info('Payment created', {
        requestId,
        paymentIntentId: paymentIntent.id,
        amount: req.body.amount
      });

      res.json({
        clientSecret: paymentIntent.client_secret,
        paymentIntentId: paymentIntent.id
      });
    } catch (error) {
      logger.error('Payment failed', {
        requestId,
        errorType: error.type,
        errorCode: error.code
      });
      res.status(400).json({ error: 'Payment processing failed' });
    }
  }
);

// Health check that validates secret access
app.get('/health', async (req, res) => {
  try {
    // Verify we can access secrets (but don't return them!)
    await secretsCache.getSecret(SECRET_IDS.STRIPE);
    res.json({ status: 'healthy', timestamp: new Date().toISOString() });
  } catch (error) {
    res.status(503).json({ status: 'unhealthy' });
  }
});

// Graceful shutdown - clear sensitive data from memory
process.on('SIGTERM', () => {
  logger.info('Shutting down gracefully');
  secretsCache.cache.clear();
  process.exit(0);
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  logger.info('Server started', { port: PORT, env: process.env.NODE_ENV });
});
```

