**Why This Is Dangerous**:
- **Clickjacking**: Without X-Frame-Options, pages can be embedded in malicious iframes to trick users into clicking hidden buttons
- **XSS Amplification**: Missing Content-Security-Policy allows inline scripts and external resource injection
- **MIME Sniffing**: Without X-Content-Type-Options, browsers may execute files as scripts regardless of declared content type
- **Man-in-the-Middle**: Missing Strict-Transport-Security allows protocol downgrade attacks

**SECURE VERSION**:

```java
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configuration.WebSecurityConfigurerAdapter;
import org.springframework.security.web.header.writers.ReferrerPolicyHeaderWriter;
import org.springframework.security.web.header.writers.StaticHeadersWriter;

@SpringBootApplication
public class SecureApplication {
    public static void main(String[] args) {
        SpringApplication.run(SecureApplication.class, args);
    }
}

@Configuration
@EnableWebSecurity
class SecurityConfig extends WebSecurityConfigurerAdapter {

    @Override
    protected void configure(HttpSecurity http) throws Exception {
        http
            // Enable comprehensive security headers
            .headers(headers -> headers
                // Prevent clickjacking - deny all framing
                .frameOptions().deny()

                // Prevent XSS attacks in older browsers
                .xssProtection().block(true)

                // Prevent MIME type sniffing
                .contentTypeOptions().and()

                // Enforce HTTPS for 1 year including subdomains
                .httpStrictTransportSecurity(hsts -> hsts
                    .maxAgeInSeconds(31536000)
                    .includeSubDomains(true)
                    .preload(true)
                )

                // Content Security Policy
                .contentSecurityPolicy("default-src 'self'; script-src 'self'; style-src 'self'; img-src 'self' data:; font-src 'self'; frame-ancestors 'none'; form-action 'self';")
                .and()

                // Referrer Policy
                .referrerPolicy(ReferrerPolicyHeaderWriter.ReferrerPolicy.STRICT_ORIGIN_WHEN_CROSS_ORIGIN)
                .and()

                // Permissions Policy (formerly Feature Policy)
                .addHeaderWriter(new StaticHeadersWriter(
                    "Permissions-Policy",
                    "geolocation=(), microphone=(), camera=()"
                ))
            )
            .csrf().csrfTokenRepository(CookieCsrfTokenRepository.withHttpOnlyFalse())
            .and()
            .authorizeRequests()
                .antMatchers("/api/**").authenticated()
                .anyRequest().permitAll();
    }
}
```

**Key Security Controls**:
- **X-Frame-Options: DENY** - Prevents the page from being embedded in any iframe, blocking clickjacking attacks
- **Content-Security-Policy** - Defines allowed sources for scripts, styles, and other resources, mitigating XSS
- **Strict-Transport-Security** - Forces HTTPS connections, preventing protocol downgrade attacks
- **X-Content-Type-Options: nosniff** - Prevents browsers from MIME-sniffing responses away from declared content-type

Great question! Production applications often need flexible framing policies and dynamic CSP. Here's a comprehensive approach with nonce-based CSP, conditional framing, and monitoring.

**PRODUCTION PATTERN**:

```java
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.core.env.Environment;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.annotation.web.configuration.WebSecurityConfigurerAdapter;
import org.springframework.security.web.header.writers.DelegatingRequestMatcherHeaderWriter;
import org.springframework.security.web.header.writers.StaticHeadersWriter;
import org.springframework.security.web.header.writers.frameoptions.XFrameOptionsHeaderWriter;
import org.springframework.security.web.util.matcher.AntPathRequestMatcher;
import org.springframework.web.filter.OncePerRequestFilter;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.servlet.FilterChain;
import javax.servlet.ServletException;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.security.SecureRandom;
import java.util.Base64;
import java.util.Arrays;
import java.util.List;

@SpringBootApplication
public class ProductionSecureApplication {
    public static void main(String[] args) {
        SpringApplication.run(ProductionSecureApplication.class, args);
    }
}

@Configuration
@EnableWebSecurity
class ProductionSecurityConfig extends WebSecurityConfigurerAdapter {

    private static final Logger securityLogger = LoggerFactory.getLogger("security-audit");

    // Trusted domains that can embed our application
    private static final List<String> ALLOWED_FRAME_ANCESTORS = Arrays.asList(
        "https://partner.trusted-company.com",
        "https://dashboard.internal.company.com"
    );

    private final Environment environment;

    public ProductionSecurityConfig(Environment environment) {
        this.environment = environment;
    }

    @Override
    protected void configure(HttpSecurity http) throws Exception {
        boolean isProduction = Arrays.asList(environment.getActiveProfiles()).contains("production");

        http
            // Add CSP nonce filter before security headers
            .addFilterBefore(cspNonceFilter(), org.springframework.security.web.header.HeaderWriterFilter.class)

            .headers(headers -> headers
                // Conditional X-Frame-Options based on endpoint
                .frameOptions().disable() // We'll handle this via CSP frame-ancestors

                .xssProtection().block(true).and()
                .contentTypeOptions().and()

                // HSTS - stronger settings for production
                .httpStrictTransportSecurity(hsts -> {
                    hsts.maxAgeInSeconds(isProduction ? 63072000 : 3600); // 2 years prod, 1 hour dev
                    hsts.includeSubDomains(true);
                    if (isProduction) {
                        hsts.preload(true);
                    }
                })

                // Cache control for sensitive pages
                .cacheControl().and()

                // Permissions Policy
                .addHeaderWriter(new StaticHeadersWriter(
                    "Permissions-Policy",
                    "accelerometer=(), camera=(), geolocation=(self), gyroscope=(), magnetometer=(), microphone=(), payment=(self), usb=()"
                ))

                // Cross-Origin headers for additional isolation
                .addHeaderWriter(new StaticHeadersWriter("Cross-Origin-Opener-Policy", "same-origin"))
                .addHeaderWriter(new StaticHeadersWriter("Cross-Origin-Embedder-Policy", "require-corp"))
                .addHeaderWriter(new StaticHeadersWriter("Cross-Origin-Resource-Policy", "same-origin"))
            )
            .csrf().csrfTokenRepository(CookieCsrfTokenRepository.withHttpOnlyFalse())
            .and()
            .authorizeRequests()
                .antMatchers("/api/**").authenticated()
                .antMatchers("/embed/**").permitAll() // Embeddable endpoints
                .anyRequest().permitAll();
    }

    @Bean
    public CspNonceFilter cspNonceFilter() {
        return new CspNonceFilter(ALLOWED_FRAME_ANCESTORS);
    }
}

/**
 * Filter that generates unique CSP nonces per request and sets dynamic CSP headers
 */
class CspNonceFilter extends OncePerRequestFilter {

    private static final Logger securityLogger = LoggerFactory.getLogger("security-audit");
    private static final SecureRandom secureRandom = new SecureRandom();

    public static final String CSP_NONCE_ATTRIBUTE = "cspNonce";

    private final List<String> allowedFrameAncestors;

    public CspNonceFilter(List<String> allowedFrameAncestors) {
        this.allowedFrameAncestors = allowedFrameAncestors;
    }

    @Override
    protected void doFilterInternal(HttpServletRequest request, 
                                    HttpServletResponse response, 
                                    FilterChain filterChain) throws ServletException, IOException {

        // Generate cryptographically secure nonce
        String nonce = generateNonce();
        request.setAttribute(CSP_NONCE_ATTRIBUTE, nonce);

        // Build dynamic CSP based on request path
        String csp = buildCspHeader(request, nonce);
        response.setHeader("Content-Security-Policy", csp);

        // Report-only header for testing new policies without breaking functionality
        String reportOnlyCsp = buildStrictCspHeader(nonce);
        response.setHeader("Content-Security-Policy-Report-Only", reportOnlyCsp);

        // Log CSP for audit
        securityLogger.debug("CSP applied for {}: {}", request.getRequestURI(), csp);

        filterChain.doFilter(request, response);
    }

    private String generateNonce() {
        byte[] nonceBytes = new byte[16];
        secureRandom.nextBytes(nonceBytes);
        return Base64.getEncoder().encodeToString(nonceBytes);
    }

    private String buildCspHeader(HttpServletRequest request, String nonce) {
        StringBuilder csp = new StringBuilder();

        // Base policy
        csp.append("default-src 'self'; ");

        // Script policy with nonce for inline scripts
        csp.append("script-src 'self' 'nonce-").append(nonce).append("' 'strict-dynamic'; ");

        // Style policy
        csp.append("style-src 'self' 'nonce-").append(nonce).append("'; ");

        // Image policy
        csp.append("img-src 'self' data: https:; ");

        // Font policy
        csp.append("font-src 'self'; ");

        // Connect policy for API calls
        csp.append("connect-src 'self' https://api.company.com; ");

        // Frame ancestors - conditional based on endpoint
        if (request.getRequestURI().startsWith("/embed/")) {
            // Allow trusted domains to embed specific pages
            csp.append("frame-ancestors ").append(String.join(" ", allowedFrameAncestors)).append("; ");
        } else {
            // Default: no framing allowed
            csp.append("frame-ancestors 'none'; ");
        }

        // Form action restriction
        csp.append("form-action 'self'; ");

        // Base URI restriction
        csp.append("base-uri 'self'; ");

        // Object/embed restriction
        csp.append("object-src 'none'; ");

        // Upgrade insecure requests in production
        csp.append("upgrade-insecure-requests; ");

        // CSP violation reporting endpoint
        csp.append("report-uri /api/security/csp-report; ");
        csp.append("report-to csp-endpoint");

        return csp.toString();
    }

    private String buildStrictCspHeader(String nonce) {
        // Stricter policy for report-only to test future restrictions
        return String.format(
            "default-src 'none'; " +
            "script-src 'nonce-%s'; " +
            "style-src 'nonce-%s'; " +
            "img-src 'self'; " +
            "font-src 'self'; " +
            "connect-src 'self'; " +
            "frame-ancestors 'none'; " +
            "report-uri /api/security/csp-report-strict",
            nonce, nonce
        );
    }
}

/**
 * Controller for handling CSP violation reports
 */
import org.springframework.web.bind.annotation.*;
import com.fasterxml.jackson.databind.JsonNode;

@RestController
@RequestMapping("/api/security")
class CspReportController {

    private static final Logger securityLogger = LoggerFactory.getLogger("security-audit");

    @PostMapping("/csp-report")
    public void handleCspReport(@RequestBody JsonNode report, HttpServletRequest request) {
        JsonNode cspReport = report.get("csp-report");
        if (cspReport != null) {
            securityLogger.warn(
                "CSP_VIOLATION: blocked_uri={}, violated_directive={}, document_uri={}, source_ip={}, user_agent={}",
                cspReport.path("blocked-uri").asText(),
                cspReport.path("violated-directive").asText(),
                cspReport.path("document-uri").asText(),
                request.getRemoteAddr(),
                request.getHeader("User-Agent")
            );

            // Alert security team for suspicious patterns
            if (isSuspiciousViolation(cspReport)) {
                alertSecurityTeam(cspReport, request);
            }
        }
    }

    @PostMapping("/csp-report-strict")
    public void handleStrictCspReport(@RequestBody JsonNode report) {
        // Log report-only violations for policy tuning
        securityLogger.info("CSP_STRICT_VIOLATION: {}", report.toString());
    }

    private boolean isSuspiciousViolation(JsonNode cspReport) {
        String blockedUri = cspReport.path("blocked-uri").asText("");
        // Flag external domains or inline violations
        return blockedUri.startsWith("http") && !blockedUri.contains("company.com");
    }

    private void alertSecurityTeam(JsonNode report, HttpServletRequest request) {
        // Integration with alerting system (PagerDuty, Slack, etc.)
        securityLogger.error("SECURITY_ALERT: Suspicious CSP violation detected - {}", report);
    }
}

