Excellent questions! DNS rebinding is a sophisticated attack where attackers configure their DNS to first return a safe IP (passing validation), then quickly change it to an internal IP before the actual request. For redirects, you need to validate each redirect destination, not just the initial URL.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const axios = require('axios');
const cheerio = require('cheerio');
const { URL } = require('url');
const dns = require('dns').promises;
const net = require('net');
const https = require('https');
const http = require('http');

const app = express();
app.use(express.json());

// Configuration
const CONFIG = {
  MAX_REDIRECTS: 3,
  REQUEST_TIMEOUT: 5000,
  MAX_RESPONSE_SIZE: 1024 * 1024, // 1MB
  DNS_CACHE_TTL: 60000, // 1 minute
  RATE_LIMIT_WINDOW: 60000,
  RATE_LIMIT_MAX: 30
};

// DNS cache to prevent rebinding between validation and request
const dnsCache = new Map();

const BLOCKED_IP_RANGES = [
  /^127\./,
  /^10\./,
  /^172\.(1[6-9]|2[0-9]|3[0-1])\./,
  /^192\.168\./,
  /^169\.254\./,
  /^0\./,
  /^224\./,
  /^100\.(6[4-9]|[7-9][0-9]|1[0-1][0-9]|12[0-7])\./,  // Carrier-grade NAT
  /^::1$/,
  /^fc00:/i,
  /^fe80:/i,
  /^fd/i
];

const BLOCKED_HOSTNAMES = new Set([
  'localhost',
  'metadata.google.internal',
  'metadata',
  'kubernetes.default.svc',
  'kubernetes.default',
  '169.254.169.254',
  'instance-data',
  'metadata.internal'
]);

// Rate limiting per IP
const rateLimiter = new Map();

function checkRateLimit(ip) {
  const now = Date.now();
  const windowStart = now - CONFIG.RATE_LIMIT_WINDOW;

  if (!rateLimiter.has(ip)) {
    rateLimiter.set(ip, []);
  }

  const requests = rateLimiter.get(ip).filter(t => t > windowStart);
  requests.push(now);
  rateLimiter.set(ip, requests);

  return requests.length <= CONFIG.RATE_LIMIT_MAX;
}

function isIpBlocked(ip) {
  return BLOCKED_IP_RANGES.some(range => range.test(ip));
}

async function resolveAndCache(hostname) {
  const cacheKey = hostname.toLowerCase();
  const cached = dnsCache.get(cacheKey);

  if (cached && cached.expiry > Date.now()) {
    return cached.addresses;
  }

  const addresses = await dns.resolve4(hostname).catch(() => []);
  const addresses6 = await dns.resolve6(hostname).catch(() => []);
  const allAddresses = [...addresses, ...addresses6];

  if (allAddresses.length === 0) {
    throw new Error('DNS resolution failed');
  }

  dnsCache.set(cacheKey, {
    addresses: allAddresses,
    expiry: Date.now() + CONFIG.DNS_CACHE_TTL
  });

  return allAddresses;
}

async function validateUrl(urlString, isRedirect = false) {
  let parsedUrl;

  try {
    parsedUrl = new URL(urlString);
  } catch (e) {
    return { safe: false, reason: 'Invalid URL format' };
  }

  if (!['http:', 'https:'].includes(parsedUrl.protocol)) {
    return { safe: false, reason: `Protocol ${parsedUrl.protocol} not allowed` };
  }

  const hostname = parsedUrl.hostname.toLowerCase();

  // Check blocked hostnames with fuzzy matching
  for (const blocked of BLOCKED_HOSTNAMES) {
    if (hostname === blocked || hostname.endsWith('.' + blocked)) {
      return { safe: false, reason: 'Blocked hostname' };
    }
  }

  // Check ports - only allow standard ports
  const port = parsedUrl.port || (parsedUrl.protocol === 'https:' ? '443' : '80');
  if (!['80', '443', '8080', '8443'].includes(port)) {
    return { safe: false, reason: 'Non-standard port not allowed' };
  }

  // Direct IP check
  if (net.isIP(hostname)) {
    if (isIpBlocked(hostname)) {
      return { safe: false, reason: 'Direct IP access to internal network blocked' };
    }
  } else {
    // DNS resolution with caching (anti-rebinding)
    try {
      const addresses = await resolveAndCache(hostname);
      for (const ip of addresses) {
        if (isIpBlocked(ip)) {
          return { 
            safe: false, 
            reason: `Hostname ${hostname} resolves to blocked IP ${ip}` 
          };
        }
      }
    } catch (dnsError) {
      return { safe: false, reason: 'DNS resolution failed' };
    }
  }

  return { safe: true, url: parsedUrl, hostname };
}

// Custom HTTP agent that forces using our cached DNS
function createSafeAgent(hostname) {
  const cached = dnsCache.get(hostname.toLowerCase());

  if (!cached || cached.addresses.length === 0) {
    throw new Error('No cached DNS for hostname');
  }

  // Use first safe IP from cache
  const safeIp = cached.addresses.find(ip => !isIpBlocked(ip));

  if (!safeIp) {
    throw new Error('No safe IP in cache');
  }

  return {
    lookup: (hostname, options, callback) => {
      // Force use of our validated IP
      callback(null, safeIp, net.isIPv4(safeIp) ? 4 : 6);
    }
  };
}

async function fetchWithRedirectValidation(url, redirectCount = 0) {
  if (redirectCount > CONFIG.MAX_REDIRECTS) {
    throw new Error('Too many redirects');
  }

  const validation = await validateUrl(url, redirectCount > 0);

  if (!validation.safe) {
    throw new Error(`URL blocked: ${validation.reason}`);
  }

  const agentConfig = createSafeAgent(validation.hostname);
  const isHttps = validation.url.protocol === 'https:';

  const agent = isHttps 
    ? new https.Agent({ lookup: agentConfig.lookup })
    : new http.Agent({ lookup: agentConfig.lookup });

  const response = await axios.get(url, {
    timeout: CONFIG.REQUEST_TIMEOUT,
    maxRedirects: 0, // Handle redirects manually
    maxContentLength: CONFIG.MAX_RESPONSE_SIZE,
    validateStatus: () => true, // Accept all status codes
    httpAgent: isHttps ? undefined : agent,
    httpsAgent: isHttps ? agent : undefined,
    headers: {
      'User-Agent': 'URLPreviewBot/1.0 (Security-Hardened)',
      'Accept': 'text/html,application/xhtml+xml'
    }
  });

  // Handle redirects with validation
  if ([301, 302, 303, 307, 308].includes(response.status)) {
    const redirectUrl = response.headers.location;

    if (!redirectUrl) {
      throw new Error('Redirect without Location header');
    }

    // Resolve relative URLs
    const absoluteRedirect = new URL(redirectUrl, url).href;

    console.info(`Following redirect: ${url} -> ${absoluteRedirect}`);
    return fetchWithRedirectValidation(absoluteRedirect, redirectCount + 1);
  }

  return response;
}

