Membership inference attacks determine whether specific data points were in the training set, which can violate privacy and reveal proprietary training data. This requires comprehensive defense-in-depth strategies.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const tf = require('@tensorflow/tfjs-node');
const rateLimit = require('express-rate-limit');
const { createClient } = require('redis');
const crypto = require('crypto');
const winston = require('winston');

const app = express();
app.use(express.json());

// Production logging for security monitoring
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' }),
    new winston.transports.File({ filename: 'ml-api.log' })
  ]
});

// Redis for distributed rate limiting and query tracking
const redis = createClient({ url: process.env.REDIS_URL });

class MLSecurityService {
  constructor(model) {
    this.model = model;
    this.temperatureCalibration = 1.5;  // Softens overconfident predictions
  }

  // Temperature scaling to reduce membership inference vulnerability
  // Overconfident predictions leak training membership
  applyTemperatureScaling(logits, temperature = this.temperatureCalibration) {
    return logits.map(l => l / temperature);
  }

  // Softmax with temperature
  softmaxWithTemperature(logits, temperature) {
    const scaled = this.applyTemperatureScaling(logits, temperature);
    const maxLogit = Math.max(...scaled);
    const exps = scaled.map(l => Math.exp(l - maxLogit));
    const sumExps = exps.reduce((a, b) => a + b, 0);
    return exps.map(e => e / sumExps);
  }

  // Label smoothing defense - reduces confidence gap between members/non-members
  applyLabelSmoothing(probabilities, smoothingFactor = 0.1) {
    const numClasses = probabilities.length;
    const uniform = 1.0 / numClasses;
    return probabilities.map(p => 
      (1 - smoothingFactor) * p + smoothingFactor * uniform
    );
  }

  // Differential privacy noise calibrated to sensitivity
  addCalibratedNoise(value, sensitivity = 0.01, epsilon = 1.0) {
    // Laplace mechanism for differential privacy
    const scale = sensitivity / epsilon;
    const u = Math.random() - 0.5;
    const noise = -scale * Math.sign(u) * Math.log(1 - 2 * Math.abs(u));
    return Math.max(0, Math.min(1, value + noise));
  }

  // Prediction with all privacy defenses
  async securePrediction(inputTensor) {
    // Get raw model output (logits before softmax)
    const logits = await this.model.predict(inputTensor).array();

    // Apply temperature scaling
    const calibratedProbs = this.softmaxWithTemperature(
      logits[0], 
      this.temperatureCalibration
    );

    // Apply label smoothing
    const smoothedProbs = this.applyLabelSmoothing(calibratedProbs);

    // Add differential privacy noise
    const privatizedProbs = smoothedProbs.map(p => 
      this.addCalibratedNoise(p)
    );

    return privatizedProbs;
  }
}

class QueryAnomalyDetector {
  constructor(redisClient) {
    this.redis = redisClient;
    this.WINDOW_SIZE = 3600;  // 1 hour window
    this.EXTRACTION_THRESHOLD = 100;
    this.MEMBERSHIP_THRESHOLD = 50;
  }

