            boolean hashValid = currentHash.equals(storedMetadata.getSha256Hash());

            // Verify HMAC signature
            String currentHmac = generateHMAC(archivedData);
            boolean hmacValid = currentHmac.equals(storedMetadata.getHmacSignature());

            if (!hashValid || !hmacValid) {
                // CRITICAL: Log tampering detected
                alertSecurityTeam("LOG_TAMPERING_DETECTED", batchId, storedMetadata);
                logger.error("SECURITY ALERT: Log tampering detected for batch {}", batchId);
            }

            return new IntegrityVerificationResult(batchId, hashValid, hmacValid);

        } catch (Exception e) {
            logger.error("Integrity verification failed for batch {}: {}", batchId, e.getMessage());
            return new IntegrityVerificationResult(batchId, false, false);
        }
    }

    private byte[] compressLogEntries(List<LogEntry> entries) throws IOException {
        ByteArrayOutputStream baos = new ByteArrayOutputStream();
        try (GZIPOutputStream gzip = new GZIPOutputStream(baos)) {
            for (LogEntry entry : entries) {
                gzip.write(entry.toJson().getBytes(StandardCharsets.UTF_8));
                gzip.write('\n');
            }
        }
        return baos.toByteArray();
    }

    private String calculateSHA256(byte[] data) throws Exception {
        MessageDigest digest = MessageDigest.getInstance("SHA-256");
        byte[] hash = digest.digest(data);
        return Base64.getEncoder().encodeToString(hash);
    }

    private String generateHMAC(byte[] data) throws Exception {
        Mac mac = Mac.getInstance("HmacSHA256");
        SecretKeySpec keySpec = new SecretKeySpec(hmacKey, "HmacSHA256");
        mac.init(keySpec);
        byte[] hmac = mac.doFinal(data);
        return Base64.getEncoder().encodeToString(hmac);
    }

