Spring Security requires careful configuration to prevent HTTP verb tampering, especially with REST APIs where multiple methods are legitimately used. Here's a production-ready approach.

**PRODUCTION PATTERN**:

```java
// SecurityConfig.java - Production-ready Spring Security configuration
package com.example.security;

import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.http.HttpMethod;
import org.springframework.security.config.annotation.method.configuration.EnableMethodSecurity;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.config.http.SessionCreationPolicy;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.header.writers.XXssProtectionHeaderWriter;
import org.springframework.web.cors.CorsConfiguration;
import org.springframework.web.cors.CorsConfigurationSource;
import org.springframework.web.cors.UrlBasedCorsConfigurationSource;

import java.util.Arrays;
import java.util.List;

@Configuration
@EnableWebSecurity
@EnableMethodSecurity(prePostEnabled = true, securedEnabled = true)
public class SecurityConfig {

    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            // SECURE: Disable TRACE method globally
            .headers(headers -> headers
                .frameOptions(frame -> frame.deny())
                .xssProtection(xss -> xss
                    .headerValue(XXssProtectionHeaderWriter.HeaderValue.ENABLED_MODE_BLOCK))
                .contentSecurityPolicy(csp -> csp
                    .policyDirectives("default-src 'self'"))
            )

            // SECURE: Configure CORS to restrict methods
            .cors(cors -> cors.configurationSource(corsConfigurationSource()))

            // SECURE: Stateless session for APIs
            .sessionManagement(session -> session
                .sessionCreationPolicy(SessionCreationPolicy.STATELESS))

            // SECURE: Explicit method-based authorization
            .authorizeHttpRequests(auth -> auth
                // Public endpoints - only allow specific methods
                .requestMatchers(HttpMethod.GET, "/api/public/**").permitAll()
                .requestMatchers(HttpMethod.POST, "/api/auth/login").permitAll()

                // Admin endpoints - require ADMIN role for all methods
                .requestMatchers(HttpMethod.GET, "/api/admin/**").hasRole("ADMIN")
                .requestMatchers(HttpMethod.POST, "/api/admin/**").hasRole("ADMIN")
                .requestMatchers(HttpMethod.PUT, "/api/admin/**").hasRole("ADMIN")
                .requestMatchers(HttpMethod.DELETE, "/api/admin/**").hasRole("ADMIN")
                .requestMatchers(HttpMethod.PATCH, "/api/admin/**").hasRole("ADMIN")

                // User endpoints - authenticated users
                .requestMatchers(HttpMethod.GET, "/api/users/**").authenticated()
                .requestMatchers(HttpMethod.PUT, "/api/users/{id}").authenticated()

                // SECURE: Deny all other methods explicitly
                .requestMatchers(HttpMethod.OPTIONS, "/**").denyAll()
                .requestMatchers(HttpMethod.TRACE, "/**").denyAll()
                .requestMatchers(HttpMethod.HEAD, "/api/admin/**").denyAll()

                // SECURE: Deny all unmatched requests
                .anyRequest().denyAll()
            )

            // Add custom filter for method validation
            .addFilterBefore(new HttpMethodValidationFilter(), 
                            org.springframework.security.web.authentication.UsernamePasswordAuthenticationFilter.class)

            .oauth2ResourceServer(oauth2 -> oauth2.jwt(jwt -> {}));

        return http.build();
    }

    @Bean
    public CorsConfigurationSource corsConfigurationSource() {
        CorsConfiguration configuration = new CorsConfiguration();
        configuration.setAllowedOrigins(List.of("https://trusted-domain.com"));
        // SECURE: Only allow necessary HTTP methods
        configuration.setAllowedMethods(Arrays.asList("GET", "POST", "PUT", "DELETE", "PATCH"));
        configuration.setAllowedHeaders(List.of("Authorization", "Content-Type"));
        configuration.setMaxAge(3600L);

        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();
        source.registerCorsConfiguration("/api/**", configuration);
        return source;
    }
}
