**Key Security Controls**:
- **JSON instead of Java serialization**: JSON cannot execute code during parsing
- **Explicit target class**: Only UserSession can be created, no arbitrary class instantiation
- **Disabled default typing**: Prevents Jackson polymorphic deserialization attacks
- **Input size limits**: Prevents memory exhaustion attacks
- **Post-deserialization validation**: Verifies data integrity after parsing

If you must use Java serialization for legacy systems, you need multiple defense layers including deserialization filters, class whitelisting, and integrity verification. This is a high-risk pattern that should be migrated away from as soon as possible.

**PRODUCTION PATTERN**:

```java
import java.io.*;
import java.security.*;
import java.util.*;
import javax.crypto.*;
import javax.crypto.spec.*;
import javax.servlet.http.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class HardenedSerializationHandler extends HttpServlet {

    private static final Logger logger = LoggerFactory.getLogger(HardenedSerializationHandler.class);
    private static final int MAX_SERIALIZED_SIZE = 50000;  // 50KB limit
    private static final long MAX_ARRAY_SIZE = 1000;
    private static final long MAX_DEPTH = 10;

    // HMAC key for integrity verification (load from secure config)
    private static final byte[] HMAC_KEY = loadHmacKey();

    // Strict whitelist of allowed classes
    private static final Set<String> ALLOWED_CLASSES = Set.of(
        "com.myapp.dto.UserSession",
        "com.myapp.dto.UserPreferences",
        "java.lang.String",
        "java.lang.Integer",
        "java.lang.Long",
        "java.util.ArrayList",
        "java.util.HashMap"
    );

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String clientIp = request.getRemoteAddr();
        String requestId = UUID.randomUUID().toString();

        try {
            byte[] signedData = readLimitedInput(request.getInputStream(), MAX_SERIALIZED_SIZE);

            if (signedData == null) {
                logger.warn("[{}] Oversized payload rejected from {}", requestId, clientIp);
                response.setStatus(HttpServletResponse.SC_REQUEST_ENTITY_TOO_LARGE);
                return;
            }

            // DEFENSE 1: Verify HMAC integrity before any deserialization
            byte[] payload = verifyAndExtractPayload(signedData, requestId);
            if (payload == null) {
                logger.warn("[{}] HMAC verification failed from {}", requestId, clientIp);
                response.setStatus(HttpServletResponse.SC_FORBIDDEN);
                return;
            }

            // DEFENSE 2: Use filtering ObjectInputStream
            Object result = safeDeserialize(payload, requestId);

            if (result != null) {
                // DEFENSE 3: Post-deserialization type check
                if (result instanceof UserSession) {
                    UserSession session = (UserSession) result;

                    // DEFENSE 4: Business logic validation
                    if (validateSession(session)) {
                        logger.info("[{}] Session loaded for user {} from {}", 
                            requestId, session.getUserId(), clientIp);
                        processSession(session);
                        response.setStatus(HttpServletResponse.SC_OK);
                    } else {
                        logger.warn("[{}] Invalid session data from {}", requestId, clientIp);
                        response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
                    }
                } else {
                    logger.error("[{}] Unexpected type {} from {}", 
                        requestId, result.getClass().getName(), clientIp);
                    response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
                }
            }
        } catch (Exception e) {
            logger.error("[{}] Deserialization error from {}: {}", requestId, clientIp, e.getMessage());
            response.setStatus(HttpServletResponse.SC_INTERNAL_SERVER_ERROR);
        }
    }

    private byte[] verifyAndExtractPayload(byte[] signedData, String requestId) {
        try {
            if (signedData.length < 32) return null;  // HMAC-SHA256 = 32 bytes

            // Extract HMAC (first 32 bytes) and payload
            byte[] receivedHmac = Arrays.copyOfRange(signedData, 0, 32);
            byte[] payload = Arrays.copyOfRange(signedData, 32, signedData.length);

            // Calculate expected HMAC
            Mac mac = Mac.getInstance("HmacSHA256");
            mac.init(new SecretKeySpec(HMAC_KEY, "HmacSHA256"));
            byte[] expectedHmac = mac.doFinal(payload);

            // Constant-time comparison to prevent timing attacks
            if (MessageDigest.isEqual(receivedHmac, expectedHmac)) {
                return payload;
            }
            return null;
        } catch (Exception e) {
            logger.debug("[{}] HMAC verification exception: {}", requestId, e.getMessage());
            return null;
        }
    }

    private Object safeDeserialize(byte[] data, String requestId) {
        try (ByteArrayInputStream bis = new ByteArrayInputStream(data);
             SafeObjectInputStream ois = new SafeObjectInputStream(bis, requestId)) {
            return ois.readObject();
        } catch (Exception e) {
            logger.warn("[{}] Safe deserialization rejected: {}", requestId, e.getMessage());
            return null;
        }
    }

    // Custom ObjectInputStream with JEP 290 filters
    private static class SafeObjectInputStream extends ObjectInputStream {
        private final String requestId;
        private int depth = 0;

        public SafeObjectInputStream(InputStream in, String requestId) throws IOException {
            super(in);
            this.requestId = requestId;

            // JEP 290 Deserialization Filter (Java 9+)
            setObjectInputFilter(filterInfo -> {
                Class<?> clazz = filterInfo.serialClass();

                // Check recursion depth
                if (filterInfo.depth() > MAX_DEPTH) {
                    LoggerFactory.getLogger(SafeObjectInputStream.class)
                        .warn("[{}] Max depth exceeded", requestId);
                    return ObjectInputFilter.Status.REJECTED;
                }

                // Check array size
                if (filterInfo.arrayLength() > MAX_ARRAY_SIZE) {
                    LoggerFactory.getLogger(SafeObjectInputStream.class)
                        .warn("[{}] Max array size exceeded", requestId);
                    return ObjectInputFilter.Status.REJECTED;
                }

                // Class whitelist check
                if (clazz != null) {
                    String className = clazz.getName();
                    if (!ALLOWED_CLASSES.contains(className)) {
                        LoggerFactory.getLogger(SafeObjectInputStream.class)
                            .warn("[{}] Blocked class: {}", requestId, className);
                        return ObjectInputFilter.Status.REJECTED;
                    }
                }

                return ObjectInputFilter.Status.ALLOWED;
            });
        }
    }

    private byte[] readLimitedInput(InputStream is, int maxSize) throws IOException {
        ByteArrayOutputStream buffer = new ByteArrayOutputStream();
        byte[] chunk = new byte[4096];
        int bytesRead;
        int totalRead = 0;

        while ((bytesRead = is.read(chunk)) != -1) {
            totalRead += bytesRead;
            if (totalRead > maxSize) {
                return null;  // Exceeded limit
            }
            buffer.write(chunk, 0, bytesRead);
        }
        return buffer.toByteArray();
    }

    private boolean validateSession(UserSession session) {
        return session.getUserId() != null &&
               session.getUserId().matches("^[a-zA-Z0-9-]{1,50}$") &&
               session.getTimestamp() > System.currentTimeMillis() - 86400000;  // 24 hours
    }

    private void processSession(UserSession session) {
        // Business logic here
    }

    private static byte[] loadHmacKey() {
        // Load from secure key management (HashiCorp Vault, AWS KMS, etc.)
        return System.getenv("SERIALIZATION_HMAC_KEY").getBytes();
    }
}

// DTO class must be final and implement Serializable securely
final class UserSession implements Serializable {
    @Serial
    private static final long serialVersionUID = 1L;

    private String userId;
    private long timestamp;

    // Defensive readObject
    @Serial
    private void readObject(ObjectInputStream ois) throws IOException, ClassNotFoundException {
        ois.defaultReadObject();
        // Validate after deserialization
        if (userId != null && !userId.matches("^[a-zA-Z0-9-]{1,50}$")) {
            throw new InvalidObjectException("Invalid userId format");
        }
    }

    public String getUserId() { return userId; }
    public void setUserId(String userId) { this.userId = userId; }
    public long getTimestamp() { return timestamp; }
    public void setTimestamp(long timestamp) { this.timestamp = timestamp; }
}
```

**Defense in Depth Layers**:

1. **HMAC Integrity Verification** - Ensures only server-signed payloads are accepted:
```java
