Automated vulnerability scanning is essential for catching issues in both direct and transitive dependencies. The 2023 polyfill.io supply chain attack showed how transitive dependencies can be weaponized months after initial compromise.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/sha256"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"os"
	"os/exec"
	"strings"
	"time"
)

// DependencyInfo represents a Go module dependency
type DependencyInfo struct {
	Path       string `json:"Path"`
	Version    string `json:"Version"`
	Indirect   bool   `json:"Indirect"`
	GoVersion  string `json:"GoVersion,omitempty"`
}

// VulnerabilityReport from govulncheck
type VulnerabilityReport struct {
	OSV      string   `json:"osv"`
	Affected []string `json:"affected"`
	Fixed    string   `json:"fixed"`
}

// DependencyAuditor handles security scanning of dependencies
type DependencyAuditor struct {
	allowedModules  map[string]bool
	blockedModules  map[string]string // module -> reason
	checksumCache   map[string]string
	logger          *log.Logger
}

// NewDependencyAuditor creates a configured auditor
func NewDependencyAuditor(logger *log.Logger) *DependencyAuditor {
	return &DependencyAuditor{
		allowedModules: map[string]bool{
			"github.com/gin-gonic/gin":     true,
			"github.com/golang-jwt/jwt/v5": true,
			"golang.org/x/crypto":          true,
		},
		blockedModules: map[string]string{
			"github.com/dgrijalva/jwt-go": "CVE-2020-26160: algorithm confusion vulnerability",
			"github.com/ulikunitz/xz":     "CVE-2021-29482: denial of service",
		},
		checksumCache: make(map[string]string),
		logger:        logger,
	}
}

// RunGovulncheck executes the official Go vulnerability checker
func (da *DependencyAuditor) RunGovulncheck(ctx context.Context, modulePath string) ([]VulnerabilityReport, error) {
	ctx, cancel := context.WithTimeout(ctx, 5*time.Minute)
	defer cancel()

	// Run govulncheck (official Go vulnerability scanner)
	cmd := exec.CommandContext(ctx, "govulncheck", "-json", "./...")
	cmd.Dir = modulePath

	output, err := cmd.Output()
	if err != nil {
		// Exit code 3 means vulnerabilities found
		if exitErr, ok := err.(*exec.ExitError); ok && exitErr.ExitCode() != 3 {
			return nil, fmt.Errorf("govulncheck failed: %w", err)
		}
	}

	var reports []VulnerabilityReport
	// Parse JSON output line by line
	for _, line := range strings.Split(string(output), "\n") {
		if strings.Contains(line, `"osv"`) {
			var report VulnerabilityReport
			if err := json.Unmarshal([]byte(line), &report); err == nil {
				reports = append(reports, report)
			}
		}
	}

	da.logger.Printf("[AUDIT] Scanned %s: found %d vulnerabilities", modulePath, len(reports))
	return reports, nil
}

// ValidateModuleChecksum verifies module integrity against go.sum
func (da *DependencyAuditor) ValidateModuleChecksum(modulePath, version string) error {
	// Read go.sum file
	sumData, err := os.ReadFile("go.sum")
	if err != nil {
		return fmt.Errorf("cannot read go.sum: %w", err)
	}

	expectedEntry := fmt.Sprintf("%s %s", modulePath, version)
	if !strings.Contains(string(sumData), expectedEntry) {
		return fmt.Errorf("module %s@%s not found in go.sum", modulePath, version)
	}

	da.logger.Printf("[AUDIT] Checksum verified for %s@%s", modulePath, version)
	return nil
}

// CheckBlockedModules identifies forbidden dependencies
func (da *DependencyAuditor) CheckBlockedModules(deps []DependencyInfo) []string {
	var violations []string

	for _, dep := range deps {
		if reason, blocked := da.blockedModules[dep.Path]; blocked {
			violation := fmt.Sprintf("%s@%s: %s", dep.Path, dep.Version, reason)
			violations = append(violations, violation)
			da.logger.Printf("[SECURITY] Blocked module detected: %s", violation)
		}
	}

	return violations
}

// ListAllDependencies returns all direct and transitive dependencies
func (da *DependencyAuditor) ListAllDependencies(ctx context.Context) ([]DependencyInfo, error) {
	cmd := exec.CommandContext(ctx, "go", "list", "-m", "-json", "all")
	output, err := cmd.Output()
	if err != nil {
		return nil, fmt.Errorf("go list failed: %w", err)
	}

	var deps []DependencyInfo
	decoder := json.NewDecoder(strings.NewReader(string(output)))

	for decoder.More() {
		var dep DependencyInfo
		if err := decoder.Decode(&dep); err != nil {
			continue
		}
		deps = append(deps, dep)
	}

	da.logger.Printf("[AUDIT] Found %d total dependencies (direct + transitive)", len(deps))
	return deps, nil
}

// GenerateSBOM creates a Software Bill of Materials
func (da *DependencyAuditor) GenerateSBOM(deps []DependencyInfo) ([]byte, error) {
	sbom := struct {
		Format     string           `json:"bomFormat"`
		SpecVersion string          `json:"specVersion"`
		Version    int              `json:"version"`
		Components []DependencyInfo `json:"components"`
		Timestamp  string           `json:"timestamp"`
	}{
		Format:      "CycloneDX",
		SpecVersion: "1.4",
		Version:     1,
		Components:  deps,
		Timestamp:   time.Now().UTC().Format(time.RFC3339),
	}

	return json.MarshalIndent(sbom, "", "  ")
}

// ComputeModuleHash generates SHA256 hash for integrity verification
func ComputeModuleHash(modulePath string) (string, error) {
	data, err := os.ReadFile(modulePath)
	if err != nil {
		return "", err
	}
	hash := sha256.Sum256(data)
	return hex.EncodeToString(hash[:]), nil
}

func main() {
	logger := log.New(os.Stdout, "[DEPS] ", log.LstdFlags)
	auditor := NewDependencyAuditor(logger)
	ctx := context.Background()

	// List all dependencies including transitive
	deps, err := auditor.ListAllDependencies(ctx)
	if err != nil {
		logger.Fatalf("Failed to list dependencies: %v", err)
	}

	// Check for blocked modules
	if violations := auditor.CheckBlockedModules(deps); len(violations) > 0 {
		logger.Printf("[CRITICAL] Found %d blocked modules:", len(violations))
		for _, v := range violations {
			logger.Printf("  - %s", v)
		}
		os.Exit(1)
	}

	// Run vulnerability scan
	vulns, err := auditor.RunGovulncheck(ctx, ".")
	if err != nil {
		logger.Printf("[WARN] Vulnerability scan failed: %v", err)
	}

	if len(vulns) > 0 {
		logger.Printf("[CRITICAL] Found %d vulnerabilities", len(vulns))
		for _, v := range vulns {
			logger.Printf("  - %s (fixed in: %s)", v.OSV, v.Fixed)
		}
		os.Exit(1)
	}

	// Generate SBOM for compliance
	sbom, _ := auditor.GenerateSBOM(deps)
	os.WriteFile("sbom.json", sbom, 0644)

	logger.Println("[SUCCESS] Dependency audit passed")
}
```

