**Attack Vector**:
```bash
# Attacker decompiles JAR file
jad -r -d output/ application.jar

# Or uses strings to find credentials
strings application.jar | grep -i password
strings application.jar | grep -i "jdbc:"

# Or searches Git history
git log -p --all -S 'password' --source
```

**Why This Is Dangerous**:
- Credentials visible in decompiled bytecode - Java is trivially decompilable
- Credentials committed to version control history permanently
- Cannot rotate credentials without redeployment
- Same credentials often used across environments (dev/staging/prod)
- Insider threats - any developer with repo access has production credentials

**SECURE VERSION**:

```java
import java.sql.Connection;
import java.sql.DriverManager;
import java.sql.PreparedStatement;
import java.sql.ResultSet;
import java.sql.SQLException;
import java.util.logging.Logger;

public class UserRepository {
    private static final Logger logger = Logger.getLogger(UserRepository.class.getName());

    // Credentials loaded from environment variables
    private final String dbUrl;
    private final String dbUser;
    private final String dbPassword;

    public UserRepository() {
        // Load from environment variables at startup
        this.dbUrl = getRequiredEnv("DATABASE_URL");
        this.dbUser = getRequiredEnv("DATABASE_USER");
        this.dbPassword = getRequiredEnv("DATABASE_PASSWORD");

        logger.info("Database connection configured for host: " + 
                    maskConnectionString(dbUrl));
    }

    private String getRequiredEnv(String name) {
        String value = System.getenv(name);
        if (value == null || value.trim().isEmpty()) {
            throw new IllegalStateException(
                "Required environment variable not set: " + name);
        }
        return value;
    }

    private String maskConnectionString(String url) {
        // Log host but not credentials
        return url.replaceAll("://[^@]+@", "://***@");
    }

    public Connection getConnection() throws SQLException {
        return DriverManager.getConnection(dbUrl, dbUser, dbPassword);
    }

    public User findByUsername(String username) throws SQLException {
        try (Connection conn = getConnection();
             PreparedStatement stmt = conn.prepareStatement(
                 "SELECT * FROM users WHERE username = ?")) {
            stmt.setString(1, username);
            ResultSet rs = stmt.executeQuery();
            if (rs.next()) {
                return new User(rs.getString("username"), rs.getString("email"));
            }
            return null;
        } catch (SQLException e) {
            logger.severe("Database query failed: " + e.getMessage());
            throw e;
        }
    }
}
```

**Key Security Controls**:
- **Environment variables**: Credentials injected at runtime, never in code or config files
- **Fail-fast validation**: Application won't start without required credentials
- **Masked logging**: Connection info logged without exposing secrets
- **Separation of concerns**: Code doesn't know credential values

For enterprise production systems, you need a dedicated secrets management solution like HashiCorp Vault, AWS Secrets Manager, or Azure Key Vault. These provide encryption, automatic rotation, access auditing, and fine-grained permissions.

**PRODUCTION PATTERN**:

```java
import software.amazon.awssdk.services.secretsmanager.SecretsManagerClient;
import software.amazon.awssdk.services.secretsmanager.model.GetSecretValueRequest;
import software.amazon.awssdk.services.secretsmanager.model.GetSecretValueResponse;
import software.amazon.awssdk.regions.Region;
import com.fasterxml.jackson.databind.ObjectMapper;
import com.zaxxer.hikari.HikariConfig;
import com.zaxxer.hikari.HikariDataSource;

import javax.sql.DataSource;
import java.sql.Connection;
import java.sql.SQLException;
import java.util.Map;
import java.util.concurrent.Executors;
import java.util.concurrent.ScheduledExecutorService;
import java.util.concurrent.TimeUnit;
import java.util.concurrent.atomic.AtomicReference;
import java.util.logging.Logger;

public class SecureCredentialManager {
    private static final Logger logger = Logger.getLogger(SecureCredentialManager.class.getName());
    private static final ObjectMapper objectMapper = new ObjectMapper();

    private final SecretsManagerClient secretsClient;
    private final String secretName;
    private final AtomicReference<HikariDataSource> dataSourceRef;
    private final ScheduledExecutorService scheduler;

    public SecureCredentialManager(String secretName, String region) {
        this.secretName = secretName;
        this.secretsClient = SecretsManagerClient.builder()
                .region(Region.of(region))
                .build();
        this.dataSourceRef = new AtomicReference<>();
        this.scheduler = Executors.newSingleThreadScheduledExecutor();

        // Initial credential load
        refreshCredentials();

        // Schedule automatic rotation check every hour
        scheduler.scheduleAtFixedRate(
            this::refreshCredentialsIfRotated,
            1, 1, TimeUnit.HOURS
        );

        logger.info("SecureCredentialManager initialized for secret: " + secretName);
    }

    private DatabaseCredentials fetchSecretFromVault() {
        try {
            GetSecretValueRequest request = GetSecretValueRequest.builder()
                    .secretId(secretName)
                    .build();

            GetSecretValueResponse response = secretsClient.getSecretValue(request);
            String secretJson = response.secretString();

            // Parse JSON secret
            Map<String, String> secretMap = objectMapper.readValue(
                secretJson, Map.class);

            logger.info("Successfully retrieved credentials from Secrets Manager");

            return new DatabaseCredentials(
                secretMap.get("host"),
                Integer.parseInt(secretMap.get("port")),
                secretMap.get("database"),
                secretMap.get("username"),
                secretMap.get("password")
            );

        } catch (Exception e) {
            logger.severe("Failed to retrieve secret: " + e.getMessage());
            throw new SecurityException("Cannot retrieve database credentials", e);
        }
    }

    private synchronized void refreshCredentials() {
        DatabaseCredentials creds = fetchSecretFromVault();

        HikariConfig config = new HikariConfig();
        config.setJdbcUrl(String.format(
            "jdbc:postgresql://%s:%d/%s",
            creds.host(), creds.port(), creds.database()
        ));
        config.setUsername(creds.username());
        config.setPassword(creds.password());

        // Connection pool security settings
        config.setMaximumPoolSize(10);
        config.setMinimumIdle(2);
        config.setConnectionTimeout(30000);
        config.setIdleTimeout(600000);
        config.setMaxLifetime(1800000);

        // SSL/TLS for database connection
        config.addDataSourceProperty("ssl", "true");
        config.addDataSourceProperty("sslmode", "verify-full");

        HikariDataSource newDataSource = new HikariDataSource(config);
        HikariDataSource oldDataSource = dataSourceRef.getAndSet(newDataSource);

        // Gracefully close old connection pool
        if (oldDataSource != null) {
            scheduler.schedule(() -> {
                oldDataSource.close();
                logger.info("Old connection pool closed after credential rotation");
            }, 30, TimeUnit.SECONDS);
        }

        logger.info("Database connection pool refreshed with new credentials");
    }

    private void refreshCredentialsIfRotated() {
        try {
            // Check version/rotation status
            refreshCredentials();
        } catch (Exception e) {
            logger.warning("Credential refresh check failed: " + e.getMessage());
        }
    }

    public Connection getConnection() throws SQLException {
        HikariDataSource ds = dataSourceRef.get();
        if (ds == null) {
            throw new SQLException("DataSource not initialized");
        }
        return ds.getConnection();
    }

    public void shutdown() {
        scheduler.shutdown();
        HikariDataSource ds = dataSourceRef.get();
        if (ds != null) {
            ds.close();
        }
        secretsClient.close();
        logger.info("SecureCredentialManager shutdown complete");
    }

    // Immutable credentials record
    private record DatabaseCredentials(
        String host, int port, String database,
        String username, String password
    ) {}
}
```

**Defense in Depth Layers**:

