// PKCE utilities
function generateCodeVerifier() {
  return crypto.randomBytes(32)
    .toString('base64url')
    .substring(0, 128);
}

function generateCodeChallenge(verifier) {
  return crypto
    .createHash('sha256')
    .update(verifier)
    .digest('base64url');
}

// Generate cryptographically secure state with embedded provider
function generateSecureState(provider) {
  const random = crypto.randomBytes(32).toString('hex');
  const timestamp = Date.now().toString(36);
  // Embed provider in state to prevent IdP mixup attacks
  const payload = JSON.stringify({ r: random, t: timestamp, p: provider });
  const signature = crypto
    .createHmac('sha256', process.env.STATE_SECRET)
    .update(payload)
    .digest('hex');
  return Buffer.from(`${payload}.${signature}`).toString('base64url');
}

// Validate state and extract provider
function validateSecureState(state) {
  try {
    const decoded = Buffer.from(state, 'base64url').toString();
    const [payload, signature] = decoded.split('.');

    const expectedSignature = crypto
      .createHmac('sha256', process.env.STATE_SECRET)
      .update(payload)
      .digest('hex');

    if (!crypto.timingSafeEqual(
      Buffer.from(signature), 
      Buffer.from(expectedSignature)
    )) {
      return null;
    }

    const data = JSON.parse(payload);
    const age = Date.now() - parseInt(data.t, 36);

    // State valid for 10 minutes
    if (age > 600000) {
      return null;
    }

    return data;
  } catch {
    return null;
  }
}

