class AdminAuthenticator {
    private PDO $db;
    private int $maxAttempts = 5;
    private int $lockoutMinutes = 30;

    public function __construct(PDO $db) {
        $this->db = $db;
    }

    public function isIPAllowed(string $ip): bool {
        $allowedIPs = getenv('ADMIN_ALLOWED_IPS') ?: '';
        $allowList = array_filter(explode(',', $allowedIPs));

        if (empty($allowList)) {
            // If no whitelist configured, deny all in production
            return getenv('APP_ENV') !== 'production';
        }

        return in_array($ip, $allowList, true);
    }

    public function isLockedOut(string $ip): bool {
        $stmt = $this->db->prepare(
            "SELECT COUNT(*) FROM admin_login_attempts 
             WHERE ip_address = ? AND success = 0 
             AND attempted_at > DATE_SUB(NOW(), INTERVAL ? MINUTE)"
        );
        $stmt->execute([$ip, $this->lockoutMinutes]);
        return $stmt->fetchColumn() >= $this->maxAttempts;
