**Key Security Controls**:
- **Unpredictable URL path**: `/secure-mgmt-a7x9k2/` instead of `/admin/` - attackers can't guess it
- **IP whitelisting**: Only authorized IP addresses can even see the login page; others get 404
- **Rate limiting with lockout**: 5 failed attempts trigger 30-minute lockout per IP
- **Secure password storage**: Uses `password_verify()` with bcrypt hashes, not plaintext comparison
- **Session regeneration**: Prevents session fixation attacks
- **Comprehensive logging**: All access attempts logged for forensic analysis

Excellent questions! For production admin panels, you need TOTP-based 2FA, proper proxy header handling, comprehensive audit logging, and additional security layers. Here's a complete production-ready implementation:

**PRODUCTION PATTERN**:

```php
<?php
// File: /secure-mgmt-a7x9k2/index.php - PRODUCTION ADMIN PANEL
declare(strict_types=1);

require_once __DIR__ . '/../vendor/autoload.php';

use OTPHP\TOTP;
use ParagonIE\CSPBuilder\CSPBuilder;

// Load environment configuration
$dotenv = Dotenv\Dotenv::createImmutable(__DIR__ . '/../');
$dotenv->load();

class ProductionAdminAuth {
    private PDO $db;
    private array $config;

    public function __construct(PDO $db) {
        $this->db = $db;
        $this->config = [
            'max_attempts' => (int)getenv('ADMIN_MAX_ATTEMPTS') ?: 5,
            'lockout_minutes' => (int)getenv('ADMIN_LOCKOUT_MINUTES') ?: 30,
            'session_lifetime' => (int)getenv('ADMIN_SESSION_LIFETIME') ?: 1800,
            'require_2fa' => getenv('ADMIN_REQUIRE_2FA') !== 'false',
            'allowed_ips' => array_filter(explode(',', getenv('ADMIN_ALLOWED_IPS') ?: '')),
            'trusted_proxies' => array_filter(explode(',', getenv('TRUSTED_PROXIES') ?: '')),
        ];
    }

    public function getClientIP(): string {
        $remoteAddr = $_SERVER['REMOTE_ADDR'];

        // Only trust X-Forwarded-For from known proxies
        if (in_array($remoteAddr, $this->config['trusted_proxies'], true)) {
            if (isset($_SERVER['HTTP_X_FORWARDED_FOR'])) {
                $ips = array_map('trim', explode(',', $_SERVER['HTTP_X_FORWARDED_FOR']));
                // Return the rightmost untrusted IP
                foreach (array_reverse($ips) as $ip) {
                    if (!in_array($ip, $this->config['trusted_proxies'], true)) {
                        return filter_var($ip, FILTER_VALIDATE_IP) ?: $remoteAddr;
                    }
                }
            }
            // Check X-Real-IP header
            if (isset($_SERVER['HTTP_X_REAL_IP'])) {
                $ip = filter_var($_SERVER['HTTP_X_REAL_IP'], FILTER_VALIDATE_IP);
                if ($ip) return $ip;
            }
        }

        return $remoteAddr;
    }

    public function enforceIPWhitelist(string $clientIP): void {
        if (empty($this->config['allowed_ips'])) {
            if (getenv('APP_ENV') === 'production') {
                $this->auditLog('access_denied', $clientIP, 'No IP whitelist configured in production');
                $this->show404AndDie();
            }
            return;
        }

        // Support CIDR notation
        foreach ($this->config['allowed_ips'] as $allowedIP) {
            if ($this->ipInRange($clientIP, trim($allowedIP))) {
                return;
            }
        }

        $this->auditLog('access_denied', $clientIP, 'IP not in whitelist');
        $this->show404AndDie();
    }

    private function ipInRange(string $ip, string $range): bool {
        if (strpos($range, '/') === false) {
            return $ip === $range;
        }

        list($subnet, $bits) = explode('/', $range);
        $ip = ip2long($ip);
        $subnet = ip2long($subnet);
        $mask = -1 << (32 - (int)$bits);

        return ($ip & $mask) === ($subnet & $mask);
    }

    public function checkRateLimit(string $clientIP): void {
        $stmt = $this->db->prepare(
            "SELECT COUNT(*) as attempts, MAX(attempted_at) as last_attempt 
             FROM admin_login_attempts 
             WHERE ip_address = ? AND success = 0 
             AND attempted_at > DATE_SUB(NOW(), INTERVAL ? MINUTE)"
        );
        $stmt->execute([$clientIP, $this->config['lockout_minutes']]);
        $result = $stmt->fetch(PDO::FETCH_ASSOC);

        if ($result['attempts'] >= $this->config['max_attempts']) {
            $this->auditLog('lockout_triggered', $clientIP, "Attempts: {$result['attempts']}");

            // Alert security team
            $this->sendSecurityAlert('Admin panel lockout', [
                'ip' => $clientIP,
                'attempts' => $result['attempts'],
                'last_attempt' => $result['last_attempt']
            ]);

            http_response_code(429);
            header('Retry-After: ' . ($this->config['lockout_minutes'] * 60));
            die('Account temporarily locked. Please try again later.');
        }
    }

    public function authenticate(string $username, string $password): ?array {
        // Constant-time comparison for username to prevent timing attacks
        $stmt = $this->db->prepare(
            "SELECT id, username, password_hash, totp_secret, is_active, 
                    failed_attempts, last_failed_at
             FROM admin_users WHERE username = ?"
        );
        $stmt->execute([$username]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        // Perform password check even if user doesn't exist (timing attack prevention)
        $dummyHash = '$2y$12$' . str_repeat('x', 53);
        $hashToCheck = $user ? $user['password_hash'] : $dummyHash;

        if (!password_verify($password, $hashToCheck) || !$user || !$user['is_active']) {
            return null;
        }

        // Check if password needs rehash (algorithm upgrade)
        if (password_needs_rehash($user['password_hash'], PASSWORD_ARGON2ID)) {
            $newHash = password_hash($password, PASSWORD_ARGON2ID);
            $updateStmt = $this->db->prepare(
                "UPDATE admin_users SET password_hash = ? WHERE id = ?"
            );
            $updateStmt->execute([$newHash, $user['id']]);
        }

        return $user;
    }

    public function verifyTOTP(string $secret, string $code): bool {
        $totp = TOTP::create($secret);
        $totp->setDigits(6);
        $totp->setPeriod(30);

        // Allow 1 period window for clock drift
        return $totp->verify($code, null, 1);
    }

    public function createSecureSession(array $user, string $clientIP): void {
        // Regenerate session ID
        session_regenerate_id(true);

        // Set session data
        $_SESSION['admin_user_id'] = $user['id'];
        $_SESSION['admin_username'] = $user['username'];
        $_SESSION['admin_ip'] = $clientIP;
        $_SESSION['admin_user_agent'] = $_SERVER['HTTP_USER_AGENT'] ?? '';
        $_SESSION['admin_login_time'] = time();
        $_SESSION['admin_last_activity'] = time();
        $_SESSION['admin_csrf_token'] = bin2hex(random_bytes(32));

        // Fingerprint for session hijacking detection
        $_SESSION['admin_fingerprint'] = hash('sha256', 
            $clientIP . $_SERVER['HTTP_USER_AGENT'] . $user['id']
        );
    }

    public function validateSession(string $clientIP): bool {
        if (!isset($_SESSION['admin_user_id'])) {
            return false;
        }

        // Check session timeout
        if (time() - $_SESSION['admin_last_activity'] > $this->config['session_lifetime']) {
            $this->auditLog('session_timeout', $clientIP, "User: {$_SESSION['admin_username']}");
            $this->destroySession();
            return false;
        }

        // Validate fingerprint (detect session hijacking)
        $expectedFingerprint = hash('sha256',
            $clientIP . $_SERVER['HTTP_USER_AGENT'] . $_SESSION['admin_user_id']
        );

        if (!hash_equals($_SESSION['admin_fingerprint'], $expectedFingerprint)) {
            $this->auditLog('session_hijack_attempt', $clientIP, [
                'expected_ip' => $_SESSION['admin_ip'],
                'user' => $_SESSION['admin_username']
            ]);
            $this->sendSecurityAlert('Possible session hijacking detected', [
                'user' => $_SESSION['admin_username'],
                'original_ip' => $_SESSION['admin_ip'],
                'current_ip' => $clientIP
            ]);
            $this->destroySession();
            return false;
        }

        // Update last activity
        $_SESSION['admin_last_activity'] = time();
        return true;
    }

    public function auditLog(string $event, string $clientIP, $details = null): void {
        $stmt = $this->db->prepare(
            "INSERT INTO admin_audit_log 
             (event_type, ip_address, user_agent, username, details, created_at)
             VALUES (?, ?, ?, ?, ?, NOW())"
        );

        $username = $_SESSION['admin_username'] ?? null;
        $detailsJson = is_array($details) ? json_encode($details) : $details;

        $stmt->execute([
            $event,
            $clientIP,
            $_SERVER['HTTP_USER_AGENT'] ?? 'Unknown',
            $username,
            $detailsJson
        ]);

        // Also log to system log for SIEM integration
        $logMessage = sprintf(
            "ADMIN_AUDIT [%s] IP=%s User=%s Details=%s",
            $event, $clientIP, $username ?? 'anonymous', $detailsJson
        );
        error_log($logMessage);
    }

    private function sendSecurityAlert(string $subject, array $data): void {
        $alertEmail = getenv('SECURITY_ALERT_EMAIL');
        $slackWebhook = getenv('SECURITY_SLACK_WEBHOOK');

        if ($alertEmail) {
            mail($alertEmail, "[SECURITY] $subject", json_encode($data, JSON_PRETTY_PRINT));
        }

        if ($slackWebhook) {
            $payload = json_encode(['text' => "🚨 $subject\n```" . json_encode($data, JSON_PRETTY_PRINT) . "```"]);
            $ch = curl_init($slackWebhook);
            curl_setopt($ch, CURLOPT_POST, true);
            curl_setopt($ch, CURLOPT_POSTFIELDS, $payload);
            curl_setopt($ch, CURLOPT_HTTPHEADER, ['Content-Type: application/json']);
            curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
            curl_exec($ch);
            curl_close($ch);
        }
    }

    private function show404AndDie(): void {
        http_response_code(404);
        include __DIR__ . '/../public/404.html';
        exit;
    }

    public function destroySession(): void {
        $_SESSION = [];
        if (ini_get('session.use_cookies')) {
            $params = session_get_cookie_params();
            setcookie(session_name(), '', time() - 42000,
                $params['path'], $params['domain'],
                $params['secure'], $params['httponly']
            );
        }
        session_destroy();
    }
}

