    const sessionValid = await verifyAdminSession(decoded.id, sessionToken);
    if (!sessionValid) {
      auditLog('ADMIN_AUTH_FAILED', { userId: decoded.id, reason: 'invalid_session', ip: req.ip });
      return res.status(401).json({ error: 'Invalid admin session' });
    }

    req.admin = decoded;
    req.trustZone = 'admin';
    next();
  } catch (err) {
    auditLog('ADMIN_AUTH_FAILED', { reason: 'token_verification_failed', ip: req.ip });
    return res.status(401).json({ error: 'Invalid admin token' });
  }
};

// Public endpoint
