  const { targetUserId, reason, ticketId } = req.body;

  // SECURE: Require justification for sensitive actions
  if (!reason || !ticketId) {
    return res.status(400).json({ error: 'Reason and ticket ID required' });
  }

  // SECURE: Comprehensive audit logging
