**Key Security Controls**:
- **Separate JWT secrets**: Different cryptographic keys for public and admin authentication prevents token reuse across trust boundaries
- **Database-backed role verification**: Never trust JWT claims for authorization; always verify against authoritative data source
- **Session binding**: Admin tokens tied to active sessions that can be revoked instantly
- **Comprehensive audit logging**: Every admin action logged with full context for forensic analysis

Microservice-to-microservice communication is a critical trust boundary that's often overlooked. The 2023 Retool breach partly succeeded because internal services implicitly trusted each other. You need a zero-trust architecture where every service authenticates and authorizes every request.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const jwt = require('jsonwebtoken');
const crypto = require('crypto');
const { createClient } = require('redis');

const app = express();
app.use(express.json());

// Service identity configuration
const SERVICE_CONFIG = {
  serviceName: process.env.SERVICE_NAME,
  serviceSecret: process.env.SERVICE_SECRET,
  trustedServices: JSON.parse(process.env.TRUSTED_SERVICES || '{}'),
  mTLSEnabled: process.env.MTLS_ENABLED === 'true'
};

// Redis for distributed rate limiting and service registry
const redis = createClient({ url: process.env.REDIS_URL });

// Service-to-service authentication token generator
class ServiceAuth {
  constructor(config) {
    this.config = config;
    this.tokenCache = new Map();
  }

  // Generate signed token for outbound service calls
  generateServiceToken(targetService) {
    const payload = {
      iss: this.config.serviceName,
      aud: targetService,
      iat: Math.floor(Date.now() / 1000),
      exp: Math.floor(Date.now() / 1000) + 300, // 5 minute expiry
      jti: crypto.randomUUID(),
      permissions: this.config.trustedServices[targetService]?.allowedOperations || []
    };

    return jwt.sign(payload, this.config.serviceSecret, { algorithm: 'HS256' });
  }

  // Verify inbound service token
  async verifyServiceToken(token, expectedSource) {
    try {
      const decoded = jwt.verify(token, this.config.serviceSecret);

      // Verify issuer is a known trusted service
      if (!this.config.trustedServices[decoded.iss]) {
        throw new Error(`Unknown service: ${decoded.iss}`);
      }

      // Verify this service is the intended audience
      if (decoded.aud !== this.config.serviceName) {
        throw new Error('Token not intended for this service');
      }

      // Check token hasn't been replayed (store JTI in Redis)
      const jtiKey = `service_token:${decoded.jti}`;
      const exists = await redis.get(jtiKey);
      if (exists) {
        throw new Error('Token replay detected');
      }
      await redis.setEx(jtiKey, 600, 'used'); // Store for 10 mins

      return decoded;
    } catch (err) {
      throw new Error(`Service authentication failed: ${err.message}`);
    }
  }
}

const serviceAuth = new ServiceAuth(SERVICE_CONFIG);

// Trust boundary middleware for service-to-service calls
const authenticateService = async (req, res, next) => {
  const serviceToken = req.headers['x-service-token'];
  const callerService = req.headers['x-caller-service'];
  const requestId = req.headers['x-request-id'] || crypto.randomUUID();

  req.requestId = requestId;

  if (!serviceToken || !callerService) {
    await auditServiceCall({
      requestId,
      action: 'SERVICE_AUTH_FAILED',
      reason: 'missing_credentials',
      callerIp: req.ip
    });
    return res.status(401).json({ error: 'Service authentication required' });
  }

  try {
    const serviceIdentity = await serviceAuth.verifyServiceToken(serviceToken, callerService);

    // Verify caller IP is in allowlist for this service (defense in depth)
    const allowedIPs = SERVICE_CONFIG.trustedServices[callerService]?.allowedIPs || [];
    if (allowedIPs.length > 0 && !allowedIPs.includes(req.ip)) {
      throw new Error(`IP ${req.ip} not authorized for service ${callerService}`);
    }

    req.callerService = serviceIdentity;
    req.trustZone = 'internal-service';

    await auditServiceCall({
      requestId,
      action: 'SERVICE_AUTH_SUCCESS',
      callerService: serviceIdentity.iss,
      targetEndpoint: req.path
    });

    next();
  } catch (err) {
    await auditServiceCall({
      requestId,
      action: 'SERVICE_AUTH_FAILED',
      reason: err.message,
      callerService,
      callerIp: req.ip
    });
    return res.status(403).json({ error: 'Service authentication failed' });
  }
};

// Permission-based authorization for service operations
const requireServicePermission = (permission) => {
  return (req, res, next) => {
    if (!req.callerService?.permissions?.includes(permission)) {
      auditServiceCall({
        requestId: req.requestId,
        action: 'PERMISSION_DENIED',
        callerService: req.callerService?.iss,
        requiredPermission: permission
      });
      return res.status(403).json({ 
        error: 'Insufficient permissions',
        required: permission 
      });
    }
    next();
  };
};

// Rate limiting per service to prevent abuse
const serviceRateLimit = async (req, res, next) => {
  const callerService = req.callerService?.iss;
  if (!callerService) return next();

  const rateLimitKey = `ratelimit:service:${callerService}`;
  const limit = SERVICE_CONFIG.trustedServices[callerService]?.rateLimit || 100;

  const current = await redis.incr(rateLimitKey);
  if (current === 1) {
    await redis.expire(rateLimitKey, 60); // 1 minute window
  }

  if (current > limit) {
    await auditServiceCall({
      requestId: req.requestId,
      action: 'RATE_LIMIT_EXCEEDED',
      callerService,
      currentCount: current,
      limit
    });
    return res.status(429).json({ error: 'Rate limit exceeded' });
  }

  res.setHeader('X-RateLimit-Remaining', Math.max(0, limit - current));
  next();
};

// Internal service endpoint with proper trust boundary
app.post('/internal/user/reset-mfa',
  authenticateService,
  serviceRateLimit,
  requireServicePermission('user:mfa:reset'),
  async (req, res) => {
    const { targetUserId, reason, initiatedBy, approvedBy } = req.body;

    // Validate required approval chain
    if (!approvedBy || approvedBy === initiatedBy) {
      return res.status(400).json({ 
        error: 'MFA reset requires approval from different admin' 
      });
    }

    // Create audit record before action
    const auditId = await createAuditRecord({
      action: 'MFA_RESET',
      targetUserId,
      reason,
      initiatedBy,
      approvedBy,
      callerService: req.callerService.iss,
      requestId: req.requestId,
      timestamp: new Date().toISOString()
    });

    try {
      await resetUserMFA(targetUserId);
      await notifySecurityTeam('MFA_RESET', { targetUserId, auditId });

      res.json({ 
        success: true, 
        auditId,
        message: 'MFA reset completed' 
      });
    } catch (err) {
      await updateAuditRecord(auditId, { status: 'FAILED', error: err.message });
      throw err;
    }
  }
);

// Health check - no auth required but limited info
app.get('/health', (req, res) => {
  res.json({ status: 'healthy', service: SERVICE_CONFIG.serviceName });
});

// Secure audit logging function
async function auditServiceCall(event) {
  const logEntry = {
    ...event,
    timestamp: new Date().toISOString(),
    service: SERVICE_CONFIG.serviceName,
    environment: process.env.NODE_ENV
  };

  // Log to multiple destinations for durability
  console.log(JSON.stringify(logEntry));
  await redis.xAdd('audit:service_calls', '*', logEntry);

  // Alert on suspicious patterns
  if (event.action.includes('FAILED') || event.action === 'RATE_LIMIT_EXCEEDED') {
    await alertSecurityTeam(logEntry);
  }
}

app.listen(3000);
```

**Defense in Depth Layers**:

1. **Service Identity Verification**:
```javascript
// Each service has unique cryptographic identity
const serviceIdentity = {
  name: 'user-service',
  publicKey: fs.readFileSync('/etc/secrets/service.pub'),
  privateKey: fs.readFileSync('/etc/secrets/service.key'),
  // Certificate rotated every 24 hours
  certExpiry: new Date(Date.now() + 86400000)
};
```

2. **Mutual TLS (mTLS) for Network Layer**:
```javascript
// Configure HTTPS server with client certificate verification
const https = require('https');
const server = https.createServer({
  key: fs.readFileSync('/etc/secrets/server.key'),
  cert: fs.readFileSync('/etc/secrets/server.crt'),
  ca: fs.readFileSync('/etc/secrets/ca.crt'),
  requestCert: true,
  rejectUnauthorized: true
}, app);
```

3. **Request Signing for Integrity**:
```javascript
// Sign outbound requests to prevent tampering
const signRequest = (method, path, body, timestamp) => {
  const payload = `${method}\n${path}\n${timestamp}\n${JSON.stringify(body)}`;
  return crypto.createHmac('sha256', SERVICE_CONFIG.serviceSecret)
    .update(payload)
    .digest('hex');
};

// Verify inbound request signatures
const verifyRequestSignature = (req) => {
  const signature = req.headers['x-request-signature'];
  const timestamp = req.headers['x-request-timestamp'];

  // Reject if timestamp too old (prevent replay)
  if (Date.now() - parseInt(timestamp) > 30000) {
    throw new Error('Request timestamp too old');
  }

  const expected = signRequest(req.method, req.path, req.body, timestamp);
  if (!crypto.timingSafeEqual(Buffer.from(signature), Buffer.from(expected))) {
    throw new Error('Invalid request signature');
  }
};
```

**Additional Protections**:
- **Service mesh integration**: Use Istio/Linkerd for automatic mTLS and traffic policies
- **Network segmentation**: Internal services on separate VLANs/subnets with firewall rules
- **Principle of least privilege**: Each service only has permissions for operations it needs
- **Circuit breakers**: Prevent cascade failures if one service is compromised
- **Canary deployments**: Detect anomalous behavior from new service versions
- **Immutable audit logs**: Write audit logs to append-only storage (S3 with Object Lock)
- **Regular rotation**: Service credentials and certificates rotated automatically

Your discount code logic likely has critical business logic flaws that attackers can exploit to get unauthorized discounts or even negative totals (resulting in credits/refunds). This mirrors the 2023 Revolut incident where improper state validation cost $23 million.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const app = express();
app.use(express.json());

// In-memory cart storage (simplified)
const carts = new Map();
const discountCodes = {
  'SAVE10': { percent: 10, minOrder: 50 },
  'SAVE25': { percent: 25, minOrder: 100 },
  'FREESHIP': { type: 'shipping', value: 0 }
};

app.post('/api/cart/:cartId/apply-discount', (req, res) => {
  const { cartId } = req.params;
  const { code } = req.body;

  const cart = carts.get(cartId);
  if (!cart) return res.status(404).json({ error: 'Cart not found' });

  const discount = discountCodes[code.toUpperCase()];
  if (!discount) return res.status(400).json({ error: 'Invalid code' });

  // FLAW 1: No check if discount already applied
  // FLAW 2: No check for minimum order after discount
  // FLAW 3: Discount applied to already-discounted total

  if (discount.percent) {
    cart.discount = (cart.discount || 0) + discount.percent;
    cart.total = cart.subtotal * (1 - cart.discount / 100);
  }

  // FLAW 4: No validation that total can't go negative
  cart.appliedCodes = cart.appliedCodes || [];
  cart.appliedCodes.push(code);

  res.json({ cart, message: 'Discount applied!' });
});

app.post('/api/cart/:cartId/checkout', (req, res) => {
  const cart = carts.get(req.params.cartId);

  // FLAW 5: No re-validation of business rules at checkout
  // FLAW 6: Price from client-side cart not verified against server
  processPayment(cart.total); // Could be negative!

  res.json({ success: true, charged: cart.total });
});
```

**Attack Payload**:
```bash
# Apply same discount code multiple times
curl -X POST http://localhost:3000/api/cart/abc123/apply-discount \
  -H "Content-Type: application/json" \
  -d '{"code": "SAVE25"}'

# Repeat 5 times to get 125% discount (negative total = store owes customer)
curl -X POST http://localhost:3000/api/cart/abc123/apply-discount \
  -H "Content-Type: application/json" \
  -d '{"code": "SAVE25"}'
```

**Why This Is Dangerous**:
- Discount codes can be stacked infinitely, exceeding 100% off
- No server-side validation of cart state before checkout
- Minimum order requirements not re-validated after discounts
- Race conditions allow multiple simultaneous discount applications
- Negative totals could trigger refunds instead of charges

**SECURE VERSION**:

```javascript
const express = require('express');
const app = express();
app.use(express.json());

const carts = new Map();
const discountCodes = {
  'SAVE10': { percent: 10, minOrder: 50, stackable: false, maxUses: 1 },
  'SAVE25': { percent: 25, minOrder: 100, stackable: false, maxUses: 1 },
  'FREESHIP': { type: 'shipping', value: 0, stackable: true, maxUses: 1 }
};

// Centralized cart calculation - single source of truth
function calculateCartTotal(cart) {
  let subtotal = cart.items.reduce((sum, item) => {
    // Always use server-side prices, never trust client
    const serverPrice = getProductPrice(item.productId);
    return sum + (serverPrice * item.quantity);
  }, 0);

  let discountAmount = 0;
  let maxDiscountPercent = 0;

  // Calculate maximum single discount (no stacking percentage discounts)
  for (const code of cart.appliedCodes || []) {
    const discount = discountCodes[code];
    if (discount && discount.percent) {
      maxDiscountPercent = Math.max(maxDiscountPercent, discount.percent);
    }
  }

  // Apply maximum percentage discount (capped at 50%)
  const cappedDiscount = Math.min(maxDiscountPercent, 50);
  discountAmount = subtotal * (cappedDiscount / 100);

  const total = Math.max(subtotal - discountAmount, 0.01); // Never below $0.01

  return {
    subtotal: Math.round(subtotal * 100) / 100,
    discountAmount: Math.round(discountAmount * 100) / 100,
    discountPercent: cappedDiscount,
    total: Math.round(total * 100) / 100
  };
}

app.post('/api/cart/:cartId/apply-discount', async (req, res) => {
  const { cartId } = req.params;
  const { code } = req.body;
  const userId = req.user.id; // From authentication middleware

  const cart = carts.get(cartId);
  if (!cart || cart.userId !== userId) {
    return res.status(404).json({ error: 'Cart not found' });
  }

  const normalizedCode = code.toUpperCase().trim();
  const discount = discountCodes[normalizedCode];

  if (!discount) {
    return res.status(400).json({ error: 'Invalid discount code' });
  }

  // Check if code already applied
  if (cart.appliedCodes?.includes(normalizedCode)) {
    return res.status(400).json({ error: 'Discount code already applied' });
  }

  // Check if non-stackable percentage discount already exists
  if (discount.percent && !discount.stackable) {
    const hasPercentDiscount = cart.appliedCodes?.some(c => 
      discountCodes[c]?.percent && !discountCodes[c]?.stackable
    );
    if (hasPercentDiscount) {
      return res.status(400).json({ 
        error: 'Cannot combine with existing percentage discount' 
      });
    }
  }

  // Calculate current totals to validate minimum order
  const currentCalc = calculateCartTotal(cart);
  if (discount.minOrder && currentCalc.subtotal < discount.minOrder) {
    return res.status(400).json({ 
      error: `Minimum order of $${discount.minOrder} required` 
    });
  }

  // Apply discount
  cart.appliedCodes = cart.appliedCodes || [];
  cart.appliedCodes.push(normalizedCode);

  // Recalculate with new discount
  const finalCalc = calculateCartTotal(cart);
  cart.calculatedTotal = finalCalc.total;

  res.json({ 
    cart: { ...cart, calculated: finalCalc },
    message: 'Discount applied successfully'
  });
});
```

**Key Security Controls**:
- **Single source of truth**: `calculateCartTotal()` always recalculates from server-side prices
- **Maximum discount cap**: Percentage discounts capped at 50% to prevent over-discount
- **Non-stackable enforcement**: Only one percentage discount allowed
- **Minimum total floor**: Cart total can never go below $0.01
- **Ownership validation**: Cart must belong to authenticated user

