      });
    }

    // Re-validate all items are still available and prices match
    const itemValidation = await validateCartItems(cart.items);
    if (!itemValidation.valid) {
      return res.status(400).json({ 
        error: 'Some items are unavailable or prices changed',
        details: itemValidation.issues
      });
    }

    // Re-validate all discount codes are still valid
    const discountValidation = await revalidateDiscounts(
      cart.appliedCodes,
      cart.subtotal,
      userId
    );

    // CRITICAL: Use server-calculated total, NEVER trust client
    const serverCalculatedTotal = calculateSecureTotal(
      itemValidation.items,
      discountValidation.validDiscounts
    );

    // Mark cart as processing BEFORE charging
    await updateCartStatus(cartId, 'processing', cart.version);

    // Process payment with server-calculated amount
    const paymentResult = await processPaymentSecure({
      amount: serverCalculatedTotal.total,
      currency: 'USD',
      paymentToken,
      metadata: {
        checkoutId,
        cartId,
        userId,
        itemCount: cart.items.length
      }
    });

    if (!paymentResult.success) {
      await updateCartStatus(cartId, 'active', cart.version + 1);
      return res.status(402).json({ error: 'Payment failed' });
    }

    // Create order record
    const order = await createOrder({
      checkoutId,
      cartId,
      userId,
      items: itemValidation.items,
      discounts: discountValidation.validDiscounts,
      subtotal: serverCalculatedTotal.subtotal,
      discountAmount: serverCalculatedTotal.discountAmount,
      total: serverCalculatedTotal.total,
      paymentId: paymentResult.paymentId,
      status: 'confirmed'
    });

    // Mark cart as completed
    await updateCartStatus(cartId, 'completed', cart.version + 1);

    // Audit log for compliance
    await logCheckout({
      checkoutId,
      orderId: order.id,
      userId,
      total: serverCalculatedTotal.total,
      timestamp: new Date().toISOString(),
      ipAddress: req.ip
    });

    return res.json({
      success: true,
      orderId: order.id,
      charged: serverCalculatedTotal.total
    });

  } finally {
    await releaseLock(`checkout:${cartId}`, lockValue);
  }
});

// Secure total calculation - defense in depth
function calculateSecureTotal(items, discounts) {
  // Use Decimal.js or similar for financial calculations
  let subtotal = items.reduce((sum, item) => {
    // CRITICAL: Use server-side price lookup
    const serverPrice = item.serverVerifiedPrice;
    const quantity = Math.min(Math.max(1, item.quantity), 100); // Cap quantity
    return sum + (serverPrice * quantity);
  }, 0);

  // Calculate discount with multiple caps
  let totalDiscountPercent = 0;
  for (const discount of discounts) {
    if (discount.percent) {
      totalDiscountPercent += discount.percent;
    }
  }

  // BUSINESS RULE: Maximum 60% discount ever
  const cappedDiscountPercent = Math.min(totalDiscountPercent, 60);
  const discountAmount = subtotal * (cappedDiscountPercent / 100);

  // BUSINESS RULE: Minimum charge of $1.00
  const total = Math.max(subtotal - discountAmount, 1.00);

  // Round to cents (avoid floating point issues)
  return {
    subtotal: Math.round(subtotal * 100) / 100,
    discountAmount: Math.round(discountAmount * 100) / 100,
    discountPercent: cappedDiscountPercent,
    total: Math.round(total * 100) / 100
  };
}
```

**Defense in Depth Layers**:

1. **Distributed Locking** - Prevents race conditions:
```javascript
// Redis-based lock with automatic expiration
const lockValue = await acquireLock(`cart:${cartId}:discount`, 10000);
if (!lockValue) {
  return res.status(429).json({ error: 'Please retry' });
}
```

2. **Idempotency Keys** - Prevents duplicate processing:
```javascript
// Same request = same result
const cached = await checkIdempotency(idempotencyKey);
if (cached) return res.status(cached.status).json(cached.body);
```

3. **Optimistic Locking** - Detects concurrent modifications:
```javascript
// Version check on save
const saved = await saveCartWithVersionCheck(cartId, cart, expectedVersion);
if (!saved) return res.status(409).json({ error: 'Concurrent modification' });
```

**Additional Protections**:
- **Server-side price verification**: Never trust client-submitted prices
- **Maximum discount caps**: Both per-code (50%) and total (60%)
- **Minimum charge floor**: $1.00 minimum prevents negative totals
- **Cart status state machine**: active → processing → completed (no rollback)
- **Comprehensive audit logging**: All discount and checkout operations logged
- **Rate limiting**: Prevent brute-force discount code guessing
- **Quantity caps**: Maximum 100 of any item to prevent overflow attacks

Blindly concatenating user input into SQL is dangerous even if you "mostly" trust your users. Rust’s type system doesn’t protect you from SQL injection; you must validate input and use parameterized queries.

**VULNERABLE CODE**:

```rust
use std::env;
use std::io::{self, Read};
use postgres::{Client, NoTls};

fn main() -> Result<(), Box<dyn std::error::Error>> {
    // Simulate reading a username from HTTP request body (no validation)
    let mut input = String::new();
    io::stdin().read_to_string(&mut input)?;
    let username = input.trim();

    let db_url = env::var("DATABASE_URL")
        .unwrap_or_else(|_| "postgres://user:pass@localhost/app".to_string());

    let mut client = Client::connect(&db_url, NoTls)?;

    // DANGEROUS: directly interpolating user input into SQL
    let query = format!(
        "SELECT id, username, email FROM users WHERE username = '{}'",
        username
    );

    println!("Executing: {}", query); // May leak sensitive query details

    for row in client.query(&query, &[])? {
        let id: i32 = row.get("id");
        let uname: String = row.get("username");
        let email: String = row.get("email");
        println!("User: {} (#{}) <{}>", uname, id, email);
    }

    Ok(())
}
```

**Attack Payload** (if applicable):
```sql
' OR '1'='1'--
```

If this payload is supplied as the `username`, the resulting query becomes:
```sql
SELECT id, username, email FROM users WHERE username = '' OR '1'='1'--'
```
This returns all users instead of just one.

A more destructive payload could be:

```sql
'; DROP TABLE users; --
```

**Why This Is Dangerous**:
- User input is inserted directly into the SQL string, letting an attacker break out of the intended literal and inject arbitrary SQL.
- There is no input validation or length/character restrictions, enabling abusive payloads and potential denial of service.
- Query text is printed to stdout, which in production may end up in logs and leak sensitive structure and data to attackers.

**SECURE VERSION**:

```rust
use std::env;
use std::io::{self, Read};
use std::time::Duration;
use postgres::{Client, NoTls, Error};

// Basic whitelist validation for usernames
fn validate_username(raw: &str) -> Result<String, String> {
    let trimmed = raw.trim();

    if trimmed.is_empty() {
        return Err("Username must not be empty".to_string());
    }

    if trimmed.len() > 32 {
        return Err("Username too long".to_string());
    }

    if !trimmed
        .chars()
        .all(|c| c.is_ascii_alphanumeric() || c == '_' || c == '-')
    {
        return Err("Username contains invalid characters".to_string());
    }

    Ok(trimmed.to_string())
}

fn main() -> Result<(), Box<dyn std::error::Error>> {
    let mut input = String::new();
    io::stdin().read_to_string(&mut input)?;

    // DEFENSE-IN-DEPTH #1: Input validation
    let username = match validate_username(&input) {
        Ok(u) => u,
        Err(msg) => {
            eprintln!("Invalid username: {}", msg);
            // Fail securely without touching the database
            return Ok(());
        }
    };

    let db_url = env::var("DATABASE_URL")
        .unwrap_or_else(|_| "postgres://user:pass@localhost/app".to_string());

    // In real apps, configure connection pool and timeouts
    let mut client = Client::connect(&db_url, NoTls)?;

    // PRIMARY DEFENSE: Parameterized query (prepared statement)
    let stmt = client.prepare_typed(
        "SELECT id, username, email FROM users WHERE username = $1",
        &[
            &postgres::types::Type::TEXT,
        ],
    )?;

    // Structured error handling and minimal leakage of internals
    match client.query(&stmt, &[&username]) {
        Ok(rows) => {
            if rows.is_empty() {
                println!("No user found");
            } else {
                for row in rows {
                    let id: i32 = row.get("id");
                    let uname: String = row.get("username");
                    let email: String = row.get("email");
                    println!("User: {} (#{}) <{}>", uname, id, email);
                }
            }
        }
        Err(e) => {
            // DEFENSE-IN-DEPTH #2: Safe logging
            log_db_error(&e);
            eprintln!("Internal error while fetching user");
        }
    }

    Ok(())
}

fn log_db_error(err: &Error) {
    // In production, send to a structured logger instead of println!
    // Ensure no sensitive data is logged.
    eprintln!("[db_error] code={:?} message={}", err.code(), err);
}
```

**Key Security Controls**:
- **Parameterized queries with typed placeholders**: `username` is passed as a parameter (`$1`) rather than concatenated into the SQL string, preventing it from altering the query structure.
- **Strict input validation and normalization**: Whitelisting allowed characters and enforcing length constraints drastically reduces the attack surface and unexpected input states.
- **Secure error handling and logging**: Database errors are logged in a controlled way without exposing raw SQL or internal details to the caller, limiting information leakage to attackers.

In production you often need dynamic WHERE clauses, pagination, and multiple filters. The key is to keep SQL structure under your control while only making values dynamic, and to combine that with layered protections (validation, rate limiting, logging, environment-specific config).

**PRODUCTION PATTERN**:

```rust
use std::env;
use std::net::SocketAddr;
use std::time::Duration;

use axum::{routing::get, Router, extract::Query, response::IntoResponse};
use hyper::StatusCode;
use once_cell::sync::Lazy;
use serde::Deserialize;
use tokio_postgres::{Client, NoTls, Error as PgError};
use deadpool_postgres::{Config as PoolConfig, ManagerConfig, RecyclingMethod, Runtime};
use tower_http::trace::TraceLayer;
use tower::{ServiceBuilder, limit::RateLimitLayer};

static IS_PROD: Lazy<bool> = Lazy::new(|| {
    env::var("APP_ENV").unwrap_or_else(|_| "development".into()) == "production"
});

#[derive(Deserialize, Debug)]
struct UserFilter {
    username: Option<String>,
    email: Option<String>,
    page: Option<u32>,
    page_size: Option<u32>,
}

// Validate and normalize query parameters
fn validate_filter(filter: UserFilter) -> Result<(Option<String>, Option<String>, i64, i64), String> {
    let mut uname = None;
    let mut email = None;

    if let Some(u) = filter.username {
        let t = u.trim();
        if !t.is_empty() {
            if t.len() > 32 {
                return Err("username too long".into());
            }
            if !t
                .chars()
                .all(|c| c.is_ascii_alphanumeric() || c == '_' || c == '-')
            {
                return Err("username has invalid characters".into());
            }
            uname = Some(t.to_string());
        }
    }

    if let Some(e) = filter.email {
        let t = e.trim();
        if !t.is_empty() {
            if t.len() > 128 {
                return Err("email too long".into());
            }
            // very simple email shape check; in real code, use a proper validator
            if !t.contains('@') {
                return Err("invalid email".into());
            }
            email = Some(t.to_string());
        }
    }

    let page = filter.page.unwrap_or(1).max(1);
    let page_size = filter.page_size.unwrap_or(20).clamp(1, 100);

    let offset = ((page - 1) as i64) * (page_size as i64);
    let limit = page_size as i64;

    Ok((uname, email, offset, limit))
}

async fn get_db_client() -> Result<Client, PgError> {
    static POOL: Lazy<deadpool_postgres::Pool> = Lazy::new(|| {
        let mut cfg = PoolConfig::new();
        cfg.dbname = Some(env::var("DB_NAME").unwrap_or_else(|_| "app".into()));
        cfg.user = Some(env::var("DB_USER").unwrap_or_else(|_| "user".into()));
        cfg.password = Some(env::var("DB_PASS").unwrap_or_else(|_| "pass".into()));
        cfg.host = Some(env::var("DB_HOST").unwrap_or_else(|_| "localhost".into()));
        cfg.manager = Some(ManagerConfig { recycling_method: RecyclingMethod::Fast });
        cfg.create_pool(Some(Runtime::Tokio1), NoTls).expect("pool creation failed")
    });

    let client = POOL.get().await?;
    Ok(client)
}

async fn list_users(Query(raw_filter): Query<UserFilter>) -> impl IntoResponse {
    // DEFENSE LAYER 1: Input validation and normalization
    let (username, email, offset, limit) = match validate_filter(raw_filter) {
        Ok(v) => v,
        Err(msg) => {
            // 400 for client-side input problems
            return (StatusCode::BAD_REQUEST, msg).into_response();
        }
    };

    let mut client = match get_db_client().await {
        Ok(c) => c,
        Err(e) => {
            log_db_error(&e);
            return (
                StatusCode::INTERNAL_SERVER_ERROR,
                "database unavailable".to_string(),
            )
                .into_response();
        }
    };

    // DEFENSE LAYER 2: Dynamic query building with parameterization only
    let mut sql = String::from("SELECT id, username, email FROM users");
    let mut params: Vec<&(dyn tokio_postgres::types::ToSql + Sync)> = Vec::new();
    let mut clauses: Vec<String> = Vec::new();

    if let Some(ref u) = username {
        clauses.push(format!("username = ${}", params.len() + 1));
        params.push(u);
    }

    if let Some(ref e) = email {
        clauses.push(format!("email = ${}", params.len() + 1));
        params.push(e);
    }

    if !clauses.is_empty() {
        sql.push_str(" WHERE ");
        sql.push_str(&clauses.join(" AND "));
    }

    // Pagination parameters (offset & limit) also parameterized
    sql.push_str(&format!(" ORDER BY id ASC OFFSET ${} LIMIT ${}", params.len() + 1, params.len() + 2));
    params.push(&offset);
    params.push(&limit);

    let rows = match client.query(&sql, &params[..]).await {
        Ok(r) => r,
        Err(e) => {
            log_db_error(&e);
            return (
                StatusCode::INTERNAL_SERVER_ERROR,
                "query error".to_string(),
            )
                .into_response();
        }
    };

    // In real apps, serialize to JSON. Here we just format as text.
    let mut out = String::new();
    for row in rows {
        let id: i32 = row.get("id");
        let uname: String = row.get("username");
        let email: String = row.get("email");
        out.push_str(&format!("{}: {} <{}>\n", id, uname, email));
    }

    (StatusCode::OK, out).into_response()
}

fn log_db_error(err: &PgError) {
    // DEFENSE LAYER 3: Centralized, sanitized logging
    if *IS_PROD {
        eprintln!("[db_error] message={}", err); // hook into structured logger in real code
    } else {
        eprintln!("[db_error][dev] {:?}", err);
    }
}

#[tokio::main]
async fn main() {
    // Environment-specific configuration
    if *IS_PROD {
        // Example: configure secure logging, TLS termination in front proxy, etc.
        eprintln!("Starting in PRODUCTION mode");
    } else {
        eprintln!("Starting in DEVELOPMENT mode");
    }

    let rate_layer = ServiceBuilder::new()
        // Basic rate limiting: 60 requests per minute per instance
        .layer(RateLimitLayer::new(60, Duration::from_secs(60)))
        .layer(TraceLayer::new_for_http());

    let app = Router::new()
        .route("/users", get(list_users))
        .layer(rate_layer);

    let addr: SocketAddr = "0.0.0.0:3000".parse().unwrap();
    eprintln!("Listening on {}", addr);

    if let Err(e) = axum::Server::bind(&addr)
        .serve(app.into_make_service())
        .await
    {
        eprintln!("server error: {}", e);
    }
}
```

**Defense in Depth Layers**:
1. **Strict input validation and normalization**:
   - `validate_filter` enforces length limits, character whitelists, and basic email shape before any SQL is built:
   ```rust
   if t.len() > 32 { return Err("username too long".into()); }
   if !t.chars().all(|c| c.is_ascii_alphanumeric() || c == '_' || c == '-') {
       return Err("username has invalid characters".into());
   }
   ```
2. **Safe dynamic query construction with parameters only**:
   - SQL structure is built by trusted server code; user data only ever appears as `$n` parameters:
   ```rust
   if let Some(ref u) = username {
       clauses.push(format!("username = ${}", params.len() + 1));
       params.push(u);
   }
   ```
   This avoids string concatenation like `... WHERE username = '" + u + "'`.
3. **Centralized error handling and logging**:
   - All DB errors go through `log_db_error`, which hides detailed internals from clients and differentiates dev/prod behavior.
   ```rust
   log_db_error(&e);
   return (StatusCode::INTERNAL_SERVER_ERROR, "query error".to_string()).into_response();
   ```

**Additional Protections**:
- **Environment-specific configuration**: Behavior changes based on `APP_ENV`; in production you can tighten logging, enable TLS at the edge, enforce stricter timeouts, and disable verbose errors.
- **Rate limiting**: `RateLimitLayer` helps mitigate brute force and resource-exhaustion attempts, making abusive SQL injection probing harder and noisier.
- **Observability and monitoring**: `TraceLayer` plus consistent error logs enable alerting on spikes in 400/500 responses or DB errors, helping you detect and respond to injection attempts early.

HTTP verb tampering is a serious authorization bypass technique where attackers use unexpected HTTP methods to circumvent security controls. Many developers only check for specific methods but fail to explicitly deny others.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/json"
	"log"
	"net/http"
)

type User struct {
	ID    int    `json:"id"`
	Role  string `json:"role"`
	Email string `json:"email"`
}

var adminUser = User{ID: 1, Role: "admin", Email: "admin@example.com"}

// VULNERABLE: Only checks if method is POST, allows other methods through
func deleteUserHandler(w http.ResponseWriter, r *http.Request) {
	// Weak check - only validates POST but doesn't reject others
	if r.Method == http.MethodPost {
		// Requires admin auth for POST
		if !isAdmin(r) {
			http.Error(w, "Forbidden", http.StatusForbidden)
			return
		}
	}
	// BUG: Other methods (PUT, DELETE, PATCH) bypass the admin check!

	userID := r.URL.Query().Get("id")
	log.Printf("Deleting user: %s", userID)
	// Performs the deletion regardless of method if not POST
	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"status": "user deleted"})
}

func isAdmin(r *http.Request) bool {
	return r.Header.Get("X-Admin-Token") == "secret-admin-token"
}

func main() {
	http.HandleFunc("/admin/delete-user", deleteUserHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

**Attack Payload**:
```bash
# Normal POST request - blocked without admin token
curl -X POST "http://localhost:8080/admin/delete-user?id=42"
# Response: Forbidden

# HTTP verb tampering - using PUT bypasses admin check!
curl -X PUT "http://localhost:8080/admin/delete-user?id=42"
# Response: {"status": "user deleted"}

# Using DELETE method also bypasses
curl -X DELETE "http://localhost:8080/admin/delete-user?id=42"
# Response: {"status": "user deleted"}
```

**Why This Is Dangerous**:
- Only checks authorization for POST requests, not for PUT/DELETE/PATCH
- Attackers can use alternative HTTP methods to bypass access controls
- The vulnerable pattern treats unrecognized methods as implicitly allowed
- Common in legacy code that predates RESTful API conventions

**SECURE VERSION**:

```go
package main

import (
	"encoding/json"
	"log"
	"net/http"
)

type User struct {
	ID    int    `json:"id"`
	Role  string `json:"role"`
	Email string `json:"email"`
}

// Middleware to enforce allowed HTTP methods
func methodEnforcer(allowedMethods []string, next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		methodAllowed := false
		for _, method := range allowedMethods {
			if r.Method == method {
				methodAllowed = true
				break
			}
		}

		if !methodAllowed {
			log.Printf("SECURITY: Blocked HTTP verb tampering attempt: %s from %s", 
				r.Method, r.RemoteAddr)
			w.Header().Set("Allow", "POST")
			http.Error(w, "Method Not Allowed", http.StatusMethodNotAllowed)
			return
		}
		next(w, r)
	}
}

// Middleware to enforce admin authorization
func requireAdmin(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if !isAdmin(r) {
			log.Printf("SECURITY: Unauthorized admin access attempt from %s", r.RemoteAddr)
			http.Error(w, "Forbidden", http.StatusForbidden)
			return
		}
		next(w, r)
	}
}

// SECURE: Authorization check runs regardless of HTTP method
func deleteUserHandler(w http.ResponseWriter, r *http.Request) {
	userID := r.URL.Query().Get("id")
	if userID == "" {
		http.Error(w, "Missing user ID", http.StatusBadRequest)
		return
	}

	log.Printf("Admin deleting user: %s", userID)
	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(map[string]string{"status": "user deleted"})
}

func isAdmin(r *http.Request) bool {
	return r.Header.Get("X-Admin-Token") == "secret-admin-token"
}

func main() {
	// Chain: Method enforcement -> Admin check -> Handler
	http.HandleFunc("/admin/delete-user", 
		methodEnforcer([]string{http.MethodPost}, 
			requireAdmin(deleteUserHandler)))

	log.Println("Server starting on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

**Key Security Controls**:
- **Explicit method allowlist**: Only POST is permitted; all other methods return 405
- **Layered middleware**: Method check runs BEFORE authorization, blocking tampering attempts
- **Security logging**: All bypass attempts are logged with client IP for forensics
- **Proper HTTP response**: Returns 405 with Allow header per RFC 7231

Excellent question! HEAD requests are particularly tricky because Go's http.ServeMux automatically handles HEAD requests for GET handlers. This can lead to subtle authorization bypasses. Here's a production-ready pattern:

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"encoding/json"
	"log"
	"net/http"
	"sync"
	"time"
)

// RouteConfig defines allowed methods and required roles per endpoint
type RouteConfig struct {
	AllowedMethods []string
	RequiredRoles  []string
	Handler        http.HandlerFunc
	RateLimit      int // requests per minute
}

// SecurityRouter implements defense-in-depth HTTP method enforcement
type SecurityRouter struct {
	routes      map[string]RouteConfig
	rateLimiter *RateLimiter
	mu          sync.RWMutex
}

// RateLimiter tracks request counts per IP
type RateLimiter struct {
	counts map[string]int
	mu     sync.Mutex
}

func NewSecurityRouter() *SecurityRouter {
	router := &SecurityRouter{
		routes:      make(map[string]RouteConfig),
		rateLimiter: &RateLimiter{counts: make(map[string]int)},
	}

	// Reset rate limits every minute
	go func() {
		for range time.Tick(time.Minute) {
			router.rateLimiter.mu.Lock()
			router.rateLimiter.counts = make(map[string]int)
			router.rateLimiter.mu.Unlock()
		}
	}()

	return router
}

func (sr *SecurityRouter) Register(path string, config RouteConfig) {
	sr.mu.Lock()
	defer sr.mu.Unlock()
	sr.routes[path] = config
}

func (sr *SecurityRouter) ServeHTTP(w http.ResponseWriter, r *http.Request) {
	// LAYER 1: Route lookup
	sr.mu.RLock()
	config, exists := sr.routes[r.URL.Path]
	sr.mu.RUnlock()

	if !exists {
		http.NotFound(w, r)
		return
	}

	// LAYER 2: Strict HTTP method enforcement (blocks HEAD tampering)
	methodAllowed := false
	for _, method := range config.AllowedMethods {
		if r.Method == method {
			methodAllowed = true
			break
		}
	}

	// CRITICAL: Explicitly block HEAD unless specifically allowed
	// This prevents implicit HEAD-for-GET behavior
	if r.Method == http.MethodHead && !methodAllowed {
		log.Printf("SECURITY_ALERT: HEAD tampering blocked for %s from %s",
			r.URL.Path, r.RemoteAddr)
		sr.sendSecurityHeaders(w)
		http.Error(w, "Method Not Allowed", http.StatusMethodNotAllowed)
		return
	}

	if !methodAllowed {
		log.Printf("SECURITY_ALERT: HTTP verb tampering: %s %s from %s",
			r.Method, r.URL.Path, r.RemoteAddr)
		sr.sendSecurityHeaders(w)
		http.Error(w, "Method Not Allowed", http.StatusMethodNotAllowed)
		return
	}

	// LAYER 3: Rate limiting
	if !sr.checkRateLimit(r.RemoteAddr, config.RateLimit) {
		log.Printf("RATE_LIMIT: Exceeded for %s on %s", r.RemoteAddr, r.URL.Path)
		http.Error(w, "Too Many Requests", http.StatusTooManyRequests)
		return
	}

	// LAYER 4: Role-based authorization
	if len(config.RequiredRoles) > 0 {
		userRoles := extractUserRoles(r)
		if !hasRequiredRole(userRoles, config.RequiredRoles) {
			log.Printf("AUTHZ_DENIED: User roles %v insufficient for %s (needs %v)",
				userRoles, r.URL.Path, config.RequiredRoles)
			http.Error(w, "Forbidden", http.StatusForbidden)
			return
		}
	}

	// LAYER 5: Add security context and call handler
	ctx := context.WithValue(r.Context(), "request_id", generateRequestID())
	sr.sendSecurityHeaders(w)
	config.Handler(w, r.WithContext(ctx))
}

func (sr *SecurityRouter) checkRateLimit(ip string, limit int) bool {
	if limit <= 0 {
		return true
	}
	sr.rateLimiter.mu.Lock()
	defer sr.rateLimiter.mu.Unlock()
	sr.rateLimiter.counts[ip]++
	return sr.rateLimiter.counts[ip] <= limit
}

func (sr *SecurityRouter) sendSecurityHeaders(w http.ResponseWriter) {
	w.Header().Set("X-Content-Type-Options", "nosniff")
	w.Header().Set("X-Frame-Options", "DENY")
	w.Header().Set("Cache-Control", "no-store")
}

func extractUserRoles(r *http.Request) []string {
	// In production: decode JWT claims or query session store
	token := r.Header.Get("Authorization")
	if token == "Bearer admin-token" {
		return []string{"admin", "user"}
	}
	if token == "Bearer user-token" {
		return []string{"user"}
	}
	return []string{}
}

func hasRequiredRole(userRoles, requiredRoles []string) bool {
	for _, required := range requiredRoles {
		for _, userRole := range userRoles {
			if userRole == required {
				return true
			}
		}
	}
	return false
}

func generateRequestID() string {
	return time.Now().Format("20060102150405.000000")
}

// Handlers
func getUserHandler(w http.ResponseWriter, r *http.Request) {
	json.NewEncoder(w).Encode(map[string]string{"user": "john", "role": "user"})
}

func createUserHandler(w http.ResponseWriter, r *http.Request) {
	json.NewEncoder(w).Encode(map[string]string{"status": "user created"})
}

func deleteUserHandler(w http.ResponseWriter, r *http.Request) {
	json.NewEncoder(w).Encode(map[string]string{"status": "user deleted"})
}

func adminConfigHandler(w http.ResponseWriter, r *http.Request) {
	json.NewEncoder(w).Encode(map[string]string{"config": "sensitive data"})
}

func main() {
	router := NewSecurityRouter()

	// Public endpoint - GET only, no HEAD
	router.Register("/api/users", RouteConfig{
		AllowedMethods: []string{http.MethodGet},
		RequiredRoles:  []string{},
		Handler:        getUserHandler,
		RateLimit:      100,
	})

	// User creation - POST only, requires user role
	router.Register("/api/users/create", RouteConfig{
		AllowedMethods: []string{http.MethodPost},
		RequiredRoles:  []string{"user"},
		Handler:        createUserHandler,
		RateLimit:      10,
	})

	// Admin deletion - DELETE only, requires admin role
	router.Register("/api/admin/users/delete", RouteConfig{
		AllowedMethods: []string{http.MethodDelete},
		RequiredRoles:  []string{"admin"},
		Handler:        deleteUserHandler,
		RateLimit:      5,
	})

	// Admin config - GET and POST, requires admin role
	router.Register("/api/admin/config", RouteConfig{
		AllowedMethods: []string{http.MethodGet, http.MethodPost},
		RequiredRoles:  []string{"admin"},
		Handler:        adminConfigHandler,
		RateLimit:      20,
	})

	log.Println("Production server starting on :8080")
	log.Fatal(http.ListenAndServe(":8080", router))
}
```

**Defense in Depth Layers**:

1. **Layer 1 - Route Validation**: Unknown routes return 404, preventing path-based bypasses
```go
if !exists {
    http.NotFound(w, r)
    return
}
```

2. **Layer 2 - Explicit Method Allowlist with HEAD Protection**: HEAD requests are explicitly blocked unless allowed, preventing Go's implicit HEAD handling
```go
if r.Method == http.MethodHead && !methodAllowed {
    // Block HEAD tampering specifically
}
```

3. **Layer 3 - Rate Limiting**: Per-endpoint rate limits prevent brute-force method enumeration
```go
if !sr.checkRateLimit(r.RemoteAddr, config.RateLimit) {
    http.Error(w, "Too Many Requests", http.StatusTooManyRequests)
}
```

4. **Layer 4 - Role-Based Access Control**: Authorization checked AFTER method validation
```go
if !hasRequiredRole(userRoles, config.RequiredRoles) {
    http.Error(w, "Forbidden", http.StatusForbidden)
}
```

5. **Layer 5 - Security Headers and Audit Trail**: Request IDs for correlation
```go
ctx := context.WithValue(r.Context(), "request_id", generateRequestID())
```

**Additional Protections**:
- **Security headers**: X-Content-Type-Options, X-Frame-Options, Cache-Control added to all responses
- **Comprehensive logging**: All security events logged with IP, method, path for SIEM integration
- **Graceful degradation**: Rate-limited requests get 429 instead of blocking
- **Thread-safe design**: Mutex-protected route and rate limit maps for concurrent access
- **No implicit behavior**: Every HTTP method must be explicitly allowed per route

Debug endpoints are extremely dangerous when exposed in production environments. Go's built-in profiling endpoints and custom debug routes can leak sensitive information including memory dumps, goroutine stacks, environment variables, and internal application state.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"net/http/pprof"
	"os"
	"runtime"
)

type DebugInfo struct {
	Environment map[string]string `json:"environment"`
	DBConnection string            `json:"db_connection"`
	APIKeys      map[string]string `json:"api_keys"`
	MemStats     runtime.MemStats  `json:"memory_stats"`
}

func main() {
	mux := http.NewServeMux()

	// VULNERABLE: Debug endpoints always enabled
	mux.HandleFunc("/debug/pprof/", pprof.Index)
	mux.HandleFunc("/debug/pprof/cmdline", pprof.Cmdline)
	mux.HandleFunc("/debug/pprof/profile", pprof.Profile)
	mux.HandleFunc("/debug/pprof/symbol", pprof.Symbol)
	mux.HandleFunc("/debug/pprof/trace", pprof.Trace)

	// VULNERABLE: Custom debug endpoint exposing secrets
	mux.HandleFunc("/debug/info", func(w http.ResponseWriter, r *http.Request) {
		var memStats runtime.MemStats
		runtime.ReadMemStats(&memStats)

		info := DebugInfo{
			Environment:  getAllEnvVars(),
			DBConnection: os.Getenv("DATABASE_URL"),
			APIKeys: map[string]string{
				"stripe":   os.Getenv("STRIPE_SECRET_KEY"),
				"sendgrid": os.Getenv("SENDGRID_API_KEY"),
			},
			MemStats: memStats,
		}
		json.NewEncoder(w).Encode(info)
	})

	mux.HandleFunc("/", homeHandler)
	log.Fatal(http.ListenAndServe(":8080", mux))
}

func getAllEnvVars() map[string]string {
	envs := make(map[string]string)
	for _, env := range os.Environ() {
		envs[env] = os.Getenv(env)
	}
	return envs
}

func homeHandler(w http.ResponseWriter, r *http.Request) {
	fmt.Fprintf(w, "Welcome to our application")
}
```

**Attack Payload**:
```bash
# Discover debug endpoints
curl http://target.com/debug/pprof/
curl http://target.com/debug/info

# Extract heap dump (may contain secrets in memory)
curl http://target.com/debug/pprof/heap > heap.dump

# Get goroutine stacks (reveals internal code paths)
curl http://target.com/debug/pprof/goroutine?debug=2

# Extract command line arguments (may contain secrets)
curl http://target.com/debug/pprof/cmdline
```

**Why This Is Dangerous**:
- Environment variables containing database credentials, API keys, and secrets are exposed
- Heap dumps can contain passwords, tokens, and sensitive data in memory
- Goroutine stacks reveal internal application architecture and code paths
- CPU profiles help attackers understand performance characteristics for DoS attacks
- No authentication protects these sensitive endpoints

**SECURE VERSION**:

```go
package main

import (
