        MDC.put("requestId", requestId);

        String settingName = request.getParameter("setting");
        String settingValue = request.getParameter("value");
        String userId = (String) request.getSession().getAttribute("userId");
        String username = (String) request.getSession().getAttribute("username");
        String sourceIp = getClientIpAddress(request);
        String userAgent = request.getHeader("User-Agent");

        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            // Get the previous value for audit trail
            String previousValue = getPreviousValue(conn, settingName);

            // Update the setting
            String sql = "UPDATE system_settings SET value = ?, modified_by = ?, modified_at = ? WHERE name = ?";
            PreparedStatement stmt = conn.prepareStatement(sql);
            stmt.setString(1, settingValue);
            stmt.setString(2, userId);
            stmt.setTimestamp(3, Timestamp.from(Instant.now()));
            stmt.setString(4, settingName);
            int rowsAffected = stmt.executeUpdate();

            // Write comprehensive audit log
            AuditEvent event = new AuditEvent.Builder()
                .requestId(requestId)
                .timestamp(Instant.now())
                .eventType("ADMIN_SETTING_CHANGE")
                .action("UPDATE")
                .actorId(userId)
                .actorUsername(username)
                .sourceIp(sourceIp)
                .userAgent(userAgent)
                .resource("system_settings")
                .resourceId(settingName)
                .previousValue(previousValue)
                .newValue(settingValue)
                .outcome(rowsAffected > 0 ? "SUCCESS" : "NO_CHANGE")
                .build();

            writeAuditLog(event);
            persistAuditRecord(conn, event);

            response.setStatus(HttpServletResponse.SC_OK);
        } catch (SQLException e) {
            auditLogger.error("requestId={} action=ADMIN_SETTING_CHANGE outcome=FAILURE " +
                "actor={} setting={} error={}", requestId, userId, settingName, e.getMessage());
            response.setStatus(HttpServletResponse.SC_INTERNAL_SERVER_ERROR);
        } finally {
            MDC.clear();
        }
    }

    private String getPreviousValue(Connection conn, String settingName) throws SQLException {
        String sql = "SELECT value FROM system_settings WHERE name = ?";
        try (PreparedStatement stmt = conn.prepareStatement(sql)) {
            stmt.setString(1, settingName);
            ResultSet rs = stmt.executeQuery();
            return rs.next() ? rs.getString("value") : null;
        }
    }

    private String getClientIpAddress(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
