            int recentFailures = persistence.countRecentEvents(
                "AUTH_FAILURE", event.getSourceIp(), 5, TimeUnit.MINUTES);
            if (recentFailures >= 5) {
                alertService.sendCriticalAlert("BRUTE_FORCE_DETECTED",
                    String.format("5+ auth failures from %s in 5 minutes", event.getSourceIp()));
            }
        }

        // Check for privilege escalation
        if ("USER_ROLE_CHANGE".equals(event.getEventType())) {
            if (event.getNewValue().contains("ADMIN")) {
                alertService.sendCriticalAlert("PRIVILEGE_ESCALATION",
                    String.format("User %s granted admin role by %s",
                        event.getResourceId(), event.getActorUsername()));
            }
        }

        // Check for off-hours activity
        if (isOutsideBusinessHours(event.getTimestamp())) {
            if (isSensitiveOperation(event)) {
                alertService.sendAlert("OFF_HOURS_SENSITIVE_OPERATION",
                    String.format("%s performed by %s at %s",
                        event.getEventType(), event.getActorUsername(), event.getTimestamp()));
            }
        }
    }

    /**
     * Background processor for async queue
     */
    private void processAuditQueue() {
        while (!Thread.currentThread().isInterrupted()) {
            try {
                AuditEvent event = auditQueue.poll(100, TimeUnit.MILLISECONDS);
                if (event != null) {
                    logSynchronously(event);
                }
            } catch (InterruptedException e) {
                Thread.currentThread().interrupt();
                break;
            }
        }
    }

    /**
     * Periodic integrity verification
     */
    public boolean verifyAuditLogIntegrity(Instant from, Instant to) {
        List<AuditEvent> events = persistence.getEventsBetween(from, to);
        String expectedPreviousHash = null;

        for (AuditEvent event : events) {
            if (expectedPreviousHash != null && 
                !expectedPreviousHash.equals(event.getPreviousEventHash())) {
                logger.error("Audit log integrity violation detected at event: {}", 
                    event.getRequestId());
                alertService.sendCriticalAlert("AUDIT_LOG_TAMPERING",
                    "Hash chain broken at event " + event.getRequestId());
                return false;
            }

            String calculatedHash = calculateEventHash(event, event.getPreviousEventHash());
            if (!calculatedHash.equals(event.getEventHash())) {
                logger.error("Audit event hash mismatch: {}", event.getRequestId());
                alertService.sendCriticalAlert("AUDIT_LOG_TAMPERING",
                    "Event hash mismatch at " + event.getRequestId());
                return false;
            }

            expectedPreviousHash = event.getEventHash();
        }

        logger.info("Audit log integrity verified for {} events", events.size());
        return true;
    }

    private boolean isOutsideBusinessHours(Instant timestamp) {
        // Implementation to check business hours
