// SECURE: Safe complex object serialization with integrity
class SecureSerializer {
  constructor(secret) {
    this.secret = secret;
  }

  // Create HMAC signature for integrity verification
  sign(data) {
    const hmac = crypto.createHmac('sha256', this.secret);
    hmac.update(data);
    return hmac.digest('hex');
  }

  // Verify HMAC signature
  verify(data, signature) {
    const expected = this.sign(data);
    return crypto.timingSafeEqual(
      Buffer.from(signature, 'hex'),
      Buffer.from(expected, 'hex')
    );
  }

  // Serialize with signature and timestamp
  serialize(obj) {
    // SuperJSON safely handles: Date, Map, Set, BigInt, RegExp, undefined
    // It does NOT serialize functions (safe!)
    const payload = {
      data: obj,
      timestamp: Date.now()
    };

    const serialized = serialize(payload);
    const jsonStr = JSON.stringify(serialized);
    const signature = this.sign(jsonStr);

    return JSON.stringify({
      payload: serialized,
      sig: signature
    });
  }

  // Deserialize with signature and timestamp verification
  deserialize(str, maxAge = config.maxPayloadAge) {
    let parsed;
    try {
      parsed = JSON.parse(str);
    } catch (e) {
      throw new Error('Invalid JSON format');
    }

    if (!parsed.payload || !parsed.sig) {
      throw new Error('Missing payload or signature');
    }

    // Verify integrity
    const payloadStr = JSON.stringify(parsed.payload);
    if (!this.verify(payloadStr, parsed.sig)) {
      console.error('SECURITY: Signature verification failed');
      throw new Error('Integrity check failed');
    }

    // Deserialize using SuperJSON (safe - no eval)
    const { data, timestamp } = deserialize(parsed.payload);

    // Check timestamp to prevent replay attacks
    if (Date.now() - timestamp > maxAge) {
      throw new Error('Payload expired');
    }

    return data;
  }
}

