  // For RS256: Use separate public/private keys
  privateKey: process.env.JWT_PRIVATE_KEY,
  publicKey: process.env.JWT_PUBLIC_KEY,

  // CRITICAL: Never allow algorithm switching
  accessTokenOptions: {
    algorithm: 'RS256',
    expiresIn: '15m',
    issuer: process.env.JWT_ISSUER || 'my-secure-app',
    audience: process.env.JWT_AUDIENCE || 'my-secure-app-users'
  },
  refreshTokenOptions: {
    algorithm: 'RS256',
    expiresIn: '7d',
    issuer: process.env.JWT_ISSUER || 'my-secure-app',
    audience: process.env.JWT_AUDIENCE || 'my-secure-app-users'
  },
  verifyOptions: {
    algorithms: ['RS256'],  // CRITICAL: Whitelist ONLY RS256
    issuer: process.env.JWT_ISSUER || 'my-secure-app',
    audience: process.env.JWT_AUDIENCE || 'my-secure-app-users',
    complete: true  // Returns decoded header for additional checks
  }
};

// Validate key configuration on startup
function validateKeyConfig() {
  if (!JWT_CONFIG.privateKey || !JWT_CONFIG.publicKey) {
    throw new Error('JWT keys must be configured');
  }

  // Ensure keys are appropriate type
  if (!JWT_CONFIG.privateKey.includes('BEGIN') || 
      !JWT_CONFIG.publicKey.includes('BEGIN PUBLIC KEY')) {
    throw new Error('Invalid key format - use PEM formatted RSA keys');
