        [HttpPost("login")]
        public async Task<IActionResult> Login([FromBody] LoginRequest request)
        {
            var clientIp = GetClientIp();

            // Rate limiting by IP and username
            if (!await _rateLimiter.AllowRequestAsync($"login:{clientIp}", 10, TimeSpan.FromMinutes(15)))
            {
                await _auditService.LogAsync(AuditEvent.RateLimitExceeded, clientIp);
                return StatusCode(429, "Too many attempts. Please try again later.");
            }

            var user = await _userManager.FindByEmailAsync(request.Email);
            if (user == null)
            {
                await Task.Delay(Random.Shared.Next(200, 600));
                await _auditService.LogAsync(AuditEvent.LoginFailedUnknownUser, 
                    request.Email, clientIp);
                return Unauthorized("Invalid credentials");
            }

            // Verify password first
            if (!await _userManager.CheckPasswordAsync(user, request.Password))
            {
                await _userManager.AccessFailedAsync(user);
                await _auditService.LogAsync(AuditEvent.LoginFailedBadPassword, 
                    user.Id, clientIp);

                if (await _userManager.IsLockedOutAsync(user))
                {
                    await _auditService.LogAsync(AuditEvent.AccountLockedOut, user.Id);
                    return StatusCode(423, "Account locked due to multiple failed attempts");
                }
                return Unauthorized("Invalid credentials");
            }

            // Reset failed attempts on successful password
            await _userManager.ResetAccessFailedCountAsync(user);

            // Risk-based authentication assessment
            var riskScore = await _riskEngine.EvaluateLoginRiskAsync(new RiskContext
            {
                UserId = user.Id,
                IpAddress = clientIp,
                UserAgent = Request.Headers["User-Agent"].ToString(),
                GeoLocation = await GetGeoLocationAsync(clientIp),
                DeviceFingerprint = request.DeviceFingerprint,
                LoginTime = DateTime.UtcNow
            });

            // Get available MFA methods for user
            var mfaMethods = await _mfaService.GetEnabledMethodsAsync(user.Id);

            // Determine required authentication level
            var requiredMfaLevel = DetermineRequiredMfaLevel(user, riskScore, mfaMethods);

            if (requiredMfaLevel == MfaLevel.None && riskScore < 0.3)
            {
                // Low risk, basic user - allow login but encourage MFA
                var token = await GenerateSecureTokenAsync(user, MfaLevel.None);
                await _auditService.LogAsync(AuditEvent.LoginSuccess, user.Id, clientIp);
                return Ok(new { Token = token, MfaRecommended = true });
            }

            // Create secure MFA challenge session
            var challengeSession = await _mfaService.CreateChallengeSessionAsync(
                user.Id, mfaMethods, requiredMfaLevel, TimeSpan.FromMinutes(5));

            await _auditService.LogAsync(AuditEvent.MfaChallengeIssued, 
                user.Id, clientIp, requiredMfaLevel.ToString());

            return Ok(new
            {
                RequiresMfa = true,
                ChallengeId = challengeSession.Id,
                AvailableMethods = mfaMethods.Select(m => new
                {
                    Type = m.Type.ToString(),
                    Hint = m.GetMaskedHint() // e.g., "***-***-1234" for SMS
                }),
                PreferredMethod = user.PreferredMfaMethod?.ToString(),
                ExpiresIn = 300
            });
