        [HttpPost("verify-totp")]
        public async Task<IActionResult> VerifyTotp([FromBody] TotpVerifyRequest request)
        {
            var challenge = await _mfaService.GetChallengeSessionAsync(request.ChallengeId);
            if (challenge == null || challenge.IsExpired)
            {
                return Unauthorized("Challenge expired. Please login again.");
            }

            var user = await _userManager.FindByIdAsync(challenge.UserId);
            var totpSecret = await _mfaService.GetTotpSecretAsync(user.Id);

            // TOTP verification with replay protection
            var totp = new Totp(Base32Encoding.ToBytes(totpSecret));
            long timeStepMatched;
            var isValid = totp.VerifyTotp(
                request.Code, 
                out timeStepMatched, 
                VerificationWindow.RfcSpecifiedNetworkDelay);

            if (!isValid)
            {
                await _mfaService.IncrementFailedAttemptsAsync(challenge.Id);
                await _auditService.LogAsync(AuditEvent.MfaFailed, 
                    user.Id, "TOTP", GetClientIp());

                if (await _mfaService.IsChallengeLocked(challenge.Id))
                {
                    return StatusCode(423, "Too many failed attempts");
                }
                return Unauthorized("Invalid code");
            }

            // Replay protection - ensure code wasn't already used
            if (await _mfaService.IsCodeReplayedAsync(user.Id, timeStepMatched))
            {
                await _auditService.LogAsync(AuditEvent.MfaReplayAttempt, user.Id);
                return Unauthorized("Code already used");
            }
            await _mfaService.RecordCodeUseAsync(user.Id, timeStepMatched);

            return await CompleteMfaVerificationAsync(user, challenge, MfaMethodType.Totp);
        }

        [HttpPost("verify-webauthn")]
        public async Task<IActionResult> VerifyWebAuthn([FromBody] WebAuthnVerifyRequest request)
        {
            var challenge = await _mfaService.GetChallengeSessionAsync(request.ChallengeId);
            if (challenge == null || challenge.IsExpired)
            {
                return Unauthorized("Challenge expired");
            }

            var user = await _userManager.FindByIdAsync(challenge.UserId);
            var credentials = await _mfaService.GetWebAuthnCredentialsAsync(user.Id);

            // Verify FIDO2/WebAuthn assertion
            var options = await _fido2.GetAssertionOptionsAsync(
                credentials.Select(c => c.Descriptor).ToList(),
                UserVerificationRequirement.Required);

            var result = await _fido2.MakeAssertionAsync(
                request.AuthenticatorResponse,
                options,
                credentials.First(c => c.Id.SequenceEqual(request.CredentialId)).PublicKey,
                credentials.First(c => c.Id.SequenceEqual(request.CredentialId)).SignatureCounter,
                async (args, ct) =>
                {
                    var cred = credentials.FirstOrDefault(c => c.Id.SequenceEqual(args.CredentialId));
                    return cred != null;
                });

            if (result.Status != "ok")
            {
                await _auditService.LogAsync(AuditEvent.MfaFailed, user.Id, "WebAuthn");
                return Unauthorized("Hardware key verification failed");
            }

            // Update signature counter for cloning detection
            await _mfaService.UpdateSignatureCounterAsync(
                user.Id, request.CredentialId, result.Counter);

            return await CompleteMfaVerificationAsync(user, challenge, MfaMethodType.WebAuthn);
        }

