                return availableMethods.Any(m => m.Type == MfaMethodType.WebAuthn)
                    ? MfaLevel.PhishingResistant
                    : MfaLevel.Required;
            }

            // Medium risk requires standard MFA
            if (riskScore > 0.4)
            {
                return MfaLevel.Required;
            }

            // User has MFA enabled - use it
            if (availableMethods.Any())
            {
                return MfaLevel.Optional;
            }

            return MfaLevel.None;
        }

        private string GenerateSecureSmsCode()
