import org.springframework.boot.actuate.health.Health;
import org.springframework.boot.actuate.health.HealthIndicator;
import org.springframework.stereotype.Component;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Counter;

import javax.net.ssl.*;
import java.security.cert.X509Certificate;
import java.util.Date;
import java.util.concurrent.TimeUnit;

@Component
public class TLSHealthIndicator implements HealthIndicator {

    private static final Logger logger = LoggerFactory.getLogger(TLSHealthIndicator.class);
    private final Counter tlsHandshakeFailures;
    private final Counter weakCipherAttempts;

    public TLSHealthIndicator(MeterRegistry registry) {
        this.tlsHandshakeFailures = Counter.builder("tls.handshake.failures")
            .description("Number of TLS handshake failures")
            .register(registry);
        this.weakCipherAttempts = Counter.builder("tls.weak.cipher.attempts")
            .description("Attempts to use weak cipher suites")
            .register(registry);
    }

    @Override
    public Health health() {
        try {
            // Check certificate expiration
            KeyStore keyStore = KeyStore.getInstance("PKCS12");
            // Load and check certificate expiration
            X509Certificate cert = (X509Certificate) keyStore.getCertificate("server");

            Date expirationDate = cert.getNotAfter();
            long daysUntilExpiry = TimeUnit.MILLISECONDS.toDays(
                expirationDate.getTime() - System.currentTimeMillis());

            if (daysUntilExpiry < 30) {
                logger.warn("Certificate expires in {} days", daysUntilExpiry);
                return Health.down()
                    .withDetail("certificate_expiry_days", daysUntilExpiry)
                    .withDetail("status", "Certificate expiring soon")
                    .build();
            }

            return Health.up()
                .withDetail("tls_version", "TLSv1.3,TLSv1.2")
                .withDetail("certificate_expiry_days", daysUntilExpiry)
                .withDetail("cipher_suites", "AEAD only")
                .build();

        } catch (Exception e) {
            logger.error("TLS health check failed", e);
            return Health.down(e).build();
        }
    }

    public void recordHandshakeFailure(String reason) {
        tlsHandshakeFailures.increment();
        logger.warn("TLS handshake failure: {}", reason);
    }

    public void recordWeakCipherAttempt(String clientIP, String requestedCipher) {
        weakCipherAttempts.increment();
        logger.warn("Weak cipher attempt from {}: {}", clientIP, requestedCipher);
    }
}
```

**Defense in Depth Layers**:

1. **JVM-Level Restrictions**: Disable weak algorithms at the JVM level using `jdk.tls.disabledAlgorithms`
```java
// In java.security or programmatically
Security.setProperty("jdk.tls.disabledAlgorithms", 
    "SSLv3, TLSv1, TLSv1.1, RC4, DES, MD5withRSA");
```

2. **Application-Level Configuration**: Explicit protocol and cipher configuration in Spring Boot
```yaml
server:
  ssl:
    enabled-protocols: TLSv1.3,TLSv1.2
    ciphers: TLS_AES_256_GCM_SHA384,TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384
```

3. **Runtime Validation**: Startup checks that fail fast if insecure configuration detected
```java
if (!disabledAlgorithms.contains("SSLv3")) {
    throw new SecurityException("Insecure TLS configuration");
}
```

**Additional Protections**:

- **HSTS Header**: Force browsers to use HTTPS with `Strict-Transport-Security: max-age=31536000; includeSubDomains; preload`
- **Certificate Pinning**: For mobile/desktop clients, pin specific certificates or public keys
- **OCSP Stapling**: Enable for faster certificate validation and privacy
- **Perfect Forward Secrecy**: Use only ECDHE key exchange to protect past sessions if private key compromised
- **Certificate Transparency**: Monitor CT logs for unauthorized certificate issuance
- **Automated Certificate Renewal**: Use ACME/Let's Encrypt with automatic renewal 30+ days before expiry

**PCI DSS 4.0 Compliance Checklist**:
- ✅ TLS 1.2 minimum (TLS 1.3 preferred)
- ✅ Strong cipher suites only (no RC4, 3DES, CBC without AEAD)
- ✅ 2048-bit minimum RSA keys / 256-bit minimum ECC keys
- ✅ Certificate validation enabled
- ✅ Proper key management (encrypted storage, rotation)

Being logged in is NOT enough - you need to verify the user owns the specific resource they're requesting. This is a classic forced browsing vulnerability where attackers can access other users' data by guessing or enumerating resource IDs.

**VULNERABLE CODE**:

```csharp
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System.Threading.Tasks;

namespace InvoiceApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize] // User must be logged in - but this is NOT enough!
    public class InvoicesController : ControllerBase
    {
        private readonly AppDbContext _context;

        public InvoicesController(AppDbContext context)
        {
            _context = context;
        }

        // VULNERABLE: Only checks if user is authenticated, not authorized
        [HttpGet("{id}")]
        public async Task<IActionResult> GetInvoice(int id)
        {
            // Fetches ANY invoice by ID - no ownership check!
            var invoice = await _context.Invoices
                .FirstOrDefaultAsync(i => i.Id == id);

            if (invoice == null)
                return NotFound();

            return Ok(invoice);
        }

        // VULNERABLE: User can download any document by guessing IDs
        [HttpGet("{id}/download")]
        public async Task<IActionResult> DownloadInvoice(int id)
        {
            var invoice = await _context.Invoices.FindAsync(id);

            if (invoice == null)
                return NotFound();

            var filePath = $"/invoices/{invoice.FileName}";
            return PhysicalFile(filePath, "application/pdf");
        }
    }
}
```

**Attack Payload**:
```bash
# Attacker enumerates invoice IDs to access other users' data
for i in {1..10000}; do
  curl -H "Authorization: Bearer $ATTACKER_TOKEN" \
       https://api.example.com/api/invoices/$i \
       -o invoice_$i.json
done

# Automated script to find valid invoices
curl -s https://api.example.com/api/invoices/12345 -H "Authorization: Bearer $TOKEN" | jq '.customerName, .amount, .bankAccount'
```

**Why This Is Dangerous**:
- Any authenticated user can access ANY invoice by changing the ID in the URL
- Sequential/predictable IDs make enumeration trivial
- Attackers can harvest all customer financial data, PII, and payment information
- This exact pattern caused the First American breach exposing 885 million records

**SECURE VERSION**:

```csharp
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System.Security.Claims;
using System.Threading.Tasks;
using Microsoft.Extensions.Logging;

namespace InvoiceApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize]
    public class InvoicesController : ControllerBase
    {
        private readonly AppDbContext _context;
        private readonly ILogger<InvoicesController> _logger;

        public InvoicesController(AppDbContext context, ILogger<InvoicesController> logger)
        {
            _context = context;
            _logger = logger;
        }

        // SECURE: Verifies ownership before returning data
        [HttpGet("{id}")]
        public async Task<IActionResult> GetInvoice(int id)
        {
            // Extract the authenticated user's ID
            var userId = User.FindFirstValue(ClaimTypes.NameIdentifier);

            if (string.IsNullOrEmpty(userId))
            {
                _logger.LogWarning("Invoice access attempt without valid user ID");
                return Unauthorized();
            }

            // CRITICAL: Filter by BOTH invoice ID AND owner ID
            var invoice = await _context.Invoices
                .FirstOrDefaultAsync(i => i.Id == id && i.UserId == userId);

            if (invoice == null)
            {
                // Log potential forced browsing attempt
                _logger.LogWarning(
                    "User {UserId} attempted to access invoice {InvoiceId} - not found or not owned",
                    userId, id);

                // Return 404, not 403, to prevent information leakage
                return NotFound();
            }

            _logger.LogInformation(
                "User {UserId} accessed invoice {InvoiceId}",
                userId, id);

            return Ok(invoice);
        }

        // SECURE: Get only current user's invoices
        [HttpGet]
        public async Task<IActionResult> GetMyInvoices()
        {
            var userId = User.FindFirstValue(ClaimTypes.NameIdentifier);

            var invoices = await _context.Invoices
                .Where(i => i.UserId == userId)
                .ToListAsync();

            return Ok(invoices);
        }
    }
}
```

**Key Security Controls**:
- **Ownership verification**: Every request validates that the authenticated user owns the requested resource
- **Consistent 404 response**: Returns NotFound() whether the resource doesn't exist or isn't owned by the user (prevents enumeration)
- **Audit logging**: All access attempts are logged for security monitoring and incident response

Great questions! You need a robust authorization policy system that handles role-based access, resource ownership, and shared access scenarios. Here's a production-ready implementation using ASP.NET Core's policy-based authorization.

**PRODUCTION PATTERN**:

```csharp
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.EntityFrameworkCore;
using System.Security.Claims;
using System.Threading.Tasks;
using Microsoft.Extensions.Logging;
using System;
using System.Linq;

namespace InvoiceApp.Authorization
{
    // Custom authorization requirement for resource ownership
    public class ResourceOwnerRequirement : IAuthorizationRequirement
    {
        public bool AllowSharedAccess { get; }
        public bool AllowAdminAccess { get; }

        public ResourceOwnerRequirement(bool allowSharedAccess = true, bool allowAdminAccess = true)
        {
            AllowSharedAccess = allowSharedAccess;
            AllowAdminAccess = allowAdminAccess;
        }
    }

    // Authorization handler that checks ownership, sharing, and admin roles
    public class InvoiceAuthorizationHandler : AuthorizationHandler<ResourceOwnerRequirement, Invoice>
    {
        private readonly ILogger<InvoiceAuthorizationHandler> _logger;
        private readonly AppDbContext _context;

        public InvoiceAuthorizationHandler(
            ILogger<InvoiceAuthorizationHandler> logger,
            AppDbContext context)
        {
            _logger = logger;
            _context = context;
        }

        protected override async Task HandleRequirementAsync(
            AuthorizationHandlerContext context,
            ResourceOwnerRequirement requirement,
            Invoice resource)
        {
            var userId = context.User.FindFirstValue(ClaimTypes.NameIdentifier);
            var userEmail = context.User.FindFirstValue(ClaimTypes.Email);
            var clientIp = context.User.FindFirstValue("client_ip");

            // Check 1: Is user the owner?
            if (resource.UserId == userId)
            {
                _logger.LogDebug(
                    "Owner access granted: User {UserId} to Invoice {InvoiceId}",
                    userId, resource.Id);
                context.Succeed(requirement);
                return;
            }

            // Check 2: Is user an admin with appropriate permissions?
            if (requirement.AllowAdminAccess && 
                context.User.IsInRole("Admin"))
            {
                // Additional check: Admin must have invoice management permission
                if (context.User.HasClaim("permission", "invoices:read:all"))
                {
                    _logger.LogInformation(
                        "ADMIN ACCESS: Admin {UserId} accessed Invoice {InvoiceId} owned by {OwnerId}. IP: {ClientIp}",
                        userId, resource.Id, resource.UserId, clientIp);
                    context.Succeed(requirement);
                    return;
                }
            }

            // Check 3: Is user in a shared access list?
            if (requirement.AllowSharedAccess)
            {
                var hasSharedAccess = await _context.InvoiceShares
                    .AnyAsync(s => 
                        s.InvoiceId == resource.Id && 
                        s.SharedWithUserId == userId &&
                        s.ExpiresAt > DateTime.UtcNow &&
                        s.IsActive);

                if (hasSharedAccess)
                {
                    _logger.LogInformation(
                        "SHARED ACCESS: User {UserId} accessed Invoice {InvoiceId} via share. IP: {ClientIp}",
                        userId, resource.Id, clientIp);
                    context.Succeed(requirement);
                    return;
                }
            }

            // Access denied - log the attempt
            _logger.LogWarning(
                "ACCESS DENIED: User {UserId} ({Email}) attempted to access Invoice {InvoiceId} owned by {OwnerId}. IP: {ClientIp}",
                userId, userEmail, resource.Id, resource.UserId, clientIp);

            // Don't call context.Fail() - let other handlers run
            // The context will fail automatically if no handler succeeds
        }
    }
}

namespace InvoiceApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize]
    public class InvoicesController : ControllerBase
    {
        private readonly AppDbContext _context;
        private readonly IAuthorizationService _authService;
        private readonly ILogger<InvoicesController> _logger;

        public InvoicesController(
            AppDbContext context,
            IAuthorizationService authService,
            ILogger<InvoicesController> logger)
        {
            _context = context;
            _authService = authService;
            _logger = logger;
        }

        [HttpGet("{id}")]
        public async Task<IActionResult> GetInvoice(Guid id)  // Use GUIDs, not sequential IDs
        {
            // First, fetch the resource
            var invoice = await _context.Invoices
                .AsNoTracking()
                .FirstOrDefaultAsync(i => i.Id == id);

            if (invoice == null)
            {
                return NotFound();
            }

            // Then, check authorization using policy
            var authResult = await _authService.AuthorizeAsync(
                User,
                invoice,
                new ResourceOwnerRequirement());

            if (!authResult.Succeeded)
            {
                // Return 404 to prevent information disclosure
                // (Don't reveal that the resource exists but user can't access it)
                return NotFound();
            }

            return Ok(invoice);
        }

        // Admin-only endpoint with explicit policy
        [HttpGet("admin/all")]
        [Authorize(Roles = "Admin")]
        [Authorize(Policy = "RequireInvoiceManagement")]
        public async Task<IActionResult> GetAllInvoices(
            [FromQuery] int page = 1,
            [FromQuery] int pageSize = 50)
        {
            // Rate limit and cap page size
            pageSize = Math.Min(pageSize, 100);

            var userId = User.FindFirstValue(ClaimTypes.NameIdentifier);

            _logger.LogInformation(
                "ADMIN AUDIT: Admin {UserId} requested all invoices (page {Page}, size {Size})",
                userId, page, pageSize);

            var invoices = await _context.Invoices
                .AsNoTracking()
                .OrderByDescending(i => i.CreatedAt)
                .Skip((page - 1) * pageSize)
                .Take(pageSize)
                .Select(i => new InvoiceListDto
                {
                    Id = i.Id,
                    // Don't include sensitive fields in list view
                    CustomerName = i.CustomerName,
                    Amount = i.Amount,
                    CreatedAt = i.CreatedAt
                })
                .ToListAsync();

            return Ok(invoices);
        }

        // Share an invoice with another user
        [HttpPost("{id}/share")]
        public async Task<IActionResult> ShareInvoice(Guid id, [FromBody] ShareRequest request)
        {
            var invoice = await _context.Invoices.FindAsync(id);

            if (invoice == null)
                return NotFound();

            var userId = User.FindFirstValue(ClaimTypes.NameIdentifier);

            // Only owner can share (not shared users)
            if (invoice.UserId != userId)
            {
                return NotFound();  // Don't reveal existence
            }

            // Validate the target user exists
            var targetUser = await _context.Users.FindAsync(request.ShareWithUserId);
            if (targetUser == null)
            {
                return BadRequest("User not found");
            }

            var share = new InvoiceShare
            {
                Id = Guid.NewGuid(),
                InvoiceId = id,
                SharedByUserId = userId,
                SharedWithUserId = request.ShareWithUserId,
                CreatedAt = DateTime.UtcNow,
                ExpiresAt = DateTime.UtcNow.AddDays(request.ExpiresInDays ?? 30),
                IsActive = true
            };

            _context.InvoiceShares.Add(share);
            await _context.SaveChangesAsync();

            _logger.LogInformation(
                "Invoice {InvoiceId} shared by {OwnerId} with {TargetUserId}, expires {ExpiresAt}",
                id, userId, request.ShareWithUserId, share.ExpiresAt);

            return Ok(new { share.Id, share.ExpiresAt });
        }
    }
}

// Startup/Program.cs configuration
namespace InvoiceApp
{
    public static class AuthorizationConfig
    {
        public static void ConfigureAuthorization(IServiceCollection services)
        {
            services.AddScoped<IAuthorizationHandler, InvoiceAuthorizationHandler>();

            services.AddAuthorization(options =>
            {
                options.AddPolicy("RequireInvoiceManagement", policy =>
                    policy.RequireClaim("permission", "invoices:read:all"));

                options.AddPolicy("RequireInvoiceOwnership", policy =>
                    policy.Requirements.Add(new ResourceOwnerRequirement(
                        allowSharedAccess: false,
                        allowAdminAccess: false)));
            });
        }
    }
}
```

**Defense in Depth Layers**:

1. **Use non-enumerable identifiers (GUIDs)**:
```csharp
// Instead of sequential IDs that can be guessed
public class Invoice
{
    public Guid Id { get; set; } = Guid.NewGuid();  // Not int Id
    public string UserId { get; set; }
    // ...
}
```

2. **Centralized authorization service**:
```csharp
// Reusable authorization check across all controllers
public interface IResourceAuthorizationService
{
    Task<bool> CanAccessAsync<T>(ClaimsPrincipal user, T resource) where T : IOwnedResource;
}

public class ResourceAuthorizationService : IResourceAuthorizationService
{
    public async Task<bool> CanAccessAsync<T>(ClaimsPrincipal user, T resource) 
        where T : IOwnedResource
    {
        var userId = user.FindFirstValue(ClaimTypes.NameIdentifier);
        return resource.OwnerId == userId || user.IsInRole("Admin");
    }
}
```

3. **Rate limiting to prevent enumeration**:
```csharp
// In Program.cs
builder.Services.AddRateLimiter(options =>
{
    options.AddFixedWindowLimiter("resource-access", limiter =>
    {
        limiter.PermitLimit = 100;  // 100 requests
        limiter.Window = TimeSpan.FromMinutes(1);
        limiter.QueueLimit = 0;
    });
});

// In controller
[EnableRateLimiting("resource-access")]
[HttpGet("{id}")]
public async Task<IActionResult> GetInvoice(Guid id) { }
```

**Additional Protections**:
- **Anomaly detection**: Monitor for users accessing resources at abnormal rates or patterns
- **Consistent response times**: Prevent timing attacks that reveal resource existence
- **Access expiration**: Shared access automatically expires and must be renewed
- **Audit trail**: Every access (granted or denied) is logged with user ID, resource ID, and IP
- **Principle of least privilege**: Admins need explicit permissions, not just role membership

Great question! A common mistake is only checking authorization on certain HTTP methods, leaving your API vulnerable to HTTP verb tampering attacks. Let me show you the problem and the secure solution.

**VULNERABLE CODE**:

```python
from flask import Flask, request, jsonify, session
from functools import wraps

app = Flask(__name__)
app.secret_key = 'super-secret-key'

def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # VULNERABLE: Only checks authorization on POST requests
        if request.method == 'POST':
            if not session.get('is_admin'):
                return jsonify({'error': 'Admin access required'}), 403
        return f(*args, **kwargs)
    return decorated_function

@app.route('/api/users/<int:user_id>', methods=['GET', 'POST', 'DELETE'])
@admin_required
def manage_user(user_id):
    if request.method == 'DELETE':
        # Delete user from database
        delete_user(user_id)
        return jsonify({'message': f'User {user_id} deleted'})
    elif request.method == 'GET':
        return jsonify({'user_id': user_id, 'name': 'John Doe'})
    elif request.method == 'POST':
        # Update user
        return jsonify({'message': 'User updated'})

def delete_user(user_id):
    # Database deletion logic
    pass
```

**Attack Payload**:
```bash
# Bypass admin check using DELETE method directly
curl -X DELETE http://localhost:5000/api/users/1 \
  -H "Cookie: session=non_admin_session_token"

# The admin_required decorator only checks POST, so DELETE bypasses authorization
```

**Why This Is Dangerous**:
- The decorator only validates admin status for POST requests
- DELETE requests completely bypass the authorization check
- Attackers can delete any user without admin privileges
- This pattern was exploited in CVE-2023-41080 affecting Tomcat's security constraints

**SECURE VERSION**:

```python
from flask import Flask, request, jsonify, session, abort
from functools import wraps
import logging

app = Flask(__name__)
app.secret_key = 'super-secret-key'
logging.basicConfig(level=logging.INFO)

def admin_required(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        # SECURE: Check authorization for ALL request methods
        if not session.get('is_admin'):
            app.logger.warning(
                f"Unauthorized admin access attempt: user={session.get('user_id')}, "
                f"method={request.method}, path={request.path}, ip={request.remote_addr}"
            )
            abort(403, description='Admin access required')
        return f(*args, **kwargs)
    return decorated_function

@app.route('/api/users/<int:user_id>', methods=['GET', 'POST', 'DELETE'])
@admin_required
def manage_user(user_id):
    # Authorization is now enforced for ALL methods
    if request.method == 'DELETE':
        delete_user(user_id)
        app.logger.info(f"User {user_id} deleted by admin {session.get('user_id')}")
        return jsonify({'message': f'User {user_id} deleted'})
    elif request.method == 'GET':
        return jsonify({'user_id': user_id, 'name': 'John Doe'})
    elif request.method == 'POST':
        return jsonify({'message': 'User updated'})

def delete_user(user_id):
    # Database deletion logic
    pass
```

**Key Security Controls**:
- **Method-agnostic authorization**: The decorator checks authorization regardless of HTTP method, preventing verb tampering
- **Audit logging**: Failed authorization attempts are logged with user ID, method, path, and IP address for security monitoring
- **Fail-secure design**: Uses abort() to immediately terminate request processing on unauthorized access

Serving user files is extremely dangerous without proper path validation. The 2024 Fortinet FortiOS vulnerability (CVE-2024-21762) allowed attackers to read arbitrary files from 150,000+ firewalls using path traversal, demonstrating how devastating this flaw can be.

**VULNERABLE CODE**:

```go
package main

import (
	"io"
	"net/http"
	"os"
	"path/filepath"
)

const uploadDir = "/var/app/uploads"

func downloadHandler(w http.ResponseWriter, r *http.Request) {
	// DANGEROUS: Directly using user input in file path
	filename := r.URL.Query().Get("file")
	if filename == "" {
		http.Error(w, "Missing file parameter", http.StatusBadRequest)
		return
	}

	// VULNERABLE: Path traversal possible!
	filePath := filepath.Join(uploadDir, filename)

	file, err := os.Open(filePath)
	if err != nil {
		http.Error(w, "File not found", http.StatusNotFound)
		return
	}
	defer file.Close()

	w.Header().Set("Content-Type", "application/octet-stream")
	io.Copy(w, file)
}

func main() {
	http.HandleFunc("/download", downloadHandler)
	http.ListenAndServe(":8080", nil)
}
```

**Attack Payload**:
```text
GET /download?file=../../../etc/passwd HTTP/1.1
GET /download?file=....//....//....//etc/shadow HTTP/1.1
GET /download?file=%2e%2e%2f%2e%2e%2f%2e%2e%2fetc%2fpasswd HTTP/1.1
```

**Why This Is Dangerous**:
- `filepath.Join` does NOT prevent path traversal - it simply concatenates paths
- Attackers can use `../` sequences to escape the upload directory
- URL encoding (`%2e%2e%2f`) can bypass naive string checks
- Exposes sensitive system files like `/etc/passwd`, `/etc/shadow`, application configs
- Can lead to credential theft, configuration exposure, and full system compromise

**SECURE VERSION**:

```go
package main

import (
	"io"
	"log"
	"net/http"
	"os"
	"path/filepath"
	"strings"
)

const uploadDir = "/var/app/uploads"

func secureDownloadHandler(w http.ResponseWriter, r *http.Request) {
	filename := r.URL.Query().Get("file")
	if filename == "" {
		http.Error(w, "Missing file parameter", http.StatusBadRequest)
		return
	}

	// SECURITY: Clean the filename to remove path traversal sequences
	cleanFilename := filepath.Clean(filename)

	// SECURITY: Reject any path with directory components
	if strings.ContainsAny(cleanFilename, "/\\") || cleanFilename == ".." {
		log.Printf("SECURITY: Path traversal attempt blocked: %s from %s", 
			filename, r.RemoteAddr)
		http.Error(w, "Invalid filename", http.StatusBadRequest)
		return
	}

	// SECURITY: Use only the base filename
	baseFilename := filepath.Base(cleanFilename)

	// SECURITY: Construct full path and verify it's within allowed directory
	fullPath := filepath.Join(uploadDir, baseFilename)
	absPath, err := filepath.Abs(fullPath)
	if err != nil {
		http.Error(w, "Invalid path", http.StatusBadRequest)
		return
	}

	absUploadDir, _ := filepath.Abs(uploadDir)

	// CRITICAL: Verify the resolved path is within the upload directory
	if !strings.HasPrefix(absPath, absUploadDir+string(os.PathSeparator)) {
		log.Printf("SECURITY: Path escape attempt blocked: %s -> %s from %s", 
			filename, absPath, r.RemoteAddr)
		http.Error(w, "Access denied", http.StatusForbidden)
		return
	}

	file, err := os.Open(absPath)
	if err != nil {
		http.Error(w, "File not found", http.StatusNotFound)
		return
	}
	defer file.Close()

	// SECURITY: Verify it's a regular file, not a symlink or directory
	fileInfo, err := file.Stat()
	if err != nil || !fileInfo.Mode().IsRegular() {
		http.Error(w, "Invalid file", http.StatusBadRequest)
		return
	}

	w.Header().Set("Content-Type", "application/octet-stream")
	w.Header().Set("Content-Disposition", "attachment; filename=\""+baseFilename+"\"")
	io.Copy(w, file)
}

func main() {
	http.HandleFunc("/download", secureDownloadHandler)
	http.ListenAndServe(":8080", nil)
}
```

**Key Security Controls**:
- **filepath.Clean()**: Normalizes the path, removing `.` and `..` sequences
- **filepath.Base()**: Extracts only the filename, stripping all directory components
- **Absolute path verification**: Ensures the final resolved path is within the allowed directory using `strings.HasPrefix`
- **Regular file check**: Prevents serving directories or following symlinks
- **Security logging**: Records attack attempts for monitoring and forensics

Supporting subdirectories adds complexity because you need to allow legitimate directory traversal while blocking malicious attempts. This requires a robust authorization model that verifies both path safety AND user permissions.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/rand"
	"database/sql"
	"encoding/hex"
	"fmt"
	"io"
	"log"
	"net/http"
	"os"
	"path/filepath"
	"strings"
	"time"

	_ "github.com/lib/pq"
)

type FileService struct {
	baseDir    string
	db         *sql.DB
	allowedExt map[string]bool
}

type FileAccess struct {
	UserID     string
	FilePath   string
	AccessTime time.Time
	IPAddress  string
	Action     string
	Success    bool
	Reason     string
}

func NewFileService(baseDir string, db *sql.DB) *FileService {
	return &FileService{
		baseDir: baseDir,
		db:      db,
		allowedExt: map[string]bool{
			".pdf": true, ".txt": true, ".doc": true, 
			".docx": true, ".png": true, ".jpg": true,
		},
	}
}

// ValidatePath performs comprehensive path validation
func (fs *FileService) ValidatePath(requestedPath string) (string, error) {
	// Step 1: Clean the path to normalize separators and remove . and ..
	cleanPath := filepath.Clean(requestedPath)

	// Step 2: Reject null bytes (can truncate strings in some contexts)
	if strings.ContainsRune(cleanPath, '\x00') {
		return "", fmt.Errorf("invalid character in path")
	}

	// Step 3: Reject absolute paths and paths starting with ..
	if filepath.IsAbs(cleanPath) || strings.HasPrefix(cleanPath, "..") {
		return "", fmt.Errorf("absolute or parent paths not allowed")
	}

	// Step 4: Build full path and resolve any remaining symlinks
	fullPath := filepath.Join(fs.baseDir, cleanPath)

	// Step 5: Resolve to absolute path (follows symlinks)
	resolvedPath, err := filepath.EvalSymlinks(fullPath)
	if err != nil {
		// File might not exist yet, use Abs for new files
		resolvedPath, err = filepath.Abs(fullPath)
		if err != nil {
			return "", fmt.Errorf("invalid path resolution")
		}
	}

	// Step 6: Resolve base directory to compare
	resolvedBase, err := filepath.EvalSymlinks(fs.baseDir)
	if err != nil {
		resolvedBase, _ = filepath.Abs(fs.baseDir)
	}

	// Step 7: CRITICAL - Verify resolved path is within base directory
	if !strings.HasPrefix(resolvedPath, resolvedBase+string(os.PathSeparator)) &&
		resolvedPath != resolvedBase {
		return "", fmt.Errorf("path traversal detected")
	}

	// Step 8: Validate file extension
	ext := strings.ToLower(filepath.Ext(resolvedPath))
	if ext != "" && !fs.allowedExt[ext] {
		return "", fmt.Errorf("file type not allowed: %s", ext)
	}

	return resolvedPath, nil
}

// CheckUserAuthorization verifies user has permission to access the file
func (fs *FileService) CheckUserAuthorization(ctx context.Context, userID, filePath string) (bool, error) {
	// Extract user directory from path
	relPath, err := filepath.Rel(fs.baseDir, filePath)
	if err != nil {
		return false, err
	}

	parts := strings.Split(relPath, string(os.PathSeparator))
	if len(parts) < 1 {
		return false, fmt.Errorf("invalid path structure")
	}

	// First directory should be user's ID or they need explicit permission
	pathOwner := parts[0]

	// Check if user owns this path
	if pathOwner == userID {
		return true, nil
	}

	// Check for explicit sharing permission in database
	var permitted bool
	err = fs.db.QueryRowContext(ctx,
		`SELECT EXISTS(
			SELECT 1 FROM file_permissions 
			WHERE file_owner = $1 
			AND granted_to = $2 
			AND file_path = $3
			AND expires_at > NOW()
		)`,
		pathOwner, userID, relPath,
	).Scan(&permitted)

	return permitted, err
}

// AuditLog records file access attempts
func (fs *FileService) AuditLog(ctx context.Context, access FileAccess) {
	_, err := fs.db.ExecContext(ctx,
		`INSERT INTO file_access_log 
		(user_id, file_path, access_time, ip_address, action, success, reason)
		VALUES ($1, $2, $3, $4, $5, $6, $7)`,
		access.UserID, access.FilePath, access.AccessTime,
		access.IPAddress, access.Action, access.Success, access.Reason,
	)
	if err != nil {
		log.Printf("ERROR: Failed to write audit log: %v", err)
	}
}

// GenerateSecureToken creates a time-limited download token
func (fs *FileService) GenerateSecureToken(ctx context.Context, userID, filePath string) (string, error) {
	tokenBytes := make([]byte, 32)
	if _, err := rand.Read(tokenBytes); err != nil {
		return "", err
	}
	token := hex.EncodeToString(tokenBytes)

	_, err := fs.db.ExecContext(ctx,
		`INSERT INTO download_tokens (token, user_id, file_path, expires_at)
		VALUES ($1, $2, $3, $4)`,
		token, userID, filePath, time.Now().Add(5*time.Minute),
	)
	return token, err
}

// SecureFileHandler handles file downloads with full security
func (fs *FileService) SecureFileHandler(w http.ResponseWriter, r *http.Request) {
	ctx := r.Context()

	// Get authenticated user from context (set by auth middleware)
	userID, ok := ctx.Value("user_id").(string)
	if !ok || userID == "" {
		http.Error(w, "Unauthorized", http.StatusUnauthorized)
		return
	}

	requestedPath := r.URL.Query().Get("path")
	if requestedPath == "" {
		http.Error(w, "Missing path parameter", http.StatusBadRequest)
		return
	}

	// Initialize audit record
	audit := FileAccess{
		UserID:     userID,
		FilePath:   requestedPath,
		AccessTime: time.Now(),
		IPAddress:  r.RemoteAddr,
		Action:     "DOWNLOAD",
	}

	// Validate path security
	validatedPath, err := fs.ValidatePath(requestedPath)
	if err != nil {
		audit.Success = false
		audit.Reason = fmt.Sprintf("Path validation failed: %v", err)
		fs.AuditLog(ctx, audit)
		log.Printf("SECURITY ALERT: Path traversal attempt by user %s: %s -> %v", 
			userID, requestedPath, err)
		http.Error(w, "Invalid path", http.StatusBadRequest)
		return
	}

	// Check user authorization
	authorized, err := fs.CheckUserAuthorization(ctx, userID, validatedPath)
	if err != nil || !authorized {
		audit.Success = false
		audit.Reason = "Authorization denied"
		fs.AuditLog(ctx, audit)
		log.Printf("SECURITY: Unauthorized file access attempt by user %s: %s", 
			userID, validatedPath)
		http.Error(w, "Access denied", http.StatusForbidden)
		return
	}

	// Open and verify file
	file, err := os.Open(validatedPath)
	if err != nil {
		audit.Success = false
		audit.Reason = "File not found"
		fs.AuditLog(ctx, audit)
		http.Error(w, "File not found", http.StatusNotFound)
		return
	}
	defer file.Close()

	// Verify it's a regular file
	fileInfo, err := file.Stat()
	if err != nil || !fileInfo.Mode().IsRegular() {
		audit.Success = false
		audit.Reason = "Invalid file type"
		fs.AuditLog(ctx, audit)
		http.Error(w, "Invalid file", http.StatusBadRequest)
		return
	}

	// Record successful access
	audit.Success = true
	audit.Reason = "OK"
	fs.AuditLog(ctx, audit)

	// Set secure headers
	filename := filepath.Base(validatedPath)
	w.Header().Set("Content-Type", "application/octet-stream")
	w.Header().Set("Content-Disposition", 
		fmt.Sprintf("attachment; filename=%q", filename))
	w.Header().Set("Content-Length", fmt.Sprintf("%d", fileInfo.Size()))
	w.Header().Set("X-Content-Type-Options", "nosniff")
	w.Header().Set("Cache-Control", "no-store")

	io.Copy(w, file)
}

func main() {
	db, err := sql.Open("postgres", os.Getenv("DATABASE_URL"))
	if err != nil {
		log.Fatal(err)
	}
	defer db.Close()

	fs := NewFileService("/var/app/uploads", db)

	http.HandleFunc("/api/files/download", fs.SecureFileHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

**Defense in Depth Layers**:

1. **Path Normalization & Validation**:
