type FileAccess struct {
	UserID, FilePath, IPAddress, Action, Reason string
	AccessTime time.Time
	Success bool
}
```

**Additional Protections**:
- **Symlink resolution**: `filepath.EvalSymlinks` prevents symlink attacks where attackers create symlinks pointing outside the allowed directory
- **File type validation**: Extension allowlist prevents serving executable files
- **Time-limited tokens**: For sensitive downloads, generate one-time tokens that expire in minutes
- **Regular file verification**: `fileInfo.Mode().IsRegular()` ensures we're serving a file, not a directory or device
- **Security headers**: `X-Content-Type-Options: nosniff` prevents MIME-type sniffing attacks
- **Null byte rejection**: Prevents attacks that use null bytes to truncate paths in some implementations
- **Rate limiting**: Not shown, but should limit download requests per user to prevent enumeration attacks

Your login form may be vulnerable to Cross-Site Request Forgery (CSRF) attacks if it doesn't include proper CSRF protection. CSRF allows attackers to trick authenticated users into submitting malicious requests, potentially enabling account takeover through password changes or email updates.

**VULNERABLE CODE**:

```php
<?php
// login.php - VULNERABLE: No CSRF protection
session_start();

class AuthController {
    private $pdo;

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    public function login() {
        // No CSRF token validation!
        $username = $_POST['username'] ?? '';
        $password = $_POST['password'] ?? '';

        $stmt = $this->pdo->prepare("SELECT id, password_hash FROM users WHERE username = ?");
        $stmt->execute([$username]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        if ($user && password_verify($password, $user['password_hash'])) {
            $_SESSION['user_id'] = $user['id'];
            $_SESSION['logged_in'] = true;
            header('Location: /dashboard');
            exit;
        }

        return "Invalid credentials";
    }

    public function changePassword() {
        // CRITICAL: No CSRF protection on password change!
        if (!isset($_SESSION['user_id'])) {
            header('Location: /login');
            exit;
        }

        $newPassword = $_POST['new_password'] ?? '';
        $hashedPassword = password_hash($newPassword, PASSWORD_DEFAULT);

        $stmt = $this->pdo->prepare("UPDATE users SET password_hash = ? WHERE id = ?");
        $stmt->execute([$hashedPassword, $_SESSION['user_id']]);

        return "Password changed successfully";
    }
}
?>
```

**Attack Payload** (malicious HTML hosted on attacker's site):
```html
<!-- attacker-site.com/steal-password.html -->
<html>
<body onload="document.getElementById('csrfForm').submit();">
  <h1>Loading...</h1>
  <form id="csrfForm" action="https://victim-site.com/change-password.php" method="POST">
    <input type="hidden" name="new_password" value="attacker123" />
  </form>
</body>
</html>
```

**Why This Is Dangerous**:
- Attacker can change victim's password without their knowledge by tricking them into visiting a malicious page
- Login forms without CSRF tokens can be targeted in login CSRF attacks (forcing victim to authenticate as attacker)
- Session fixation combined with CSRF allows complete account takeover
- Email change forms are particularly dangerous as they enable password reset attacks

**SECURE VERSION**:

```php
<?php
// secure_auth.php - CSRF Protected Authentication
session_start();

class CSRFProtection {
    public static function generateToken(): string {
        if (empty($_SESSION['csrf_token'])) {
            $_SESSION['csrf_token'] = bin2hex(random_bytes(32));
            $_SESSION['csrf_token_time'] = time();
        }
        return $_SESSION['csrf_token'];
    }

    public static function validateToken(string $token): bool {
        if (empty($_SESSION['csrf_token']) || empty($token)) {
            return false;
        }

        // Token expiration (15 minutes)
        $tokenAge = time() - ($_SESSION['csrf_token_time'] ?? 0);
        if ($tokenAge > 900) {
            self::regenerateToken();
            return false;
        }

        return hash_equals($_SESSION['csrf_token'], $token);
    }

    public static function regenerateToken(): string {
        $_SESSION['csrf_token'] = bin2hex(random_bytes(32));
        $_SESSION['csrf_token_time'] = time();
        return $_SESSION['csrf_token'];
    }
}

class SecureAuthController {
    private $pdo;

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    public function login(): string {
        // Validate CSRF token on ALL POST requests
        $csrfToken = $_POST['csrf_token'] ?? '';
        if (!CSRFProtection::validateToken($csrfToken)) {
            error_log("CSRF validation failed from IP: " . $_SERVER['REMOTE_ADDR']);
            http_response_code(403);
            return "Invalid request. Please refresh and try again.";
        }

        $username = trim($_POST['username'] ?? '');
        $password = $_POST['password'] ?? '';

        // Input validation
        if (empty($username) || empty($password)) {
            return "Username and password are required.";
        }

        $stmt = $this->pdo->prepare("SELECT id, password_hash FROM users WHERE username = ?");
        $stmt->execute([$username]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        if ($user && password_verify($password, $user['password_hash'])) {
            // Regenerate session ID on login (prevent session fixation)
            session_regenerate_id(true);

            // Regenerate CSRF token after login
            CSRFProtection::regenerateToken();

            $_SESSION['user_id'] = $user['id'];
            $_SESSION['logged_in'] = true;
            $_SESSION['login_time'] = time();

            error_log("Successful login for user: " . $username);
            header('Location: /dashboard');
            exit;
        }

        error_log("Failed login attempt for user: " . $username . " from IP: " . $_SERVER['REMOTE_ADDR']);
        return "Invalid credentials";
    }

    public function changePassword(): string {
        // Verify user is authenticated
        if (!isset($_SESSION['user_id'])) {
            header('Location: /login');
            exit;
        }

        // CSRF validation for password change
        $csrfToken = $_POST['csrf_token'] ?? '';
        if (!CSRFProtection::validateToken($csrfToken)) {
            error_log("CSRF attack blocked on password change for user: " . $_SESSION['user_id']);
            http_response_code(403);
            return "Invalid request. Please refresh and try again.";
        }

        // Require current password for sensitive operations
        $currentPassword = $_POST['current_password'] ?? '';
        $newPassword = $_POST['new_password'] ?? '';

        // Verify current password
        $stmt = $this->pdo->prepare("SELECT password_hash FROM users WHERE id = ?");
        $stmt->execute([$_SESSION['user_id']]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        if (!$user || !password_verify($currentPassword, $user['password_hash'])) {
            return "Current password is incorrect.";
        }

        // Password strength validation
        if (strlen($newPassword) < 12) {
            return "Password must be at least 12 characters.";
        }

        $hashedPassword = password_hash($newPassword, PASSWORD_ARGON2ID);
        $stmt = $this->pdo->prepare("UPDATE users SET password_hash = ? WHERE id = ?");
        $stmt->execute([$hashedPassword, $_SESSION['user_id']]);

        // Regenerate CSRF token after sensitive action
        CSRFProtection::regenerateToken();

        error_log("Password changed for user: " . $_SESSION['user_id']);
        return "Password changed successfully";
    }
}
?>
```

**Key Security Controls**:
- **CSRF Token Validation**: Every state-changing request must include a valid CSRF token generated per-session
- **Token Timing Protection**: Using `hash_equals()` prevents timing attacks on token comparison
- **Session Regeneration**: Regenerating session ID on login prevents session fixation attacks
- **Re-authentication**: Requiring current password for sensitive operations provides additional protection

AJAX authentication endpoints require additional CSRF protection strategies since traditional hidden form fields don't work the same way. You need to use a combination of custom headers, double-submit cookies, and SameSite cookie attributes.

**PRODUCTION PATTERN**:

```php
<?php
// config/security.php - Security Configuration
define('CSRF_COOKIE_NAME', 'csrf_token');
define('CSRF_HEADER_NAME', 'X-CSRF-Token');
define('SESSION_TIMEOUT', 3600); // 1 hour
define('MAX_LOGIN_ATTEMPTS', 5);
define('LOCKOUT_DURATION', 900); // 15 minutes

// bootstrap.php - Secure Session Configuration
function initSecureSession(): void {
    ini_set('session.cookie_httponly', 1);
    ini_set('session.cookie_secure', 1);
    ini_set('session.cookie_samesite', 'Strict');
    ini_set('session.use_strict_mode', 1);
    ini_set('session.use_only_cookies', 1);

    session_start();

    // Session timeout check
    if (isset($_SESSION['last_activity']) && (time() - $_SESSION['last_activity'] > SESSION_TIMEOUT)) {
        session_unset();
        session_destroy();
        session_start();
    }
    $_SESSION['last_activity'] = time();
}

class AjaxCSRFProtection {
    private static $logger;

    public static function setLogger($logger): void {
        self::$logger = $logger;
    }

    public static function generateToken(): string {
        $token = bin2hex(random_bytes(32));
        $_SESSION['csrf_token'] = $token;
        $_SESSION['csrf_token_time'] = time();

        // Set double-submit cookie (SameSite=Strict prevents CSRF)
        setcookie(
            CSRF_COOKIE_NAME,
            $token,
            [
                'expires' => time() + 3600,
                'path' => '/',
                'domain' => $_SERVER['HTTP_HOST'],
                'secure' => true,
                'httponly' => false, // JavaScript needs to read this
                'samesite' => 'Strict'
            ]
        );

        return $token;
    }

    public static function validateAjaxRequest(): bool {
        // Check Origin header
        $origin = $_SERVER['HTTP_ORIGIN'] ?? '';
        $allowedOrigins = ['https://yourdomain.com', 'https://www.yourdomain.com'];

        if (!empty($origin) && !in_array($origin, $allowedOrigins, true)) {
            self::logSecurityEvent('Invalid Origin header', ['origin' => $origin]);
            return false;
        }

        // For AJAX, validate both header and cookie (double-submit)
        $headerToken = $_SERVER['HTTP_' . str_replace('-', '_', strtoupper(CSRF_HEADER_NAME))] ?? '';
        $cookieToken = $_COOKIE[CSRF_COOKIE_NAME] ?? '';
        $sessionToken = $_SESSION['csrf_token'] ?? '';

        if (empty($headerToken) || empty($cookieToken) || empty($sessionToken)) {
            self::logSecurityEvent('Missing CSRF tokens', [
                'has_header' => !empty($headerToken),
                'has_cookie' => !empty($cookieToken),
                'has_session' => !empty($sessionToken)
            ]);
            return false;
        }

        // All three must match (triple validation)
        if (!hash_equals($sessionToken, $headerToken) || !hash_equals($sessionToken, $cookieToken)) {
            self::logSecurityEvent('CSRF token mismatch');
            return false;
        }

        // Token age validation (15 minutes max)
        $tokenAge = time() - ($_SESSION['csrf_token_time'] ?? 0);
        if ($tokenAge > 900) {
            self::logSecurityEvent('CSRF token expired', ['age' => $tokenAge]);
            return false;
        }

        return true;
    }

    public static function setSecurityHeaders(): void {
        header('Content-Type: application/json; charset=utf-8');
        header('X-Content-Type-Options: nosniff');
        header('X-Frame-Options: DENY');
        header('X-XSS-Protection: 1; mode=block');
        header('Referrer-Policy: strict-origin-when-cross-origin');
        header('Cache-Control: no-store, no-cache, must-revalidate');
    }

    private static function logSecurityEvent(string $message, array $context = []): void {
        $logEntry = [
            'timestamp' => date('c'),
            'message' => $message,
            'ip' => $_SERVER['REMOTE_ADDR'] ?? 'unknown',
            'user_agent' => $_SERVER['HTTP_USER_AGENT'] ?? 'unknown',
            'user_id' => $_SESSION['user_id'] ?? null,
            'context' => $context
        ];

        error_log('[SECURITY] ' . json_encode($logEntry));
    }
}

class RateLimiter {
    private $pdo;

    public function __construct($pdo) {
        $this->pdo = $pdo;
    }

    public function isRateLimited(string $identifier): bool {
        $stmt = $this->pdo->prepare("
            SELECT COUNT(*) as attempts 
            FROM login_attempts 
            WHERE identifier = ? AND attempted_at > DATE_SUB(NOW(), INTERVAL ? SECOND)
        ");
        $stmt->execute([$identifier, LOCKOUT_DURATION]);
        $result = $stmt->fetch(PDO::FETCH_ASSOC);

        return ($result['attempts'] ?? 0) >= MAX_LOGIN_ATTEMPTS;
    }

    public function recordAttempt(string $identifier): void {
        $stmt = $this->pdo->prepare("INSERT INTO login_attempts (identifier, attempted_at) VALUES (?, NOW())");
        $stmt->execute([$identifier]);
    }

    public function clearAttempts(string $identifier): void {
        $stmt = $this->pdo->prepare("DELETE FROM login_attempts WHERE identifier = ?");
        $stmt->execute([$identifier]);
    }
}

class SecureAjaxAuthController {
    private $pdo;
    private $rateLimiter;

    public function __construct($pdo) {
        $this->pdo = $pdo;
        $this->rateLimiter = new RateLimiter($pdo);
    }

    public function handleAjaxLogin(): void {
        AjaxCSRFProtection::setSecurityHeaders();

        // Verify this is an AJAX request
        if (($_SERVER['HTTP_X_REQUESTED_WITH'] ?? '') !== 'XMLHttpRequest') {
            $this->sendJsonResponse(400, ['error' => 'Invalid request type']);
            return;
        }

        // Validate CSRF for login (protects against login CSRF)
        if (!AjaxCSRFProtection::validateAjaxRequest()) {
            $this->sendJsonResponse(403, ['error' => 'Invalid security token. Please refresh the page.']);
            return;
        }

        // Parse JSON body
        $input = json_decode(file_get_contents('php://input'), true);
        if (json_last_error() !== JSON_ERROR_NONE) {
            $this->sendJsonResponse(400, ['error' => 'Invalid request format']);
            return;
        }

        $username = trim($input['username'] ?? '');
        $password = $input['password'] ?? '';
        $clientIP = $_SERVER['REMOTE_ADDR'];

        // Rate limiting check
        $rateLimitKey = $clientIP . ':' . $username;
        if ($this->rateLimiter->isRateLimited($rateLimitKey)) {
            error_log("[SECURITY] Rate limit exceeded for: " . $rateLimitKey);
            $this->sendJsonResponse(429, [
                'error' => 'Too many login attempts. Please try again later.',
                'retry_after' => LOCKOUT_DURATION
            ]);
            return;
        }

        // Input validation
        if (empty($username) || empty($password)) {
            $this->sendJsonResponse(400, ['error' => 'Username and password are required']);
            return;
        }

        // Authenticate
        $stmt = $this->pdo->prepare("SELECT id, password_hash, is_active FROM users WHERE username = ?");
        $stmt->execute([$username]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        if (!$user || !$user['is_active'] || !password_verify($password, $user['password_hash'])) {
            $this->rateLimiter->recordAttempt($rateLimitKey);
            error_log("[AUTH] Failed login for: " . $username . " from IP: " . $clientIP);

            // Generic error message (don't reveal if user exists)
            $this->sendJsonResponse(401, ['error' => 'Invalid credentials']);
            return;
        }

        // Successful authentication
        $this->rateLimiter->clearAttempts($rateLimitKey);
        session_regenerate_id(true);

        $_SESSION['user_id'] = $user['id'];
        $_SESSION['logged_in'] = true;
        $_SESSION['login_time'] = time();
        $_SESSION['ip_address'] = $clientIP;

        // Generate new CSRF token for authenticated session
        $newToken = AjaxCSRFProtection::generateToken();

        error_log("[AUTH] Successful login for user ID: " . $user['id']);

        $this->sendJsonResponse(200, [
            'success' => true,
            'redirect' => '/dashboard',
            'csrf_token' => $newToken
        ]);
    }

    private function sendJsonResponse(int $statusCode, array $data): void {
        http_response_code($statusCode);
        echo json_encode($data);
        exit;
    }
}

