// Laplacian noise for differential privacy
function laplacianNoise(scale) {
  const u = Math.random() - 0.5;
  return -scale * Math.sign(u) * Math.log(1 - 2 * Math.abs(u));
}

// Apply differential privacy to model outputs
function applyDifferentialPrivacy(probabilities, config) {
  const { epsilon, sensitivity } = config;
  const scale = sensitivity / epsilon;

  return probabilities.map(p => {
    const noise = laplacianNoise(scale);
    return Math.max(0, Math.min(1, p + noise));
  });
}

// Temperature scaling to prevent overconfident predictions
// (reduces membership inference attack effectiveness)
function applyTemperatureScaling(logits, temperature) {
  const scaledLogits = logits.map(l => l / temperature);
  const expLogits = scaledLogits.map(l => Math.exp(l));
  const sumExp = expLogits.reduce((a, b) => a + b, 0);
  return expLogits.map(e => e / sumExp);
}

// Detect model inversion attack patterns
async function detectModelInversionAttempt(userId, input, redis) {
  const key = `inversion:${userId}`;
