**Why This Is Dangerous**:
- Go's standard `encoding/xml` package processes external entities by default when used with certain underlying parsers
- SOAP services are prime targets because they must accept XML input
- The attack can read sensitive files like `/etc/passwd`, AWS credentials, or internal configuration
- SSRF via XXE can access cloud metadata endpoints exposing IAM credentials

**SECURE VERSION**:

```go
package main

import (
	"bytes"
	"encoding/xml"
	"fmt"
	"io"
	"net/http"
	"regexp"
	"strings"
)

type SOAPEnvelope struct {
	XMLName xml.Name `xml:"Envelope"`
	Body    SOAPBody `xml:"Body"`
}

type SOAPBody struct {
	Request UserRequest `xml:"GetUserRequest"`
}

type UserRequest struct {
	UserID   string `xml:"UserID"`
	UserName string `xml:"UserName"`
}

const maxBodySize = 1024 * 1024 // 1MB limit

// sanitizeXMLInput removes DOCTYPE declarations and entity definitions
func sanitizeXMLInput(input []byte) ([]byte, error) {
	// Reject any DOCTYPE declarations
	doctypePattern := regexp.MustCompile(`(?i)<!DOCTYPE[^>]*>`)
	entityPattern := regexp.MustCompile(`(?i)<!ENTITY[^>]*>`)

	if doctypePattern.Match(input) || entityPattern.Match(input) {
		return nil, fmt.Errorf("XML contains forbidden DOCTYPE or ENTITY declarations")
	}

	return input, nil
}

func handleSOAPRequestSecure(w http.ResponseWriter, r *http.Request) {
	// Limit request body size
	r.Body = http.MaxBytesReader(w, r.Body, maxBodySize)

	body, err := io.ReadAll(r.Body)
	if err != nil {
		http.Error(w, "Error reading request", http.StatusBadRequest)
		return
	}
	defer r.Body.Close()

	// Sanitize XML input to prevent XXE
	sanitizedBody, err := sanitizeXMLInput(body)
	if err != nil {
		http.Error(w, "Invalid XML input", http.StatusBadRequest)
		return
	}

	// Use a decoder with strict settings
	decoder := xml.NewDecoder(bytes.NewReader(sanitizedBody))
	decoder.Strict = true
	decoder.Entity = make(map[string]string) // Empty entity map

	var envelope SOAPEnvelope
	err = decoder.Decode(&envelope)
	if err != nil {
		http.Error(w, "Invalid SOAP envelope", http.StatusBadRequest)
		return
	}

	// Validate extracted data
	if !isValidUserID(envelope.Body.Request.UserID) {
		http.Error(w, "Invalid user ID", http.StatusBadRequest)
		return
	}

	fmt.Fprintf(w, "User: %s, ID: %s",
		html.EscapeString(envelope.Body.Request.UserName),
		html.EscapeString(envelope.Body.Request.UserID))
}

func isValidUserID(id string) bool {
	return len(id) > 0 && len(id) <= 36 && !strings.ContainsAny(id, "<>&'\"")
}

func main() {
	http.HandleFunc("/soap", handleSOAPRequestSecure)
	http.ListenAndServe(":8080", nil)
}
```

**Key Security Controls**:
- **DOCTYPE/ENTITY rejection**: Regex pattern matching blocks any XML with DOCTYPE or ENTITY declarations before parsing
- **Strict decoder**: `xml.NewDecoder` with `Strict = true` and empty entity map prevents entity expansion
- **Input size limiting**: `http.MaxBytesReader` prevents memory exhaustion from large payloads
- **Output encoding**: `html.EscapeString` prevents XSS when reflecting data

Excellent concern. Production SOAP services need to handle complex namespaces while maintaining XXE protection. Here's a comprehensive production pattern using a whitelist approach with proper XML processing.

**PRODUCTION PATTERN**:

```go
package main

import (
	"bytes"
	"context"
	"encoding/xml"
	"fmt"
	"html"
	"io"
	"log"
	"net/http"
	"os"
	"regexp"
	"strings"
	"sync"
	"time"

	"golang.org/x/time/rate"
)

// Configuration
type Config struct {
	MaxBodySize       int64
	RequestTimeout    time.Duration
	AllowedNamespaces []string
	RateLimitPerSec   int
}

var config = Config{
	MaxBodySize:       1024 * 1024, // 1MB
	RequestTimeout:    30 * time.Second,
	AllowedNamespaces: []string{
		"http://schemas.xmlsoap.org/soap/envelope/",
		"http://www.w3.org/2001/XMLSchema",
		"http://www.w3.org/2001/XMLSchema-instance",
		"http://example.com/userservice",
	},
	RateLimitPerSec: 100,
}

// Structured logging
type SecurityLogger struct {
	logger *log.Logger
	mu     sync.Mutex
}

func NewSecurityLogger() *SecurityLogger {
	return &SecurityLogger{
		logger: log.New(os.Stdout, "[SOAP-SECURITY] ", log.LstdFlags|log.LUTC),
	}
}

func (sl *SecurityLogger) LogEvent(eventType, clientIP, details string) {
	sl.mu.Lock()
	defer sl.mu.Unlock()
	sl.logger.Printf("event=%s client_ip=%s details=%q", eventType, clientIP, details)
}

var securityLogger = NewSecurityLogger()

// SOAP message structures with namespace support
type SOAPEnvelope struct {
	XMLName   xml.Name   `xml:"http://schemas.xmlsoap.org/soap/envelope/ Envelope"`
	Namespace string     `xml:"xmlns:soap,attr"`
	Header    SOAPHeader `xml:"Header"`
	Body      SOAPBody   `xml:"Body"`
}

type SOAPHeader struct {
	Authentication AuthHeader `xml:"http://example.com/userservice Authentication"`
}

type AuthHeader struct {
	Token string `xml:"Token"`
}

type SOAPBody struct {
	Request  *UserRequest  `xml:"http://example.com/userservice GetUserRequest"`
	Response *UserResponse `xml:"http://example.com/userservice GetUserResponse"`
}

type UserRequest struct {
	UserID   string `xml:"UserID"`
	UserName string `xml:"UserName"`
}

type UserResponse struct {
	Status  string `xml:"Status"`
	Message string `xml:"Message"`
}

// SafeXMLParser with XXE protection
type SafeXMLParser struct {
	allowedNamespaces map[string]bool
	forbiddenPatterns []*regexp.Regexp
}

func NewSafeXMLParser(allowedNS []string) *SafeXMLParser {
	nsMap := make(map[string]bool)
	for _, ns := range allowedNS {
		nsMap[ns] = true
	}

	return &SafeXMLParser{
		allowedNamespaces: nsMap,
		forbiddenPatterns: []*regexp.Regexp{
			regexp.MustCompile(`(?i)<!DOCTYPE`),
			regexp.MustCompile(`(?i)<!ENTITY`),
			regexp.MustCompile(`(?i)SYSTEM\s+["']`),
			regexp.MustCompile(`(?i)PUBLIC\s+["']`),
			regexp.MustCompile(`(?i)%[a-zA-Z0-9]+;`), // Parameter entities
			regexp.MustCompile(`(?i)\[\s*<!`),        // Internal subset
		},
	}
}

func (p *SafeXMLParser) Validate(input []byte) error {
	inputStr := string(input)

	// Check for forbidden patterns
	for _, pattern := range p.forbiddenPatterns {
		if pattern.MatchString(inputStr) {
			return fmt.Errorf("potentially malicious XML content detected")
		}
	}

	return nil
}

func (p *SafeXMLParser) Parse(input []byte, v interface{}) error {
	if err := p.Validate(input); err != nil {
		return err
	}

	decoder := xml.NewDecoder(bytes.NewReader(input))
	decoder.Strict = true
	// Disable external entity resolution completely
	decoder.Entity = make(map[string]string)
	// Custom CharsetReader for encoding attacks prevention
	decoder.CharsetReader = func(charset string, input io.Reader) (io.Reader, error) {
		allowedCharsets := map[string]bool{"utf-8": true, "UTF-8": true}
		if !allowedCharsets[charset] {
			return nil, fmt.Errorf("unsupported charset: %s", charset)
		}
		return input, nil
	}

	return decoder.Decode(v)
}

// Rate limiter per IP
type IPRateLimiter struct {
	limiters map[string]*rate.Limiter
	mu       sync.RWMutex
	limit    rate.Limit
	burst    int
}

func NewIPRateLimiter(rps int) *IPRateLimiter {
	return &IPRateLimiter{
		limiters: make(map[string]*rate.Limiter),
		limit:    rate.Limit(rps),
		burst:    rps * 2,
	}
}

func (l *IPRateLimiter) GetLimiter(ip string) *rate.Limiter {
	l.mu.Lock()
	defer l.mu.Unlock()

	if limiter, exists := l.limiters[ip]; exists {
		return limiter
	}

	limiter := rate.NewLimiter(l.limit, l.burst)
	l.limiters[ip] = limiter
	return limiter
}

var rateLimiter = NewIPRateLimiter(config.RateLimitPerSec)
var xmlParser = NewSafeXMLParser(config.AllowedNamespaces)

// Middleware: Security headers
func securityHeadersMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("Content-Type", "application/soap+xml; charset=utf-8")
		w.Header().Set("X-Content-Type-Options", "nosniff")
		w.Header().Set("X-Frame-Options", "DENY")
		w.Header().Set("Content-Security-Policy", "default-src 'none'")
		next.ServeHTTP(w, r)
	})
}

// Middleware: Rate limiting
func rateLimitMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		clientIP := getClientIP(r)
		limiter := rateLimiter.GetLimiter(clientIP)

		if !limiter.Allow() {
			securityLogger.LogEvent("RATE_LIMIT_EXCEEDED", clientIP, "SOAP endpoint")
			http.Error(w, createSOAPFault("Rate limit exceeded"), http.StatusTooManyRequests)
			return
		}
		next.ServeHTTP(w, r)
	})
}

func getClientIP(r *http.Request) string {
	// Check X-Forwarded-For for proxy scenarios (validate in production)
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		ips := strings.Split(xff, ",")
		return strings.TrimSpace(ips[0])
	}
	return strings.Split(r.RemoteAddr, ":")[0]
}

func createSOAPFault(message string) string {
	return fmt.Sprintf(`<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <soap:Fault>
      <faultcode>soap:Server</faultcode>
      <faultstring>%s</faultstring>
    </soap:Fault>
  </soap:Body>
</soap:Envelope>`, html.EscapeString(message))
}

func handleSOAPRequest(w http.ResponseWriter, r *http.Request) {
	ctx, cancel := context.WithTimeout(r.Context(), config.RequestTimeout)
	defer cancel()

	clientIP := getClientIP(r)

	// Validate HTTP method
	if r.Method != http.MethodPost {
		securityLogger.LogEvent("INVALID_METHOD", clientIP, r.Method)
		http.Error(w, createSOAPFault("Method not allowed"), http.StatusMethodNotAllowed)
		return
	}

	// Validate Content-Type
	contentType := r.Header.Get("Content-Type")
	if !strings.Contains(contentType, "xml") {
		securityLogger.LogEvent("INVALID_CONTENT_TYPE", clientIP, contentType)
		http.Error(w, createSOAPFault("Invalid content type"), http.StatusUnsupportedMediaType)
		return
	}

	// Limit body size
	r.Body = http.MaxBytesReader(w, r.Body, config.MaxBodySize)

	body, err := io.ReadAll(r.Body)
	if err != nil {
		securityLogger.LogEvent("BODY_READ_ERROR", clientIP, err.Error())
		http.Error(w, createSOAPFault("Error reading request"), http.StatusBadRequest)
		return
	}
	defer r.Body.Close()

	// Parse with XXE protection
	var envelope SOAPEnvelope
	if err := xmlParser.Parse(body, &envelope); err != nil {
		securityLogger.LogEvent("XXE_ATTEMPT_BLOCKED", clientIP, err.Error())
		http.Error(w, createSOAPFault("Invalid SOAP request"), http.StatusBadRequest)
		return
	}

	// Validate request content
	if envelope.Body.Request == nil {
		http.Error(w, createSOAPFault("Missing request body"), http.StatusBadRequest)
		return
	}

	// Process request with context
	select {
	case <-ctx.Done():
		securityLogger.LogEvent("REQUEST_TIMEOUT", clientIP, "SOAP processing")
		http.Error(w, createSOAPFault("Request timeout"), http.StatusGatewayTimeout)
		return
	default:
		// Process normally
		securityLogger.LogEvent("SOAP_REQUEST_PROCESSED", clientIP,
			fmt.Sprintf("UserID=%s", envelope.Body.Request.UserID))

		response := createSOAPResponse("Success", "Request processed")
		w.WriteHeader(http.StatusOK)
		w.Write([]byte(response))
	}
}

func createSOAPResponse(status, message string) string {
	return fmt.Sprintf(`<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/" xmlns:ns="http://example.com/userservice">
  <soap:Body>
    <ns:GetUserResponse>
      <ns:Status>%s</ns:Status>
      <ns:Message>%s</ns:Message>
    </ns:GetUserResponse>
  </soap:Body>
</soap:Envelope>`, html.EscapeString(status), html.EscapeString(message))
}

func main() {
	mux := http.NewServeMux()
	mux.HandleFunc("/soap/user", handleSOAPRequest)

	// Apply middleware chain
	handler := securityHeadersMiddleware(rateLimitMiddleware(mux))

	server := &http.Server{
		Addr:         ":8443",
		Handler:      handler,
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 30 * time.Second,
		IdleTimeout:  120 * time.Second,
	}

	log.Printf("Starting secure SOAP server on :8443")
	if err := server.ListenAndServe(); err != nil {
		log.Fatalf("Server failed: %v", err)
	}
}
```

**Defense in Depth Layers**:

1. **Input Validation Layer**: Multiple regex patterns detect DOCTYPE, ENTITY, SYSTEM, PUBLIC declarations and parameter entities before any parsing occurs

2. **Parser Configuration Layer**: XML decoder with `Strict = true`, empty entity map, and custom charset reader that only allows UTF-8

3. **Rate Limiting Layer**: Per-IP rate limiting prevents enumeration and DoS attacks targeting the XML parser

4. **Request Lifecycle Layer**: Context timeouts, body size limits, and proper HTTP method/content-type validation

**Additional Protections**:
- **Namespace whitelisting**: Only predefined SOAP namespaces are accepted, preventing injection of malicious namespace URIs
- **SOAP Fault responses**: Error messages never expose internal details, returning standardized SOAP faults
- **Security audit logging**: All XXE attempts, rate limit violations, and successful requests are logged with client IP for forensics
- **Server hardening**: Read/write/idle timeouts prevent slowloris and connection exhaustion attacks
- **Output encoding**: All reflected content passes through `html.EscapeString` to prevent secondary XSS

JSON.parse itself is generally safe for data deserialization, but the real danger comes from trusting and using deserialized data without integrity verification, especially when that data comes from external sources or contains executable configurations.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const axios = require('axios');
const vm = require('vm');

const app = express();
app.use(express.json());

// Vulnerable: Fetches and executes configuration without integrity checks
app.post('/api/load-plugin', async (req, res) => {
  const { pluginUrl } = req.body;

  try {
    // Fetches remote configuration without verifying source
    const response = await axios.get(pluginUrl);
    const pluginConfig = response.data;

    // Dangerous: Executes code from untrusted source
    if (pluginConfig.initScript) {
      const script = new vm.Script(pluginConfig.initScript);
      script.runInThisContext();
    }

    // Stores configuration without validation
    global.plugins = global.plugins || {};
    global.plugins[pluginConfig.name] = pluginConfig;

    res.json({ success: true, loaded: pluginConfig.name });
  } catch (error) {
    res.status(500).json({ error: 'Failed to load plugin' });
  }
});

// Vulnerable: Deserializes user preferences without schema validation
app.post('/api/import-settings', (req, res) => {
  const { settingsData } = req.body;

  // Directly uses deserialized data without checks
  const settings = JSON.parse(Buffer.from(settingsData, 'base64').toString());

  // Prototype pollution possible if settings contains __proto__
  Object.assign(req.session.user, settings);

  res.json({ success: true });
});

app.listen(3000);
```

