import org.springframework.stereotype.Service;
import java.util.Set;

@Service
public class AuthorizationService {

    /**
     * Centralized authorization logic with role hierarchy
     */
    public AuthorizationResult checkOrderAccess(
            UserPrincipal user, Order order, AccessType accessType) {

        // Super admin has full access
        if (user.hasRole("SUPER_ADMIN")) {
            return AuthorizationResult.authorized("SUPER_ADMIN", FieldSet.ALL);
        }

        // Regular admin has access with field restrictions
        if (user.hasRole("ADMIN") || user.hasRole("SUPPORT")) {
            return AuthorizationResult.authorized("ADMIN", FieldSet.ADMIN);
        }

        // Owner has access to their own orders
        if (order.getUserId().equals(user.getId())) {
            return AuthorizationResult.authorized("OWNER", FieldSet.USER);
        }

        // Check delegated access (e.g., family accounts, business accounts)
        if (delegatedAccessRepository.hasAccess(user.getId(), order.getUserId())) {
            return AuthorizationResult.authorized("DELEGATED", FieldSet.DELEGATED);
        }

        return AuthorizationResult.denied("No access relationship found");
    }

    public boolean hasAdminAccess(UserPrincipal user) {
        return user.hasAnyRole("ADMIN", "SUPER_ADMIN", "SUPPORT");
    }
}
