@Service
public class RateLimiterService {
    private final Map<String, Map<Long, Bucket>> buckets = new ConcurrentHashMap<>();

    public boolean tryConsume(Long userId, String resourceType) {
        Bucket bucket = buckets
            .computeIfAbsent(resourceType, k -> new ConcurrentHashMap<>())
            .computeIfAbsent(userId, k -> createBucket(resourceType));
        return bucket.tryConsume(1);
    }

    private Bucket createBucket(String resourceType) {
        // 100 requests per minute for order access
        return Bucket.builder()
            .addLimit(Bandwidth.classic(100, Refill.greedy(100, Duration.ofMinutes(1))))
            .build();
    }
}
