}
```

**Security Features:**

1. **Executable Allowlist**: Only pre-approved executables
2. **Argument Schemas**: Each executable has validation rules
3. **No cmd.exe**: Direct execution only
4. **Sequential Execution**: Stop on first failure
5. **Overall Timeout**: Prevent long-running attacks
6. **Method Chaining**: Clean, fluent API

**When to Use Native .NET Instead:**

```csharp
// PREFER: Native .NET APIs when available
Directory.CreateDirectory(path);  // Instead of cmd /c mkdir
File.Copy(source, dest);          // Instead of cmd /c copy
File.Delete(path);                // Instead of cmd /c del

// Use DirectorySecurity for permissions
var security = new DirectorySecurity();
security.AddAccessRule(new FileSystemAccessRule(
    "Users",
    FileSystemRights.Read,
    AccessControlType.Allow
));
Directory.SetAccessControl(path, security);
```

Only use command execution when native .NET APIs are insufficient.

**Operational Security Considerations:**

- **Logging & Monitoring**: Log all security-relevant events (authentication attempts, authorization failures, suspicious patterns) to a centralized logging system for detection and forensic analysis.
- **Detection**: Implement alerts for anomalous behavior such as repeated failed attempts, unusual access patterns, or privilege escalation attempts.
- **Least Privilege**: Ensure services and users operate with minimum necessary permissions to limit blast radius of potential compromises.
- **Defense-in-Depth**: Layer multiple security controls (input validation, parameterized queries, WAF, rate limiting, network segmentation) so that failure of one control doesn't lead to full compromise.

Manually handling passwords and user lookup in ASP.NET Core while partially using Identity can easily create authentication bypasses and weak password handling.

**VULNERABLE CODE**:

```csharp
using System;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Data.SqlClient;
using System.Security.Cryptography;
using System.Text;

namespace MyApp.Controllers
{
    [Route("account")]
    public class AccountController : Controller
    {
        private const string ConnectionString = "Server=localhost;Database=MyApp;Trusted_Connection=True;";

        [HttpPost("login")]        
        public async Task<IActionResult> Login(string email, string password)
        {
            // Manually querying the database, bypassing ASP.NET Core Identity
            using var conn = new SqlConnection(ConnectionString);
            await conn.OpenAsync();

            var cmd = conn.CreateCommand();
            cmd.CommandText = $"SELECT Id, Email, PasswordHash FROM AspNetUsers WHERE Email = '{email}'";

            using var reader = await cmd.ExecuteReaderAsync();
            if (!await reader.ReadAsync())
            {
                return Unauthorized("Invalid credentials");
            }

            var storedHash = reader.GetString(2); // stored as plain SHA256 hex

            using var sha = SHA256.Create();
            var inputBytes = Encoding.UTF8.GetBytes(password);
            var inputHash = BitConverter.ToString(sha.ComputeHash(inputBytes)).Replace("-", string.Empty);

            if (storedHash == inputHash)
            {
                // No lockout, no sign-in manager, just issue an auth cookie
                Response.Cookies.Append("auth", reader.GetString(0));
                return Ok("Logged in");
            }

            return Unauthorized("Invalid credentials");
        }
    }
}
```

**Attack Payload** (SQL injection on email):
```sql
' OR '1'='1'--
```

This payload, used as the `email` value, turns the query into:
```sql
SELECT Id, Email, PasswordHash FROM AspNetUsers WHERE Email = '' OR '1'='1'--'
```
which returns the first user (often an admin). The code then only checks the password hash against the attacker's input; combined with implementation mistakes (e.g., comparing wrong columns, NULL checks, or logic bugs), this pattern commonly results in auth bypasses.

**Why This Is Dangerous**:
- Directly concatenates user input into SQL, allowing SQL injection and potential account takeover.
- Bypasses ASP.NET Core Identity's hardened password hashing (PBKDF2/Argon2), using raw SHA-256 without salt.
- Issues a home-grown auth cookie instead of using the Identity sign-in pipeline (no protection against tampering, no lockout, no security stamp validation).

**SECURE VERSION**:

```csharp
using System.Threading.Tasks;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Identity;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    public class ApplicationUser : IdentityUser
    {
    }

    [Route("account")]
    public class AccountController : Controller
    {
        private readonly SignInManager<ApplicationUser> _signInManager;
        private readonly UserManager<ApplicationUser> _userManager;
        private readonly ILogger<AccountController> _logger;

        public AccountController(
            SignInManager<ApplicationUser> signInManager,
            UserManager<ApplicationUser> userManager,
            ILogger<AccountController> logger)
        {
            _signInManager = signInManager;
            _userManager = userManager;
            _logger = logger;
        }

        public class LoginRequest
        {
            public string Email { get; set; } = string.Empty;
            public string Password { get; set; } = string.Empty;
            public bool RememberMe { get; set; }
        }

        [HttpPost("login")]
        public async Task<IActionResult> Login([FromBody] LoginRequest model)
        {
            if (!ModelState.IsValid)
            {
                return BadRequest("Invalid request");
            }

            // Primary defense: use ASP.NET Core Identity SignInManager
            var user = await _userManager.FindByEmailAsync(model.Email);
            if (user == null)
            {
                // Generic error to avoid user enumeration
                _logger.LogWarning("Login failed for non-existent email {Email}", model.Email);
                await Task.Delay(200); // small delay to reduce timing attacks
                return Unauthorized("Invalid credentials");
            }

            var result = await _signInManager.PasswordSignInAsync(
                user,
                model.Password,
                isPersistent: model.RememberMe,
                lockoutOnFailure: true);

            if (result.Succeeded)
            {
                _logger.LogInformation("User {UserId} logged in successfully", user.Id);
                return Ok("Logged in");
            }

            if (result.IsLockedOut)
            {
                _logger.LogWarning("User account {UserId} locked out due to failures", user.Id);
                return Unauthorized("Account locked. Try again later.");
            }

            _logger.LogWarning("Invalid login attempt for user {UserId}", user.Id);
            return Unauthorized("Invalid credentials");
        }
    }
}
```

**Key Security Controls**:
- Uses `SignInManager` and `UserManager`, which rely on parameterized queries and hardened password hashing algorithms (PBKDF2 by default) instead of manual SQL and weak hashes.
- Enables account lockout (`lockoutOnFailure: true`), throttling brute-force attempts and providing safe, generic responses to avoid user enumeration.
- Centralizes authentication in the ASP.NET Core Identity pipeline, which issues signed, protected cookies and supports security stamps, two-factor auth, and revocation instead of custom cookie handling.

For production, you want a layered approach: hardened Identity options, proper error handling and logging, rate limiting/brute-force protection, and environment-specific security settings.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Identity;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    public class ApplicationUser : IdentityUser
    {
    }

    public class LoginRequest
    {
        public string Email { get; set; } = string.Empty;
        public string Password { get; set; } = string.Empty;
        public bool RememberMe { get; set; }
        public string? TwoFactorCode { get; set; }
    }

    [AllowAnonymous]
    [Route("api/account")]
    [ApiController]
    public class AccountController : ControllerBase
    {
        private readonly SignInManager<ApplicationUser> _signInManager;
        private readonly UserManager<ApplicationUser> _userManager;
        private readonly ILogger<AccountController> _logger;
        private readonly IConfiguration _configuration;

        public AccountController(
            SignInManager<ApplicationUser> signInManager,
            UserManager<ApplicationUser> userManager,
            ILogger<AccountController> logger,
            IConfiguration configuration)
        {
            _signInManager = signInManager;
            _userManager = userManager;
            _logger = logger;
            _configuration = configuration;
        }

        [HttpPost("login")]
        public async Task<IActionResult> Login([FromBody] LoginRequest model)
        {
            if (!ModelState.IsValid)
            {
                _logger.LogWarning("Invalid login model from {Ip}", HttpContext.Connection.RemoteIpAddress);
                return BadRequest("Invalid request");
            }

            try
            {
                var user = await _userManager.FindByEmailAsync(model.Email);
                if (user == null)
                {
                    await Task.Delay(200);
                    _logger.LogWarning("Login failed for non-existent email from {Ip}", HttpContext.Connection.RemoteIpAddress);
                    return Unauthorized("Invalid credentials");
                }

                // Primary auth attempt
                var result = await _signInManager.CheckPasswordSignInAsync(
                    user,
                    model.Password,
                    lockoutOnFailure: true);

                if (result.IsLockedOut)
                {
                    _logger.LogWarning("Locked-out user {UserId} attempted login from {Ip}", user.Id, HttpContext.Connection.RemoteIpAddress);
                    return Unauthorized("Account locked. Try again later.");
                }

                if (!result.Succeeded && !result.RequiresTwoFactor)
                {
                    _logger.LogWarning("Invalid password for user {UserId} from {Ip}", user.Id, HttpContext.Connection.RemoteIpAddress);
                    return Unauthorized("Invalid credentials");
                }

                // Two-factor flow
                if (result.RequiresTwoFactor)
                {
                    if (string.IsNullOrWhiteSpace(model.TwoFactorCode))
                    {
                        _logger.LogInformation("2FA required for user {UserId}", user.Id);
                        return Unauthorized("Two-factor authentication required.");
                    }

                    var twoFactorResult = await _signInManager.TwoFactorAuthenticatorSignInAsync(
                        model.TwoFactorCode,
                        isPersistent: model.RememberMe,
                        rememberClient: true);

                    if (!twoFactorResult.Succeeded)
                    {
                        _logger.LogWarning("Invalid 2FA code for user {UserId} from {Ip}", user.Id, HttpContext.Connection.RemoteIpAddress);
                        return Unauthorized("Invalid credentials");
                    }

                    _logger.LogInformation("User {UserId} logged in with 2FA", user.Id);
                    return Ok("Logged in with 2FA");
                }

                // Successful password-only sign in (2FA not required for this user)
                await _signInManager.SignInAsync(user, isPersistent: model.RememberMe);
                _logger.LogInformation("User {UserId} logged in successfully from {Ip}", user.Id, HttpContext.Connection.RemoteIpAddress);
                return Ok("Logged in");
            }
            catch (Exception ex)
            {
                // Fail securely: generic response, detailed log
                _logger.LogError(ex, "Unhandled error during login for email {Email} from {Ip}",
                    model.Email, HttpContext.Connection.RemoteIpAddress);
                return StatusCode(500, "An error occurred.");
            }
        }
    }

    public static class IdentityConfig
    {
        public static void ConfigureIdentity(IdentityOptions options, bool isProduction)
        {
            // Password strength
            options.Password.RequireDigit = true;
            options.Password.RequireLowercase = true;
            options.Password.RequireUppercase = true;
            options.Password.RequireNonAlphanumeric = true;
            options.Password.RequiredLength = isProduction ? 12 : 8;

            // Lockout settings
            options.Lockout.DefaultLockoutTimeSpan = TimeSpan.FromMinutes(isProduction ? 15 : 2);
            options.Lockout.MaxFailedAccessAttempts = isProduction ? 5 : 10;
            options.Lockout.AllowedForNewUsers = true;

            // User
            options.User.RequireUniqueEmail = true;

            // Sign-in
            options.SignIn.RequireConfirmedEmail = isProduction;
        }
    }
}
```

**Defense in Depth Layers**:
1. **Framework-based authentication & 2FA**:
   - Uses `CheckPasswordSignInAsync`, `SignInAsync`, and `TwoFactorAuthenticatorSignInAsync` so all password hashing, cookie creation, and security stamp handling are done by ASP.NET Core Identity instead of custom code.
2. **Lockout, throttling, and environment-specific hardening**:
   - `IdentityConfig.ConfigureIdentity` enforces strong passwords, lockout thresholds, and email confirmation with tighter settings in production than in development.
3. **Robust logging and secure error handling**:
   - Structured logging for failed and successful attempts (`_logger.LogWarning`, `_logger.LogInformation`, `_logger.LogError`) including user ID and IP, while returning only generic messages to clients to avoid information disclosure.

**Additional Protections**:
- Configure authentication cookies in `Program.cs` / `Startup`:
  - Set `Cookie.SecurePolicy = CookieSecurePolicy.Always`, `HttpOnly = true`, and `SameSite = SameSiteMode.Strict` or `Lax` in production.
- Add rate limiting at the API gateway or middleware level (e.g., "5 login attempts per minute per IP") to reduce credential stuffing and password spraying.
- Enable centralized monitoring and alerting (e.g., Application Insights, ELK, SIEM) on suspicious patterns such as repeated lockouts, login attempts from new countries, or 2FA failures to quickly detect and respond to attacks.

Your login code likely has a **timing attack vulnerability** - a subtle but serious security flaw that allows attackers to enumerate valid usernames and potentially crack passwords by measuring response time differences.

**VULNERABLE CODE**:

```php
<?php
class LoginController {
    private $pdo;

    public function __construct(PDO $pdo) {
        $this->pdo = $pdo;
    }

    public function authenticate(string $username, string $password): bool {
        // VULNERABLE: Different execution paths create timing differences
        $stmt = $this->pdo->prepare("SELECT id, password_hash FROM users WHERE username = ?");
        $stmt->execute([$username]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        // TIMING LEAK #1: Early return if user not found
        if (!$user) {
            return false; // Fast return - no password check
        }

        // TIMING LEAK #2: password_verify takes measurable time
        if (password_verify($password, $user['password_hash'])) {
            session_regenerate_id(true);
            $_SESSION['user_id'] = $user['id'];
            return true;
        }

        return false;
    }

    public function login(): void {
        $username = $_POST['username'] ?? '';
        $password = $_POST['password'] ?? '';

        // VULNERABLE: Error message timing also leaks information
        if ($this->authenticate($username, $password)) {
            header('Location: /dashboard');
        } else {
            // Same message but different timing reveals user existence
            echo 'Invalid credentials';
        }
    }
}
```

**Attack Payload**:
```bash
# Timing attack script using curl with timing measurement
for user in admin root administrator test user1; do
  time=$(curl -o /dev/null -s -w '%{time_total}' \
    -X POST http://target.com/login \
    -d "username=$user&password=wrongpassword")
  echo "$user: ${time}s"
done

# Output shows timing differences:
# admin: 0.045s     <- User EXISTS (password_verify ran)
# root: 0.012s      <- User NOT found (early return)
# administrator: 0.048s <- User EXISTS
# test: 0.011s      <- User NOT found
# user1: 0.047s     <- User EXISTS
```

**Why This Is Dangerous**:
- **Username enumeration**: Attackers can determine which usernames exist in your system by measuring response times (10-50ms difference is detectable)
- **Optimized brute-force**: Once valid usernames are known, attackers focus credential stuffing on confirmed accounts
- **Statistical analysis**: Even with noise, attackers can run thousands of requests and use statistical methods to identify valid accounts
- **bcrypt timing**: `password_verify()` with bcrypt takes 50-100ms, creating a huge timing difference vs early return

**SECURE VERSION**:

```php
<?php
class SecureLoginController {
    private $pdo;
    private $fakePasswordHash;

    public function __construct(PDO $pdo) {
        $this->pdo = $pdo;
        // Pre-computed hash for constant-time comparison on non-existent users
        $this->fakePasswordHash = password_hash('dummy_password_for_timing', PASSWORD_BCRYPT, ['cost' => 12]);
    }

    public function authenticate(string $username, string $password): bool {
        $stmt = $this->pdo->prepare("SELECT id, password_hash FROM users WHERE username = ?");
        $stmt->execute([$username]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        // SECURE: Always perform password verification to maintain constant time
        $hashToCheck = $user ? $user['password_hash'] : $this->fakePasswordHash;
        $passwordValid = password_verify($password, $hashToCheck);

        // SECURE: Only succeed if BOTH user exists AND password is correct
        if ($user && $passwordValid) {
            session_regenerate_id(true);
            $_SESSION['user_id'] = $user['id'];
            return true;
        }

        return false;
    }

    public function login(): void {
        $username = filter_input(INPUT_POST, 'username', FILTER_SANITIZE_STRING) ?? '';
        $password = $_POST['password'] ?? '';

        // Add small random delay to further obscure timing
        usleep(random_int(10000, 50000)); // 10-50ms random delay

        if ($this->authenticate($username, $password)) {
            header('Location: /dashboard');
            exit;
        } else {
            // Generic error message
            $_SESSION['error'] = 'Invalid credentials';
            header('Location: /login');
            exit;
        }
    }
}
```

**Key Security Controls**:
- **Constant-time password verification**: Always run `password_verify()` regardless of whether user exists, using a pre-computed fake hash
- **Random timing jitter**: Add 10-50ms random delay to obscure any remaining timing differences
- **Generic error messages**: Never reveal whether username or password was incorrect
- **Logical AND check**: Both conditions must be true, preventing early returns

