```java
// DependencySecurityMonitor.java - Runtime dependency monitoring
package com.enterprise.security;

import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.boot.context.event.ApplicationReadyEvent;
import org.springframework.context.event.EventListener;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Component;
import io.micrometer.core.instrument.MeterRegistry;
import io.micrometer.core.instrument.Gauge;

import java.io.IOException;
import java.io.InputStream;
import java.util.*;
import java.util.jar.Manifest;

@Component
public class DependencySecurityMonitor {

    private static final Logger logger = LoggerFactory.getLogger(DependencySecurityMonitor.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    private final MeterRegistry meterRegistry;
    private final Map<String, String> loadedDependencies = new HashMap<>();

    public DependencySecurityMonitor(MeterRegistry meterRegistry) {
        this.meterRegistry = meterRegistry;
    }

    @EventListener(ApplicationReadyEvent.class)
    public void onApplicationReady() {
        scanLoadedDependencies();
        registerMetrics();
        logDependencyManifest();
    }

    private void scanLoadedDependencies() {
        try {
            Enumeration<java.net.URL> resources = getClass().getClassLoader()
                .getResources("META-INF/MANIFEST.MF");

            while (resources.hasMoreElements()) {
                try (InputStream is = resources.nextElement().openStream()) {
                    Manifest manifest = new Manifest(is);
                    String bundleName = manifest.getMainAttributes().getValue("Bundle-SymbolicName");
                    String bundleVersion = manifest.getMainAttributes().getValue("Bundle-Version");
                    String implementationTitle = manifest.getMainAttributes().getValue("Implementation-Title");
                    String implementationVersion = manifest.getMainAttributes().getValue("Implementation-Version");

                    String name = bundleName != null ? bundleName : implementationTitle;
                    String version = bundleVersion != null ? bundleVersion : implementationVersion;

                    if (name != null && version != null) {
                        loadedDependencies.put(name, version);
                        checkKnownVulnerabilities(name, version);
                    }
                } catch (IOException e) {
                    logger.debug("Could not read manifest: {}", e.getMessage());
                }
            }
        } catch (IOException e) {
            logger.error("Failed to scan dependencies", e);
        }
    }

    private void checkKnownVulnerabilities(String name, String version) {
        // Known vulnerable version patterns
        Map<String, String> vulnerablePatterns = Map.of(
            "log4j-core", "2\\.(0|1[0-6])\\..*",
            "spring-beans", "5\\.3\\.(0|1[0-7])$",
            "jackson-databind", "2\\.([0-9]|1[0-2])\\..*",
            "commons-collections", "3\\.[0-2]\\..*"
        );

        for (Map.Entry<String, String> entry : vulnerablePatterns.entrySet()) {
            if (name.contains(entry.getKey()) && version.matches(entry.getValue())) {
                String message = String.format(
                    "CRITICAL: Vulnerable dependency detected - %s:%s", name, version);
                auditLogger.error("event=vulnerable_dependency, name={}, version={}, severity=CRITICAL",
                    name, version);
                logger.error(message);

                // Alert security team
                meterRegistry.counter("security.vulnerable.dependencies",
                    "name", name, "version", version).increment();
            }
        }
    }

    private void registerMetrics() {
        Gauge.builder("application.dependencies.count", loadedDependencies, Map::size)
            .description("Number of loaded dependencies")
            .register(meterRegistry);
    }

    private void logDependencyManifest() {
        auditLogger.info("event=startup_dependency_scan, count={}, dependencies={}",
            loadedDependencies.size(), loadedDependencies);
    }

    @Scheduled(cron = "0 0 6 * * *") // Daily at 6 AM
    public void scheduledSecurityCheck() {
        auditLogger.info("event=scheduled_dependency_scan, timestamp={}", System.currentTimeMillis());
        scanLoadedDependencies();
    }
}
