SHA256 is **NOT** secure for password hashing! While SHA256 is a cryptographically secure hash function for data integrity, it's completely unsuitable for passwords because it's designed to be fast. Attackers with modern GPUs can compute billions of SHA256 hashes per second, making brute-force attacks trivial.

**VULNERABLE CODE**:

```csharp
using System;
using System.Security.Cryptography;
using System.Text;

namespace VulnerableApp
{
    public class InsecurePasswordHasher
    {
        // DANGEROUS: Using SHA256 for password hashing
        public string HashPassword(string password)
        {
            using (SHA256 sha256 = SHA256.Create())
            {
                byte[] bytes = Encoding.UTF8.GetBytes(password);
                byte[] hash = sha256.ComputeHash(bytes);
                return Convert.ToBase64String(hash);
            }
        }

        public bool VerifyPassword(string password, string storedHash)
        {
            string computedHash = HashPassword(password);
            return computedHash == storedHash; // Vulnerable to timing attacks
        }
    }
}
```

**Attack Payload**:
```bash
# Using hashcat to crack SHA256 passwords at ~10 billion hashes/sec on RTX 4090
hashcat -m 1400 -a 3 hashes.txt ?a?a?a?a?a?a?a?a

# Common password "password123" cracked in milliseconds
# 8-character alphanumeric password cracked in hours
```

**Why This Is Dangerous**:
- SHA256 computes 10+ billion hashes/second on modern GPUs, enabling rapid brute-force attacks
- No salt means identical passwords produce identical hashes (rainbow table attacks)
- No iteration/work factor means cost doesn't scale with hardware improvements
- String comparison is vulnerable to timing attacks, leaking hash information

**SECURE VERSION**:

```csharp
using System;
using System.Security.Cryptography;
using Microsoft.AspNetCore.Cryptography.KeyDerivation;

namespace SecureApp
{
    public class SecurePasswordHasher
    {
        private const int SaltSize = 16; // 128 bits
        private const int HashSize = 32; // 256 bits
        private const int Iterations = 100000; // OWASP 2023 recommendation

        public string HashPassword(string password)
        {
            // Generate cryptographically secure random salt
            byte[] salt = RandomNumberGenerator.GetBytes(SaltSize);

            // Use PBKDF2 with SHA256 - purpose-built for password hashing
            byte[] hash = KeyDerivation.Pbkdf2(
                password: password,
                salt: salt,
                prf: KeyDerivationPrf.HMACSHA256,
                iterationCount: Iterations,
                numBytesRequested: HashSize
            );

            // Combine iteration count, salt, and hash for storage
            byte[] result = new byte[4 + SaltSize + HashSize];
            BitConverter.GetBytes(Iterations).CopyTo(result, 0);
            salt.CopyTo(result, 4);
            hash.CopyTo(result, 4 + SaltSize);

            return Convert.ToBase64String(result);
        }

        public bool VerifyPassword(string password, string storedHash)
        {
            byte[] hashBytes = Convert.FromBase64String(storedHash);

            // Extract components
            int iterations = BitConverter.ToInt32(hashBytes, 0);
            byte[] salt = new byte[SaltSize];
            byte[] storedHashBytes = new byte[HashSize];
            Array.Copy(hashBytes, 4, salt, 0, SaltSize);
            Array.Copy(hashBytes, 4 + SaltSize, storedHashBytes, 0, HashSize);

            // Compute hash with same parameters
            byte[] computedHash = KeyDerivation.Pbkdf2(
                password: password,
                salt: salt,
                prf: KeyDerivationPrf.HMACSHA256,
                iterationCount: iterations,
                numBytesRequested: HashSize
            );

            // Constant-time comparison prevents timing attacks
            return CryptographicOperations.FixedTimeEquals(computedHash, storedHashBytes);
        }
    }
}
```

**Key Security Controls**:
- **PBKDF2 with high iteration count**: 100,000 iterations makes each hash attempt computationally expensive (~100ms vs nanoseconds)
- **Unique random salt per password**: Defeats rainbow tables and ensures identical passwords have different hashes
- **Constant-time comparison**: `CryptographicOperations.FixedTimeEquals` prevents timing side-channel attacks
- **Embedded iteration count**: Allows future upgrades without breaking existing hashes

Excellent questions! Argon2 is the current gold standard (winner of the 2015 Password Hashing Competition) as it's resistant to both GPU and ASIC attacks through memory-hardness. BCrypt remains a solid choice but lacks memory-hardness. Here's a production-ready implementation with hash migration support.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Security.Cryptography;
using System.Text.RegularExpressions;
using Konscious.Security.Cryptography;
using Microsoft.Extensions.Logging;
using Microsoft.Extensions.Options;

namespace SecureApp.Security
{
    public class PasswordHashingOptions
    {
        public int Argon2MemorySize { get; set; } = 65536; // 64 MB
        public int Argon2Iterations { get; set; } = 4;
        public int Argon2Parallelism { get; set; } = 2;
        public int SaltSize { get; set; } = 16;
        public int HashSize { get; set; } = 32;
        public int MinimumPbkdf2Iterations { get; set; } = 100000;
    }

    public enum HashAlgorithmVersion
    {
        Unknown = 0,
        Pbkdf2V1 = 1,      // Legacy PBKDF2
        Argon2idV1 = 2     // Current standard
    }

    public class PasswordHashResult
    {
        public bool IsValid { get; set; }
        public bool NeedsRehash { get; set; }
        public string NewHash { get; set; }
    }

    public class ProductionPasswordHasher
    {
        private readonly PasswordHashingOptions _options;
        private readonly ILogger<ProductionPasswordHasher> _logger;
        private const HashAlgorithmVersion CurrentVersion = HashAlgorithmVersion.Argon2idV1;

        public ProductionPasswordHasher(
            IOptions<PasswordHashingOptions> options,
            ILogger<ProductionPasswordHasher> logger)
        {
            _options = options.Value;
            _logger = logger;
        }

        public string HashPassword(string password)
        {
            if (string.IsNullOrEmpty(password))
                throw new ArgumentException("Password cannot be empty", nameof(password));

            byte[] salt = RandomNumberGenerator.GetBytes(_options.SaltSize);

            using var argon2 = new Argon2id(System.Text.Encoding.UTF8.GetBytes(password))
            {
                Salt = salt,
                DegreeOfParallelism = _options.Argon2Parallelism,
                MemorySize = _options.Argon2MemorySize,
                Iterations = _options.Argon2Iterations
            };

            byte[] hash = argon2.GetBytes(_options.HashSize);

            // Format: $argon2id$v=1$m=65536,t=4,p=2$<salt>$<hash>
            string encodedSalt = Convert.ToBase64String(salt);
            string encodedHash = Convert.ToBase64String(hash);

            return $"$argon2id$v=1$m={_options.Argon2MemorySize},t={_options.Argon2Iterations}," +
                   $"p={_options.Argon2Parallelism}${encodedSalt}${encodedHash}";
        }

        public PasswordHashResult VerifyAndUpgrade(string password, string storedHash)
        {
            var result = new PasswordHashResult();

            try
            {
                var version = DetectHashVersion(storedHash);

                bool isValid = version switch
                {
                    HashAlgorithmVersion.Argon2idV1 => VerifyArgon2(password, storedHash),
                    HashAlgorithmVersion.Pbkdf2V1 => VerifyLegacyPbkdf2(password, storedHash),
                    _ => false
                };

                result.IsValid = isValid;

                // Upgrade hash if using legacy algorithm or outdated parameters
                if (isValid && (version != CurrentVersion || NeedsParameterUpgrade(storedHash)))
                {
                    result.NeedsRehash = true;
                    result.NewHash = HashPassword(password);

                    _logger.LogInformation(
                        "Password hash upgraded from {OldVersion} to {NewVersion}",
                        version, CurrentVersion);
                }

                return result;
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Password verification failed");

                // Fail securely - don't reveal why verification failed
                return new PasswordHashResult { IsValid = false };
            }
        }

        private HashAlgorithmVersion DetectHashVersion(string hash)
        {
            if (hash.StartsWith("$argon2id$"))
                return HashAlgorithmVersion.Argon2idV1;
            if (hash.StartsWith("$pbkdf2$"))
                return HashAlgorithmVersion.Pbkdf2V1;

            return HashAlgorithmVersion.Unknown;
        }

        private bool VerifyArgon2(string password, string storedHash)
        {
            // Parse: $argon2id$v=1$m=65536,t=4,p=2$<salt>$<hash>
            var pattern = @"^\$argon2id\$v=1\$m=(\d+),t=(\d+),p=(\d+)\$([^$]+)\$([^$]+)$";
            var match = Regex.Match(storedHash, pattern);

            if (!match.Success)
                return false;

            int memorySize = int.Parse(match.Groups[1].Value);
            int iterations = int.Parse(match.Groups[2].Value);
            int parallelism = int.Parse(match.Groups[3].Value);
            byte[] salt = Convert.FromBase64String(match.Groups[4].Value);
            byte[] expectedHash = Convert.FromBase64String(match.Groups[5].Value);

            using var argon2 = new Argon2id(System.Text.Encoding.UTF8.GetBytes(password))
            {
                Salt = salt,
                DegreeOfParallelism = parallelism,
                MemorySize = memorySize,
                Iterations = iterations
            };

            byte[] computedHash = argon2.GetBytes(expectedHash.Length);

            return CryptographicOperations.FixedTimeEquals(computedHash, expectedHash);
        }

        private bool VerifyLegacyPbkdf2(string password, string storedHash)
        {
            // Parse legacy format: $pbkdf2$<iterations>$<salt>$<hash>
            var pattern = @"^\$pbkdf2\$(\d+)\$([^$]+)\$([^$]+)$";
            var match = Regex.Match(storedHash, pattern);

            if (!match.Success)
                return false;

            int iterations = int.Parse(match.Groups[1].Value);

            // Reject dangerously low iteration counts
            if (iterations < _options.MinimumPbkdf2Iterations)
            {
                _logger.LogWarning(
                    "Rejected PBKDF2 hash with insufficient iterations: {Iterations}",
                    iterations);
                return false;
            }

            byte[] salt = Convert.FromBase64String(match.Groups[2].Value);
            byte[] expectedHash = Convert.FromBase64String(match.Groups[3].Value);

            using var pbkdf2 = new Rfc2898DeriveBytes(
                password,
                salt,
                iterations,
                HashAlgorithmName.SHA256);

            byte[] computedHash = pbkdf2.GetBytes(expectedHash.Length);

            return CryptographicOperations.FixedTimeEquals(computedHash, expectedHash);
        }

        private bool NeedsParameterUpgrade(string hash)
        {
            if (!hash.StartsWith("$argon2id$"))
                return true;

            var pattern = @"m=(\d+),t=(\d+),p=(\d+)";
            var match = Regex.Match(hash, pattern);

            if (!match.Success)
                return true;

            int memorySize = int.Parse(match.Groups[1].Value);
            int iterations = int.Parse(match.Groups[2].Value);

            // Upgrade if parameters are below current recommendations
            return memorySize < _options.Argon2MemorySize ||
                   iterations < _options.Argon2Iterations;
        }
    }
}
```

**Defense in Depth Layers**:

1. **Memory-hard algorithm (Argon2id)**: Requires 64MB RAM per hash attempt, making GPU/ASIC attacks economically infeasible
```csharp
MemorySize = 65536, // 64 MB - expensive to parallelize
Iterations = 4,     // Time cost
Parallelism = 2     // Lane count
```

2. **Transparent hash migration**: Automatically upgrades legacy hashes on successful login
```csharp
if (isValid && version != CurrentVersion)
{
    result.NeedsRehash = true;
    result.NewHash = HashPassword(password);
}
```

3. **Fail-secure error handling**: Never reveals why verification failed to attackers
```csharp
catch (Exception ex)
{
    _logger.LogError(ex, "Password verification failed");
    return new PasswordHashResult { IsValid = false };
}
```

**Additional Protections**:

- **Self-describing hash format**: Embeds algorithm and parameters in the hash string for future-proof verification
- **Constant-time comparison**: `CryptographicOperations.FixedTimeEquals` prevents timing attacks even with complex hash formats
- **Parameter validation**: Rejects hashes with dangerously weak parameters (e.g., low PBKDF2 iterations)
- **Audit logging**: Tracks hash upgrades for compliance and security monitoring
- **Configurable via DI**: Production parameters can be tuned per environment without code changes

**Dependency Installation**:
```bash
dotnet add package Konscious.Security.Cryptography.Argon2
```

**Usage in Authentication Controller**:
```csharp
[HttpPost("login")]
public async Task<IActionResult> Login([FromBody] LoginRequest request)
{
    var user = await _userRepository.GetByEmailAsync(request.Email);
    if (user == null)
    {
        // Prevent user enumeration - still compute a hash
        _hasher.HashPassword(request.Password);
        return Unauthorized();
    }

    var result = _hasher.VerifyAndUpgrade(request.Password, user.PasswordHash);

    if (!result.IsValid)
        return Unauthorized();

    if (result.NeedsRehash)
    {
        user.PasswordHash = result.NewHash;
        await _userRepository.UpdateAsync(user);
    }

    return Ok(GenerateToken(user));
}
```

When using claims-based security (e.g., JWT bearer tokens), it's easy to trust whatever claims are present without validating their origin and scope. That leads to broken access control, especially multi-tenant or role-based APIs.

**VULNERABLE CODE**:

```csharp
using System;
using System.Linq;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Authorization;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class OrdersController : ControllerBase
    {
        // Insecure: trusts role and tenant claims blindly
        [HttpGet("{orderId}")]
        [Authorize] // Only checks that the user is authenticated
        public IActionResult GetOrder(string orderId)
        {
            // Reads claims directly without validating issuer/audience/scope
            var role = User.Claims.FirstOrDefault(c => c.Type == "role")?.Value;
            var tenantId = User.Claims.FirstOrDefault(c => c.Type == "tenant_id")?.Value;

            // Insecure: "admin" can access any tenant's orders
            if (role == "admin")
            {
                // No tenant boundary enforcement
                return Ok(new { OrderId = orderId, TenantId = tenantId, Status = "AnyTenantOrderVisible" });
            }

            // Insecure: trusts tenant_id in token without checking against route
            var requestedTenantId = HttpContext.Request.Query["tenantId"].ToString();
            if (tenantId == requestedTenantId)
            {
                return Ok(new { OrderId = orderId, TenantId = tenantId, Status = "TenantOrderVisible" });
            }

            // Generic 404 hides abuse but also hides suspicious attempts
            return NotFound();
        }
    }
}
```

**Attack Payload** (JWT with forged claims):
```text
Header:
{
  "alg": "none",
  "typ": "JWT"
}

Payload:
{
  "sub": "attacker@example.com",
  "role": "admin",
  "tenant_id": "victim-tenant",
  "exp": 4102444800
}

Signature:
<empty because alg=none or signed with leaked key>
```

An attacker can send this JWT as the `Authorization: Bearer <token>` header, exploiting an API that:
- Accepts tokens without validating signature/issuer/audience
- Treats `role=admin` and arbitrary `tenant_id` as fully trusted

**Why This Is Dangerous**:
- The API assumes any `role` and `tenant_id` claim is genuine without validating token signature, issuer, audience, or allowed algorithms.
- Authorization logic is implemented manually and inconsistently, bypassing robust policy/role checks.
- Multi-tenant boundaries are missing: an `admin` of one tenant (or a forged token) can read data from any other tenant.

**SECURE VERSION**:

```csharp
using System;
using System.Linq;
using System.Security.Claims;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    public static class CustomClaimTypes
    {
        public const string TenantId = "tenant_id";
        public const string Scope = "scope";
    }

    public class Order
    {
        public string OrderId { get; set; } = string.Empty;
        public string TenantId { get; set; } = string.Empty;
        public string Status { get; set; } = string.Empty;
    }

    [ApiController]
    [Route("api/tenants/{tenantId}/[controller]")]
    public class OrdersController : ControllerBase
    {
        private readonly ILogger<OrdersController> _logger;

        public OrdersController(ILogger<OrdersController> logger)
        {
            _logger = logger;
        }

        // Secure: uses policy-based, claims-aware authorization
        [HttpGet("{orderId}")]
        [Authorize(Policy = "TenantOrderRead")]
        public IActionResult GetOrder(string tenantId, string orderId)
        {
            // PRIMARY DEFENSE: Enforce tenant boundary at controller level
            var userTenantId = User.FindFirstValue(CustomClaimTypes.TenantId);
            if (string.IsNullOrWhiteSpace(userTenantId) || !string.Equals(userTenantId, tenantId, StringComparison.Ordinal))
            {
                _logger.LogWarning("Tenant mismatch: user {User} attempted to access tenant {Tenant}",
                    User.FindFirstValue(ClaimTypes.NameIdentifier) ?? "unknown", tenantId);

                return Forbid(); // Fail securely
            }

            // DEFENSE-IN-DEPTH: Check scopes/permissions from validated token
            var scopes = User.FindAll(CustomClaimTypes.Scope).Select(c => c.Value).ToArray();
            if (!scopes.Contains("orders.read"))
            {
                _logger.LogWarning("Missing scope 'orders.read' for user {User}",
                    User.FindFirstValue(ClaimTypes.NameIdentifier) ?? "unknown");
                return Forbid();
            }

            try
            {
                // Normally you would enforce tenant filter at data access layer too
                var order = new Order
                {
                    OrderId = orderId,
                    TenantId = tenantId,
                    Status = "ExampleOrder"
                };

                return Ok(order);
            }
            catch (Exception ex)
            {
                // ERROR HANDLING: Log details, return generic message
                _logger.LogError(ex, "Error retrieving order {OrderId} for tenant {TenantId}", orderId, tenantId);
                return StatusCode(500, "An unexpected error occurred.");
            }
        }
    }
}
```

**Key Security Controls**:
- **Validated identity tokens**: Assumes upstream configuration validates JWT signature, issuer, audience, and disallows `alg=none`; only trusted identity providers can set claims.
- **Policy-based and tenant-aware authorization**: Uses `[Authorize(Policy = "TenantOrderRead")]` plus explicit tenant/claim comparison to enforce per-tenant boundaries regardless of user role.
- **Defense in depth & secure failure**: Verifies required scopes, logs mismatches, uses `Forbid()` instead of leaking details, and performs tenant checks both at the controller and (in a real app) at the data-access layer.

In production, you want centralized, policy-based authorization that treats claims as *input* (not as truth) and reinforces tenant and role rules at multiple layers. Configuration should be environment-specific, auditable, and observable.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.Linq;
using System.Security.Claims;
using System.Threading.Tasks;
using Microsoft.AspNetCore.Authentication.JwtBearer;
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Builder;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;

namespace MyApp
{
    public static class ClaimTypesCustom
    {
        public const string TenantId = "tenant_id";
        public const string Scope = "scope";
    }

    // 1. Central policy that enforces tenant + scope + role from validated tokens
    public class TenantOrderReadRequirement : IAuthorizationRequirement { }

    public class TenantOrderReadHandler : AuthorizationHandler<TenantOrderReadRequirement>
    {
        private readonly ILogger<TenantOrderReadHandler> _logger;

        public TenantOrderReadHandler(ILogger<TenantOrderReadHandler> logger)
        {
            _logger = logger;
        }

        protected override Task HandleRequirementAsync(AuthorizationHandlerContext context, TenantOrderReadRequirement requirement)
        {
            var user = context.User;
            var httpContext = (context.Resource as DefaultHttpContext) ??
                              (context.Resource as HttpContext);

            if (user?.Identity?.IsAuthenticated != true || httpContext == null)
            {
                _logger.LogWarning("Unauthorized access attempt (not authenticated)");
                return Task.CompletedTask;
            }

            var routeTenantId = httpContext.Request.RouteValues["tenantId"]?.ToString();
            var claimTenantId = user.FindFirstValue(ClaimTypesCustom.TenantId);
            var scopes = user.FindAll(ClaimTypesCustom.Scope).Select(c => c.Value).ToArray();
            var roles = user.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray();

            if (string.IsNullOrEmpty(routeTenantId) || string.IsNullOrEmpty(claimTenantId))
            {
                _logger.LogWarning("Missing tenant information for user {User}", user.FindFirstValue(ClaimTypes.NameIdentifier));
                return Task.CompletedTask;
            }

            if (!string.Equals(routeTenantId, claimTenantId, StringComparison.Ordinal))
            {
                _logger.LogWarning("Tenant boundary violation: user {User} with tenant {UserTenant} tried to access tenant {RouteTenant}",
                    user.FindFirstValue(ClaimTypes.NameIdentifier), claimTenantId, routeTenantId);
                return Task.CompletedTask; // Do not satisfy requirement
            }

            // Require either 'orders.read' scope or a specific role
            var hasScope = scopes.Contains("orders.read", StringComparer.Ordinal);
            var hasPrivilegedRole = roles.Contains("TenantAdmin", StringComparer.Ordinal) ||
                                    roles.Contains("SupportRead", StringComparer.Ordinal);

            if (!hasScope && !hasPrivilegedRole)
            {
                _logger.LogWarning("Insufficient permissions: user {User} lacks required scope/role", user.FindFirstValue(ClaimTypes.NameIdentifier));
                return Task.CompletedTask;
            }

            context.Succeed(requirement);
            return Task.CompletedTask;
        }
    }

    public class Startup
    {
        private readonly IConfiguration _configuration;

        public Startup(IConfiguration configuration)
        {
            _configuration = configuration;
        }

        public void ConfigureServices(IServiceCollection services)
        {
            var env = _configuration["ASPNETCORE_ENVIRONMENT"] ?? "Production";

            // 2. Authentication: validate JWT from Azure AD/Okta with strict settings
            services
                .AddAuthentication(JwtBearerDefaults.AuthenticationScheme)
                .AddJwtBearer(options =>
                {
                    options.Authority = _configuration["Auth:Authority"]; // e.g., https://login.microsoftonline.com/{tenant}/v2.0
                    options.Audience = _configuration["Auth:Audience"]; // e.g., API application ID URI
                    options.RequireHttpsMetadata = env != "Development";

                    options.TokenValidationParameters.ValidIssuer = _configuration["Auth:Issuer"];
                    options.TokenValidationParameters.ValidateIssuer = true;
                    options.TokenValidationParameters.ValidateAudience = true;
                    options.TokenValidationParameters.ValidateLifetime = true;
                    options.TokenValidationParameters.ValidateIssuerSigningKey = true;
                    options.TokenValidationParameters.ClockSkew = TimeSpan.FromMinutes(2);
                });

            // 3. Authorization policies
            services.AddSingleton<IAuthorizationHandler, TenantOrderReadHandler>();
            services.AddAuthorization(options =>
            {
                options.AddPolicy("TenantOrderRead", policy =>
                {
                    policy.RequireAuthenticatedUser();
                    policy.AddRequirements(new TenantOrderReadRequirement());
                });
            });

            services.AddControllers();

            // 4. Rate limiting / throttling via middleware or external gateway (placeholder comment)
        }

        public void Configure(IApplicationBuilder app, IHostEnvironment env, ILogger<Startup> logger)
        {
            if (env.IsDevelopment())
            {
                app.UseDeveloperExceptionPage();
            }
            else
            {
                app.UseHsts();
            }

            // 5. Global error handling & logging
            app.Use(async (context, next) =>
            {
                try
                {
                    await next();
                }
                catch (Exception ex)
                {
                    logger.LogError(ex, "Unhandled exception for {Path}", context.Request.Path);
                    context.Response.StatusCode = StatusCodes.Status500InternalServerError;
                    await context.Response.WriteAsync("An unexpected error occurred.");
                }
            });

            // Basic security headers (for APIs)
            app.Use(async (context, next) =>
            {
                context.Response.Headers["X-Content-Type-Options"] = "nosniff";
                context.Response.Headers["X-Frame-Options"] = "DENY";
                context.Response.Headers["X-XSS-Protection"] = "0";
                await next();
            });

            app.UseRouting();
            app.UseAuthentication();
            app.UseAuthorization();

            app.UseEndpoints(endpoints =>
            {
                endpoints.MapControllers();
            });
        }
    }
}
```

**Defense in Depth Layers**:
1. **Token-level validation (identity provider integration)**:
   - Strict JWT validation in `AddJwtBearer`: validates issuer, audience, signing key, lifetime, and disallows insecure algorithms.
   - Example: `options.TokenValidationParameters.ValidateIssuerSigningKey = true;` ensures only tokens signed by trusted IdPs are accepted.

2. **Centralized, policy-based authorization**:
   - `TenantOrderReadRequirement` and `TenantOrderReadHandler` encapsulate tenant boundary, scopes, and role logic in one place.
   - Controllers simply apply `[Authorize(Policy = "TenantOrderRead")]`, reducing the risk of inconsistent checks.

3. **Runtime monitoring, logging, and secure error handling**:
   - Global middleware captures unhandled exceptions and logs with request path context.
   - Authorization handler logs tenant boundary violations and insufficient permissions for audit and anomaly detection.

**Additional Protections**:
- **Environment-specific configuration**: `RequireHttpsMetadata` and `HSTS` are enforced in non-development environments; auth endpoints and audiences are configured via environment variables or secrets, not hard-coded.
- **Rate limiting and abuse detection**: Apply rate limiting (e.g., via API gateway or middleware) on sensitive endpoints like `/api/tenants/{tenantId}/orders` and monitor for repeated `Forbid()` results from the same IP or user.
- **Data-layer enforcement**: In repositories/ORM queries, always filter on `tenantId` from the validated claim, not from arbitrary input, creating another boundary so even a misconfigured controller cannot leak cross-tenant data.

File uploads are a critical attack surface. The most dangerous vulnerability is path traversal, where attackers manipulate filenames to write files outside your intended upload directory or overwrite critical system files.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const multer = require('multer');
const path = require('path');
const fs = require('fs');

const app = express();

// DANGEROUS: Using user-provided filename directly
const storage = multer.diskStorage({
  destination: './uploads/',
  filename: (req, file, cb) => {
    // Trusting user-provided filename - VULNERABLE!
    cb(null, file.originalname);
  }
});

const upload = multer({ storage: storage });

app.post('/api/upload', upload.single('avatar'), (req, res) => {
  res.json({ message: 'File uploaded', filename: req.file.filename });
});

// DANGEROUS: Path traversal in file download
app.get('/api/files/:filename', (req, res) => {
  const filename = req.params.filename;
  const filepath = path.join('./uploads/', filename);

  // No validation - attacker can read any file!
  res.sendFile(filepath, { root: '.' });
});

app.listen(3000);
```

**Attack Payload**:
```text
Filename: ../../../etc/passwd
Filename: ....//....//....//etc/shadow
Filename: ..\..\..\windows\system32\config\sam
```

**Why This Is Dangerous**:
- Attacker can overwrite critical files like `../../../app/config.js` during upload
- Download endpoint allows reading `/etc/passwd`, `.env` files, or application source code
- Double encoding (`....//`) bypasses naive `../` filters
- On Windows, backslashes (`..\`) provide alternative traversal paths

**SECURE VERSION**:

```javascript
const express = require('express');
const multer = require('multer');
const path = require('path');
const crypto = require('crypto');
const fs = require('fs');

const app = express();

const UPLOAD_DIR = path.resolve('./uploads');
const ALLOWED_EXTENSIONS = ['.jpg', '.jpeg', '.png', '.gif', '.webp'];
const MAX_FILE_SIZE = 5 * 1024 * 1024; // 5MB

// SECURE: Generate random filename, ignore user input
const storage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, UPLOAD_DIR);
  },
  filename: (req, file, cb) => {
    // Generate cryptographically random filename
    const randomName = crypto.randomBytes(16).toString('hex');
    const ext = path.extname(file.originalname).toLowerCase();

    // Validate extension against allowlist
    if (!ALLOWED_EXTENSIONS.includes(ext)) {
      return cb(new Error('Invalid file type'));
    }

    cb(null, `${randomName}${ext}`);
  }
});

const upload = multer({
  storage: storage,
  limits: { fileSize: MAX_FILE_SIZE },
  fileFilter: (req, file, cb) => {
    const ext = path.extname(file.originalname).toLowerCase();
    if (!ALLOWED_EXTENSIONS.includes(ext)) {
      return cb(new Error('Invalid file type'), false);
    }
    cb(null, true);
  }
});

app.post('/api/upload', upload.single('avatar'), (req, res) => {
  if (!req.file) {
    return res.status(400).json({ error: 'No file uploaded' });
  }
  res.json({ message: 'File uploaded', filename: req.file.filename });
});

// SECURE: Validate path stays within upload directory
app.get('/api/files/:filename', (req, res) => {
  const filename = path.basename(req.params.filename); // Strip path components
  const requestedPath = path.resolve(UPLOAD_DIR, filename);

  // Critical: Ensure resolved path is within UPLOAD_DIR
  if (!requestedPath.startsWith(UPLOAD_DIR + path.sep)) {
    console.warn(`Path traversal attempt: ${req.params.filename} from ${req.ip}`);
    return res.status(403).json({ error: 'Access denied' });
  }

  // Verify file exists
  if (!fs.existsSync(requestedPath)) {
    return res.status(404).json({ error: 'File not found' });
  }

  res.sendFile(requestedPath);
});

app.listen(3000);
```

**Key Security Controls**:
- **Random filename generation**: User-provided filenames are completely ignored; we use `crypto.randomBytes()` for unpredictable names
- **Extension allowlist**: Only specific image extensions are permitted, not a denylist
- **Path resolution check**: `path.resolve()` + `startsWith()` ensures the final path stays within the upload directory
- **path.basename()**: Strips all directory components from user input as first line of defense

Great question! Subdirectory organization is common but introduces additional path traversal risks. The key is to never use user-controlled values directly in paths and to always validate the final resolved path.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const multer = require('multer');
const path = require('path');
const crypto = require('crypto');
const fs = require('fs').promises;
const fsSync = require('fs');
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');

const app = express();
app.use(helmet());

// Configuration
const CONFIG = {
  uploadDir: path.resolve(process.env.UPLOAD_DIR || './uploads'),
  allowedExtensions: new Set(['.jpg', '.jpeg', '.png', '.gif', '.webp']),
  allowedMimeTypes: new Set(['image/jpeg', 'image/png', 'image/gif', 'image/webp']),
  maxFileSize: parseInt(process.env.MAX_UPLOAD_SIZE) || 5 * 1024 * 1024,
  maxFilesPerRequest: 5
};

// Rate limiting for upload endpoint
const uploadLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 50, // 50 uploads per window
  message: { error: 'Too many upload attempts' },
  standardHeaders: true,
  legacyHeaders: false
});

// SECURE: Path validation utility
class SecurePath {
  static isWithinDirectory(filePath, directory) {
    const resolvedPath = path.resolve(filePath);
    const resolvedDir = path.resolve(directory);
    return resolvedPath.startsWith(resolvedDir + path.sep);
  }

  static sanitizeFilename(filename) {
    // Remove all path separators and null bytes
    return path.basename(filename)
      .replace(/[\x00-\x1f\x80-\x9f]/g, '') // Control characters
      .replace(/[<>:"|?*\/\\]/g, '')         // Dangerous characters
      .substring(0, 255);                      // Limit length
  }

  static async ensureDirectoryExists(dirPath, baseDir) {
    const resolvedPath = path.resolve(dirPath);

    if (!this.isWithinDirectory(resolvedPath + path.sep, baseDir)) {
      throw new Error('Directory outside allowed base');
    }

    await fs.mkdir(resolvedPath, { recursive: true, mode: 0o755 });
    return resolvedPath;
  }
}

// SECURE: Generate user-specific upload directory
async function getUserUploadDir(userId, baseDir) {
  // Validate userId is numeric/alphanumeric only
  if (!/^[a-zA-Z0-9_-]+$/.test(userId)) {
    throw new Error('Invalid user ID format');
  }

  // Organize by date for easier management
  const now = new Date();
  const datePath = `${now.getFullYear()}/${String(now.getMonth() + 1).padStart(2, '0')}`;

  // Create path: uploads/{userId}/{year}/{month}/
  const userDir = path.join(baseDir, userId, datePath);

  return SecurePath.ensureDirectoryExists(userDir, baseDir);
}

// File type validation with magic bytes
const FILE_SIGNATURES = {
  'ffd8ffe0': 'image/jpeg',
  'ffd8ffe1': 'image/jpeg',
  'ffd8ffe2': 'image/jpeg',
  '89504e47': 'image/png',
  '47494638': 'image/gif',
  '52494646': 'image/webp'
};

async function validateFileType(filePath) {
  const buffer = Buffer.alloc(4);
  const fd = await fs.open(filePath, 'r');
  await fd.read(buffer, 0, 4, 0);
  await fd.close();

  const signature = buffer.toString('hex');
  const mimeType = FILE_SIGNATURES[signature];

  if (!mimeType || !CONFIG.allowedMimeTypes.has(mimeType)) {
    await fs.unlink(filePath); // Delete invalid file
    throw new Error('Invalid file content');
  }

  return mimeType;
}

// Multer configuration
const storage = multer.diskStorage({
  destination: async (req, file, cb) => {
    try {
      // req.user should be set by authentication middleware
      if (!req.user || !req.user.id) {
        return cb(new Error('Authentication required'));
      }

      const uploadDir = await getUserUploadDir(req.user.id, CONFIG.uploadDir);
      cb(null, uploadDir);
    } catch (err) {
      cb(err);
    }
  },
  filename: (req, file, cb) => {
    const randomName = crypto.randomBytes(32).toString('hex');
    const ext = path.extname(file.originalname).toLowerCase();

    if (!CONFIG.allowedExtensions.has(ext)) {
      return cb(new Error('Invalid file extension'));
    }

    cb(null, `${randomName}${ext}`);
  }
});

const upload = multer({
  storage: storage,
  limits: {
    fileSize: CONFIG.maxFileSize,
    files: CONFIG.maxFilesPerRequest
  },
  fileFilter: (req, file, cb) => {
    const ext = path.extname(file.originalname).toLowerCase();

    if (!CONFIG.allowedExtensions.has(ext)) {
      return cb(new Error('Invalid file type'), false);
    }

    if (!CONFIG.allowedMimeTypes.has(file.mimetype)) {
      return cb(new Error('Invalid MIME type'), false);
    }

    cb(null, true);
  }
});

// Upload endpoint with full security controls
app.post('/api/upload',
  uploadLimiter,
  // authMiddleware, // Add your auth middleware
  upload.single('file'),
  async (req, res) => {
    try {
      if (!req.file) {
        return res.status(400).json({ error: 'No file uploaded' });
      }

      // Validate file content matches extension
      await validateFileType(req.file.path);

      // Audit logging
