**Key Security Controls**:
- **Mutual TLS (mTLS)**: Cryptographically verify the calling service's identity using client certificates
- **Service-to-service tokens**: JWT tokens with specific permissions scoped to each service interaction
- **Input re-validation at every boundary**: Never trust data, even from internal services
- **Parameterized queries**: Prevent SQL injection regardless of data source
- **Audit logging**: Track all cross-boundary requests for forensic analysis

Implementing zero-trust architecture across microservices requires explicit trust verification at every interaction point, regardless of network location. This pattern was developed in response to attacks like SolarWinds where implicit internal trust enabled devastating lateral movement.

**PRODUCTION PATTERN**:

```java
import io.jsonwebtoken.*;
import io.jsonwebtoken.security.Keys;
import javax.crypto.SecretKey;
import java.time.Instant;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

/**
 * Zero-Trust Service Mesh Security Gateway
 * Enforces trust boundaries between all service interactions
 */
public class TrustBoundaryGateway {
    private static final Logger securityLog = LoggerFactory.getLogger("SECURITY");
    private static final Logger auditLog = LoggerFactory.getLogger("AUDIT");

    private final ServiceRegistry serviceRegistry;
    private final PolicyEngine policyEngine;
    private final TokenValidator tokenValidator;
    private final RateLimiter rateLimiter;
    private final AnomalyDetector anomalyDetector;

    // Security zone definitions
    public enum SecurityZone {
        DMZ(1),           // External-facing services
        APPLICATION(2),   // Business logic services  
        DATA(3),          // Database access layer
        MANAGEMENT(4);    // Admin/monitoring services

        private final int level;
        SecurityZone(int level) { this.level = level; }
        public int getLevel() { return level; }
    }

    public TrustBoundaryGateway(ServiceRegistry registry, PolicyEngine policy,
                                 TokenValidator validator, RateLimiter limiter,
                                 AnomalyDetector detector) {
        this.serviceRegistry = registry;
        this.policyEngine = policy;
        this.tokenValidator = validator;
        this.rateLimiter = limiter;
        this.anomalyDetector = detector;
    }

    /**
     * Main entry point - validates ALL cross-boundary requests
     */
    public BoundaryValidationResult validateCrossBoundaryRequest(
            ServiceRequest request) {

        String requestId = UUID.randomUUID().toString();
        BoundaryValidationResult result = new BoundaryValidationResult(requestId);

        try {
            // LAYER 1: Rate limiting per service
            if (!rateLimiter.allowRequest(request.getSourceService())) {
                securityLog.warn("[{}] Rate limit exceeded: {}", 
                    requestId, request.getSourceService());
                return result.deny("RATE_LIMIT_EXCEEDED");
            }

            // LAYER 2: Mutual TLS certificate validation
            CertificateValidation certResult = validateServiceCertificate(request);
            if (!certResult.isValid()) {
                securityLog.error("[{}] Certificate validation failed: {}", 
                    requestId, certResult.getReason());
                return result.deny("INVALID_CERTIFICATE");
            }

            // LAYER 3: Service identity token validation
            TokenValidation tokenResult = tokenValidator.validate(
                request.getServiceToken(),
                request.getSourceService(),
                request.getTargetService()
            );
            if (!tokenResult.isValid()) {
                securityLog.error("[{}] Token validation failed: {}", 
                    requestId, tokenResult.getReason());
                return result.deny("INVALID_TOKEN");
            }

            // LAYER 4: Zone crossing policy check
            ZoneCrossingResult zoneResult = validateZoneCrossing(
                request.getSourceZone(),
                request.getTargetZone(),
                request.getOperation()
            );
            if (!zoneResult.isAllowed()) {
                securityLog.error("[{}] Zone crossing denied: {} -> {}", 
                    requestId, request.getSourceZone(), request.getTargetZone());
                return result.deny("ZONE_CROSSING_DENIED");
            }

            // LAYER 5: Operation-level authorization
            AuthorizationResult authResult = policyEngine.authorize(
                tokenResult.getServiceContext(),
                request.getOperation(),
                request.getResource()
            );
            if (!authResult.isAuthorized()) {
                securityLog.warn("[{}] Authorization denied: {} for {}", 
                    requestId, request.getSourceService(), request.getOperation());
                return result.deny("UNAUTHORIZED_OPERATION");
            }

            // LAYER 6: Payload validation at boundary
            PayloadValidation payloadResult = validatePayloadAtBoundary(
                request.getPayload(),
                request.getTargetZone(),
                request.getOperation()
            );
            if (!payloadResult.isValid()) {
                securityLog.warn("[{}] Payload validation failed: {}", 
                    requestId, payloadResult.getViolations());
                return result.deny("PAYLOAD_VALIDATION_FAILED");
            }

            // LAYER 7: Anomaly detection
            if (anomalyDetector.isAnomalous(request)) {
                securityLog.warn("[{}] Anomalous request pattern detected", requestId);
                // Don't immediately block, but flag for review and add friction
                result.addFlag("ANOMALY_DETECTED");
                result.requireAdditionalVerification();
            }

            // All checks passed - allow with context
            result.allow(tokenResult.getServiceContext());

            auditLog.info("[{}] Cross-boundary request allowed: {} -> {} op={}",
                requestId, request.getSourceService(), 
                request.getTargetService(), request.getOperation());

            return result;

        } catch (Exception e) {
            securityLog.error("[{}] Validation error", requestId, e);
            return result.deny("VALIDATION_ERROR");
        }
    }

    /**
     * Zone crossing policy enforcement
     */
    private ZoneCrossingResult validateZoneCrossing(
            SecurityZone source, SecurityZone target, String operation) {

        // Rule 1: DMZ can only communicate with APPLICATION zone
        if (source == SecurityZone.DMZ && target != SecurityZone.APPLICATION) {
            return ZoneCrossingResult.denied(
                "DMZ services can only access APPLICATION zone");
        }

        // Rule 2: Only APPLICATION zone can access DATA zone
        if (target == SecurityZone.DATA && source != SecurityZone.APPLICATION) {
            return ZoneCrossingResult.denied(
                "Only APPLICATION services can access DATA zone");
        }

        // Rule 3: MANAGEMENT zone requires elevated privileges
        if (target == SecurityZone.MANAGEMENT) {
            return ZoneCrossingResult.requiresElevation(
                "MANAGEMENT zone requires additional authentication");
        }

        // Rule 4: No zone can skip levels (defense in depth)
        int levelDiff = Math.abs(source.getLevel() - target.getLevel());
        if (levelDiff > 1) {
            return ZoneCrossingResult.denied(
                "Direct zone skipping not allowed");
        }

        return ZoneCrossingResult.allowed();
    }

    /**
     * Validates and sanitizes payload at trust boundary
     */
    private PayloadValidation validatePayloadAtBoundary(
            Object payload, SecurityZone targetZone, String operation) {

        PayloadValidation validation = new PayloadValidation();

        if (payload == null) {
            return validation; // Empty payload is valid for some operations
        }

        // Validate payload structure
        if (payload instanceof Map) {
            Map<String, Object> data = (Map<String, Object>) payload;

            // Check for injection attempts in all string values
            for (Map.Entry<String, Object> entry : data.entrySet()) {
                if (entry.getValue() instanceof String) {
                    String value = (String) entry.getValue();

                    // SQL injection patterns
                    if (containsSqlInjection(value)) {
                        validation.addViolation(entry.getKey(), "SQL_INJECTION_PATTERN");
                    }

                    // Command injection patterns  
                    if (containsCommandInjection(value)) {
                        validation.addViolation(entry.getKey(), "COMMAND_INJECTION_PATTERN");
                    }

                    // Path traversal patterns
                    if (containsPathTraversal(value)) {
                        validation.addViolation(entry.getKey(), "PATH_TRAVERSAL_PATTERN");
                    }
                }

                // Validate nested objects recursively
                if (entry.getValue() instanceof Map) {
                    PayloadValidation nested = validatePayloadAtBoundary(
                        entry.getValue(), targetZone, operation);
                    validation.merge(nested);
                }
            }
        }

        // Zone-specific validation rules
        if (targetZone == SecurityZone.DATA) {
            // Stricter validation for data zone
            validation.merge(validateForDataZone(payload));
        }

        return validation;
    }

    private boolean containsSqlInjection(String value) {
        String lower = value.toLowerCase();
        return lower.contains("union") || lower.contains("select") ||
               lower.contains("drop") || lower.contains("delete") ||
               lower.contains("insert") || lower.contains("update") ||
               value.contains("'") || value.contains("--") ||
               value.contains(";");
    }

    private boolean containsCommandInjection(String value) {
        return value.contains("|") || value.contains(";") ||
               value.contains("`") || value.contains("$(") ||
               value.contains("&&") || value.contains("||");
    }

    private boolean containsPathTraversal(String value) {
        return value.contains("..") || value.contains("%2e%2e") ||
               value.contains("%252e");
    }

    private PayloadValidation validateForDataZone(Object payload) {
        // Additional strict validation for data zone access
        return new PayloadValidation();
    }

    private CertificateValidation validateServiceCertificate(ServiceRequest request) {
        // Verify mTLS client certificate
        return new CertificateValidation(true, null);
    }
}

/**
 * Service-to-Service Token Generator with Scoped Permissions
 */
public class ServiceTokenGenerator {
    private final SecretKey signingKey;
    private final String issuer;
    private static final long TOKEN_VALIDITY_SECONDS = 300; // 5 minutes max

    public ServiceTokenGenerator(String keySecret, String issuer) {
        this.signingKey = Keys.hmacShaKeyFor(keySecret.getBytes());
        this.issuer = issuer;
    }

    public String generateServiceToken(
            String sourceService,
            String targetService,
            Set<String> permissions,
            Map<String, Object> context) {

        Instant now = Instant.now();

        return Jwts.builder()
            .setIssuer(issuer)
            .setSubject(sourceService)
            .setAudience(targetService)
            .setIssuedAt(Date.from(now))
            .setExpiration(Date.from(now.plusSeconds(TOKEN_VALIDITY_SECONDS)))
            .setId(UUID.randomUUID().toString())
            .claim("permissions", permissions)
            .claim("source_zone", context.get("zone"))
            .claim("correlation_id", context.get("correlationId"))
            .claim("original_user", context.get("userId")) // Preserve user context
            .signWith(signingKey, SignatureAlgorithm.HS512)
            .compact();
    }
}

