    private $uploadDir = '/var/www/uploads/';

    public function processUpload($file) {
        $filename = $this->uploadDir . basename($file['name']);
        move_uploaded_file($file['tmp_name'], $filename);

        // VULNERABLE: Processes image and follows external references
        $imageData = $this->extractMetadata($filename);

        // VULNERABLE: Fetches URL from image metadata without validation
        if (isset($imageData['source_url'])) {
            $content = file_get_contents($imageData['source_url']);
            $this->cacheExternalResource($content);
        }

        // VULNERABLE: SVG files can contain external entity references
        if ($this->isSvg($filename)) {
            $this->processSvg($filename);
        }

        return $imageData;
    }

    private function processSvg($filename) {
        // VULNERABLE: Loads SVG which may contain external references
        $doc = new DOMDocument();
        $doc->load($filename);  // Follows external entities!
        return $doc->saveXML();
    }

    private function extractMetadata($filename) {
        // Extract EXIF and process any URLs found
        $exif = exif_read_data($filename);
        return $exif;
    }

    private function isSvg($filename) {
