```

**Why This Is Dangerous**:
- SVG files can contain XXE payloads that fetch internal resources
- Image metadata (EXIF/XMP) can contain malicious URLs that get fetched
- `file_get_contents()` on user-controlled URLs enables SSRF to internal services
- AWS/GCP/Azure metadata endpoints (169.254.169.254) can expose credentials
- Internal APIs and services become accessible through the server

**SECURE VERSION**:

```php
<?php
class SecureImageProcessor {
    private $uploadDir = '/var/www/uploads/';
    private $allowedMimeTypes = ['image/jpeg', 'image/png', 'image/gif', 'image/webp'];
    private $maxFileSize = 10485760; // 10MB

    public function processUpload($file) {
        // Validate file before processing
        $this->validateUpload($file);

        // Generate safe filename
        $extension = $this->getSafeExtension($file);
        $filename = $this->uploadDir . bin2hex(random_bytes(16)) . '.' . $extension;

        move_uploaded_file($file['tmp_name'], $filename);

        // Extract metadata safely without following URLs
        $metadata = $this->extractMetadataSafely($filename);

        // Never fetch external URLs from uploaded content
        // If needed, queue for async processing with strict validation

        return [
            'filename' => basename($filename),
            'metadata' => $metadata
        ];
    }

    private function validateUpload($file) {
        if ($file['error'] !== UPLOAD_ERR_OK) {
            throw new InvalidArgumentException('Upload failed');
        }

        if ($file['size'] > $this->maxFileSize) {
            throw new InvalidArgumentException('File too large');
        }

        // Verify actual MIME type, not just extension
        $finfo = new finfo(FILEINFO_MIME_TYPE);
        $mimeType = $finfo->file($file['tmp_name']);

        if (!in_array($mimeType, $this->allowedMimeTypes, true)) {
            throw new InvalidArgumentException('Invalid file type: ' . $mimeType);
        }

        // Block SVG files entirely due to XXE risks
        if (stripos($mimeType, 'svg') !== false) {
            throw new InvalidArgumentException('SVG files not allowed');
        }

        // Verify image is actually valid
        $imageInfo = @getimagesize($file['tmp_name']);
        if ($imageInfo === false) {
            throw new InvalidArgumentException('Invalid image file');
        }
    }

    private function getSafeExtension($file) {
        $finfo = new finfo(FILEINFO_MIME_TYPE);
        $mimeType = $finfo->file($file['tmp_name']);

        $mimeToExt = [
            'image/jpeg' => 'jpg',
            'image/png' => 'png',
            'image/gif' => 'gif',
            'image/webp' => 'webp'
        ];

        return $mimeToExt[$mimeType] ?? 'bin';
    }

    private function extractMetadataSafely($filename) {
        // Only extract safe metadata fields
        $safeFields = ['Width', 'Height', 'MimeType', 'DateTime'];
        $exif = @exif_read_data($filename);

        if (!$exif) {
            return [];
        }

        $safeMetadata = [];
        foreach ($safeFields as $field) {
            if (isset($exif[$field])) {
                // Sanitize the value
                $safeMetadata[$field] = htmlspecialchars(
                    substr((string)$exif[$field], 0, 255),
                    ENT_QUOTES,
                    'UTF-8'
                );
            }
        }

        return $safeMetadata;
    }
}
```

**Key Security Controls**:
- **File type validation**: Verifies actual MIME type using finfo, not just extension
- **SVG blocking**: Completely blocks SVG files which can contain XXE payloads
- **No external URL fetching**: Never follows URLs found in uploaded content
- **Safe metadata extraction**: Only extracts whitelisted, sanitized metadata fields
- **Random filenames**: Prevents path traversal and predictable file locations

When you must process SVG files or fetch external resources, you need multiple security layers including sandboxing, strict URL validation, and network-level controls.

**PRODUCTION PATTERN**:

```php
<?php
declare(strict_types=1);

class ProductionImageProcessor {
    private string $uploadDir;
    private array $allowedMimeTypes;
    private UrlValidator $urlValidator;
    private SvgSanitizer $svgSanitizer;
    private HttpClient $httpClient;
    private LoggerInterface $logger;
    private MetricsCollector $metrics;

    public function __construct(
        string $uploadDir,
        UrlValidator $urlValidator,
        SvgSanitizer $svgSanitizer,
        HttpClient $httpClient,
        LoggerInterface $logger,
        MetricsCollector $metrics
    ) {
        $this->uploadDir = $uploadDir;
        $this->urlValidator = $urlValidator;
        $this->svgSanitizer = $svgSanitizer;
        $this->httpClient = $httpClient;
        $this->logger = $logger;
        $this->metrics = $metrics;
        $this->allowedMimeTypes = [
            'image/jpeg', 'image/png', 'image/gif', 
            'image/webp', 'image/svg+xml'
        ];
    }

    public function processUpload(array $file, string $userId): array {
        $startTime = microtime(true);

        try {
            $this->validateUpload($file);

            $mimeType = $this->getVerifiedMimeType($file['tmp_name']);
            $safeFilename = $this->generateSafeFilename($mimeType);
            $fullPath = $this->uploadDir . $safeFilename;

            if ($mimeType === 'image/svg+xml') {
                // Process SVG through sanitizer before saving
                $sanitizedContent = $this->processSvgSecurely($file['tmp_name']);
                file_put_contents($fullPath, $sanitizedContent);
            } else {
                move_uploaded_file($file['tmp_name'], $fullPath);
                // Re-encode raster images to strip malicious metadata
                $this->reencodeImage($fullPath, $mimeType);
            }

            $this->logger->info('Image processed', [
                'user_id' => $userId,
                'filename' => $safeFilename,
                'mime_type' => $mimeType,
                'size' => filesize($fullPath)
            ]);

            $this->metrics->increment('image.processed.success');

            return [
                'success' => true,
                'filename' => $safeFilename,
                'processing_time' => microtime(true) - $startTime
            ];

        } catch (SecurityException $e) {
            $this->logger->warning('Security violation in upload', [
                'user_id' => $userId,
                'error' => $e->getMessage(),
                'file_info' => $this->getSafeFileInfo($file)
            ]);
            $this->metrics->increment('image.processed.security_blocked');
            throw $e;
        }
    }

    private function processSvgSecurely(string $tempPath): string {
        $content = file_get_contents($tempPath);

        // Create DOM with external entities disabled
        $doc = new DOMDocument();
        $doc->resolveExternals = false;
        $doc->substituteEntities = false;

        // Disable external entity loading entirely
        $previousValue = libxml_disable_entity_loader(true);
        libxml_use_internal_errors(true);

        try {
            // Load with strict options
            $loaded = $doc->loadXML($content, 
                LIBXML_NONET | LIBXML_NOENT | LIBXML_DTDLOAD | LIBXML_DTDATTR
            );

            if (!$loaded) {
                throw new SecurityException('Invalid SVG structure');
            }

            // Use dedicated sanitizer to remove dangerous elements
            $sanitized = $this->svgSanitizer->sanitize($doc);

            return $sanitized;

        } finally {
            libxml_disable_entity_loader($previousValue);
            libxml_clear_errors();
        }
    }

    public function fetchExternalResourceSecurely(
        string $url, 
        string $userId,
        string $purpose
    ): ?array {
        // Validate URL before any network request
        $validationResult = $this->urlValidator->validate($url);

        if (!$validationResult->isValid()) {
            $this->logger->warning('Blocked SSRF attempt', [
                'user_id' => $userId,
                'url' => $this->sanitizeUrlForLog($url),
                'reason' => $validationResult->getReason(),
                'purpose' => $purpose
            ]);
            $this->metrics->increment('ssrf.blocked');
            return null;
        }

        try {
            // Use restricted HTTP client
            $response = $this->httpClient->get($url, [
                'timeout' => 5,
                'max_redirects' => 0,  // No redirects to prevent SSRF bypass
                'verify_ssl' => true
            ]);

            // Validate response content type
            $contentType = $response->getHeader('Content-Type')[0] ?? '';
            if (!$this->isAllowedContentType($contentType)) {
                throw new SecurityException('Disallowed content type: ' . $contentType);
            }

            // Limit response size
            $body = $response->getBody();
            if (strlen($body) > 10485760) { // 10MB limit
                throw new SecurityException('Response too large');
            }

            $this->logger->info('External resource fetched', [
                'user_id' => $userId,
                'url_host' => parse_url($url, PHP_URL_HOST),
                'content_type' => $contentType,
                'size' => strlen($body)
            ]);

            return [
                'content' => $body,
                'content_type' => $contentType
            ];

        } catch (\Exception $e) {
            $this->logger->error('External fetch failed', [
                'user_id' => $userId,
                'error' => $e->getMessage()
            ]);
            return null;
        }
    }

    private function reencodeImage(string $path, string $mimeType): void {
        // Re-encode image to strip all metadata including potential payloads
        $image = match($mimeType) {
            'image/jpeg' => imagecreatefromjpeg($path),
            'image/png' => imagecreatefrompng($path),
            'image/gif' => imagecreatefromgif($path),
            'image/webp' => imagecreatefromwebp($path),
            default => throw new InvalidArgumentException('Unsupported type')
        };

        if (!$image) {
            throw new SecurityException('Failed to process image');
        }

        // Save without metadata
        match($mimeType) {
            'image/jpeg' => imagejpeg($image, $path, 90),
            'image/png' => imagepng($image, $path, 9),
            'image/gif' => imagegif($image, $path),
            'image/webp' => imagewebp($image, $path, 90)
        };

        imagedestroy($image);
    }

    private function generateSafeFilename(string $mimeType): string {
        $extensions = [
            'image/jpeg' => 'jpg',
            'image/png' => 'png',
            'image/gif' => 'gif',
            'image/webp' => 'webp',
            'image/svg+xml' => 'svg'
        ];

        return bin2hex(random_bytes(16)) . '.' . $extensions[$mimeType];
    }

    private function sanitizeUrlForLog(string $url): string {
        // Only log scheme and host to prevent log injection
        $parsed = parse_url($url);
        return ($parsed['scheme'] ?? 'unknown') . '://' . 
               ($parsed['host'] ?? 'unknown');
    }
}

class UrlValidator {
    private array $blockedNetworks = [
        '127.0.0.0/8',      // Localhost
        '10.0.0.0/8',       // Private
        '172.16.0.0/12',    // Private
        '192.168.0.0/16',   // Private
        '169.254.0.0/16',   // Link-local (AWS/GCP metadata!)
        '100.64.0.0/10',    // Carrier-grade NAT
        '0.0.0.0/8',        // Current network
        '224.0.0.0/4',      // Multicast
        '240.0.0.0/4',      // Reserved
        'fd00::/8',         // IPv6 private
        '::1/128',          // IPv6 localhost
        'fe80::/10',        // IPv6 link-local
    ];

    private array $allowedSchemes = ['https'];
    private array $blockedHosts = [
        'metadata.google.internal',
        'metadata.azure.com',
        'localhost',
        '*.local'
    ];

    public function validate(string $url): ValidationResult {
        $parsed = parse_url($url);

        // Validate scheme
        $scheme = strtolower($parsed['scheme'] ?? '');
        if (!in_array($scheme, $this->allowedSchemes, true)) {
            return new ValidationResult(false, 'Invalid scheme: ' . $scheme);
        }

        $host = $parsed['host'] ?? '';

        // Check for blocked hosts
        foreach ($this->blockedHosts as $blockedHost) {
            if ($this->matchesPattern($host, $blockedHost)) {
                return new ValidationResult(false, 'Blocked host');
            }
        }

        // Resolve DNS and check IP
        $ips = gethostbynamel($host);
        if (!$ips) {
            return new ValidationResult(false, 'DNS resolution failed');
        }

        foreach ($ips as $ip) {
            if ($this->isBlockedIp($ip)) {
                return new ValidationResult(false, 'IP in blocked range');
            }
        }

        // Check for DNS rebinding by re-resolving
        usleep(100000); // 100ms delay
        $ipsRecheck = gethostbynamel($host);
        if ($ips !== $ipsRecheck) {
            return new ValidationResult(false, 'DNS rebinding detected');
        }

        return new ValidationResult(true);
    }

    private function isBlockedIp(string $ip): bool {
        foreach ($this->blockedNetworks as $cidr) {
            if ($this->ipInCidr($ip, $cidr)) {
                return true;
            }
        }
        return false;
    }

    private function ipInCidr(string $ip, string $cidr): bool {
        list($subnet, $bits) = explode('/', $cidr);

        if (filter_var($ip, FILTER_VALIDATE_IP, FILTER_FLAG_IPV4)) {
            $ip = ip2long($ip);
            $subnet = ip2long($subnet);
            $mask = -1 << (32 - (int)$bits);
            return ($ip & $mask) === ($subnet & $mask);
        }

        return false;
    }

    private function matchesPattern(string $host, string $pattern): bool {
        if (str_starts_with($pattern, '*.')) {
            $suffix = substr($pattern, 1);
            return str_ends_with($host, $suffix);
        }
        return $host === $pattern;
    }
}

class SvgSanitizer {
    private array $allowedElements = [
        'svg', 'g', 'path', 'rect', 'circle', 'ellipse',
        'line', 'polyline', 'polygon', 'text', 'tspan',
        'defs', 'clipPath', 'mask', 'linearGradient',
        'radialGradient', 'stop', 'use', 'symbol'
    ];

    private array $dangerousElements = [
        'script', 'foreignObject', 'iframe', 'object',
        'embed', 'link', 'style', 'image', 'animate',
        'set', 'animateTransform', 'animateMotion'
    ];

    public function sanitize(DOMDocument $doc): string {
        $xpath = new DOMXPath($doc);

        // Remove all dangerous elements
        foreach ($this->dangerousElements as $tagName) {
            $nodes = $xpath->query('//' . $tagName);
            foreach ($nodes as $node) {
                $node->parentNode->removeChild($node);
            }
        }

        // Remove event handlers and dangerous attributes
        $allElements = $xpath->query('//*');
        foreach ($allElements as $element) {
            $attributesToRemove = [];

            foreach ($element->attributes as $attr) {
                $name = strtolower($attr->name);

                // Block event handlers
                if (str_starts_with($name, 'on')) {
                    $attributesToRemove[] = $attr->name;
                }

                // Block href/xlink:href with javascript:
                if (in_array($name, ['href', 'xlink:href'])) {
                    if (preg_match('/^\s*javascript:/i', $attr->value)) {
                        $attributesToRemove[] = $attr->name;
                    }
                }
            }

            foreach ($attributesToRemove as $attrName) {
                $element->removeAttribute($attrName);
            }
        }

        return $doc->saveXML();
    }
}

class ValidationResult {
    public function __construct(
        private bool $valid,
        private string $reason = ''
    ) {}

    public function isValid(): bool { return $this->valid; }
    public function getReason(): string { return $this->reason; }
}

class SecurityException extends \Exception {}
