      timestamp: new Date().toISOString()
    }));

    return sessionId; // Return unhashed ID to client
  }

  async validateSession(sessionId, metadata = {}) {
    const sessionKey = this.hashSessionId(sessionId);
    const data = await this.redis.get(`session:${sessionKey}`);

    if (!data) {
      return { valid: false, reason: 'session_not_found' };
    }

    const session = JSON.parse(data);

    // Check for session binding (optional strict mode)
    if (session.fingerprint) {
      const currentFingerprint = await this.generateFingerprint(metadata);
      if (!this.timingSafeCompare(session.fingerprint, currentFingerprint)) {
        // Possible session hijacking
        console.warn(JSON.stringify({
          event: 'session_fingerprint_mismatch',
          userId: session.userId,
          ip: metadata.ip,
          timestamp: new Date().toISOString()
        }));
        // Optionally invalidate session here
      }
    }

    // Rotate session ID if needed (sliding window)
    if (Date.now() - session.lastRotated > this.rotationInterval) {
      return await this.rotateSession(sessionId, session, metadata);
    }

    return { valid: true, userId: session.userId, sessionId };
  }

  async rotateSession(oldSessionId, sessionData, metadata) {
    // Generate new session ID
    const newSessionId = await SecureTokenGenerator.generateSessionId();
    const oldKey = this.hashSessionId(oldSessionId);
    const newKey = this.hashSessionId(newSessionId);

    sessionData.lastRotated = Date.now();

    // Atomic rotation
    const multi = this.redis.multi();
    multi.setex(`session:${newKey}`, this.sessionTTL, JSON.stringify(sessionData));
    multi.del(`session:${oldKey}`);
    multi.srem(`user:${sessionData.userId}:sessions`, oldKey);
    multi.sadd(`user:${sessionData.userId}:sessions`, newKey);
    await multi.exec();

    return { valid: true, userId: sessionData.userId, sessionId: newSessionId, rotated: true };
  }

  hashSessionId(sessionId) {
    return crypto.createHash('sha256').update(sessionId).digest('hex');
  }

  async generateFingerprint(metadata) {
    const data = `${metadata.userAgent || ''}|${metadata.acceptLanguage || ''}`;
    return crypto.createHash('sha256').update(data).digest('hex').substring(0, 16);
  }

  timingSafeCompare(a, b) {
    if (a.length !== b.length) return false;
    return crypto.timingSafeEqual(Buffer.from(a), Buffer.from(b));
  }

  async enforceSessionLimit(userId) {
    const sessions = await this.redis.smembers(`user:${userId}:sessions`);
    if (sessions.length > this.maxSessions) {
      // Remove oldest sessions
      const toRemove = sessions.slice(0, sessions.length - this.maxSessions);
      const multi = this.redis.multi();
      for (const sessionKey of toRemove) {
        multi.del(`session:${sessionKey}`);
        multi.srem(`user:${userId}:sessions`, sessionKey);
      }
      await multi.exec();
    }
  }

  async invalidateAllSessions(userId) {
    const sessions = await this.redis.smembers(`user:${userId}:sessions`);
    const multi = this.redis.multi();
    for (const sessionKey of sessions) {
      multi.del(`session:${sessionKey}`);
    }
    multi.del(`user:${userId}:sessions`);
    await multi.exec();

    console.log(JSON.stringify({
      event: 'all_sessions_invalidated',
      userId,
      count: sessions.length,
      timestamp: new Date().toISOString()
    }));
  }
}

module.exports = { SecureTokenGenerator, SecureSessionManager };
```

**Defense in Depth Layers**:

1. **Cryptographic randomness at every layer**:
```javascript
// Always use crypto module, never Math.random()
const crypto = require('crypto');

// For synchronous contexts (startup code only)
const syncToken = crypto.randomBytes(32).toString('hex');

// For async contexts (preferred in production)
const asyncToken = await promisify(crypto.randomBytes)(32);
```

2. **Token hashing before storage**:
```javascript
// Never store raw tokens in database
const storedValue = crypto
  .createHash('sha256')
  .update(rawToken)
  .digest('hex');

// On validation, hash the incoming token and compare
function validateToken(inputToken, storedHash) {
  const inputHash = crypto
    .createHash('sha256')
    .update(inputToken)
    .digest('hex');
  return crypto.timingSafeEqual(
    Buffer.from(inputHash),
    Buffer.from(storedHash)
  );
}
```

3. **Timing-safe comparisons**:
```javascript
// WRONG: Vulnerable to timing attacks
if (userToken === storedToken) { /* ... */ }

// CORRECT: Constant-time comparison
function secureCompare(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;
  if (a.length !== b.length) return false;
  return crypto.timingSafeEqual(Buffer.from(a), Buffer.from(b));
}
```

**Additional Protections**:
- **Rate limiting**: Limit token validation attempts to prevent brute force
- **Token expiration**: Always set TTLs, never use permanent tokens for sensitive operations
- **Audit logging**: Log all token generation and validation for forensics
- **Session binding**: Optionally bind sessions to IP/user-agent fingerprint
- **Automatic rotation**: Rotate long-lived tokens periodically to limit exposure window
- **Secure transmission**: Always use HTTPS, set Secure flag on session cookies

Allowing users to specify file paths directly is extremely dangerous and leads to path traversal attacks. This was exploited in the 2024 Fortinet vulnerability (CVE-2024-21762) that affected 150,000+ devices.

**VULNERABLE CODE**:

```csharp
using System.IO;
using Microsoft.AspNetCore.Mvc;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FileController : ControllerBase
    {
        private readonly string _baseDirectory = @"C:\AppFiles\Documents";

        [HttpGet("download")]
        public IActionResult DownloadFile([FromQuery] string filename)
        {
            // VULNERABLE: User input directly concatenated to path
            string filePath = Path.Combine(_baseDirectory, filename);

            if (!System.IO.File.Exists(filePath))
            {
                return NotFound("File not found");
            }

            // Attacker can read ANY file on the server
            byte[] fileBytes = System.IO.File.ReadAllBytes(filePath);
            return File(fileBytes, "application/octet-stream", filename);
        }
    }
}
```

**Attack Payload**:
```text
GET /api/file/download?filename=..\..\..\..\Windows\System32\config\SAM
GET /api/file/download?filename=....//....//....//etc/passwd
GET /api/file/download?filename=..%5C..%5C..%5Cweb.config
```

**Why This Is Dangerous**:
- `Path.Combine()` does NOT prevent traversal - it happily combines "../" sequences
- Attackers can read sensitive files like `web.config`, SAM database, SSH keys
- URL encoding bypasses naive string filters (`%2e%2e%2f` = `../`)
- Different OS path separators (`/` vs `\`) may bypass validation

**SECURE VERSION**:

```csharp
using System;
using System.IO;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class FileController : ControllerBase
    {
        private readonly string _baseDirectory = @"C:\AppFiles\Documents";
        private readonly ILogger<FileController> _logger;

        public FileController(ILogger<FileController> logger)
        {
            _logger = logger;
        }

        [HttpGet("download")]
        public IActionResult DownloadFile([FromQuery] string filename)
        {
            // SECURITY: Validate filename is not null or empty
            if (string.IsNullOrWhiteSpace(filename))
            {
                return BadRequest("Filename is required");
            }

            // SECURITY: Extract only the filename, strip any path components
            string safeFilename = Path.GetFileName(filename);

            // SECURITY: Reject if GetFileName returned different value (path was included)
            if (safeFilename != filename || string.IsNullOrEmpty(safeFilename))
            {
                _logger.LogWarning("Path traversal attempt detected: {Filename} from {IP}", 
                    filename, HttpContext.Connection.RemoteIpAddress);
                return BadRequest("Invalid filename");
            }

            // SECURITY: Build full path and verify it's within allowed directory
            string fullPath = Path.GetFullPath(Path.Combine(_baseDirectory, safeFilename));
            string canonicalBase = Path.GetFullPath(_baseDirectory);

            if (!fullPath.StartsWith(canonicalBase, StringComparison.OrdinalIgnoreCase))
            {
                _logger.LogWarning("Path escape attempt: {Path} from {IP}", 
                    fullPath, HttpContext.Connection.RemoteIpAddress);
                return BadRequest("Invalid filename");
            }

            if (!System.IO.File.Exists(fullPath))
            {
                return NotFound("File not found");
            }

            byte[] fileBytes = System.IO.File.ReadAllBytes(fullPath);
            return File(fileBytes, "application/octet-stream", safeFilename);
        }
    }
}
```

**Key Security Controls**:
- `Path.GetFileName()` strips directory components, returning only the filename portion
- `Path.GetFullPath()` resolves all traversal sequences to get the canonical absolute path
- `StartsWith()` check ensures the resolved path is still within the allowed directory
- Audit logging captures attack attempts with source IP for incident response

Supporting subdirectories requires additional validation since you can't simply use `Path.GetFileName()`. Here's a production-ready pattern with comprehensive defense in depth.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.IO;
using System.Text.RegularExpressions;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Authorization;
using Microsoft.Extensions.Logging;
using Microsoft.AspNetCore.RateLimiting;

namespace MyApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize]
    public class SecureFileController : ControllerBase
    {
        private readonly string _baseDirectory;
        private readonly ILogger<SecureFileController> _logger;
        private static readonly Regex AllowedPathPattern = 
            new Regex(@"^[a-zA-Z0-9_\-/]+\.[a-zA-Z0-9]+$", RegexOptions.Compiled);
        private static readonly string[] AllowedExtensions = 
            { ".pdf", ".docx", ".xlsx", ".txt", ".png", ".jpg" };

        public SecureFileController(
            ILogger<SecureFileController> logger,
            IConfiguration config)
        {
            _logger = logger;
            _baseDirectory = Path.GetFullPath(
                config["FileStorage:BasePath"] ?? @"C:\AppFiles\Documents");
        }

        [HttpGet("download")]
        [EnableRateLimiting("FileDownload")]
        public IActionResult DownloadFile([FromQuery] string path)
        {
            var userId = User.FindFirst("sub")?.Value ?? "anonymous";

            try
            {
                // LAYER 1: Input presence validation
                if (string.IsNullOrWhiteSpace(path))
                {
                    return BadRequest(new { error = "Path is required" });
                }

                // LAYER 2: Normalize path separators to forward slash
                string normalizedPath = path.Replace('\\', '/');

                // LAYER 3: Block obvious traversal patterns before any processing
                if (ContainsTraversalPatterns(normalizedPath))
                {
                    _logger.LogWarning(
                        "Blocked traversal attempt. User: {User}, Path: {Path}, IP: {IP}",
                        userId, path, HttpContext.Connection.RemoteIpAddress);
                    return BadRequest(new { error = "Invalid path" });
                }

                // LAYER 4: Whitelist validation - only allowed characters
                if (!AllowedPathPattern.IsMatch(normalizedPath))
                {
                    _logger.LogWarning(
                        "Invalid path characters. User: {User}, Path: {Path}",
                        userId, path);
                    return BadRequest(new { error = "Invalid path format" });
                }

                // LAYER 5: Extension whitelist
                string extension = Path.GetExtension(normalizedPath).ToLowerInvariant();
                if (!Array.Exists(AllowedExtensions, ext => ext == extension))
                {
                    _logger.LogWarning(
                        "Blocked extension. User: {User}, Extension: {Ext}",
                        userId, extension);
                    return BadRequest(new { error = "File type not allowed" });
                }

                // LAYER 6: Canonical path resolution and containment check
                string requestedFullPath = Path.GetFullPath(
                    Path.Combine(_baseDirectory, normalizedPath));

                if (!IsPathWithinBase(requestedFullPath, _baseDirectory))
                {
                    _logger.LogCritical(
                        "PATH ESCAPE DETECTED! User: {User}, Attempted: {Path}, Resolved: {Full}",
                        userId, path, requestedFullPath);

                    // Alert security team for critical attempts
                    // await _alertService.SendSecurityAlert(...);

                    return BadRequest(new { error = "Access denied" });
                }

                // LAYER 7: File existence check
                if (!System.IO.File.Exists(requestedFullPath))
                {
                    return NotFound(new { error = "File not found" });
                }

                // LAYER 8: Authorization check - verify user can access this file
                if (!CanUserAccessFile(userId, normalizedPath))
                {
                    _logger.LogWarning(
                        "Unauthorized file access. User: {User}, Path: {Path}",
                        userId, normalizedPath);
                    return Forbid();
                }

                // Success - log and serve file
                _logger.LogInformation(
                    "File download. User: {User}, Path: {Path}, Size: {Size}",
                    userId, normalizedPath, new FileInfo(requestedFullPath).Length);

                var stream = new FileStream(
                    requestedFullPath, FileMode.Open, FileAccess.Read, FileShare.Read);
                string contentType = GetContentType(extension);
                string downloadName = Path.GetFileName(requestedFullPath);

                return File(stream, contentType, downloadName);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, 
                    "File download error. User: {User}, Path: {Path}", userId, path);
                return StatusCode(500, new { error = "An error occurred" });
            }
        }

        private static bool ContainsTraversalPatterns(string path)
        {
            string[] dangerousPatterns = {
                "..", "...", ".../", "...\\",
                "%2e", "%252e",  // URL encoded dots
                "%00", "\0",     // Null bytes
                ":",              // Alternate data streams (Windows)
            };

            string lowerPath = path.ToLowerInvariant();
            foreach (var pattern in dangerousPatterns)
            {
                if (lowerPath.Contains(pattern))
                    return true;
            }
            return false;
        }

        private static bool IsPathWithinBase(string fullPath, string basePath)
        {
            // Ensure both paths end consistently for comparison
            string normalizedBase = Path.GetFullPath(basePath).TrimEnd(Path.DirectorySeparatorChar) 
                + Path.DirectorySeparatorChar;
            string normalizedFull = Path.GetFullPath(fullPath);

            return normalizedFull.StartsWith(normalizedBase, StringComparison.OrdinalIgnoreCase);
        }

        private bool CanUserAccessFile(string userId, string relativePath)
        {
            // Implement your authorization logic here
            // Example: Check if user owns file, has department access, etc.
            // This prevents horizontal privilege escalation
            return true; // Placeholder
        }

        private static string GetContentType(string extension)
        {
            return extension switch
            {
                ".pdf" => "application/pdf",
                ".docx" => "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
                ".xlsx" => "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
                ".txt" => "text/plain",
                ".png" => "image/png",
                ".jpg" => "image/jpeg",
                _ => "application/octet-stream"
            };
        }
    }
}
```

**Defense in Depth Layers**:
1. **Input Validation**: Reject empty/null input immediately
2. **Path Normalization**: Convert all separators to consistent format
3. **Pattern Blocking**: Detect traversal sequences including encoded variants
4. **Whitelist Regex**: Only allow alphanumeric, underscore, hyphen, forward slash
5. **Extension Whitelist**: Prevent access to config files, executables
6. **Canonical Path Check**: Resolve path and verify containment
7. **Existence Check**: Verify file exists
8. **Authorization Check**: Verify user is allowed to access specific file

