Parameter pollution attacks exploit inconsistent handling of duplicate HTTP parameters across different layers of your application. When authorization decisions are based on parameter values, attackers can inject duplicate parameters to bypass security checks.

**VULNERABLE CODE**:

```java
import javax.servlet.http.*;
import javax.servlet.*;
import java.io.*;
import java.sql.*;

public class UserDataServlet extends HttpServlet {
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws ServletException, IOException {

        // VULNERABLE: Using getParameter which returns only first value
        String userId = request.getParameter("userId");
        String sessionUserId = (String) request.getSession().getAttribute("userId");

        // Authorization check based on single parameter value
        if (!userId.equals(sessionUserId)) {
            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Access denied");
            return;
        }

        // Fetch user data - but what if multiple userId params were sent?
        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            // Backend might use different parameter (last value)
            String query = "SELECT * FROM user_data WHERE user_id = ?";
            PreparedStatement stmt = conn.prepareStatement(query);
            stmt.setString(1, userId);
            ResultSet rs = stmt.executeQuery();

            // Return data...
            response.getWriter().write("User data retrieved");
        } catch (SQLException e) {
            response.sendError(500, "Database error");
        }
    }
}
```

**Attack Payload**:
```text
GET /api/userData?userId=100&userId=999 HTTP/1.1
Host: vulnerable-app.com
Cookie: JSESSIONID=abc123

# Attacker's session has userId=100
# First parameter (100) passes authorization check
# If backend/database layer uses last parameter (999), attacker accesses victim's data
```

**Why This Is Dangerous**:
- `getParameter()` returns only the first parameter value, but other components may use different values
- Load balancers, API gateways, and databases may process parameters differently (first vs last vs array)
- Authorization check passes with legitimate userId, but data retrieval may use attacker-controlled value
- No validation that only one parameter instance exists

**SECURE VERSION**:

```java
import javax.servlet.http.*;
import javax.servlet.*;
import java.io.*;
import java.sql.*;
import java.util.logging.Logger;

public class SecureUserDataServlet extends HttpServlet {
    private static final Logger LOGGER = Logger.getLogger(SecureUserDataServlet.class.getName());
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws ServletException, IOException {

        // SECURE: Check for parameter pollution
        String[] userIdValues = request.getParameterValues("userId");

        if (userIdValues == null || userIdValues.length == 0) {
            LOGGER.warning("Missing userId parameter from IP: " + request.getRemoteAddr());
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Missing userId");
            return;
        }

        // DEFENSE 1: Reject duplicate parameters
        if (userIdValues.length > 1) {
            LOGGER.warning("Parameter pollution attempt detected from IP: " + 
                          request.getRemoteAddr() + " - Multiple userId values: " + 
                          String.join(", ", userIdValues));
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Duplicate parameters not allowed");
            return;
        }

        String userId = userIdValues[0];

        // DEFENSE 2: Validate parameter format
        if (!userId.matches("^[0-9]{1,10}$")) {
            LOGGER.warning("Invalid userId format from IP: " + request.getRemoteAddr());
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid userId format");
            return;
        }

        // DEFENSE 3: Get authenticated user ID from secure session only
        HttpSession session = request.getSession(false);
        if (session == null) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Session required");
            return;
        }

        Integer sessionUserId = (Integer) session.getAttribute("authenticatedUserId");
        if (sessionUserId == null) {
            response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Not authenticated");
            return;
        }

        // DEFENSE 4: Authorization - use session userId for data access, not request parameter
        // Don't trust client-provided userId at all for authorization
        try (Connection conn = DriverManager.getConnection(DB_URL, DB_USER, DB_PASS)) {
            String query = "SELECT * FROM user_data WHERE user_id = ?";
            PreparedStatement stmt = conn.prepareStatement(query);
            stmt.setInt(1, sessionUserId);  // Use ONLY session-stored ID
            ResultSet rs = stmt.executeQuery();

            LOGGER.info("Data accessed by userId: " + sessionUserId);
            response.getWriter().write("User data retrieved securely");
        } catch (SQLException e) {
            LOGGER.severe("Database error for user: " + sessionUserId);
            response.sendError(500, "Internal error");
        }
    }
}
```

**Key Security Controls**:
- **Duplicate parameter detection**: Using `getParameterValues()` to check for and reject multiple values
- **Server-side identity**: Using session-stored authenticated userId instead of trusting request parameters
- **Input validation**: Strict regex validation on parameter format before processing
- **Audit logging**: Recording parameter pollution attempts for security monitoring

Role-based access with parameter pollution protection requires a layered approach that validates parameters, verifies roles, and maintains strict audit trails. Here's a production-ready pattern:

**PRODUCTION PATTERN**:

```java
import javax.servlet.http.*;
import javax.servlet.*;
import javax.servlet.annotation.WebServlet;
import java.io.*;
import java.sql.*;
import java.util.*;
import java.util.logging.Logger;
import java.time.Instant;

@WebServlet("/api/user/*")
public class SecureUserAccessServlet extends HttpServlet {
    private static final Logger LOGGER = Logger.getLogger(SecureUserAccessServlet.class.getName());
    private static final Logger AUDIT_LOGGER = Logger.getLogger("SECURITY_AUDIT");
    private static final String DB_URL = "jdbc:postgresql://localhost/userdb";
    private static final String DB_USER = "appuser";
    private static final String DB_PASS = "password";

    // Define allowed parameters to prevent injection of unexpected params
    private static final Set<String> ALLOWED_PARAMS = Set.of("userId", "fields", "format");

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) 
            throws ServletException, IOException {

        String requestId = UUID.randomUUID().toString();
        String clientIp = getClientIp(request);

        try {
            // LAYER 1: Parameter pollution detection for ALL parameters
            ParameterValidationResult paramResult = validateParameters(request);
            if (!paramResult.isValid()) {
                AUDIT_LOGGER.warning(String.format(
                    "[%s] PARAMETER_POLLUTION ip=%s reason=%s params=%s",
                    requestId, clientIp, paramResult.getReason(), paramResult.getDetails()));
                response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid request parameters");
                return;
            }

            // LAYER 2: Session validation
            AuthenticatedUser currentUser = getAuthenticatedUser(request);
            if (currentUser == null) {
                response.sendError(HttpServletResponse.SC_UNAUTHORIZED, "Authentication required");
                return;
            }

            // LAYER 3: Extract and validate target userId
            String targetUserIdStr = request.getParameter("userId");
            int targetUserId;

            if (targetUserIdStr == null || targetUserIdStr.isEmpty()) {
                // Default: user accesses their own data
                targetUserId = currentUser.getUserId();
            } else {
                try {
                    targetUserId = Integer.parseInt(targetUserIdStr);
                    if (targetUserId <= 0 || targetUserId > 999999999) {
                        throw new NumberFormatException("Out of range");
                    }
                } catch (NumberFormatException e) {
                    AUDIT_LOGGER.warning(String.format(
                        "[%s] INVALID_USERID ip=%s user=%d attempted=%s",
                        requestId, clientIp, currentUser.getUserId(), targetUserIdStr));
                    response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid user ID");
                    return;
                }
            }

            // LAYER 4: Role-based authorization check
            AccessDecision decision = checkAccess(currentUser, targetUserId);

            if (!decision.isAllowed()) {
                AUDIT_LOGGER.warning(String.format(
                    "[%s] ACCESS_DENIED ip=%s user=%d role=%s target=%d reason=%s",
                    requestId, clientIp, currentUser.getUserId(), 
                    currentUser.getRole(), targetUserId, decision.getReason()));
                response.sendError(HttpServletResponse.SC_FORBIDDEN, "Access denied");
                return;
            }

            // LAYER 5: Fetch data with audit trail
            UserData userData = fetchUserData(targetUserId, decision.getAllowedFields());

            // LAYER 6: Audit successful access
            AUDIT_LOGGER.info(String.format(
                "[%s] DATA_ACCESS ip=%s user=%d role=%s target=%d fields=%s",
                requestId, clientIp, currentUser.getUserId(),
                currentUser.getRole(), targetUserId, decision.getAllowedFields()));

            response.setContentType("application/json");
            response.getWriter().write(userData.toJson());

        } catch (Exception e) {
            LOGGER.severe(String.format("[%s] ERROR: %s", requestId, e.getMessage()));
            response.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR, "Internal error");
        }
    }

    private ParameterValidationResult validateParameters(HttpServletRequest request) {
        Map<String, String[]> params = request.getParameterMap();

        for (Map.Entry<String, String[]> entry : params.entrySet()) {
            String paramName = entry.getKey();
            String[] values = entry.getValue();

            // Check for unexpected parameters
            if (!ALLOWED_PARAMS.contains(paramName)) {
                return new ParameterValidationResult(false, 
                    "Unexpected parameter", paramName);
            }

            // Check for duplicate parameters (pollution)
            if (values.length > 1) {
                return new ParameterValidationResult(false,
                    "Duplicate parameter detected", 
                    paramName + "=" + Arrays.toString(values));
            }

            // Check for parameter value anomalies
            String value = values[0];
            if (value.contains("&") || value.contains("=")) {
                return new ParameterValidationResult(false,
                    "Parameter value contains URL characters", paramName);
            }
        }

        return new ParameterValidationResult(true, null, null);
    }

    private AccessDecision checkAccess(AuthenticatedUser user, int targetUserId) {
        // Self-access always allowed with full fields
        if (user.getUserId() == targetUserId) {
            return new AccessDecision(true, "SELF_ACCESS", 
