// SecurePageController.java - Modern templating without SSI
import javax.servlet.http.*;
import java.io.*;
import java.util.regex.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecurePageController extends HttpServlet {

    private static final Logger logger = LoggerFactory.getLogger(SecurePageController.class);
    private static final Pattern SSI_PATTERN = Pattern.compile(
        "<!--\\s*#(include|exec|echo|config|fsize|flastmod|printenv).*?-->",
        Pattern.CASE_INSENSITIVE | Pattern.DOTALL);
    private static final Pattern SAFE_USERNAME = Pattern.compile("^[a-zA-Z0-9_-]{1,50}$");

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response)
            throws IOException {

        String username = request.getParameter("user");

        // INPUT VALIDATION: Strict allowlist for username
        if (username == null || !SAFE_USERNAME.matcher(username).matches()) {
            logger.warn("Invalid username attempted: {} from IP: {}", 
                sanitizeForLog(username), request.getRemoteAddr());
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid username");
            return;
        }

        // DEFENSE IN DEPTH: Check for SSI injection attempts
        if (containsSSIDirectives(username)) {
            logger.error("SSI injection attempt detected from IP: {}", 
                request.getRemoteAddr());
            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Invalid input detected");
            return;
        }

        // Use HTML encoding for output
        String safeUsername = encodeHtml(username);

        response.setContentType("text/html;charset=UTF-8");
        response.setHeader("X-Content-Type-Options", "nosniff");
        response.setHeader("Content-Security-Policy", "default-src 'self'");

        try (PrintWriter out = response.getWriter()) {
            out.println("<html><body>");
            out.println("<h1>Welcome, " + safeUsername + "</h1>");
            out.println("</body></html>");
        }
    }

    private boolean containsSSIDirectives(String input) {
        if (input == null) return false;
        return SSI_PATTERN.matcher(input).find();
    }

    private String encodeHtml(String input) {
        if (input == null) return "";
        return input.replace("&", "&amp;")
                    .replace("<", "&lt;")
                    .replace(">", "&gt;")
                    .replace("\"", "&quot;")
                    .replace("'", "&#x27;");
    }

    private String sanitizeForLog(String input) {
        if (input == null) return "null";
        return input.replaceAll("[\\r\\n]", "_").substring(0, Math.min(input.length(), 100));
    }
}
```

**Key Security Controls**:
- **Disable SSI entirely**: Modern applications should use proper templating engines (Thymeleaf, FreeMarker) instead of SSI
- **allowExec=false**: Never allow command execution through SSI directives
- **isVirtualWebappRelative=true**: Restricts file inclusion to the webapp context only
- **Input validation**: Strict allowlist patterns reject SSI injection attempts before processing
- **Defense in depth**: Multiple layers including HTML encoding and SSI pattern detection

When SSI is absolutely required for legacy compatibility, you need multiple layers of protection including WAF rules, content filtering, strict file permissions, and comprehensive monitoring.

**PRODUCTION PATTERN**:

```java
// SecureSSIFilter.java - Servlet filter to protect SSI processing
package com.example.security.filters;

import javax.servlet.*;
import javax.servlet.http.*;
import javax.servlet.annotation.WebFilter;
import java.io.*;
import java.util.regex.*;
import java.util.*;
import java.time.Instant;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import io.micrometer.core.instrument.Counter;
import io.micrometer.core.instrument.MeterRegistry;

@WebFilter(urlPatterns = {"/ssi-content/*", "*.shtml"})
public class SecureSSIFilter implements Filter {

    private static final Logger logger = LoggerFactory.getLogger(SecureSSIFilter.class);
    private static final Logger securityAudit = LoggerFactory.getLogger("SECURITY_AUDIT");

    // SSI directive patterns for detection
    private static final Pattern SSI_EXEC_PATTERN = Pattern.compile(
        "<!--\\s*#exec\\s+", Pattern.CASE_INSENSITIVE);
    private static final Pattern SSI_INCLUDE_PATTERN = Pattern.compile(
        "<!--\\s*#include\\s+(virtual|file)\\s*=\\s*[\"']([^\"']+)[\"']", 
        Pattern.CASE_INSENSITIVE);
    private static final Pattern PATH_TRAVERSAL_PATTERN = Pattern.compile(
        "(\\.\\./|\\.\\.\\\\|%2e%2e%2f|%2e%2e/|\\.\\.%2f|%2e%2e%5c)", 
        Pattern.CASE_INSENSITIVE);

    // Allowed include paths (whitelist)
    private static final Set<String> ALLOWED_INCLUDE_PATHS = new HashSet<>(Arrays.asList(
        "/ssi-content/headers/",
        "/ssi-content/footers/",
        "/ssi-content/common/"
    ));

    private Counter ssiBlockedCounter;
    private Counter ssiAllowedCounter;
    private boolean enabled = true;

    @Override
    public void init(FilterConfig filterConfig) throws ServletException {
        String enabledParam = filterConfig.getInitParameter("enabled");
        this.enabled = enabledParam == null || Boolean.parseBoolean(enabledParam);

        // Initialize metrics (assuming Spring Boot with Micrometer)
        try {
            ServletContext ctx = filterConfig.getServletContext();
            MeterRegistry registry = (MeterRegistry) ctx.getAttribute("meterRegistry");
            if (registry != null) {
                ssiBlockedCounter = Counter.builder("security.ssi.blocked")
                    .description("SSI requests blocked by security filter")
                    .register(registry);
                ssiAllowedCounter = Counter.builder("security.ssi.allowed")
                    .description("SSI requests allowed through filter")
                    .register(registry);
            }
        } catch (Exception e) {
            logger.warn("Could not initialize metrics: {}", e.getMessage());
        }

        logger.info("SecureSSIFilter initialized, enabled={}", enabled);
    }

    @Override
    public void doFilter(ServletRequest request, ServletResponse response, 
                        FilterChain chain) throws IOException, ServletException {

        if (!enabled) {
            chain.doFilter(request, response);
            return;
        }

        HttpServletRequest httpRequest = (HttpServletRequest) request;
        HttpServletResponse httpResponse = (HttpServletResponse) response;

        String requestId = UUID.randomUUID().toString();
        String clientIP = getClientIP(httpRequest);
        String requestURI = httpRequest.getRequestURI();

        // LAYER 1: Check for path traversal in URL
        if (containsPathTraversal(requestURI)) {
            logSecurityEvent(requestId, clientIP, "PATH_TRAVERSAL", requestURI);
            incrementBlocked();
            httpResponse.sendError(HttpServletResponse.SC_FORBIDDEN, "Access denied");
            return;
        }

        // LAYER 2: Check query parameters for SSI injection
        if (checkParametersForSSI(httpRequest, requestId, clientIP)) {
            incrementBlocked();
            httpResponse.sendError(HttpServletResponse.SC_FORBIDDEN, "Invalid input");
            return;
        }

        // LAYER 3: Wrap response to filter SSI content
        SSIContentFilterWrapper responseWrapper = new SSIContentFilterWrapper(httpResponse);

        try {
            chain.doFilter(request, responseWrapper);

            // LAYER 4: Validate SSI content before sending to client
            String content = responseWrapper.getCapturedContent();
            if (content != null) {
                ValidationResult result = validateSSIContent(content);

                if (!result.isValid()) {
                    logSecurityEvent(requestId, clientIP, "SSI_CONTENT_VIOLATION", 
                        result.getViolation());
                    incrementBlocked();
                    httpResponse.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR);
                    return;
                }

                // Content is safe, write to actual response
                response.setContentType(responseWrapper.getContentType());
                response.getWriter().write(content);
            }

            incrementAllowed();

        } catch (Exception e) {
            logger.error("Error processing SSI request: {}", e.getMessage());
            httpResponse.sendError(HttpServletResponse.SC_INTERNAL_SERVER_ERROR);
        }
    }

    private boolean checkParametersForSSI(HttpServletRequest request, 
                                          String requestId, String clientIP) {
        Enumeration<String> paramNames = request.getParameterNames();

        while (paramNames.hasMoreElements()) {
            String paramName = paramNames.nextElement();
            String[] values = request.getParameterValues(paramName);

            for (String value : values) {
                if (SSI_EXEC_PATTERN.matcher(value).find()) {
                    logSecurityEvent(requestId, clientIP, "SSI_EXEC_INJECTION", 
                        "param=" + paramName);
                    return true;
                }

                Matcher includeMatcher = SSI_INCLUDE_PATTERN.matcher(value);
                if (includeMatcher.find()) {
                    String includePath = includeMatcher.group(2);
                    if (!isAllowedIncludePath(includePath)) {
                        logSecurityEvent(requestId, clientIP, "SSI_INCLUDE_INJECTION", 
                            "param=" + paramName + ", path=" + includePath);
                        return true;
                    }
                }

                if (containsPathTraversal(value)) {
                    logSecurityEvent(requestId, clientIP, "PATH_TRAVERSAL_PARAM", 
                        "param=" + paramName);
                    return true;
                }
            }
        }
        return false;
    }

    private ValidationResult validateSSIContent(String content) {
        // Check for exec directives (should never be in output)
        if (SSI_EXEC_PATTERN.matcher(content).find()) {
            return new ValidationResult(false, "Exec directive found in content");
        }

        // Validate all include paths
        Matcher includeMatcher = SSI_INCLUDE_PATTERN.matcher(content);
        while (includeMatcher.find()) {
            String includePath = includeMatcher.group(2);
            if (!isAllowedIncludePath(includePath)) {
                return new ValidationResult(false, 
                    "Unauthorized include path: " + includePath);
            }
        }

        return new ValidationResult(true, null);
    }

    private boolean isAllowedIncludePath(String path) {
        if (path == null) return false;
        String normalizedPath = path.toLowerCase().trim();

        // Reject path traversal
        if (containsPathTraversal(normalizedPath)) return false;

        // Check against whitelist
        for (String allowed : ALLOWED_INCLUDE_PATHS) {
            if (normalizedPath.startsWith(allowed)) {
                return true;
            }
        }
        return false;
    }

    private boolean containsPathTraversal(String input) {
        if (input == null) return false;
        return PATH_TRAVERSAL_PATTERN.matcher(input).find();
    }

    private String getClientIP(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private void logSecurityEvent(String requestId, String clientIP, 
                                  String eventType, String details) {
        securityAudit.warn("SSI_SECURITY_EVENT | request_id={} | client_ip={} | " +
            "event_type={} | details={} | timestamp={}",
            requestId, clientIP, eventType, 
            sanitizeLogInput(details), Instant.now().toString());
    }

    private String sanitizeLogInput(String input) {
        if (input == null) return "null";
        return input.replaceAll("[\\r\\n\\t]", "_")
                    .substring(0, Math.min(input.length(), 200));
    }

    private void incrementBlocked() {
        if (ssiBlockedCounter != null) ssiBlockedCounter.increment();
    }

    private void incrementAllowed() {
        if (ssiAllowedCounter != null) ssiAllowedCounter.increment();
    }

    @Override
    public void destroy() {
        logger.info("SecureSSIFilter destroyed");
    }

    // Inner class for validation results
    private static class ValidationResult {
        private final boolean valid;
        private final String violation;

        ValidationResult(boolean valid, String violation) {
            this.valid = valid;
            this.violation = violation;
        }

        boolean isValid() { return valid; }
        String getViolation() { return violation; }
    }
}
```

