Excellent question! Multi-role authorization requires a robust Role-Based Access Control (RBAC) system with clear permission boundaries. Here's a production-ready pattern that handles horizontal escalation prevention across different privilege levels.

**PRODUCTION PATTERN**:

```python
from flask import Flask, request, jsonify, abort, g
from functools import wraps
from enum import Enum
from typing import Optional, List, Callable
import sqlite3
import logging
import time
from dataclasses import dataclass

app = Flask(__name__)
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger(__name__)

class Role(Enum):
    CUSTOMER = "customer"
    SUPPORT_AGENT = "support_agent"
    SUPPORT_SUPERVISOR = "support_supervisor"
    ADMIN = "admin"

class Permission(Enum):
    VIEW_OWN_ORDERS = "view_own_orders"
    VIEW_ASSIGNED_ORDERS = "view_assigned_orders"
    VIEW_ALL_ORDERS = "view_all_orders"
    VIEW_CUSTOMER_PII = "view_customer_pii"
    MODIFY_ORDERS = "modify_orders"
    EXPORT_DATA = "export_data"

# Role-Permission mapping with principle of least privilege
ROLE_PERMISSIONS = {
    Role.CUSTOMER: {
        Permission.VIEW_OWN_ORDERS
    },
    Role.SUPPORT_AGENT: {
        Permission.VIEW_OWN_ORDERS,
        Permission.VIEW_ASSIGNED_ORDERS,
    },
    Role.SUPPORT_SUPERVISOR: {
        Permission.VIEW_OWN_ORDERS,
        Permission.VIEW_ASSIGNED_ORDERS,
        Permission.VIEW_ALL_ORDERS,
        Permission.VIEW_CUSTOMER_PII,
    },
    Role.ADMIN: {
        Permission.VIEW_OWN_ORDERS,
        Permission.VIEW_ALL_ORDERS,
        Permission.VIEW_CUSTOMER_PII,
        Permission.MODIFY_ORDERS,
        Permission.EXPORT_DATA,
    },
}

@dataclass
class User:
    id: int
    email: str
    role: Role
    assigned_customer_ids: List[int]  # For support agents

    def has_permission(self, permission: Permission) -> bool:
        return permission in ROLE_PERMISSIONS.get(self.role, set())

    def can_access_customer(self, customer_id: int) -> bool:
        """Check if user can access a specific customer's data"""
        if self.has_permission(Permission.VIEW_ALL_ORDERS):
            return True
        if customer_id == self.id:
            return True
        if (self.has_permission(Permission.VIEW_ASSIGNED_ORDERS) and 
            customer_id in self.assigned_customer_ids):
            return True
        return False

def require_auth(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        user = get_current_user_from_token()
        if not user:
            abort(401, description="Authentication required")
        g.current_user = user
        return f(*args, **kwargs)
    return decorated

def require_permission(permission: Permission):
    """Decorator to check specific permission"""
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            if not g.current_user.has_permission(permission):
                log_security_event(
                    "PERMISSION_DENIED",
                    user_id=g.current_user.id,
                    attempted_permission=permission.value,
                    endpoint=request.endpoint
                )
                abort(403, description="Insufficient permissions")
            return f(*args, **kwargs)
        return decorated
    return decorator

def log_security_event(event_type: str, **kwargs):
    """Centralized security event logging for SIEM integration"""
    event = {
        "timestamp": time.time(),
        "event_type": event_type,
        "ip_address": request.remote_addr,
        "user_agent": request.user_agent.string,
        "endpoint": request.endpoint,
        "method": request.method,
        **kwargs
    }
    logger.warning(f"SECURITY_EVENT: {event}")

class OrderService:
    def __init__(self, db_path: str = 'orders.db'):
        self.db_path = db_path

    def get_connection(self):
        conn = sqlite3.connect(self.db_path)
        conn.row_factory = sqlite3.Row
        return conn

    def get_order_with_authorization(self, order_id: int, user: User) -> Optional[dict]:
        """Fetch order with multi-level authorization check"""
        conn = self.get_connection()
        cursor = conn.cursor()

        # First, fetch order to check ownership
        cursor.execute(
            "SELECT o.*, c.id as customer_id FROM orders o "
            "JOIN customers c ON o.customer_id = c.id "
            "WHERE o.id = ?",
            (order_id,)
        )
        order = cursor.fetchone()
        conn.close()

        if not order:
            return None

        order_dict = dict(order)
        customer_id = order_dict['customer_id']

        # Authorization check based on role
        if not user.can_access_customer(customer_id):
            log_security_event(
                "HORIZONTAL_ESCALATION_ATTEMPT",
                user_id=user.id,
                user_role=user.role.value,
                requested_order_id=order_id,
                order_owner_id=customer_id
            )
            return None  # Return None, not 403, to prevent enumeration

        # Redact PII if user lacks permission
        if not user.has_permission(Permission.VIEW_CUSTOMER_PII):
            order_dict = self._redact_pii(order_dict)

        log_security_event(
            "ORDER_ACCESSED",
            user_id=user.id,
            user_role=user.role.value,
            order_id=order_id,
            access_reason=self._get_access_reason(user, customer_id)
        )

        return order_dict

    def _redact_pii(self, order: dict) -> dict:
        """Mask sensitive fields for users without PII permission"""
        redacted = order.copy()
        pii_fields = ['email', 'phone', 'address', 'payment_method_last4']
        for field in pii_fields:
            if field in redacted and redacted[field]:
                redacted[field] = self._mask_field(field, redacted[field])
        return redacted

    def _mask_field(self, field_name: str, value: str) -> str:
        """Mask sensitive data appropriately"""
        if field_name == 'email':
            parts = value.split('@')
            return f"{parts[0][:2]}***@{parts[1]}" if len(parts) == 2 else "***"
        elif field_name == 'phone':
            return f"***-***-{value[-4:]}" if len(value) >= 4 else "***"
        return "[REDACTED]"

    def _get_access_reason(self, user: User, customer_id: int) -> str:
        """Document why access was granted for audit trail"""
        if user.id == customer_id:
            return "own_data"
        if customer_id in user.assigned_customer_ids:
            return "assigned_customer"
        if user.has_permission(Permission.VIEW_ALL_ORDERS):
            return "admin_access"
        return "unknown"

order_service = OrderService()

@app.route('/api/orders/<int:order_id>', methods=['GET'])
@require_auth
def get_order(order_id: int):
    """Fetch order with role-based access control"""
    order = order_service.get_order_with_authorization(
        order_id, 
        g.current_user
    )

    if not order:
        # Consistent 404 prevents enumeration attacks
        abort(404, description="Order not found")

    return jsonify(order)

@app.route('/api/customers/<int:customer_id>/orders', methods=['GET'])
@require_auth
def get_customer_orders(customer_id: int):
    """List all orders for a customer - requires appropriate access"""
    if not g.current_user.can_access_customer(customer_id):
        log_security_event(
            "UNAUTHORIZED_CUSTOMER_ACCESS",
            user_id=g.current_user.id,
            requested_customer_id=customer_id
        )
        abort(404, description="Customer not found")

    # Fetch orders with same authorization logic
    orders = order_service.get_orders_for_customer(customer_id, g.current_user)
    return jsonify({"orders": orders, "count": len(orders)})

@app.route('/api/admin/orders/export', methods=['POST'])
@require_auth
@require_permission(Permission.EXPORT_DATA)
def export_all_orders():
    """Admin-only bulk export with additional security"""
    # Additional verification for sensitive operations
    if not request.headers.get('X-Admin-Verification'):
        log_security_event(
            "ADMIN_VERIFICATION_MISSING",
            user_id=g.current_user.id,
            endpoint="export_all_orders"
        )
        abort(403, description="Additional verification required")

    log_security_event(
        "BULK_EXPORT_INITIATED",
        user_id=g.current_user.id,
        user_role=g.current_user.role.value
    )

    # Implementation of export with rate limiting
    return jsonify({"status": "export_queued", "job_id": "..."})
