**Defense in Depth Layers**:

1. **Authentication Layer**: Verify user identity before any authorization check
```python
@require_auth  # Always applied first
def any_endpoint():
    # g.current_user is guaranteed to exist
    pass
```

2. **Permission Layer**: Check role-based permissions for the action type
```python
@require_permission(Permission.VIEW_ALL_ORDERS)
def admin_endpoint():
    # Only users with explicit permission reach here
    pass
```

3. **Resource Ownership Layer**: Verify user can access the specific resource
```python
if not user.can_access_customer(customer_id):
    return None  # Fails closed
```

4. **Data Redaction Layer**: Minimize exposed data based on permissions
```python
if not user.has_permission(Permission.VIEW_CUSTOMER_PII):
    order_dict = self._redact_pii(order_dict)
```

**Additional Protections**:

- **Uniform error responses**: Always return 404 for both "not found" and "not authorized" to prevent resource enumeration
- **Comprehensive audit logging**: Every access attempt is logged with user, role, resource, and outcome for SIEM/SOC analysis
- **Assigned customer model**: Support agents can only access explicitly assigned customers, preventing lateral movement
- **PII redaction by default**: Sensitive data is masked unless user has explicit PII permission
- **Sensitive operation verification**: High-risk actions like bulk export require additional verification headers
- **Immutable role definitions**: Permission mappings are defined in code, not database, preventing privilege escalation via data manipulation

Your code is vulnerable to LDAP injection, which allows attackers to bypass authentication or extract sensitive directory information. LDAP injection is similar to SQL injection but targets directory services like Active Directory.

**VULNERABLE CODE**:

```php
<?php
class LdapAuthenticator {
    private $ldapHost = 'ldap://dc.company.com';
    private $ldapPort = 389;
    private $baseDn = 'DC=company,DC=com';

    public function authenticate($username, $password) {
        $ldapConn = ldap_connect($this->ldapHost, $this->ldapPort);

        if (!$ldapConn) {
            return false;
        }

        ldap_set_option($ldapConn, LDAP_OPT_PROTOCOL_VERSION, 3);
        ldap_set_option($ldapConn, LDAP_OPT_REFERRALS, 0);

        // VULNERABLE: User input directly in LDAP filter
        $filter = "(&(uid=$username)(userPassword=$password))";

        $searchResult = ldap_search($ldapConn, $this->baseDn, $filter);

        if ($searchResult) {
            $entries = ldap_get_entries($ldapConn, $searchResult);
            if ($entries['count'] > 0) {
                return true;  // Authentication successful
            }
        }

        ldap_close($ldapConn);
        return false;
    }
}

// Usage
$auth = new LdapAuthenticator();
if ($auth->authenticate($_POST['username'], $_POST['password'])) {
    session_start();
    $_SESSION['authenticated'] = true;
}
?>
```

**Attack Payload**:
```text
Username: *)(uid=*))(|(uid=*
Password: anything

Or for authentication bypass:
Username: admin)(&)
Password: anything

Resulting malicious filter:
(&(uid=admin)(&))(userPassword=anything))
```

**Why This Is Dangerous**:
- **Authentication Bypass**: Attacker can login as any user without knowing their password
- **Information Disclosure**: Attackers can craft filters to enumerate users, groups, and attributes
- **Privilege Escalation**: Bypassing authentication to gain admin access to systems
- **Data Exfiltration**: LDAP queries can reveal sensitive organizational structure and user data

**SECURE VERSION**:

```php
<?php
class SecureLdapAuthenticator {
    private $ldapHost = 'ldaps://dc.company.com';  // Use LDAPS
    private $ldapPort = 636;
    private $baseDn = 'DC=company,DC=com';
    private $serviceAccount = 'CN=ldap_service,OU=ServiceAccounts,DC=company,DC=com';
    private $servicePassword;

    public function __construct() {
        $this->servicePassword = getenv('LDAP_SERVICE_PASSWORD');
    }

    /**
     * Escape special LDAP characters to prevent injection
     */
    private function escapeLdapFilter($input) {
        // LDAP filter special characters that must be escaped
        $specialChars = array('\\', '*', '(', ')', '\0', '/');
        $escapedChars = array('\5c', '\2a', '\28', '\29', '\00', '\2f');
        return str_replace($specialChars, $escapedChars, $input);
    }

    /**
     * Validate username format before LDAP query
     */
    private function validateUsername($username) {
        // Allow only alphanumeric, dots, underscores, hyphens
        if (!preg_match('/^[a-zA-Z0-9._-]{3,50}$/', $username)) {
            return false;
        }
        return true;
    }

    public function authenticate($username, $password) {
        // Input validation first
        if (!$this->validateUsername($username)) {
            error_log("Invalid username format attempted: " . substr($username, 0, 50));
            return false;
        }

        if (empty($password) || strlen($password) > 256) {
            return false;
        }

        $ldapConn = ldap_connect($this->ldapHost, $this->ldapPort);

        if (!$ldapConn) {
            error_log("LDAP connection failed");
            return false;
        }

        ldap_set_option($ldapConn, LDAP_OPT_PROTOCOL_VERSION, 3);
        ldap_set_option($ldapConn, LDAP_OPT_REFERRALS, 0);

        // Bind with service account first
        if (!@ldap_bind($ldapConn, $this->serviceAccount, $this->servicePassword)) {
            error_log("Service account bind failed");
            ldap_close($ldapConn);
            return false;
        }

        // SECURE: Escape LDAP special characters
        $safeUsername = $this->escapeLdapFilter($username);
        $filter = "(uid={$safeUsername})";

        // Search for user DN only (don't include password in filter)
        $searchResult = @ldap_search($ldapConn, $this->baseDn, $filter, array('dn'));

        if (!$searchResult) {
            ldap_close($ldapConn);
            return false;
        }

        $entries = ldap_get_entries($ldapConn, $searchResult);

        if ($entries['count'] !== 1) {
            ldap_close($ldapConn);
            return false;
        }

        $userDn = $entries[0]['dn'];

        // SECURE: Authenticate by binding as the user
        $authResult = @ldap_bind($ldapConn, $userDn, $password);

        ldap_close($ldapConn);

        if ($authResult) {
            error_log("Successful authentication for user: " . $safeUsername);
        }

        return $authResult;
    }
}
?>
```

**Key Security Controls**:
- **LDAP Character Escaping**: Special characters (*, (, ), \, NUL, /) are escaped to prevent filter manipulation
- **Input Validation**: Username format validated with strict regex before any LDAP operation
- **Bind Authentication**: Instead of checking password in filter, authenticate by binding as the user (the secure LDAP pattern)
- **Service Account Separation**: Use dedicated service account for searches, then bind as user for authentication

Complex LDAP searches with multiple user-controlled attributes require careful handling. Here's a production-ready pattern with comprehensive protections.

**PRODUCTION PATTERN**:

```php
<?php

class ProductionLdapService {
    private $ldapConn;
    private $config;
    private $logger;
    private $rateLimiter;

    // Whitelist of searchable attributes
    private const SEARCHABLE_ATTRIBUTES = [
        'department' => 'departmentNumber',
        'location' => 'l',
        'title' => 'title',
        'email' => 'mail',
        'name' => 'cn'
    ];

    // Whitelist of retrievable attributes
    private const RETRIEVABLE_ATTRIBUTES = [
        'cn', 'mail', 'telephoneNumber', 'department', 'title', 'l'
    ];

    public function __construct(array $config, $logger, $rateLimiter) {
        $this->config = $config;
        $this->logger = $logger;
        $this->rateLimiter = $rateLimiter;
    }

    /**
     * RFC 4515 compliant LDAP filter escaping
     */
    private function escapeLdapFilterValue($value) {
        $escapeChars = [
            '\\' => '\5c',
            '*'  => '\2a',
            '('  => '\28',
            ')'  => '\29',
            "\x00" => '\00',
            '/'  => '\2f'
        ];

        $escaped = str_replace(
            array_keys($escapeChars),
            array_values($escapeChars),
            $value
        );

        // Also escape high-bit characters
        $escaped = preg_replace_callback(
            '/[\x80-\xff]/',
            function($match) {
                return '\\' . bin2hex($match[0]);
            },
            $escaped
        );

        return $escaped;
    }

    /**
     * Escape DN component for safe binding
     */
    private function escapeDnComponent($value) {
        $escapeChars = [
            '\\' => '\\\\',
            ','  => '\\,',
            '+'  => '\\+',
            '"'  => '\\"',
            '<'  => '\\<',
            '>'  => '\\>',
            ';'  => '\\;',
            '='  => '\\=',
            '#'  => '\\#'
        ];

        return str_replace(
            array_keys($escapeChars),
            array_values($escapeChars),
            $value
        );
    }

    /**
     * Validate search criteria against whitelist
     */
    private function validateSearchCriteria(array $criteria) {
        $errors = [];

        foreach ($criteria as $field => $value) {
            // Check field is in whitelist
            if (!isset(self::SEARCHABLE_ATTRIBUTES[$field])) {
                $errors[] = "Invalid search field: {$field}";
                continue;
            }

            // Validate value length and characters
            if (strlen($value) < 1 || strlen($value) > 100) {
                $errors[] = "Invalid value length for field: {$field}";
            }

            // Basic character validation (allow unicode letters, numbers, spaces)
            if (!preg_match('/^[\p{L}\p{N}\s._-]+$/u', $value)) {
                $errors[] = "Invalid characters in field: {$field}";
            }
        }

        return $errors;
    }

    /**
     * Build safe LDAP filter from validated criteria
     */
    private function buildSafeFilter(array $criteria) {
        $filterParts = [];

        foreach ($criteria as $field => $value) {
            $ldapAttribute = self::SEARCHABLE_ATTRIBUTES[$field];
            $escapedValue = $this->escapeLdapFilterValue($value);
            $filterParts[] = "({$ldapAttribute}={$escapedValue})";
        }

        // Combine with AND operator
        if (count($filterParts) === 1) {
            return $filterParts[0];
        }

        return '(&' . implode('', $filterParts) . ')';
    }

    /**
     * Connect and bind to LDAP server
     */
    private function connect() {
        $this->ldapConn = ldap_connect(
            $this->config['host'],
            $this->config['port']
        );

        if (!$this->ldapConn) {
            throw new \RuntimeException('LDAP connection failed');
        }

        ldap_set_option($this->ldapConn, LDAP_OPT_PROTOCOL_VERSION, 3);
        ldap_set_option($this->ldapConn, LDAP_OPT_REFERRALS, 0);
        ldap_set_option($this->ldapConn, LDAP_OPT_NETWORK_TIMEOUT, 5);
        ldap_set_option($this->ldapConn, LDAP_OPT_TIMELIMIT, 10);

        // Bind with service account
        $bindResult = @ldap_bind(
            $this->ldapConn,
            $this->config['bind_dn'],
            $this->config['bind_password']
        );

        if (!$bindResult) {
            $error = ldap_error($this->ldapConn);
            $this->logger->error("LDAP bind failed", ['error' => $error]);
            throw new \RuntimeException('LDAP authentication failed');
        }
    }

    /**
     * Search LDAP with multiple criteria - production safe
     */
    public function searchUsers(array $criteria, string $clientIp, string $requestId) {
        // Rate limiting check
        if (!$this->rateLimiter->check($clientIp, 'ldap_search', 20, 60)) {
            $this->logger->warning('Rate limit exceeded for LDAP search', [
                'client_ip' => $clientIp,
                'request_id' => $requestId
            ]);
            throw new \RuntimeException('Rate limit exceeded');
        }

        // Validate all criteria before any LDAP operation
        $errors = $this->validateSearchCriteria($criteria);
        if (!empty($errors)) {
            $this->logger->warning('Invalid LDAP search criteria', [
                'errors' => $errors,
                'client_ip' => $clientIp,
                'request_id' => $requestId
            ]);
            throw new \InvalidArgumentException(implode('; ', $errors));
        }

        // Log search attempt (sanitized)
        $this->logger->info('LDAP search initiated', [
            'fields' => array_keys($criteria),
            'client_ip' => $clientIp,
            'request_id' => $requestId
        ]);

        try {
            $this->connect();

            $filter = $this->buildSafeFilter($criteria);

            // Limit search scope and results
            $searchResult = @ldap_search(
                $this->ldapConn,
                $this->config['base_dn'],
                $filter,
                self::RETRIEVABLE_ATTRIBUTES,  // Only retrieve whitelisted attributes
                0,  // attrsonly
                100,  // sizelimit - prevent large result sets
                10   // timelimit
            );

            if (!$searchResult) {
                $error = ldap_error($this->ldapConn);
                $this->logger->error('LDAP search failed', [
                    'error' => $error,
                    'request_id' => $requestId
                ]);
                return [];
            }

            $entries = ldap_get_entries($this->ldapConn, $searchResult);

            // Sanitize output - remove sensitive attributes
            $results = $this->sanitizeResults($entries);

            $this->logger->info('LDAP search completed', [
                'result_count' => count($results),
                'request_id' => $requestId
            ]);

            return $results;

        } catch (\Exception $e) {
            $this->logger->error('LDAP operation error', [
                'message' => $e->getMessage(),
                'request_id' => $requestId
            ]);
            throw new \RuntimeException('Directory search failed');
        } finally {
            if ($this->ldapConn) {
                ldap_close($this->ldapConn);
            }
        }
    }

    /**
     * Sanitize LDAP results for safe output
     */
    private function sanitizeResults(array $entries) {
        $results = [];

        for ($i = 0; $i < $entries['count']; $i++) {
            $entry = $entries[$i];
            $user = [];

            foreach (self::RETRIEVABLE_ATTRIBUTES as $attr) {
                $attrLower = strtolower($attr);
                if (isset($entry[$attrLower])) {
                    // Get first value only, sanitize for output
                    $value = $entry[$attrLower][0] ?? '';
                    $user[$attr] = htmlspecialchars($value, ENT_QUOTES, 'UTF-8');
                }
            }

            if (!empty($user)) {
                $results[] = $user;
            }
        }

        return $results;
    }

    /**
     * Secure user authentication with proper binding
     */
    public function authenticateUser(string $username, string $password, string $clientIp) {
        // Rate limiting for authentication
        if (!$this->rateLimiter->check($clientIp, 'ldap_auth', 5, 300)) {
            $this->logger->warning('Authentication rate limit exceeded', [
                'client_ip' => $clientIp
            ]);
            sleep(2);  // Add delay to slow brute force
            return false;
        }

        // Strict username validation
        if (!preg_match('/^[a-zA-Z0-9._-]{3,50}$/', $username)) {
            $this->logger->warning('Invalid username format', [
                'client_ip' => $clientIp
            ]);
            return false;
        }

        // Password requirements
        if (strlen($password) < 8 || strlen($password) > 256) {
            return false;
        }

        try {
            $this->connect();

            // Find user DN with escaped username
            $safeUsername = $this->escapeLdapFilterValue($username);
            $filter = "(uid={$safeUsername})";

            $searchResult = @ldap_search(
                $this->ldapConn,
                $this->config['base_dn'],
                $filter,
                ['dn'],
                0,
                1,
                5
            );

            if (!$searchResult) {
                return false;
            }

            $entries = ldap_get_entries($this->ldapConn, $searchResult);

            if ($entries['count'] !== 1) {
                return false;
            }

            $userDn = $entries[0]['dn'];

            // Authenticate by rebinding as user
            $authResult = @ldap_bind($this->ldapConn, $userDn, $password);

            // Log result (without sensitive data)
            $this->logger->info('Authentication attempt', [
                'success' => $authResult,
                'username' => $safeUsername,
                'client_ip' => $clientIp
            ]);

            return $authResult;

        } catch (\Exception $e) {
            $this->logger->error('Authentication error', [
                'client_ip' => $clientIp
            ]);
            return false;
        } finally {
            if ($this->ldapConn) {
                ldap_close($this->ldapConn);
            }
        }
    }
}

