Excellent questions. IPv6, localhost subdomains (like localtest.me which resolves to 127.0.0.1), and redirects are common bypass techniques. Redirects are particularly dangerous because the server might redirect to an internal URL after passing initial validation.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const http = require('http');
const https = require('https');
const dns = require('dns').promises;
const { URL } = require('url');
const net = require('net');
const ipaddr = require('ipaddr.js');
const winston = require('winston');

const app = express();
app.use(express.json());

// Production logger
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'ssrf-audit.log' })
  ]
});

// Configuration
const CONFIG = {
  MAX_REDIRECTS: 3,
  TIMEOUT_MS: 10000,
  MAX_RESPONSE_SIZE: 5 * 1024 * 1024,
  ALLOWED_PORTS: [80, 443, 8080, 8443],
  BLOCKED_HOSTNAMES: ['metadata.google.internal', 'metadata.goog']
};

// Comprehensive IP validation supporting IPv4 and IPv6
function isBlockedIP(ip) {
  try {
    const addr = ipaddr.parse(ip);

    // Check IPv4
    if (addr.kind() === 'ipv4') {
      const ranges = [
        'unspecified',     // 0.0.0.0/8
        'broadcast',       // 255.255.255.255/32
        'multicast',       // 224.0.0.0/4
        'linkLocal',       // 169.254.0.0/16
        'loopback',        // 127.0.0.0/8
        'private',         // 10/8, 172.16/12, 192.168/16
        'reserved'         // Various reserved ranges
      ];
      return ranges.some(range => addr.range() === range);
    }

    // Check IPv6
    if (addr.kind() === 'ipv6') {
      // Block IPv6 loopback, link-local, private ranges
      const ranges = [
        'unspecified',     // ::
        'loopback',        // ::1
        'linkLocal',       // fe80::/10
        'uniqueLocal',     // fc00::/7
        'multicast'        // ff00::/8
      ];
      if (ranges.some(range => addr.range() === range)) return true;

      // Check for IPv4-mapped IPv6 (::ffff:127.0.0.1)
      if (addr.isIPv4MappedAddress()) {
        return isBlockedIP(addr.toIPv4Address().toString());
      }
    }

    return false;
  } catch (e) {
    return true; // Block unparseable addresses
  }
}

function isBlockedHostname(hostname) {
  const lower = hostname.toLowerCase();

  // Block cloud metadata hostnames
  if (CONFIG.BLOCKED_HOSTNAMES.some(h => lower.includes(h))) return true;

  // Block localhost variations
  if (lower === 'localhost' || lower.endsWith('.localhost')) return true;

  // Block common DNS rebinding domains
  const rebindingDomains = ['localtest.me', 'lvh.me', 'vcap.me', 'nip.io', 'xip.io', 'sslip.io'];
  if (rebindingDomains.some(d => lower.endsWith(d))) return true;

  return false;
}

function validatePort(port, protocol) {
  const defaultPort = protocol === 'https:' ? 443 : 80;
  const actualPort = port ? parseInt(port) : defaultPort;
  return CONFIG.ALLOWED_PORTS.includes(actualPort);
}

// Create agent with DNS validation at connection time
function createSecureAgent(protocol) {
  const Agent = protocol === 'https:' ? https.Agent : http.Agent;

  return new Agent({
    keepAlive: false,
    lookup: (hostname, options, callback) => {
      // First check hostname blocklist
      if (isBlockedHostname(hostname)) {
        return callback(new Error(`Blocked hostname: ${hostname}`));
      }

      dns.lookup(hostname, { all: true, family: 0 }) // 0 = both IPv4 and IPv6
        .then(addresses => {
          if (addresses.length === 0) {
            return callback(new Error('No addresses found'));
          }

          // Validate ALL resolved IPs
          for (const addr of addresses) {
            if (isBlockedIP(addr.address)) {
              logger.warn('Blocked IP access attempt', {
                hostname,
                ip: addr.address,
                timestamp: new Date().toISOString()
              });
              return callback(new Error(`Blocked IP: ${addr.address}`));
            }
          }

          callback(null, addresses[0].address, addresses[0].family);
        })
        .catch(err => callback(err));
    }
  });
}

// Safe URL fetcher with redirect handling
async function safeFetch(urlString, redirectCount = 0, requestId) {
  if (redirectCount > CONFIG.MAX_REDIRECTS) {
    throw new Error('Too many redirects');
  }

  const parsedUrl = new URL(urlString);

  // Protocol validation
  if (!['http:', 'https:'].includes(parsedUrl.protocol)) {
    throw new Error(`Blocked protocol: ${parsedUrl.protocol}`);
  }

  // Port validation
  if (!validatePort(parsedUrl.port, parsedUrl.protocol)) {
    throw new Error(`Blocked port: ${parsedUrl.port || 'default'}`);
  }

  // Hostname validation (defense in depth)
  if (isBlockedHostname(parsedUrl.hostname)) {
    throw new Error(`Blocked hostname: ${parsedUrl.hostname}`);
  }

  const agent = createSecureAgent(parsedUrl.protocol);
  const client = parsedUrl.protocol === 'https:' ? https : http;

  return new Promise((resolve, reject) => {
    const request = client.get(parsedUrl.href, {
      agent,
      timeout: CONFIG.TIMEOUT_MS,
      headers: {
        'User-Agent': 'SecureWebhookBot/2.0',
        'Accept': 'application/json, text/plain, */*'
      }
    }, async (response) => {
      // Handle redirects with full validation
      if ([301, 302, 303, 307, 308].includes(response.statusCode)) {
        const location = response.headers.location;
        if (!location) {
          return reject(new Error('Redirect without location'));
        }

        // Resolve relative URLs
        const redirectUrl = new URL(location, urlString).href;

        logger.info('Following redirect', {
          requestId,
          from: urlString,
          to: redirectUrl,
          redirectCount: redirectCount + 1
        });

        try {
          // Recursively fetch with full validation on redirect target
          const result = await safeFetch(redirectUrl, redirectCount + 1, requestId);
          resolve(result);
        } catch (e) {
          reject(e);
        }
        return;
      }

      // Collect response with size limit
      let data = '';
      let size = 0;

      response.on('data', chunk => {
        size += chunk.length;
        if (size > CONFIG.MAX_RESPONSE_SIZE) {
          request.destroy();
          reject(new Error('Response too large'));
        }
        data += chunk;
      });

      response.on('end', () => {
        resolve({
          statusCode: response.statusCode,
          headers: response.headers,
          body: data,
          finalUrl: urlString
        });
      });
    });

    request.on('error', reject);
    request.on('timeout', () => {
      request.destroy();
      reject(new Error('Request timeout'));
    });
  });
}

