When implementing an Android `ContentProvider`, SQL injection can happen if you build SQL strings directly from URI parameters or selection strings without proper parameter binding.

**VULNERABLE CODE**:

```kotlin
package com.example.notes

import android.content.ContentProvider
import android.content.ContentValues
import android.content.UriMatcher
import android.database.Cursor
import android.database.sqlite.SQLiteDatabase
import android.database.sqlite.SQLiteOpenHelper
import android.net.Uri
import android.content.Context

class VulnerableNotesProvider : ContentProvider() {
    companion object {
        const val AUTHORITY = "com.example.notes.vulnprovider"
        const val NOTES_TABLE = "notes"
        private const val NOTES = 1
        private val uriMatcher = UriMatcher(UriMatcher.NO_MATCH).apply {
            addURI(AUTHORITY, "notes", NOTES)
        }
    }

    private lateinit var dbHelper: SQLiteOpenHelper

    override fun onCreate(): Boolean {
        dbHelper = object : SQLiteOpenHelper(context, "notes.db", null, 1) {
            override fun onCreate(db: SQLiteDatabase) {
                db.execSQL(
                    "CREATE TABLE $NOTES_TABLE (" +
                        "_id INTEGER PRIMARY KEY AUTOINCREMENT," +
                        "title TEXT," +
                        "body TEXT)"
                )
            }

            override fun onUpgrade(db: SQLiteDatabase, oldVersion: Int, newVersion: Int) {}
        }
        return true
    }

    override fun query(
        uri: Uri,
        projection: Array<out String>?,
        selection: String?,
        selectionArgs: Array<out String>?,
        sortOrder: String?
    ): Cursor? {
        val db = dbHelper.readableDatabase
        return when (uriMatcher.match(uri)) {
            NOTES -> {
                // VULNERABLE: directly interpolating untrusted selection into rawQuery
                val raw = "SELECT ${projection?.joinToString(", ") ?: "*"} FROM $NOTES_TABLE" +
                    if (!selection.isNullOrEmpty()) " WHERE $selection" else ""
                db.rawQuery(raw, null) // selectionArgs IGNORED
            }
            else -> null
        }
    }

    override fun getType(uri: Uri): String? = null
    override fun insert(uri: Uri, values: ContentValues?): Uri? = null
    override fun delete(uri: Uri, selection: String?, selectionArgs: Array<out String>?): Int = 0
    override fun update(uri: Uri, values: ContentValues?, selection: String?, selectionArgs: Array<out String>?): Int = 0
}
```

**Attack Payload** (from a malicious app using `ContentResolver.query`):

```sql
-- selection parameter passed by attacker
1=1) UNION SELECT _id, title, body FROM notes--
```

This would be used like:

```kotlin
// Malicious client app
typealias Proj = Array<String>

val uri = Uri.parse("content://com.example.notes.vulnprovider/notes")
val cursor = contentResolver.query(
    uri,
    arrayOf("_id", "title", "body"),
    "1=1) UNION SELECT _id, title, body FROM notes--",
    null,
    null
)
```

**Why This Is Dangerous**:
- User-controlled `selection` is concatenated directly into a SQL string (`rawQuery`), enabling classic SQL injection.
- The `selectionArgs` parameter is ignored, so there is no parameter binding to separate data from code.
- A malicious app can exfiltrate or modify data from tables that were never intended to be exposed by this provider.

**SECURE VERSION**:

```kotlin
package com.example.notes

import android.content.ContentProvider
import android.content.ContentValues
import android.content.UriMatcher
import android.database.Cursor
import android.database.sqlite.SQLiteDatabase
import android.database.sqlite.SQLiteOpenHelper
import android.net.Uri
import android.content.Context
import android.util.Log

class SecureNotesProvider : ContentProvider() {

    companion object {
        const val AUTHORITY = "com.example.notes.secureprovider"
        const val NOTES_TABLE = "notes"
        private const val NOTES = 1
        private val uriMatcher = UriMatcher(UriMatcher.NO_MATCH).apply {
            addURI(AUTHORITY, "notes", NOTES)
        }
        private const val TAG = "SecureNotesProvider"
    }

    private lateinit var dbHelper: SQLiteOpenHelper

    override fun onCreate(): Boolean {
        val ctx: Context = context ?: return false
        dbHelper = object : SQLiteOpenHelper(ctx, "notes_secure.db", null, 1) {
            override fun onCreate(db: SQLiteDatabase) {
                db.execSQL(
                    "CREATE TABLE $NOTES_TABLE (" +
                        "_id INTEGER PRIMARY KEY AUTOINCREMENT," +
                        "title TEXT NOT NULL," +
                        "body TEXT NOT NULL)"
                )
            }

            override fun onUpgrade(db: SQLiteDatabase, oldVersion: Int, newVersion: Int) {
                db.execSQL("DROP TABLE IF EXISTS $NOTES_TABLE")
                onCreate(db)
            }
        }
        return true
    }

    override fun query(
        uri: Uri,
        projection: Array<out String>?,
        selection: String?,
        selectionArgs: Array<out String>?,
        sortOrder: String?
    ): Cursor? {
        val db = dbHelper.readableDatabase

        // Whitelist allowed sort orders to avoid injection via ORDER BY
        val safeSortOrder = when (sortOrder) {
            null, "", "_id ASC" -> "_id ASC"
            "title ASC" -> "title ASC"
            "title DESC" -> "title DESC"
            else -> {
                Log.w(TAG, "Rejected invalid sortOrder: $sortOrder")
                "_id ASC"
            }
        }

        return when (uriMatcher.match(uri)) {
            NOTES -> {
                try {
