    override fun delete(uri: Uri, selection: String?, selectionArgs: Array<out String>?): Int {
        // Implementation would also rely on parameterized selectionArgs
        return 0
    }

    override fun update(
        uri: Uri,
        values: ContentValues?,
        selection: String?,
