**Key Security Controls**:
- Parameterized queries with `db.query(...)`: The `selection` string uses `?` placeholders, and attacker-controlled values go into `selectionArgs`, preventing them from altering the SQL structure.
- Whitelisting of `sortOrder`: Only known-safe column names and directions are allowed, blocking injection via `ORDER BY` clauses.
- Error handling and logging: Catches database exceptions, logs minimal diagnostic information, and avoids leaking SQL details to callers, supporting secure failure and monitoring.

In production, a `ContentProvider` should treat *every* piece of data coming from URIs, selection strings, and calling apps as untrusted. You also need call-site authorization, strict projection whitelisting, and good observability.

**PRODUCTION PATTERN**:

```kotlin
package com.example.notes

import android.content.ContentProvider
import android.content.ContentValues
import android.content.UriMatcher
import android.database.Cursor
import android.database.SQLException
import android.database.sqlite.SQLiteDatabase
import android.database.sqlite.SQLiteOpenHelper
import android.net.Uri
import android.content.Context
import android.os.Binder
import android.util.Log

class ProdNotesProvider : ContentProvider() {

    companion object {
        const val AUTHORITY = "com.example.notes.prodprovider"
        const val NOTES_TABLE = "notes"

        private const val NOTES = 1
        private const val NOTE_ID = 2

        private val uriMatcher = UriMatcher(UriMatcher.NO_MATCH).apply {
            addURI(AUTHORITY, "notes", NOTES)
            addURI(AUTHORITY, "notes/#", NOTE_ID)
        }

        private const val TAG = "ProdNotesProvider"
    }

    private lateinit var dbHelper: SQLiteOpenHelper

    override fun onCreate(): Boolean {
        val ctx = context ?: return false
        dbHelper = object : SQLiteOpenHelper(ctx, "notes_prod.db", null, 1) {
            override fun onCreate(db: SQLiteDatabase) {
                db.execSQL(
                    "CREATE TABLE $NOTES_TABLE (" +
                        "_id INTEGER PRIMARY KEY AUTOINCREMENT," +
                        "owner_uid INTEGER NOT NULL," +
                        "title TEXT NOT NULL," +
                        "body TEXT NOT NULL)"
                )
            }

            override fun onUpgrade(db: SQLiteDatabase, oldVersion: Int, newVersion: Int) {
                db.execSQL("DROP TABLE IF EXISTS $NOTES_TABLE")
                onCreate(db)
            }
        }
        return true
    }

    private fun getCallerUid(): Int = Binder.getCallingUid()

    // Enforce per-caller access control at provider boundary
    private fun buildOwnerSelection(
        baseSelection: String?,
        baseArgs: Array<out String>?
    ): Pair<String, Array<String>> {
        val callerUid = getCallerUid()
        val selectionBuilder = StringBuilder("owner_uid = ?")
        val args = mutableListOf(callerUid.toString())

        if (!baseSelection.isNullOrBlank()) {
            selectionBuilder.append(" AND (")
            selectionBuilder.append(baseSelection)
            selectionBuilder.append(")")
            if (baseArgs != null) {
                args.addAll(baseArgs)
            }
        }
        return Pair(selectionBuilder.toString(), args.toTypedArray())
    }

    private fun validateProjection(projection: Array<out String>?): Array<String>? {
        // Whitelist allowed columns only
        val allowed = setOf("_id", "title", "body")
        if (projection == null) return allowed.toTypedArray()

        projection.forEach {
            if (!allowed.contains(it)) {
                throw SecurityException("Invalid projection column: $it")
            }
        }
        return projection
    }

    private fun safeSortOrder(sortOrder: String?): String {
        return when (sortOrder) {
            null, "", "_id ASC" -> "_id ASC"
            "title ASC" -> "title ASC"
            "title DESC" -> "title DESC"
            else -> {
                Log.w(TAG, "Rejected sortOrder: $sortOrder")
                "_id ASC"
            }
        }
    }

    override fun query(
        uri: Uri,
        projection: Array<out String>?,
        selection: String?,
        selectionArgs: Array<out String>?,
        sortOrder: String?
    ): Cursor? {
        val db = dbHelper.readableDatabase
        val validatedProjection = try {
            validateProjection(projection)
        } catch (se: SecurityException) {
            Log.w(TAG, "Projection validation failed: ${se.message}")
            return null
        }
        val finalSortOrder = safeSortOrder(sortOrder)

        val (finalSelection, finalArgs) = when (uriMatcher.match(uri)) {
            NOTES -> buildOwnerSelection(selection, selectionArgs)
            NOTE_ID -> {
                // URI-based filtering: notes/#
                val noteId = uri.lastPathSegment
                if (noteId.isNullOrBlank()) {
                    Log.w(TAG, "Missing note ID in URI: $uri")
                    return null
                }
                val baseSel = if (selection.isNullOrBlank()) "_id = ?" else "_id = ? AND ($selection)"
                val baseArgsList = mutableListOf(noteId)
                if (selectionArgs != null) baseArgsList.addAll(selectionArgs)
                buildOwnerSelection(baseSel, baseArgsList.toTypedArray())
            }
            else -> {
                Log.w(TAG, "Unknown URI in query: $uri")
                return null
            }
        }

        return try {
            val cursor = db.query(
                NOTES_TABLE,
                validatedProjection,
                finalSelection,
                finalArgs,
                null,
                null,
                finalSortOrder
            )

            // Basic audit logging (avoid sensitive data in logs)
            Log.i(TAG, "Query by uid=${getCallerUid()} uri=$uri count=${cursor.count}")
            cursor
        } catch (e: SQLException) {
            Log.e(TAG, "SQL error during query: ${e.message}", e)
            null
        } catch (e: Exception) {
            Log.e(TAG, "Unexpected error during query", e)
            null
        }
    }

    override fun insert(uri: Uri, values: ContentValues?): Uri? {
        if (values == null) return null
        val db = dbHelper.writableDatabase

        // Attach owner_uid based on caller
        values.put("owner_uid", getCallerUid())

        return try {
            val id = db.insertOrThrow(NOTES_TABLE, null, values)
            if (id == -1L) return null

            val resultUri = Uri.withAppendedPath(uri, id.toString())
            context?.contentResolver?.notifyChange(resultUri, null)
            Log.i(TAG, "Insert by uid=${getCallerUid()} uri=$resultUri")
            resultUri
        } catch (e: SQLException) {
            Log.e(TAG, "SQL error during insert: ${e.message}", e)
            null
        }
    }

    override fun delete(
        uri: Uri,
        selection: String?,
        selectionArgs: Array<out String>?
    ): Int {
        val db = dbHelper.writableDatabase
        val (finalSelection, finalArgs) = when (uriMatcher.match(uri)) {
            NOTES, NOTE_ID -> buildOwnerSelection(selection, selectionArgs)
            else -> {
                Log.w(TAG, "Unknown URI in delete: $uri")
                return 0
            }
        }
        return try {
            val rows = db.delete(NOTES_TABLE, finalSelection, finalArgs)
            if (rows > 0) context?.contentResolver?.notifyChange(uri, null)
            Log.i(TAG, "Delete by uid=${getCallerUid()} uri=$uri rows=$rows")
            rows
        } catch (e: SQLException) {
            Log.e(TAG, "SQL error during delete: ${e.message}", e)
            0
        }
    }

    override fun update(
        uri: Uri,
        values: ContentValues?,
        selection: String?,
        selectionArgs: Array<out String>?
    ): Int {
        if (values == null) return 0
        val db = dbHelper.writableDatabase
        val (finalSelection, finalArgs) = when (uriMatcher.match(uri)) {
            NOTES, NOTE_ID -> buildOwnerSelection(selection, selectionArgs)
            else -> {
                Log.w(TAG, "Unknown URI in update: $uri")
                return 0
            }
        }
        return try {
            val rows = db.update(NOTES_TABLE, values, finalSelection, finalArgs)
            if (rows > 0) context?.contentResolver?.notifyChange(uri, null)
            Log.i(TAG, "Update by uid=${getCallerUid()} uri=$uri rows=$rows")
            rows
        } catch (e: SQLException) {
            Log.e(TAG, "SQL error during update: ${e.message}", e)
            0
        }
    }

    override fun getType(uri: Uri): String? = when (uriMatcher.match(uri)) {
        NOTES -> "vnd.android.cursor.dir/vnd.$AUTHORITY.notes"
        NOTE_ID -> "vnd.android.cursor.item/vnd.$AUTHORITY.notes"
        else -> null
    }
}
```

**Defense in Depth Layers**:
1. **SQL Injection Prevention via Parameter Binding**:
   - All data from URIs and callers is injected only via `selectionArgs`, `insert`, `update`, and `delete` parameters, never by concatenating into SQL strings.
   - Example:
   ```kotlin
   val cursor = db.query(
       NOTES_TABLE,
       validatedProjection,
       finalSelection,
       finalArgs,
       null,
       null,
       finalSortOrder
   )
   ```
2. **Per-Caller Access Control and Row Ownership**:
   - Each row is tagged with `owner_uid` and every operation injects `owner_uid = ?` into the selection, scoped to `Binder.getCallingUid()`.
   - Example:
   ```kotlin
   val (finalSelection, finalArgs) = buildOwnerSelection(selection, selectionArgs)
   ```
3. **Input Validation, Whitelisting, and Safe Defaults**:
   - Projection, sort order, and URIs are strictly validated, with rejections logged and safe defaults applied.
   - Example:
   ```kotlin
   val validatedProjection = validateProjection(projection)
   val finalSortOrder = safeSortOrder(sortOrder)
   ```

**Additional Protections**:
- **Environment-specific configuration**: In release builds, reduce log verbosity and avoid logging sensitive content, while keeping security-relevant events (failed access, invalid URIs) for incident response.
- **Rate limiting / abuse detection**: Implement (or integrate with) a layer that detects high-frequency queries from the same UID and flags or throttles them to mitigate scraping or brute-force behavior.
- **Monitoring and audit logging**: Centralize logs (e.g., via logcat shipping or in-app telemetry) that record URI patterns, calling UIDs, and error types so you can detect anomalies and respond quickly to attempted injections or access control violations.

Your login function is vulnerable to timing attacks, which allow attackers to enumerate valid usernames by measuring response time differences. This was exploited in CVE-2023-20269 against Cisco ASA, enabling mass VPN credential attacks.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const db = require('./database');

const app = express();
app.use(express.json());

app.post('/api/login', async (req, res) => {
  const { username, password } = req.body;

  // VULNERABLE: Early return reveals username existence
  const user = await db.query(
    'SELECT * FROM users WHERE username = $1',
    [username]
  );

  if (!user.rows[0]) {
    // Returns immediately - FAST response for invalid username
    return res.status(401).json({ error: 'Invalid credentials' });
  }

  // bcrypt.compare takes ~100ms - SLOW response for valid username
  const validPassword = await bcrypt.compare(password, user.rows[0].password_hash);

  if (!validPassword) {
    return res.status(401).json({ error: 'Invalid credentials' });
  }

  return res.json({ token: generateToken(user.rows[0]) });
});
```

**Attack Payload**:
```bash
# Timing attack script measuring response times
for user in admin root administrator john jane; do
  start=$(date +%s%N)
  curl -s -X POST http://target.com/api/login \
    -H "Content-Type: application/json" \
    -d "{\"username\":\"$user\",\"password\":\"test\"}" > /dev/null
  end=$(date +%s%N)
  echo "$user: $((($end-$start)/1000000))ms"
done
# Valid usernames show ~100ms+ (bcrypt), invalid show ~5ms (early return)
```

**Why This Is Dangerous**:
- Invalid usernames return in ~5ms, valid usernames take ~100ms due to bcrypt
- Attackers can enumerate thousands of usernames per minute
- Reduces brute-force search space dramatically
- Bypasses account lockout by confirming accounts before password attempts

**SECURE VERSION**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const crypto = require('crypto');
const db = require('./database');

const app = express();
app.use(express.json());

// Pre-generated fake hash for timing consistency
const FAKE_HASH = bcrypt.hashSync('fake_password_for_timing', 12);

app.post('/api/login', async (req, res) => {
  const { username, password } = req.body;

  // Input validation
  if (!username || !password || typeof username !== 'string' || typeof password !== 'string') {
    return res.status(400).json({ error: 'Invalid request' });
  }

  const user = await db.query(
    'SELECT * FROM users WHERE username = $1',
    [username]
  );

  // SECURE: Always perform bcrypt comparison for constant time
  const hashToCompare = user.rows[0] ? user.rows[0].password_hash : FAKE_HASH;
  const validPassword = await bcrypt.compare(password, hashToCompare);

  // SECURE: Only succeed if user exists AND password is valid
  if (!user.rows[0] || !validPassword) {
    // Identical response and timing for all failures
    return res.status(401).json({ error: 'Invalid credentials' });
  }

  return res.json({ token: generateToken(user.rows[0]) });
});
```

**Key Security Controls**:
- **Constant-time execution**: Always run bcrypt.compare() regardless of username validity, ensuring ~100ms response for all requests
- **Fake hash comparison**: Pre-computed fake hash ensures timing is identical when user doesn't exist
- **Unified error response**: Same error message and HTTP status for all authentication failures

Excellent question! Timing attacks affect many authentication flows beyond login. Password reset tokens, API keys, and session tokens are all vulnerable to timing-based enumeration. Here's a comprehensive production-ready approach.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const crypto = require('crypto');
const { RateLimiterMemory } = require('rate-limiter-flexible');
const db = require('./database');
const logger = require('./logger');

const app = express();
app.use(express.json());

// Rate limiting per IP
const rateLimiter = new RateLimiterMemory({
  points: 5,
  duration: 60,
  blockDuration: 300
});

const FAKE_HASH = bcrypt.hashSync(crypto.randomBytes(32).toString('hex'), 12);

// Constant-time string comparison for tokens/API keys
function safeCompare(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') {
    return false;
  }
  const bufA = Buffer.from(a, 'utf8');
  const bufB = Buffer.from(b, 'utf8');
  // crypto.timingSafeEqual requires equal length buffers
  if (bufA.length !== bufB.length) {
    // Compare against itself to maintain constant time
    crypto.timingSafeEqual(bufA, bufA);
    return false;
  }
  return crypto.timingSafeEqual(bufA, bufB);
}

// SECURE LOGIN with timing attack protection
app.post('/api/login', async (req, res) => {
  const startTime = Date.now();
  const MINIMUM_RESPONSE_TIME = 200; // Ensure minimum 200ms response

  try {
    await rateLimiter.consume(req.ip);
  } catch (rejRes) {
    logger.warn({ ip: req.ip, action: 'login_rate_limited' });
    return res.status(429).json({ error: 'Too many requests' });
  }

  const { username, password } = req.body;

  if (!username || !password) {
    await enforceMinimumTime(startTime, MINIMUM_RESPONSE_TIME);
    return res.status(400).json({ error: 'Invalid request' });
  }

  const user = await db.query(
    'SELECT id, username, password_hash, failed_attempts, locked_until FROM users WHERE username = $1',
    [username.toLowerCase().trim()]
  );

  // Always perform bcrypt comparison
  const hashToCompare = user.rows[0]?.password_hash || FAKE_HASH;
  const validPassword = await bcrypt.compare(password, hashToCompare);

  // Check account lockout
  const isLocked = user.rows[0]?.locked_until && new Date(user.rows[0].locked_until) > new Date();

  if (!user.rows[0] || !validPassword || isLocked) {
    if (user.rows[0] && !isLocked) {
      await incrementFailedAttempts(user.rows[0].id);
    }

    logger.info({
      action: 'login_failed',
      username: username.substring(0, 3) + '***',
      ip: req.ip,
      userAgent: req.get('User-Agent')
    });

    await enforceMinimumTime(startTime, MINIMUM_RESPONSE_TIME);
    return res.status(401).json({ error: 'Invalid credentials' });
  }

  await resetFailedAttempts(user.rows[0].id);

  logger.info({
    action: 'login_success',
    userId: user.rows[0].id,
    ip: req.ip
  });

  await enforceMinimumTime(startTime, MINIMUM_RESPONSE_TIME);
  return res.json({ token: generateToken(user.rows[0]) });
});

// SECURE API KEY VALIDATION
async function validateApiKey(providedKey) {
  if (!providedKey || typeof providedKey !== 'string') {
    return { valid: false, client: null };
  }

  // Extract key prefix for lookup (first 8 chars)
  const keyPrefix = providedKey.substring(0, 8);

  const result = await db.query(
    'SELECT id, key_hash, client_name, rate_limit FROM api_keys WHERE key_prefix = $1 AND revoked = false',
    [keyPrefix]
  );

  // Use constant-time comparison for the full key hash
  const storedHash = result.rows[0]?.key_hash || FAKE_HASH;
  const providedHash = crypto.createHash('sha256').update(providedKey).digest('hex');

  const isValid = safeCompare(providedHash, storedHash) && result.rows[0];

  return {
    valid: isValid,
    client: isValid ? result.rows[0] : null
  };
}

// SECURE PASSWORD RESET TOKEN VALIDATION
app.post('/api/reset-password', async (req, res) => {
  const startTime = Date.now();
  const { token, newPassword } = req.body;

  if (!token || !newPassword) {
    await enforceMinimumTime(startTime, 200);
    return res.status(400).json({ error: 'Invalid request' });
  }

