Using AES incorrectly can completely break your security, even if you "use AES". Common mistakes include hard-coded keys, static IVs, and insecure modes.

**VULNERABLE CODE**:

```csharp
using System;
using System.IO;
using System.Security.Cryptography;
using System.Text;

namespace CryptoDemo
{
    public static class InsecureAesExample
    {
        // HARD-CODED KEY AND IV (16 bytes for AES-128)
        private static readonly byte[] HardCodedKey = Encoding.UTF8.GetBytes("1234567890ABCDEF");
        private static readonly byte[] StaticIv = Encoding.UTF8.GetBytes("FEDCBA0987654321");

        public static string Encrypt(string plaintext)
        {
            using (var aes = Aes.Create())
            {
                aes.Key = HardCodedKey;              // Insecure: same key for all users/environments
                aes.IV = StaticIv;                   // Insecure: static, predictable IV
                aes.Mode = CipherMode.CBC;           // CBC without integrity
                aes.Padding = PaddingMode.PKCS7;

                using (var ms = new MemoryStream())
                using (var cs = new CryptoStream(ms, aes.CreateEncryptor(), CryptoStreamMode.Write))
                using (var writer = new StreamWriter(cs))
                {
                    writer.Write(plaintext);
                    writer.Flush();
                    cs.FlushFinalBlock();
                    return Convert.ToBase64String(ms.ToArray());
                }
            }
        }

        public static string Decrypt(string base64Ciphertext)
        {
            var cipherBytes = Convert.FromBase64String(base64Ciphertext);
            using (var aes = Aes.Create())
            {
                aes.Key = HardCodedKey;              // Same hard-coded key
                aes.IV = StaticIv;                   // Same static IV
                aes.Mode = CipherMode.CBC;
                aes.Padding = PaddingMode.PKCS7;

                using (var ms = new MemoryStream(cipherBytes))
                using (var cs = new CryptoStream(ms, aes.CreateDecryptor(), CryptoStreamMode.Read))
                using (var reader = new StreamReader(cs))
                {
                    return reader.ReadToEnd();
                }
            }
        }
    }
}
```

**Attack Payload** (example offline attack on hard-coded key):
```bash
# Attacker extracts the hard-coded key from the binary using strings
strings InsecureAesExample.dll | grep 1234567890ABCDEF

# With the key and static IV, attacker can decrypt any captured ciphertext
# (pseudo-command using OpenSSL for illustration)
openssl enc -d -aes-128-cbc -K 31323334353637383930414243444546 -iv 46454443424130393837363534333231 -in captured.bin -out decrypted.txt
```

**Why This Is Dangerous**:
- Hard-coded, shared keys make it trivial for an attacker who gets the binary (or source) to decrypt all data.
- Static IV means identical plaintexts produce identical ciphertexts, enabling pattern analysis and some chosen-plaintext attacks.
- AES-CBC without authentication is vulnerable to padding oracle and ciphertext modification; you get confidentiality only, no integrity.

**SECURE VERSION**:

```csharp
using System;
using System.IO;
using System.Security.Cryptography;
using System.Text;

namespace CryptoDemo
{
    public sealed class SecureAesService : IDisposable
    {
        // In production, this key must come from secure configuration or a KMS,
        // not from code. Here we simulate an injected key.
        private readonly byte[] _key;

        public SecureAesService(byte[] key)
        {
            if (key == null || (key.Length != 16 && key.Length != 24 && key.Length != 32))
            {
                throw new ArgumentException("AES key must be 128, 192, or 256 bits.", nameof(key));
            }
            _key = key;
        }

        // Encrypts plaintext using AES-GCM (authenticated encryption)
        public string Encrypt(string plaintext)
        {
            if (plaintext == null) throw new ArgumentNullException(nameof(plaintext));

            // Generate a fresh, random 12-byte nonce for each encryption
            byte[] nonce = new byte[12];
            RandomNumberGenerator.Fill(nonce);

            byte[] plaintextBytes = Encoding.UTF8.GetBytes(plaintext);
            byte[] ciphertext = new byte[plaintextBytes.Length];
            byte[] tag = new byte[16];

            using (var aesGcm = new AesGcm(_key))
            {
                aesGcm.Encrypt(nonce, plaintextBytes, ciphertext, tag);
            }

            // Store nonce || tag || ciphertext
            using (var ms = new MemoryStream())
            using (var bw = new BinaryWriter(ms))
            {
                bw.Write(nonce.Length);
                bw.Write(nonce);
                bw.Write(tag.Length);
                bw.Write(tag);
                bw.Write(ciphertext.Length);
                bw.Write(ciphertext);
                return Convert.ToBase64String(ms.ToArray());
            }
        }

        // Decrypts ciphertext produced by Encrypt
        public string Decrypt(string encoded)
        {
            if (encoded == null) throw new ArgumentNullException(nameof(encoded));

            byte[] data = Convert.FromBase64String(encoded);

            using (var ms = new MemoryStream(data))
            using (var br = new BinaryReader(ms))
            {
                int nonceLen = br.ReadInt32();
                byte[] nonce = br.ReadBytes(nonceLen);

                int tagLen = br.ReadInt32();
                byte[] tag = br.ReadBytes(tagLen);

                int cipherLen = br.ReadInt32();
                byte[] ciphertext = br.ReadBytes(cipherLen);

                byte[] plaintextBytes = new byte[cipherLen];

                try
                {
                    using (var aesGcm = new AesGcm(_key))
                    {
                        aesGcm.Decrypt(nonce, ciphertext, tag, plaintextBytes);
                    }
                }
                catch (CryptographicException ex)
                {
                    // Log error securely in real system; do not leak details to caller
                    Console.Error.WriteLine($"[WARN] Decryption failed: {ex.Message}");
                    throw new InvalidOperationException("Decryption failed.");
                }

                return Encoding.UTF8.GetString(plaintextBytes);
            }
        }

        public void Dispose()
        {
            // Clear key material from memory where possible
            if (_key != null)
            {
                CryptographicOperations.ZeroMemory(_key);
            }
        }
    }
}
```

**Key Security Controls**:
- **Random nonces (IVs)**: Uses a fresh, cryptographically random 12-byte nonce per encryption, preventing pattern leakage and replay of identical ciphertexts for identical inputs.
- **Authenticated encryption (AES-GCM)**: Provides both confidentiality and integrity; tampering with ciphertext or nonce causes decryption to fail with a `CryptographicException`.
- **Externalized key management & memory hygiene**: The key is passed into the service (not hard-coded), and `CryptographicOperations.ZeroMemory` is used to reduce exposure of key material in process memory. In production, keys should come from secure configuration or a KMS, with rotation and strict access controls.

In production, you need more than just correct AES usage. You must integrate secure key management, tenant isolation, logging, monitoring, and environment-specific safeguards.

**PRODUCTION PATTERN**:

```csharp
using System;
using System.IO;
using System.Security.Cryptography;
using System.Text;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Configuration;
using Microsoft.Extensions.Logging;

namespace MyApp.Api.Controllers
{
    public interface ITenantKeyProvider
    {
        // Returns a key specific to the tenant from a secure store (e.g., Azure Key Vault)
        byte[] GetTenantKey(string tenantId);
    }

    public sealed class TenantKeyProvider : ITenantKeyProvider
    {
        private readonly IConfiguration _configuration;

        public TenantKeyProvider(IConfiguration configuration)
        {
            _configuration = configuration;
        }

        public byte[] GetTenantKey(string tenantId)
        {
            // In real life, retrieve from a KMS or HSM; here we simulate per-tenant keys
            string base64Key = _configuration[$"Crypto:Tenants:{tenantId}:AesKey"]
                               ?? throw new InvalidOperationException("Key not configured for tenant.");

            byte[] key = Convert.FromBase64String(base64Key);
            if (key.Length != 16 && key.Length != 24 && key.Length != 32)
            {
                throw new InvalidOperationException("Invalid key length.");
            }
            return key;
        }
    }

    public sealed class AesGcmEncryptionService
    {
        private readonly ITenantKeyProvider _keyProvider;
        private readonly ILogger<AesGcmEncryptionService> _logger;

        public AesGcmEncryptionService(ITenantKeyProvider keyProvider,
                                       ILogger<AesGcmEncryptionService> logger)
        {
            _keyProvider = keyProvider;
            _logger = logger;
        }

        public string Encrypt(string tenantId, string plaintext)
        {
            if (string.IsNullOrWhiteSpace(tenantId)) throw new ArgumentNullException(nameof(tenantId));
            if (plaintext == null) throw new ArgumentNullException(nameof(plaintext));

            byte[] key = _keyProvider.GetTenantKey(tenantId);
            byte[] nonce = new byte[12];
            RandomNumberGenerator.Fill(nonce);

            byte[] plaintextBytes = Encoding.UTF8.GetBytes(plaintext);
            byte[] ciphertext = new byte[plaintextBytes.Length];
            byte[] tag = new byte[16];

            using (var aesGcm = new AesGcm(key))
            {
                aesGcm.Encrypt(nonce, plaintextBytes, ciphertext, tag);
            }

            using (var ms = new MemoryStream())
            using (var bw = new BinaryWriter(ms))
            {
                bw.Write(nonce.Length);
                bw.Write(nonce);
                bw.Write(tag.Length);
                bw.Write(tag);
                bw.Write(ciphertext.Length);
                bw.Write(ciphertext);

                string encoded = Convert.ToBase64String(ms.ToArray());

                // Audit log (no sensitive data)
                _logger.LogInformation("Encrypted payload for tenant {TenantId} (len={Length})", tenantId, plaintextBytes.Length);

                CryptographicOperations.ZeroMemory(plaintextBytes);
                return encoded;
            }
        }

        public string Decrypt(string tenantId, string encodedCiphertext)
        {
            if (string.IsNullOrWhiteSpace(tenantId)) throw new ArgumentNullException(nameof(tenantId));
            if (encodedCiphertext == null) throw new ArgumentNullException(nameof(encodedCiphertext));

            byte[] key = _keyProvider.GetTenantKey(tenantId);
            byte[] data;

            try
            {
                data = Convert.FromBase64String(encodedCiphertext);
            }
            catch (FormatException ex)
            {
                _logger.LogWarning(ex, "Invalid Base64 ciphertext for tenant {TenantId}", tenantId);
                throw new InvalidOperationException("Invalid ciphertext format.");
            }

            using (var ms = new MemoryStream(data))
            using (var br = new BinaryReader(ms))
            {
                try
                {
                    int nonceLen = br.ReadInt32();
                    byte[] nonce = br.ReadBytes(nonceLen);
                    int tagLen = br.ReadInt32();
                    byte[] tag = br.ReadBytes(tagLen);
                    int cipherLen = br.ReadInt32();
                    byte[] ciphertext = br.ReadBytes(cipherLen);

                    byte[] plaintextBytes = new byte[cipherLen];
                    using (var aesGcm = new AesGcm(key))
                    {
                        aesGcm.Decrypt(nonce, ciphertext, tag, plaintextBytes);
                    }

                    string plaintext = Encoding.UTF8.GetString(plaintextBytes);
                    CryptographicOperations.ZeroMemory(plaintextBytes);

                    _logger.LogInformation("Decrypted payload for tenant {TenantId} (len={Length})", tenantId, plaintext.Length);
                    return plaintext;
                }
                catch (EndOfStreamException ex)
                {
                    _logger.LogWarning(ex, "Malformed ciphertext structure for tenant {TenantId}", tenantId);
                    throw new InvalidOperationException("Malformed ciphertext.");
                }
                catch (CryptographicException ex)
                {
                    // Possible tampering or wrong key/tenant ID
                    _logger.LogWarning(ex, "Decryption failed for tenant {TenantId}", tenantId);
                    throw new InvalidOperationException("Decryption failed.");
                }
            }
        }
    }

    [ApiController]
    [Route("api/[controller]")]
    public class SecretsController : ControllerBase
    {
        private readonly AesGcmEncryptionService _crypto;
        private readonly ILogger<SecretsController> _logger;
        private readonly IConfiguration _config;

        public SecretsController(AesGcmEncryptionService crypto,
                                 ILogger<SecretsController> logger,
                                 IConfiguration config)
        {
            _crypto = crypto;
            _logger = logger;
            _config = config;
        }

        [HttpPost("encrypt")] // Rate-limit via middleware in production
        public IActionResult Encrypt([FromHeader(Name = "X-Tenant-Id")] string tenantId,
                                     [FromBody] string secret)
        {
            if (!IsTenantAllowed(tenantId))
            {
                _logger.LogWarning("Unauthorized tenant access attempt: {TenantId}", tenantId);
                return Forbid();
            }

            try
            {
                string cipher = _crypto.Encrypt(tenantId, secret);
                return Ok(cipher);
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Encryption error for tenant {TenantId}", tenantId);
                return StatusCode(500, "Internal error.");
            }
        }

        [HttpPost("decrypt")] // Rate-limit via middleware in production
        public IActionResult Decrypt([FromHeader(Name = "X-Tenant-Id")] string tenantId,
                                     [FromBody] string cipher)
        {
            if (!IsTenantAllowed(tenantId))
            {
                _logger.LogWarning("Unauthorized tenant access attempt: {TenantId}", tenantId);
                return Forbid();
            }

            try
            {
                string plaintext = _crypto.Decrypt(tenantId, cipher);
                return Ok(plaintext);
            }
            catch (InvalidOperationException ex)
            {
                _logger.LogWarning(ex, "User-facing decrypt error for tenant {TenantId}", tenantId);
                return BadRequest("Invalid ciphertext.");
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Unexpected decrypt error for tenant {TenantId}", tenantId);
                return StatusCode(500, "Internal error.");
            }
        }

        private bool IsTenantAllowed(string tenantId)
        {
            if (string.IsNullOrWhiteSpace(tenantId)) return false;

            // Basic example: in production, validate against DB/IDP and enforce RBAC
            string allowed = _config[$"Crypto:Tenants:{tenantId}:Enabled"];
            return string.Equals(allowed, "true", StringComparison.OrdinalIgnoreCase);
        }
    }
}
```

**Defense in Depth Layers**:
1. **Strong cryptography and per-tenant key isolation**:
   - AES-GCM with fresh nonces and authenticated encryption per operation.
   - Per-tenant keys from `ITenantKeyProvider` avoid cross-tenant data exposure. Example:
   ```csharp
   byte[] key = _keyProvider.GetTenantKey(tenantId);
   using var aesGcm = new AesGcm(key);
   aesGcm.Encrypt(nonce, plaintextBytes, ciphertext, tag);
   ```
2. **Secure configuration and environment separation**:
   - Keys and flags read from `IConfiguration`, enabling different keys for dev/stage/prod and easy rotation. Example:
   ```csharp
   string base64Key = _configuration[$"Crypto:Tenants:{tenantId}:AesKey"];
   ```
3. **Auditing, monitoring, and secure error handling**:
   - Logs key events without sensitive payloads; uses warning vs. error levels.
   - Returns generic error messages to clients, logs technical details server-side:
   ```csharp
   catch (CryptographicException ex)
   {
       _logger.LogWarning(ex, "Decryption failed for tenant {TenantId}", tenantId);
       throw new InvalidOperationException("Decryption failed.");
   }
   ```

**Additional Protections**:
- Rate limiting on crypto endpoints (via ASP.NET Core middleware) to mitigate abuse and brute-force attempts on ciphertext structures.
- Security headers and TLS enforcement in production (e.g., HSTS, TLS 1.2+ only) to protect ciphertext and tenant identifiers in transit.
- Regular key rotation and revocation processes (update KMS/KeyVault keys and roll out via configuration) combined with database-level encryption or tokenization to reduce blast radius if a single key is compromised.

Setting up admin panels requires extreme care - exposed admin endpoints are one of the most common and devastating security misconfigurations. The SolarWinds breach (CVE-2020-10148) showed how attackers exploit unprotected admin APIs to compromise entire organizations.

**VULNERABLE CODE**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import java.util.List;

@Controller
public class AdminController {

    private final UserRepository userRepository;
    private final SystemConfigRepository configRepository;

    public AdminController(UserRepository userRepository, 
                          SystemConfigRepository configRepository) {
        this.userRepository = userRepository;
        this.configRepository = configRepository;
    }

    // VULNERABLE: No authentication required!
    @GetMapping("/admin")
    public String adminDashboard(Model model) {
        model.addAttribute("users", userRepository.findAll());
        model.addAttribute("configs", configRepository.findAll());
        return "admin/dashboard";
    }

    // VULNERABLE: Sensitive endpoint exposed without auth
    @PostMapping("/admin/users/delete/{id}")
    public String deleteUser(@PathVariable Long id) {
        userRepository.deleteById(id);
        return "redirect:/admin";
    }

    // VULNERABLE: System configuration exposed
    @GetMapping("/admin/config")
    @ResponseBody
    public List<SystemConfig> getConfig() {
        return configRepository.findAll(); // Exposes DB credentials, API keys
    }

    // VULNERABLE: Predictable admin endpoint
    @PostMapping("/admin/execute")
    @ResponseBody
    public String executeCommand(@RequestParam String cmd) {
        // Extremely dangerous: command execution without auth
        return Runtime.getRuntime().exec(cmd).toString();
    }
}
```

**Attack Payload**:
```bash
# Attackers scan for common admin paths
curl -X GET https://target.com/admin
curl -X GET https://target.com/admin/config
curl -X GET https://target.com/administrator
curl -X GET https://target.com/admin.php
curl -X GET https://target.com/wp-admin

# Exploit unprotected endpoint
curl -X POST https://target.com/admin/execute?cmd=cat%20/etc/passwd
curl -X POST https://target.com/admin/users/delete/1
```

**Why This Is Dangerous**:
- Admin endpoints accessible to anyone on the internet without authentication
- Sensitive system configuration (database credentials, API keys) exposed via /admin/config
- Predictable URL patterns allow attackers to easily discover admin functionality
- No role-based access control - any authenticated user could access admin features
- Command execution endpoint creates immediate RCE vulnerability

**SECURE VERSION**:

```java
import org.springframework.web.bind.annotation.*;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.security.access.prepost.PreAuthorize;
import org.springframework.security.core.annotation.AuthenticationPrincipal;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.util.List;

@Controller
@RequestMapping("/secure-mgmt-7x9k2")  // Non-predictable admin path
@PreAuthorize("hasRole('ADMIN')")  // Require ADMIN role for all endpoints
public class SecureAdminController {

    private static final Logger auditLog = LoggerFactory.getLogger("AUDIT");

    private final UserRepository userRepository;
    private final SystemConfigRepository configRepository;

    public SecureAdminController(UserRepository userRepository,
                                  SystemConfigRepository configRepository) {
        this.userRepository = userRepository;
        this.configRepository = configRepository;
    }

    @GetMapping("/dashboard")
    public String adminDashboard(Model model, 
                                  @AuthenticationPrincipal UserDetails admin) {
        auditLog.info("Admin dashboard accessed by: {}", admin.getUsername());

        // Only return non-sensitive user info
        model.addAttribute("users", userRepository.findAllSanitized());
        return "admin/dashboard";
    }

    @PostMapping("/users/deactivate/{id}")
    @PreAuthorize("hasRole('SUPER_ADMIN')")  // Additional role requirement
    public String deactivateUser(@PathVariable Long id,
                                  @AuthenticationPrincipal UserDetails admin) {
        auditLog.warn("User {} deactivated by admin: {}", id, admin.getUsername());
        userRepository.deactivateById(id);  // Soft delete, not hard delete
        return "redirect:/secure-mgmt-7x9k2/dashboard";
    }

    // No config endpoint - sensitive data should never be exposed via API
    // No command execution - this should never exist in production
}
```

**Key Security Controls**:
- **@PreAuthorize annotation**: Enforces role-based access control at method level, requiring ADMIN role
- **Non-predictable URL path**: Using randomized path `/secure-mgmt-7x9k2` prevents automated scanning
- **Audit logging**: All admin actions logged with administrator identity for forensic analysis
- **Removed dangerous endpoints**: Config exposure and command execution endpoints eliminated entirely

Excellent question! Defense in depth for admin panels requires multiple layers: application security, network segmentation, IP restrictions, and monitoring. Here's a production-grade implementation:

**PRODUCTION PATTERN**:

```java
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.authentication.www.BasicAuthenticationFilter;
import org.springframework.core.env.Environment;
import javax.servlet.*;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.util.Arrays;
import java.util.List;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

@Configuration
@EnableWebSecurity
public class AdminSecurityConfig {

    private static final Logger securityLog = LoggerFactory.getLogger("SECURITY");

    // Admin paths - loaded from environment, not hardcoded
    private final String adminBasePath;
    private final List<String> allowedAdminIPs;
    private final boolean adminEnabled;

    public AdminSecurityConfig(Environment env) {
        this.adminBasePath = env.getProperty("admin.base-path", "/secure-mgmt-" + 
            System.getenv("ADMIN_PATH_TOKEN"));
        this.allowedAdminIPs = Arrays.asList(
            env.getProperty("admin.allowed-ips", "10.0.0.0/8,192.168.0.0/16").split(",")
        );
        this.adminEnabled = Boolean.parseBoolean(
            env.getProperty("admin.enabled", "false")
        );
    }

    @Bean
    public SecurityFilterChain adminSecurityFilterChain(HttpSecurity http) throws Exception {
        http
            .securityMatcher(adminBasePath + "/**")
            .addFilterBefore(new AdminIPFilter(allowedAdminIPs, adminEnabled), 
                            BasicAuthenticationFilter.class)
            .authorizeHttpRequests(auth -> auth
                .requestMatchers(adminBasePath + "/**").hasRole("ADMIN")
            )
            .httpBasic(basic -> basic.disable())  // Disable basic auth
            .formLogin(form -> form
                .loginPage(adminBasePath + "/login")
                .failureHandler((req, res, ex) -> {
                    securityLog.warn("Failed admin login from IP: {} - User: {}",
                        req.getRemoteAddr(), req.getParameter("username"));
                    res.sendRedirect(adminBasePath + "/login?error");
                })
            )
            .sessionManagement(session -> session
                .maximumSessions(1)  // Only one admin session per user
                .maxSessionsPreventsLogin(true)
            )
            .headers(headers -> headers
                .frameOptions(frame -> frame.deny())
                .contentSecurityPolicy(csp -> 
                    csp.policyDirectives("default-src 'self'; script-src 'self'"))
            );

        return http.build();
    }
}

// IP-based access filter for admin endpoints
public class AdminIPFilter implements Filter {

    private static final Logger securityLog = LoggerFactory.getLogger("SECURITY");
    private final List<String> allowedCIDRs;
    private final boolean adminEnabled;

    public AdminIPFilter(List<String> allowedCIDRs, boolean adminEnabled) {
        this.allowedCIDRs = allowedCIDRs;
        this.adminEnabled = adminEnabled;
    }

    @Override
    public void doFilter(ServletRequest request, ServletResponse response, 
                         FilterChain chain) throws IOException, ServletException {
        HttpServletRequest httpRequest = (HttpServletRequest) request;
        HttpServletResponse httpResponse = (HttpServletResponse) response;

        // Layer 1: Check if admin is enabled in this environment
        if (!adminEnabled) {
            securityLog.warn("Admin access attempted but disabled: IP={}", 
                httpRequest.getRemoteAddr());
            httpResponse.sendError(404);  // Return 404, not 403 (don't reveal existence)
            return;
        }

        // Layer 2: IP allowlist check
        String clientIP = getClientIP(httpRequest);
        if (!isIPAllowed(clientIP)) {
            securityLog.error("Admin access BLOCKED - Unauthorized IP: {}, Path: {}",
                clientIP, httpRequest.getRequestURI());
            httpResponse.sendError(404);  // Return 404 to hide admin existence
            return;
        }

        // Layer 3: VPN/Internal network header check
        String vpnHeader = httpRequest.getHeader("X-VPN-Authenticated");
        if (vpnHeader == null || !validateVPNToken(vpnHeader)) {
            securityLog.error("Admin access BLOCKED - Missing VPN: IP={}", clientIP);
            httpResponse.sendError(404);
            return;
        }

        securityLog.info("Admin access allowed: IP={}, Path={}", 
            clientIP, httpRequest.getRequestURI());
        chain.doFilter(request, response);
    }

    private String getClientIP(HttpServletRequest request) {
        String xForwardedFor = request.getHeader("X-Forwarded-For");
        if (xForwardedFor != null && !xForwardedFor.isEmpty()) {
            return xForwardedFor.split(",")[0].trim();
        }
        return request.getRemoteAddr();
    }

    private boolean isIPAllowed(String clientIP) {
        return allowedCIDRs.stream()
            .anyMatch(cidr -> isIPInCIDR(clientIP, cidr));
    }

    private boolean isIPInCIDR(String ip, String cidr) {
        // Implementation using SubnetUtils or similar
        try {
            org.apache.commons.net.util.SubnetUtils subnet = 
                new org.apache.commons.net.util.SubnetUtils(cidr);
            subnet.setInclusiveHostCount(true);
            return subnet.getInfo().isInRange(ip);
        } catch (Exception e) {
            return false;
        }
    }

    private boolean validateVPNToken(String token) {
        // Validate VPN authentication token from corporate VPN
        return token != null && token.startsWith("VPN-AUTH-");
    }
}
```

**Defense in Depth Layers**:

1. **Network Segmentation** - Admin only accessible from internal network:
