**Additional Protections**:
- **Separate deployment**: Deploy admin panel as separate service with different domain (admin.internal.company.com)
- **MFA requirement**: Enforce hardware token or TOTP for all admin access
- **Session timeout**: 15-minute idle timeout for admin sessions
- **Audit trail**: Log every admin action to immutable audit log (CloudWatch, Splunk)
- **Alerting**: Real-time alerts for failed login attempts, unusual admin activity patterns
- **Regular rotation**: Rotate admin path token monthly via CI/CD pipeline
- **Penetration testing**: Quarterly testing specifically targeting admin panel discovery

Parsing DOCX files requires careful handling because DOCX files are ZIP archives containing multiple XML documents. If you use an unsafe XML parser configuration, attackers can embed XXE (XML External Entity) payloads in the document's internal XML files to read server files or perform SSRF attacks.

**VULNERABLE CODE**:

```csharp
using System;
using System.IO;
using System.IO.Packaging;
using System.Xml;
using System.Text;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;

namespace DocumentProcessor.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class DocumentController : ControllerBase
    {
        [HttpPost("extract-text")]
        public IActionResult ExtractText(IFormFile file)
        {
            if (file == null || file.Length == 0)
                return BadRequest("No file uploaded");

            using var stream = file.OpenReadStream();
            using var package = Package.Open(stream, FileMode.Open, FileAccess.Read);

            var documentPart = package.GetPart(
                new Uri("/word/document.xml", UriKind.Relative));

            // VULNERABLE: Default XmlDocument settings allow DTD processing
            var xmlDoc = new XmlDocument();
            using var partStream = documentPart.GetStream();
            xmlDoc.Load(partStream);  // XXE vulnerability here!

            var namespaceManager = new XmlNamespaceManager(xmlDoc.NameTable);
            namespaceManager.AddNamespace("w", 
                "http://schemas.openxmlformats.org/wordprocessingml/2006/main");

            var textNodes = xmlDoc.SelectNodes("//w:t", namespaceManager);
            var content = new StringBuilder();

            foreach (XmlNode node in textNodes)
            {
                content.Append(node.InnerText);
            }

            return Ok(new { text = content.ToString() });
        }
    }
}
```

**Attack Payload** - Malicious [Content_Types].xml inside DOCX:
```xml
<?xml version="1.0" encoding="UTF-8"?>
<!DOCTYPE foo [
  <!ENTITY xxe SYSTEM "file:///c:/windows/win.ini">
  <!ENTITY ssrf SYSTEM "http://169.254.169.254/latest/meta-data/iam/security-credentials/">
]>
<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">
  <Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>
  <Default Extension="xml" ContentType="application/xml"/>
  <Override PartName="/word/document.xml" ContentType="&xxe;"/>
</Types>
```

**Why This Is Dangerous**:
- `XmlDocument` with default settings enables DTD processing, allowing external entity resolution
- DOCX files contain multiple XML files that can each carry XXE payloads
- Attackers can exfiltrate sensitive files like web.config, appsettings.json, or cloud metadata
- SSRF attacks can reach internal services or cloud metadata endpoints (AWS, Azure, GCP)

**SECURE VERSION**:

```csharp
using System;
using System.IO;
using System.IO.Packaging;
using System.Xml;
using System.Text;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;

namespace DocumentProcessor.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class SecureDocumentController : ControllerBase
    {
        private readonly ILogger<SecureDocumentController> _logger;
        private const long MaxFileSize = 10 * 1024 * 1024; // 10MB limit
        private static readonly string[] AllowedExtensions = { ".docx" };

        public SecureDocumentController(ILogger<SecureDocumentController> logger)
        {
            _logger = logger;
        }

        [HttpPost("extract-text")]
        public IActionResult ExtractText(IFormFile file)
        {
            if (file == null || file.Length == 0)
                return BadRequest("No file uploaded");

            // Defense Layer 1: File size validation
            if (file.Length > MaxFileSize)
                return BadRequest("File too large");

            // Defense Layer 2: Extension validation
            var extension = Path.GetExtension(file.FileName).ToLowerInvariant();
            if (!AllowedExtensions.Contains(extension))
                return BadRequest("Invalid file type");

            try
            {
                using var stream = file.OpenReadStream();
                using var package = Package.Open(stream, FileMode.Open, FileAccess.Read);

                var documentUri = new Uri("/word/document.xml", UriKind.Relative);
                if (!package.PartExists(documentUri))
                    return BadRequest("Invalid DOCX structure");

                var documentPart = package.GetPart(documentUri);

                // SECURE: Create XmlReaderSettings with XXE protections
                var settings = new XmlReaderSettings
                {
                    DtdProcessing = DtdProcessing.Prohibit,  // Block DTDs entirely
                    XmlResolver = null,                       // Prevent external resolution
                    MaxCharactersFromEntities = 0,            // No entity expansion
                    MaxCharactersInDocument = 10_000_000      // Limit document size
                };

                var xmlDoc = new XmlDocument();
                xmlDoc.XmlResolver = null;  // Additional protection

                using var partStream = documentPart.GetStream();
                using var reader = XmlReader.Create(partStream, settings);
                xmlDoc.Load(reader);  // Safe loading with protected reader

                var namespaceManager = new XmlNamespaceManager(xmlDoc.NameTable);
                namespaceManager.AddNamespace("w", 
                    "http://schemas.openxmlformats.org/wordprocessingml/2006/main");

                var textNodes = xmlDoc.SelectNodes("//w:t", namespaceManager);
                var content = new StringBuilder();

                foreach (XmlNode node in textNodes)
                {
                    content.Append(node.InnerText);
                }

                _logger.LogInformation("Successfully processed document: {FileName}", 
                    file.FileName);

                return Ok(new { text = content.ToString() });
            }
            catch (XmlException ex)
            {
                _logger.LogWarning(ex, "XML parsing error - possible XXE attempt");
                return BadRequest("Invalid document format");
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, "Document processing error");
                return StatusCode(500, "Error processing document");
            }
        }
    }
}
```

**Key Security Controls**:
- `DtdProcessing.Prohibit` completely blocks DTD declarations, preventing XXE attacks
- `XmlResolver = null` prevents the parser from resolving any external references
- `MaxCharactersFromEntities = 0` prevents entity expansion attacks (billion laughs)
- File size and extension validation provide defense in depth
- Proper error handling avoids information disclosure

XLSX files present similar XXE risks because they're also ZIP archives containing XML files (worksheets, shared strings, styles). For legitimate DTD handling, you can use `DtdProcessing.Ignore` instead of `Prohibit`, but you must ensure `XmlResolver` remains null. Here's a production-grade solution:

**PRODUCTION PATTERN**:

```csharp
using System;
using System.IO;
using System.IO.Packaging;
using System.Xml;
using System.Xml.Linq;
using System.Collections.Generic;
using System.Linq;
using System.Security.Cryptography;
using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;
using Microsoft.AspNetCore.RateLimiting;

namespace DocumentProcessor.Services
{
    public interface ISecureDocumentParser
    {
        DocumentResult ParseDocument(Stream stream, string fileName);
    }

    public class DocumentResult
    {
        public bool Success { get; set; }
        public string Content { get; set; }
        public List<string> Errors { get; set; } = new();
        public string FileHash { get; set; }
    }

    public class SecureDocumentParser : ISecureDocumentParser
    {
        private readonly ILogger<SecureDocumentParser> _logger;

        // Secure XML reader settings - singleton for performance
        private static readonly XmlReaderSettings SecureXmlSettings = new()
        {
            DtdProcessing = DtdProcessing.Ignore,    // Ignore DTDs (don't process them)
            XmlResolver = null,                       // CRITICAL: No external resolution
            MaxCharactersFromEntities = 0,            // No entity expansion
            MaxCharactersInDocument = 50_000_000,     // 50MB character limit
            Async = false,
            CheckCharacters = true,
            CloseInput = true
        };

        private static readonly Dictionary<string, string[]> DocumentParts = new()
        {
            { ".docx", new[] { "/word/document.xml" } },
            { ".xlsx", new[] { "/xl/sharedStrings.xml", "/xl/worksheets/sheet1.xml" } },
            { ".pptx", new[] { "/ppt/slides/slide1.xml" } }
        };

        public SecureDocumentParser(ILogger<SecureDocumentParser> logger)
        {
            _logger = logger;
        }

        public DocumentResult ParseDocument(Stream stream, string fileName)
        {
            var result = new DocumentResult();
            var extension = Path.GetExtension(fileName).ToLowerInvariant();

            // Compute file hash for audit logging
            stream.Position = 0;
            using (var sha256 = SHA256.Create())
            {
                result.FileHash = Convert.ToHexString(sha256.ComputeHash(stream));
            }
            stream.Position = 0;

            try
            {
                // Validate it's actually a valid ZIP/OOXML package
                if (!IsValidOoxmlPackage(stream))
                {
                    _logger.LogWarning(
                        "Invalid OOXML package detected. Hash: {Hash}", 
                        result.FileHash);
                    result.Errors.Add("Invalid document format");
                    return result;
                }
                stream.Position = 0;

                using var package = Package.Open(stream, FileMode.Open, FileAccess.Read);

                // Scan all XML parts for potential XXE indicators before processing
                if (ContainsSuspiciousContent(package))
                {
                    _logger.LogWarning(
                        "Suspicious XML content detected in document. Hash: {Hash}",
                        result.FileHash);
                    result.Errors.Add("Document contains suspicious content");
                    return result;
                }

                if (!DocumentParts.TryGetValue(extension, out var parts))
                {
                    result.Errors.Add("Unsupported document type");
                    return result;
                }

                var contentBuilder = new List<string>();

                foreach (var partPath in parts)
                {
                    var uri = new Uri(partPath, UriKind.Relative);
                    if (!package.PartExists(uri))
                        continue;

                    var content = SafeParseXmlPart(package.GetPart(uri), extension);
                    if (!string.IsNullOrEmpty(content))
                        contentBuilder.Add(content);
                }

                result.Content = string.Join("\n", contentBuilder);
                result.Success = true;

                _logger.LogInformation(
                    "Successfully parsed document. Hash: {Hash}, Size: {Size} chars",
                    result.FileHash, result.Content.Length);
            }
            catch (XmlException ex)
            {
                _logger.LogWarning(ex, 
                    "XML parsing failed - potential XXE attack. Hash: {Hash}",
                    result.FileHash);
                result.Errors.Add("Document parsing failed");
            }
            catch (InvalidDataException ex)
            {
                _logger.LogWarning(ex,
                    "Invalid ZIP structure. Hash: {Hash}", result.FileHash);
                result.Errors.Add("Corrupted document");
            }
            catch (Exception ex)
            {
                _logger.LogError(ex, 
                    "Unexpected error processing document. Hash: {Hash}",
                    result.FileHash);
                result.Errors.Add("Processing error");
            }

            return result;
        }

        private bool IsValidOoxmlPackage(Stream stream)
        {
            try
            {
                // Check ZIP magic bytes: PK\x03\x04
                var buffer = new byte[4];
                stream.Read(buffer, 0, 4);
                stream.Position = 0;

                return buffer[0] == 0x50 && buffer[1] == 0x4B && 
                       buffer[2] == 0x03 && buffer[3] == 0x04;
            }
            catch
            {
                return false;
            }
        }

        private bool ContainsSuspiciousContent(Package package)
        {
            var suspiciousPatterns = new[]
            {
                "<!ENTITY",
                "<!DOCTYPE",
                "SYSTEM \"",
                "PUBLIC \"",
                "file://",
                "http://",
                "https://",
                "expect://",
                "php://"
            };

            foreach (var part in package.GetParts())
            {
                if (!part.ContentType.Contains("xml"))
                    continue;

                try
                {
                    using var partStream = part.GetStream();
                    using var reader = new StreamReader(partStream);

                    // Read first 10KB to check for DTD declarations
                    var buffer = new char[10240];
                    var read = reader.Read(buffer, 0, buffer.Length);
                    var content = new string(buffer, 0, read).ToUpperInvariant();

                    foreach (var pattern in suspiciousPatterns)
                    {
                        if (content.Contains(pattern.ToUpperInvariant()))
                        {
                            _logger.LogWarning(
                                "Suspicious pattern '{Pattern}' found in {Part}",
                                pattern, part.Uri);
                            return true;
                        }
                    }
                }
                catch
                {
                    // If we can't read a part, consider it suspicious
                    return true;
                }
            }

            return false;
        }

        private string SafeParseXmlPart(PackagePart part, string docType)
        {
            using var partStream = part.GetStream();
            using var reader = XmlReader.Create(partStream, SecureXmlSettings);

            var doc = XDocument.Load(reader);

            return docType switch
            {
                ".docx" => ExtractWordContent(doc),
                ".xlsx" => ExtractExcelContent(doc, part.Uri.ToString()),
                ".pptx" => ExtractPowerPointContent(doc),
                _ => string.Empty
            };
        }

        private string ExtractWordContent(XDocument doc)
        {
            XNamespace w = "http://schemas.openxmlformats.org/wordprocessingml/2006/main";
            return string.Join(" ", doc.Descendants(w + "t").Select(e => e.Value));
        }

        private string ExtractExcelContent(XDocument doc, string partUri)
        {
            XNamespace ns = "http://schemas.openxmlformats.org/spreadsheetml/2006/main";

            if (partUri.Contains("sharedStrings"))
            {
                return string.Join("\n", doc.Descendants(ns + "t").Select(e => e.Value));
            }
            else
            {
                // Worksheet cells
                return string.Join("\n", doc.Descendants(ns + "v").Select(e => e.Value));
            }
        }

        private string ExtractPowerPointContent(XDocument doc)
        {
            XNamespace a = "http://schemas.openxmlformats.org/drawingml/2006/main";
            return string.Join(" ", doc.Descendants(a + "t").Select(e => e.Value));
        }
    }
}

// Controller with rate limiting and additional protections
namespace DocumentProcessor.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    public class ProductionDocumentController : ControllerBase
    {
        private readonly ISecureDocumentParser _parser;
        private readonly ILogger<ProductionDocumentController> _logger;

        private const long MaxFileSize = 25 * 1024 * 1024; // 25MB
        private static readonly HashSet<string> AllowedTypes = new()
        {
            ".docx", ".xlsx", ".pptx"
        };
        private static readonly HashSet<string> AllowedMimeTypes = new()
        {
            "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
            "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet",
            "application/vnd.openxmlformats-officedocument.presentationml.presentation"
        };

        public ProductionDocumentController(
            ISecureDocumentParser parser,
            ILogger<ProductionDocumentController> logger)
        {
            _parser = parser;
            _logger = logger;
        }

        [HttpPost("parse")]
        [RequestSizeLimit(26_214_400)] // 25MB + overhead
        [EnableRateLimiting("document-upload")]
        public IActionResult ParseDocument(IFormFile file)
        {
            var clientIp = HttpContext.Connection.RemoteIpAddress?.ToString();

            // Validation Layer 1: Basic checks
            if (file == null || file.Length == 0)
            {
                _logger.LogWarning("Empty file upload from {IP}", clientIp);
                return BadRequest(new { error = "No file provided" });
            }

            if (file.Length > MaxFileSize)
            {
                _logger.LogWarning(
                    "Oversized file upload attempt: {Size} bytes from {IP}",
                    file.Length, clientIp);
                return BadRequest(new { error = "File too large" });
            }

            // Validation Layer 2: Extension check
            var extension = Path.GetExtension(file.FileName).ToLowerInvariant();
            if (!AllowedTypes.Contains(extension))
            {
                _logger.LogWarning(
                    "Invalid extension '{Ext}' from {IP}", extension, clientIp);
                return BadRequest(new { error = "Unsupported file type" });
            }

            // Validation Layer 3: MIME type check
            if (!AllowedMimeTypes.Contains(file.ContentType))
            {
                _logger.LogWarning(
                    "MIME type mismatch: '{Type}' for {Ext} from {IP}",
                    file.ContentType, extension, clientIp);
                return BadRequest(new { error = "Invalid content type" });
            }

            using var stream = new MemoryStream();
            file.CopyTo(stream);
            stream.Position = 0;

            var result = _parser.ParseDocument(stream, file.FileName);

            if (!result.Success)
            {
                _logger.LogWarning(
                    "Document parsing failed for {Hash} from {IP}: {Errors}",
                    result.FileHash, clientIp, string.Join(", ", result.Errors));
                return BadRequest(new { errors = result.Errors });
            }

            return Ok(new 
            { 
                content = result.Content,
                fileHash = result.FileHash
            });
        }
    }
}
