const Joi = require('joi');

const app = express();
app.use(helmet());
app.use(express.json({ limit: '10kb' }));

// Predefined templates - never allow user-controlled templates
const ALLOWED_TEMPLATES = {
  welcome: (data) => `Welcome, ${sanitize(data.name)}!`,
  notification: (data) => `You have ${parseInt(data.count, 10)} new messages`
};

function sanitize(input) {
  if (typeof input !== 'string') return '';
  return input.replace(/[<>"'&]/g, '');
}

const templateSchema = Joi.object({
  templateId: Joi.string().valid(...Object.keys(ALLOWED_TEMPLATES)).required(),
  data: Joi.object().required()
});

app.post('/api/render-template', (req, res) => {
  const { error, value } = templateSchema.validate(req.body);
  if (error) {
    return res.status(400).json({ error: 'Invalid request' });
  }

  const template = ALLOWED_TEMPLATES[value.templateId];
  const result = template(value.data);
  res.send(result);
});

app.listen(3000);
