Excellent! Automated dependency scanning is essential for continuous security. Here's a production-ready setup that catches vulnerabilities early and provides multiple layers of defense.

**PRODUCTION PATTERN**:

```javascript
// security/dependency-scanner.js
const { execSync } = require('child_process');
const fs = require('fs');
const path = require('path');

class DependencyScanner {
  constructor(options = {}) {
    this.severityThreshold = options.severityThreshold || 'moderate';
    this.allowedVulnerabilities = options.allowedVulnerabilities || [];
    this.outputDir = options.outputDir || './security-reports';
    this.failOnVulnerability = options.failOnVulnerability ?? true;
  }

  async scan() {
    const results = {
      timestamp: new Date().toISOString(),
      npmAudit: null,
      snykScan: null,
      licenseScan: null,
      overallStatus: 'pass'
    };

    try {
      results.npmAudit = this.runNpmAudit();
      results.snykScan = this.runSnykScan();
      results.licenseScan = this.runLicenseScan();

      if (this.hasBlockingVulnerabilities(results)) {
        results.overallStatus = 'fail';
      }

      this.generateReport(results);
      return results;
    } catch (error) {
      console.error('Security scan failed:', error.message);
      throw error;
    }
  }

  runNpmAudit() {
    try {
      const output = execSync('npm audit --json', {
        encoding: 'utf-8',
        maxBuffer: 10 * 1024 * 1024
      });
      return JSON.parse(output);
    } catch (error) {
      // npm audit exits with non-zero when vulnerabilities found
      if (error.stdout) {
        return JSON.parse(error.stdout);
      }
      throw error;
    }
  }

  runSnykScan() {
    try {
      const output = execSync('snyk test --json', {
        encoding: 'utf-8',
        maxBuffer: 10 * 1024 * 1024
      });
      return JSON.parse(output);
    } catch (error) {
      if (error.stdout) {
        return JSON.parse(error.stdout);
      }
      console.warn('Snyk scan unavailable, skipping...');
      return null;
    }
  }

  runLicenseScan() {
    try {
      const output = execSync('npx license-checker --json --production', {
        encoding: 'utf-8'
      });
      const licenses = JSON.parse(output);
      const riskyLicenses = ['GPL-3.0', 'AGPL-3.0', 'SSPL-1.0'];
      const violations = [];

      for (const [pkg, info] of Object.entries(licenses)) {
        if (riskyLicenses.some(l => info.licenses?.includes(l))) {
          violations.push({ package: pkg, license: info.licenses });
        }
      }

      return { violations, totalPackages: Object.keys(licenses).length };
    } catch (error) {
      console.warn('License scan failed:', error.message);
      return null;
    }
  }

  hasBlockingVulnerabilities(results) {
    const severityLevels = ['low', 'moderate', 'high', 'critical'];
    const thresholdIndex = severityLevels.indexOf(this.severityThreshold);

    if (results.npmAudit?.vulnerabilities) {
      const vulns = results.npmAudit.vulnerabilities;
      for (const [name, vuln] of Object.entries(vulns)) {
        const vulnSeverityIndex = severityLevels.indexOf(vuln.severity);
        if (vulnSeverityIndex >= thresholdIndex) {
          if (!this.allowedVulnerabilities.includes(name)) {
            console.error(`Blocking vulnerability: ${name} (${vuln.severity})`);
            return true;
          }
        }
      }
    }

    return false;
  }

  generateReport(results) {
    if (!fs.existsSync(this.outputDir)) {
      fs.mkdirSync(this.outputDir, { recursive: true });
    }

    const reportPath = path.join(
      this.outputDir,
      `security-report-${Date.now()}.json`
    );
    fs.writeFileSync(reportPath, JSON.stringify(results, null, 2));
    console.log(`Security report generated: ${reportPath}`);
  }
}

module.exports = DependencyScanner;
```

