This is a critical security question! Many applications suffer from insufficient workflow validation, allowing attackers to skip steps or manipulate state. The 2023 Retool breach showed how skipping workflow steps can lead to complete authentication bypass.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/json"
	"net/http"
	"sync"
)

type Order struct {
	ID          string  `json:"id"`
	Status      string  `json:"status"`
	TotalAmount float64 `json:"total_amount"`
	Items       []Item  `json:"items"`
}

type Item struct {
	ProductID string  `json:"product_id"`
	Quantity  int     `json:"quantity"`
	Price     float64 `json:"price"`
}

var orders = make(map[string]*Order)
var mu sync.RWMutex

// VULNERABLE: No validation of workflow transitions
func updateOrderStatus(w http.ResponseWriter, r *http.Request) {
	orderID := r.URL.Query().Get("order_id")
	newStatus := r.URL.Query().Get("status")

	mu.Lock()
	defer mu.Unlock()

	order, exists := orders[orderID]
	if !exists {
		http.Error(w, "Order not found", http.StatusNotFound)
		return
	}

	// DANGEROUS: Accepts any status without validation
	order.Status = newStatus

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(order)
}

// VULNERABLE: Direct jump to confirmation without payment
func confirmOrder(w http.ResponseWriter, r *http.Request) {
	orderID := r.URL.Query().Get("order_id")

	mu.Lock()
	defer mu.Unlock()

	order, exists := orders[orderID]
	if !exists {
		http.Error(w, "Order not found", http.StatusNotFound)
		return
	}

	// DANGEROUS: No check if payment was actually processed
	order.Status = "confirmed"
	// Ship order without payment verification!

	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(order)
}
```

**Attack Payload**:
```bash
# Skip payment step entirely - jump from cart to confirmed
curl -X POST "http://localhost:8080/api/order/status?order_id=12345&status=confirmed"

# Or directly call confirmation endpoint without paying
curl -X POST "http://localhost:8080/api/order/confirm?order_id=12345"
```

**Why This Is Dangerous**:
- Attackers can skip payment and get free products by jumping directly to "confirmed" status
- No validation that required steps (inventory check, payment processing) were completed
- Status can be arbitrarily set to any value, including invalid states
- Business logic bypass leads to direct financial loss

**SECURE VERSION**:

```go
package main

import (
	"encoding/json"
	"errors"
	"log"
	"net/http"
	"sync"
	"time"
)

type OrderStatus string

const (
	StatusCart       OrderStatus = "cart"
	StatusCheckout   OrderStatus = "checkout"
	StatusPayment    OrderStatus = "payment_pending"
	StatusPaid       OrderStatus = "paid"
	StatusProcessing OrderStatus = "processing"
	StatusShipped    OrderStatus = "shipped"
	StatusDelivered  OrderStatus = "delivered"
	StatusCancelled  OrderStatus = "cancelled"
)

// Define valid state transitions
var validTransitions = map[OrderStatus][]OrderStatus{
	StatusCart:       {StatusCheckout, StatusCancelled},
	StatusCheckout:   {StatusPayment, StatusCart, StatusCancelled},
	StatusPayment:    {StatusPaid, StatusCheckout, StatusCancelled},
	StatusPaid:       {StatusProcessing},
	StatusProcessing: {StatusShipped, StatusCancelled},
	StatusShipped:    {StatusDelivered},
	StatusDelivered:  {}, // Terminal state
	StatusCancelled:  {}, // Terminal state
}

type SecureOrder struct {
	ID              string        `json:"id"`
	Status          OrderStatus   `json:"status"`
	TotalAmount     float64       `json:"total_amount"`
	Items           []Item        `json:"items"`
	PaymentID       string        `json:"payment_id,omitempty"`
	PaymentVerified bool          `json:"payment_verified"`
	StatusHistory   []StatusEntry `json:"status_history"`
}

type StatusEntry struct {
	Status    OrderStatus `json:"status"`
	Timestamp time.Time   `json:"timestamp"`
	ActorID   string      `json:"actor_id"`
}

func (o *SecureOrder) CanTransitionTo(newStatus OrderStatus) bool {
	allowedStatuses, exists := validTransitions[o.Status]
	if !exists {
		return false
	}

	for _, allowed := range allowedStatuses {
		if allowed == newStatus {
			return true
		}
	}
	return false
}

func (o *SecureOrder) TransitionTo(newStatus OrderStatus, actorID string) error {
	if !o.CanTransitionTo(newStatus) {
		return errors.New("invalid state transition")
	}

	// Additional business rule validation
	if newStatus == StatusProcessing && !o.PaymentVerified {
		return errors.New("cannot process order without verified payment")
	}

	o.Status = newStatus
	o.StatusHistory = append(o.StatusHistory, StatusEntry{
		Status:    newStatus,
		Timestamp: time.Now(),
		ActorID:   actorID,
	})

	return nil
}
```

**Key Security Controls**:
- **State machine validation**: Only predefined transitions are allowed using a whitelist approach
- **Business rule enforcement**: Payment verification is required before order processing
- **Audit trail**: All status changes are logged with timestamp and actor ID for forensics

Excellent question! Production workflows need role-based transition control, external verification handling, and idempotency protection against replay attacks.

**PRODUCTION PATTERN**:

```go
package workflow

import (
	"context"
	"crypto/hmac"
	"crypto/sha256"
	"database/sql"
	"encoding/hex"
	"errors"
	"fmt"
	"log/slog"
	"sync"
	"time"

	"github.com/google/uuid"
)

// Role-based permissions
type Role string

const (
	RoleCustomer  Role = "customer"
	RoleStaff     Role = "staff"
	RoleManager   Role = "manager"
	RoleSystem    Role = "system"
	RolePaymentGW Role = "payment_gateway"
)

type OrderStatus string

const (
	StatusCart            OrderStatus = "cart"
	StatusCheckout        OrderStatus = "checkout"
	StatusAwaitingPayment OrderStatus = "awaiting_payment"
	StatusPaymentReceived OrderStatus = "payment_received"
	StatusVerified        OrderStatus = "verified"
	StatusProcessing      OrderStatus = "processing"
	StatusShipped         OrderStatus = "shipped"
	StatusDelivered       OrderStatus = "delivered"
	StatusRefundRequested OrderStatus = "refund_requested"
	StatusRefunded        OrderStatus = "refunded"
	StatusCancelled       OrderStatus = "cancelled"
)

type TransitionRule struct {
	FromStatus       OrderStatus
	ToStatus         OrderStatus
	AllowedRoles     []Role
	RequiresCallback bool
	CallbackType     string
	MaxRetries       int
	TimeoutSeconds   int
}

type WorkflowEngine struct {
	db               *sql.DB
	logger           *slog.Logger
	transitionRules  map[string]TransitionRule
	callbackSecrets  map[string]string
	processedNonces  sync.Map
	nonceExpiry      time.Duration
}

type TransitionRequest struct {
	OrderID       string
	TargetStatus  OrderStatus
	ActorID       string
	ActorRole     Role
	IdempotencyKey string
	CallbackData  *CallbackVerification
}

type CallbackVerification struct {
	Source    string
	Signature string
	Timestamp time.Time
	Nonce     string
	Payload   []byte
}

type Order struct {
	ID                string
	Status            OrderStatus
	TotalAmount       float64
	PaymentID         string
	PaymentVerified   bool
	PaymentVerifiedAt *time.Time
	ExternalRefID     string
	Version           int64 // Optimistic locking
	CreatedAt         time.Time
	UpdatedAt         time.Time
}

func NewWorkflowEngine(db *sql.DB, logger *slog.Logger) *WorkflowEngine {
	engine := &WorkflowEngine{
		db:              db,
		logger:          logger,
		transitionRules: make(map[string]TransitionRule),
		callbackSecrets: make(map[string]string),
		nonceExpiry:     15 * time.Minute,
	}

	// Define role-based transition rules
	engine.registerTransitions()
	return engine
}

func (e *WorkflowEngine) registerTransitions() {
	rules := []TransitionRule{
		// Customer can move from cart to checkout
		{StatusCart, StatusCheckout, []Role{RoleCustomer}, false, "", 0, 0},
		// Customer can initiate payment
		{StatusCheckout, StatusAwaitingPayment, []Role{RoleCustomer, RoleStaff}, false, "", 0, 0},
		// ONLY payment gateway can confirm payment (requires callback verification)
		{StatusAwaitingPayment, StatusPaymentReceived, []Role{RolePaymentGW}, true, "stripe", 3, 30},
		// System verifies payment automatically
		{StatusPaymentReceived, StatusVerified, []Role{RoleSystem}, false, "", 0, 0},
		// Staff processes verified orders
		{StatusVerified, StatusProcessing, []Role{RoleStaff, RoleManager}, false, "", 0, 0},
		// Staff marks as shipped
		{StatusProcessing, StatusShipped, []Role{RoleStaff, RoleManager}, false, "", 0, 0},
		// Delivery confirmation (could be carrier callback)
		{StatusShipped, StatusDelivered, []Role{RoleStaff, RoleSystem}, false, "", 0, 0},
		// Customer can request refund on delivered orders
		{StatusDelivered, StatusRefundRequested, []Role{RoleCustomer}, false, "", 0, 0},
		// Only managers can approve refunds
		{StatusRefundRequested, StatusRefunded, []Role{RoleManager}, false, "", 0, 0},
		// Various cancellation paths
		{StatusCart, StatusCancelled, []Role{RoleCustomer, RoleStaff}, false, "", 0, 0},
		{StatusCheckout, StatusCancelled, []Role{RoleCustomer, RoleStaff}, false, "", 0, 0},
		{StatusAwaitingPayment, StatusCancelled, []Role{RoleCustomer, RoleStaff, RoleSystem}, false, "", 0, 0},
	}

	for _, rule := range rules {
		key := fmt.Sprintf("%s->%s", rule.FromStatus, rule.ToStatus)
		e.transitionRules[key] = rule
	}
}

func (e *WorkflowEngine) ProcessTransition(ctx context.Context, req TransitionRequest) error {
	// Idempotency check - prevent replay attacks
	if req.IdempotencyKey != "" {
		if _, exists := e.processedNonces.Load(req.IdempotencyKey); exists {
			e.logger.Warn("duplicate transition request detected",
				slog.String("order_id", req.OrderID),
				slog.String("idempotency_key", req.IdempotencyKey),
			)
			return errors.New("duplicate request")
		}
	}

	// Start transaction for atomic operations
	tx, err := e.db.BeginTx(ctx, &sql.TxOptions{Isolation: sql.LevelSerializable})
	if err != nil {
		return fmt.Errorf("failed to start transaction: %w", err)
	}
	defer tx.Rollback()

	// Fetch current order with pessimistic lock
	order, err := e.getOrderForUpdate(ctx, tx, req.OrderID)
	if err != nil {
		return fmt.Errorf("failed to fetch order: %w", err)
	}

	// Validate transition is allowed
	rule, err := e.validateTransition(order.Status, req.TargetStatus, req.ActorRole)
	if err != nil {
		e.logger.Error("invalid transition attempted",
			slog.String("order_id", req.OrderID),
			slog.String("from_status", string(order.Status)),
			slog.String("to_status", string(req.TargetStatus)),
			slog.String("actor_id", req.ActorID),
			slog.String("actor_role", string(req.ActorRole)),
		)
		return err
	}

	// Verify callback signature if required
	if rule.RequiresCallback {
		if err := e.verifyCallback(req.CallbackData, rule.CallbackType); err != nil {
			e.logger.Error("callback verification failed",
				slog.String("order_id", req.OrderID),
				slog.String("callback_type", rule.CallbackType),
				slog.String("error", err.Error()),
			)
			return fmt.Errorf("callback verification failed: %w", err)
		}
	}

	// Apply business rules for specific transitions
	if err := e.applyBusinessRules(ctx, tx, order, req); err != nil {
		return err
	}

	// Update order status with optimistic locking
	if err := e.updateOrderStatus(ctx, tx, order, req); err != nil {
		return err
	}

	// Record audit log
	if err := e.recordAuditLog(ctx, tx, order, req); err != nil {
		return err
	}

	// Commit transaction
	if err := tx.Commit(); err != nil {
		return fmt.Errorf("failed to commit transaction: %w", err)
	}

	// Mark idempotency key as processed (with expiry)
	if req.IdempotencyKey != "" {
		e.processedNonces.Store(req.IdempotencyKey, time.Now())
		go e.scheduleNonceCleanup(req.IdempotencyKey)
	}

	e.logger.Info("order transition successful",
		slog.String("order_id", req.OrderID),
		slog.String("from_status", string(order.Status)),
		slog.String("to_status", string(req.TargetStatus)),
		slog.String("actor_id", req.ActorID),
	)

	return nil
}

func (e *WorkflowEngine) validateTransition(from, to OrderStatus, role Role) (TransitionRule, error) {
	key := fmt.Sprintf("%s->%s", from, to)
	rule, exists := e.transitionRules[key]
	if !exists {
		return TransitionRule{}, fmt.Errorf("transition %s is not allowed", key)
	}

	// Check if actor's role is permitted for this transition
	roleAllowed := false
	for _, allowedRole := range rule.AllowedRoles {
		if allowedRole == role {
			roleAllowed = true
			break
		}
	}

	if !roleAllowed {
		return TransitionRule{}, fmt.Errorf("role %s is not authorized for transition %s", role, key)
	}

	return rule, nil
}

func (e *WorkflowEngine) verifyCallback(callback *CallbackVerification, callbackType string) error {
	if callback == nil {
		return errors.New("callback data required but not provided")
	}

	// Check timestamp freshness (prevent replay attacks)
	if time.Since(callback.Timestamp) > 5*time.Minute {
		return errors.New("callback timestamp too old")
	}

	// Check nonce hasn't been used before
	if _, exists := e.processedNonces.Load(callback.Nonce); exists {
		return errors.New("callback nonce already used")
	}

	// Get secret for this callback source
	secret, exists := e.callbackSecrets[callbackType]
	if !exists {
		return fmt.Errorf("unknown callback source: %s", callbackType)
	}

	// Verify HMAC signature
	expectedSig := e.computeHMAC(callback.Payload, secret)
	if !hmac.Equal([]byte(callback.Signature), []byte(expectedSig)) {
		return errors.New("invalid callback signature")
	}

	// Store nonce to prevent replay
	e.processedNonces.Store(callback.Nonce, time.Now())

	return nil
}

func (e *WorkflowEngine) computeHMAC(payload []byte, secret string) string {
	mac := hmac.New(sha256.New, []byte(secret))
	mac.Write(payload)
	return hex.EncodeToString(mac.Sum(nil))
}

func (e *WorkflowEngine) applyBusinessRules(ctx context.Context, tx *sql.Tx, order *Order, req TransitionRequest) error {
	switch req.TargetStatus {
	case StatusVerified:
		// Payment must be verified before processing
		if !order.PaymentVerified {
			return errors.New("payment verification required before processing")
		}
	case StatusShipped:
		// Ensure inventory was decremented
		if err := e.verifyInventoryReserved(ctx, tx, order.ID); err != nil {
			return fmt.Errorf("inventory check failed: %w", err)
		}
	case StatusRefunded:
		// Verify refund was actually processed by payment gateway
		if err := e.verifyRefundProcessed(ctx, order.PaymentID); err != nil {
			return fmt.Errorf("refund verification failed: %w", err)
		}
	}
	return nil
}

func (e *WorkflowEngine) getOrderForUpdate(ctx context.Context, tx *sql.Tx, orderID string) (*Order, error) {
	query := `SELECT id, status, total_amount, payment_id, payment_verified, 
	          payment_verified_at, external_ref_id, version, created_at, updated_at
	          FROM orders WHERE id = $1 FOR UPDATE`

	var order Order
	err := tx.QueryRowContext(ctx, query, orderID).Scan(
		&order.ID, &order.Status, &order.TotalAmount, &order.PaymentID,
		&order.PaymentVerified, &order.PaymentVerifiedAt, &order.ExternalRefID,
		&order.Version, &order.CreatedAt, &order.UpdatedAt,
	)
	if err != nil {
		return nil, err
	}
	return &order, nil
}

func (e *WorkflowEngine) updateOrderStatus(ctx context.Context, tx *sql.Tx, order *Order, req TransitionRequest) error {
	// Optimistic locking with version check
	query := `UPDATE orders SET status = $1, version = version + 1, updated_at = NOW()
	          WHERE id = $2 AND version = $3`

	result, err := tx.ExecContext(ctx, query, req.TargetStatus, order.ID, order.Version)
	if err != nil {
		return err
	}

	rowsAffected, _ := result.RowsAffected()
	if rowsAffected == 0 {
		return errors.New("concurrent modification detected - please retry")
	}
	return nil
}

func (e *WorkflowEngine) recordAuditLog(ctx context.Context, tx *sql.Tx, order *Order, req TransitionRequest) error {
	query := `INSERT INTO order_audit_log (id, order_id, from_status, to_status, actor_id, actor_role, timestamp, idempotency_key)
	          VALUES ($1, $2, $3, $4, $5, $6, NOW(), $7)`

	_, err := tx.ExecContext(ctx, query,
		uuid.New().String(),
		order.ID,
		order.Status,
		req.TargetStatus,
		req.ActorID,
		req.ActorRole,
		req.IdempotencyKey,
	)
	return err
}

func (e *WorkflowEngine) scheduleNonceCleanup(key string) {
	time.Sleep(e.nonceExpiry)
	e.processedNonces.Delete(key)
}

func (e *WorkflowEngine) verifyInventoryReserved(ctx context.Context, tx *sql.Tx, orderID string) error {
	// Implementation: verify inventory reservation exists
	return nil
}

func (e *WorkflowEngine) verifyRefundProcessed(ctx context.Context, paymentID string) error {
