Setting up HTTPS requires careful TLS configuration. Many older tutorials show configurations that are now critically insecure due to protocol vulnerabilities like POODLE, BEAST, and CRIME attacks.

**VULNERABLE CODE**:

```javascript
const https = require('https');
const fs = require('fs');
const express = require('express');

const app = express();

// VULNERABLE: Allows weak TLS versions and ciphers
const options = {
  key: fs.readFileSync('server.key'),
  cert: fs.readFileSync('server.crt'),
  // Explicitly allowing deprecated protocols
  secureProtocol: 'SSLv23_method',
  // No minimum version specified - allows TLS 1.0
  // No cipher restrictions
};

app.get('/api/payment', (req, res) => {
  // Sensitive payment data transmitted over weak TLS
  res.json({ cardNumber: '4111111111111111', cvv: '123' });
});

https.createServer(options, app).listen(443, () => {
  console.log('HTTPS Server running on port 443');
});
```

**Attack Scenario** (POODLE Attack):
```text
1. Attacker positions as MITM on network (coffee shop WiFi, compromised router)
2. Injects TCP RST packets to force connection failures
3. Client/server fall back to SSLv3 or TLS 1.0
4. Attacker exploits CBC padding oracle vulnerability
5. Decrypts ~256 requests per byte of secret data
6. Session cookies and payment data exposed within minutes
```

**Why This Is Dangerous**:
- SSLv3 and TLS 1.0/1.1 have known cryptographic weaknesses exploited by POODLE, BEAST attacks
- Default cipher suites include weak algorithms (RC4, DES, export ciphers)
- Protocol downgrade attacks force connections to weakest supported version
- PCI DSS 3.2+ explicitly prohibits SSLv3 and TLS 1.0 for payment data

**SECURE VERSION**:

```javascript
const https = require('https');
const fs = require('fs');
const express = require('express');
const crypto = require('crypto');

const app = express();

// SECURE: Modern TLS configuration
const options = {
  key: fs.readFileSync('server.key'),
  cert: fs.readFileSync('server.crt'),
  ca: fs.readFileSync('ca-chain.crt'), // Full certificate chain

  // CRITICAL: Enforce minimum TLS 1.2 (TLS 1.3 preferred)
  minVersion: 'TLSv1.2',
  maxVersion: 'TLSv1.3',

  // Strong cipher suites only - TLS 1.3 and secure TLS 1.2 ciphers
  ciphers: [
    'TLS_AES_256_GCM_SHA384',
    'TLS_CHACHA20_POLY1305_SHA256',
    'TLS_AES_128_GCM_SHA256',
    'ECDHE-ECDSA-AES256-GCM-SHA384',
    'ECDHE-RSA-AES256-GCM-SHA384',
    'ECDHE-ECDSA-CHACHA20-POLY1305',
    'ECDHE-RSA-CHACHA20-POLY1305'
  ].join(':'),

  // Prefer server cipher order
  honorCipherOrder: true,

  // Enable secure ECDH curves
  ecdhCurve: 'X25519:P-256:P-384'
};

// Security headers middleware
app.use((req, res, next) => {
  res.setHeader('Strict-Transport-Security', 'max-age=31536000; includeSubDomains; preload');
  next();
});

app.get('/api/payment', (req, res) => {
  res.json({ status: 'secure', timestamp: Date.now() });
});

https.createServer(options, app).listen(443, () => {
  console.log('Secure HTTPS Server running with TLS 1.2+');
});
```

**Key Security Controls**:
- `minVersion: 'TLSv1.2'` prevents downgrade to vulnerable protocols; TLS 1.2 is minimum for PCI compliance
- Explicit cipher list excludes weak algorithms (RC4, DES, 3DES, CBC-mode without AEAD)
- `honorCipherOrder: true` ensures server chooses strongest mutually-supported cipher
- HSTS header forces browsers to always use HTTPS, preventing SSL stripping attacks

Excellent question! Outbound requests are often overlooked but equally critical. A compromised outbound connection can leak API keys, customer data, and enable supply chain attacks.

**PRODUCTION PATTERN**:

```javascript
const https = require('https');
const tls = require('tls');
const axios = require('axios');
const fs = require('fs');

// Create secure HTTPS agent for all outbound requests
const createSecureAgent = () => {
  return new https.Agent({
    // CRITICAL: Enforce TLS 1.2 minimum
    minVersion: 'TLSv1.2',
    maxVersion: 'TLSv1.3',

    // Strong ciphers only
    ciphers: [
      'TLS_AES_256_GCM_SHA384',
      'TLS_CHACHA20_POLY1305_SHA256',
      'ECDHE-ECDSA-AES256-GCM-SHA384',
      'ECDHE-RSA-AES256-GCM-SHA384'
    ].join(':'),

    // CRITICAL: Always verify certificates in production
    rejectUnauthorized: process.env.NODE_ENV === 'production',

    // Optional: Pin specific CAs for critical services
    ca: process.env.CUSTOM_CA_PATH 
      ? fs.readFileSync(process.env.CUSTOM_CA_PATH)
      : undefined,

    // Connection pooling settings
    keepAlive: true,
    maxSockets: 50,
    maxFreeSockets: 10,
    timeout: 30000
  });
};

// Create configured axios instance
const secureAxios = axios.create({
  httpsAgent: createSecureAgent(),
  timeout: 30000,
  validateStatus: (status) => status >= 200 && status < 500
});

// Request interceptor for logging and monitoring
secureAxios.interceptors.request.use(
  (config) => {
    config.metadata = { startTime: Date.now() };
    console.log(`[OUTBOUND] ${config.method?.toUpperCase()} ${config.url}`);
    return config;
  },
  (error) => {
    console.error('[OUTBOUND ERROR]', error.message);
    return Promise.reject(error);
  }
);

// Response interceptor for TLS verification logging
secureAxios.interceptors.response.use(
  (response) => {
    const duration = Date.now() - response.config.metadata.startTime;
    const socket = response.request?.socket;

    if (socket && socket.getPeerCertificate) {
      const cert = socket.getPeerCertificate();
      const tlsVersion = socket.getProtocol();
      const cipher = socket.getCipher();

      console.log(`[TLS] Version: ${tlsVersion}, Cipher: ${cipher?.name}`);
      console.log(`[CERT] Subject: ${cert.subject?.CN}, Valid until: ${cert.valid_to}`);

      // Alert on TLS 1.2 (prefer 1.3)
      if (tlsVersion === 'TLSv1.2') {
        console.warn('[SECURITY] TLS 1.2 in use - TLS 1.3 preferred');
      }
    }

    console.log(`[OUTBOUND] Response ${response.status} in ${duration}ms`);
    return response;
  },
  (error) => {
    // Handle certificate/TLS errors specifically
    if (error.code === 'UNABLE_TO_VERIFY_LEAF_SIGNATURE') {
      console.error('[SECURITY ALERT] Certificate verification failed!');
    } else if (error.code === 'ERR_TLS_CERT_ALTNAME_INVALID') {
      console.error('[SECURITY ALERT] Certificate hostname mismatch!');
    } else if (error.message.includes('SSL')) {
      console.error('[SECURITY ALERT] SSL/TLS error:', error.message);
    }
    return Promise.reject(error);
  }
);

// Certificate pinning for critical services
const createPinnedAgent = (expectedFingerprint) => {
  return new https.Agent({
    minVersion: 'TLSv1.2',
    rejectUnauthorized: true,
    checkServerIdentity: (hostname, cert) => {
      // Standard hostname verification
      const err = tls.checkServerIdentity(hostname, cert);
      if (err) return err;

      // Certificate pinning
      const fingerprint = cert.fingerprint256;
      if (fingerprint !== expectedFingerprint) {
        return new Error(
          `Certificate fingerprint mismatch. ` +
          `Expected: ${expectedFingerprint}, Got: ${fingerprint}`
        );
      }
      return undefined;
    }
  });
};

// Example: Secure API call with retry logic
const callExternalAPI = async (endpoint, data, retries = 3) => {
  for (let attempt = 1; attempt <= retries; attempt++) {
    try {
      const response = await secureAxios.post(endpoint, data, {
        headers: {
          'Content-Type': 'application/json',
          'X-Request-ID': crypto.randomUUID()
        }
      });
      return response.data;
    } catch (error) {
      // Don't retry on certificate errors - fail fast
      if (error.code?.includes('CERT') || error.code?.includes('SSL')) {
        throw error;
      }

      if (attempt === retries) throw error;

      const delay = Math.pow(2, attempt) * 1000;
      console.log(`[RETRY] Attempt ${attempt} failed, retrying in ${delay}ms`);
      await new Promise(r => setTimeout(r, delay));
    }
  }
};

module.exports = { secureAxios, createPinnedAgent, callExternalAPI };
```

