        // Dynamic metadata: stored as JSON, but still bound with parameters
        $metadata = normalizeMetadata($_POST['meta'] ?? []);
        $metadataJson = json_encode($metadata, JSON_UNESCAPED_UNICODE | JSON_UNESCAPED_SLASHES);

        // PRIMARY DEFENSE: parameterized SQL with fixed structure
        $stmt = $pdo->prepare(
            'INSERT INTO uploaded_files (
                user_id, original_name, stored_name, stored_path,
                content_type, size_bytes, metadata_json, created_at
