            ':original_name' => $file['name'],
            ':stored_name'   => $safeName,
            ':stored_path'   => $targetPath,
            ':content_type'  => $file['type'],
            ':size_bytes'    => $file['size'],
            ':metadata_json' => $metadataJson,
