**Attack Scenario**:
```text
# Attacker performs credential stuffing attack
# 10,000 failed logins in 1 hour from rotating IPs
# All logged to file, no one notices for weeks
# Eventually one account is compromised
# Attacker accesses sensitive data undetected
```

**Why This Is Dangerous**:
- Logs are written but never actively monitored
- No threshold-based alerting for brute force attacks
- No detection of impossible travel or unusual access patterns
- No real-time notification to security team
- Attackers can persist for days/weeks before discovery

**SECURE VERSION**:

```javascript
const express = require('express');
const winston = require('winston');
const bcrypt = require('bcrypt');
const Redis = require('ioredis');
const axios = require('axios');

const app = express();
app.use(express.json());

const redis = new Redis();

// Structured logging with CloudWatch/SIEM integration
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  transports: [
    new winston.transports.File({ filename: 'auth.log' }),
    new winston.transports.Console()
  ]
});

// Alert thresholds
const ALERT_CONFIG = {
  failedLoginsPerUser: 5,
  failedLoginsPerIP: 10,
  failedLoginsGlobal: 100,
  timeWindowSeconds: 300, // 5 minutes
  slackWebhook: process.env.SLACK_SECURITY_WEBHOOK,
  pagerDutyKey: process.env.PAGERDUTY_KEY
};

async function sendSecurityAlert(alertType, details) {
  const alert = {
    type: alertType,
    severity: details.severity || 'HIGH',
    timestamp: new Date().toISOString(),
    ...details
  };

  logger.error('SECURITY_ALERT', alert);

  // Send to Slack for immediate visibility
  if (ALERT_CONFIG.slackWebhook) {
    await axios.post(ALERT_CONFIG.slackWebhook, {
      text: `:rotating_light: Security Alert: ${alertType}`,
      attachments: [{
        color: 'danger',
        fields: Object.entries(details).map(([k, v]) => ({
          title: k,
          value: String(v),
          short: true
        }))
      }]
    }).catch(err => logger.error('Slack alert failed', { error: err.message }));
  }

  // Critical alerts go to PagerDuty
  if (details.severity === 'CRITICAL' && ALERT_CONFIG.pagerDutyKey) {
    await axios.post('https://events.pagerduty.com/v2/enqueue', {
      routing_key: ALERT_CONFIG.pagerDutyKey,
      event_action: 'trigger',
      payload: {
        summary: `Security: ${alertType}`,
        severity: 'critical',
        source: 'auth-service',
        custom_details: details
      }
    }).catch(err => logger.error('PagerDuty alert failed', { error: err.message }));
  }
}

async function checkAndAlert(username, ip) {
  const now = Math.floor(Date.now() / 1000);
  const windowStart = now - ALERT_CONFIG.timeWindowSeconds;

  // Track failures per user
  const userKey = `auth:fail:user:${username}`;
  await redis.zadd(userKey, now, `${now}:${ip}`);
  await redis.zremrangebyscore(userKey, 0, windowStart);
  const userFailures = await redis.zcard(userKey);

  // Track failures per IP
  const ipKey = `auth:fail:ip:${ip}`;
  await redis.zadd(ipKey, now, `${now}:${username}`);
  await redis.zremrangebyscore(ipKey, 0, windowStart);
  const ipFailures = await redis.zcard(ipKey);

  // Track global failures
  const globalKey = 'auth:fail:global';
  await redis.zadd(globalKey, now, `${now}:${ip}:${username}`);
  await redis.zremrangebyscore(globalKey, 0, windowStart);
  const globalFailures = await redis.zcard(globalKey);

  // Alert on suspicious patterns
  if (userFailures >= ALERT_CONFIG.failedLoginsPerUser) {
    await sendSecurityAlert('BRUTE_FORCE_USER', {
      username,
      failureCount: userFailures,
      timeWindowMinutes: ALERT_CONFIG.timeWindowSeconds / 60,
      lastIP: ip,
      severity: userFailures >= 20 ? 'CRITICAL' : 'HIGH'
    });
  }

  if (ipFailures >= ALERT_CONFIG.failedLoginsPerIP) {
    await sendSecurityAlert('CREDENTIAL_STUFFING_IP', {
      ip,
      failureCount: ipFailures,
      timeWindowMinutes: ALERT_CONFIG.timeWindowSeconds / 60,
      severity: ipFailures >= 50 ? 'CRITICAL' : 'HIGH'
    });
  }

  if (globalFailures >= ALERT_CONFIG.failedLoginsGlobal) {
    await sendSecurityAlert('DISTRIBUTED_ATTACK', {
      globalFailures,
      timeWindowMinutes: ALERT_CONFIG.timeWindowSeconds / 60,
      severity: 'CRITICAL'
    });
  }
}

app.post('/api/login', async (req, res) => {
