  slackWebhook: process.env.SLACK_SECURITY_WEBHOOK,
  pagerDutyKey: process.env.PAGERDUTY_KEY,
  siemEndpoint: process.env.SIEM_ENDPOINT,

  thresholds: {
    failedLoginsPerUser: { count: 5, windowSec: 300, severity: 'HIGH' },
    failedLoginsPerIP: { count: 10, windowSec: 300, severity: 'HIGH' },
    sensitiveDataAccess: { count: 50, windowSec: 60, severity: 'CRITICAL' },
    bulkExportRecords: { count: 1000, windowSec: 300, severity: 'CRITICAL' },
    apiRequestsPerUser: { count: 1000, windowSec: 60, severity: 'MEDIUM' }
  },

  // Impossible travel: km/h threshold (commercial flight ~900 km/h)
  maxTravelSpeedKmH: 1000,

  // Off-hours for alerting (UTC)
  businessHours: { start: 8, end: 20 },

  // Sensitive resources requiring extra monitoring
  sensitiveEndpoints: [
    '/api/admin',
    '/api/users/export',
    '/api/billing',
    '/api/secrets',
    '/api/audit-logs'
  ]
};

class SecurityAlertingService {
  constructor(config) {
    this.config = config;
    this.logger = winston.createLogger({
      level: 'info',
      format: winston.format.combine(
        winston.format.timestamp(),
        winston.format.json()
      ),
      defaultMeta: { service: 'security-alerting' },
      transports: [
        new winston.transports.File({ filename: 'security-events.log' }),
        new winston.transports.Console()
      ]
    });
  }

  async logSecurityEvent(eventType, details) {
    const event = {
      eventId: crypto.randomUUID(),
      eventType,
      timestamp: new Date().toISOString(),
      ...details
    };

    this.logger.info('SECURITY_EVENT', event);

    // Forward to SIEM for correlation
    if (this.config.siemEndpoint) {
      await this.forwardToSIEM(event);
    }

    return event;
  }

  async forwardToSIEM(event) {
    try {
      await axios.post(this.config.siemEndpoint, event, {
        headers: { 'Content-Type': 'application/json' },
        timeout: 5000
      });
    } catch (error) {
      this.logger.error('SIEM_FORWARD_FAILED', { error: error.message, event });
    }
  }

  async sendAlert(alertType, details) {
    const alert = {
      alertId: crypto.randomUUID(),
      type: alertType,
      timestamp: new Date().toISOString(),
      ...details
    };

    this.logger.error('SECURITY_ALERT', alert);

    // Slack notification
    await this.sendSlackAlert(alert);

    // PagerDuty for critical alerts
    if (details.severity === 'CRITICAL') {
      await this.sendPagerDutyAlert(alert);
    }

    return alert;
  }

  async sendSlackAlert(alert) {
    if (!this.config.slackWebhook) return;

    const severityEmoji = {
      CRITICAL: ':rotating_light:',
      HIGH: ':warning:',
      MEDIUM: ':information_source:'
    };

    try {
      await axios.post(this.config.slackWebhook, {
        text: `${severityEmoji[alert.severity] || ':bell:'} *Security Alert: ${alert.type}*`,
        attachments: [{
          color: alert.severity === 'CRITICAL' ? 'danger' : 'warning',
          fields: [
            { title: 'Alert ID', value: alert.alertId, short: true },
            { title: 'Severity', value: alert.severity, short: true },
            { title: 'User', value: alert.userId || 'N/A', short: true },
            { title: 'IP', value: alert.ip || 'N/A', short: true },
            { title: 'Details', value: JSON.stringify(alert.details || {}, null, 2), short: false }
          ],
          ts: Math.floor(Date.now() / 1000)
        }]
      });
    } catch (error) {
      this.logger.error('SLACK_ALERT_FAILED', { error: error.message });
    }
  }

  async sendPagerDutyAlert(alert) {
    if (!this.config.pagerDutyKey) return;

    try {
      await axios.post('https://events.pagerduty.com/v2/enqueue', {
        routing_key: this.config.pagerDutyKey,
        event_action: 'trigger',
        dedup_key: `${alert.type}-${alert.userId || alert.ip}`,
        payload: {
          summary: `Security Alert: ${alert.type}`,
          severity: 'critical',
          source: 'security-monitoring',
          custom_details: alert
        }
      });
    } catch (error) {
      this.logger.error('PAGERDUTY_ALERT_FAILED', { error: error.message });
    }
  }

  // Impossible travel detection
  async checkImpossibleTravel(userId, currentIP) {
    const currentGeo = geoip.lookup(currentIP);
    if (!currentGeo || !currentGeo.ll) return null;

    const lastLoginKey = `user:lastlogin:${userId}`;
    const lastLogin = await redis.hgetall(lastLoginKey);

    if (lastLogin && lastLogin.lat && lastLogin.lon) {
      const timeDiffHours = (Date.now() - parseInt(lastLogin.timestamp)) / (1000 * 60 * 60);
      const distanceKm = this.calculateDistance(
        parseFloat(lastLogin.lat),
        parseFloat(lastLogin.lon),
        currentGeo.ll[0],
        currentGeo.ll[1]
      );

      const speedKmH = distanceKm / timeDiffHours;

      if (speedKmH > this.config.maxTravelSpeedKmH && distanceKm > 100) {
        return {
          detected: true,
          lastLocation: { lat: lastLogin.lat, lon: lastLogin.lon, city: lastLogin.city },
          currentLocation: { lat: currentGeo.ll[0], lon: currentGeo.ll[1], city: currentGeo.city },
          distanceKm: Math.round(distanceKm),
          timeDiffHours: timeDiffHours.toFixed(2),
          impliedSpeedKmH: Math.round(speedKmH)
        };
      }
    }

    // Update last login location
    await redis.hmset(lastLoginKey, {
      lat: currentGeo.ll[0],
      lon: currentGeo.ll[1],
      city: currentGeo.city || 'Unknown',
      ip: currentIP,
      timestamp: Date.now()
    });
    await redis.expire(lastLoginKey, 86400 * 30); // 30 days

    return null;
  }

  calculateDistance(lat1, lon1, lat2, lon2) {
    const R = 6371; // Earth radius in km
    const dLat = this.toRad(lat2 - lat1);
    const dLon = this.toRad(lon2 - lon1);
    const a = Math.sin(dLat / 2) ** 2 +
              Math.cos(this.toRad(lat1)) * Math.cos(this.toRad(lat2)) *
              Math.sin(dLon / 2) ** 2;
    return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
  }

  toRad(deg) {
    return deg * (Math.PI / 180);
  }

  // Privilege escalation detection
  async checkPrivilegeEscalation(userId, oldRole, newRole, changedBy) {
    const privilegeHierarchy = { user: 1, moderator: 2, admin: 3, superadmin: 4 };

    if (privilegeHierarchy[newRole] > privilegeHierarchy[oldRole]) {
      const isSelfEscalation = userId === changedBy;

      await this.sendAlert('PRIVILEGE_ESCALATION', {
        severity: isSelfEscalation ? 'CRITICAL' : 'HIGH',
        userId,
        oldRole,
        newRole,
        changedBy,
        selfEscalation: isSelfEscalation,
        details: {
          riskLevel: isSelfEscalation ? 'CRITICAL - Self escalation attempt' : 'HIGH - Role elevation'
        }
      });

      return true;
    }
    return false;
  }

  // Bulk data access detection
  async checkBulkDataAccess(userId, endpoint, recordCount) {
    const threshold = this.config.thresholds.bulkExportRecords;
    const key = `data:access:${userId}:${endpoint.replace(/\//g, ':')}}`;
    const now = Math.floor(Date.now() / 1000);

    await redis.zadd(key, now, `${now}:${recordCount}`);
    await redis.zremrangebyscore(key, 0, now - threshold.windowSec);

    // Sum records accessed in window
    const accessLogs = await redis.zrange(key, 0, -1);
    const totalRecords = accessLogs.reduce((sum, log) => {
      return sum + parseInt(log.split(':')[1] || 0);
    }, 0);

    if (totalRecords >= threshold.count) {
      await this.sendAlert('BULK_DATA_EXFILTRATION', {
        severity: threshold.severity,
        userId,
        endpoint,
        recordsAccessed: totalRecords,
        timeWindowMinutes: threshold.windowSec / 60,
        details: {
          message: 'Potential data exfiltration detected'
        }
      });
      return true;
    }
    return false;
  }

  // Off-hours access detection
  async checkOffHoursAccess(userId, ip, endpoint) {
    const hour = new Date().getUTCHours();
    const isOffHours = hour < this.config.businessHours.start || 
                       hour >= this.config.businessHours.end;

    const isSensitive = this.config.sensitiveEndpoints.some(
      se => endpoint.startsWith(se)
    );

    if (isOffHours && isSensitive) {
      await this.sendAlert('OFF_HOURS_SENSITIVE_ACCESS', {
        severity: 'MEDIUM',
        userId,
        ip,
        endpoint,
        hourUTC: hour,
        details: {
          message: 'Sensitive resource accessed outside business hours'
        }
      });
      return true;
    }
    return false;
  }
}

// Initialize service
const alertingService = new SecurityAlertingService(ALERT_CONFIG);

// Middleware for comprehensive monitoring
const securityMonitoringMiddleware = async (req, res, next) => {
  const startTime = Date.now();
  const userId = req.user?.id || 'anonymous';
  const ip = req.ip;
  const endpoint = req.path;

  // Check off-hours access for sensitive endpoints
  await alertingService.checkOffHoursAccess(userId, ip, endpoint);

  // Capture response for data access monitoring
  const originalJson = res.json.bind(res);
  res.json = async (data) => {
    // Check for bulk data access
    if (Array.isArray(data) || (data && data.records)) {
      const recordCount = Array.isArray(data) ? data.length : 
                          (data.records?.length || 0);
      await alertingService.checkBulkDataAccess(userId, endpoint, recordCount);
    }

    // Log access event
    await alertingService.logSecurityEvent(SECURITY_EVENTS.SENSITIVE_DATA_ACCESS, {
      userId,
      ip,
      endpoint,
      method: req.method,
      statusCode: res.statusCode,
      responseTimeMs: Date.now() - startTime,
      userAgent: req.get('User-Agent')
    });

    return originalJson(data);
  };

  next();
};

app.use(securityMonitoringMiddleware);

// Export for use in routes
module.exports = { alertingService, SECURITY_EVENTS, securityMonitoringMiddleware };
```

