**Additional Protections**:
- **Two-factor debug enablement**: Requires both `APP_ENV=development` AND `ENABLE_DEBUG=true`
- **Error ID correlation**: Users can report error IDs, ops can find full details in logs
- **Context timeout**: Prevents hanging requests from leaking timing information
- **Security headers**: `X-Content-Type-Options: nosniff` prevents MIME sniffing
- **Structured JSON logging in production**: Enables log aggregation and alerting
- **Request context preservation**: Error IDs flow through the entire request lifecycle
- **Explicit error categorization**: Different messages for 400 vs 404 vs 500 without leaking internals

Simply logging authentication events without alerting on suspicious patterns leaves you blind to active attacks. The 2023 Uber breach demonstrated how attackers exploited the lack of alerting on repeated MFA failures - 18,000+ failed attempts went unnoticed until it was too late.

**VULNERABLE CODE**:

```go
package main

import (
	"database/sql"
	"log"
	"net/http"
	"time"

	"golang.org/x/crypto/bcrypt"
	_ "github.com/lib/pq"
)

var db *sql.DB

func loginHandler(w http.ResponseWriter, r *http.Request) {
	username := r.FormValue("username")
	password := r.FormValue("password")

	var storedHash string
	err := db.QueryRow("SELECT password_hash FROM users WHERE username = $1", username).Scan(&storedHash)
	if err != nil {
		// Simple log, no alerting
		log.Printf("Login failed for user: %s", username)
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	if err := bcrypt.CompareHashAndPassword([]byte(storedHash), []byte(password)); err != nil {
		// Just logging to stdout, no pattern detection
		log.Printf("Password mismatch for user: %s at %s", username, time.Now().Format(time.RFC3339))
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	log.Printf("Successful login for user: %s", username)
	w.WriteHeader(http.StatusOK)
}
```

**Attack Scenario**:
```bash
# Attacker runs brute force script - thousands of attempts
for i in {1..10000}; do
  curl -X POST http://target.com/login -d "username=admin&password=attempt$i"
done
# Each attempt is logged but nobody is alerted until breach occurs
```

**Why This Is Dangerous**:
- Logs exist but are never monitored or analyzed in real-time
- No threshold-based alerting for failed attempts
- No IP-based anomaly detection
- Attackers can conduct brute force attacks indefinitely
- Security team only discovers attack during post-incident forensics

**SECURE VERSION**:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"net/http"
	"sync"
	"time"

	"github.com/go-redis/redis/v8"
	"github.com/sirupsen/logrus"
	"golang.org/x/crypto/bcrypt"
	_ "github.com/lib/pq"
)

var (
	db          *sql.DB
	redisClient *redis.Client
	log         = logrus.New()
	alertMutex  sync.Mutex
)

const (
	FailedLoginThreshold    = 5
	FailedLoginWindowSecs   = 300 // 5 minutes
	IPFailedLoginThreshold  = 20
)

type SecurityEvent struct {
	EventType   string    `json:"event_type"`
	Username    string    `json:"username"`
	IPAddress   string    `json:"ip_address"`
	UserAgent   string    `json:"user_agent"`
	Timestamp   time.Time `json:"timestamp"`
	FailCount   int64     `json:"fail_count,omitempty"`
	Severity    string    `json:"severity"`
}

func loginHandler(w http.ResponseWriter, r *http.Request) {
	ctx := context.Background()
	username := r.FormValue("username")
	password := r.FormValue("password")
	clientIP := getClientIP(r)

	event := SecurityEvent{
		Username:  username,
		IPAddress: clientIP,
		UserAgent: r.UserAgent(),
		Timestamp: time.Now().UTC(),
	}

	var storedHash string
	err := db.QueryRow("SELECT password_hash FROM users WHERE username = $1", username).Scan(&storedHash)
	if err != nil {
		event.EventType = "LOGIN_FAILED_USER_NOT_FOUND"
		event.Severity = "MEDIUM"
		logAndCheckThresholds(ctx, event, clientIP, username)
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	if err := bcrypt.CompareHashAndPassword([]byte(storedHash), []byte(password)); err != nil {
		event.EventType = "LOGIN_FAILED_INVALID_PASSWORD"
		event.Severity = "MEDIUM"
		logAndCheckThresholds(ctx, event, clientIP, username)
		http.Error(w, "Invalid credentials", http.StatusUnauthorized)
		return
	}

	// Reset failed attempt counters on success
	resetFailedAttempts(ctx, clientIP, username)

	event.EventType = "LOGIN_SUCCESS"
	event.Severity = "INFO"
	logSecurityEvent(event)

	w.WriteHeader(http.StatusOK)
}

func logAndCheckThresholds(ctx context.Context, event SecurityEvent, ip, username string) {
	// Track per-user failures
	userKey := "failed_login:user:" + username
	userFailCount, _ := redisClient.Incr(ctx, userKey).Result()
	redisClient.Expire(ctx, userKey, time.Duration(FailedLoginWindowSecs)*time.Second)

	// Track per-IP failures
	ipKey := "failed_login:ip:" + ip
	ipFailCount, _ := redisClient.Incr(ctx, ipKey).Result()
	redisClient.Expire(ctx, ipKey, time.Duration(FailedLoginWindowSecs)*time.Second)

	event.FailCount = userFailCount

	// Check user threshold - possible account compromise attempt
	if userFailCount >= FailedLoginThreshold {
		event.Severity = "HIGH"
		event.EventType = "BRUTE_FORCE_DETECTED_USER"
		triggerAlert(event, "Account brute force detected")
	}

	// Check IP threshold - possible distributed attack
	if ipFailCount >= IPFailedLoginThreshold {
		event.Severity = "CRITICAL"
		event.EventType = "BRUTE_FORCE_DETECTED_IP"
		triggerAlert(event, "IP-based attack detected")
	}

	logSecurityEvent(event)
}

func triggerAlert(event SecurityEvent, message string) {
	alertMutex.Lock()
	defer alertMutex.Unlock()

	// Send to alerting system (PagerDuty, Slack, etc.)
	log.WithFields(logrus.Fields{
		"alert_type": "SECURITY_ALERT",
		"message":    message,
		"event":      event,
	}).Error("SECURITY ALERT TRIGGERED")

	// Integration with external alerting would go here
	// sendToPagerDuty(event)
	// sendToSlack(event)
}

func logSecurityEvent(event SecurityEvent) {
	eventJSON, _ := json.Marshal(event)
	log.WithFields(logrus.Fields{
		"security_event": string(eventJSON),
	}).Info("Security event logged")
}

func getClientIP(r *http.Request) string {
	if xff := r.Header.Get("X-Forwarded-For"); xff != "" {
		return xff
	}
	return r.RemoteAddr
}

func resetFailedAttempts(ctx context.Context, ip, username string) {
	redisClient.Del(ctx, "failed_login:user:"+username)
	redisClient.Del(ctx, "failed_login:ip:"+ip)
}
```

**Key Security Controls**:
- **Real-time threshold monitoring**: Tracks failed attempts per user and per IP with automatic alerting
- **Structured security events**: JSON-formatted logs enable automated analysis and SIEM integration
- **Multi-level severity**: Escalates from INFO → MEDIUM → HIGH → CRITICAL based on attack patterns
- **Sliding window detection**: Redis TTL provides time-bounded failure counting

Excellent question! Sophisticated attackers use distributed infrastructure and compromised credentials from data breaches. You need behavioral analytics that detect anomalies beyond simple thresholds.

**PRODUCTION PATTERN**:

```go
package security

import (
	"context"
	"encoding/json"
	"fmt"
	"math"
	"net/http"
	"sync"
	"time"

	"github.com/go-redis/redis/v8"
	"github.com/oschwald/geoip2-golang"
	"github.com/prometheus/client_golang/prometheus"
	"github.com/prometheus/client_golang/prometheus/promauto"
	"github.com/sirupsen/logrus"
)

var (
	log         = logrus.New()
	redisClient *redis.Client
	geoDB       *geoip2.Reader

	// Prometheus metrics for alerting
	failedLoginsTotal = promauto.NewCounterVec(
		prometheus.CounterOpts{
			Name: "auth_failed_logins_total",
			Help: "Total number of failed login attempts",
		},
		[]string{"reason", "country"},
	)

	credentialStuffingScore = promauto.NewGaugeVec(
		prometheus.GaugeOpts{
			Name: "auth_credential_stuffing_score",
			Help: "Credential stuffing risk score (0-100)",
		},
		[]string{"ip_range"},
	)

	impossibleTravelAlerts = promauto.NewCounter(
		prometheus.CounterOpts{
			Name: "auth_impossible_travel_alerts_total",
			Help: "Total impossible travel alerts triggered",
		},
	)
)

type GeoLocation struct {
	Latitude  float64 `json:"latitude"`
	Longitude float64 `json:"longitude"`
	Country   string  `json:"country"`
	City      string  `json:"city"`
}

type LoginAttempt struct {
	Username  string      `json:"username"`
	IPAddress string      `json:"ip_address"`
	Location  GeoLocation `json:"location"`
	Timestamp time.Time   `json:"timestamp"`
	Success   bool        `json:"success"`
	UserAgent string      `json:"user_agent"`
}

type ThreatIntelligence struct {
	CredentialStuffingScore float64   `json:"credential_stuffing_score"`
	ImpossibleTravel        bool      `json:"impossible_travel"`
	TravelSpeedKmH          float64   `json:"travel_speed_kmh,omitempty"`
	DistinctUsersFromIP     int64     `json:"distinct_users_from_ip"`
	DistinctIPsForUser      int64     `json:"distinct_ips_for_user"`
	RiskFactors             []string  `json:"risk_factors"`
	RecommendedAction       string    `json:"recommended_action"`
}

type SecurityMonitor struct {
	mu            sync.RWMutex
	alertChannels []AlertChannel
}

type AlertChannel interface {
	SendAlert(ctx context.Context, alert SecurityAlert) error
}

type SecurityAlert struct {
	AlertID       string            `json:"alert_id"`
	Severity      string            `json:"severity"`
	AlertType     string            `json:"alert_type"`
	Description   string            `json:"description"`
	Attempt       LoginAttempt      `json:"attempt"`
	ThreatIntel   ThreatIntelligence `json:"threat_intel"`
	Timestamp     time.Time         `json:"timestamp"`
	ActionsTaken  []string          `json:"actions_taken"`
}

func NewSecurityMonitor(channels ...AlertChannel) *SecurityMonitor {
	return &SecurityMonitor{
		alertChannels: channels,
	}
}

func (sm *SecurityMonitor) AnalyzeLoginAttempt(ctx context.Context, attempt LoginAttempt) (*ThreatIntelligence, error) {
	threatIntel := &ThreatIntelligence{
		RiskFactors: make([]string, 0),
	}

	// Check for impossible travel
	if impossibleTravel, speed := sm.detectImpossibleTravel(ctx, attempt); impossibleTravel {
		threatIntel.ImpossibleTravel = true
		threatIntel.TravelSpeedKmH = speed
		threatIntel.RiskFactors = append(threatIntel.RiskFactors, 
			fmt.Sprintf("Impossible travel detected: %.0f km/h", speed))
		impossibleTravelAlerts.Inc()
	}

	// Check for credential stuffing patterns
	stuffingScore := sm.calculateCredentialStuffingScore(ctx, attempt)
	threatIntel.CredentialStuffingScore = stuffingScore
	if stuffingScore > 70 {
		threatIntel.RiskFactors = append(threatIntel.RiskFactors,
			fmt.Sprintf("High credential stuffing score: %.1f", stuffingScore))
	}

	// Track distinct users from this IP (credential stuffing indicator)
	ipUsersKey := fmt.Sprintf("auth:ip_users:%s", attempt.IPAddress)
	redisClient.SAdd(ctx, ipUsersKey, attempt.Username)
	redisClient.Expire(ctx, ipUsersKey, 1*time.Hour)
	threatIntel.DistinctUsersFromIP, _ = redisClient.SCard(ctx, ipUsersKey).Result()

	// Track distinct IPs for this user (account takeover indicator)
	userIPsKey := fmt.Sprintf("auth:user_ips:%s", attempt.Username)
	redisClient.SAdd(ctx, userIPsKey, attempt.IPAddress)
	redisClient.Expire(ctx, userIPsKey, 24*time.Hour)
	threatIntel.DistinctIPsForUser, _ = redisClient.SCard(ctx, userIPsKey).Result()

	// Determine recommended action
	threatIntel.RecommendedAction = sm.determineAction(threatIntel)

	// Trigger alerts based on threat level
	if err := sm.evaluateAndAlert(ctx, attempt, threatIntel); err != nil {
		log.WithError(err).Error("Failed to send security alert")
	}

	return threatIntel, nil
}

func (sm *SecurityMonitor) detectImpossibleTravel(ctx context.Context, current LoginAttempt) (bool, float64) {
	// Get last successful login location
	lastLoginKey := fmt.Sprintf("auth:last_login:%s", current.Username)
	lastLoginData, err := redisClient.Get(ctx, lastLoginKey).Result()
	if err != nil {
		// No previous login, store current and return
		if current.Success {
			data, _ := json.Marshal(current)
			redisClient.Set(ctx, lastLoginKey, data, 30*24*time.Hour)
		}
		return false, 0
	}

	var lastLogin LoginAttempt
	if err := json.Unmarshal([]byte(lastLoginData), &lastLogin); err != nil {
		return false, 0
	}

	// Calculate distance between locations
	distanceKm := haversineDistance(
		lastLogin.Location.Latitude, lastLogin.Location.Longitude,
		current.Location.Latitude, current.Location.Longitude,
	)

	// Calculate time difference
	timeDiffHours := current.Timestamp.Sub(lastLogin.Timestamp).Hours()
	if timeDiffHours <= 0 {
		timeDiffHours = 0.01 // Avoid division by zero
	}

	// Calculate required travel speed
	speedKmH := distanceKm / timeDiffHours

	// Max realistic travel speed (commercial jet ~900 km/h + buffer)
	const maxRealisticSpeedKmH = 1200

	// Update last login on success
	if current.Success {
		data, _ := json.Marshal(current)
		redisClient.Set(ctx, lastLoginKey, data, 30*24*time.Hour)
	}

	return speedKmH > maxRealisticSpeedKmH && distanceKm > 100, speedKmH
}

func (sm *SecurityMonitor) calculateCredentialStuffingScore(ctx context.Context, attempt LoginAttempt) float64 {
	score := 0.0

	// Factor 1: Multiple usernames from same IP in short window
	ipUsersKey := fmt.Sprintf("auth:ip_users_1h:%s", attempt.IPAddress)
	userCount, _ := redisClient.SCard(ctx, ipUsersKey).Result()
	if userCount > 10 {
		score += 30
	} else if userCount > 5 {
		score += 15
	}

	// Factor 2: Failure rate from this IP
	failKey := fmt.Sprintf("auth:fails:%s", attempt.IPAddress)
	totalKey := fmt.Sprintf("auth:total:%s", attempt.IPAddress)
	fails, _ := redisClient.Get(ctx, failKey).Float64()
	total, _ := redisClient.Get(ctx, totalKey).Float64()
	if total > 10 {
		failRate := fails / total
		if failRate > 0.9 {
			score += 40
		} else if failRate > 0.7 {
			score += 20
		}
	}

	// Factor 3: Unusual timing patterns (bot-like precision)
	timingKey := fmt.Sprintf("auth:timing:%s", attempt.IPAddress)
	// Analysis of request timing variance would go here
	_ = timingKey

	// Factor 4: Known malicious IP ranges (would integrate with threat feeds)
	// score += checkThreatIntelFeeds(attempt.IPAddress)

	credentialStuffingScore.WithLabelValues(attempt.IPAddress[:8]).Set(score)

	return math.Min(score, 100)
}

func (sm *SecurityMonitor) determineAction(intel *ThreatIntelligence) string {
	if intel.ImpossibleTravel && intel.CredentialStuffingScore > 80 {
		return "BLOCK_AND_REQUIRE_MFA_RESET"
	}
	if intel.ImpossibleTravel {
		return "REQUIRE_STEP_UP_AUTH"
	}
	if intel.CredentialStuffingScore > 70 {
		return "CAPTCHA_AND_RATE_LIMIT"
	}
	if intel.DistinctUsersFromIP > 20 {
		return "TEMPORARY_IP_BLOCK"
	}
	return "ALLOW"
}

func (sm *SecurityMonitor) evaluateAndAlert(ctx context.Context, attempt LoginAttempt, intel *ThreatIntelligence) error {
	var severity, alertType string

	switch {
	case intel.ImpossibleTravel && intel.CredentialStuffingScore > 80:
		severity = "CRITICAL"
		alertType = "ACCOUNT_TAKEOVER_ATTEMPT"
	case intel.ImpossibleTravel:
		severity = "HIGH"
		alertType = "IMPOSSIBLE_TRAVEL"
	case intel.CredentialStuffingScore > 70:
		severity = "HIGH"
		alertType = "CREDENTIAL_STUFFING"
	case intel.DistinctUsersFromIP > 50:
		severity = "MEDIUM"
		alertType = "DISTRIBUTED_ATTACK"
	default:
		return nil // No alert needed
	}

	alert := SecurityAlert{
		AlertID:     fmt.Sprintf("SEC-%d", time.Now().UnixNano()),
		Severity:    severity,
		AlertType:   alertType,
		Description: fmt.Sprintf("%s detected for user %s from IP %s", alertType, attempt.Username, attempt.IPAddress),
		Attempt:     attempt,
		ThreatIntel: *intel,
		Timestamp:   time.Now().UTC(),
		ActionsTaken: []string{intel.RecommendedAction},
	}

	// Log structured alert for SIEM
	alertJSON, _ := json.Marshal(alert)
	log.WithFields(logrus.Fields{
		"alert":    string(alertJSON),
		"severity": severity,
	}).Warn("Security alert triggered")

	// Send to all configured alert channels
	sm.mu.RLock()
	defer sm.mu.RUnlock()
	for _, channel := range sm.alertChannels {
		if err := channel.SendAlert(ctx, alert); err != nil {
			log.WithError(err).Error("Failed to send alert to channel")
		}
	}

	return nil
}

// Haversine formula for calculating distance between coordinates
func haversineDistance(lat1, lon1, lat2, lon2 float64) float64 {
	const earthRadiusKm = 6371.0

	dLat := (lat2 - lat1) * math.Pi / 180
	dLon := (lon2 - lon1) * math.Pi / 180

	a := math.Sin(dLat/2)*math.Sin(dLat/2) +
		math.Cos(lat1*math.Pi/180)*math.Cos(lat2*math.Pi/180)*
			math.Sin(dLon/2)*math.Sin(dLon/2)

	c := 2 * math.Atan2(math.Sqrt(a), math.Sqrt(1-a))

	return earthRadiusKm * c
}

