// application.properties - disable Java serialization in Spring
spring.security.filter.order=1
spring.http.converters.preferred-json-mapper=jackson

// Block serialized data at ingress
@Configuration
public class SecurityConfig {
    @Bean
    public FilterRegistrationBean<SerializationBlockingFilter> serializationFilter() {
        FilterRegistrationBean<SerializationBlockingFilter> reg = new FilterRegistrationBean<>();
        reg.setFilter(new SerializationBlockingFilter());
        reg.addUrlPatterns("/*");
        return reg;
