public class SerializationBlockingFilter extends OncePerRequestFilter {
    @Override
    protected void doFilterInternal(HttpServletRequest request, 
            HttpServletResponse response, FilterChain chain) throws ServletException, IOException {
        String contentType = request.getContentType();

        // Block Java serialization content types
        if (contentType != null && 
            (contentType.contains("application/x-java-serialized-object") ||
             contentType.contains("application/java-serialized"))) {
            response.sendError(415, "Java serialization not accepted");
            return;
        }
        chain.doFilter(request, response);
    }
}
