    );

    @Override
    public void setupModule(SetupContext context) {
        context.addDeserializationProblemHandler(new DeserializationProblemHandler() {
            @Override
            public Object handleUnexpectedToken(DeserializationContext ctxt, 
                    JavaType targetType, JsonToken t, JsonParser p, String failureMsg) {
                if (BLOCKED_CLASSES.contains(targetType.getRawClass().getName())) {
                    throw new SecurityException("Blocked dangerous type: " + targetType);
                }
                return super.handleUnexpectedToken(ctxt, targetType, t, p, failureMsg);
            }
        });
    }
}
```

