**Additional Protections**:
- **Introspection disabled in production**: Attackers can't discover your schema
- **Persisted queries**: Only allow pre-approved queries in production
- **Audit trail**: Every data access logged with user ID, timestamp, and operation
- **Data masking**: Sensitive fields (SSN, credit cards) masked based on role
- **Request correlation**: All logs include request ID for incident investigation

Using `math/rand` for session tokens is one of the most dangerous cryptographic mistakes in Go. The `math/rand` package generates predictable pseudo-random numbers that attackers can easily predict and exploit.

**VULNERABLE CODE**:

```go
package main

import (
	"encoding/hex"
	"fmt"
	"math/rand"
	"net/http"
	"time"
)

var sessions = make(map[string]string)

func init() {
	// DANGEROUS: Seeding with time is predictable
	rand.Seed(time.Now().UnixNano())
}

func generateSessionToken() string {
	// VULNERABLE: math/rand is not cryptographically secure
	b := make([]byte, 32)
	for i := range b {
		b[i] = byte(rand.Intn(256))
	}
	return hex.EncodeToString(b)
}

func loginHandler(w http.ResponseWriter, r *http.Request) {
	username := r.FormValue("username")
	// Assume authentication succeeded

	token := generateSessionToken()
	sessions[token] = username

	http.SetCookie(w, &http.Cookie{
		Name:  "session",
		Value: token,
	})
	fmt.Fprintf(w, "Logged in as %s", username)
}
```

**Attack Payload**:
```go
// Attacker can predict tokens by:
// 1. Knowing approximate server start time (seed)
// 2. Observing a few tokens to reconstruct PRNG state
package main

import (
	"math/rand"
	"time"
)

func predictNextToken(observedTime int64) {
	// Brute force seed within time window
	for seed := observedTime - 1000000000; seed <= observedTime; seed++ {
		rand.Seed(seed)
		// Generate and test tokens
	}
}
```

**Why This Is Dangerous**:
- `math/rand` uses a deterministic algorithm (linear congruential generator)
- Time-based seeds have very low entropy (~30 bits for nanoseconds in realistic windows)
- An attacker observing any token can reconstruct the internal state and predict all future tokens
- Session hijacking becomes trivial once the PRNG state is recovered

**SECURE VERSION**:

```go
package main

import (
	"crypto/rand"
	"encoding/base64"
	"fmt"
	"io"
	"log"
	"net/http"
	"sync"
)

var (
	sessions     = make(map[string]string)
	sessionsLock sync.RWMutex
)

// generateSecureToken creates a cryptographically secure random token
func generateSecureToken(length int) (string, error) {
	// SECURE: crypto/rand uses OS entropy source
	b := make([]byte, length)
	_, err := io.ReadFull(rand.Reader, b)
	if err != nil {
		return "", fmt.Errorf("failed to generate random bytes: %w", err)
	}
	// URL-safe base64 encoding
	return base64.URLEncoding.EncodeToString(b), nil
}

func loginHandler(w http.ResponseWriter, r *http.Request) {
	username := r.FormValue("username")
	// Assume authentication succeeded

	// Generate 32 bytes = 256 bits of entropy
	token, err := generateSecureToken(32)
	if err != nil {
		log.Printf("Token generation failed: %v", err)
		http.Error(w, "Internal server error", http.StatusInternalServerError)
		return
	}

	sessionsLock.Lock()
	sessions[token] = username
	sessionsLock.Unlock()

	http.SetCookie(w, &http.Cookie{
		Name:     "session",
		Value:    token,
		HttpOnly: true,
		Secure:   true,
		SameSite: http.SameSiteStrictMode,
	})
	fmt.Fprintf(w, "Logged in as %s", username)
}
```

**Key Security Controls**:
- **crypto/rand.Reader**: Uses OS-level CSPRNG (/dev/urandom on Linux, CryptGenRandom on Windows)
- **256-bit tokens**: Provides 2^256 possible values, making brute force infeasible
- **io.ReadFull()**: Ensures all requested bytes are read, fails safely if entropy is unavailable
- **Secure cookie flags**: HttpOnly prevents XSS token theft, Secure ensures HTTPS only

For API keys and production systems, you need additional considerations: secure storage with hashing, proper key formatting, rate limiting on generation, and monitoring for anomalies.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/rand"
	"crypto/sha256"
	"crypto/subtle"
	"encoding/base64"
	"encoding/hex"
	"fmt"
	"io"
	"log"
	"sync"
	"time"

	"golang.org/x/crypto/argon2"
	"golang.org/x/time/rate"
)

const (
	APIKeyLength     = 32  // 256 bits
	APIKeyPrefix     = "sk_live_"
	Argon2Time       = 1
	Argon2Memory     = 64 * 1024
	Argon2Threads    = 4
	Argon2KeyLen     = 32
)

type APIKey struct {
	ID           string
	Prefix       string    // Visible prefix for identification
	HashedKey    []byte    // Argon2 hash of full key
	Salt         []byte
	CreatedAt    time.Time
	LastUsedAt   *time.Time
	RateLimitRPS int
}

type SecureKeyManager struct {
	mu           sync.RWMutex
	keys         map[string]*APIKey
	generateLimiter *rate.Limiter
	logger       *log.Logger
}

func NewSecureKeyManager(logger *log.Logger) *SecureKeyManager {
	return &SecureKeyManager{
		keys:            make(map[string]*APIKey),
		generateLimiter: rate.NewLimiter(rate.Limit(10), 5), // 10/sec, burst 5
		logger:          logger,
	}
}

// GenerateAPIKey creates a new API key with cryptographically secure randomness
func (km *SecureKeyManager) GenerateAPIKey(ctx context.Context, userID string) (string, error) {
	// Rate limit key generation to prevent abuse
	if err := km.generateLimiter.Wait(ctx); err != nil {
		km.logger.Printf("SECURITY: Rate limit exceeded for API key generation, user=%s", userID)
		return "", fmt.Errorf("rate limit exceeded")
	}

	// Generate cryptographically secure random bytes
	keyBytes := make([]byte, APIKeyLength)
	if _, err := io.ReadFull(rand.Reader, keyBytes); err != nil {
		km.logger.Printf("CRITICAL: Entropy source failed: %v", err)
		return "", fmt.Errorf("failed to generate secure key: %w", err)
	}

	// Generate unique salt for this key
	salt := make([]byte, 16)
	if _, err := io.ReadFull(rand.Reader, salt); err != nil {
		return "", fmt.Errorf("failed to generate salt: %w", err)
	}

	// Create the full API key with prefix
	fullKey := APIKeyPrefix + base64.URLEncoding.EncodeToString(keyBytes)

	// Generate short ID for lookup (first 8 chars of hash)
	idHash := sha256.Sum256([]byte(fullKey))
	keyID := hex.EncodeToString(idHash[:4])

	// Hash the key for storage using Argon2id
	hashedKey := argon2.IDKey(
		[]byte(fullKey),
		salt,
		Argon2Time,
		Argon2Memory,
		Argon2Threads,
		Argon2KeyLen,
	)

	apiKey := &APIKey{
		ID:           keyID,
		Prefix:       fullKey[:12], // Store visible prefix for UI
		HashedKey:    hashedKey,
		Salt:         salt,
		CreatedAt:    time.Now().UTC(),
		RateLimitRPS: 100,
	}

	km.mu.Lock()
	km.keys[keyID] = apiKey
	km.mu.Unlock()

	km.logger.Printf("AUDIT: API key generated, id=%s, user=%s, prefix=%s",
		keyID, userID, apiKey.Prefix)

	// Return full key ONLY ONCE - it cannot be recovered
	return fullKey, nil
}

// ValidateAPIKey verifies a key using constant-time comparison
func (km *SecureKeyManager) ValidateAPIKey(ctx context.Context, providedKey string) (*APIKey, error) {
	// Quick format validation
	if len(providedKey) < len(APIKeyPrefix)+10 {
		return nil, fmt.Errorf("invalid key format")
	}

	// Find key by ID hash
	idHash := sha256.Sum256([]byte(providedKey))
	keyID := hex.EncodeToString(idHash[:4])

	km.mu.RLock()
	apiKey, exists := km.keys[keyID]
	km.mu.RUnlock()

	if !exists {
		// Perform dummy hash to prevent timing attacks
		_ = argon2.IDKey([]byte(providedKey), make([]byte, 16),
			Argon2Time, Argon2Memory, Argon2Threads, Argon2KeyLen)
		return nil, fmt.Errorf("invalid API key")
	}

	// Hash provided key with stored salt
	computedHash := argon2.IDKey(
		[]byte(providedKey),
		apiKey.Salt,
		Argon2Time,
		Argon2Memory,
		Argon2Threads,
		Argon2KeyLen,
	)

	// Constant-time comparison prevents timing attacks
	if subtle.ConstantTimeCompare(computedHash, apiKey.HashedKey) != 1 {
		km.logger.Printf("SECURITY: Invalid API key attempt, id=%s", keyID)
		return nil, fmt.Errorf("invalid API key")
	}

	// Update last used timestamp
	now := time.Now().UTC()
	km.mu.Lock()
	apiKey.LastUsedAt = &now
	km.mu.Unlock()

	return apiKey, nil
}

// MonitorEntropyHealth checks CSPRNG availability
func (km *SecureKeyManager) MonitorEntropyHealth() error {
	testBytes := make([]byte, 32)
	start := time.Now()

	if _, err := io.ReadFull(rand.Reader, testBytes); err != nil {
		km.logger.Printf("CRITICAL: Entropy source unhealthy: %v", err)
		return err
	}

	elapsed := time.Since(start)
	if elapsed > 100*time.Millisecond {
		km.logger.Printf("WARNING: Slow entropy generation: %v", elapsed)
	}

	return nil
}
```

**Defense in Depth Layers**:

1. **Cryptographically Secure Generation**:
```go
// Always use crypto/rand, never math/rand
keyBytes := make([]byte, 32)
_, err := io.ReadFull(rand.Reader, keyBytes)
// io.ReadFull ensures we get ALL requested entropy or fail
```

2. **Secure Storage with Argon2id Hashing**:
```go
// Never store raw API keys - hash them like passwords
hashedKey := argon2.IDKey(
	[]byte(fullKey),
	salt,           // Unique salt per key
	1,              // Time parameter
	64*1024,        // Memory in KB
	4,              // Parallelism
	32,             // Output length
)
```

3. **Constant-Time Validation**:
```go
// Prevent timing attacks during key comparison
if subtle.ConstantTimeCompare(computedHash, storedHash) != 1 {
	return nil, fmt.Errorf("invalid key")
}
```

**Additional Protections**:
- **Rate limiting on generation**: Prevents mass key generation attacks
- **Audit logging**: All key operations logged with timestamps and user context
- **Key prefixes**: Allow identification without revealing the secret (e.g., `sk_live_...`)
- **Entropy monitoring**: Health checks ensure CSPRNG availability
- **One-time display**: API keys shown only at creation, never retrievable afterward
- **Argon2id over bcrypt**: Memory-hard algorithm resistant to GPU/ASIC attacks
- **Timing attack prevention**: Dummy hash computation for non-existent keys

Many developers add basic logging that only captures successful events, missing critical security-relevant information needed to detect attacks.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');

const app = express();
app.use(express.json());

app.post('/api/login', async (req, res) => {
  const { username, password } = req.body;

  try {
    const user = await db.findUserByUsername(username);

    if (!user) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const validPassword = await bcrypt.compare(password, user.passwordHash);

    if (!validPassword) {
      return res.status(401).json({ error: 'Invalid credentials' });
    }

    const token = jwt.sign({ userId: user.id }, process.env.JWT_SECRET);

    // Only logs successful logins
    console.log(`User ${username} logged in`);

    res.json({ token });
  } catch (error) {
    res.status(500).json({ error: 'Server error' });
  }
});
```

**Attack Scenario**:
```text
Attacker performs credential stuffing attack:
- 10,000 failed login attempts over 2 hours
- Uses rotating IP addresses
- No alerts triggered because failures aren't logged
- Eventually succeeds with compromised credentials
- Attack goes undetected for weeks
```

**Why This Is Dangerous**:
- Failed login attempts are not logged, hiding brute force attacks
- No IP address or user agent captured for forensics
- No timestamp or correlation ID for investigation
- Cannot detect account enumeration attacks
- Impossible to identify compromised accounts after breach

**SECURE VERSION**:

```javascript
const express = require('express');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');
const winston = require('winston');
const { v4: uuidv4 } = require('uuid');

const app = express();
app.use(express.json());

// Structured security logger
const securityLogger = winston.createLogger({
  level: 'info',
  format: winston.format.combine(
    winston.format.timestamp(),
    winston.format.json()
  ),
  defaultMeta: { service: 'auth-service' },
  transports: [
    new winston.transports.File({ filename: 'security-events.log' }),
