      eventId,
      userId: user.id,
      username: user.username,
      ...clientInfo
    });

    res.json({ token });
  } catch (error) {
    securityLogger.error('Authentication error', {
      eventType: 'AUTH_ERROR',
      eventId,
      error: error.message,
      ...clientInfo
    });
    res.status(500).json({ error: 'Server error' });
  }
});
