**Key Security Controls**:
- **Structured logging**: JSON format enables automated analysis and alerting
- **All outcomes logged**: Success, failure (user not found), failure (wrong password), and errors
- **Client forensics**: IP address, user agent, and forwarded headers captured
- **Correlation IDs**: Enable tracing requests across distributed systems
- **Separate failure reasons internally**: Helps detect enumeration vs brute force attacks

Comprehensive security logging should cover all security-relevant events across your application, with tamper-proof storage and real-time alerting capabilities.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const winston = require('winston');
const WinstonCloudWatch = require('winston-cloudwatch');
const crypto = require('crypto');
const { v4: uuidv4 } = require('uuid');

const app = express();
app.use(express.json());

// Security event types that MUST be logged
const SECURITY_EVENTS = {
  AUTH_SUCCESS: 'Authentication successful',
  AUTH_FAILURE: 'Authentication failed',
  AUTH_LOCKOUT: 'Account locked due to failed attempts',
  SESSION_CREATED: 'New session created',
  SESSION_TERMINATED: 'Session terminated',
  SESSION_HIJACK_ATTEMPT: 'Possible session hijacking detected',
  AUTHZ_SUCCESS: 'Authorization granted',
  AUTHZ_FAILURE: 'Authorization denied',
  PRIVILEGE_ESCALATION: 'Privilege escalation attempt',
  DATA_ACCESS: 'Sensitive data accessed',
  DATA_EXPORT: 'Data exported from system',
  CONFIG_CHANGE: 'Security configuration changed',
  USER_CREATED: 'New user account created',
  USER_DELETED: 'User account deleted',
  PASSWORD_CHANGED: 'Password changed',
  MFA_ENABLED: 'MFA enabled',
  MFA_DISABLED: 'MFA disabled',
  API_KEY_CREATED: 'API key generated',
  API_KEY_REVOKED: 'API key revoked',
  RATE_LIMIT_EXCEEDED: 'Rate limit exceeded',
  INPUT_VALIDATION_FAILURE: 'Input validation failed',
  CSRF_VIOLATION: 'CSRF token mismatch',
  SQL_INJECTION_ATTEMPT: 'Potential SQL injection detected',
  XSS_ATTEMPT: 'Potential XSS attack detected'
};

class SecurityLogger {
  constructor() {
    this.hmacKey = process.env.LOG_INTEGRITY_KEY;

    this.logger = winston.createLogger({
      level: 'info',
      format: winston.format.combine(
        winston.format.timestamp({ format: 'YYYY-MM-DDTHH:mm:ss.SSSZ' }),
        winston.format.json()
      ),
      defaultMeta: {
        service: process.env.SERVICE_NAME,
        environment: process.env.NODE_ENV,
        version: process.env.APP_VERSION
      },
      transports: [
        // Local file with rotation
        new winston.transports.File({
          filename: 'security-events.log',
          maxsize: 50 * 1024 * 1024, // 50MB
          maxFiles: 30,
          tailable: true
        }),
        // Immutable cloud storage (WORM - Write Once Read Many)
        new WinstonCloudWatch({
          logGroupName: '/security/events',
          logStreamName: `${process.env.SERVICE_NAME}-${process.env.HOSTNAME}`,
          awsRegion: process.env.AWS_REGION,
          retentionInDays: 365
        })
      ]
    });
  }

  // Generate HMAC for log integrity verification
  generateIntegrityHash(logEntry) {
    const data = JSON.stringify(logEntry);
    return crypto
      .createHmac('sha256', this.hmacKey)
      .update(data)
      .digest('hex');
  }

  // Log security event with integrity protection
  logSecurityEvent(eventType, data, severity = 'info') {
    const eventId = uuidv4();
    const timestamp = new Date().toISOString();

    const logEntry = {
      eventId,
      eventType,
      eventDescription: SECURITY_EVENTS[eventType] || eventType,
      timestamp,
      severity: severity.toUpperCase(),
      ...data
    };

    // Add integrity hash to detect tampering
    logEntry.integrityHash = this.generateIntegrityHash(logEntry);

    this.logger[severity](logEntry);

    // Trigger real-time alerts for critical events
    if (severity === 'error' || this.isCriticalEvent(eventType)) {
      this.triggerAlert(logEntry);
    }

    return eventId;
  }

  isCriticalEvent(eventType) {
    const criticalEvents = [
      'AUTH_LOCKOUT',
      'SESSION_HIJACK_ATTEMPT',
      'PRIVILEGE_ESCALATION',
      'SQL_INJECTION_ATTEMPT',
      'XSS_ATTEMPT'
    ];
    return criticalEvents.includes(eventType);
  }

  async triggerAlert(logEntry) {
    // Send to SIEM/alerting system
    try {
      await fetch(process.env.ALERT_WEBHOOK_URL, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          severity: logEntry.severity,
          event: logEntry.eventType,
          details: logEntry,
          timestamp: logEntry.timestamp
        })
      });
    } catch (error) {
      console.error('Failed to send security alert:', error);
    }
  }
}

const securityLogger = new SecurityLogger();

// Middleware to capture request context
function securityContext(req, res, next) {
  req.securityContext = {
    correlationId: req.headers['x-correlation-id'] || uuidv4(),
    clientIp: req.ip || req.connection.remoteAddress,
    userAgent: req.get('User-Agent'),
    forwardedFor: req.get('X-Forwarded-For'),
    referer: req.get('Referer'),
    requestPath: req.path,
    requestMethod: req.method,
    userId: req.user?.id,
    sessionId: req.session?.id
  };
  next();
}

app.use(securityContext);

// Example: Authorization logging middleware
function logAuthorizationCheck(resource, action) {
  return (req, res, next) => {
    const authorized = checkAuthorization(req.user, resource, action);

    if (authorized) {
      securityLogger.logSecurityEvent('AUTHZ_SUCCESS', {
        ...req.securityContext,
        resource,
        action,
        userId: req.user.id
      });
      next();
    } else {
      securityLogger.logSecurityEvent('AUTHZ_FAILURE', {
        ...req.securityContext,
        resource,
        action,
        userId: req.user?.id,
        reason: 'INSUFFICIENT_PERMISSIONS'
      }, 'warn');
      res.status(403).json({ error: 'Access denied' });
    }
  };
}

// Example: Sensitive data access logging
