from flask import Flask, request, jsonify
import requests
import ipaddress
import socket
import logging
from urllib.parse import urlparse
from functools import wraps
from datetime import datetime, timedelta
import hashlib
import redis
from typing import Optional, Tuple, List

app = Flask(__name__)
app.config['MAX_REDIRECTS'] = 3
app.config['REQUEST_TIMEOUT'] = 10
app.config['MAX_RESPONSE_SIZE'] = 1024 * 1024  # 1MB

logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(levelname)s - %(message)s'
)
logger = logging.getLogger(__name__)

# Redis for rate limiting and DNS caching
redis_client = redis.Redis(host='localhost', port=6379, db=0)

class SSRFProtection:
    """Production SSRF protection with DNS pinning and redirect validation"""

    ALLOWED_SCHEMES = {'http', 'https'}
    ALLOWED_PORTS = {80, 443, 8080, 8443}

    # Comprehensive blocklist including cloud provider metadata
    BLOCKED_RANGES = [
        '127.0.0.0/8',       # Loopback
        '10.0.0.0/8',        # Private Class A
        '172.16.0.0/12',     # Private Class B
        '192.168.0.0/16',    # Private Class C
        '169.254.0.0/16',    # Link-local (AWS/Azure metadata)
        '100.64.0.0/10',     # Carrier-grade NAT
        'fc00::/7',          # IPv6 unique local
        '::1/128',           # IPv6 loopback
        'fe80::/10',         # IPv6 link-local
    ]

    def __init__(self):
        self.blocked_networks = [
            ipaddress.ip_network(cidr) for cidr in self.BLOCKED_RANGES
        ]

    def is_ip_blocked(self, ip_str: str) -> bool:
        """Check if IP falls within any blocked range"""
        try:
            ip = ipaddress.ip_address(ip_str)
            for network in self.blocked_networks:
                if ip in network:
                    return True
            return False
        except ValueError:
            return True  # Invalid IPs are blocked

    def resolve_and_validate(self, hostname: str, port: int) -> Tuple[bool, Optional[str], List[str]]:
        """Resolve hostname and validate all returned IPs"""
        try:
            # Get all IP addresses for hostname
            addr_info = socket.getaddrinfo(
                hostname, port,
                socket.AF_UNSPEC,
                socket.SOCK_STREAM
            )

            validated_ips = []
            for family, socktype, proto, canonname, sockaddr in addr_info:
                ip = sockaddr[0]
                if self.is_ip_blocked(ip):
                    logger.warning(
                        f"SSRF blocked: {hostname} resolves to blocked IP {ip}"
                    )
                    return False, f"Blocked IP: {ip}", []
                validated_ips.append(ip)

            if not validated_ips:
                return False, "No valid IPs resolved", []

            return True, None, validated_ips

        except socket.gaierror as e:
            return False, f"DNS resolution failed: {e}", []

    def validate_url(self, url: str) -> Tuple[bool, Optional[str], dict]:
        """Full URL validation with metadata extraction"""
        try:
            parsed = urlparse(url)

            # Scheme validation
            if parsed.scheme.lower() not in self.ALLOWED_SCHEMES:
                return False, f"Scheme '{parsed.scheme}' not allowed", {}

            # Block embedded credentials
            if parsed.username or parsed.password:
                return False, "URLs with credentials not allowed", {}

            hostname = parsed.hostname
            if not hostname:
                return False, "No hostname in URL", {}

            # Port validation
            port = parsed.port or (443 if parsed.scheme == 'https' else 80)
            if port not in self.ALLOWED_PORTS:
                return False, f"Port {port} not allowed", {}

            # DNS resolution and IP validation
            is_valid, error, ips = self.resolve_and_validate(hostname, port)
            if not is_valid:
                return False, error, {}

            return True, None, {
                'hostname': hostname,
                'port': port,
                'scheme': parsed.scheme,
                'resolved_ips': ips
            }

        except Exception as e:
            logger.error(f"URL validation error: {e}")
            return False, "URL parsing failed", {}


class DNSPinningSession(requests.Session):
    """Custom session that pins DNS resolution to prevent rebinding attacks"""

    def __init__(self, ssrf_protection: SSRFProtection, pinned_ips: List[str]):
        super().__init__()
        self.ssrf_protection = ssrf_protection
        self.pinned_ips = pinned_ips
        self._original_getaddrinfo = socket.getaddrinfo

    def _pinned_getaddrinfo(self, host, port, family=0, socktype=0, proto=0, flags=0):
        """Return only pre-validated IPs"""
        results = []
        for ip in self.pinned_ips:
            try:
                ip_obj = ipaddress.ip_address(ip)
                af = socket.AF_INET6 if ip_obj.version == 6 else socket.AF_INET
                if family == 0 or family == af:
                    sockaddr = (ip, port, 0, 0) if af == socket.AF_INET6 else (ip, port)
                    results.append((af, socket.SOCK_STREAM, 0, '', sockaddr))
            except ValueError:
                continue
        return results if results else self._original_getaddrinfo(host, port, family, socktype, proto, flags)

    def request(self, method, url, **kwargs):
        # Temporarily override DNS resolution
        socket.getaddrinfo = self._pinned_getaddrinfo
        try:
            return super().request(method, url, **kwargs)
        finally:
            socket.getaddrinfo = self._original_getaddrinfo


ssrf_protection = SSRFProtection()


def rate_limit(key_prefix: str, max_requests: int, window_seconds: int):
    """Rate limiting decorator using Redis"""
    def decorator(f):
        @wraps(f)
        def wrapped(*args, **kwargs):
            client_ip = request.remote_addr
            key = f"{key_prefix}:{client_ip}"

            current = redis_client.incr(key)
            if current == 1:
                redis_client.expire(key, window_seconds)

            if current > max_requests:
                logger.warning(f"Rate limit exceeded for {client_ip}")
                return jsonify({'error': 'Rate limit exceeded'}), 429

            return f(*args, **kwargs)
        return wrapped
    return decorator


def safe_fetch_with_redirects(
    url: str,
    max_redirects: int = 3,
    timeout: int = 10
) -> Tuple[bool, dict]:
    """Safely fetch URL with redirect validation at each hop"""

    visited_urls = set()
    current_url = url
    redirect_count = 0

    while redirect_count <= max_redirects:
        # Prevent redirect loops
        if current_url in visited_urls:
            return False, {'error': 'Redirect loop detected'}
        visited_urls.add(current_url)

        # Validate current URL
        is_valid, error, metadata = ssrf_protection.validate_url(current_url)
        if not is_valid:
            logger.warning(f"SSRF blocked during redirect chain: {error}")
            return False, {'error': f'Blocked: {error}', 'url': current_url}

        # Create DNS-pinned session
        session = DNSPinningSession(ssrf_protection, metadata['resolved_ips'])

        try:
            response = session.get(
                current_url,
                allow_redirects=False,
                timeout=timeout,
                headers={
                    'User-Agent': 'SecureWebhookFetcher/2.0',
                    'Accept': 'application/json, text/plain, */*'
                },
                stream=True  # Don't load full response immediately
            )

            # Check for redirects
            if response.is_redirect and 'Location' in response.headers:
                redirect_count += 1
                current_url = response.headers['Location']

                # Handle relative redirects
                if not current_url.startswith(('http://', 'https://')):
                    from urllib.parse import urljoin
                    current_url = urljoin(url, current_url)

                logger.info(f"Following redirect {redirect_count}: {current_url}")
                response.close()
                continue

            # Read response with size limit
            content_length = response.headers.get('Content-Length', 0)
            if int(content_length or 0) > app.config['MAX_RESPONSE_SIZE']:
                response.close()
                return False, {'error': 'Response too large'}

            # Read in chunks with size limit
            content = b''
            for chunk in response.iter_content(chunk_size=8192):
                content += chunk
                if len(content) > app.config['MAX_RESPONSE_SIZE']:
                    response.close()
                    return False, {'error': 'Response exceeded size limit'}

            return True, {
                'status_code': response.status_code,
                'content': content.decode('utf-8', errors='replace')[:10000],
                'content_type': response.headers.get('Content-Type', ''),
                'final_url': current_url,
                'redirect_count': redirect_count
            }

        except requests.exceptions.Timeout:
            return False, {'error': 'Request timeout'}
        except requests.exceptions.RequestException as e:
            logger.error(f"Request failed: {e}")
            return False, {'error': 'Request failed'}

    return False, {'error': 'Too many redirects'}


@app.route('/api/webhook/fetch', methods=['POST'])
@rate_limit('webhook_fetch', max_requests=10, window_seconds=60)
def fetch_webhook():
    """Production webhook fetch endpoint with full SSRF protection"""

    data = request.get_json()
    if not data or 'url' not in data:
        return jsonify({'error': 'URL required'}), 400

    url = data['url'].strip()
    request_id = hashlib.sha256(f"{url}{datetime.utcnow()}".encode()).hexdigest()[:16]

    logger.info(f"Webhook fetch request [{request_id}]: {url[:100]}")

    success, result = safe_fetch_with_redirects(
        url,
        max_redirects=app.config['MAX_REDIRECTS'],
        timeout=app.config['REQUEST_TIMEOUT']
    )

    if success:
        logger.info(
            f"Webhook fetch success [{request_id}]: "
            f"status={result['status_code']}, redirects={result['redirect_count']}"
        )
        return jsonify({
            'success': True,
            'request_id': request_id,
            'data': result
        })
    else:
        logger.warning(f"Webhook fetch blocked [{request_id}]: {result.get('error')}")
        return jsonify({
            'success': False,
            'request_id': request_id,
            'error': result.get('error', 'Unknown error')
        }), 403


