using Microsoft.AspNetCore.Mvc;
using Microsoft.AspNetCore.Mvc.Filters;
using Microsoft.Extensions.Logging;
using System;
using System.Collections.Generic;
using System.Linq;
using System.Security.Claims;
using System.Text.RegularExpressions;

namespace SecureApp.Security
{
    /// <summary>
    /// Middleware to detect and block HTTP Parameter Pollution attacks
    /// </summary>
    public class ParameterPollutionProtectionAttribute : ActionFilterAttribute
    {
        // Whitelist of parameters that legitimately accept multiple values
        private static readonly HashSet<string> AllowedMultiValueParams = new HashSet<string>
        (
            StringComparer.OrdinalIgnoreCase
        )
        {
            "ids",
            "tags",
            "categories",
            "filters"
        };

        // Security-sensitive parameters that MUST be single-value
        private static readonly HashSet<string> ProtectedParams = new HashSet<string>
        (
            StringComparer.OrdinalIgnoreCase
        )
        {
            "role",
            "permission",
            "admin",
            "userId",
            "token",
            "redirect",
            "callback",
            "action"
        };

        public override void OnActionExecuting(ActionExecutingContext context)
        {
            var logger = context.HttpContext.RequestServices
                .GetService(typeof(ILogger<ParameterPollutionProtectionAttribute>)) 
                as ILogger<ParameterPollutionProtectionAttribute>;

            var request = context.HttpContext.Request;
            var userId = context.HttpContext.User
                .FindFirst(ClaimTypes.NameIdentifier)?.Value ?? "anonymous";

            // Check query string parameters
            foreach (var param in request.Query)
            {
                if (param.Value.Count > 1)
                {
                    // Protected params NEVER allow multiple values
                    if (ProtectedParams.Contains(param.Key))
                    {
                        logger?.LogWarning(
                            "HPP attack blocked: protected param '{Param}' with {Count} values from user {UserId}, IP: {IP}",
                            param.Key, param.Value.Count, userId, 
                            request.HttpContext.Connection.RemoteIpAddress);

                        context.Result = new BadRequestObjectResult(new
                        {
                            error = "Invalid request",
                            code = "HPP_DETECTED"
                        });
                        return;
                    }

                    // Non-whitelisted params with multiple values are suspicious
                    if (!AllowedMultiValueParams.Contains(param.Key))
                    {
                        logger?.LogWarning(
                            "Suspicious duplicate param '{Param}' from user {UserId}",
                            param.Key, userId);

                        context.Result = new BadRequestObjectResult(new
                        {
                            error = "Duplicate parameters not allowed for this field",
                            code = "DUPLICATE_PARAM"
                        });
                        return;
                    }

                    // Validate array size for whitelisted multi-value params
                    if (param.Value.Count > 100)
                    {
                        logger?.LogWarning(
                            "Excessive array size for param '{Param}': {Count}",
                            param.Key, param.Value.Count);

                        context.Result = new BadRequestObjectResult(new
                        {
                            error = "Too many values",
                            code = "ARRAY_TOO_LARGE"
                        });
                        return;
                    }
                }
            }

            // Check for encoding tricks (double encoding, null bytes)
            var rawQuery = request.QueryString.Value ?? "";
            if (ContainsEncodingAttack(rawQuery))
            {
                logger?.LogWarning(
                    "Encoding attack detected from user {UserId}: {Query}",
                    userId, rawQuery.Substring(0, Math.Min(200, rawQuery.Length)));

                context.Result = new BadRequestObjectResult(new
                {
                    error = "Invalid request encoding",
                    code = "ENCODING_ATTACK"
                });
                return;
            }

            base.OnActionExecuting(context);
        }

        private bool ContainsEncodingAttack(string input)
        {
            // Detect double encoding: %25 = encoded %, %00 = null byte
            var suspiciousPatterns = new[]
            {
                "%25",      // Double-encoded %
                "%00",      // Null byte
                "%2525",    // Triple-encoded %
                "\x00",     // Literal null
                "%c0%ae",   // Overlong UTF-8 encoding for .
                "%c0%af"    // Overlong UTF-8 encoding for /
            };

            return suspiciousPatterns.Any(p => 
                input.IndexOf(p, StringComparison.OrdinalIgnoreCase) >= 0);
        }
    }

    /// <summary>
    /// Controller demonstrating secure multi-value parameter handling
    /// </summary>
    [ApiController]
    [Route("api/[controller]")]
