        public IActionResult SearchProducts([FromQuery] ProductSearchRequest request)
        {
            // Model binding handles array params safely
            // ids[] parameter becomes List<int> Ids property

            // Validate array contents, not just structure
            if (request.Ids?.Any(id => id <= 0) == true)
            {
                return BadRequest("Invalid product ID");
            }

            if (request.Categories?.Any(c => !IsValidCategory(c)) == true)
            {
