```csharp
// Services/AzureKeyVaultSecretManager.cs
using Azure.Identity;
using Azure.Security.KeyVault.Secrets;
using Microsoft.Extensions.Caching.Memory;
using Microsoft.Extensions.Logging;
using System;
using System.Threading.Tasks;

namespace MyApp.Services
{
    public interface ISecretManager
    {
        Task<string> GetSecretAsync(string secretName);
        Task RotateSecretAsync(string secretName);
    }

    public class AzureKeyVaultSecretManager : ISecretManager
    {
        private readonly SecretClient _secretClient;
        private readonly IMemoryCache _cache;
        private readonly ILogger<AzureKeyVaultSecretManager> _logger;
        private static readonly TimeSpan CacheDuration = TimeSpan.FromMinutes(5);

        public AzureKeyVaultSecretManager(
            IConfiguration configuration,
            IMemoryCache cache,
            ILogger<AzureKeyVaultSecretManager> logger)
        {
            var keyVaultEndpoint = configuration["Azure:KeyVaultEndpoint"];

            // SECURE: DefaultAzureCredential uses Managed Identity in Azure
            // Falls back to Azure CLI/VS credentials for local dev
            _secretClient = new SecretClient(
                new Uri(keyVaultEndpoint),
                new DefaultAzureCredential());

            _cache = cache;
            _logger = logger;
        }

        public async Task<string> GetSecretAsync(string secretName)
        {
            // SECURE: Cache secrets to reduce Key Vault calls and latency
            var cacheKey = $"secret:{secretName}";

            if (_cache.TryGetValue(cacheKey, out string cachedSecret))
            {
                return cachedSecret;
            }

            try
            {
                _logger.LogInformation(
                    "Retrieving secret {SecretName} from Key Vault", 
                    secretName);

                KeyVaultSecret secret = await _secretClient
                    .GetSecretAsync(secretName);

                // SECURE: Cache with expiration for rotation support
                _cache.Set(cacheKey, secret.Value, CacheDuration);

                return secret.Value;
            }
            catch (Azure.RequestFailedException ex)
            {
                _logger.LogError(ex, 
                    "Failed to retrieve secret {SecretName}. Status: {Status}",
                    secretName, ex.Status);
                throw new InvalidOperationException(
                    $"Unable to retrieve required secret: {secretName}");
            }
        }

        public async Task RotateSecretAsync(string secretName)
        {
            // SECURE: Clear cache to force reload after rotation
            var cacheKey = $"secret:{secretName}";
            _cache.Remove(cacheKey);

            _logger.LogInformation(
                "Secret {SecretName} cache cleared for rotation", 
                secretName);

            // Pre-warm cache with new value
            await GetSecretAsync(secretName);
        }
    }
}
```

