cleaned := filepath.Clean(userPath)

// Absolute path resolution catches edge cases
absPath, err := filepath.Abs(fullPath)

// Final containment check
if !strings.HasPrefix(absPath, absUserBase+string(os.PathSeparator)) {
    // Block access
