// Even if traversal succeeds, they can't access other users' files
```

**Additional Protections**:
- **Symlink rejection**: Prevents attackers from creating symlinks that point outside allowed directories
- **File extension allowlist**: Only explicitly permitted file types can be served
- **Rate limiting**: Prevents brute-force enumeration of file paths
- **Comprehensive audit logging**: All access attempts (successful and blocked) are logged with full context for incident response
- **Security headers**: `X-Content-Type-Options: nosniff` prevents MIME-sniffing attacks, `Content-Disposition: attachment` forces download rather than inline rendering

URL preview features are extremely dangerous if not properly secured. They're a prime target for Server-Side Request Forgery (SSRF) attacks, which allow attackers to make your server send requests to internal services, cloud metadata endpoints, or other sensitive resources.

**VULNERABLE CODE**:

```javascript
const express = require('express');
const axios = require('axios');
const cheerio = require('cheerio');

const app = express();
app.use(express.json());

// VULNERABLE: No URL validation - allows SSRF attacks
app.post('/api/preview', async (req, res) => {
  const { url } = req.body;

  try {
    // Dangerous: Directly fetching user-provided URL
    const response = await axios.get(url, {
      timeout: 5000,
      headers: { 'User-Agent': 'LinkPreview/1.0' }
    });

    const $ = cheerio.load(response.data);

    const preview = {
      title: $('meta[property="og:title"]').attr('content') || $('title').text(),
      description: $('meta[property="og:description"]').attr('content'),
      image: $('meta[property="og:image"]').attr('content'),
      url: url
    };

    res.json(preview);
  } catch (error) {
    res.status(500).json({ error: 'Failed to fetch URL' });
  }
});

app.listen(3000);
```

**Attack Payloads**:
```text
# Access AWS metadata service to steal IAM credentials
http://169.254.169.254/latest/meta-data/iam/security-credentials/

# Access internal services
http://localhost:6379/INFO
http://192.168.1.100:8080/admin
http://internal-api.company.local/sensitive-data

# Cloud metadata endpoints
http://169.254.169.254/latest/user-data
http://metadata.google.internal/computeMetadata/v1/
