// Validate actual file content (magic bytes)
async function validateFileContent(filePath, declaredMime) {
  try {
    const buffer = await fs.readFile(filePath);
    const detected = await fileType.fromBuffer(buffer);

    if (!detected) {
      return { valid: false, reason: 'Unable to detect file type' };
    }

    if (!ALLOWED_MIME_TYPES.includes(detected.mime)) {
      return { valid: false, reason: `Actual type ${detected.mime} not allowed` };
