    if (detected.mime !== declaredMime) {
      return { 
        valid: false, 
        reason: `Type mismatch: declared ${declaredMime}, actual ${detected.mime}` 
      };
    }

    return { valid: true, detectedType: detected.mime };
  } catch (error) {
    return { valid: false, reason: 'File validation error' };
  }
