**SECURE VERSION**:

```go
package main

import (
	"crypto/tls"
	"database/sql"
	"log"
	"net/http"
	"os"
	"time"

	"github.com/gin-gonic/gin"
	_ "github.com/lib/pq"
)

var db *sql.DB

func main() {
	// SECURE: Force release mode in production
	gin.SetMode(gin.ReleaseMode)

	router := gin.New()
	router.Use(gin.Recovery()) // Panic recovery without debug info

	// SECURE: Database with TLS and environment variables
	dbURL := os.Getenv("DATABASE_URL")
	if dbURL == "" {
		log.Fatal("DATABASE_URL environment variable required")
	}

	var err error
	db, err = sql.Open("postgres", dbURL+"?sslmode=require")
	if err != nil {
		log.Fatal("Database connection failed")
	}
	db.SetMaxOpenConns(25)
	db.SetMaxIdleConns(5)
	db.SetConnMaxLifetime(5 * time.Minute)

	// SECURE: Restrictive CORS
	router.Use(secureCORS())

	// SECURE: Security headers
	router.Use(securityHeaders())

	router.GET("/user/:id", getUser)

	// SECURE: TLS configuration
	tlsConfig := &tls.Config{
		MinVersion:               tls.VersionTLS12,
		PreferServerCipherSuites: true,
		CipherSuites: []uint16{
			tls.TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384,
			tls.TLS_ECDHE_RSA_WITH_AES_128_GCM_SHA256,
		},
	}

	server := &http.Server{
		Addr:         ":443",
		Handler:      router,
		TLSConfig:    tlsConfig,
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 10 * time.Second,
		IdleTimeout:  120 * time.Second,
	}

	log.Fatal(server.ListenAndServeTLS("cert.pem", "key.pem"))
}

func secureCORS() gin.HandlerFunc {
	allowedOrigins := map[string]bool{
		"https://app.example.com":   true,
		"https://admin.example.com": true,
	}

	return func(c *gin.Context) {
		origin := c.Request.Header.Get("Origin")
		if allowedOrigins[origin] {
			c.Writer.Header().Set("Access-Control-Allow-Origin", origin)
			c.Writer.Header().Set("Access-Control-Allow-Methods", "GET, POST, PUT, DELETE")
			c.Writer.Header().Set("Access-Control-Allow-Headers", "Content-Type, Authorization")
			c.Writer.Header().Set("Access-Control-Allow-Credentials", "true")
			c.Writer.Header().Set("Access-Control-Max-Age", "86400")
		}
		if c.Request.Method == "OPTIONS" {
			c.AbortWithStatus(204)
			return
		}
		c.Next()
	}
}

func securityHeaders() gin.HandlerFunc {
	return func(c *gin.Context) {
		c.Writer.Header().Set("X-Content-Type-Options", "nosniff")
		c.Writer.Header().Set("X-Frame-Options", "DENY")
		c.Writer.Header().Set("X-XSS-Protection", "1; mode=block")
		c.Writer.Header().Set("Strict-Transport-Security", "max-age=31536000; includeSubDomains")
		c.Writer.Header().Set("Content-Security-Policy", "default-src 'self'")
		c.Next()
	}
}

func getUser(c *gin.Context) {
	id := c.Param("id")
	var username string
	err := db.QueryRow("SELECT username FROM users WHERE id = $1", id).Scan(&username)
	if err != nil {
		// SECURE: Generic error message
		log.Printf("Database error for user %s: %v", id, err)
		c.JSON(500, gin.H{"error": "An internal error occurred"})
		return
	}
	c.JSON(200, gin.H{"username": username})
}
```

**Key Security Controls**:
- **Release Mode**: `gin.SetMode(gin.ReleaseMode)` disables debug output and stack traces
- **Environment Variables**: Secrets loaded from environment, never hardcoded
- **TLS Required**: Database connections use `sslmode=require`, server uses TLS 1.2+
- **Restrictive CORS**: Whitelist of allowed origins instead of wildcard
- **Security Headers**: HSTS, CSP, X-Frame-Options prevent common web attacks
- **Generic Errors**: Internal details logged server-side, not exposed to clients

Managing secure configurations across microservices requires a centralized, environment-aware approach with secure defaults that can't be accidentally overridden. Here's a production pattern used by organizations running hundreds of Go services.

**PRODUCTION PATTERN**:

```go
package config

import (
	"crypto/tls"
	"encoding/json"
	"fmt"
	"log"
	"net/http"
	"os"
	"strings"
	"sync"
	"time"
)

// Environment represents deployment environment
type Environment string

const (
	EnvDevelopment Environment = "development"
	EnvStaging     Environment = "staging"
	EnvProduction  Environment = "production"
)

// SecureConfig holds all security-related configuration
type SecureConfig struct {
	Environment      Environment
	DebugEnabled     bool
	TLSConfig        *tls.Config
	CORSConfig       CORSConfig
	DatabaseConfig   DatabaseConfig
	RateLimitConfig  RateLimitConfig
	SecurityHeaders  map[string]string
	AllowedEndpoints map[string]bool
	mu               sync.RWMutex
}

type CORSConfig struct {
	AllowedOrigins   []string
	AllowedMethods   []string
	AllowedHeaders   []string
	AllowCredentials bool
	MaxAge           int
}

type DatabaseConfig struct {
	Host            string
	Port            int
	SSLMode         string
	MaxConnections  int
	ConnectTimeout  time.Duration
	CertPath        string
}

type RateLimitConfig struct {
	RequestsPerMinute int
	BurstSize         int
	Enabled           bool
}

var (
	globalConfig *SecureConfig
	configOnce   sync.Once
)

// GetSecureConfig returns singleton secure configuration
func GetSecureConfig() *SecureConfig {
	configOnce.Do(func() {
		globalConfig = loadSecureDefaults()
	})
	return globalConfig
}

// loadSecureDefaults creates configuration with secure defaults
// Production defaults are always secure - dev must explicitly opt-out
func loadSecureDefaults() *SecureConfig {
	env := getEnvironment()

	config := &SecureConfig{
		Environment: env,
		// SECURE DEFAULT: Debug disabled unless explicitly development
		DebugEnabled: env == EnvDevelopment,

		// SECURE DEFAULT: Strong TLS configuration
		TLSConfig: &tls.Config{
			MinVersion:               tls.VersionTLS12,
			PreferServerCipherSuites: true,
			CipherSuites: []uint16{
				tls.TLS_ECDHE_ECDSA_WITH_AES_256_GCM_SHA384,
				tls.TLS_ECDHE_RSA_WITH_AES_256_GCM_SHA384,
				tls.TLS_ECDHE_ECDSA_WITH_AES_128_GCM_SHA256,
				tls.TLS_ECDHE_RSA_WITH_AES_128_GCM_SHA256,
			},
		},

		// SECURE DEFAULT: Restrictive CORS
		CORSConfig: CORSConfig{
			AllowedOrigins:   []string{}, // Must be explicitly set
			AllowedMethods:   []string{"GET", "POST", "PUT", "DELETE"},
			AllowedHeaders:   []string{"Content-Type", "Authorization"},
			AllowCredentials: false, // Must be explicitly enabled
			MaxAge:           86400,
		},

		// SECURE DEFAULT: Database requires TLS
		DatabaseConfig: DatabaseConfig{
			SSLMode:        "verify-full", // Strongest by default
			MaxConnections: 25,
			ConnectTimeout: 10 * time.Second,
		},

		// SECURE DEFAULT: Rate limiting enabled
		RateLimitConfig: RateLimitConfig{
			RequestsPerMinute: 100,
			BurstSize:         20,
			Enabled:           true,
		},

		// SECURE DEFAULT: All security headers enabled
		SecurityHeaders: map[string]string{
			"X-Content-Type-Options":    "nosniff",
			"X-Frame-Options":           "DENY",
			"X-XSS-Protection":          "1; mode=block",
			"Referrer-Policy":           "strict-origin-when-cross-origin",
			"Content-Security-Policy":   "default-src 'self'; script-src 'self'; style-src 'self'",
			"Strict-Transport-Security": "max-age=31536000; includeSubDomains; preload",
			"Permissions-Policy":        "geolocation=(), microphone=(), camera=()",
		},

		// SECURE DEFAULT: No debug endpoints allowed
		AllowedEndpoints: map[string]bool{
			"/debug/":   false,
			"/metrics":  false, // Must be explicitly enabled with auth
			"/profiler": false,
			"/swagger":  false,
		},
	}

	// Apply environment-specific overrides
	config.applyEnvironmentOverrides()

	// Validate configuration is secure for production
	if env == EnvProduction {
		if err := config.validateProductionSecurity(); err != nil {
			log.Fatalf("SECURITY VIOLATION: %v", err)
		}
	}

	return config
}

func getEnvironment() Environment {
	env := os.Getenv("APP_ENV")
	switch strings.ToLower(env) {
	case "development", "dev":
		return EnvDevelopment
	case "staging", "stage":
		return EnvStaging
	case "production", "prod":
		return EnvProduction
	default:
		// SECURE DEFAULT: Unknown environment treated as production
		log.Printf("WARNING: Unknown APP_ENV '%s', defaulting to production security", env)
		return EnvProduction
	}
}

func (c *SecureConfig) applyEnvironmentOverrides() {
	switch c.Environment {
	case EnvDevelopment:
		// Development can relax some controls
		c.DatabaseConfig.SSLMode = "prefer"
		c.CORSConfig.AllowedOrigins = []string{"http://localhost:3000", "http://localhost:8080"}
		c.AllowedEndpoints["/swagger"] = true
		c.AllowedEndpoints["/debug/"] = true

	case EnvStaging:
		// Staging mirrors production but allows metrics
		c.AllowedEndpoints["/metrics"] = true
		c.loadCORSFromEnv()
		c.loadDatabaseFromEnv()

	case EnvProduction:
		// Production: load from secure sources only
		c.loadCORSFromEnv()
		c.loadDatabaseFromEnv()
		c.loadTLSCertsFromVault()
	}
}

func (c *SecureConfig) loadCORSFromEnv() {
	origins := os.Getenv("CORS_ALLOWED_ORIGINS")
	if origins != "" {
		c.CORSConfig.AllowedOrigins = strings.Split(origins, ",")
	}
}

func (c *SecureConfig) loadDatabaseFromEnv() {
	c.DatabaseConfig.Host = os.Getenv("DB_HOST")
	c.DatabaseConfig.CertPath = os.Getenv("DB_SSL_CERT_PATH")
}

func (c *SecureConfig) loadTLSCertsFromVault() {
	// In production, load certs from HashiCorp Vault or similar
	vaultAddr := os.Getenv("VAULT_ADDR")
	if vaultAddr == "" {
		log.Fatal("VAULT_ADDR required in production")
	}
	// Implementation: fetch TLS certs from Vault
}

// validateProductionSecurity ensures production config is secure
func (c *SecureConfig) validateProductionSecurity() error {
	var violations []string

	// Check debug is disabled
	if c.DebugEnabled {
		violations = append(violations, "debug mode enabled in production")
	}

	// Check TLS version
	if c.TLSConfig.MinVersion < tls.VersionTLS12 {
		violations = append(violations, "TLS version below 1.2")
	}

	// Check database SSL
	if c.DatabaseConfig.SSLMode != "verify-full" && c.DatabaseConfig.SSLMode != "verify-ca" {
		violations = append(violations, "database SSL not set to verify-full or verify-ca")
	}

	// Check CORS isn't wildcard
	for _, origin := range c.CORSConfig.AllowedOrigins {
		if origin == "*" {
			violations = append(violations, "wildcard CORS origin not allowed in production")
		}
	}

	// Check debug endpoints are disabled
	for endpoint, enabled := range c.AllowedEndpoints {
		if enabled && strings.Contains(endpoint, "debug") {
			violations = append(violations, fmt.Sprintf("debug endpoint %s enabled in production", endpoint))
		}
	}

	// Check rate limiting is enabled
	if !c.RateLimitConfig.Enabled {
		violations = append(violations, "rate limiting disabled in production")
	}

	if len(violations) > 0 {
		return fmt.Errorf("security violations: %s", strings.Join(violations, "; "))
	}
	return nil
}

// ConfigAuditLog logs configuration for security auditing
func (c *SecureConfig) ConfigAuditLog() {
	audit := map[string]interface{}{
		"timestamp":      time.Now().UTC().Format(time.RFC3339),
		"environment":    c.Environment,
		"debug_enabled":  c.DebugEnabled,
		"tls_min_version": "TLS1.2",
		"db_ssl_mode":    c.DatabaseConfig.SSLMode,
		"rate_limiting":  c.RateLimitConfig.Enabled,
		"cors_origins":   len(c.CORSConfig.AllowedOrigins),
	}

	auditJSON, _ := json.Marshal(audit)
	log.Printf("CONFIG_AUDIT: %s", string(auditJSON))
}

// SecurityMiddleware returns HTTP middleware with all security controls
func (c *SecureConfig) SecurityMiddleware() func(http.Handler) http.Handler {
	return func(next http.Handler) http.Handler {
		return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
			// Apply security headers
			for header, value := range c.SecurityHeaders {
				w.Header().Set(header, value)
			}

			// Block disallowed endpoints
			for endpoint, allowed := range c.AllowedEndpoints {
				if !allowed && strings.HasPrefix(r.URL.Path, endpoint) {
					log.Printf("SECURITY: Blocked access to %s from %s", r.URL.Path, r.RemoteAddr)
					http.Error(w, "Not Found", http.StatusNotFound)
					return
				}
			}

			// Handle CORS
			origin := r.Header.Get("Origin")
			if c.isOriginAllowed(origin) {
				w.Header().Set("Access-Control-Allow-Origin", origin)
				w.Header().Set("Access-Control-Allow-Methods", strings.Join(c.CORSConfig.AllowedMethods, ", "))
				w.Header().Set("Access-Control-Allow-Headers", strings.Join(c.CORSConfig.AllowedHeaders, ", "))
				if c.CORSConfig.AllowCredentials {
					w.Header().Set("Access-Control-Allow-Credentials", "true")
				}
			}

			if r.Method == "OPTIONS" {
				w.WriteHeader(http.StatusNoContent)
				return
			}

			next.ServeHTTP(w, r)
		})
	}
}

func (c *SecureConfig) isOriginAllowed(origin string) bool {
	for _, allowed := range c.CORSConfig.AllowedOrigins {
		if allowed == origin {
			return true
		}
	}
	return false
}
